-- Entry Set 1 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q1',
     'You are in a project review meeting and your manager presents a slide that contains your analysis - the framework, the structure, the key finding - without mentioning your name. The senior stakeholder in the room asks who built this. Your manager says the team put it together.', 'How do you handle this?', 'நீங்கள் ஒரு திட்ட மதிப்பாய்வுக் கூட்டத்தில் இருக்கிறீர்கள். அப்போது உங்கள் மேலாளர், உங்கள் பெயரைக் குறிப்பிடாமல், உங்கள் பகுப்பாய்வை (அதன் கட்டமைப்பு, அமைப்பு, முக்கியக் கண்டுபிடிப்பு போன்றவை) உள்ளடக்கிய ஒரு ஸ்லைடை முன்வைக்கிறார். அறையில் உள்ள மூத்த பங்குதாரர், இதை யார் உருவாக்கினார்கள் என்று கேட்கிறார். அதற்கு உங்கள் மேலாளர், குழுவினர்தான் இதை உருவாக்கினார்கள் என்று கூறுகிறார்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You say nothing in the room but speak to your manager afterward and ask how she would like to handle attribution going forward.', 'நீங்கள் அறையில் எதுவும் பேசாமல், பின்னர் உங்கள் மேலாளரிடம் பேசி, இனிமேல் உரிமை கோரலை அவர் எவ்வாறு கையாள விரும்புகிறார் என்று கேளுங்கள்.', 'D'),
  (2, 'You say, calmly and without tension, that you worked on that section - you make it a fact, not a complaint.', 'நீங்கள் அந்தப் பிரிவில் பணியாற்றியதாக, அமைதியாகவும் பதற்றமின்றியும் கூறுகிறீர்கள் - அதை ஒரு புகாராக அல்லாமல், உண்மையாக ஆக்குகிறீர்கள்.', 'I'),
  (3, 'You let it go entirely - it is one meeting and turning this into an issue will cost you more than the credit is worth.', 'நீங்கள் அதை முற்றிலுமாக விட்டுவிடுங்கள் - அது ஒரே ஒரு சந்திப்புதான், இதை ஒரு பிரச்சினையாக மாற்றுவது, அதனால் கிடைக்கும் நன்மையை விட உங்களுக்கு அதிக செலவை ஏற்படுத்தும்.', 'S'),
  (4, 'You note it, say nothing now, and start keeping a clearer record of what you are producing and when.', 'நீங்கள் அதைக் கவனியுங்கள், இப்போது எதுவும் சொல்லாதீர்கள், மேலும் நீங்கள் என்ன உருவாக்குகிறீர்கள், எப்போது உருவாக்குகிறீர்கள் என்பது குறித்த தெளிவான பதிவைப் பராமரிக்கத் தொடங்குங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q2',
     'Your skip-level manager stops you in the corridor and asks your opinion on a process that your direct manager recently changed. You think the change was a mistake. Your direct manager is someone you are still trying to build trust with.', 'How do you respond now?', 'உங்களுக்கு அடுத்த நிலையில் உள்ள மேலாளர் உங்களை நடைபாதையில் நிறுத்தி, உங்கள் நேரடி மேலாளர் சமீபத்தில் மாற்றிய ஒரு செயல்முறை குறித்து உங்கள் கருத்தைக் கேட்கிறார். அந்த மாற்றம் ஒரு தவறு என்று நீங்கள் நினைக்கிறீர்கள். உங்கள் நேரடி மேலாளரிடம் நீங்கள் இன்னும் நம்பிக்கையை வளர்க்க முயன்று கொண்டிருக்கிறீர்கள்.', 'நீங்கள் இப்போது எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You give your honest assessment - the skip-level asked directly and a vague answer wastes both your time.', 'உங்கள் நேர்மையான மதிப்பீட்டைத் தெரிவியுங்கள் - அடுத்த நிலைக்குச் செல்பவர் நேரடியாகக் கேட்ட கேள்விக்கு ஒரு தெளிவற்ற பதில் அளிப்பது உங்கள் இருவரின் நேரத்தையும் வீணடிக்கும்.', 'D'),
  (2, 'You say you are still getting familiar with the full context and redirect to your direct manager as the right person to ask.', 'நீங்கள் முழு சூழலையும் இன்னும் புரிந்துகொள்ளவில்லை என்றும், இதைக் கேட்பதற்குச் சரியான நபர் உங்கள் நேரடி மேலாளர்தான் என்றும் கூறி அவரை அணுகுகிறீர்கள்.', 'I'),
  (3, 'You share what you observed factually without framing it as a judgment on your manager''s decision.', 'உங்கள் மேலாளரின் முடிவைப் பற்றிய ஒரு தீர்ப்பாகக் கூறாமல், நீங்கள் கவனித்த உண்மைகளை அப்படியே பகிர்ந்து கொள்கிறீர்கள்.', 'S'),
  (4, 'You say the change is still new and you will have a clearer view once you see how it plays out over the next few weeks.', 'இந்த மாற்றம் இன்னும் புதிது என்றும், அடுத்த சில வாரங்களில் அது எவ்வாறு வெளிப்படுகிறது என்பதைப் பார்த்த பிறகுதான் உங்களுக்கு ஒரு தெளிவான பார்வை கிடைக்கும் என்றும் சொல்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q3',
     'What matters more to you in this moment? You have just been asked to represent your team at a cross-functional meeting - the first time you have been given this kind of exposure. Your manager did not explain why she chose you. You do not know if this is a reward, a test, or just a gap she needed filled.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? பல்துறை சார்ந்த கூட்டத்தில் உங்கள் குழுவைப் பிரதிநிதித்துவப்படுத்தும்படி நீங்கள் இப்போதுதான் கேட்டுக்கொள்ளப்பட்டிருக்கிறீர்கள் - இந்த வகையான அனுபவம் உங்களுக்குக் கிடைப்பது இதுவே முதல் முறை. அவர் உங்களை ஏன் தேர்ந்தெடுத்தார் என்பதை உங்கள் மேலாளர் விளக்கவில்லை. இது ஒரு வெகுமதியா, ஒரு சோதனையா, அல்லது அவர் நிரப்ப வேண்டிய ஒரு காலி இடமா என்பது உங்களுக்குத் தெரியவில்லை.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 2", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Performing well in the room - whatever the reason you were chosen, the opportunity is real and how you show up is what will matter.', 'அந்த அறையில் சிறப்பாகச் செயல்படுவது - நீங்கள் தேர்ந்தெடுக்கப்பட்டதற்கான காரணம் எதுவாக இருந்தாலும், அந்த வாய்ப்பு உண்மையானது, மேலும் நீங்கள் உங்களை எப்படி வெளிப்படுத்துகிறீர்கள் என்பதுதான் முக்கியத்துவம் பெறும்.', 'D'),
  (2, 'Understanding why you were chosen - you want to know if this is the start of something or just a practical decision with no signal in it.', 'நீங்கள் ஏன் தேர்ந்தெடுக்கப்பட்டீர்கள் என்பதைப் புரிந்துகொள்வது - இது ஒரு புதிய தொடக்கமா அல்லது எந்தவித முக்கியத்துவமும் இல்லாத ஒரு நடைமுறை முடிவா என்பதை நீங்கள் தெரிந்துகொள்ள விரும்புகிறீர்கள்.', 'I'),
  (3, 'Being seen by the right people - the meeting itself matters less than who will be in that room and what they will carry away about you.', 'சரியான நபர்களின் பார்வையில் படுவது - சந்திப்பை விட, அந்த அறையில் யார் இருப்பார்கள் என்பதும், அவர்கள் உங்களைப் பற்றி என்ன தெரிந்துகொள்வார்கள் என்பதுமே முக்கியம்.', 'S'),
  (4, 'Not getting it wrong - the exposure cuts both ways and the fear of performing poorly is louder than the excitement of being asked.', 'நான் தவறாகப் புரிந்துகொள்ளவில்லை - இந்த வெளிப்பாடு இருபுறமும் கூர்மையானது, மேலும் அழைக்கப்படுவதில் உள்ள உற்சாகத்தை விட, மோசமாகச் செயல்பட்டுவிடுவோமோ என்ற பயமே மேலோங்கி நிற்கிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q4',
     'Before you say anything - you have been at this company for eleven months and your manager has just told you, in your one-on-one, that senior leadership has noticed your work. She does not say more than that. The meeting moves on. You are sitting with those words now.', 'How do you feel now?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - நீங்கள் இந்த நிறுவனத்தில் பதினொரு மாதங்களாகப் பணிபுரிந்து வருகிறீர்கள், உங்களுடனான தனிப்பட்ட சந்திப்பில், உயர் தலைமை உங்கள் பணியைக் கவனித்திருப்பதாக உங்கள் மேலாளர் இப்போதுதான் உங்களிடம் கூறியுள்ளார். அவர் அதற்கு மேல் எதுவும் சொல்லவில்லை. கூட்டம் தொடர்கிறது. நீங்கள் இப்போது அந்த வார்த்தைகளுடன் அமர்ந்திருக்கிறீர்கள்.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 3", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A desperate need to know more - noticed how, by whom, in what context, and what they said - the vagueness is harder to sit with than no information at all.', 'மேலும் தெரிந்துகொள்ள வேண்டும் என்ற தீவிரத் தேவை - எப்படி, யாரால், எந்தச் சூழலில், அவர்கள் என்ன சொன்னார்கள் என்பதைக் கவனித்த பிறகு - எந்தத் தகவலும் இல்லாததை விட, இந்தத் தெளிவின்மையுடன் இருப்பது மிகவும் கடினமாக இருக்கிறது.', 'D'),
  (2, 'A careful stillness - you have learned not to build too much on words that have not been followed by anything concrete.', 'ஒரு கவனமான அமைதி - உறுதியான எதுவும் தொடராத வார்த்தைகளை வைத்து அதிகம் கட்டியெழுப்பக் கூடாது என்பதை நீங்கள் கற்றுக்கொண்டிருக்கிறீர்கள்.', 'I'),
  (3, 'A warmth that surprises you - you have been doing the work without much signal and this, even incomplete, feels like it landed somewhere.', 'உங்களை ஆச்சரியப்படுத்தும் ஓர் அரவணைப்பு - பெரிய அறிகுறிகள் ஏதுமின்றி நீங்கள் அந்த வேலையைச் செய்து வந்திருக்கிறீர்கள், அது முழுமையடையாததாக இருந்தாலும், எங்கோ வந்து சேர்ந்தது போல் உணர்கிறீர்கள்.', 'S'),
  (4, 'A pressure that did not exist this morning - being noticed raises the cost of the next mistake in a way that flying under the radar did not.', 'இன்று காலை இல்லாத ஒரு அழுத்தம் - யாருக்கும் தெரியாமல் செயல்படுவதைப் போலல்லாமல், பிறர் கவனிக்கும்போது அடுத்த தவறுக்கான செலவு அதிகரித்துவிடுகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q5',
     'You sent a report to three stakeholders yesterday. This morning you realise you attached the wrong version - one that contains a comment in the margin that reads like a note to yourself and is mildly critical of a decision one of the stakeholders made. None of them have replied yet.', 'What should you do now?', 'நேற்று நீங்கள் மூன்று சம்பந்தப்பட்டவர்களுக்கு ஒரு அறிக்கையை அனுப்பினீர்கள். இன்று காலை, நீங்கள் தவறான பதிப்பை இணைத்திருப்பதை உணர்கிறீர்கள் - அதன் ஓரத்தில், சம்பந்தப்பட்டவர்களில் ஒருவர் எடுத்த முடிவை லேசாக விமர்சிக்கும் விதமாக, உங்களுக்கே நீங்கள் எழுதிக்கொள்ளும் ஒரு குறிப்பைப் போன்ற ஒரு கருத்து இடம்பெற்றுள்ளது. அவர்களில் யாரும் இன்னும் பதிலளிக்கவில்லை.', 'இப்போது நீங்கள் என்ன செய்ய வேண்டும்?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You send a follow-up immediately, acknowledge the error, attach the correct version, and keep the explanation brief and professional.', 'நீங்கள் உடனடியாக ஒரு பின்தொடர் செய்தியை அனுப்புங்கள், பிழையை ஒப்புக்கொண்டு, சரியான பதிப்பை இணைத்து, விளக்கத்தைச் சுருக்கமாகவும் தொழில்முறையாகவும் வைத்திருங்கள்.', 'D'),
  (2, 'You call the stakeholder who would have seen the comment before you send anything in writing - this needs a voice first.', 'எழுத்துப்பூர்வமாக எதையும் அனுப்புவதற்கு முன், அந்தக் கருத்தைப் பார்த்திருக்கக்கூடிய சம்பந்தப்பட்ட நபரை நீங்கள் அழைக்க வேண்டும் - இதற்கு முதலில் ஒரு கருத்து கேட்கப்பட வேண்டும்.', 'I'),
  (3, 'You send the corrected version with no explanation and hope the comment was not read.', 'நீங்கள் எந்த விளக்கமும் அளிக்காமல் திருத்தப்பட்ட பதிப்பை அனுப்பிவிட்டு, அந்தக் கருத்து படிக்கப்படவில்லை என நம்புகிறீர்கள்.', 'S'),
  (4, 'You own it fully - you send a short note explaining exactly what happened, why, and that the correct version is attached.', 'அதன் முழுப் பொறுப்பும் உங்களையே சாரும் - என்ன நடந்தது, ஏன் நடந்தது என்பதைத் துல்லியமாக விளக்கி, சரியான பதிப்பு இணைக்கப்பட்டுள்ளது என்பதையும் ஒரு சிறு குறிப்பாக அனுப்புங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q6',
     'You are halfway through a task and you have just realised that the way you were briefed does not match what the end output actually needs to be. The briefing was verbal. Your manager is in back-to-back meetings until 4pm. The work is due at 5pm.', 'How to handle mismatched briefs?', 'நீங்கள் ஒரு பணியின் பாதியில் இருக்கிறீர்கள், அப்போதுதான் உங்களுக்கு விளக்கமளிக்கப்பட்ட விதத்திற்கும், உண்மையில் தேவைப்படும் இறுதி வெளியீட்டிற்கும் சம்பந்தமில்லை என்பதை உணர்கிறீர்கள். அந்த விளக்கம் வாய்மொழியாக அளிக்கப்பட்டது. உங்கள் மேலாளர் மாலை 4 மணி வரை தொடர்ச்சியான கூட்டங்களில் இருக்கிறார். அந்தப் பணியை மாலை 5 மணிக்குச் சமர்ப்பிக்க வேண்டும்.', 'பொருந்தாத சுருக்கங்களை எவ்வாறு கையாள்வது?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 1", "dimension": "accuracy_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You send a message to your manager flagging the gap and ask her to confirm the direction before you go further.', 'அந்தக் குறைபாட்டைச் சுட்டிக்காட்டி உங்கள் மேலாளருக்கு ஒரு செய்தி அனுப்பி, மேற்கொண்டு செல்வதற்கு முன் திசையை உறுதிப்படுத்துமாறு அவரிடம் கேளுங்கள்.', 'D'),
  (2, 'You make your best judgment call about what the output should be, complete the work, and flag the assumption when you submit it.', 'வெளியீடு எப்படி இருக்க வேண்டும் என்பது குறித்து நீங்களே சிறந்த முடிவை எடுத்து, அந்தப் பணியை முடித்து, அதைச் சமர்ப்பிக்கும்போது உங்கள் அனுமானத்தைக் குறித்துக் காட்டுங்கள்.', 'I'),
  (3, 'You stop working on it and wait until you can speak to your manager - you are not willing to produce the wrong thing just to hit the deadline.', 'நீங்கள் அதில் வேலை செய்வதை நிறுத்திவிட்டு, உங்கள் மேலாளரிடம் பேசும் வரை காத்திருங்கள் - காலக்கெடுவை எட்டுவதற்காக மட்டும் தவறான ஒன்றை உருவாக்க நீங்கள் தயாராக இருக்க மாட்டீர்கள்.', 'S'),
  (4, 'You complete two versions - one based on the briefing and one based on what you think the output should be - and present both with an explanation.', 'வழங்கப்பட்ட விளக்கத்தின் அடிப்படையில் ஒன்று, மற்றும் அதன் விளைவு எப்படி இருக்க வேண்டும் என்று நீங்கள் கருதுகிறீர்களோ அதன் அடிப்படையில் மற்றொன்று என இரண்டு பதிப்புகளைத் தயாரித்து, இரண்டையும் ஒரு விளக்கத்துடன் சமர்ப்பிக்கவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q7',
     'Two things are pulling at you. Which is stronger? You have been asked to pull together a summary for a leadership presentation. You have most of the data but one section relies on a number from a colleague who has not come back to you despite two follow-ups. The presentation is tomorrow morning.', 'Which pulling force is stronger?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? ஒரு தலைமைத்துவ விளக்கக்காட்சிக்காக ஒரு சுருக்கத்தைத் தொகுக்குமாறு நீங்கள் கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள். உங்களிடம் பெரும்பாலான தரவுகள் உள்ளன, ஆனால் ஒரு பகுதி, இரண்டு முறை பின்தொடர்ந்தும் பதிலளிக்காத ஒரு சக ஊழியரிடமிருந்து கிடைத்த எண்ணைச் சார்ந்துள்ளது. அந்த விளக்கக்காட்சி நாளை காலை நடைபெற உள்ளது.', 'எந்த இழுவிசை வலிமையானது?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 2", "dimension": "accuracy_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Getting the number right - submitting with a gap or an estimate feels like putting your name on something you cannot stand behind.', 'சரியான எண்ணைப் பெறுவது - ஒரு இடைவெளியுடனோ அல்லது மதிப்பீடோ சமர்ப்பிப்பது என்பது, உங்களால் பொறுப்பேற்க முடியாத ஒரு விஷயத்தில் உங்கள் பெயரைப் போடுவது போன்ற உணர்வைத் தரும்.', 'D'),
  (2, 'Delivering something complete - a presentation with a missing section is a bigger problem than one with a clearly flagged estimate.', 'முழுமையான ஒன்றை வழங்குவது - தெளிவாகக் குறிப்பிடப்பட்ட மதிப்பீட்டைக் கொண்ட ஒரு விளக்கக்காட்சியை விட, விடுபட்ட ஒரு பகுதியைக் கொண்ட விளக்கக்காட்சி ஒரு பெரிய சிக்கலாகும்.', 'I'),
  (3, 'Protecting yourself - if the number is wrong because someone else did not deliver, you want that clearly visible before the presentation goes in.', 'உங்களைப் பாதுகாத்துக் கொள்வது - வேறொருவர் வழங்கத் தவறியதால் எண்ணிக்கை தவறாக இருந்தால், விளக்கக்காட்சி சமர்ப்பிக்கப்படுவதற்கு முன்பு அது தெளிவாகத் தெரிய வேண்டும்.', 'S'),
  (4, 'The relationship with the colleague - chasing a third time feels like pressure you do not want to create, even if the deadline justifies it.', 'சக ஊழியருடனான உறவைப் பொறுத்தவரை, காலக்கெடு அதை நியாயப்படுத்தினாலும், மூன்றாவது முறையாகப் பின்தொடர்வது என்பது நீங்கள் உருவாக்க விரும்பாத ஒரு அழுத்தமாகவே உணரப்படுகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q8',
     'What is actually happening inside you - you worked on a piece of analysis for three days. You submitted it. Your manager glanced at it, said it was fine, and moved on. No one has looked at it properly. It is sitting in a folder somewhere doing nothing.', 'How do you feel now?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - நீங்கள் ஒரு பகுப்பாய்வுக் கட்டுரையில் மூன்று நாட்கள் உழைத்தீர்கள். அதைச் சமர்ப்பித்தீர்கள். உங்கள் மேலாளர் அதை மேலோட்டமாகப் பார்த்துவிட்டு, ''சரி'' என்று சொல்லிவிட்டு அடுத்த வேலைக்குச் சென்றுவிட்டார். யாரும் அதை முறையாகப் பார்க்கவில்லை. அது எங்கோ ஒரு கோப்புறையில் சும்மா கிடக்கிறது.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A deflation that you are trying not to call demotivation - you worked carefully on something and its disappearance into a folder feels like a verdict on the effort.', 'நீங்கள் ஊக்கமின்மை என்று கூற விரும்பாத ஒரு சோர்வு - நீங்கள் ஒரு விஷயத்தில் கவனமாக உழைத்தீர்கள், ஆனால் அது ஒரு கோப்புறைக்குள் மறைந்து போவது, அந்த முயற்சிக்கு அளிக்கப்பட்ட ஒரு தீர்ப்பு போலத் தோன்றுகிறது.', 'D'),
  (2, 'A question about whether the work was actually as good as you thought - maybe the lack of response is information, not oversight.', 'அந்தப் பணி நீங்கள் நினைத்த அளவுக்கு உண்மையில் சிறப்பாக இருந்ததா என்பது பற்றிய ஒரு கேள்வி - ஒருவேளை, பதில் வராதது ஒரு குறைபாடாக இல்லாமல், தகவலாக இருக்கலாம்.', 'I'),
  (3, 'A frustration at the process - not at your manager personally but at the way things get commissioned and then forgotten in this place.', 'இந்தச் செயல்முறையின் மீதான விரக்தி - உங்கள் மேலாளர் மீது தனிப்பட்ட முறையில் அல்ல, மாறாக இங்கு காரியங்கள் ஒப்படைக்கப்பட்டுப் பின்னர் மறக்கப்படும் விதத்தின் மீதான விரக்தி.', 'S'),
  (4, 'A practical recalibration - you are learning what level of effort this environment actually rewards and adjusting your internal threshold accordingly.', 'ஒரு நடைமுறை மறுசீரமைப்பு - இந்தச் சூழல் உண்மையில் எந்த அளவிலான முயற்சிக்கு வெகுமதி அளிக்கிறது என்பதை நீங்கள் கற்றுக்கொண்டு, அதற்கேற்ப உங்கள் உள் வரம்பைச் சரிசெய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q9',
     'You are working on a joint deliverable with a colleague. He has strong opinions about how the final output should look and has been making changes to the shared document without discussing them with you first. Some of the changes overwrite your work. You have a final submission deadline in two days.', 'How handle overwriting shared work?', 'நீங்கள் ஒரு சக ஊழியருடன் இணைந்து ஒரு கூட்டுப் பணியில் ஈடுபட்டுள்ளீர்கள். இறுதி வெளியீடு எப்படி இருக்க வேண்டும் என்பது குறித்து அவருக்கு வலுவான கருத்துக்கள் உள்ளன. மேலும், உங்களுடன் முதலில் கலந்தாலோசிக்காமல், பகிரப்பட்ட ஆவணத்தில் அவர் மாற்றங்களைச் செய்து வருகிறார். அந்த மாற்றங்களில் சில, நீங்கள் செய்த வேலையை மேலெழுதிவிடுகின்றன. இன்னும் இரண்டு நாட்களில் நீங்கள் இறுதியாகச் சமர்ப்பிக்க வேண்டும்.', 'பகிரப்பட்ட பணியை மேலெழுதுவதை எவ்வாறு கையாள்வது?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You message him directly and set a clear expectation - changes to shared work need to be discussed before they go in, not after.', 'நீங்கள் அவருக்கு நேரடியாகச் செய்தி அனுப்பி, ஒரு தெளிவான எதிர்பார்ப்பை முன்வையுங்கள் - பகிரப்பட்ட பணியில் செய்யப்படும் மாற்றங்கள், அவை செயல்படுத்தப்பட்ட பிறகு அல்ல, அதற்கு முன்பே விவாதிக்கப்பட வேண்டும்.', 'D'),
  (2, 'You set up a call to align on the structure before either of you touches the document again.', 'உங்களில் ஒருவர் அந்த ஆவணத்தை மீண்டும் தொடுவதற்கு முன்பு, அதன் கட்டமைப்பை ஒருங்கிணைவதற்கான அழைப்பை நீங்கள் ஏற்படுத்துகிறீர்கள்.', 'I'),
  (3, 'You revert the changes you disagree with and add a comment explaining your thinking - let the document be the conversation.', 'நீங்கள் உடன்படாத மாற்றங்களைத் திரும்பப் பெற்று, உங்கள் கருத்தை விளக்கி ஒரு பின்னூட்டத்தைச் சேர்க்கவும் - அந்த ஆவணமே ஒரு உரையாடலாக இருக்கட்டும்.', 'S'),
  (4, 'You let it go for now and focus on getting the work done - you will deal with the working style issue after the deadline.', 'இப்போதைக்கு அதை விட்டுவிட்டு, வேலையை முடிப்பதில் கவனம் செலுத்துங்கள் - காலக்கெடு முடிந்த பிறகு பணிபுரியும் பாணிப் பிரச்சினையைக் கவனித்துக் கொள்ளலாம்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q10',
     'A colleague at your level is visibly competitive with you. She references your work in meetings in a way that sounds collaborative but positions her own contribution as the more significant one. It has happened three times now and you do not think it is accidental.', 'How handle a competitive colleague?', 'உங்கள் நிலையில் உள்ள ஒரு சக ஊழியர் உங்களுடன் வெளிப்படையாகப் போட்டி போடுகிறார். அவர் கூட்டங்களில் உங்கள் வேலையைக் குறிப்பிடும்போது, ​​அது ஒத்துழைப்புடன் செயல்படுவது போலத் தோன்றினாலும், தனது பங்களிப்பையே மிகவும் முக்கியமானதாக முன்னிறுத்துகிறார். இது இப்போது மூன்று முறை நிகழ்ந்துள்ளது, ஆனால் இது தற்செயலானது என்று நீங்கள் நினைக்கவில்லை.', 'போட்டி மனப்பான்மை கொண்ட சக ஊழியரை எப்படி கையாள்வது?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name it privately - you find a quiet moment and tell her directly that you have noticed the pattern and you would like to talk about how you work together.', 'நீங்கள் அதைத் தனிப்பட்ட முறையில் குறிப்பிடுங்கள் - ஒரு அமைதியான தருணத்தைக் கண்டுபிடித்து, அந்தப் போக்கைக் கவனித்ததாகவும், நீங்கள் இருவரும் இணைந்து எப்படி வேலை செய்கிறீர்கள் என்பது பற்றிப் பேச விரும்புவதாகவும் அவளிடம் நேரடியாகச் சொல்லுங்கள்.', 'D'),
  (2, 'You become more deliberate about how you present your own work in group settings - you let visibility do the work rather than having a conversation about it.', 'குழுச் சூழல்களில் உங்கள் சொந்தப் படைப்புகளை முன்வைக்கும் விதத்தில் நீங்கள் அதிக கவனத்துடன் செயல்படுவீர்கள் - அதைப் பற்றி உரையாடுவதற்குப் பதிலாக, அவை கண்ணுக்குத் தெரியும்படி விட்டுவிடுவீர்கள்.', 'I'),
  (3, 'You mention it to a trusted colleague to check whether you are reading it correctly before you do anything.', 'எதையும் செய்வதற்கு முன், நீங்கள் அதைச் சரியாகப் படிக்கிறீர்களா என்பதைச் சரிபார்க்க, நம்பகமான சக ஊழியர் ஒருவரிடம் அதைக் குறிப்பிடுங்கள்.', 'S'),
  (4, 'You let it continue for now - you do not have enough proof that it is intentional and acting on a pattern that might be accidental could backfire.', 'இப்போதைக்கு இதைத் தொடர விடுங்கள் - இது வேண்டுமென்றே செய்யப்படுகிறது என்பதற்கு உங்களிடம் போதுமான ஆதாரம் இல்லை, மேலும் தற்செயலாக நிகழக்கூடிய ஒரு போக்கின்படி செயல்படுவது உங்களுக்கு எதிராகவே திரும்பக்கூடும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q11',
     'The conflict you feel most is between - you have a colleague who has become a genuine friend. You enjoy working with her and you trust her. You have recently started to notice that her work is slipping and the team is quietly absorbing the cost. You are one of the people covering for her.', 'How will you handle this?', 'நீங்கள் அதிகமாக உணரும் முரண்பாடு இவ்விரண்டிற்கும் இடையில்தான் உள்ளது - உங்களுக்கு உண்மையான நண்பராகிவிட்ட ஒரு சக ஊழியர் இருக்கிறார். அவருடன் பணிபுரிவதை நீங்கள் விரும்புகிறீர்கள், அவரை நம்புகிறீர்கள். சமீபத்தில், அவருடைய பணித்திறன் குறைந்து வருவதையும், அதன் சுமையை குழுவினர் யாருக்கும் தெரியாமல் ஏற்றுக்கொள்வதையும் நீங்கள் கவனிக்கத் தொடங்கியுள்ளீர்கள். அவருக்காகப் பொறுப்புகளை ஈடுசெய்பவர்களில் நீங்களும் ஒருவர்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Loyalty to the friendship and honesty about what you are seeing - you do not know how to be a good friend and a straight-talking colleague at the same time.', 'நட்பின் மீதான பற்றும், நீங்கள் காண்பதைப் பற்றிய நேர்மையும் - ஒரே நேரத்தில் ஒரு நல்ல நண்பராகவும், வெளிப்படையாகப் பேசும் சக ஊழியராகவும் எப்படி இருப்பது என்று உங்களுக்குத் தெரியவில்லை.', 'D'),
  (2, 'Her wellbeing and the team''s output - something is clearly going on with her but the work still has to get done and you cannot carry it indefinitely.', 'அவரது நல்வாழ்வு மற்றும் அணியின் செயல்திறன் - அவருக்கு ஏதோ ஒரு பிரச்சினை இருப்பது தெளிவாகத் தெரிகிறது, ஆனால் அந்தப் பணியை முடித்தே ஆக வேண்டும், அதை காலவரையின்றித் தொடர முடியாது.', 'I'),
  (3, 'Saying something and staying silent - you know this will only get harder the longer you wait, and you also know that saying it might change things between you.', 'ஏதாவது சொல்லிவிட்டு மௌனமாக இருப்பது - நீங்கள் எவ்வளவு காலம் காத்திருக்கிறீர்களோ, அவ்வளவு கடினமாக இது மாறும் என்பது உங்களுக்குத் தெரியும்; மேலும், அதைச் சொல்வது உங்கள் இருவருக்கும் இடையிலான உறவை மாற்றிவிடக்கூடும் என்பதும் உங்களுக்குத் தெரியும்.', 'S'),
  (4, 'Protecting her from the team''s frustration and being honest with her about what you are hearing - you cannot do both and you have to choose.', 'அணியின் விரக்தியிலிருந்து அவளைப் பாதுகாப்பதும், நீங்கள் கேள்விப்படுவதைப் பற்றி அவளிடம் நேர்மையாக இருப்பதும் - இரண்டையும் உங்களால் செய்ய முடியாது, நீங்கள் ஒன்றைத் தேர்ந்தெடுக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q12',
     'The honest feeling underneath this - a colleague you have worked closely with for the past year is leaving the company. He is not someone you would describe as a close friend but your working relationship has been one of the most reliable parts of your day. He told you privately before the announcement.', 'What is your honest feeling?', 'இதன் பின்னணியில் உள்ள உண்மையான உணர்வு இதுதான் - கடந்த ஒரு வருடமாக நீங்கள் நெருக்கமாகப் பணியாற்றிய ஒரு சக ஊழியர் நிறுவனத்தை விட்டு விலகுகிறார். அவரை நீங்கள் ஒரு நெருங்கிய நண்பர் என்று வர்ணிக்க மாட்டீர்கள், ஆனால் உங்கள் பணி உறவுதான் உங்கள் அன்றாட வாழ்வின் மிகவும் நம்பகமான அங்கங்களில் ஒன்றாக இருந்துள்ளது. இந்த அறிவிப்புக்கு முன்பு அவர் உங்களிடம் தனிப்பட்ட முறையில் இதைத் தெரிவித்திருந்தார்.', 'உங்கள் உண்மையான உணர்வு என்ன?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A quiet anxiety about the room without him - not because of the workload but because of how much of your reading of this place relied on his presence in it.', 'அவர் இல்லாத அந்த அறையைப் பற்றிய ஒரு மெல்லிய பதற்றம் - அது வேலைப்பளுவினால் அல்ல, மாறாக அந்த இடத்தைப் பற்றிய நமது புரிதல் பெருமளவில் அதில் அவருடைய இருப்பைச் சார்ந்திருந்ததினால் ஏற்பட்டது.', 'D'),
  (2, 'A realisation that you have been more dependent on this working relationship than you knew - and a small alarm at what that means.', 'நீங்கள் நினைத்ததை விட இந்தப் பணி உறவை அதிகமாகச் சார்ந்திருந்திருக்கிறீர்கள் என்ற ஒரு புரிதலும், அதன் அர்த்தம் குறித்த ஒரு சிறு எச்சரிக்கை உணர்வும்.', 'I'),
  (3, 'A genuine happiness for him that is completely true and completely separate from the part of you that is already trying to figure out what changes now.', 'இனி என்ன மாற்றங்கள் நிகழப்போகின்றன என்று ஏற்கெனவே யோசித்துக்கொண்டிருக்கும் உன் மனதின் ஒரு பகுதியிலிருந்து முற்றிலும் மாறுபட்டு, அவனுக்காக அவன் அனுபவிக்கும் ஒரு உண்மையான மகிழ்ச்சி.', 'S'),
  (4, 'A grief that feels slightly disproportionate and that you are not sure you are allowed to feel about someone who was never quite a friend.', 'ஒருபோதும் முழுமையான நண்பராக இருந்ததில்லை என்று நீங்கள் கருதும் ஒருவரைப் பற்றி, சற்றே அளவுக்கதிகமாகத் தோன்றும் ஒரு துக்கம்; அப்படி உணர்வதற்கு உங்களுக்கு அனுமதி உண்டா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q13',
     'You receive your mid-year review. The written feedback says your technical work is strong but that you need to work on your executive presence. You have never been told this before. You do not fully understand what it means and the person who wrote it is not available to discuss it for two weeks.', 'How handle vague feedback?', 'உங்கள் அரையாண்டு மதிப்பீட்டைப் பெறுகிறீர்கள். அதில் உள்ள எழுத்துப்பூர்வமான பின்னூட்டத்தில், உங்கள் தொழில்நுட்பப் பணி சிறப்பாக உள்ளது என்றும், ஆனால் உங்கள் நிர்வாகத் திறனை மேம்படுத்த வேண்டும் என்றும் கூறப்பட்டுள்ளது. இதுபற்றி இதற்கு முன்பு உங்களிடம் ஒருபோதும் கூறப்பட்டதில்லை. அதன் அர்த்தம் உங்களுக்கு முழுமையாகப் புரியவில்லை, மேலும் அதை எழுதிய நபரும் அடுத்த இரண்டு வாரங்களுக்கு இதுகுறித்துப் பேசக் கிடைக்கவில்லை.', 'தெளிவற்ற பின்னூட்டத்தை எவ்வாறு கையாள்வது?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You sit with it and try to identify specific moments where you may have fallen short - you want to work with something concrete before the follow-up conversation.', 'நீங்கள் அதைப்பற்றி நிதானமாகச் சிந்தித்து, நீங்கள் தவறியிருக்கக்கூடிய குறிப்பிட்ட தருணங்களைக் கண்டறிய முயற்சிக்க வேண்டும் - அடுத்தகட்ட உரையாடலுக்கு முன்பு, உறுதியான ஒரு விஷயத்துடன் நீங்கள் செயல்பட வேண்டும்.', 'D'),
  (2, 'You research what executive presence means in this context and start adjusting small things immediately without waiting for the conversation.', 'இந்தச் சூழலில் நிர்வாகத் தலைமைப் பண்பு என்பதன் அர்த்தம் என்ன என்பதை நீங்கள் ஆராய்ந்து, உரையாடலுக்காகக் காத்திருக்காமல் உடனடியாகச் சிறிய விஷயங்களைச் சரிசெய்யத் தொடங்குகிறீர்கள்.', 'I'),
  (3, 'You email your manager asking for one specific example so you have something real to work with before she is available.', 'உங்கள் மேலாளர் பணிக்கு வருவதற்கு முன்பாக, உங்களிடம் செயல்படுவதற்கு ஒரு உறுதியான ஆதாரம் இருப்பதற்காக, அவரிடம் ஒரு குறிப்பிட்ட உதாரணத்தைக் கேட்டு மின்னஞ்சல் அனுப்புங்கள்.', 'S'),
  (4, 'You file it until the conversation - you are not going to try to interpret feedback you cannot ask questions about yet.', 'உரையாடல் முடியும் வரை அதை நீங்கள் குறித்து வைத்துக் கொள்ளுங்கள் - உங்களால் இன்னும் கேள்விகள் கேட்க முடியாத பின்னூட்டத்தை நீங்களாகவே விளக்க முயற்சிக்கக் கூடாது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q14',
     'A senior colleague pulls you aside after a presentation and says the delivery was confident but the structure made it hard to follow the argument. You thought the structure was one of the stronger parts. You spent the most time on it.', 'How should you handle feedback?', 'ஒரு விளக்கக்காட்சிக்குப் பிறகு, ஒரு மூத்த சக ஊழியர் உங்களைத் தனியாக அழைத்து, நீங்கள் நம்பிக்கையுடன் வழங்கியதாகவும், ஆனால் அதன் கட்டமைப்பு வாதத்தைப் புரிந்துகொள்வதைக் கடினமாக்கியதாகவும் கூறுகிறார். அந்தக் கட்டமைப்புதான் வலுவான அம்சங்களில் ஒன்று என்று நீங்கள் நினைத்தீர்கள். அதற்காகத்தான் நீங்கள் அதிக நேரத்தைச் செலவிட்டீர்கள்.', 'பின்னூட்டத்தை எவ்வாறு கையாள வேண்டும்?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You thank her and ask her to walk you through where she lost the thread - you want to understand it from her perspective before you decide what to change.', 'நீங்கள் அவளுக்கு நன்றி சொல்லி, அவள் எங்கே தொடர்பைத் தவறவிட்டாள் என்பதை விளக்குமாறு கேட்கிறீர்கள் - எதை மாற்றுவது என்று தீர்மானிப்பதற்கு முன், அவளுடைய கண்ணோட்டத்தில் இருந்து அதை நீங்கள் புரிந்துகொள்ள விரும்புகிறீர்கள்.', 'D'),
  (2, 'You thank her and take it on board - her read is her read and your instinct about your own work is clearly not a reliable guide here.', 'நீங்கள் அவளுக்கு நன்றி சொல்லி, அதை ஏற்றுக்கொள்கிறீர்கள் - அவளுடைய பார்வை அவளுடையது, மேலும் உங்கள் சொந்தப் படைப்பைப் பற்றிய உங்கள் உள்ளுணர்வு இங்கே ஒரு நம்பகமான வழிகாட்டி அல்ல என்பது தெளிவாகிறது.', 'I'),
  (3, 'You ask one question: was this just her view or did others find it hard to follow? You want to know if this is a pattern or a single data point.', 'நீங்கள் ஒரு கேள்வி கேட்கிறீர்கள்: இது அவளுடைய தனிப்பட்ட கருத்தா அல்லது மற்றவர்களுக்கும் இதைப் புரிந்துகொள்வது கடினமாக இருந்ததா? இது ஒரு தொடர் நிகழ்வா அல்லது ஒரு குறிப்பிட்ட தரவுப் புள்ளியா என்பதை நீங்கள் அறிய விரும்புகிறீர்கள்.', 'S'),
  (4, 'You thank her, go back to the structure, and try to see it the way she described - not to prove her wrong but to understand whether you are missing something.', 'நீங்கள் அவளுக்கு நன்றி சொல்லிவிட்டு, அந்த அமைப்புக்குத் திரும்பிச் சென்று, அவள் விவரித்த விதத்தில் அதைப் பார்க்க முயற்சி செய்யுங்கள் - அவள் சொல்வது தவறு என்று நிரூபிப்பதற்காக அல்ல, மாறாக நீங்கள் எதையாவது தவறவிடுகிறீர்களா என்பதைப் புரிந்துகொள்வதற்காக.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q15',
     'What matters more to you in this moment? You are in your second year and you have received feedback twice in the last three months that you are not strategic enough in how you approach problems. You are not sure what strategic means in your role at your level - the examples given have been vague.', 'What does being strategic mean?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது? நீங்கள் உங்கள் இரண்டாம் ஆண்டில் இருக்கிறீர்கள், மேலும் கடந்த மூன்று மாதங்களில், பிரச்சனைகளை அணுகும் விதத்தில் நீங்கள் போதுமான அளவு உத்திபூர்வமாகச் செயல்படவில்லை என்று இரண்டு முறை பின்னூட்டம் பெற்றுள்ளீர்கள். உங்கள் நிலையில், உங்கள் பணிக்கு உத்திபூர்வமானது என்பதன் அர்த்தம் என்னவென்று உங்களுக்கு உறுதியாகத் தெரியவில்லை - கொடுக்கப்பட்ட உதாரணங்கள் தெளிவற்றவையாக இருந்துள்ளன.', 'வியூகத்துடன் செயல்படுவது என்பதன் பொருள் என்ன?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Getting clarity on what strategic means here - you cannot develop something you cannot define and you are going to ask until you have a real answer.', 'இங்கு ''வியூகம்'' என்பதன் பொருள் என்ன என்பதில் தெளிவு பெறுவது அவசியம் - உங்களால் வரையறுக்க முடியாத ஒன்றை உருவாக்க முடியாது, மேலும் ஒரு உண்மையான பதில் கிடைக்கும் வரை நீங்கள் தொடர்ந்து கேட்டுக்கொண்டே இருப்பீர்கள்.', 'D'),
  (2, 'Demonstrating that you understand the feedback - sometimes the way you respond to it matters as much as whether you can actually do the thing.', 'பின்னூட்டத்தை நீங்கள் புரிந்துகொண்டீர்கள் என்பதை வெளிப்படுத்துவது - சில சமயங்களில், உங்களால் அந்தச் செயலைச் செய்ய முடியுமா என்பதைப் போலவே, நீங்கள் அதற்குப் பதிலளிக்கும் விதமும் முக்கியத்துவம் பெறுகிறது.', 'I'),
  (3, 'Figuring it out yourself - waiting for someone to explain it is slower than watching what gets called strategic in this place and reverse-engineering it.', 'இதை நீங்களே கண்டறிவதும், யாராவது விளக்குவதற்காகக் காத்திருப்பதும், இங்கு எது உத்திசார்ந்தது என்று அழைக்கப்படுகிறதோ அதைக் கவனித்து, அதனைப் பின்னோக்கி ஆராய்ந்து புரிந்துகொள்வதை விட மெதுவானதாகும்.', 'S'),
  (4, 'Deciding whether the feedback is valid - you have a view on what strategic means and you want to know if the organisation''s definition and yours are actually aligned.', 'கருத்து செல்லுபடியாகுமா என்பதைத் தீர்மானித்தல் - வியூகம் என்றால் என்ன என்பது குறித்து உங்களுக்கு ஒரு பார்வை உள்ளது, மேலும் நிறுவனத்தின் வரையறையும் உங்களுடையதும் உண்மையில் ஒத்துப்போகின்றனவா என்பதை நீங்கள் தெரிந்துகொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q16',
     'Before you say anything - your manager has just finished your quarterly review. It was mostly positive. At the end she said one thing - that sometimes you seem like you are holding back, like there is more there but you are not fully in the room. She said it kindly. She is right.', 'Why are you holding back?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - உங்கள் மேலாளர் இப்போதுதான் உங்கள் காலாண்டு மதிப்பாய்வை முடித்திருக்கிறார். அது பெரும்பாலும் சாதகமாகவே இருந்தது. இறுதியில் அவர் ஒரு விஷயத்தைச் சொன்னார் - சில சமயங்களில் நீங்கள் எதையோ மறைப்பது போலவும், உங்களிடம் இன்னும் நிறைய இருக்கிறது ஆனால் நீங்கள் முழுமையாக அதில் ஈடுபடவில்லை என்பது போலவும் தெரிகிறது என்றார். அவர் அதை அன்பாகவே சொன்னார். அவர் சொல்வது சரிதான்.', 'ஏன் தயங்குகிறீர்கள்?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 3", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A sudden recognition that she has seen something you have been pretending not to know - and a relief and a terror at the same time.', 'நீங்கள் தெரியாதது போல் நடித்துக்கொண்டிருந்த ஒன்றை அவள் பார்த்துவிட்டாள் என்பதை திடீரென உணர்வது - அது ஒரே நேரத்தில் ஒரு நிம்மதியையும் திகிலையும் தருகிறது.', 'D'),
  (2, 'A gratitude that someone said it directly - you have been waiting for someone to notice without knowing you were waiting.', 'யாரோ ஒருவர் அதை நேரடியாகச் சொன்னதற்காக ஒரு நன்றியுணர்வு - நீங்கள் காத்துக்கொண்டிருந்தீர்கள் என்பதே தெரியாமல், யாராவது அதைக் கவனிப்பார்கள் என்று காத்துக்கொண்டிருந்தீர்கள்.', 'I'),
  (3, 'A defensiveness you are trying not to show - being told you are not fully present feels like an accusation dressed as encouragement.', 'நீங்கள் வெளிக்காட்ட விரும்பாத ஒரு தற்காப்பு நிலை - நீங்கள் முழுமையாக அங்கு இல்லை என்று கூறப்படுவது, ஊக்கமளிப்பது போல் தோன்றும் ஒரு குற்றச்சாட்டாக அமைகிறது.', 'S'),
  (4, 'A question about whether the version of yourself that is holding back is protecting you from something or costing you something - and the answer is probably both.', 'உங்களை நீங்களே அடக்கி வைத்திருக்கும் அந்தப் பண்பு, உங்களை ஏதேனும் ஒன்றிலிருந்து பாதுகாக்கிறதா அல்லது உங்களுக்கு ஏதேனும் இழப்பை ஏற்படுத்துகிறதா என்பது பற்றிய கேள்வி இது - அதற்கான பதில் அநேகமாக இரண்டுமேயாக இருக்கலாம்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q17',
     'You have just found out that a colleague at your level - same team, same band, roughly the same tenure - is being paid more than you. You found out accidentally. The difference is not small. You are trying to decide what to do with the information.', 'How will you handle this?', 'உங்கள் நிலையில் உள்ள - அதே குழு, அதே படிநிலை, ஏறக்குறைய அதே பணிக்காலம் கொண்ட - ஒரு சக ஊழியர் உங்களை விட அதிக சம்பளம் பெறுகிறார் என்பதை நீங்கள் தற்செயலாகக் கண்டறிந்துள்ளீர்கள். அந்த வித்தியாசம் சிறியதல்ல. இந்தத் தகவலை வைத்து என்ன செய்வதென்று நீங்கள் முடிவு செய்ய முயற்சிக்கிறீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 1", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise it with your manager directly - you have the information and pretending you do not is not something you are willing to do.', 'இதை உங்கள் மேலாளரிடம் நேரடியாகத் தெரிவியுங்கள் - உங்களிடம் தகவல் உள்ளது, தெரியாதது போல் நடிக்க நீங்கள் விரும்ப மாட்டீர்கள்.', 'D'),
  (2, 'You wait until your next review cycle and raise compensation as part of a broader conversation about your trajectory.', 'உங்கள் அடுத்த மதிப்பாய்வுக் காலம் வரை காத்திருந்து, உங்கள் எதிர்காலப் பாதை குறித்த ஒரு விரிவான உரையாடலின் ஒரு பகுதியாக ஊதியத்தை உயர்த்துங்கள்.', 'I'),
  (3, 'You do nothing yet - you do not know the full context and acting on incomplete information could create a bigger problem.', 'நீங்கள் இன்னும் எதுவும் செய்யவில்லை - உங்களுக்கு முழுமையான சூழல் தெரியாது, மேலும் முழுமையற்ற தகவலின் அடிப்படையில் செயல்படுவது ஒரு பெரிய சிக்கலை உருவாக்கக்கூடும்.', 'S'),
  (4, 'You use it as a signal that you need to negotiate more actively going forward - you address it in the next appropriate conversation.', 'இனிவரும் காலங்களில் நீங்கள் இன்னும் தீவிரமாகப் பேச்சுவார்த்தை நடத்த வேண்டும் என்பதற்கான ஒரு சமிக்ஞையாக இதைப் பயன்படுத்துகிறீர்கள் - அடுத்த பொருத்தமான உரையாடலில் இதைப் பற்றிப் பேசுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q18',
     'You have been in the same role for twenty months. You are performing well. Your manager has been supportive but vague about timelines. A recruiter reached out this week about a role that is a level above where you are now. You are not actively looking but you are listening.', 'Should you pursue external opportunities?', 'நீங்கள் இருபது மாதங்களாக ஒரே பதவியில் இருக்கிறீர்கள். உங்கள் பணித்திறன் சிறப்பாக உள்ளது. உங்கள் மேலாளர் ஆதரவாக இருந்தாலும், காலக்கெடுவைப் பற்றித் தெளிவாகக் கூறவில்லை. இந்த வாரம், நீங்கள் தற்போது இருக்கும் பதவிக்கு அடுத்த நிலையில் உள்ள ஒரு வேலை குறித்துப் பணியமர்த்தல் முகவர் ஒருவர் உங்களைத் தொடர்பு கொண்டார். நீங்கள் தீவிரமாக வேலை தேடவில்லை, ஆனால் அவர் சொல்வதைக் கவனித்து வருகிறீர்கள்.', 'நீங்கள் வெளி வாய்ப்புகளை நாட வேண்டுமா?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 1", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You take the conversation - gathering information is not the same as leaving and you owe yourself a sense of what is out there.', 'நீங்கள் அந்த உரையாடலை முன்னெடுத்துச் செல்லுங்கள் - தகவல்களைச் சேகரிப்பதும் அங்கிருந்து வெளியேறுவதும் ஒன்றல்ல, மேலும் வெளியில் என்ன இருக்கிறது என்பதைப் பற்றிய ஒரு புரிதலை நீங்கள் உங்களுக்குள் ஏற்படுத்திக்கொள்ள வேண்டும்.', 'D'),
  (2, 'You tell your manager that you have been approached and use it as a lever to have a direct conversation about your timeline here.', 'உங்களை அணுகியிருப்பதை உங்கள் மேலாளரிடம் தெரிவித்து, அதை ஒரு சாதகமாகப் பயன்படுத்தி, இங்குள்ள உங்கள் காலக்கெடு குறித்து நேரடியாகப் பேசுங்கள்.', 'I'),
  (3, 'You decline - you are not ready to leave and entertaining it feels like a distraction from doing the work that will move you forward here.', 'நீங்கள் மறுக்கிறீர்கள் - நீங்கள் வெளியேறத் தயாராக இல்லை, மேலும் அதைப்பற்றி சிந்திப்பது, இங்கு உங்களை முன்னேற்றும் வேலையைச் செய்வதிலிருந்து ஒரு கவனச்சிதறலாகத் தோன்றுகிறது.', 'S'),
  (4, 'You take the conversation and tell nobody - you want to make the decision with full information before you introduce any variables into your current situation.', 'அந்த உரையாடலை யாரிடமும் சொல்லாமல் நீங்களே நடத்துங்கள் - உங்கள் தற்போதைய சூழ்நிலையில் எந்தவொரு காரணிகளையும் புகுத்துவதற்கு முன்பு, முழுமையான தகவல்களுடன் முடிவெடுக்க விரும்புவீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q19',
     'Two things are pulling at you. Which is stronger? You have worked hard to build a reputation in your team over the past eighteen months. An opportunity has come up in a different department - more stretch, more visibility, higher risk. Taking it means starting over socially and professionally in a new environment.', 'Will you stay or move?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? கடந்த பதினெட்டு மாதங்களாக உங்கள் குழுவில் ஒரு நற்பெயரை உருவாக்க நீங்கள் கடினமாக உழைத்திருக்கிறீர்கள். வேறு ஒரு துறையில் ஒரு வாய்ப்பு வந்துள்ளது - இது அதிக சவாலானது, அதிக கவனத்தை ஈர்க்கக்கூடியது, ஆனால் அதிக இடர் கொண்டது. அதை ஏற்றுக்கொள்வது என்பது, ஒரு புதிய சூழலில் சமூக ரீதியாகவும் தொழில் ரீதியாகவும் புதிதாகத் தொடங்குவதாகும்.', 'நீங்கள் இங்கேயே தங்குவீர்களா அல்லது இடம் மாறுவீர்களா?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 2", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The reputation you have built - you earned it slowly and walking away from it for an uncertain opportunity feels like a gamble you have not fully thought through.', 'நீங்கள் உருவாக்கிய நற்பெயரை மெதுவாகச் சம்பாதித்தீர்கள்; நிச்சயமற்ற ஒரு வாய்ப்புக்காக அதை விட்டு விலகுவது, நீங்கள் முழுமையாகச் சிந்திக்காத ஒரு சூதாட்டம் போலத் தோன்றுகிறது.', 'D'),
  (2, 'The ceiling you can already see - you can tell how this current trajectory ends and it ends below where you want to be.', 'உச்சவரம்பை உங்களால் ஏற்கனவே பார்க்க முடிகிறது - இந்த தற்போதைய பயணப்பாதை எப்படி முடிவடைகிறது என்பதையும், அது நீங்கள் இருக்க விரும்பும் இடத்திற்குக் கீழே முடிவடைகிறது என்பதையும் உங்களால் கூற முடியும்.', 'I'),
  (3, 'The safety of the known - you know what you have here and you do not yet know if the new role will deliver what it is promising.', 'தெரிந்தவற்றின் பாதுகாப்பு - உங்களிடம் இங்கு என்ன இருக்கிறது என்பது உங்களுக்குத் தெரியும், ஆனால் இந்தப் புதிய பதவி அது அளிப்பதாக வாக்குறுதியளிக்கும் பலன்களைத் தருமா என்பது உங்களுக்கு இன்னும் தெரியாது.', 'S'),
  (4, 'The momentum of the move - you know that early career is when risk is cheapest and that waiting for certainty has a cost too.', 'இந்த நகர்வின் உத்வேகம் - தொழில் வாழ்க்கையின் ஆரம்பக் கட்டத்தில்தான் இடர் எடுப்பது மிகவும் குறைவு என்பதும், உறுதிக்காகக் காத்திருப்பதற்கும் ஒரு விலை உண்டு என்பதும் உங்களுக்குத் தெரியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q20',
     'What is actually happening inside you - you are two years in. You know this industry now. You know what good work looks like and you are producing it. But the people making decisions about what comes next for you are still treating you like someone who arrived last quarter. You are sitting with that gap.', 'Why do they underestimate you?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - நீங்கள் இந்தத் துறையில் இரண்டு வருடங்களாக இருக்கிறீர்கள். இப்போது உங்களுக்கு இந்தத் துறை பற்றி நன்கு தெரியும். ஒரு நல்ல வேலை எப்படி இருக்கும் என்பதும் உங்களுக்குத் தெரியும், அதை நீங்கள் செய்து கொண்டும் இருக்கிறீர்கள். ஆனால், உங்களுக்கு அடுத்து என்ன செய்வது என்று முடிவெடுப்பவர்கள், கடந்த காலாண்டில் வந்த ஒருவரைப் போலவே உங்களை இன்னும் நடத்துகிறார்கள். நீங்கள் அந்த இடைவெளியில் தான் இருக்கிறீர்கள்.', 'அவர்கள் உங்களை ஏன் குறைத்து மதிப்பிடுகிறார்கள்?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 3", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'An impatience that you know is dangerous - moving faster than the system allows has a cost and you have seen others pay it.', 'ஆபத்தானது என்று உங்களுக்குத் தெரிந்த ஒரு பொறுமையின்மை - அமைப்பு அனுமதிப்பதை விட வேகமாகச் செயல்படுவதற்கு ஒரு விலை உண்டு, அதை மற்றவர்கள் கொடுப்பதையும் நீங்கள் பார்த்திருக்கிறீர்கள்.', 'D'),
  (2, 'A slow-building conviction that the only way to close the gap is to be so visible and so consistent that the system has no choice but to catch up.', 'இடைவெளியைக் குறைப்பதற்கான ஒரே வழி, நாம் மிகவும் வெளிப்படையாகவும் தொடர்ச்சியாகவும் செயல்படுவதுதான்; அதன் விளைவாக, அமைப்பு வேறு வழியின்றி நம்மைப் பின்தொடர்ந்து வர வேண்டிய நிலைக்குத் தள்ளப்படும் என்ற நம்பிக்கை மெதுவாக வலுப்பெறுகிறது.', 'I'),
  (3, 'A tiredness with having to prove things to people who are not paying close enough attention to see what is already in front of them.', 'தங்கள் கண்முன்னே இருப்பதைப் பார்க்கும் அளவுக்குக் கவனம் செலுத்தாதவர்களுக்கு, விஷயங்களை நிரூபித்துக் கொண்டே இருக்க வேண்டியதால் ஏற்படும் சோர்வு.', 'S'),
  (4, 'A question about whether patience is a virtue here or just a story that benefits the people asking you to wait.', 'இங்கு பொறுமை ஒரு நற்பண்பா அல்லது உங்களைக் காத்திருக்கச் சொல்பவர்களுக்குப் பயனளிக்கும் ஒரு கதையா என்பது குறித்த கேள்வி.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q21',
     'You are from a background that is different from most people on your team - different city, different kind of education, different way of speaking. You are good at your job. But you are aware that some of your references, your humour, your cadence do not always land the way they would with people who grew up in a similar environment to yours.', 'How do you handle differences?', 'உங்கள் குழுவில் உள்ள பெரும்பாலானோரை விட நீங்கள் ஒரு வித்தியாசமான பின்னணியைச் சேர்ந்தவர் - வேறு நகரம், வேறு வகையான கல்வி, வேறு விதமான பேச்சு முறை. உங்கள் வேலையை நீங்கள் சிறப்பாகச் செய்கிறீர்கள். ஆனால், உங்களைப் போன்றே ஒத்த சூழலில் வளர்ந்தவர்களிடம் உங்கள் சில குறிப்புகள், நகைச்சுவை, பேச்சு நடை ஆகியவை எடுபடுவது போல் எப்போதும் எடுபடுவதில்லை என்பதை நீங்கள் உணர்ந்திருக்கிறீர்கள்.', 'கருத்து வேறுபாடுகளை நீங்கள் எவ்வாறு கையாளுகிறீர்கள்?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 1", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You adapt - you are fluent in more than one register and you use whichever one works in the room you are in.', 'நீங்கள் சூழ்நிலைக்கேற்ப மாற்றிக்கொள்கிறீர்கள் - உங்களுக்கு ஒன்றுக்கு மேற்பட்ட பேச்சு நடைகள் சரளமாகத் தெரியும், மேலும் நீங்கள் இருக்கும் சூழலுக்கு எது பொருத்தமாக இருக்கிறதோ அதையே பயன்படுத்துவீர்கள்.', 'D'),
  (2, 'You stay consistent - you are not going to sand down who you are so that people who have never had to adapt feel more comfortable.', 'நீங்கள் உங்கள் இயல்பில் நிலைத்திருங்கள் - இதுவரை தங்களை மாற்றிக்கொள்ள வேண்டிய அவசியம் இல்லாதவர்கள் அதிக சௌகரியமாக உணர்வதற்காக, உங்கள் இயல்பை நீங்கள் ஒருபோதும் மாற்றிக்கொள்ளப் போவதில்லை.', 'I'),
  (3, 'You adapt selectively - you shift in professional settings where it clearly matters and stop performing for contexts where it should not.', 'நீங்கள் தேர்ந்தெடுத்து மாற்றியமைத்துக் கொள்கிறீர்கள் - தெளிவாக முக்கியத்துவம் வாய்ந்த தொழில்முறைச் சூழல்களில் உங்கள் செயல்பாடுகளை மாற்றிக்கொள்கிறீர்கள், தேவையற்ற சூழல்களில் செயல்படுவதை நிறுத்திவிடுகிறீர்கள்.', 'S'),
  (4, 'You are still figuring it out - you do not yet know how much of the adaptation is pragmatic and how much of it is a loss.', 'நீங்கள் இன்னும் அதைப் புரிந்துகொள்ள முயன்றுகொண்டிருக்கிறீர்கள் - அந்தத் தழுவலில் எவ்வளவு பகுதி நடைமுறைக்கு உகந்தது, எவ்வளவு பகுதி இழப்பு என்பது உங்களுக்கு இன்னும் தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q22',
     'You have been invited to a networking dinner the company is hosting. Formal seating, senior people, the kind of event where small talk has stakes. You are not uncomfortable with people but this format - structured, hierarchical, performance-adjacent - is not natural to you.', 'How do you navigate dinner?', 'நிறுவனம் நடத்தும் ஒரு கலந்துரையாடல் இரவு விருந்திற்கு நீங்கள் அழைக்கப்பட்டுள்ளீர்கள். முறைப்படியான இருக்கை ஏற்பாடு, உயர் அதிகாரிகள், சாதாரணப் பேச்சுகளுக்கும் முக்கியத்துவம் உள்ள ஒரு நிகழ்வு. உங்களுக்கு மக்களுடன் பழகுவதில் சங்கடமில்லை, ஆனால் கட்டமைக்கப்பட்ட, படிநிலை சார்ந்த, செயல்திறனை மையமாகக் கொண்ட இந்த வடிவம் உங்களுக்கு இயல்பானதல்ல.', 'இரவு உணவை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 1", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You go, prepare a few conversation angles in advance, and commit to being present even when it feels awkward.', 'நீங்கள் செல்லுங்கள், உரையாடலுக்கான சில கோணங்களை முன்கூட்டியே தயார் செய்துகொள்ளுங்கள், மேலும் சங்கடமாக உணரும்போதும் அங்கு முழுமையாகக் கலந்துகொள்ள உறுதி கொள்ளுங்கள்.', 'D'),
  (2, 'You go and find the one or two people in the room you can have a real conversation with - you let those carry the evening.', 'அந்த அறையில், உங்களால் உண்மையாக உரையாடக்கூடிய ஓரிரு நபர்களைத் தேடிச் செல்லுங்கள் - அந்த மாலைப் பொழுதை அவர்கள் வழிநடத்தட்டும்.', 'I'),
  (3, 'You go and decide in advance that you are not going to perform - you will be warm and professional and that is enough.', 'நீங்கள் நிகழ்ச்சி நடத்தப் போவதில்லை என்று முன்கூட்டியே முடிவு செய்துவிடுங்கள் - நீங்கள் கனிவாகவும் தொழில்முறையாகவும் நடந்துகொள்வதே போதுமானது.', 'S'),
  (4, 'You go and you are more aware of being watched than you want to be - the evening passes fine but it costs you something.', 'நீங்கள் அங்கு செல்லும்போது, ​​நீங்கள் விரும்பாத அளவுக்கு யாரோ உங்களைக் கண்காணிப்பதை உணர்கிறீர்கள் - அந்த மாலைப் பொழுது இனிமையாகக் கழிகிறது, ஆனால் அதற்காக நீங்கள் ஏதோவொன்றை இழக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q23',
     'The conflict you feel most is between - you are starting to receive positive feedback on your work and your presence. People are noticing you. But the version of yourself that is getting noticed is a carefully managed one - considered, polished, strategically visible. You are not sure the real version would land the same way.', 'Which version do you trust?', 'நீங்கள் அதிகமாக உணரும் முரண்பாடு இவற்றுக்கு இடையேதான் உள்ளது: உங்கள் பணிக்கும் உங்கள் இருப்புக்கும் நேர்மறையான கருத்துகள் வரத் தொடங்கியுள்ளன. மக்கள் உங்களைக் கவனிக்கிறார்கள். ஆனால், அவ்வாறு கவனிக்கப்படும் உங்கள் வடிவம், கவனமாக நிர்வகிக்கப்பட்ட ஒன்று - அதாவது, நன்கு சிந்திக்கப்பட்ட, மெருகூட்டப்பட்ட, திட்டமிட்டு வெளிப்படும் ஒன்றாகும். உங்கள் உண்மையான வடிவம் இதேபோல மக்களைச் சென்றடையுமா என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'நீங்கள் எந்தப் பதிப்பை நம்புகிறீர்கள்?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The performance and the person - you are getting good at showing up in a way that works, and you are not sure that is the same as showing up as yourself.', 'செயல்பாடு மற்றும் அந்த நபர் - உங்களுக்குப் பலனளிக்கும் விதத்தில் வெளிப்படுவதில் நீங்கள் தேர்ச்சி பெறுகிறீர்கள், ஆனால் அது நீங்கள் நீங்களாகவே வெளிப்படுவதற்குச் சமமானதா என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'D'),
  (2, 'What is working and what is real - the results are coming but something about the distance between the two versions of you is starting to feel like a cost.', 'எது பலனளிக்கிறது, எது உண்மையானது - முடிவுகள் வரத் தொடங்கியுள்ளன, ஆனால் உங்களின் அந்த இரு வடிவங்களுக்கு இடையிலான இடைவெளி ஏதோவொரு விலையைப் போல உணரத் தொடங்கியுள்ளது.', 'I'),
  (3, 'Staying in the version that is working and risking the version that is true - you do not know yet which one you trust more in this environment.', 'செயல்படும் பதிப்பில் நிலைத்திருப்பதும், உண்மையான பதிப்பை அபாயத்திற்கு உள்ளாக்குவதும் - இந்தச் சூழலில் நீங்கள் எதை அதிகம் நம்புவீர்கள் என்பது உங்களுக்கு இன்னும் தெரியாது.', 'S'),
  (4, 'The short-term gains and the long-term question of who you are at work - you can maintain the performance, but you are not sure you want to do it for the next three years.', 'குறுகிய கால ஆதாயங்கள் மற்றும் பணியிடத்தில் நீங்கள் யார் என்பது குறித்த நீண்ட காலக் கேள்வி - உங்களால் செயல்திறனைத் தக்கவைத்துக் கொள்ள முடியும், ஆனால் அடுத்த மூன்று ஆண்டுகளுக்கு அதைத் தொடர விரும்புகிறீர்களா என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q24',
     'What is actually happening inside you - you have just come out of a social lunch with your team. It was easy and warm and people were laughing. You laughed too. But driving back to the office you notice something - you were on the whole time. Even in the easy moments, you were managing how you were coming across. You have not relaxed in this job yet. Not once.', 'Why can''t you relax yet?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - நீங்கள் இப்போதுதான் உங்கள் குழுவினருடன் ஒரு சமூக மதிய உணவிலிருந்து வெளியே வந்திருக்கிறீர்கள். அது எளிமையாகவும் இதமாகவும் இருந்தது, எல்லோரும் சிரித்துக் கொண்டிருந்தார்கள். நீங்களும் சிரித்தீர்கள். ஆனால், அலுவலகத்திற்குத் திரும்பிக் கொண்டிருக்கும்போது ஒன்றை கவனிக்கிறீர்கள் - நீங்கள் முழு நேரமும் வேலையில் மும்முரமாக இருந்தீர்கள். இயல்பான தருணங்களில்கூட, நீங்கள் மற்றவர்களுக்கு எப்படித் தெரிகிறீர்கள் என்பதைச் சமாளித்துக் கொண்டிருந்தீர்கள். இந்த வேலையில் நீங்கள் இன்னும் சற்றும் ஓய்வெடுக்கவில்லை. ஒருமுறை கூட இல்லை.', 'உங்களால் ஏன் இன்னும் நிம்மதியாக இருக்க முடியவில்லை?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 3", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A recognition that is both clarifying and exhausting - you are performing even in the moments that are supposed to be off.', 'தெளிவுபடுத்தவும் சோர்வடையச் செய்யவும் கூடிய ஒரு புரிதல் - ஓய்வாக இருக்க வேண்டிய தருணங்களில்கூட நீங்கள் சிறப்பாகச் செயல்படுகிறீர்கள்.', 'D'),
  (2, 'A question about whether this is the environment or you - whether you would relax anywhere or whether something specific about this place keeps you in management mode.', 'இது சூழலாலா அல்லது உங்களாலா - நீங்கள் எங்கு வேண்டுமானாலும் நிம்மதியாக உணர்வீர்களா அல்லது இந்த இடத்தைப் பற்றிய ஏதேனும் ஒரு குறிப்பிட்ட விஷயம் உங்களை ஒரு கட்டுப்பாட்டு மனநிலையில் வைத்திருக்கிறதா என்பது குறித்த ஒரு கேள்வி.', 'I'),
  (3, 'A loneliness that has nothing to do with the people at that lunch - they are fine people and you still somehow felt alone the entire time.', 'அந்த மதிய உணவில் இருந்தவர்களுக்கும் இதற்கும் எந்த சம்பந்தமும் இல்லை - அவர்கள் நல்ல மனிதர்கள்தான், ஆனாலும் ஏனோ அந்த நேரம் முழுவதும் நீங்கள் தனிமையாகவே உணர்ந்தீர்கள்.', 'S'),
  (4, 'A tiredness at how much energy the performance takes - and a realisation that the people who are fully themselves here are spending none of this and you cannot figure out how they do it.', 'இந்த நிகழ்ச்சிக்கு எவ்வளவு ஆற்றல் தேவைப்படுகிறது என்பதைக் கண்டு ஏற்படும் சோர்வும், இங்கு முழுமையாகத் தங்களாகவே இருப்பவர்கள் அந்த ஆற்றலில் சிறிதளவைக் கூட செலவிடுவதில்லை என்பதும், அவர்கள் அதை எப்படிச் செய்கிறார்கள் என்று நம்மால் புரிந்துகொள்ள முடியவில்லை என்பதும் புலனாகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q25',
     'Your team is preparing a proposal and your manager has asked you to frame a risk as smaller than you believe it actually is. She says the client does not need the full picture at this stage - it will complicate the conversation. You think the client probably should know.', 'Should you downplay the risk?', 'உங்கள் குழு ஒரு திட்ட முன்மொழிவைத் தயாரித்துக் கொண்டிருக்கிறது. அதில், ஒரு இடரை அது உண்மையில் இருப்பதை விடச் சிறியதாகக் குறிப்பிடுமாறு உங்கள் மேலாளர் உங்களைக் கேட்டுள்ளார். இந்தக் கட்டத்தில் வாடிக்கையாளருக்கு முழுமையான விவரங்கள் தேவையில்லை என்றும், அது உரையாடலைச் சிக்கலாக்கிவிடும் என்றும் அவர் கூறுகிறார். ஆனால், வாடிக்கையாளருக்கு இது தெரிந்திருக்க வேண்டும் என்று நீங்கள் நினைக்கிறீர்கள்.', 'நீங்கள் ஆபத்தைக் குறைத்து மதிப்பிட வேண்டுமா?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell your manager directly that you are uncomfortable framing the risk that way and ask if there is another approach.', 'அந்த இடரை அவ்வாறு விவரிப்பதில் உங்களுக்கு அசௌகரியமாக இருப்பதாக உங்கள் மேலாளரிடம் நேரடியாகக் கூறி, வேறு அணுகுமுறை ஏதேனும் உள்ளதா என்று கேளுங்கள்.', 'D'),
  (2, 'You write the section the way she asked - she has more context about the client relationship than you do.', 'அவள் கேட்டபடியே அந்தப் பகுதியை எழுதுங்கள் - உங்களை விட வாடிக்கையாளர் உறவைப் பற்றி அவளுக்கு அதிகப் பின்னணித் தகவல் தெரியும்.', 'I'),
  (3, 'You write it her way but flag in your notes that the risk was downplayed - you want a record of what you knew and when.', 'அவள் சொன்னபடியே நீங்கள் எழுதுங்கள், ஆனால் ஆபத்து குறைத்துக் காட்டப்பட்டது என்பதை உங்கள் குறிப்புகளில் குறித்து வையுங்கள் - உங்களுக்கு என்ன தெரியும், எப்போது தெரியும் என்பதற்கான ஒரு பதிவு வேண்டும்.', 'S'),
  (4, 'You ask her a clarifying question - you want to understand her reasoning before you decide whether to push back.', 'நீங்கள் அவரிடம் ஒரு தெளிவுபடுத்தும் கேள்வியைக் கேட்கிறீர்கள் - எதிர்த்துப் பேசுவதா வேண்டாமா என்று தீர்மானிப்பதற்கு முன், அவருடைய வாதத்தின் பின்னணியைப் புரிந்துகொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q26',
     'You are in a team meeting and a decision is announced that you know is based on incorrect data - you worked on the underlying analysis and the numbers being cited are from a draft that was superseded. Nobody else in the room seems to know this.', 'How handle incorrect data decisions?', 'நீங்கள் ஒரு குழு கூட்டத்தில் இருக்கிறீர்கள், அப்போது தவறான தரவுகளின் அடிப்படையில் எடுக்கப்பட்ட முடிவு ஒன்று அறிவிக்கப்படுகிறது. அதன் அடிப்படைப் பகுப்பாய்வில் நீங்கள் பணியாற்றியிருந்தீர்கள், ஆனால் மேற்கோள் காட்டப்படும் எண்கள், ஏற்கெனவே மாற்றப்பட்ட ஒரு வரைவிலிருந்து எடுக்கப்பட்டவை. அறையில் உள்ள வேறு யாருக்கும் இது தெரிந்ததாகத் தெரியவில்லை.', 'தவறான தரவு முடிவுகளை எவ்வாறு கையாள்வது?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise it in the room - the decision is based on wrong data and that needs to be corrected before it goes any further.', 'நீங்கள் இதை அவையில் எழுப்புகிறீர்கள் - இந்த முடிவு தவறான தரவுகளின் அடிப்படையில் எடுக்கப்பட்டுள்ளது, மேலும் இது அடுத்தகட்டத்திற்குச் செல்வதற்கு முன்பு சரிசெய்யப்பட வேண்டும்.', 'D'),
  (2, 'You wait until the meeting ends and speak to your manager privately - you do not want to undermine the person who made the announcement publicly.', 'கூட்டம் முடியும் வரை காத்திருந்து உங்கள் மேலாளரிடம் தனிப்பட்ட முறையில் பேசுங்கள் - பொதுவெளியில் அறிவிப்பை வெளியிட்ட நபரின் முக்கியத்துவத்தைக் குறைக்க நீங்கள் விரும்ப மாட்டீர்கள்.', 'I'),
  (3, 'You send a message to your manager under the table asking if she knows which version the numbers came from.', 'அந்த எண்கள் எந்தப் பதிப்பிலிருந்து வந்தன என்று அவருக்குத் தெரியுமா எனக் கேட்டு, உங்கள் மேலாளருக்கு மறைமுகமாக ஒரு செய்தியை அனுப்புகிறீர்கள்.', 'S'),
  (4, 'You raise it carefully in the room - you frame it as a question about which version was used rather than a correction.', 'நீங்கள் அதை அறையில் கவனமாக எழுப்புகிறீர்கள் - அதை ஒரு திருத்தமாகக் கூறாமல், எந்தப் பதிப்பு பயன்படுத்தப்பட்டது என்பது பற்றிய கேள்வியாக முன்வைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q27',
     'What matters more to you in this moment? You have been copied on an email chain that contains information you were not meant to see - a conversation about compensation decisions for your team including your own. You now have context that changes how you read your last performance review.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? நீங்கள் பார்க்கக் கூடாத தகவல்களைக் கொண்ட ஒரு மின்னஞ்சல் தொடரில் நீங்களும் இணைக்கப்பட்டுள்ளீர்கள் - அது, உங்கள் சொந்த ஊதியம் உட்பட, உங்கள் குழுவினருக்கான ஊதிய முடிவுகள் பற்றிய ஒரு உரையாடல். உங்கள் கடைசி செயல்திறன் மதிப்பாய்வை நீங்கள் பார்க்கும் விதத்தை மாற்றக்கூடிய ஒரு பின்னணி இப்போது உங்களுக்குக் கிடைத்துள்ளது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 2", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Using the information - you know what you know and pretending otherwise means operating at a disadvantage you did not choose.', 'தகவலைப் பயன்படுத்துங்கள் - உங்களுக்குத் தெரிந்ததை நீங்கள் அறிவீர்கள், அதற்கு மாறாகப் பாசாங்கு செய்வது என்பது நீங்கள் தேர்ந்தெடுக்காத ஒரு பாதகமான நிலையில் செயல்படுவதற்குச் சமமாகும்.', 'D'),
  (2, 'Disclosing that you saw it - staying quiet feels like a form of deception even if the mistake was not yours.', 'நீங்கள் அதைப் பார்த்ததை வெளிப்படுத்துவது - தவறு உங்களுடையதாக இல்லாவிட்டாலும் அமைதியாக இருப்பது ஒரு வகையான ஏமாற்றுதல் போலத் தோன்றுகிறது.', 'I'),
  (3, 'Protecting yourself first - you will not act on the information directly but you are not going to forget it either.', 'முதலில் உங்களைப் பாதுகாத்துக் கொள்ளுங்கள் - நீங்கள் அந்தத் தகவலின்படி நேரடியாகச் செயல்பட மாட்டீர்கள், ஆனால் அதை மறந்துவிடவும் மாட்டீர்கள்.', 'S'),
  (4, 'Doing nothing - getting involved in something you were accidentally included in is a risk with no clear upside.', 'ஒன்றும் செய்யாமல் இருப்பது - தற்செயலாக நீங்கள் சம்பந்தப்பட்ட ஒரு விஷயத்தில் ஈடுபடுவது என்பது, தெளிவான நன்மை ஏதுமில்லாத ஒரு ஆபத்து.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q28',
     'The honest feeling underneath this - you said yes to something last week that you should have said no to. Not something dramatic - you agreed to put your name on a piece of work you reviewed but did not produce, because saying no felt harder than the alternative. The work has since been praised.', 'What is your honest feeling?', 'இதன் அடிப்படையிலான நேர்மையான உணர்வு இதுதான் - கடந்த வாரம் நீங்கள் வேண்டாம் என்று சொல்லியிருக்க வேண்டிய ஒரு விஷயத்திற்கு ஆம் என்று சொல்லிவிட்டீர்கள். இது ஒன்றும் பெரிய விஷயமல்ல - நீங்கள் மதிப்பாய்வு செய்து, ஆனால் உருவாக்காத ஒரு படைப்பில் உங்கள் பெயரைச் சேர்க்க ஒப்புக்கொண்டீர்கள், ஏனெனில் வேண்டாம் என்று சொல்வது, அதற்கு மாற்று வழியை விடக் கடினமாகத் தோன்றியது. அந்தப் படைப்பு அதன் பிறகு பாராட்டப்பட்டது.', 'உங்கள் உண்மையான உணர்வு என்ன?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 3", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A discomfort that is still there - the praise made it worse, not better, because now there is something to lose if the truth comes out.', 'அந்த சங்கடம் இன்னமும் இருக்கிறது - அந்தப் பாராட்டு நிலைமையைச் சரிசெய்யாமல், இன்னும் மோசமாக்கியது; ஏனென்றால், உண்மை வெளிவந்தால் இப்போது இழப்பதற்கு ஒன்று இருக்கிறது.', 'D'),
  (2, 'A rationalisation you have been running - you contributed enough to justify your name on it, and you keep tweaking the definition of enough to make it fit.', 'நீங்கள் கூறிவரும் ஒரு நியாயப்படுத்தல் இது - அதில் உங்கள் பெயர் இடம்பெறுவதை நியாயப்படுத்தும் அளவுக்கு நீங்கள் பங்களித்திருக்கிறீர்கள், மேலும் அது பொருந்தும்படி ''போதுமானது'' என்பதன் வரையறையைத் தொடர்ந்து மாற்றிக்கொண்டே இருக்கிறீர்கள்.', 'I'),
  (3, 'A quiet shame that you are trying not to dramatise - it was a small thing and you know it will not be the last time you are put in that position.', 'நீங்கள் இதை பெரிதுபடுத்தாமல் இருக்க முயற்சிப்பது ஒருவிதத்தில் வருத்தமளிக்கிறது - அது ஒரு சிறிய விஷயம்தான், மேலும் நீங்கள் இதுபோன்ற ஒரு சூழ்நிலையில் தள்ளப்படுவது இதுவே கடைசி முறையாக இருக்காது என்பதும் உங்களுக்குத் தெரியும்.', 'S'),
  (4, 'An irritation at the situation more than at yourself - you were put in a position where honesty had a cost and compliance had a reward, and the system did that, not you.', 'உங்களை விட அந்தச் சூழ்நிலையின் மீதே எரிச்சல் - நேர்மைக்கு விலையும், இணக்கத்திற்கு வெகுமதியும் கிடைக்கும் ஒரு நிலையில் நீங்கள் தள்ளப்பட்டீர்கள்; அதைச் செய்தது அமைப்புதான், நீங்கள் அல்ல.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q29',
     'You need to tell your manager that a deadline she communicated to the client is not achievable. You found out this afternoon. The commitment was made without consulting you and you are the one who has to deliver the work.', 'How do handle unachievable deadlines?', 'வாடிக்கையாளரிடம் அவர் தெரிவித்த காலக்கெடுவை நிறைவேற்ற முடியாது என்பதை உங்கள் மேலாளரிடம் நீங்கள் தெரிவிக்க வேண்டும். இன்று மதியம்தான் இது உங்களுக்குத் தெரியவந்தது. உங்களிடம் கலந்தாலோசிக்காமல் அந்த வாக்குறுதி அளிக்கப்பட்டுள்ளது, மேலும் அந்த வேலையை நீங்கள்தான் செய்து முடிக்க வேண்டும்.', 'நிறைவேற்ற முடியாத காலக்கெடுவை எவ்வாறு கையாள்வது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 1", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You go to her directly as soon as possible - the earlier she knows, the more options she has, and softening it does not help either of you.', 'நீங்கள் கூடிய விரைவில் அவளிடம் நேரடியாகச் செல்லுங்கள் - அவளுக்கு எவ்வளவு சீக்கிரம் தெரிய வருகிறதோ, அவ்வளவு அதிக வாய்ப்புகள் அவளுக்கு இருக்கும், மேலும் விஷயத்தை மென்மையாக்குவது உங்கள் இருவருக்கும் உதவாது.', 'D'),
  (2, 'You think through what is achievable before you say anything - you want to walk in with a revised timeline, not just a problem.', 'எதையும் சொல்வதற்கு முன், எதைச் சாதிக்க முடியும் என்பதை நன்கு யோசித்துப் பாருங்கள் - நீங்கள் ஒரு சிக்கலை மட்டும் முன்வைக்காமல், திருத்தப்பட்ட கால அட்டவணையுடன் உள்ளே செல்ல வேண்டும்.', 'I'),
  (3, 'You send a written message outlining the gap and your recommended alternative - you want the conversation grounded in something concrete.', 'இடைவெளியையும் நீங்கள் பரிந்துரைக்கும் மாற்று வழியையும் கோடிட்டுக் காட்டி ஒரு எழுத்துப்பூர்வ செய்தியை அனுப்புகிறீர்கள் - அந்த உரையாடல் ஒரு உறுதியான விஷயத்தின் அடிப்படையில் அமைய வேண்டும் என நீங்கள் விரும்புகிறீர்கள்.', 'S'),
  (4, 'You raise it carefully, acknowledging that she may have had reasons for the timeline you were not aware of, before getting to your concern.', 'உங்கள் கவலையை வெளிப்படுத்துவதற்கு முன், உங்களுக்குத் தெரியாத காலக்கெடுவிற்கு அவளிடம் காரணங்கள் இருந்திருக்கலாம் என்பதை ஏற்றுக்கொண்டு, நீங்கள் அதை கவனமாக எழுப்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q30',
     'You have been asked to write a company-wide update on a project you are part of. The project has had delays. Your manager wants the update to sound positive. You think an honest update serves the audience better than a managed one.', 'How do you update delays?', 'நீங்கள் அங்கம் வகிக்கும் ஒரு திட்டம் குறித்து, நிறுவனம் முழுவதற்குமான ஒரு அறிக்கை எழுதுமாறு கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள். அந்தத் திட்டத்தில் தாமதங்கள் ஏற்பட்டுள்ளன. அந்த அறிக்கை நேர்மறையாக இருக்க வேண்டும் என உங்கள் மேலாளர் விரும்புகிறார். திட்டமிட்டு உருவாக்கப்பட்ட அறிக்கையை விட, ஒரு நேர்மையான அறிக்கை பார்வையாளர்களுக்குச் சிறந்த பயனைத் தரும் என்று நீங்கள் கருதுகிறீர்கள்.', 'தாமதங்களை எவ்வாறு புதுப்பிப்பது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 1", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You write the version your manager asked for - she owns the communication and this is her call to make.', 'உங்கள் மேலாளர் கேட்ட பதிப்பை நீங்கள் எழுதுங்கள் - இந்தத் தகவல்தொடர்புக்கு அவரே பொறுப்பு, மேலும் இது அவர் எடுக்க வேண்டிய முடிவு.', 'D'),
  (2, 'You write an honest version and share it with her before sending - you let her see what you think the update should say before the conversation about what it will say.', 'நீங்கள் ஒரு நேர்மையான பதிப்பை எழுதி, அனுப்புவதற்கு முன் அதை அவளுடன் பகிர்ந்துகொள்ளுங்கள் - அதாவது, அந்தப் புதுப்பிப்பில் என்ன இருக்க வேண்டும் என்பது பற்றிய உரையாடலுக்கு முன்பாகவே, அது எப்படி இருக்க வேண்டும் என்று நீங்கள் நினைப்பதை அவளுக்குக் காட்டுங்கள்.', 'I'),
  (3, 'You write a version that is accurate but frames the delays with context and a clear forward plan - honest without being unnecessarily bleak.', 'நீங்கள் எழுதும் இந்தத் திட்டம் துல்லியமானதாக இருப்பதுடன், தாமதங்களுக்கான காரணங்களைச் சூழலுடனும் தெளிவான எதிர்காலத் திட்டத்துடனும் எடுத்துரைக்கிறது; தேவையற்ற விரக்தியை ஏற்படுத்தாமல் நேர்மையாகவும் இருக்கிறது.', 'S'),
  (4, 'You tell her directly that you think the managed version will damage trust if the delays become visible later, and you ask her to reconsider.', 'பிற்காலத்தில் தாமதங்கள் வெளிப்பட்டால், நிர்வகிக்கப்பட்ட பதிப்பு நம்பிக்கையைச் சேதப்படுத்தும் என்று நீங்கள் அவரிடம் நேரடியாகக் கூறி, அதை மறுபரிசீலனை செய்யுமாறு கேட்டுக்கொள்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q31',
     'Two things are pulling at you. Which is stronger? You are about to send a message to a senior person asking for something - an introduction, a meeting, a favour. You have drafted it four times. Each version either sounds too transactional or too eager. You know what you want to say. You cannot find the voice to say it in.', 'What matters most to you?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. எது வலிமையானது? நீங்கள் ஒரு உயர் அதிகாரியிடம் அறிமுகம், சந்திப்பு, உதவி என எதையோ கேட்டு ஒரு செய்தி அனுப்பப் போகிறீர்கள். அதை நான்கு முறை வரைவு செய்துள்ளீர்கள். ஒவ்வொரு வடிவமும் ஒன்று அதிகப்படியான பேரம் பேசுவது போலவோ அல்லது அதிக ஆர்வம் காட்டுவது போலவோ ஒலிக்கிறது. நீங்கள் என்ன சொல்ல விரும்புகிறீர்கள் என்பது உங்களுக்குத் தெரியும். ஆனால் அதைச் சொல்வதற்கான குரல் உங்களுக்குக் கிடைக்கவில்லை.', 'உங்களுக்கு மிகவும் முக்கியமானது எது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 2", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Getting it sent - the perfect message is the enemy of the sent one and you are losing time to anxiety about tone.', 'அதை அனுப்புவதில் உள்ள சிக்கல் என்னவென்றால், ஒரு கச்சிதமான செய்தி என்பது அனுப்பப்பட்ட செய்திக்கு எதிரி, மேலும் அதன் தொனியைப் பற்றிய கவலையில் நீங்கள் நேரத்தை வீணடிக்கிறீர்கள்.', 'D'),
  (2, 'Getting it right - a misjudged message to this person could close a door that would otherwise be open, and that risk is real.', 'சரியாகச் செய்வது - இந்த நபருக்கு அனுப்பப்படும் ஒரு தவறான செய்தி, இல்லையெனில் திறந்திருக்கும் ஒரு கதவை மூடிவிடக்கூடும், மேலும் அந்த ஆபத்து உண்மையானது.', 'I'),
  (3, 'Being honest about what you want - every polished version sounds like someone other than you and the real version might actually land better.', 'உங்களுக்கு என்ன வேண்டும் என்பதில் நேர்மையாக இருங்கள் - மெருகேற்றப்பட்ட ஒவ்வொரு வடிவமும் உங்களைத் தவிர வேறு யாரோ பேசுவது போல் ஒலிக்கும், மேலும் உண்மையான வடிவம் உண்மையில் சிறப்பாக அமையக்கூடும்.', 'S'),
  (4, 'Managing their impression of you - this message is the first data point they will have about who you are, and first impressions at this level matter.', 'உங்களைப் பற்றிய அவர்களின் அபிப்பிராயத்தை நிர்வகித்தல் - நீங்கள் யார் என்பதைப் பற்றி அவர்கள் பெறும் முதல் தகவல் இந்தச் செய்திதான், மேலும் இந்த மட்டத்தில் ஏற்படும் முதல் அபிப்பிராயங்கள் முக்கியமானவை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q32',
     'Before you say anything - you are in a meeting and your manager has just said something that is factually incorrect about your work. Not critically wrong - but wrong in a way that slightly diminishes what you actually produced. It was a passing comment. The meeting has already moved on. You are still in the room.', 'Should you correct your manager?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - நீங்கள் ஒரு கூட்டத்தில் இருக்கிறீர்கள், உங்கள் மேலாளர் உங்கள் வேலையைப் பற்றி உண்மையில் தவறான ஒன்றைச் சொல்லிவிட்டார். அது கடுமையாகத் தவறானதல்ல - ஆனால் நீங்கள் உண்மையில் உருவாக்கியதைச் சற்றுக் குறைத்து மதிப்பிடும் விதத்தில் தவறானது. அது ஒரு சாதாரணக் கருத்து. கூட்டம் அதற்குள் முடிந்துவிட்டது. நீங்கள் இன்னும் அந்த அறையில்தான் இருக்கிறீர்கள்.', 'உங்கள் மேலாளரை நீங்கள் திருத்த வேண்டுமா?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 3", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A calculation running quietly - whether correcting it now costs more than letting it stand, and which version of you each choice produces.', 'அமைதியாக நடந்துகொண்டிருக்கும் ஒரு கணக்கீடு - அதை இப்போது சரிசெய்வதற்கு ஆகும் செலவு, அப்படியே விட்டுவிடுவதை விட அதிகமாகுமா என்பதையும், ஒவ்வொரு தேர்வும் உங்களின் எந்தப் பதிப்பை உருவாக்கும் என்பதையும் பற்றியது.', 'D'),
  (2, 'A low heat that is not quite anger - you know this was not deliberate and you still cannot make it feel like it does not matter.', 'முழுமையான கோபம் இல்லாத ஒரு மிதமான சூடு - இது வேண்டுமென்றே செய்யப்படவில்லை என்பது உங்களுக்குத் தெரியும், ஆனாலும் அது ஒரு பொருட்டல்ல என்பது போல உங்களால் காட்டிக்கொள்ள முடியாது.', 'I'),
  (3, 'A recognition of your own pattern - you have let small corrections go before and they accumulate into a version of your work that is slightly less than what it was.', 'உங்கள் சொந்தப் போக்கை நீங்களே உணர்ந்துகொள்வது - இதற்கு முன்பும் நீங்கள் செய்த சிறு திருத்தங்களைக் கவனிக்காமல் விட்டுவிட்டீர்கள், அவை சேர்ந்து உங்கள் படைப்பின் முந்தைய வடிவத்தை விடச் சற்றுத் தரம் குறைந்த ஒரு பதிப்பாக உருவாகிவிட்டன.', 'S'),
  (4, 'A tiredness at having to decide whether to speak - the fact that this is a calculation at all is the part that wears you down.', 'பேசுவதா வேண்டாமா என்று முடிவெடுக்க வேண்டிய சோர்வு - இதை ஒரு கணக்கீடாகவே பார்க்க வேண்டியிருக்கிறது என்பதே நம்மைச் சோர்வடையச் செய்யும் விஷயம்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q33',
     'Your team has agreed on an approach to a project and work has already begun. You have since found a piece of information that changes the picture - the approach you are taking is likely to produce the wrong outcome. Raising it now means reopening a decision the team has already moved past.', 'How do you handle this?', 'உங்கள் குழு ஒரு திட்டத்திற்கான அணுகுமுறையை ஒப்புக்கொண்டு, பணியும் ஏற்கனவே தொடங்கிவிட்டது. அதன் பிறகு, நிலைமையையே மாற்றக்கூடிய ஒரு தகவலை நீங்கள் கண்டறிந்துள்ளீர்கள் - நீங்கள் கையாளும் அணுகுமுறை தவறான விளைவை ஏற்படுத்தக்கூடும். இப்போது இதை எழுப்புவது என்பது, குழு ஏற்கனவே கடந்துவிட்ட ஒரு முடிவை மீண்டும் திறப்பதாகும்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise it immediately with the full team - the cost of continuing in the wrong direction is higher than the cost of revisiting a closed decision.', 'நீங்கள் அதை உடனடியாக முழு குழுவிடமும் தெரிவிக்க வேண்டும் - தவறான திசையில் தொடர்ந்து செல்வதற்கான விலையானது, எடுக்கப்பட்ட ஒரு முடிவை மறுபரிசீலனை செய்வதற்கான விலையை விட அதிகம்.', 'D'),
  (2, 'You go to your manager first and let her decide whether and how to bring it back to the team.', 'நீங்கள் முதலில் உங்கள் மேலாளரிடம் சென்று, அதை அணியிடம் கொண்டு செல்வதா, கொண்டு சென்றால் எப்படி கொண்டு செல்வது என்பதை அவரே தீர்மானிக்கட்டும்.', 'I'),
  (3, 'You raise it in the next team check-in - you want to surface it in a structured moment rather than disrupting the flow mid-work.', 'அடுத்த குழு சந்திப்பின்போது நீங்கள் அதைப் பற்றிப் பேசலாம் - வேலையின் நடுவில் அதன் ஓட்டத்தைச் சீர்குலைப்பதை விட, ஒரு கட்டமைக்கப்பட்ட தருணத்தில் அதை வெளிக்கொணர வேண்டும்.', 'S'),
  (4, 'You document what you found and flag it to one trusted colleague before deciding whether to take it further.', 'நீங்கள் கண்டறிந்தவற்றை ஆவணப்படுத்தி, அதை மேற்கொண்டு கொண்டு செல்வதா வேண்டாமா என முடிவெடுப்பதற்கு முன், நம்பகமான ஒரு சக ஊழியரிடம் தெரிவிக்கவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q34',
     'You are in a cross-functional working group with people from four different teams. The group has been running for six weeks. There is no clear owner and nothing is moving. Everyone is waiting for someone else to drive. You are the most junior person in the group.', 'How do you handle this?', 'நீங்கள் நான்கு வெவ்வேறு அணிகளைச் சேர்ந்தவர்களுடன் ஒரு பல்துறைப் பணிக்குழுவில் இருக்கிறீர்கள். அந்தக் குழு ஆறு வாரங்களாக இயங்கி வருகிறது. அதற்குத் தெளிவான பொறுப்பாளர் யாரும் இல்லை, எந்தப் பணியும் முன்னேறவில்லை. அனைவரும் அடுத்தவர் பொறுப்பேற்று வழிநடத்துவார் என்று காத்துக் கொண்டிருக்கிறார்கள். அந்தக் குழுவில் நீங்கள்தான் மிகவும் இளையவர்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You volunteer to take on the coordination role - someone has to and you would rather be the one doing it than the one watching it not happen.', 'ஒருங்கிணைப்புப் பொறுப்பை ஏற்க நீங்கள் முன்வருகிறீர்கள் - யாராவது ஒருவர் அந்தப் பொறுப்பை ஏற்கத்தான் வேண்டும்; அது நடக்காமல் பார்த்துக் கொண்டிருப்பதை விட, நீங்களே அதைச் செய்வதையே விரும்புவீர்கள்.', 'D'),
  (2, 'You name the gap in the next meeting - you say directly that the group needs someone to own the process and ask how the group wants to handle it.', 'அடுத்த கூட்டத்தில் உள்ள குறையை நீங்கள் சுட்டிக்காட்டுங்கள் - அந்தச் செயல்முறையை முன்னெடுத்துச் செல்ல ஒரு குழுவுக்கு ஒருவர் தேவை என்று நேரடியாகக் கூறி, அதை அக்குழு எவ்வாறு கையாள விரும்புகிறது என்றும் கேளுங்கள்.', 'I'),
  (3, 'You raise it with your manager and ask whether it is appropriate for you to step into a coordination role given your level.', 'உங்கள் மேலாளரிடம் இதைக் கூறி, உங்கள் தகுதிக்கு ஏற்ப ஒருங்கிணைப்புப் பொறுப்பை ஏற்பது பொருத்தமானதா என்று கேளுங்கள்.', 'S'),
  (4, 'You keep showing up and doing your part - taking on coordination without a mandate risks overstepping and you are watching to see if someone else picks it up first.', 'நீங்கள் தொடர்ந்து வந்து உங்கள் பங்கைச் செய்யுங்கள் - அதிகார ஆணை இல்லாமல் ஒருங்கிணைப்புப் பொறுப்பை ஏற்பது வரம்பு மீறுவதற்கு வழிவகுக்கும், மேலும் வேறு யாராவது அதை முதலில் எடுத்துக்கொள்கிறார்களா என்பதையும் நீங்கள் கவனித்துக் கொண்டிருக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q35',
     'The conflict you feel most is between - you are on a team that functions well but has a strong in-group culture. People who fit the mould thrive. You are effective but you have noticed that the people who get the most interesting work share a particular style, background, and way of operating that is not quite yours.', 'How navigate team culture conflict?', 'நீங்கள் அதிகமாக உணரும் முரண்பாடு இதுதான் - நீங்கள் சிறப்பாகச் செயல்படும் ஒரு குழுவில் இருக்கிறீர்கள், ஆனால் அங்கு வலுவான குழு மனப்பான்மை நிலவுகிறது. அந்தப் பொதுவான வரையறைக்குள் பொருந்துபவர்கள் சிறப்பாகச் செயல்படுகிறார்கள். நீங்கள் திறம்படச் செயல்படுகிறீர்கள், ஆனால் மிகவும் சுவாரஸ்யமான பணிகளைப் பெறும் நபர்கள், உங்களது பாணி, பின்னணி மற்றும் செயல்பாட்டு முறையிலிருந்து முற்றிலும் மாறுபட்ட ஒரு குறிப்பிட்ட பாணியைப் பகிர்ந்து கொள்கிறார்கள் என்பதை நீங்கள் கவனித்திருக்கிறீர்கள்.', 'குழு கலாச்சார முரண்பாடுகளை எவ்வாறு கையாள்வது?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Adapting enough to access what the in-group has and staying enough of yourself to know you did not disappear to get it.', 'உள் குழுவினரிடம் உள்ளவற்றை அணுகும் அளவுக்குத் தகவமைத்துக் கொள்வதும், அதைப் பெறுவதற்காக நீங்கள் மறைந்துவிடவில்லை என்பதை உணரும் அளவுக்கு உங்கள் இயல்பைத் தக்கவைத்துக் கொள்வதும்.', 'D'),
  (2, 'Pushing against it and accepting the cost - the culture is what it is but you are not going to perform your way into belonging somewhere that should not require a performance.', 'அதை எதிர்த்துப் போராடுவதும், அதற்கான விலையை ஏற்றுக்கொள்வதும் - கலாச்சாரம் அதன் இயல்பில் இருக்கிறது, ஆனால் எந்தவிதமான நடிப்பும் தேவைப்படாத ஓர் இடத்தில், உங்கள் நடிப்பால் நீங்கள் ஓர் இடத்தைப் பிடித்துக்கொள்ளப் போவதில்லை.', 'I'),
  (3, 'Understanding it before judging it - you do not yet know if this is bias, chemistry, or something else, and acting before you are sure is its own kind of risk.', 'தீர்ப்பளிக்கும் முன் அதைப்புரிந்துகொள்வது - இது ஒருதலைப்பட்சமானதா, ஈர்ப்பா, அல்லது வேறு ஏதேனுமா என்பது உங்களுக்கு இன்னும் தெரியாது, மேலும் உறுதியாகத் தெரிவதற்கு முன்பே செயல்படுவது என்பது அதற்கே உரிய ஒரு வகையான ஆபத்துதான்.', 'S'),
  (4, 'Finding the version of this you can live with long-term - because if it does not change, you need to decide what staying actually means.', 'இதில் நீங்கள் நீண்ட காலத்திற்கு ஏற்றுக்கொள்ளக்கூடிய ஒரு வடிவத்தைக் கண்டறியுங்கள் - ஏனெனில், அது மாறவில்லை என்றால், இங்கேயே தங்கியிருப்பதன் உண்மையான அர்த்தம் என்ன என்பதை நீங்கள் தீர்மானிக்க வேண்டியிருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q36',
     'What is actually happening inside you - you have just had a team offsite. Two days, shared meals, structured activities, informal evenings. You were present for all of it. People were warm. You did fine. But on the way home you are aware that you do not feel any closer to this team than you did before you left.', 'Why do I feel disconnected?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - நீங்கள் சமீபத்தில் ஒரு குழுப் பயணத்தை முடித்துவிட்டு வந்திருக்கிறீர்கள். இரண்டு நாட்கள், ஒன்றாக உணவு உண்டது, திட்டமிடப்பட்ட செயல்பாடுகள், முறைசாரா மாலைப் பொழுதுகள். நீங்கள் அனைத்திலும் கலந்துகொண்டீர்கள். மக்கள் அன்பாக இருந்தார்கள். நீங்கள் நன்றாகவே இருந்தீர்கள். ஆனால், வீடு திரும்பும் வழியில், புறப்படுவதற்கு முன்பு இருந்ததை விட இந்தக் குழுவுடன் நீங்கள் எந்த நெருக்கத்தையும் உணரவில்லை என்பதை உணர்கிறீர்கள்.', 'நான் ஏன் அந்நியமாக உணர்கிறேன்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A disappointment that you are trying not to turn into a conclusion - two days is not enough to change something that has been building for months.', 'நீங்கள் ஒரு முடிவாக மாற்றிவிட விரும்பாத ஒரு ஏமாற்றம் - மாதக்கணக்கில் உருவாகி வந்த ஒன்றை மாற்றுவதற்கு இரண்டு நாட்கள் போதாது.', 'D'),
  (2, 'A question about whether the distance is about them or about you - and an honest suspicion that the answer is not entirely comfortable.', 'இந்த இடைவெளி அவர்களைப் பற்றியதா அல்லது உங்களைப் பற்றியதா என்ற ஒரு கேள்வி - மற்றும் அதற்கான பதில் முழுமையாக ஆறுதலானதாக இருக்காது என்ற ஒரு நேர்மையான சந்தேகம்.', 'I'),
  (3, 'A resignation - you have been trying to build real connection in this team for a year and you are starting to think the environment is not set up for it.', 'ராஜினாமா - நீங்கள் ஒரு வருடமாக இந்தக் குழுவில் உண்மையான பிணைப்பை உருவாக்க முயற்சி செய்து வருகிறீர்கள், ஆனால் அதற்கான சூழல் இங்கு இல்லை என்று நினைக்கத் தொடங்கிவிட்டீர்கள்.', 'S'),
  (4, 'A loneliness that the offsite made louder rather than quieter - you were surrounded by people trying to connect and you still felt on the outside of something.', 'அந்த வெளிக்களச் சந்திப்பு, தனிமையை அமைதிப்படுத்துவதற்குப் பதிலாக மேலும் உரக்க ஒலிக்கச் செய்தது - உங்களைச் சுற்றி மற்றவர்களுடன் இணைய முயன்ற மக்கள் இருந்தபோதிலும், நீங்கள் ஏதோவொன்றிலிருந்து விலகி இருப்பது போன்ற உணர்வு இருந்தது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q37',
     'You are in your second year and you have developed a reputation for being reliable. You are the person people come to when something needs to get done. A senior colleague has just asked you to take on something significant - outside your role - because she trusts you to handle it. You are already at capacity.', 'Should you accept additional work?', 'நீங்கள் உங்கள் இரண்டாம் ஆண்டில் இருக்கிறீர்கள், மேலும் நம்பகமானவர் என்ற நற்பெயரைப் பெற்றுள்ளீர்கள். ஒரு வேலையைச் செய்து முடிக்க வேண்டியிருக்கும் போது, ​​மக்கள் நாடி வரும் நபர் நீங்கள்தான். ஒரு மூத்த சக ஊழியர், உங்கள் பொறுப்புக்கு அப்பாற்பட்ட ஒரு முக்கியமான வேலையை ஏற்றுக்கொள்ளும்படி உங்களிடம் கேட்டிருக்கிறார்; ஏனெனில், அதை உங்களால் கையாள முடியும் என்று அவர் நம்புகிறார். நீங்கள் ஏற்கெனவே உங்கள் முழுத் திறனுக்கும் உட்பட்டிருக்கிறீர்கள்.', 'நீங்கள் கூடுதல் வேலையை ஏற்றுக்கொள்ள வேண்டுமா?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell her honestly that you are at capacity and ask if the timeline has any flexibility or if it can go to someone else.', 'உங்களிடம் போதுமான வசதிகள் இல்லை என்பதை அவளிடம் நேர்மையாகக் கூறி, காலக்கெடுவில் ஏதேனும் நெகிழ்வுத்தன்மை உள்ளதா அல்லது அந்த வாய்ப்பை வேறு ஒருவருக்கு வழங்க முடியுமா என்று கேளுங்கள்.', 'D'),
  (2, 'You say yes - being trusted at this level is exactly what you have been working toward and turning it down feels like a step backward.', 'நீங்கள் சம்மதம் தெரிவிக்கிறீர்கள் - இந்த அளவில் நம்பிக்கை பெறுவதுதான் நீங்கள் இத்தனை நாளும் உழைத்து வந்த இலக்கு, அதை நிராகரிப்பது ஒரு பின்னடைவாகத் தோன்றுகிறது.', 'I'),
  (3, 'You ask her what you should deprioritise to take this on - you are not saying no but you are not saying yes without a real conversation about your plate.', 'இதைச் செய்வதற்காக எதற்கு முக்கியத்துவம் கொடுக்கக் கூடாது என்று நீங்கள் அவளிடம் கேட்கிறீர்கள் - நீங்கள் வேண்டாம் என்று சொல்லவில்லை, ஆனால் உங்கள் வேலைப்பளுவைப் பற்றி ஒரு உண்மையான உரையாடல் இல்லாமல் ஆம் என்றும் சொல்லவில்லை.', 'S'),
  (4, 'You say yes and figure out the capacity problem later - you have managed overload before and you will manage it again.', 'நீங்கள் சம்மதம் தெரிவித்துவிட்டு, கொள்ளளவுப் பிரச்சனையைப் பிறகு சமாளித்துக் கொள்ளுங்கள் - நீங்கள் இதற்கு முன்பும் அதிபாரத்தைச் சமாளித்திருக்கிறீர்கள், மீண்டும் சமாளிப்பீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q38',
     'You have noticed a pattern - you are never fully off. On weekends you are checking messages. On evenings you are thinking about tomorrow''s work. You do not think this is required. Nobody has told you it is expected. But the anxiety of being behind is louder than the boundary you know you should be holding.', 'How do you disconnect fully?', 'நீங்கள் ஒரு வழக்கத்தைக் கவனித்திருக்கிறீர்கள் - நீங்கள் ஒருபோதும் முழுமையாக ஓய்வில் இருப்பதில்லை. வார இறுதி நாட்களில் குறுஞ்செய்திகளைப் பார்க்கிறீர்கள். மாலை நேரங்களில் நாளைய வேலையைப் பற்றி யோசிக்கிறீர்கள். இது அவசியம் என்று நீங்கள் நினைக்கவில்லை. இது எதிர்பார்க்கப்படுகிறது என்று யாரும் உங்களிடம் சொல்லவில்லை. ஆனால், நீங்கள் கடைப்பிடிக்க வேண்டும் என்று உங்களுக்குத் தெரிந்த எல்லையை விட, பின்தங்கிவிட்டோமோ என்ற கவலை உரக்க ஒலிக்கிறது.', 'முழுமையாகத் துண்டிப்பது எப்படி?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You set a hard rule - specific hours, specific days - and you hold it even when the anxiety pushes back.', 'நீங்கள் குறிப்பிட்ட நேரங்கள், குறிப்பிட்ட நாட்கள் என ஒரு கடுமையான விதியை வகுத்துக்கொள்கிறீர்கள்; பதட்டம் உங்களைத் தடுத்தாலும் அதைக் கடைப்பிடிக்கிறீர்கள்.', 'D'),
  (2, 'You accept that this phase of your career is intense and that the boundary will come later when you have more control over your workload.', 'உங்கள் தொழில் வாழ்க்கையின் இந்தக் கட்டம் தீவிரமானது என்பதையும், உங்கள் பணிச்சுமையின் மீது உங்களுக்கு அதிகக் கட்டுப்பாடு வரும்போதுதான் அதற்கான எல்லை அமையும் என்பதையும் நீங்கள் ஏற்றுக்கொள்கிறீர்கள்.', 'I'),
  (3, 'You talk to a colleague who seems to manage the boundary better and ask how they actually do it.', 'எல்லையை சிறப்பாகக் கையாள்வதாகத் தோன்றும் ஒரு சக ஊழியரிடம் பேசி, அவர் அதை உண்மையில் எப்படிச் செய்கிறார் என்று கேளுங்கள்.', 'S'),
  (4, 'You try to triage - you stay available for things that are genuinely urgent and let go of the rest, even if the line between urgent and not is blurry.', 'நீங்கள் முன்னுரிமைப்படுத்த முயற்சிக்கிறீர்கள் - அவசரம் மற்றும் அவசரமற்றது ஆகியவற்றுக்கு இடையேயான வேறுபாடு தெளிவற்றதாக இருந்தாலும், உண்மையாகவே அவசரமான விஷயங்களுக்கு மட்டும் உங்களை அர்ப்பணித்து, மற்றவற்றை விட்டுவிடுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q39',
     'What matters more to you in this moment? You have just been offered a chance to work on a high-profile internal project. It is a real opportunity - the kind of visibility that does not come often at your level. It will also require weekend work for the next two months on top of your existing load. You have been running on empty for six weeks already.', 'Should you accept this project?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? ஒரு முக்கியத்துவம் வாய்ந்த உள்ளகத் திட்டத்தில் பணியாற்றும் வாய்ப்பு உங்களுக்கு இப்போதுதான் கிடைத்துள்ளது. இது ஒரு உண்மையான சந்தர்ப்பம் - உங்கள் நிலையில் அடிக்கடி கிடைக்காத ஒருவித அங்கீகாரம். மேலும், உங்கள் தற்போதைய பணிச்சுமைக்கு மேலாக, அடுத்த இரண்டு மாதங்களுக்கு வார இறுதி நாட்களிலும் நீங்கள் பணியாற்ற வேண்டியிருக்கும். ஏற்கெனவே ஆறு வாரங்களாக நீங்கள் ஆற்றல் இன்றி இயங்கிக்கொண்டிருக்கிறீர்கள்.', 'நீங்கள் இந்தத் திட்டத்தை ஏற்க வேண்டுமா?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 2", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The opportunity - you have been waiting for something like this and the cost of saying no may be higher than the cost of the next two months.', 'இந்த வாய்ப்புக்காக நீங்கள் காத்திருந்தீர்கள்; இதை மறுப்பதற்கான விலை, அடுத்த இரண்டு மாதங்களுக்கான செலவை விட அதிகமாக இருக்கலாம்.', 'D'),
  (2, 'Your own sustainability - you know what six more weeks of this will do to the quality of your work and your state of mind, and the opportunity is not worth that.', 'உங்கள் சொந்த நிலைத்தன்மைக்கு - இன்னும் ஆறு வாரங்கள் இது தொடர்ந்தால் உங்கள் வேலையின் தரத்தையும் மனநிலையையும் என்ன செய்யும் என்பது உங்களுக்குத் தெரியும், மேலும் அந்த வாய்ப்பு அதற்காக ஈடாகாது.', 'I'),
  (3, 'What the decision signals - saying no might be the right call for you but you are very aware of what it might say to the people who offered it.', 'அந்த முடிவு உணர்த்துவது என்னவென்றால் - ''வேண்டாம்'' என்று சொல்வது உங்களுக்குச் சரியான முடிவாக இருக்கலாம், ஆனால் அந்த வாய்ப்பை வழங்கியவர்களிடம் அது என்ன செய்தியைச் சொல்லிவிடும் என்பதை நீங்கள் நன்கு அறிந்திருக்கிறீர்கள்.', 'S'),
  (4, 'The version of you that will show up for this project - if you take it running on empty, you might do it badly, and doing it badly is worse than not doing it at all.', 'இந்தத் திட்டத்திற்காக நீங்கள் வெளிப்படும் விதத்தைப் பொறுத்தவரை - நீங்கள் எந்த ஆற்றலும் இல்லாமல் இதைச் செய்யத் தொடங்கினால், நீங்கள் அதை மோசமாகச் செய்யக்கூடும், மேலும் அதைச் செய்யாமல் இருப்பதை விட மோசமாகச் செய்வது இன்னும் மோசம்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 1 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S1-Q40',
     'The honest feeling underneath this - you are good at looking fine. People ask how you are and you say busy but good. Your work is holding up. Your relationships at work are fine. But there is a version of what this job is costing you that you have not told anyone - not a colleague, not a friend, not anyone - because putting it into words makes it more real than you are ready for it to be.', 'What is this job costing?', 'இதன் அடிப்படையிலான உண்மையான உணர்வு இதுதான் - நீங்கள் நன்றாக இருப்பது போல் காட்டிக்கொள்வதில் கைதேர்ந்தவர். மக்கள் உங்களிடம் எப்படி இருக்கிறீர்கள் என்று கேட்கும்போது, ​​நீங்கள் ''வேலையாக இருந்தாலும் நன்றாக இருக்கிறேன்'' என்று சொல்கிறீர்கள். உங்கள் வேலையும் நன்றாகப் போகிறது. பணியிடத்தில் உங்கள் உறவுகளும் நன்றாக இருக்கின்றன. ஆனால், இந்த வேலை உங்களுக்கு என்ன விலையைக் கொடுக்கிறது என்பதைப் பற்றி நீங்கள் யாரிடமும் - ஒரு சக ஊழியரிடமோ, நண்பரிடமோ, அல்லது வேறு யாரிடமோ - சொல்லவில்லை. ஏனென்றால், அதை வார்த்தைகளில் சொல்வது, நீங்கள் தயாராக இருப்பதை விட அதை இன்னும் நிஜமாக்கிவிடும்.', 'இந்த வேலைக்கு எவ்வளவு செலவாகும்?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 3", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A fear that if you say it out loud you will have to do something about it - and right now the not-doing feels easier than the deciding.', 'அதை சத்தமாகச் சொன்னால், அதைப் பற்றி ஏதாவது செய்ய வேண்டியிருக்கும் என்ற பயம் - இப்போதைக்கு, முடிவெடுப்பதை விட செய்யாமல் இருப்பது எளிதாகத் தோன்றுகிறது.', 'D'),
  (2, 'A shame that this is hard - you chose this, other people manage it, and the fact that it is costing you something feels like a personal failure rather than a reasonable response to an unreasonable amount.', 'இது கடினமாக இருப்பது வருத்தமளிக்கிறது - இதை நீங்கள் தேர்ந்தெடுத்தீர்கள், மற்றவர்கள் இதைச் சமாளிக்கிறார்கள், ஆனால் இதற்காக நீங்கள் செலவாவது, நியாயமற்ற ஒரு தொகைக்குக் காட்டும் நியாயமான எதிர்வினையாகத் தோன்றாமல், ஒரு தனிப்பட்ட தோல்வியாகவே உங்களை உணர வைக்கிறது.', 'I'),
  (3, 'A protectiveness over the version of yourself that is still okay - if you look at the cost directly, you are not sure what you will find, and some part of you is not ready to look.', 'இன்னும் நன்றாக இருக்கும் உங்கள் சுயத்தின் மீது ஒருவித பாதுகாப்பு உணர்வு - அதன் விலையை நேரடியாகப் பார்த்தால், என்ன கிடைக்கும் என்று உங்களுக்கு உறுதியாகத் தெரியாது, மேலும் உங்கள் மனதின் ஒரு பகுதி அதை எதிர்கொள்ளத் தயாராக இருக்காது.', 'S'),
  (4, 'A longing for someone to ask in a way that makes it safe to answer honestly - not because you need rescuing but because carrying it alone is the part that is the most tiring.', 'நேர்மையாகப் பதிலளிக்கப் பாதுகாப்பான சூழலை உருவாக்கும் விதத்தில் யாராவது கேட்க வேண்டும் என்ற ஏக்கம் - அது உங்களைக் காப்பாற்ற வேண்டும் என்பதற்காக அல்ல, மாறாக அதைத் தனியாகச் சுமப்பதுதான் மிகவும் சோர்வளிக்கும் ஒரு பகுதி என்பதால்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q1',
     'Your manager gives you feedback in front of three colleagues during a team catch-up. The feedback is about a report you submitted last week - she says the structure was confusing and that you need to work on how you present information. You are fairly sure the structure was based on a template she gave you herself. The room is quiet and everyone is looking at their laptops.', 'How do you respond now?', 'குழு சந்திப்பின் போது, ​​உங்கள் மேலாளர் மூன்று சக ஊழியர்கள் முன்னிலையில் உங்களுக்குக் கருத்துத் தெரிவிக்கிறார். அந்தக் கருத்து, நீங்கள் கடந்த வாரம் சமர்ப்பித்த ஒரு அறிக்கையைப் பற்றியது - அதன் கட்டமைப்பு குழப்பமாக இருந்ததாகவும், நீங்கள் தகவல்களை வழங்கும் விதத்தில் கவனம் செலுத்த வேண்டும் என்றும் அவர் கூறுகிறார். அந்தக் கட்டமைப்பு, அவரே உங்களுக்குக் கொடுத்த ஒரு வார்ப்புருவை அடிப்படையாகக் கொண்டது என்று நீங்கள் உறுதியாக நம்புகிறீர்கள். அறை அமைதியாக இருக்கிறது, அனைவரும் தங்கள் மடிக்கணினிகளைப் பார்த்துக் கொண்டிருக்கிறார்கள்.', 'நீங்கள் இப்போது எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You accept the feedback without comment and make a note to follow up privately later.', 'நீங்கள் எந்தக் கருத்தும் கூறாமல் பின்னூட்டத்தை ஏற்றுக்கொண்டு, பின்னர் தனிப்பட்ட முறையில் பின்தொடர்வதாகக் குறித்துக்கொள்ளுங்கள்.', 'D'),
  (2, 'You politely mention in the moment that the structure was based on the template provided, without making it confrontational.', 'மோதல் போக்கை ஏற்படுத்தாமல், வழங்கப்பட்ட வார்ப்புருவின் அடிப்படையிலேயே கட்டமைப்பு உருவாக்கப்பட்டது என்பதை அந்தத் தருணத்திலேயே நீங்கள் பணிவாகக் குறிப்பிடுகிறீர்கள்.', 'I'),
  (3, 'You say nothing now but bring it up with a trusted colleague afterward to figure out your next step.', 'இப்போது எதுவும் சொல்லாமல், பின்னர் உங்கள் அடுத்தகட்ட நடவடிக்கையைத் தீர்மானிக்க நம்பகமான சக ஊழியர் ஒருவரிடம் இதைப் பற்றிப் பேசுங்கள்.', 'S'),
  (4, 'You let it go entirely - correcting a senior person in front of others is not worth the risk.', 'நீங்கள் அதை முற்றிலுமாக விட்டுவிடுங்கள் - மற்றவர்கள் முன்னிலையில் ஒரு மூத்த நபரைத் திருத்துவது ஆபத்தை விளைவிக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q2',
     'Your manager''s manager stops by your desk and asks how a project is going. You know the project is behind, partly because your direct manager has not given you the inputs you need. Your manager is sitting twenty feet away and can probably hear the conversation.', 'How do you handle this?', 'உங்கள் மேலாளரின் மேலாளர் உங்கள் மேசைக்கு வந்து, ஒரு திட்டம் எப்படிப் போய்க்கொண்டிருக்கிறது என்று கேட்கிறார். உங்கள் நேரடி மேலாளர் உங்களுக்குத் தேவையான உள்ளீடுகளை வழங்காததால், அந்தத் திட்டம் பின்தங்கியுள்ளது என்பது உங்களுக்குத் தெரியும். உங்கள் மேலாளர் இருபது அடி தூரத்தில் அமர்ந்திருப்பதால், அநேகமாக அந்த உரையாடலை அவரால் கேட்க முடியும்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You give an honest update on the status and mention that you are waiting on a few inputs to move forward.', 'தற்போதைய நிலை குறித்து நேர்மையான தகவலை அளித்து, அடுத்தகட்ட நடவடிக்கைகளை மேற்கொள்ள சில உள்ளீடுகளுக்காகக் காத்திருப்பதாகவும் குறிப்பிடுகிறீர்கள்.', 'D'),
  (2, 'You say things are on track to avoid creating an awkward situation between the two of them.', 'அவர்கள் இருவருக்கும் இடையே ஒரு சங்கடமான சூழ்நிலை ஏற்படுவதைத் தவிர்க்க, விஷயங்கள் திட்டமிட்டபடி நடந்து கொண்டிருப்பதாக நீங்கள் சொல்கிறீர்கள்.', 'I'),
  (3, 'You keep it brief and redirect - you let her know your manager would have the full picture.', 'நீங்கள் சுருக்கமாகப் பேசி, கவனத்தைத் திசைதிருப்புங்கள் - உங்கள் மேலாளரிடம் முழு விவரமும் இருக்கும் என்பதை அவளுக்குத் தெரியப்படுத்துங்கள்.', 'S'),
  (4, 'You give an honest update but frame it carefully so it does not sound like you are pointing fingers at anyone.', 'நீங்கள் ஒரு நேர்மையான தகவலைத் தெரிவிக்கிறீர்கள், ஆனால் அது யாரையும் குற்றம் சாட்டுவது போல் தோன்றாதவாறு கவனமாக முன்வைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q3',
     'What matters more to you in this moment? Your manager has just praised your work in a team meeting - said you handled a tricky client brief really well. You notice a senior colleague roll their eyes slightly. You are not sure if you imagined it.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? உங்கள் மேலாளர் சற்று முன்பு ஒரு குழுக்கூட்டத்தில் உங்கள் வேலையைப் பாராட்டினார் - ஒரு சிக்கலான வாடிக்கையாளர் திட்டத்தை நீங்கள் மிகச் சிறப்பாகக் கையாண்டதாகக் கூறினார். உங்கள் மூத்த சக ஊழியர் ஒருவர் லேசாகக் கண்களை உருட்டுவதை நீங்கள் கவனிக்கிறீர்கள். அதை நீங்கள் கற்பனை செய்துகொண்டீர்களா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 2", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'That your manager publicly recognised your work - that visibility matters more than what one colleague thinks.', 'உங்கள் மேலாளர் உங்கள் பணியைப் பகிரங்கமாக அங்கீகரித்தார் என்பது - ஒரு சக ஊழியர் என்ன நினைக்கிறார் என்பதை விட, அங்கீகாரம் கிடைப்பதுதான் முக்கியம்.', 'D'),
  (2, 'That the senior colleague respects you - their opinion carries weight you cannot ignore.', 'மூத்த சக ஊழியர் உங்களை மதிக்கிறார் என்பது - அவருடைய கருத்துக்கு நீங்கள் புறக்கணிக்க முடியாத மதிப்பு உண்டு.', 'I'),
  (3, 'That the praise was genuine and deserved - the audience reaction matters less than whether it was true.', 'அந்தப் பாராட்டு உண்மையானதும் தகுதியானதும் ஆகும்; அது உண்மையா என்பதை விட, பார்வையாளர்களின் எதிர்வினை அவ்வளவு முக்கியமல்ல.', 'S'),
  (4, 'That you handled it gracefully - how you received the praise in front of others is what people will remember.', 'நீங்கள் அதை கண்ணியமாகக் கையாண்ட விதமும், மற்றவர்கள் முன்னிலையில் அந்தப் பாராட்டுகளை நீங்கள் ஏற்றுக்கொண்ட விதமும்தான் மக்களுக்கு நினைவில் இருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q4',
     'Before you say anything - your manager just introduced you to a visiting senior leader from another department and said, in front of both of you, that you are one of the sharper people who joined this year. You did not expect it. The senior leader is looking at you, waiting for you to say something.', 'How do you respond now?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - உங்கள் மேலாளர் சற்று முன்புதான் மற்றொரு துறையிலிருந்து வருகை தந்திருந்த ஒரு மூத்த தலைவரை உங்களுக்கு அறிமுகம் செய்து வைத்து, உங்கள் இருவர் முன்னிலையிலும், இந்த ஆண்டு சேர்ந்தவர்களில் நீங்கள் மிகவும் கூர்மையானவர்களில் ஒருவர் என்று கூறினார். நீங்கள் அதை சற்றும் எதிர்பார்க்கவில்லை. அந்த மூத்த தலைவர், நீங்கள் ஏதேனும் சொல்வீர்கள் என்று எதிர்பார்த்து, உங்களையே பார்த்துக் கொண்டிருக்கிறார்.', 'நீங்கள் இப்போது எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Managing Up and Visibility", "layer": "Layer 3", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A quiet panic - you are not sure you can live up to what was just said and you are already thinking about when you will disappoint someone.', 'ஒரு மென்மையான பதட்டம் - சற்று முன்பு சொன்னபடி உங்களால் நடந்துகொள்ள முடியுமா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை, மேலும் எப்போது ஒருவரை ஏமாற்றிவிடுவோமோ என்றும் நீங்கள் இப்போதே சிந்திக்கத் தொடங்கிவிட்டீர்கள்.', 'D'),
  (2, 'A rush of warmth - you have been working hard and this feels like it finally landed somewhere it counts.', 'ஒருவிதமான இதமான உணர்வு - நீங்கள் கடினமாக உழைத்திருக்கிறீர்கள், அது இறுதியாக ஒரு அர்த்தமுள்ள இடத்தில் வந்து சேர்ந்தது போல் உணர்கிறீர்கள்.', 'I'),
  (3, 'Suspicion - you are not sure what prompted this and whether it comes with an expectation you have not agreed to.', 'சந்தேகம் - இதற்கு என்ன காரணம் என்றும், நீங்கள் ஒப்புக்கொள்ளாத ஒரு எதிர்பார்ப்பு இதனுடன் உள்ளதா என்றும் உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'S'),
  (4, 'Pressure - the moment just raised the bar and now every interaction with this person will be measured against that introduction.', 'அழுத்தம் - அந்தத் தருணம் எதிர்பார்ப்பை இன்னும் அதிகமாக்கிவிட்டது, இனி அந்த நபருடனான ஒவ்வொரு உரையாடலும் அந்த அறிமுகத்தின் அடிப்படையிலேயே அளவிடப்படும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q5',
     'You submitted a tracker to your team lead yesterday. This morning she replies on the group email chain pointing out a formula error that changed three numbers in the summary. You caught the mistake yourself an hour after you sent it but decided it was small enough not to flag. The whole team can see the reply.', 'How do you handle this?', 'நேற்று உங்கள் குழுத் தலைவரிடம் ஒரு டிராக்கரைச் சமர்ப்பித்தீர்கள். இன்று காலை, அவர் குழு மின்னஞ்சல் தொடரில் பதிலளித்து, சுருக்கத்தில் உள்ள மூன்று எண்களை மாற்றிய ஒரு ஃபார்முலா பிழையைச் சுட்டிக்காட்டியுள்ளார். நீங்கள் அதை அனுப்பிய ஒரு மணி நேரத்திற்குப் பிறகு அந்தத் தவறை நீங்களே கண்டுபிடித்தீர்கள், ஆனால் அது மிகவும் சிறியது என்பதால் அதைப் புகாரளிக்கத் தேவையில்லை என்று முடிவு செய்தீர்கள். அந்தப் பதிலை முழு குழுவும் பார்க்க முடியும்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You reply immediately, own the error, correct it, and apologise for not catching it before submission.', 'நீங்கள் உடனடியாகப் பதிலளித்து, உங்கள் தவறை ஒப்புக்கொண்டு, அதைத் திருத்தி, சமர்ப்பிக்கும் முன் அதைக் கண்டறியாததற்காக மன்னிப்புக் கேட்க வேண்டும்.', 'D'),
  (2, 'You fix it quietly and send the corrected version without drawing more attention to what happened.', 'நீங்கள் அதை அமைதியாகச் சரிசெய்து, என்ன நடந்தது என்பது குறித்து மேலும் கவனத்தை ஈர்க்காமல் திருத்தப்பட்ட பதிப்பை அனுப்பிவிடுங்கள்.', 'I'),
  (3, 'You reply to the team lead directly - not on the chain - to apologise and send the fix privately.', 'மன்னிப்புக் கேட்பதற்கும், திருத்தத்தை தனிப்பட்ட முறையில் அனுப்புவதற்கும், நீங்கள் குழுத் தலைவருக்கு நேரடியாகப் பதிலளிக்க வேண்டும் - உரையாடல் சங்கிலியில் அல்ல.', 'S'),
  (4, 'You reply on the chain, correct the file, and briefly explain that you had caught it and were in the process of updating it.', 'நீங்கள் அந்தத் தொடருக்குப் பதிலளித்து, கோப்பைத் திருத்தி, அதை நீங்கள் கண்டறிந்துவிட்டதாகவும், அதைப் புதுப்பிக்கும் பணியில் இருப்பதாகவும் சுருக்கமாக விளக்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q6',
     'You have been given three hours to put together a competitive analysis that normally takes a full day. Your manager needs it for a leadership meeting this afternoon. You can produce something complete but thin, or something genuinely useful on two of the five sections and flag the rest as incomplete.', 'How do you prioritize tasks?', 'வழக்கமாக ஒரு முழு நாள் எடுக்கும் ஒரு போட்டிப் பகுப்பாய்வைத் தொகுப்பதற்கு உங்களுக்கு மூன்று மணி நேரம் வழங்கப்பட்டுள்ளது. இன்று பிற்பகல் நடைபெறும் தலைமைத்துவக் கூட்டத்திற்காக உங்கள் மேலாளருக்கு அது தேவைப்படுகிறது. நீங்கள் முழுமையான ஆனால் சுருக்கமான ஒன்றை உருவாக்கலாம், அல்லது ஐந்து பிரிவுகளில் இரண்டிற்கு உண்மையிலேயே பயனுள்ள ஒன்றை உருவாக்கி, மீதமுள்ளவற்றை முழுமையற்றவை எனக் குறிப்பிடலாம்.', 'பணிகளுக்கு எவ்வாறு முன்னுரிமை அளிக்கிறீர்கள்?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 1", "dimension": "accuracy_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You deliver the full five sections and accept that the quality will not be what you would normally produce.', 'நீங்கள் ஐந்து பிரிவுகளையும் முழுமையாக வழங்குகிறீர்கள், ஆனால் அதன் தரம் நீங்கள் வழக்கமாகத் தயாரிக்கும் தரத்தில் இருக்காது என்பதை ஏற்றுக்கொள்கிறீர்கள்.', 'D'),
  (2, 'You deliver two strong sections and clearly mark the other three as in-progress with a note on what is missing.', 'நீங்கள் இரண்டு வலுவான பகுதிகளை வழங்கியதோடு, விடுபட்டவை குறித்த குறிப்புடன் மற்ற மூன்று பகுதிகள் முன்னேற்றத்தில் உள்ளவை என்பதையும் தெளிவாகக் குறிப்பிடுகிறீர்கள்.', 'I'),
  (3, 'You tell your manager before the deadline that three hours is not enough time to do this properly and ask what she wants to prioritise.', 'கெடு தேதிக்கு முன்பாகவே, இதைச் சரியாகச் செய்வதற்கு மூன்று மணி நேரம் போதாது என்று உங்கள் மேலாளரிடம் கூறி, அவர் எதற்கு முன்னுரிமை அளிக்க விரும்புகிறார் என்றும் கேளுங்கள்.', 'S'),
  (4, 'You do your best across all five, submit it, and say nothing about the time constraint.', 'நீங்கள் அந்த ஐந்திலும் உங்கள் சிறந்ததைச் செய்து, அதைச் சமர்ப்பித்துவிட்டு, நேரக் கட்டுப்பாடு பற்றி எதுவும் கூறாதீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q7',
     'Two things are pulling at you. Which is stronger? You have just finished a piece of work you are genuinely proud of. It is due in ten minutes. Reading through it one last time, you find a section that is technically correct but could be misread. Fixing it properly would take thirty minutes you do not have.', 'Which pulling force is stronger?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. எது வலிமையானது? நீங்கள் மிகவும் பெருமைப்படும் ஒரு வேலையை இப்போதுதான் முடித்திருக்கிறீர்கள். அதை இன்னும் பத்து நிமிடங்களில் சமர்ப்பிக்க வேண்டும். அதை ஒரு கடைசி முறையாகப் படித்துப் பார்க்கும்போது, ​​தொழில்நுட்ப ரீதியாகச் சரியாக இருந்தாலும் தவறாகப் புரிந்துகொள்ளப்பட்டிருக்கக்கூடிய ஒரு பகுதியைக் காண்கிறீர்கள். அதைச் சரியாகச் சரிசெய்வதற்கு முப்பது நிமிடங்கள் தேவைப்படும், ஆனால் அந்த நேரம் உங்களிடம் இல்லை.', 'எந்த இழுவிசை வலிமையானது?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 2", "dimension": "accuracy_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Submitting on time - a late submission will be noticed more than a section that might be misread.', 'சரியான நேரத்தில் சமர்ப்பித்தல் - தவறாகப் படிக்கப்படக்கூடிய ஒரு பகுதியை விட, தாமதமாகச் சமர்ப்பிக்கப்படும் ஒரு பகுதி அதிகமாகக் கவனிக்கப்படும்.', 'D'),
  (2, 'Getting it right - you cannot put your name on something you know is not as clear as it should be.', 'சரியாகச் செய்வது - இருக்க வேண்டிய அளவுக்குத் தெளிவாக இல்லை என்று உங்களுக்குத் தெரிந்த ஒன்றில் உங்கள் பெயரைப் போட முடியாது.', 'I'),
  (3, 'Managing perception - how your manager reads this matters more than the technical accuracy of the section.', 'புரிதலை நிர்வகித்தல் - இந்தப் பகுதியின் தொழில்நுட்பத் துல்லியத்தை விட, உங்கள் மேலாளர் இதை எவ்வாறு புரிந்துகொள்கிறார் என்பதே மிகவும் முக்கியமானது.', 'S'),
  (4, 'Protecting yourself - if the section is misread later, you want to have flagged it even if you could not fix it.', 'உங்களைப் பாதுகாத்துக் கொள்வது - பிற்காலத்தில் அந்தப் பகுதி தவறாகப் புரிந்துகொள்ளப்பட்டால், உங்களால் அதைச் சரிசெய்ய முடியாவிட்டாலும், நீங்கள் அதைக் கொடியிட்டுக் காட்ட விரும்புவீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q8',
     'The honest feeling underneath this - you have been asked to present a project update in the weekly team meeting. You know the project is behind. You know it is partly your fault - you misjudged how long one phase would take. Your manager does not know the full story yet.', 'How do you feel now?', 'இதன் பின்னணியில் உள்ள உண்மையான உணர்வு இதுதான் - வாராந்திர குழு கூட்டத்தில் திட்டத்தின் தற்போதைய நிலையை விளக்குமாறு நீங்கள் கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள். திட்டம் பின்தங்கியுள்ளது என்பது உங்களுக்குத் தெரியும். அது ஓரளவிற்கு உங்கள் தவறுதான் என்பதும் உங்களுக்குத் தெரியும் - ஒரு கட்டத்தின் காலம் எவ்வளவு ஆகும் என்பதை நீங்கள் தவறாகக் கணித்துவிட்டீர்கள். உங்கள் மேலாளருக்கு இன்னும் முழு விவரமும் தெரியாது.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Delivering Work and Owning Output", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Dread - not because of the project but because you are going to have to say something out loud that makes you look like you did not plan properly.', 'பயம் - அது அந்தத் திட்டப்பணியால் அல்ல, மாறாக நீங்கள் சரியாகத் திட்டமிடவில்லை என்பது போல உங்களைக் காட்டிக்கொள்ளும் ஒரு விஷயத்தை உரக்கச் சொல்ல வேண்டியிருக்கும் என்பதால்தான்.', 'D'),
  (2, 'Determination - you already know what you are going to say, how you are going to explain it, and what your recovery plan is.', 'உறுதிப்பாடு - நீங்கள் என்ன சொல்லப் போகிறீர்கள், அதை எப்படி விளக்கப் போகிறீர்கள், மற்றும் உங்கள் மீட்புத் திட்டம் என்னவென்பது உங்களுக்கு ஏற்கெனவே தெரிந்திருக்கும்.', 'I'),
  (3, 'Shame - you keep running back through the decisions you made and wondering what you were thinking at the time.', 'வெட்கமாக இருக்கிறது - நீங்கள் எடுத்த முடிவுகளைத் திரும்பத் திரும்ப அசைபோட்டு, அப்போது என்ன நினைத்துக் கொண்டிருந்தீர்கள் என்று யோசித்துக் கொண்டே இருக்கிறீர்கள்.', 'S'),
  (4, 'Calculation - you are already figuring out what to say, what to leave out, and how to keep this from becoming a bigger conversation than it needs to be.', 'திட்டமிடல் - என்ன சொல்வது, எதை விடுவது, மேலும் இந்த உரையாடல் தேவையை விடப் பெரிதாகாமல் எப்படித் தடுப்பது என்பனவற்றை நீங்கள் ஏற்கெனவே சிந்தித்துக் கொண்டிருக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q9',
     'You and a colleague joined the same week. Over the last month you have noticed she gets called into meetings you are not invited to, her name comes up in conversations yours does not, and she has already been asked to lead a small internal initiative. You are doing work you believe is equally strong.', 'Why is she being noticed?', 'நீங்களும் உங்கள் சக ஊழியரும் ஒரே வாரத்தில் பணியில் சேர்ந்தீர்கள். கடந்த ஒரு மாதமாக, நீங்கள் அழைக்கப்படாத கூட்டங்களுக்கு அவர் அழைக்கப்படுவதையும், உங்கள் பெயர் இடம்பெறாத உரையாடல்களில் அவரது பெயர் வருவதையும், மேலும் ஒரு சிறிய உள்ளக முன்னெடுப்பை வழிநடத்தும்படி அவர் ஏற்கெனவே கேட்டுக்கொள்ளப்பட்டிருப்பதையும் நீங்கள் கவனித்திருக்கிறீர்கள். நீங்களும் அவருக்கு நிகரான வலிமை வாய்ந்த ஒரு பணியைச் செய்வதாக நம்புகிறீர்கள்.', 'அவள் ஏன் கவனிக்கப்படுகிறாள்?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You focus on your own output and trust that visibility will come - comparing yourself to her is not useful.', 'நீங்கள் உங்கள் சொந்தச் செயல்பாடுகளில் கவனம் செலுத்துங்கள், அங்கீகாரம் தானாகவே வரும் என்று நம்புங்கள் - உங்களை அவளுடன் ஒப்பிட்டுப் பார்ப்பதில் எந்தப் பயனும் இல்லை.', 'D'),
  (2, 'You find a quiet moment to ask her directly how she has been getting these opportunities, genuinely curious rather than competitive.', 'போட்டி மனப்பான்மையின்றி, உண்மையான ஆர்வத்துடன், அவளுக்கு இந்த வாய்ப்புகள் எப்படி கிடைக்கின்றன என்று நேரடியாகக் கேட்க ஒரு அமைதியான தருணத்தை நீங்கள் தேடிக்கொள்கிறீர்கள்.', 'I'),
  (3, 'You raise it with your manager - not about her specifically but about how you can get more visibility for your own work.', 'நீங்கள் அதை உங்கள் மேலாளரிடம் எழுப்புங்கள் - அவரைப் பற்றி குறிப்பாக அல்ல, மாறாக உங்கள் சொந்தப் பணிக்கு எப்படி அதிக அங்கீகாரம் கிடைப்பது என்பது பற்றி.', 'S'),
  (4, 'You feel the frustration but do not act on it - the dynamics are still new and you do not have enough information yet.', 'நீங்கள் விரக்தியை உணர்கிறீர்கள், ஆனால் அதன்படி செயல்படுவதில்லை - ஏனெனில் சூழல் இன்னும் புதிதாக இருக்கிறது, மேலும் உங்களிடம் போதுமான தகவல்கள் இன்னும் இல்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q10',
     'In a joint presentation your team submitted last week, one of your contributions - a section you researched and wrote entirely - is being described by a peer in conversations with senior people as something he developed. You have heard it twice now. He has not corrected the record either time.', 'How do you handle this?', 'கடந்த வாரம் உங்கள் குழு சமர்ப்பித்த ஒரு கூட்டு விளக்கக்காட்சியில், நீங்கள் முழுமையாக ஆய்வு செய்து எழுதிய உங்கள் பங்களிப்புகளில் ஒன்றான ஒரு பகுதியை, உங்கள் சக ஊழியர் ஒருவர் மூத்த அதிகாரிகளுடனான உரையாடல்களில், அவரே உருவாக்கியதாகக் கூறி வருகிறார். இதை நீங்கள் இப்போது இரண்டு முறை கேட்டிருக்கிறீர்கள். இரண்டு முறையும் அவர் தன் தவறைத் திருத்தவில்லை.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You speak to him privately and tell him clearly that you need him to acknowledge your contribution when it comes up.', 'நீங்கள் அவரிடம் தனிப்பட்ட முறையில் பேசி, உங்கள் பங்களிப்பு தேவைப்படும்போது அவர் அதை அங்கீகரிக்க வேண்டும் என்பதைத் தெளிவாகக் கூறுங்கள்.', 'D'),
  (2, 'You find natural opportunities to reference your own work in conversations without directly confronting him.', 'நீங்கள் அவரை நேரடியாக எதிர்கொள்ளாமல், உரையாடல்களில் உங்கள் சொந்தப் படைப்புகளைக் குறிப்பிடுவதற்கான இயல்பான சந்தர்ப்பங்களைக் கண்டறிகிறீர்கள்.', 'I'),
  (3, 'You let it go - getting into credit disputes early in your career feels like a losing game.', 'அதை விட்டுவிடுங்கள் - உங்கள் தொழில் வாழ்க்கையின் ஆரம்பத்தில் கடன் தகராறுகளில் சிக்குவது ஒரு தோல்வியுறும் ஆட்டம் போல் தோன்றும்.', 'S'),
  (4, 'You make sure your manager knows your contribution was yours, without turning it into a complaint about your colleague.', 'உங்கள் சக ஊழியர் மீதான புகாராக அதை மாற்றாமல், உங்கள் பங்களிப்பு உங்களுடையது என்பதை உங்கள் மேலாளருக்குத் தெரியப்படுத்துங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q11',
     'The conflict you feel most is between - you and two colleagues have developed a close working rhythm over the last few months. A new person has just joined the team and your manager has asked you specifically to bring her into your working group. You can feel the existing dynamic shifting already.', 'How to handle team changes?', 'நீங்கள் அதிகமாக உணரும் முரண்பாடு இவர்களுக்கு இடையேதான் உள்ளது - கடந்த சில மாதங்களாக நீங்களும் உங்கள் இரண்டு சக ஊழியர்களும் ஒரு நெருக்கமான பணிச்சூழலை உருவாக்கியுள்ளீர்கள். இப்போதுதான் ஒரு புதிய நபர் குழுவில் இணைந்துள்ளார், மேலும் அவரை உங்கள் பணிக்குழுவிற்குள் கொண்டுவருமாறு உங்கள் மேலாளர் உங்களிடம் குறிப்பாகக் கேட்டுள்ளார். தற்போதுள்ள பணிச்சூழல் மாறுவதை உங்களால் உணர முடிகிறது.', 'குழு மாற்றங்களை எவ்வாறு கையாள்வது?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Protecting what works - the current rhythm is productive and introducing a new variable feels like a risk to what you have built.', 'சிறப்பாகச் செயல்படுவதைப் பாதுகாத்தல் - தற்போதைய செயல்முறை பயனுள்ளதாக இருக்கிறது, மேலும் ஒரு புதிய காரணியை அறிமுகப்படுத்துவது நீங்கள் கட்டமைத்துள்ள அமைப்புக்கு ஓர் ஆபத்து விளைவிப்பதாகத் தோன்றுகிறது.', 'D'),
  (2, 'Being the kind of colleague you would have wanted when you were new - even if it disrupts something comfortable.', 'நீங்கள் புதிதாகப் பணியில் சேர்ந்தபோது விரும்பியதைப் போன்ற ஒரு சக ஊழியராக இருப்பது - அது உங்களுக்குப் பழக்கமான ஒரு விஷயத்தைச் சீர்குலைத்தாலும் கூட.', 'I'),
  (3, 'Your manager''s expectation and your own instinct - you will do it because you were asked but you are not sure it was the right call.', 'உங்கள் மேலாளரின் எதிர்பார்ப்பும் உங்கள் சொந்த உள்ளுணர்வும் - உங்களைக் கேட்டதால் நீங்கள் அதைச் செய்வீர்கள், ஆனால் அது சரியான முடிவா என்று உங்களுக்கு உறுதியாகத் தெரியாது.', 'S'),
  (4, 'Inclusion and efficiency - you want her to feel welcome but you also have deliverables that cannot slow down.', 'அனைவரையும் உள்ளடக்குதல் மற்றும் செயல்திறன் - அவர் வரவேற்கப்படுவதாக உணர வேண்டும் என நீங்கள் விரும்புகிறீர்கள், ஆனால் அதே சமயம், உங்களால் தாமதப்படுத்த முடியாத சில பணிகளும் உங்களிடம் உள்ளன.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q12',
     'What is actually happening inside you - a colleague you have become genuinely close to over the past year has just been promoted ahead of you. You expected it might happen. You are happy for her. But sitting at your desk this afternoon, something feels off and you have not been able to name it yet.', 'Why do you feel off?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - கடந்த ஒரு வருடமாக நீங்கள் மிகவும் நெருக்கமாகப் பழகிய ஒரு சக ஊழியர், உங்களை விட முன்னதாகப் பதவி உயர்வு பெற்றுள்ளார். இது நடக்கக்கூடும் என்று நீங்கள் எதிர்பார்த்தீர்கள். அவருக்காக நீங்கள் மகிழ்ச்சியடைகிறீர்கள். ஆனால் இன்று மதியம் உங்கள் மேசையில் அமர்ந்திருக்கும்போது, ​​ஏதோ சரியில்லை என்று தோன்றுகிறது, ஆனால் அது என்னவென்று உங்களால் இன்னும் கூற முடியவில்லை.', 'உங்களுக்கு ஏன் சரியில்லை போல் உணர்கிறீர்கள்?',
     '{"theme": "Navigating Peer Relationships", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A quiet grief - not about the promotion but about the fact that the dynamic between you is going to change whether you want it to or not.', 'ஒரு அமைதியான துக்கம் - அது பதவி உயர்வைப் பற்றியதல்ல, மாறாக நீங்கள் விரும்பினாலும் விரும்பாவிட்டாலும் உங்களுக்கிடையேயான உறவுமுறை மாறப்போகிறது என்ற உண்மையைப் பற்றியது.', 'D'),
  (2, 'An honest question you have not asked anyone - whether the people making decisions even know your name the way they clearly know hers.', 'நீங்கள் யாரிடமும் கேட்காத ஒரு நேர்மையான கேள்வி இது - முடிவெடுக்கும் நபர்களுக்கு அவளுடைய பெயர் தெளிவாகத் தெரிந்திருப்பது போல, உங்கள் பெயரும் தெரியுமா என்பதுதான்.', 'I'),
  (3, 'A loyalty conflict - you want to celebrate her fully but something in you feels like doing that means accepting something about yourself you are not ready to accept.', 'விசுவாசப் போராட்டம் - நீங்கள் அவளை முழுமையாகக் கொண்டாட விரும்புகிறீர்கள், ஆனால் அப்படிச் செய்வது, உங்களைப் பற்றி நீங்கள் ஏற்றுக்கொள்ளத் தயாராக இல்லாத ஒன்றை ஏற்றுக்கொள்வதற்குச் சமம் என்று உங்கள் உள்ளுணர்வு சொல்கிறது.', 'S'),
  (4, 'Relief wrapped in guilt - part of you is glad it happened to her and not a stranger, and part of you does not know what to do with that feeling.', 'குற்றவுணர்ச்சியுடன் கலந்த நிம்மதி - அது ஒரு அந்நியருக்கு நடக்காமல் அவளுக்கு நடந்ததில் உன் மனதின் ஒரு பகுதிக்கு மகிழ்ச்சி, இன்னொரு பகுதிக்கு அந்த உணர்வை என்ன செய்வதென்று தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q13',
     'Your manager pulls you aside after a client call and tells you that your tone came across as too casual - that the client noticed and mentioned it. You genuinely did not read the room that way. You thought the call went well. This is the first time anyone has said anything like this to you.', 'How do you handle feedback?', 'ஒரு வாடிக்கையாளர் அழைப்பிற்குப் பிறகு உங்கள் மேலாளர் உங்களைத் தனியாக அழைத்து, உங்கள் பேச்சு மிகவும் சாதாரணமாக இருந்ததாகவும், அதை வாடிக்கையாளர் கவனித்துக் குறிப்பிட்டதாகவும் சொல்கிறார். நீங்கள் உண்மையாகவே அந்தச் சூழலை அந்த விதத்தில் உணரவில்லை. அந்த அழைப்பு நன்றாகப் போனதாகவே நீங்கள் நினைத்தீர்கள். உங்களிடம் யாராவது இப்படிச் சொல்வது இதுவே முதல் முறை.', 'பின்னூட்டங்களை நீங்கள் எவ்வாறு கையாளுகிறீர்கள்?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You thank her, ask if there is anything specific you should change, and reflect on the call carefully afterward.', 'நீங்கள் அவளுக்கு நன்றி சொல்லி, குறிப்பாக ஏதேனும் மாற்ற வேண்டுமா என்று கேட்டு, பின்னர் அந்த அழைப்பைப் பற்றி கவனமாகச் சிந்தித்துப் பாருங்கள்.', 'D'),
  (2, 'You accept the feedback but internally you are not sure it is accurate - you replay the call and look for what she might have meant.', 'நீங்கள் அந்தப் பின்னூட்டத்தை ஏற்றுக்கொள்கிறீர்கள், ஆனால் அது துல்லியமானதா என்பதில் உங்களுக்கு மனதளவில் உறுதியில்லை - நீங்கள் அந்த அழைப்பை மீண்டும் கேட்டு, அவர் என்ன சொல்ல வந்திருக்கலாம் என்று ஆராய்கிறீர்கள்.', 'I'),
  (3, 'You ask her to walk you through the specific moment she is referring to so you understand exactly what needs to change.', 'என்ன மாற்றப்பட வேண்டும் என்பதை நீங்கள் துல்லியமாகப் புரிந்துகொள்வதற்காக, அவள் குறிப்பிடும் அந்தக் குறிப்பிட்ட தருணத்தை உங்களுக்கு விவரிக்குமாறு அவளிடம் கேளுங்கள்.', 'S'),
  (4, 'You feel shaken but you do not show it - you thank her and go back to your desk trying to figure out what version of you showed up on that call.', 'நீங்கள் அதிர்ச்சியடைந்தாலும் அதை வெளிக்காட்டாமல், அவளுக்கு நன்றி சொல்லிவிட்டு உங்கள் மேசைக்குத் திரும்பிச் செல்கிறீர்கள்; அந்த அழைப்பில் உங்களின் எந்தப் பக்கம் வெளிப்பட்டது என்று யோசித்தபடியே செல்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q14',
     'A senior colleague who is not your direct manager sends you a long email with detailed comments on a document you submitted. The tone is not unkind but it is thorough - almost every paragraph has a note on it. Some of the comments contradict what your manager had told you to do.', 'How do you handle this?', 'உங்கள் நேரடி மேலாளர் அல்லாத ஒரு மூத்த சக ஊழியர், நீங்கள் சமர்ப்பித்த ஆவணம் குறித்து விரிவான கருத்துக்களுடன் ஒரு நீண்ட மின்னஞ்சலை உங்களுக்கு அனுப்புகிறார். அதன் தொனி கடுமையாக இல்லை, ஆனால் அது மிகவும் முழுமையானதாக இருக்கிறது - ஏறக்குறைய ஒவ்வொரு பத்தியிலும் ஒரு குறிப்பு உள்ளது. அந்தக் கருத்துக்களில் சில, உங்கள் மேலாளர் உங்களுக்குச் செய்யச் சொன்னதற்கு முரணாக உள்ளன.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You reply to the senior colleague acknowledging the feedback and flag the contradictions clearly so they can be resolved.', 'மூத்த சக ஊழியரின் கருத்தை ஏற்றுக்கொண்டு, முரண்பாடுகளைத் தெளிவாகச் சுட்டிக்காட்டிப் பதிலளிக்கவும், அப்போதுதான் அவை தீர்க்கப்படும்.', 'D'),
  (2, 'You go to your manager first and show her the email - you want to understand the conflict before you respond to anyone.', 'நீங்கள் முதலில் உங்கள் மேலாளரிடம் சென்று அந்த மின்னஞ்சலைக் காட்டுங்கள் - யாருக்கும் பதிலளிக்கும் முன், அந்த முரண்பாட்டை நீங்கள் புரிந்துகொள்ள வேண்டும்.', 'I'),
  (3, 'You work through the comments, adopt what you agree with, and politely push back on the points that conflict with your manager''s direction.', 'நீங்கள் கருத்துக்களைப் படித்துப் பார்த்து, உங்களுடன் உடன்படுபவற்றை ஏற்றுக்கொண்டு, உங்கள் மேலாளரின் வழிகாட்டுதலுக்கு முரண்படும் கருத்துக்களைப் பணிவுடன் மறுக்க வேண்டும்.', 'S'),
  (4, 'You feel overwhelmed but do not say so - you sit with the document for a while and try to figure out a version that will satisfy both of them.', 'நீங்கள் மிகுந்த மனச்சுமையை உணர்ந்தாலும் அதை வெளிக்காட்டாமல், அந்த ஆவணத்துடன் சிறிது நேரம் இருந்து, அவர்கள் இருவரையும் திருப்திப்படுத்தும் ஒரு வடிவத்தைக் கண்டறிய முயற்சிப்பீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q15',
     'What matters more to you in this moment? Your manager has just given you feedback that you need to be more proactive. Last week she gave you feedback that you were moving too fast without checking in. You are sitting with both pieces of feedback and they feel like they are pointing in opposite directions.', 'How to handle conflicting feedback?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? நீங்கள் இன்னும் முனைப்புடன் செயல்பட வேண்டும் என்று உங்கள் மேலாளர் இப்போதுதான் கருத்துத் தெரிவித்திருக்கிறார். கடந்த வாரம், நீங்கள் யாரிடமும் கலந்தாலோசிக்காமல் மிகவும் வேகமாகச் செயல்படுவதாக அவர் கருத்துத் தெரிவித்தார். இந்த இரண்டு கருத்துக்களையும் நீங்கள் கையில் வைத்திருக்கிறீர்கள், ஆனால் அவை இரண்டும் ஒன்றுக்கொன்று முரண்பட்ட திசைகளில் சுட்டிக்காட்டுவது போல் உங்களுக்குத் தோன்றுகிறது.', 'முரண்பாடான கருத்துக்களை எவ்வாறு கையாள்வது?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Understanding exactly what she means - you cannot act on feedback that contradicts itself and you need clarity before you change anything.', 'அவள் சொல்வதன் அர்த்தத்தைத் துல்லியமாகப் புரிந்துகொள்வது அவசியம் - முரண்பாடான ஒரு கருத்தின் அடிப்படையில் நீங்கள் செயல்பட முடியாது, மேலும் எதையும் மாற்றுவதற்கு முன்பு உங்களுக்குத் தெளிவு தேவை.', 'D'),
  (2, 'Adapting anyway - even if the feedback feels inconsistent, the signal is that something needs to shift and you should figure out what that is.', 'எப்படியும் மாற்றியமைத்துக் கொள்ளுங்கள் - வரும் கருத்துகள் சீரற்றதாகத் தோன்றினாலும், ஏதோவொன்றை மாற்ற வேண்டும் என்பதற்கான அறிகுறி அது; அந்த மாற்றம் என்ன என்பதை நீங்கள் கண்டறிய வேண்டும்.', 'I'),
  (3, 'Being seen as someone who takes feedback seriously - how you respond to this matters more right now than whether the feedback is consistent.', 'பின்னூட்டங்களைச் sérieux ஆக எடுத்துக்கொள்பவர் என்று அறியப்படுவது - பின்னூட்டம் சீரானதாக இருக்கிறதா என்பதை விட, நீங்கள் அதற்கு எவ்வாறு பதிலளிக்கிறீர்கள் என்பது தற்போது மிகவும் முக்கியமானது.', 'S'),
  (4, 'Your own read of the situation - you have been watching closely and you trust your own instincts more than feedback that keeps changing.', 'சூழ்நிலையைப் பற்றிய உங்கள் சொந்தப் பார்வை - நீங்கள் உன்னிப்பாகக் கவனித்து வருகிறீர்கள், மேலும் மாறிக்கொண்டே இருக்கும் கருத்துக்களை விட உங்கள் சொந்த உள்ளுணர்வை அதிகம் நம்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q16',
     'Before you say anything - you are in a one-on-one with your manager. She has just finished telling you that your work has been strong but that some people on the team find you hard to read. You did not expect this. You do not know who said it or what specifically they meant.', 'What is your immediate reaction?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - உங்கள் மேலாளருடன் நீங்கள் ஒரு தனிப்பட்ட சந்திப்பில் இருக்கிறீர்கள். உங்கள் பணி சிறப்பாக இருந்தபோதிலும், குழுவில் உள்ள சிலருக்கு உங்கள் மனநிலையைப் புரிந்துகொள்வது கடினமாக இருக்கிறது என்று அவர் சற்று முன்புதான் உங்களிடம் கூறி முடித்திருக்கிறார். இதை நீங்கள் எதிர்பார்க்கவில்லை. அதை யார் சொன்னார்கள் என்றோ அல்லது அவர்கள் குறிப்பாக என்ன குறிப்பிட்டார்கள் என்றோ உங்களுக்குத் தெரியாது.', 'உங்கள் உடனடி எதிர்வினை என்ன?',
     '{"theme": "Handling Feedback and Criticism", "layer": "Layer 3", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A sudden hyperawareness of every interaction you have had in the last three months - trying to locate the moment this started.', 'கடந்த மூன்று மாதங்களில் நீங்கள் மேற்கொண்ட ஒவ்வொரு தொடர்பையும் திடீரென மிகையாக உணர்வது - இது எப்போது தொடங்கியது என்பதைக் கண்டறிய முயற்சிப்பது.', 'D'),
  (2, 'A cold defensiveness - you have been nothing but professional and the vagueness of this feedback makes it impossible to do anything useful with.', 'ஒரு உணர்ச்சியற்ற தற்காப்பு மனப்பான்மை - நீங்கள் தொழில்முறையாக மட்டுமே நடந்துகொண்டீர்கள், மேலும் இந்தக் கருத்தின் தெளிவற்ற தன்மையால் இதிலிருந்து எந்தப் பயனுள்ள செயலையும் செய்ய இயலவில்லை.', 'I'),
  (3, 'A genuine curiosity underneath the discomfort - you have suspected something was off and this confirms it even if it does not explain it.', 'அசௌகரியத்திற்கு அடியில் ஒரு உண்மையான ஆர்வம் - ஏதோ சரியில்லை என்று நீங்கள் சந்தேகித்தீர்கள், இதை விளக்க முடியாவிட்டாலும் இது அதை உறுதிப்படுத்துகிறது.', 'S'),
  (4, 'A fear that this will follow you - that it is now in someone''s head as a data point about who you are, and you cannot take it back.', 'இது உங்களைத் தொடரும் என்ற பயம் - அதாவது, நீங்கள் யார் என்பதைப் பற்றிய ஒரு தரவுப் புள்ளியாக இது இப்போது ஒருவரின் மனதில் பதிந்துவிட்டது, மேலும் இதை உங்களால் திரும்பப் பெற முடியாது என்ற அச்சம்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q17',
     'You have been in your role for fourteen months. You feel you are doing the work of someone a level above you. Your manager has told you informally that you are performing well but the formal review cycle is still four months away. A peer with less experience just got a title change through a different route.', 'How should you handle this?', 'நீங்கள் இந்தப் பதவியில் பதினான்கு மாதங்களாக இருக்கிறீர்கள். உங்களை விட ஒரு படி உயர்ந்த நிலையில் உள்ள ஒருவரின் வேலையை நீங்கள் செய்வதாக உணர்கிறீர்கள். நீங்கள் நன்றாகச் செயல்படுவதாக உங்கள் மேலாளர் முறைசாராமல் கூறியுள்ளார், ஆனால் முறையான மதிப்பாய்வுச் சுழற்சி இன்னும் நான்கு மாதங்கள் தொலைவில் உள்ளது. குறைந்த அனுபவம் உள்ள உங்கள் சக ஊழியர் ஒருவர் வேறு ஒரு வழியில் சமீபத்தில் பதவி மாற்றம் பெற்றுள்ளார்.', 'இதை நீங்கள் எப்படி கையாள வேண்டும்?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 1", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You wait for the review cycle - raising it now will seem reactive and you do not want to look like you are only motivated by titles.', 'நீங்கள் மதிப்பாய்வுச் சுழற்சிக்காகக் காத்திருங்கள் - இப்போது அதை எழுப்புவது ஒரு எதிர்வினையாகத் தோன்றும், மேலும் நீங்கள் பதவிகளுக்காக மட்டுமே செயல்படுபவர் போல் தோற்றமளிக்க விரும்ப மாட்டீர்கள்.', 'D'),
  (2, 'You ask your manager for a conversation specifically about your development trajectory and what the path forward looks like.', 'உங்கள் வளர்ச்சிப் பாதை மற்றும் எதிர்காலத் திட்டம் எப்படி இருக்கும் என்பது குறித்து குறிப்பாக உரையாட உங்கள் மேலாளரிடம் கேட்கிறீர்கள்.', 'I'),
  (3, 'You say nothing but quietly start paying attention to what opportunities exist inside or outside the organisation.', 'நீங்கள் எதுவும் பேசாமல், நிறுவனத்திற்கு உள்ளேயோ அல்லது வெளியேயோ இருக்கும் வாய்ப்புகளை அமைதியாகக் கவனிக்கத் தொடங்குங்கள்.', 'S'),
  (4, 'You ask your manager what the process looks like for recognition that happens outside of the formal cycle.', 'முறைசார்ந்த சுழற்சிக்கு வெளியே நடைபெறும் அங்கீகாரச் செயல்முறை எப்படி இருக்கும் என்று உங்கள் மேலாளரிடம் கேளுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q18',
     'You pitched an idea in a team meeting three weeks ago. It was received politely but nothing happened. Last week a senior person raised almost the same idea in a leadership review and it is now being fast-tracked. Nobody connected it back to you.', 'How do you handle this?', 'மூன்று வாரங்களுக்கு முன்பு நடந்த குழுக்கூட்டத்தில் நீங்கள் ஒரு யோசனையை முன்வைத்தீர்கள். அது மரியாதையுடன் ஏற்றுக்கொள்ளப்பட்டது, ஆனால் எதுவும் நடக்கவில்லை. கடந்த வாரம், ஒரு மூத்த அதிகாரி தலைமைத்துவ மீளாய்வில் ஏறக்குறைய அதே யோசனையை முன்வைத்தார், இப்போது அது விரைவுபடுத்தப்படுகிறது. யாரும் அதை உங்களுடன் தொடர்புபடுத்தவில்லை.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 1", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You let it go - good ideas find their moment and getting territorial about who thought of something first is not a good look.', 'அதை விட்டுவிடுங்கள் - நல்ல யோசனைகள் அவற்றுக்கான தருணத்தைக் கண்டறியும், மேலும் ஒரு விஷயத்தை முதலில் யார் யோசித்தது என்று உரிமை கொண்டாடுவது நல்லதல்ல.', 'D'),
  (2, 'You mention it to your manager - not to make a point but to make sure she knows your thinking was ahead of the curve.', 'நீங்கள் அதை உங்கள் மேலாளரிடம் குறிப்பிடுவது, உங்கள் கருத்தை வலியுறுத்துவதற்காக அல்ல, மாறாக உங்கள் சிந்தனை காலத்திற்கு முந்தையது என்பதை அவர் அறிந்துகொள்ளச் செய்வதற்காகவே.', 'I'),
  (3, 'You bring it up in a relevant conversation to make the connection visible without being explicit about the credit.', 'அதற்கான பெருமையை வெளிப்படையாகக் குறிப்பிடாமல், அந்தத் தொடர்பை உணர்த்துவதற்காகப் பொருத்தமான உரையாடலில் நீங்கள் அதைக் குறிப்பிடுகிறீர்கள்.', 'S'),
  (4, 'You note it internally as a reminder to find better ways to make your ideas land with the right people at the right time.', 'உங்கள் யோசனைகள் சரியான நேரத்தில் சரியான நபர்களிடம் சென்றடைவதற்கான சிறந்த வழிகளைக் கண்டறிய வேண்டும் என்பதை நினைவூட்டும் விதமாக, நீங்கள் அதை மனதிற்குள் குறித்துக் கொள்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q19',
     'Two things are pulling at you. Which is stronger? You have just been told unofficially that you are being considered for a stretch assignment - something above your current level. The person who told you is not the decision-maker. Nothing is confirmed. You have been waiting for something like this for nearly a year.', 'Which pulling force is stronger?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? உங்கள் தற்போதைய நிலைக்கு அப்பாற்பட்ட, ஒரு சவாலான பணிக்கு நீங்கள் பரிசீலிக்கப்படுவதாக அதிகாரப்பூர்வமற்ற முறையில் உங்களுக்குத் தெரிவிக்கப்பட்டுள்ளது. இதை உங்களுக்குத் தெரிவித்தவர் முடிவெடுப்பவர் அல்ல. எதுவும் உறுதி செய்யப்படவில்லை. இது போன்ற ஒன்றுக்காக நீங்கள் கிட்டத்தட்ட ஒரு வருடமாகக் காத்து வருகிறீர்கள்.', 'எந்த இழுவிசை வலிமையானது?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 2", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The excitement of finally being seen - after months of putting in the work, this feels like evidence that it was worth it.', 'மாதக்கணக்கில் உழைத்த பிறகு, இறுதியாகக் கவனிக்கப்படுவதில் ஏற்படும் உற்சாகம் - அந்த உழைப்புக்குக் கிடைத்த பலன் இது என்பதற்கு இதுவே சான்று போல் தோன்றுகிறது.', 'D'),
  (2, 'The caution of not knowing what is real - you have learned not to count on things that have not been decided yet.', 'எது நிஜம் என்று தெரியாததின் எச்சரிக்கை - இன்னும் தீர்மானிக்கப்படாத விஷயங்களை நம்பி இருக்கக் கூடாது என்பதை நீங்கள் கற்றுக்கொண்டீர்கள்.', 'I'),
  (3, 'The impatience of not being in the room - you want to advocate for yourself but you do not know who to speak to or whether doing so would help or hurt.', 'அந்த அறையில் இல்லாததால் ஏற்படும் பொறுமையின்மை - உங்களுக்காக நீங்களே வாதிட விரும்புகிறீர்கள், ஆனால் யாரிடம் பேசுவது என்றோ, அவ்வாறு செய்வது உதவுமா அல்லது தீங்கு விளைவிக்குமா என்றோ உங்களுக்குத் தெரியவில்லை.', 'S'),
  (4, 'The fear that you are not actually ready - that this might be real, and if it is, you are not sure you can deliver at that level yet.', 'நீங்கள் உண்மையில் தயாராக இல்லை என்ற பயம் - இது உண்மையாக இருக்கலாம், அப்படியே இருந்தாலும், அந்த அளவிற்கு உங்களால் இன்னும் செயல்பட முடியுமா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q20',
     'What is actually happening inside you - it is the end of a year in which you worked hard, delivered well, stayed late when it mattered, and said yes to things that were not your job. The formal recognition came in the form of a one-line comment in your review. You are sitting with that now.', 'How do you feel now?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால், நீங்கள் கடினமாக உழைத்து, சிறப்பாகச் செயல்பட்டு, தேவைப்பட்டபோது தாமதமாகத் தங்கி, உங்கள் வேலை அல்லாத விஷயங்களுக்கும் சம்மதம் தெரிவித்த ஓர் ஆண்டின் முடிவு இது. உங்களுக்கான முறையான அங்கீகாரம், உங்கள் மதிப்பாய்வில் இடம்பெற்ற ஓர் ஒற்றை வரிக் குறிப்பின் வடிவில் கிடைத்தது. இப்போது நீங்கள் அதனுடன் அமர்ந்திருக்கிறீர்கள்.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Ambition, Recognition and Patience", "layer": "Layer 3", "dimension": "career_patience", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A quiet anger that you are trying to decide whether is fair or whether it says more about your expectations than the organisation''s failure.', 'இது நியாயமானதா அல்லது நிறுவனத்தின் தோல்வியை விட உங்கள் எதிர்பார்ப்புகளையே அதிகம் வெளிப்படுத்துகிறதா என்று நீங்கள் தீர்மானிக்க முயலும் ஒரு அமைதியான கோபம்.', 'D'),
  (2, 'A tiredness that is more than physical - something in you is wondering whether the version of yourself you have been performing all year is actually sustainable.', 'உடல் ரீதியான சோர்வுக்கும் அப்பாற்பட்ட ஒன்று - இந்த ஆண்டு முழுவதும் நீங்கள் வெளிப்படுத்தி வந்த உங்களின் வடிவம் உண்மையில் நீடிக்கக்கூடியதா என்று உங்களுக்குள் இருக்கும் ஏதோ ஒன்று யோசிக்கிறது.', 'I'),
  (3, 'A resolve - you have been operating on someone else''s timeline and something in this moment is pushing you to define your own.', 'ஒரு உறுதி - நீங்கள் இதுவரை வேறொருவரின் கால அட்டவணைப்படி இயங்கி வந்தீர்கள், இந்தத் தருணத்தில் ஏதோ ஒன்று உங்களுக்கென ஒரு கால அட்டவணையை வரையறுக்க உங்களைத் தூண்டுகிறது.', 'S'),
  (4, 'A sadness you were not expecting - you thought you had made peace with patience and it turns out you had not.', 'நீங்கள் சற்றும் எதிர்பாராத ஒரு சோகம் - பொறுமையுடன் சமாதானமாகிவிட்டதாக நினைத்தீர்கள், ஆனால் உண்மையில் அப்படி ஆகவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q21',
     'You are in your seventh month at the company. The team has a style - self-deprecating, dry, fast-paced conversation - and you have been adapting to it. In a meeting today you made a comment in your natural voice, slightly more direct and earnest than the team norm, and you noticed two people exchange a glance.', 'How do you handle this?', 'நீங்கள் நிறுவனத்தில் சேர்ந்து ஏழாவது மாதத்தில் இருக்கிறீர்கள். அந்தக் குழுவிற்கு ஒரு தனிப் பாணி உண்டு - அது தன்னடக்கமான, விறுவிறுப்பான, வேகமான உரையாடல் பாணி - நீங்களும் அதற்குப் பழகி வருகிறீர்கள். இன்றைய கூட்டத்தில், குழுவின் வழக்கத்தை விடச் சற்றே நேரடியாகவும் உண்மையாகவும் உங்கள் இயல்பான குரலில் ஒரு கருத்தைத் தெரிவித்தீர்கள், அப்போது இருவர் ஒருவரையொருவர் பார்த்துக் கொள்வதை நீங்கள் கவனித்தீர்கள்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 1", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You file it away and start calibrating more carefully to what seems to work in this room.', 'நீங்கள் அதை ஒதுக்கி வைத்துவிட்டு, இந்த அறைக்கு எது பொருத்தமாகத் தெரிகிறதோ அதற்கேற்ப இன்னும் கவனமாகச் சரிசெய்யத் தொடங்குகிறீர்கள்.', 'D'),
  (2, 'You continue being yourself - you are not going to reshape your personality around one glance.', 'நீங்கள் நீங்களாகவே இருங்கள் - ஒரே ஒரு பார்வையால் உங்கள் ஆளுமையை மாற்றிக்கொள்ளப் போவதில்லை.', 'I'),
  (3, 'You think about it later but do not act on it - maybe it meant something, maybe it did not.', 'நீங்கள் அதைப்பற்றிப் பிறகு யோசிக்கிறீர்கள், ஆனால் அதன்படி செயல்படுவதில்லை - ஒருவேளை அதற்கு அர்த்தம் இருந்திருக்கலாம், இல்லாமலும் இருந்திருக்கலாம்.', 'S'),
  (4, 'You find a moment to test your read - you raise something similar in a smaller setting to see how it lands.', 'உங்கள் கணிப்பைச் சோதித்துப் பார்க்க ஒரு தருணத்தைக் கண்டறியுங்கள் - அது எடுபடுகிறதா என்று பார்க்க, ஒரு சிறிய சூழலில் அதுபோன்ற ஒரு கேள்வியை எழுப்புங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q22',
     'Your team goes out for drinks on a Friday. You do not drink and the whole social architecture of the evening is built around a bar, rounds, and late-night energy you do not share. You want to build relationships but this setting does not feel natural to you.', 'How do you handle this?', 'உங்கள் குழுவினர் ஒரு வெள்ளிக்கிழமை அன்று மது அருந்த வெளியே செல்கிறார்கள். உங்களுக்கு மது அருந்தும் பழக்கம் இல்லை, மேலும் அந்த மாலைப் பொழுதின் ஒட்டுமொத்த சமூகச் சூழலும், நீங்கள் பகிர்ந்துகொள்ளாத மதுக்கூடம், மதுப் பொட்டலங்கள் மற்றும் நள்ளிரவு நேர உற்சாகத்தை மையமாகக் கொண்டே அமைந்திருக்கிறது. நீங்கள் உறவுகளை வளர்க்க விரும்புகிறீர்கள், ஆனால் இந்தச் சூழல் உங்களுக்கு இயல்பானதாகத் தோன்றவில்லை.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 1", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You go, stay for a reasonable amount of time, connect with the people you want to connect with, and leave without making it a thing.', 'நீங்கள் செல்லுங்கள், நியாயமான காலத்திற்குத் தங்குங்கள், நீங்கள் தொடர்பு கொள்ள விரும்பும் நபர்களுடன் உரையாடுங்கள், பின்னர் அதை ஒரு பெரிய விஷயமாக ஆக்காமல் கிளம்பிவிடுங்கள்.', 'D'),
  (2, 'You decline politely and suggest a different format at a different time - a lunch or coffee - where you would be more genuinely present.', 'நீங்கள் பணிவுடன் மறுத்துவிட்டு, மதிய உணவு அல்லது காபி போன்ற வேறு ஒரு நேரத்தில், உங்களால் முழுமையாகக் கலந்துகொள்ளக்கூடிய ஒரு மாற்று வடிவத்தைப் பரிந்துரைக்கிறீர்கள்.', 'I'),
  (3, 'You go and work harder in this setting than you would need to in any other - you know the value of being present even when it is uncomfortable.', 'வேறு எந்தச் சூழலிலும் தேவைப்படுவதை விட, இந்தச் சூழலில் நீங்கள் சென்று கடினமாக உழைக்கிறீர்கள் - சங்கடமாக இருக்கும்போதும் நிகழ்காலத்தில் இருப்பதன் மதிப்பை நீங்கள் அறிவீர்கள்.', 'S'),
  (4, 'You feel the tension between belonging and staying true to yourself and you have not fully resolved it yet.', 'ஒரு குழுவில் சேர்வதற்கும், உங்களுக்கு உண்மையாக இருப்பதற்கும் இடையிலான பதற்றத்தை நீங்கள் உணர்கிறீர்கள், ஆனால் அதை இன்னும் முழுமையாகத் தீர்க்கவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q23',
     'The conflict you feel most is between - you have started to notice that the version of you at work and the version of you outside work are becoming increasingly different people. At work you are quieter, more careful, more measured. Outside you are quicker, funnier, more yourself. You are not sure which version is performing.', 'Which work persona is authentic?', 'நீங்கள் அதிகமாக உணரும் முரண்பாடு என்னவென்றால், பணியிடத்தில் இருக்கும் உங்களின் தன்மையும், பணிக்கு வெளியே இருக்கும் உங்களின் தன்மையும் மேலும் மேலும் மாறுபட்டு வருவதை நீங்கள் கவனிக்கத் தொடங்கியுள்ளீர்கள். பணியிடத்தில் நீங்கள் அமைதியாகவும், அதிகக் கவனமாகவும், நிதானமாகவும் இருக்கிறீர்கள். பணிக்கு வெளியே நீங்கள் வேகமாகவும், நகைச்சுவையாகவும், இயல்பாகவும் இருக்கிறீர்கள். இந்த இரண்டில் எது சிறப்பாகச் செயல்படுகிறது என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'எந்தப் பணி ஆளுமை உண்மையானது?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Authenticity and safety - you want to bring more of yourself to work but you do not yet know what is welcomed and what is held against you.', 'உண்மைத்தன்மை மற்றும் பாதுகாப்பு - நீங்கள் பணியிடத்தில் உங்களின் இயல்பான தன்மையை மேலும் வெளிப்படுத்த விரும்புகிறீர்கள், ஆனால் எது வரவேற்கப்படும், எது உங்களுக்கு எதிராகப் பயன்படுத்தப்படும் என்பது உங்களுக்கு இன்னும் தெரியவில்லை.', 'D'),
  (2, 'Your own comfort and the team''s expectations - you have started adapting so automatically you are not sure you could stop if you wanted to.', 'உங்கள் சொந்த சௌகரியம் மற்றும் அணியின் எதிர்பார்ப்புகள் - இவற்றால் நீங்கள் மிகவும் இயல்பாகப் பழகத் தொடங்கிவிட்டீர்கள்; விரும்பினாலும் உங்களால் அதை நிறுத்த முடியுமா என்பதே உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'I'),
  (3, 'Short-term belonging and long-term identity - the cost of fitting in right now might be something you pay for much later.', 'குறுகிய காலப் பிணைப்பும் நீண்ட கால அடையாளமும் - இப்போதைக்குப் பொருந்திப் போவதற்கான விலையாக, நீங்கள் மிக நீண்ட காலத்திற்குப் பிறகு பெரும் விலையைக் கொடுக்க நேரிடலாம்.', 'S'),
  (4, 'What you want to show and what you feel you are allowed to show - and the space between those two things is getting smaller.', 'நீங்கள் எதைக் காட்ட விரும்புகிறீர்கள், எதைக் காட்ட உங்களுக்கு அனுமதி உண்டு என்று நீங்கள் உணர்கிறீர்கள் - இந்த இரண்டுக்கும் இடையிலான இடைவெளி சுருங்கிக்கொண்டே வருகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q24',
     'Before you say anything - a senior colleague pulls you aside after a team presentation and tells you that you have real presence. That when you speak people listen. She says it as a genuine compliment with nothing attached to it. You are standing in the corridor. You do not know what to do with this.', 'What is happening inside you?', 'நீங்கள் எதையும் சொல்வதற்கு முன், ஒரு குழு விளக்கக்காட்சிக்குப் பிறகு, ஒரு மூத்த சக ஊழியர் உங்களைத் தனியாக அழைத்து, உங்களுக்கு உண்மையான ஆளுமை இருப்பதாகச் சொல்கிறார். நீங்கள் பேசும்போது மக்கள் கவனிப்பார்கள் என்றும் கூறுகிறார். அவர் அதை எந்தவித உள்நோக்கமும் இல்லாத ஒரு உண்மையான பாராட்டாகச் சொல்கிறார். நீங்கள் தாழ்வாரத்தில் நின்று கொண்டிருக்கிறீர்கள். இதை வைத்து என்ன செய்வதென்று உங்களுக்குத் தெரியவில்லை.', 'உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "Fitting In and Professional Identity", "layer": "Layer 3", "dimension": "approval_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A sudden vulnerability - being seen feels exposing in a way that being invisible did not and you are not sure you were ready for it.', 'திடீரென ஏற்படும் ஒரு பலவீனம் - மறைந்திருப்பதைப் போலல்லாமல், பிறர் கண்ணில் படும்போது தன்னை வெளிப்படுத்துவது போன்ற ஓர் உணர்வைத் தருகிறது, மேலும் அதற்கு நீங்கள் தயாராக இருந்தீர்களா என்பதும் உங்களுக்கு உறுதியாகத் தெரிவதில்லை.', 'D'),
  (2, 'A hunger you did not know was there - you realise in this moment how much you have needed someone to say this and how long you have been waiting.', 'உங்களுக்குள் இருந்தும் நீங்கள் அறியாத ஒரு ஏக்கம் - இதைச் சொல்வதற்கு ஒருவர் உங்களுக்கு எவ்வளவு தேவைப்பட்டிருக்கிறார் என்பதையும், எவ்வளவு காலமாக நீங்கள் காத்து வந்திருக்கிறீர்கள் என்பதையும் இந்தத் தருணத்தில் உணர்கிறீர்கள்.', 'I'),
  (3, 'A scepticism you are trying to suppress - you are waiting for the part where this comes with a task or an expectation.', 'நீங்கள் அடக்க முயற்சிக்கும் ஒரு ஐயுறவு மனப்பான்மை - இது ஒரு பணியுடனோ அல்லது எதிர்பார்ப்புடனோ வரும் தருணத்திற்காகக் காத்திருக்கிறீர்கள்.', 'S'),
  (4, 'A quiet joy that you will not let yourself fully feel until you are alone - because feeling it here, in front of someone, feels too much like wanting something.', 'நீங்கள் தனியாக இருக்கும் வரை முழுமையாக உணர அனுமதிக்காத ஒரு அமைதியான மகிழ்ச்சி - ஏனென்றால், அதை இங்கே, ஒருவரின் முன்னிலையில் உணர்வது, எதையோ விரும்புவது போல மிகையாகத் தோன்றும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q25',
     'Your manager asks you to adjust the numbers in a monthly performance report before it goes to the wider leadership team. The change is small - moving one figure from this month to last to make the trend look smoother. She frames it as a presentation decision, not a factual one. You are not sure you agree.', 'How to handle adjusted numbers?', 'விரிவான தலைமைத்துவக் குழுவிடம் சமர்ப்பிக்கப்படும் மாதாந்திர செயல்திறன் அறிக்கையில் உள்ள எண்களைச் சரிசெய்யுமாறு உங்கள் மேலாளர் உங்களைக் கேட்கிறார். அந்த மாற்றம் சிறியது - செயல்திறன் போக்கைச் சீராகக் காட்டுவதற்காக, இந்த மாதத்திலிருந்து ஒரு எண்ணைக் கடந்த மாதத்திற்கு மாற்றுவது. அவர் அதை ஒரு உண்மை சார்ந்த முடிவாகக் கூறாமல், காட்சிப்படுத்துவதற்கான ஒரு முடிவாக முன்வைக்கிறார். நீங்கள் அதை ஏற்றுக்கொள்கிறீர்களா என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'சரிசெய்யப்பட்ட எண்களை எவ்வாறு கையாள்வது?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise your concern directly - you tell her the change feels like it misrepresents the trend and ask if there is another way to present it.', 'உங்கள் கவலையை நேரடியாகத் தெரிவியுங்கள் - இந்த மாற்றம் தற்போதைய போக்கைத் தவறாகப் பிரதிபலிப்பது போல் தோன்றுவதாக அவரிடம் கூறி, அதை முன்வைக்க வேறு வழி உள்ளதா என்று கேளுங்கள்.', 'D'),
  (2, 'You make the change - she is your manager and she has more context about what leadership expects than you do.', 'மாற்றத்தை நீங்கள் செய்யுங்கள் - அவர் உங்கள் மேலாளர், மேலும் தலைமைத்துவம் என்ன எதிர்பார்க்கிறது என்பது பற்றி உங்களை விட அவருக்கு அதிகப் புரிதல் உள்ளது.', 'I'),
  (3, 'You ask a clarifying question - you want to understand her reasoning before you decide how to respond.', 'நீங்கள் ஒரு தெளிவுபடுத்தும் கேள்வியைக் கேட்கிறீர்கள் - எப்படிப் பதிலளிப்பது என்று தீர்மானிப்பதற்கு முன், அவளுடைய வாதத்தின் காரணத்தைப் புரிந்துகொள்ள விரும்புகிறீர்கள்.', 'S'),
  (4, 'You make the change but you keep a copy of the original - you do not want to be the person who altered the numbers without a record of what they were.', 'நீங்கள் மாற்றத்தைச் செய்கிறீர்கள், ஆனால் அசலின் ஒரு நகலை வைத்துக்கொள்ளுங்கள் - எண்கள் என்னவாக இருந்தன என்பதற்கான பதிவு இல்லாமல் அவற்றை மாற்றிய நபராக நீங்கள் இருக்க விரும்ப மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q26',
     'A colleague asks you to say that you both worked on a proposal when the work was entirely yours. She was supposed to contribute but was pulled into something else. She says it will make things easier for both of you - her manager will not ask questions and you will not have to explain the solo work.', 'How do you handle this?', 'முழுக்க முழுக்க உங்களுடைய வேலையாக இருந்த ஒரு திட்ட முன்மொழிவில், நீங்கள் இருவரும் இணைந்து பணியாற்றியதாகக் கூறுமாறு ஒரு சக ஊழியர் உங்களைக் கேட்கிறார். அவரும் பங்களிக்க வேண்டியிருந்தும், வேறு ஒரு வேலையில் சிக்கிக்கொண்டார். இது உங்கள் இருவருக்கும் விஷயங்களை எளிதாக்கும் என்றும், அவருடைய மேலாளர் கேள்விகள் கேட்க மாட்டார் என்றும், நீங்கள் தனியாகச் செய்த வேலையை விளக்க வேண்டிய அவசியம் இருக்காது என்றும் அவர் கூறுகிறார்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 1", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell her you are not comfortable saying something that is not true and you will find another way to handle the explanation together.', 'உண்மையல்லாத ஒன்றைச் சொல்வதில் உங்களுக்குச் சங்கடமாக இருப்பதாகவும், அந்த விளக்கத்தை இருவரும் சேர்ந்து கையாள்வதற்கு வேறு வழியைக் கண்டுபிடிப்பீர்கள் என்றும் அவளிடம் சொல்லுங்கள்.', 'D'),
  (2, 'You go along with it - it is a small thing and it is not worth damaging the relationship over.', 'நீங்கள் அதற்குச் சம்மதியுங்கள் - இது ஒரு சிறிய விஷயம், இதற்காக உறவைச் சேதப்படுத்திக்கொள்ள வேண்டிய அவசியமில்லை.', 'I'),
  (3, 'You tell her you will not actively say you both worked on it but you will not correct anyone who assumes it either.', 'நீங்கள் இருவரும் இதில் பணியாற்றினீர்கள் என்று வெளிப்படையாகச் சொல்ல மாட்டீர்கள் என்றும், அதே சமயம் அப்படி ஊகிப்பவர்களை நீங்கள் திருத்தவும் மாட்டீர்கள் என்றும் அவளிடம் கூறுங்கள்.', 'S'),
  (4, 'You raise it with your manager yourself - not to get her in trouble but to get ahead of a version of events that is not accurate.', 'உங்கள் மேலாளருக்குச் சிக்கலை ஏற்படுத்துவதற்காக அல்ல, மாறாக, உண்மை அல்லாத ஒரு சம்பவத்தின் பதிப்பை முன்கூட்டியே தவிர்ப்பதற்காக, நீங்களே அவரிடம் இதைப் பற்றிப் பேசுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q27',
     'What matters more to you in this moment? You are in a room where a decision is being made that you think is wrong. Not unethical - just wrong. The person driving the decision is two levels above you. Everyone else in the room is nodding. You have one piece of information they have not considered.', 'Should you speak up now?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? நீங்கள் இருக்கும் அறையில் எடுக்கப்படும் ஒரு முடிவு தவறானது என்று நீங்கள் நினைக்கிறீர்கள். அது அறநெறிக்கு விரோதமானது அல்ல - வெறுமனே தவறானது. அந்த முடிவை எடுப்பவர் உங்களை விட இரண்டு படிநிலைகள் உயர்ந்தவர். அறையில் உள்ள மற்ற அனைவரும் தலையசைக்கிறார்கள். அவர்கள் கருத்தில் கொள்ளாத ஒரு தகவல் உங்களிடம் உள்ளது.', 'நீங்கள் இப்போது பேச வேண்டுமா?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 2", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Saying what you know - if the information is relevant, staying quiet makes you complicit in a bad outcome.', 'உங்களுக்குத் தெரிந்ததைச் சொல்லுங்கள் - அந்தத் தகவல் பொருத்தமானதாக இருந்தால், அமைதியாக இருப்பது ஒரு மோசமான விளைவுக்கு உங்களையும் உடந்தையாக்கிவிடும்.', 'D'),
  (2, 'Reading the room - this is not your decision and inserting yourself could cost more than the decision itself.', 'சூழலைப் புரிந்து கொள்ளுங்கள் - இது உங்கள் முடிவு அல்ல, இதில் நீங்கள் தலையிடுவது அந்த முடிவை விட அதிக விலையை ஏற்படுத்தக்கூடும்.', 'I'),
  (3, 'Protecting the relationship - you can find a way to surface the information later without disrupting the dynamic in this room right now.', 'உறவைப் பாதுகாத்தல் - தற்போதைய இந்த அறையின் சூழலைக் குலைக்காமல், அந்தத் தகவலைப் பின்னர் வெளிக்கொணர ஒரு வழியைக் கண்டறியலாம்.', 'S'),
  (4, 'Being the person you want to be - not because it changes the outcome but because you have to live with how you showed up.', 'நீங்கள் எப்படி இருக்க விரும்புகிறீர்களோ, அப்படியே இருப்பது - அது முடிவை மாற்றும் என்பதற்காக அல்ல, மாறாக நீங்கள் எப்படி வெளிப்பட்டீர்களோ அதனுடன் வாழ வேண்டியிருப்பதால்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q28',
     'The honest feeling underneath this - you witnessed something at work last week that did not sit right. Not something dramatic - a comment made in a closed meeting that felt designed to exclude someone, a process that seems to benefit some people and not others, a small thing that most people would call normal. You have been sitting with it since then.', 'How do you feel now?', 'இதன் அடிப்படையிலான உண்மையான உணர்வு இதுதான் - கடந்த வாரம் பணியிடத்தில் உங்களுக்குச் சரியெனத் தோன்றாத ஒரு விஷயத்தை நீங்கள் கண்டீர்கள். அது ஒன்றும் பெரிய பிரச்சனையல்ல - ஒரு மூடிய கூட்டத்தில், யாரையோ ஒதுக்கும் நோக்கத்தில் சொல்லப்பட்டது போன்ற ஒரு கருத்து; சிலருக்குப் பயனளித்து மற்றவர்களுக்குப் பயனளிக்காத ஒரு செயல்முறை; பெரும்பாலானோர் இயல்பானது என்று கருதும் ஒரு சிறிய விஷயம். அன்று முதல் நீங்கள் அதைப்பற்றியே சிந்தித்துக்கொண்டிருக்கிறீர்கள்.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Integrity Under Pressure", "layer": "Layer 3", "dimension": "upward_courage", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A frustration at your own uncertainty - you cannot tell if your instinct is right or if you are just not experienced enough yet to understand how these things work.', 'உங்கள் சொந்த நிச்சயமற்ற தன்மையால் ஏற்படும் விரக்தி - உங்கள் உள்ளுணர்வு சரியா அல்லது இந்த விஷயங்கள் எப்படிச் செயல்படுகின்றன என்பதைப் புரிந்துகொள்ளும் அளவுக்கு உங்களுக்கு இன்னும் அனுபவம் போதவில்லையா என்பதை உங்களால் சொல்லிக்கொள்ள முடியாது.', 'D'),
  (2, 'A loneliness - you have looked around and no one else seems troubled by it and that is the part that bothers you most.', 'ஒரு தனிமை - உங்களைச் சுற்றிப் பார்த்தும், வேறு யாரும் அதனால் பாதிக்கப்படுவதாகத் தெரியவில்லை; அதுதான் உங்களை மிகவும் தொந்தரவு செய்யும் விஷயம்.', 'I'),
  (3, 'A slow-burning clarity - the more time passes the more sure you are that something was wrong, even if you cannot fully name it yet.', 'மெதுவாகப் புரியக்கூடிய தெளிவு - காலம் செல்லச் செல்ல, ஏதோ தவறு நடந்திருக்கிறது என்பதில் உங்களுக்கு உறுதி வலுப்பெறும், அதை உங்களால் இன்னும் முழுமையாகக் கூற முடியாவிட்டாலும் கூட.', 'S'),
  (4, 'A fear of being the person who speaks up - not because you think you are wrong but because you have seen what happens to people who raise things too early.', 'குரல் கொடுக்கும் நபராக இருப்பதற்கு ஏற்படும் பயம் - நீங்கள் தவறு செய்கிறீர்கள் என்று நினைப்பதனால் அல்ல, மாறாக, விஷயங்களை மிக விரைவில் கிளப்புபவர்களுக்கு என்ன நடக்கிறது என்பதைப் பார்த்திருப்பதால்தான்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q29',
     'You need to push back on a timeline your manager has set. The deadline is not realistic and you know it will mean producing work that is not good enough. You have tried once before to raise a timeline concern and it did not land well. You are writing the message now.', 'How do you handle this?', 'உங்கள் மேலாளர் நிர்ணயித்த காலக்கெடுவை நீங்கள் எதிர்க்க வேண்டும். அந்தக் காலக்கெடு யதார்த்தமானதல்ல, மேலும் அது போதுமான தரமற்ற வேலையைச் செய்ய வழிவகுக்கும் என்பதும் உங்களுக்குத் தெரியும். காலக்கெடு குறித்த உங்கள் கவலையை இதற்கு முன்பும் ஒருமுறை எழுப்ப முயன்றீர்கள், ஆனால் அது நல்ல வரவேற்பைப் பெறவில்லை. இப்போது நீங்கள்தான் அந்தச் செய்தியை எழுதுகிறீர்கள்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 1", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You write a direct, factual message - here is the timeline, here is what it means for quality, here is what you recommend instead.', 'நீங்கள் ஒரு நேரடியான, உண்மையான செய்தியை எழுதுகிறீர்கள் - இதோ காலக்கெடு, தரத்தின் மீது இதன் தாக்கம் என்ன, இதற்குப் பதிலாக நீங்கள் பரிந்துரைப்பது என்ன என்பனவற்றை விளக்குங்கள்.', 'D'),
  (2, 'You frame it as a question - you ask whether the deadline is fixed or whether there is any flexibility given what you are working with.', 'நீங்கள் அதை ஒரு கேள்வியாக முன்வைக்கிறீர்கள் - காலக்கெடு நிர்ணயிக்கப்பட்டதா அல்லது நீங்கள் பணிபுரியும் சூழலைக் கருத்தில் கொண்டு ஏதேனும் நெகிழ்வுத்தன்மை உள்ளதா என்று கேட்கிறீர்கள்.', 'I'),
  (3, 'You ask for a conversation rather than trying to resolve it in writing - tone is easier to manage face to face.', 'எழுத்துப்பூர்வமாகத் தீர்க்க முயற்சிப்பதை விட, நேருக்கு நேர் உரையாடலுக்கு அழைப்பு விடுக்கிறீர்கள் - ஏனெனில் அப்போது பேச்சின் தொனியைக் கையாள்வது எளிது.', 'S'),
  (4, 'You sit on it for a few hours before sending anything - you want to be sure you are raising a real problem and not just anxiety about the workload.', 'எதையும் அனுப்புவதற்கு முன் சில மணிநேரம் அதைப் பற்றி யோசிக்க வேண்டும் - நீங்கள் எழுப்புவது வெறும் பணிச்சுமை குறித்த கவலையல்ல, மாறாக ஒரு உண்மையான பிரச்சினைதான் என்பதை உறுதிப்படுத்திக்கொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q30',
     'You sent an update to your team yesterday and a senior colleague has replied to the whole group saying your numbers do not match what she is seeing in the system. You have checked and you are right. She has either misread the system or is working from an older version.', 'How to handle senior''s mistake?', 'நேற்று உங்கள் குழுவிற்கு நீங்கள் ஒரு புதுப்பிப்பை அனுப்பியிருந்தீர்கள். அதற்கு ஒரு மூத்த சக ஊழியர், உங்கள் புள்ளிவிவரங்கள் கணினி அமைப்பில் அவர் பார்க்கும் புள்ளிவிவரங்களுடன் பொருந்தவில்லை என்று முழு குழுவிற்கும் பதிலளித்துள்ளார். நீங்கள் சரிபார்த்ததில், நீங்கள் சொல்வது சரிதான் என்பது உறுதியானது. அவர் கணினி அமைப்பைத் தவறாகப் புரிந்துகொண்டிருக்க வேண்டும் அல்லது அதன் பழைய பதிப்பைப் பயன்படுத்திக்கொண்டிருக்க வேண்டும்.', 'மூத்தவரின் தவறை எவ்வாறு கையாள்வது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 1", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You reply to the group calmly, walk through the source of your numbers, and explain the discrepancy without making it a confrontation.', 'நீங்கள் குழுவிற்கு அமைதியாகப் பதிலளித்து, உங்கள் புள்ளிவிவரங்களின் மூலத்தை விளக்கி, அதை ஒரு மோதலாக மாற்றாமல் முரண்பாட்டை விளக்குங்கள்.', 'D'),
  (2, 'You message her privately first to give her the chance to correct herself before the whole group sees the resolution.', 'முழு குழுவும் அந்தத் தீர்வைப் பார்க்கும் முன், அவள் தன்னைத் திருத்திக்கொள்ள வாய்ப்பளிக்கும் வகையில், நீங்கள் முதலில் அவளுக்குத் தனிப்பட்ட முறையில் செய்தி அனுப்புங்கள்.', 'I'),
  (3, 'You go back and check one more time before you say anything - the possibility that you are wrong, even at one percent, stops you from replying immediately.', 'எதையும் சொல்வதற்கு முன், நீங்கள் மீண்டும் ஒருமுறை சரிபார்த்துக் கொள்கிறீர்கள் - ஒரு சதவிகிதம் தவறாக இருக்கக்கூடும் என்ற சாத்தியக்கூறு கூட, உடனடியாகப் பதிலளிப்பதிலிருந்து உங்களைத் தடுக்கிறது.', 'S'),
  (4, 'You reply to the group with your source clearly cited and let the data speak without commenting on what she may have looked at.', 'உங்கள் ஆதாரத்தைத் தெளிவாகக் குறிப்பிட்டு, அவர் எதைப் பார்த்திருக்கலாம் என்பது குறித்துக் கருத்துத் தெரிவிக்காமல், தரவுகளே பேசட்டும் என்று குழுவிற்குப் பதிலளிக்கவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q31',
     'Two things are pulling at you. Which is stronger? You have a piece of feedback for a colleague - something specific that is affecting a project you share. You know how to say it professionally. But you also know she is going through something difficult personally right now and the timing feels wrong.', 'Which pulling force is stronger?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? உங்கள் சக ஊழியர் ஒருவருக்கு ஒரு கருத்தைத் தெரிவிக்க விரும்புகிறீர்கள் - அது நீங்கள் இருவரும் இணைந்து பணியாற்றும் ஒரு திட்டத்தைப் பாதிக்கும் ஒரு குறிப்பிட்ட விஷயம். அதைத் தொழில்முறையாக எப்படிச் சொல்வது என்று உங்களுக்குத் தெரியும். ஆனால், அவர் தற்போது தனிப்பட்ட முறையில் ஒரு கடினமான சூழலைச் சந்தித்துக் கொண்டிருக்கிறார் என்பதும், இதைச் சொல்வதற்கு இது சரியான நேரம் இல்லை என்பதும் உங்களுக்குத் தெரியும்.', 'எந்த இழுவிசை வலிமையானது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 2", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The project - the feedback needs to land before the next milestone or the work will suffer, whatever is happening personally.', 'தனிப்பட்ட முறையில் என்ன நடந்தாலும், அடுத்த கட்டத்தை எட்டுவதற்குள் திட்டத்திற்கான பின்னூட்டம் சென்றடைய வேண்டும், இல்லையெனில் பணி பாதிக்கப்படும்.', 'D'),
  (2, 'The relationship - how you handle this moment will define how she sees you and a short-term project problem is not worth a long-term trust cost.', 'இந்த உறவில், இந்தத் தருணத்தை நீங்கள் கையாளும் விதமே அவள் உங்களை எப்படிப் பார்க்கிறாள் என்பதை நிர்ணயிக்கும். மேலும், ஒரு குறுகிய கால திட்டப் பிரச்சனைக்காக நீண்ட கால நம்பிக்கையை இழப்பது மதிப்புக்குரியது அல்ல.', 'I'),
  (3, 'The honesty - she deserves to know what is not working, regardless of when you deliver it, and holding it longer makes it harder to say.', 'நேர்மை - நீங்கள் எப்போது தெரிவித்தாலும் சரி, எது சரியாகச் செயல்படவில்லை என்பதை அவள் தெரிந்துகொள்ள உரிமை உண்டு; அதை நீண்ட நேரம் சொல்லாமல் இருப்பது, சொல்வதைக் கடினமாக்குகிறது.', 'S'),
  (4, 'The kindness - finding a way to say it that protects her in this moment without losing the substance of what needs to change.', 'கருணை என்பது, மாற்றப்பட வேண்டியதன் சாராம்சத்தை இழக்காமல், இந்தத் தருணத்தில் அவளைப் பாதுகாக்கும் விதத்தில் அதைச் சொல்வதற்கான ஒரு வழியைக் கண்டறிவதாகும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q32',
     'What is actually happening inside you - you are about to walk into a meeting to present work to a group that includes two people you know are critical of your team. You have prepared well. You know the material. But you are standing outside the room and something in your body is not cooperating.', 'What is happening inside you?', 'உங்களுக்குள் உண்மையில் என்ன நடக்கிறது என்றால் - உங்கள் குழுவை விமர்சிப்பவர்கள் என்று உங்களுக்குத் தெரிந்த இருவர் அடங்கிய ஒரு குழுவிடம் உங்கள் பணியை முன்வைப்பதற்காக ஒரு கூட்டத்திற்குள் நீங்கள் நுழையப் போகிறீர்கள். நீங்கள் நன்றாகத் தயாராகியுள்ளீர்கள். உங்களுக்குப் பாடப்பொருள் தெரியும். ஆனால் நீங்கள் அறைக்கு வெளியே நிற்கிறீர்கள், உங்கள் உடலுக்குள் இருக்கும் ஏதோ ஒன்று ஒத்துழைக்க மறுக்கிறது.', 'உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "Communication in the Workplace", "layer": "Layer 3", "dimension": "influence_style", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A fear that is not about the work - it is about whether the people in that room will be able to see past whatever they already think about you.', 'அந்தப் பயம் வேலையைப் பற்றியது அல்ல; மாறாக, அந்த அறையில் உள்ளவர்கள் உங்களைப் பற்றி ஏற்கனவே என்ன நினைக்கிறார்களோ அதைக் கடந்து உங்களைப் பார்க்க முடியுமா என்பதைப் பற்றியது.', 'D'),
  (2, 'A sharpness - the pressure is real and something in you rises to meet it, even if the surface does not look that way.', 'ஒரு கூர்மை - அந்த அழுத்தம் உண்மையானது, வெளித்தோற்றம் அப்படித் தெரியாவிட்டாலும், உங்களுக்குள் இருக்கும் ஏதோ ஒன்று அதை எதிர்கொள்ள மேலெழுகிறது.', 'I'),
  (3, 'An anger underneath the nerves - you should not have to prove yourself this hard to people whose minds might already be made up.', 'பதற்றத்திற்கு அடியில் ஒரு கோபம் - ஒருவேளை ஏற்கனவே ஒரு முடிவுக்கு வந்துவிட்டவர்களிடம், உங்களை இவ்வளவு கடினமாக நிரூபிக்க வேண்டிய அவசியம் இல்லை.', 'S'),
  (4, 'A tiredness - you have done this before, it went fine, and something about having to do it again feels like a tax you did not agree to pay.', 'ஒருவித சோர்வு - இதை நீங்கள் முன்பே செய்திருக்கிறீர்கள், அது நன்றாகவே போனது; ஆனால் இதை மீண்டும் செய்ய வேண்டியிருப்பது, நீங்கள் செலுத்த ஒப்புக்கொள்ளாத ஒரு வரியைப் போல உணர்த்துகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q33',
     'Your team is three days from a deadline. One member has not delivered his section and the group has been covering for him quietly - redistributing his tasks without raising it formally. You are carrying more than your share. The deadline is tomorrow.', 'How do you handle this?', 'உங்கள் குழுவிற்கு ஒரு காலக்கெடு முடிய இன்னும் மூன்று நாட்களே உள்ளன. உறுப்பினர்களில் ஒருவர் தனது பகுதியை இன்னும் முடிக்கவில்லை, மேலும் குழுவினர் அதை முறையாகத் தெரிவிக்காமல், அவருக்குப் பதிலாக அமைதியாகப் பணிகளைப் பகிர்ந்தளித்து வருகின்றனர். நீங்கள் உங்கள் பங்கிற்கு அதிகமான பணிகளைச் செய்கிறீர்கள். காலக்கெடு நாளை.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You go to him directly and tell him clearly that the team is absorbing work that is his and it cannot continue past today.', 'நீங்கள் நேரடியாக அவரிடம் சென்று, அவருடைய வேலையை அணி எடுத்துக்கொண்டிருக்கிறது என்றும், இது இன்றைக்கு மேல் தொடர முடியாது என்றும் தெளிவாகக் கூறுங்கள்.', 'D'),
  (2, 'You raise it with the team - not to call him out but to make the redistribution visible so it becomes a shared decision rather than something a few of you absorb silently.', 'அவரைக் குற்றம் சாட்டுவதற்காக அல்ல, மாறாக அந்த மறுபங்கீட்டை வெளிப்படையாகக் காண்பிப்பதற்காகவே நீங்கள் அதை அணியிடம் தெரிவிக்கிறீர்கள். இதன்மூலம், அது உங்களில் சிலர் மட்டும் மௌனமாக உள்வாங்கிக்கொள்ளும் ஒரு முடிவாக இல்லாமல், ஒரு கூட்டு முடிவாக மாறும்.', 'I'),
  (3, 'You keep covering because the deadline is more important than the conversation right now - you can address it after the work is submitted.', 'தற்போதைய உரையாடலை விட காலக்கெடு முக்கியம் என்பதால் நீங்கள் சமாளித்துக் கொண்டே இருக்கிறீர்கள் - வேலையைச் சமர்ப்பித்த பிறகு அதைப் பற்றிப் பேசலாம்.', 'S'),
  (4, 'You flag it to your manager with the facts and without editorial - you are not willing to carry this quietly into the submission.', 'நீங்கள் இதை உண்மைகளுடன், எந்தவிதத் திருத்தமும் இல்லாமல் உங்கள் மேலாளரிடம் சுட்டிக்காட்டுகிறீர்கள் - இதை அமைதியாகச் சமர்ப்பிப்பில் கொண்டு செல்ல நீங்கள் தயாராக இல்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q34',
     'You are in a group project meeting and a colleague keeps redirecting the conversation away from a problem you believe is central to the work. Others are following her lead. The meeting is running short on time. You are not the most senior person in the room.', 'How do you handle this?', 'நீங்கள் ஒரு குழுத் திட்டக் கூட்டத்தில் இருக்கிறீர்கள். அந்தப் பணிக்கு மையமானது என்று நீங்கள் நம்பும் ஒரு சிக்கலிலிருந்து, உங்கள் சக ஊழியர் ஒருவர் உரையாடலைத் தொடர்ந்து திசை திருப்புகிறார். மற்றவர்களும் அவரைப் பின்பற்றுகிறார்கள். கூட்டத்திற்கு நேரம் குறைவாக உள்ளது. அந்த அறையில் உள்ளவர்களில் நீங்கள் மிகவும் மூத்தவர் அல்ல.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise the problem directly - you name it clearly, say why you think it matters, and ask the group to spend five minutes on it before moving on.', 'நீங்கள் பிரச்சனையை நேரடியாக எழுப்புகிறீர்கள் - அதைத் தெளிவாகக் குறிப்பிட்டு, அது ஏன் முக்கியமானது என்று நீங்கள் கருதுகிறீர்கள் என்பதைக் கூறி, அடுத்த விஷயத்திற்குச் செல்வதற்கு முன், அதைப் பற்றி ஐந்து நிமிடங்கள் சிந்திக்குமாறு குழுவிடம் கேட்டுக்கொள்கிறீர்கள்.', 'D'),
  (2, 'You let the meeting run and find a way to raise the issue in a different setting with the right person.', 'கூட்டம் நடக்கட்டும் என்று விட்டுவிட்டு, சரியான நபரிடம் வேறு ஒரு சூழலில் அந்தப் பிரச்சினையை எழுப்ப ஒரு வழியைக் கண்டறியுங்கள்.', 'I'),
  (3, 'You ask a question rather than making a statement - you frame the problem as something you need help understanding, which surfaces it without positioning you as the one pushing back.', 'நீங்கள் ஒரு கூற்றை முன்வைப்பதற்குப் பதிலாக ஒரு கேள்வியைக் கேட்கிறீர்கள் - அதாவது, அந்தப் பிரச்சனையைப் புரிந்துகொள்ள உங்களுக்கு உதவி தேவைப்படுவது போல முன்வைக்கிறீர்கள்; இது, நீங்கள் எதிர்ப்பவர் என்ற தோற்றத்தை ஏற்படுத்தாமல், அந்தப் பிரச்சனையை வெளிக்கொணர்கிறது.', 'S'),
  (4, 'You say nothing in the meeting and send a written note afterward with your concern clearly laid out.', 'நீங்கள் கூட்டத்தில் எதுவும் கூறாமல், பின்னர் உங்கள் கவலையைத் தெளிவாகக் குறிப்பிட்டு ஒரு எழுத்துப்பூர்வக் குறிப்பை அனுப்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q35',
     'The conflict you feel most is between - you are on a team where the culture is highly collaborative, everyone checks in, decisions are made together, and nothing moves without group alignment. You work faster alone and you are starting to feel slowed down by the process.', 'Does collaboration slow you down?', 'நீங்கள் மிகவும் உணரும் முரண்பாடு என்னவென்றால் - நீங்கள் இருக்கும் குழுவில், அனைவரும் ஒருவருக்கொருவர் கலந்தாலோசித்து, முடிவுகள் ஒன்றாக எடுக்கப்பட்டு, குழுவின் ஒருங்கிணைப்பு இல்லாமல் எதுவும் நகராது. ஆனால், நீங்கள் தனியாக இருக்கும்போது வேகமாகச் செயல்படுவதால், அந்தச் செயல்முறையால் உங்கள் வேகம் குறைவதை உணரத் தொடங்குகிறீர்கள்.', 'கூட்டுப்பணி உங்கள் வேகத்தைக் குறைக்கிறதா?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Your own pace and the team''s rhythm - you can see what you could deliver if you were not waiting for alignment on every step.', 'உங்கள் சொந்த வேகம் மற்றும் அணியின் ஒருங்கிணைப்பு - ஒவ்வொரு அடியிலும் ஒருங்கிணைப்பிற்காகக் காத்திருக்காமல் இருந்தால் உங்களால் என்ன சாதிக்க முடியும் என்பதை நீங்களே பார்க்கலாம்.', 'D'),
  (2, 'Your preference and the group''s need - you value the relationships and you know that the culture exists for a reason even when it frustrates you.', 'உங்கள் விருப்பமும் குழுவின் தேவையும் - நீங்கள் உறவுகளுக்கு மதிப்பளிக்கிறீர்கள், மேலும் அந்தக் கலாச்சாரம் உங்களுக்கு எரிச்சலூட்டினாலும், அது ஒரு காரணத்திற்காகவே இருக்கிறது என்பதையும் நீங்கள் அறிவீர்கள்.', 'I'),
  (3, 'Short-term output and long-term belonging - moving fast alone might produce better work this week but it will cost you something in how you are seen.', 'குறுகிய கால வெளியீடு மற்றும் நீண்ட கால இணைப்பு - வேகமாகச் செயல்படுவது மட்டுமே இந்த வாரம் சிறந்த பணியை அளிக்கக்கூடும், ஆனால் அது உங்களைப் பற்றிய பார்வையின் அடிப்படையில் உங்களுக்கு ஒரு இழப்பை ஏற்படுத்தும்.', 'S'),
  (4, 'Your definition of good work and the team''s definition - you are not sure they are the same thing and that uncertainty is starting to matter.', 'நல்ல பணி குறித்த உங்கள் வரையறையும், குழுவின் வரையறையும் ஒன்றுதானா என்பதில் உங்களுக்கு உறுதியில்லை, மேலும் அந்த நிச்சயமற்ற தன்மை இப்போது ஒரு பொருட்டாகத் தோன்றத் தொடங்கியுள்ளது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q36',
     'Before you say anything - you have just come out of a group session where your idea was quietly absorbed into the group''s direction without your name attached to it. Nobody did it deliberately. It just happened the way ideas do in rooms - they float free of whoever said them. You are walking back to your desk.', 'How do you feel now?', 'நீங்கள் எதையும் சொல்வதற்கு முன் - நீங்கள் இப்போதுதான் ஒரு குழு அமர்விலிருந்து வெளியே வந்திருக்கிறீர்கள். அங்கே, உங்கள் பெயர் குறிப்பிடப்படாமலேயே, உங்கள் யோசனை அமைதியாக அந்தக் குழுவின் போக்கிற்குள் உள்வாங்கப்பட்டது. இதை யாரும் வேண்டுமென்றே செய்யவில்லை. அறைகளில் யோசனைகள் இயல்பாக நிகழ்வது போல, அவை யார் சொன்னாலும் கட்டுப்படாமல் தானாகவே மிதந்து வந்துவிட்டன. நீங்கள் உங்கள் மேசைக்குத் திரும்பிச் சென்று கொண்டிருக்கிறீர்கள்.', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Collaboration and Team Dynamics", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A resignation that you are trying not to let become cynicism - this is how it works and you knew that and you have to decide whether you are okay with it.', 'நீங்கள் அவநம்பிக்கையாக மாறிவிடாமல் தடுக்க முயற்சிக்கும் ஒரு மனமுறிவு - இது இப்படித்தான் செயல்படும், அது உங்களுக்கு முன்பே தெரியும், மேலும் நீங்கள் அதை ஏற்றுக்கொள்கிறீர்களா இல்லையா என்பதை நீங்கள்தான் முடிவு செய்ய வேண்டும்.', 'D'),
  (2, 'A question about your own visibility - not about this idea specifically but about whether you are the kind of person who shows up in rooms the way others do.', 'உங்கள் வெளிப்படைத்தன்மை பற்றிய ஒரு கேள்வி - இது குறிப்பாக இந்தக் கருத்தைப் பற்றியது அல்ல, மாறாக மற்றவர்கள் கூடும் இடங்களில் தங்களைக் காட்டிக்கொள்வது போல நீங்களும் கூடும் இடத்திலா இருக்கிறீர்கள் என்பதைப் பற்றியது.', 'I'),
  (3, 'A clean irritation - it was your idea, people are excited about it, and the person getting credit for moving it forward is not you.', 'இது ஒரு நியாயமான எரிச்சல்தான் - அது உங்கள் யோசனை, மக்கள் அதைப் பற்றி உற்சாகமாக இருக்கிறார்கள், ஆனால் அதை முன்னெடுத்துச் சென்றதற்கான பெருமை உங்களுக்குக் கிடைக்கவில்லை.', 'S'),
  (4, 'An impulse to say something and a knowledge that saying it will make you look smaller than staying quiet will - and you are not sure which one is worse.', 'ஏதாவது சொல்ல வேண்டும் என்ற உந்துதல்; அதைச் சொல்வது, அமைதியாக இருப்பதை விட உங்களைச் சிறுமைப்படுத்தும் என்ற அறிவு; இந்த இரண்டில் எது மோசமானது என்று உங்களுக்குத் தெரியவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q37',
     'You have been the person who says yes. Every request, every extra task, every favour someone needed. You are now at a point where your own work is suffering because of it. A colleague just messaged you asking for help on something that is going to take two hours you do not have.', 'How do you respond now?', 'இதுவரை நீங்கள் ''ஆம்'' என்று சொல்பவராகவே இருந்திருக்கிறீர்கள். ஒவ்வொரு கோரிக்கைக்கும், ஒவ்வொரு கூடுதல் பணிக்கும், ஒருவர் கேட்ட ஒவ்வொரு உதவிக்கும் கூட நீங்கள் ''ஆம்'' என்று சொல்லியிருக்கிறீர்கள். அதன் காரணமாக, இப்போது உங்கள் சொந்த வேலையே பாதிக்கப்படும் ஒரு நிலையில் நீங்கள் இருக்கிறீர்கள். உங்களிடம் இல்லாத, இரண்டு மணி நேரம் ஆகக்கூடிய ஒரு விஷயத்திற்கு உதவி கேட்டு, உங்கள் சக ஊழியர் ஒருவர் இப்போதுதான் உங்களுக்குச் செய்தி அனுப்பியுள்ளார்.', 'நீங்கள் இப்போது எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell him you cannot help right now and explain briefly why - you have a deadline and you need to protect it.', 'உங்களால் இப்போது உதவ முடியாது என்று அவரிடம் கூறி, அதற்கான காரணத்தையும் சுருக்கமாக விளக்குங்கள் - உங்களுக்கு ஒரு காலக்கெடு இருக்கிறது, அதை நீங்கள் பூர்த்தி செய்ய வேண்டும்.', 'D'),
  (2, 'You help him anyway - you will find the two hours somewhere and the relationship matters.', 'நீ எப்படியும் அவனுக்கு உதவு - அந்த இரண்டு மணி நேரத்தை நீ எங்காவது கண்டுபிடித்துவிடுவாய், மேலும் உறவும் முக்கியமானது.', 'I'),
  (3, 'You offer a smaller version - you cannot do the full task but you can point him in the right direction and give thirty minutes.', 'நீங்கள் ஒரு சிறிய வடிவத்தை வழங்குகிறீர்கள் - உங்களால் முழுப் பணியையும் செய்ய முடியாது, ஆனால் அவருக்குச் சரியான வழியைக் காட்டி முப்பது நிமிடங்கள் கொடுக்கலாம்.', 'S'),
  (4, 'You say yes but you feel the cost of it and you know something has to change after this one.', 'நீங்கள் சம்மதம் சொல்கிறீர்கள், ஆனால் அதற்கான விலையை உணர்கிறீர்கள், மேலும் இதற்குப் பிறகு ஏதோவொன்று மாற வேண்டும் என்பதும் உங்களுக்குத் தெரியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q38',
     'It is 8pm on a Thursday. You have been in the office since 8am. The work is done. There is no specific reason to stay. But everyone else on the team is still at their desks and leaving feels like a statement you are not sure you want to make.', 'Should you leave work now?', 'வியாழக்கிழமை இரவு 8 மணி. நீங்கள் காலை 8 மணியிலிருந்து அலுவலகத்தில் இருக்கிறீர்கள். வேலை முடிந்துவிட்டது. இங்கேயே தங்குவதற்கு குறிப்பிட்ட காரணம் எதுவும் இல்லை. ஆனால், குழுவில் உள்ள மற்ற அனைவரும் இன்னும் தங்கள் மேசைகளில்தான் இருக்கிறார்கள். இங்கிருந்து கிளம்புவது என்பது, நீங்கள் வெளிப்படுத்த விரும்புகிறீர்களா இல்லையா என்று உறுதியாகத் தெரியாத ஒரு கருத்தைக் கூறுவது போல உங்களுக்குத் தோன்றுகிறது.', 'நீங்கள் இப்போது வேலையை விட்டுச் செல்ல வேண்டுமா?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You pack up and leave - you have done your work and your physical presence after hours is not something you are willing to perform.', 'நீங்கள் உங்கள் பொருட்களை எடுத்துக்கொண்டு கிளம்புகிறீர்கள் - உங்கள் வேலையை முடித்துவிட்டீர்கள், மேலும் வேலை நேரம் முடிந்த பிறகும் அங்கு இருப்பதற்கு நீங்கள் விரும்பவில்லை.', 'D'),
  (2, 'You stay another hour and use the time for something genuinely useful - getting ahead of tomorrow rather than just filling the room.', 'நீங்கள் மேலும் ஒரு மணி நேரம் தங்கி, அந்த நேரத்தை வெறுமனே அறையை நிரப்புவதற்குப் பதிலாக, நாளைக்கான வேலைகளை முன்கூட்டியே திட்டமிடுவது போன்ற உண்மையிலேயே பயனுள்ள ஒரு காரியத்திற்குப் பயன்படுத்துங்கள்.', 'I'),
  (3, 'You find a natural exit - you wrap something up visibly, say goodnight to the right people, and leave in a way that does not feel abrupt.', 'நீங்கள் இயல்பான ஒரு வழியைக் கண்டறிகிறீர்கள் - அதாவது, உங்கள் வேலையை வெளிப்படையாக முடித்து, உரிய நபர்களுக்கு இரவு வணக்கம் கூறி, திடீரென முடிவெடுக்காதது போல் தோன்றும் வகையில் அங்கிருந்து கிளம்புகிறீர்கள்.', 'S'),
  (4, 'You stay and you are not entirely sure why - it is not about the work anymore but leaving first still does not feel like an option.', 'நீங்கள் அங்கேயே இருக்கிறீர்கள், ஆனால் ஏன் என்று உங்களுக்கு முழுமையாகத் தெரியவில்லை - இனி அது வேலையைப் பற்றியதல்ல, ஆனாலும் முதலில் வெளியேறுவது ஒரு தேர்வாகவே தோன்றவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q39',
     'What matters more to you in this moment? You have not had a full weekend off in six weeks. You are performing well. Nothing has collapsed. But you are aware that something in you is running on fumes rather than genuine energy. A colleague just said you look tired and asked if you are okay.', 'What matters most to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? கடந்த ஆறு வாரங்களாக உங்களுக்கு ஒரு முழு வார இறுதி விடுமுறை கூட கிடைக்கவில்லை. நீங்கள் நன்றாகப் பணிபுரிகிறீர்கள். எதுவும் செயலிழக்கவில்லை. ஆனால், உங்களுக்குள் இருக்கும் ஏதோ ஒன்று உண்மையான ஆற்றலுக்குப் பதிலாகத் தளர்ந்து போயிருப்பதை நீங்கள் உணர்கிறீர்கள். ஒரு சக ஊழியர் நீங்கள் சோர்வாகத் தெரிவதாகவும், நலமாக இருக்கிறீர்களா என்றும் கேட்டார்.', 'உங்களுக்கு மிகவும் முக்கியமானது எது?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 2", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Keeping up appearances - you are fine, the work is good, and drawing attention to the cost of that is not something you want to do right now.', 'வெளித்தோற்றத்தைப் பேணுவது - நீங்கள் நலமாக இருக்கிறீர்கள், வேலையும் நன்றாக இருக்கிறது, அதற்கான செலவை வெளிச்சம் போட்டுக் காட்டுவதை நீங்கள் இப்போது விரும்ப மாட்டீர்கள்.', 'D'),
  (2, 'Being honest with yourself - you know what is happening and pretending otherwise does not make it easier to manage.', 'உங்களுக்கு நீங்களே உண்மையாக இருங்கள் - என்ன நடக்கிறது என்பது உங்களுக்குத் தெரியும், அதை மறுப்பது சமாளிப்பதை எளிதாக்காது.', 'I'),
  (3, 'The work - the output is what matters and how you feel while producing it is a secondary concern right now.', 'வேலை - அதன் விளைவுதான் முக்கியம்; அதை உருவாக்கும்போது நீங்கள் எப்படி உணர்கிறீர்கள் என்பது இப்போதைக்கு இரண்டாம் பட்சமான விஷயம்.', 'S'),
  (4, 'The relationship - this person asked because they noticed and the fact that someone noticed matters more to you in this moment than the answer you give them.', 'அந்த உறவுமுறை - அந்த நபர் கவனித்ததால்தான் கேட்டார், மேலும் நீங்கள் அவருக்கு அளிக்கும் பதிலை விட, ஒருவர் கவனித்திருக்கிறார் என்பதே அந்தத் தருணத்தில் உங்களுக்கு மிகவும் முக்கியமானது.', 'C')
) AS v(ord, en, ta, fac);

-- Entry Set 2 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Entry', 'EMP-ENT-S2-Q40',
     'The honest feeling underneath this - you are a year into this job. You are good at it. People tell you so. But late on a Friday afternoon, when the week finally stops moving, something underneath the competence surfaces that you do not usually let yourself look at directly.', 'What surfaces underneath your competence?', 'இதன் அடிப்படையிலான உண்மையான உணர்வு இதுதான் - நீங்கள் இந்த வேலையில் சேர்ந்து ஒரு வருடம் ஆகிறது. நீங்கள் இதில் திறமையானவர். மற்றவர்களும் உங்களிடம் அப்படித்தான் சொல்வார்கள். ஆனால், ஒரு வெள்ளிக்கிழமை பிற்பகலில், வாரம் மெல்ல மெல்ல நகர்வதை நிறுத்தும் போது, ​​உங்கள் திறமைக்கு அடியில் இருக்கும் ஏதோ ஒன்று வெளிப்படுகிறது; அதை நீங்கள் வழக்கமாக நேரடியாகப் பார்க்க உங்களை அனுமதிக்க மாட்டீர்கள்.', 'உங்கள் திறமைக்கு அடியில் என்ன வெளிப்படுகிறது?',
     '{"theme": "Personal Boundaries and Sustainability", "layer": "Layer 3", "dimension": "stability_need", "board": "Entry", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A loneliness that has nothing to do with the people around you - you are surrounded by colleagues and you are still somehow doing this alone.', 'உங்களைச் சுற்றியுள்ளவர்களுடன் எந்த சம்பந்தமும் இல்லாத ஒரு தனிமை - நீங்கள் சக ஊழியர்களால் சூழப்பட்டிருக்கிறீர்கள், ஆனாலும் ஏனோ இதைத் தனியாகவே செய்கிறீர்கள்.', 'D'),
  (2, 'A question about whether this is actually what you want or whether you got good at something and confused that for meaning.', 'இதுதான் உங்களுக்கு உண்மையிலேயே வேண்டுமா அல்லது ஏதேனும் ஒன்றில் திறமை பெற்று, அதையே அர்த்தம் என்று தவறாகப் புரிந்துகொண்டீர்களா என்பது பற்றிய ஒரு கேள்வி.', 'I'),
  (3, 'A grief for the version of yourself that existed before you learned to perform this well - and a realisation that you cannot fully remember what that felt like.', 'இவ்வளவு சிறப்பாகச் செயல்படக் கற்றுக்கொள்வதற்கு முன்பு இருந்த உங்கள் நிலையை நினைத்து ஏற்படும் ஒரு துக்கம் - மற்றும் அந்த உணர்வு எப்படி இருந்தது என்பதை உங்களால் முழுமையாக நினைவுகூர முடியாது என்ற ஒரு புரிதல்.', 'S'),
  (4, 'A quiet pride that you are trying not to trust too much - because you have learned that the moment you relax is usually the moment something shifts.', 'அதிகமாக நம்பாமல் இருக்க முயற்சிக்கும் ஒரு மெல்லிய பெருமிதம் - ஏனென்றால், நீங்கள் ஓய்வெடுக்கும் தருணத்தில்தான் பொதுவாக ஏதோ ஒன்று மாறுகிறது என்பதை நீங்கள் கற்றுக்கொண்டிருக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- ============================================================
-- Sheet 'Level 2' -> board 'Medium'
-- ============================================================
-- Medium Set 1 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q1',
     'Your senior leader presents your team''s project outcomes in a leadership meeting as though the ideas originated from his own initiative. You were not in the room. Three of your team members who attended message you immediately afterward, frustrated and expecting you to do something. Your manager is aware it happened and has said nothing.', 'How will you handle conflict?', 'உங்கள் மூத்த தலைவர், ஒரு தலைமைத்துவக் கூட்டத்தில் உங்கள் குழுவின் திட்ட முடிவுகளை, அந்த யோசனைகள் தனது சொந்த முயற்சியால் உருவானவை போல முன்வைக்கிறார். நீங்கள் அந்தக் கூட்டத்தில் இல்லை. அதில் கலந்துகொண்ட உங்கள் குழு உறுப்பினர்களில் மூவர், உடனடியாகப் பிறகு, விரக்தியுடனும் நீங்கள் ஏதாவது செய்வீர்கள் என்ற எதிர்பார்ப்புடனும் உங்களுக்குச் செய்தி அனுப்புகிறார்கள். இது நடந்ததை உங்கள் மேலாளர் அறிந்திருக்கிறார், ஆனால் அவர் எதுவும் கூறவில்லை.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a one-on-one with the senior leader and calmly name what happened, asking how you can ensure your team gets visibility going forward.', 'மூத்த தலைவருடன் தனிப்பட்ட சந்திப்பிற்கு நீங்கள் கோரிக்கை விடுத்து, என்ன நடந்தது என்பதை அமைதியாகக் கூறி, இனிவரும் காலங்களில் உங்கள் குழுவுக்கு இதுபற்றித் தெளிவாகத் தெரியவருவதை எப்படி உறுதிசெய்யலாம் என்று கேட்கிறீர்கள்.', 'D'),
  (2, 'You send a follow-up email to the broader group summarising your team''s contributions with specific names attached, framing it as a project update.', 'உங்கள் குழுவின் பங்களிப்புகளைச் சுருக்கமாகக் கூறி, குறிப்பிட்ட பெயர்களை இணைத்து, அதனை ஒரு திட்டப் புதுப்பிப்பு போல வடிவமைத்து, பரந்த குழுவிற்கு ஒரு பின்தொடர் மின்னஞ்சலை அனுப்புகிறீர்கள்.', 'I'),
  (3, 'You absorb it for now, focus on protecting your team''s morale privately, and wait to see if your manager addresses it.', 'தற்போதைக்கு இதை நீங்கள் பொறுத்துக்கொள்ளுங்கள், தனிப்பட்ட முறையில் உங்கள் அணியின் மன உறுதியைப் பாதுகாப்பதில் கவனம் செலுத்துங்கள், மேலும் உங்கள் மேலாளர் இதுகுறித்து நடவடிக்கை எடுக்கிறாரா என்று காத்திருங்கள்.', 'S'),
  (4, 'You document the full timeline of contributions before doing anything, then decide on next steps once you have a clear record.', 'எதையும் செய்வதற்கு முன், பங்களிப்புகளின் முழுமையான காலவரிசையை நீங்கள் ஆவணப்படுத்த வேண்டும்; பின்னர், உங்களிடம் தெளிவான பதிவு கிடைத்தவுடன் அடுத்தகட்ட நடவடிக்கைகள் குறித்து முடிவெடுக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q2',
     'Your manager gives you a target for the quarter that requires your team to deliver forty percent more output with no additional headcount. She frames it as non-negotiable and tells you to figure out the how. You believe the target will break your team''s rhythm and trigger resignations. Two of your strongest people have already flagged burnout privately.', 'How will you handle this?', 'உங்கள் மேலாளர், கூடுதல் பணியாளர்கள் இல்லாமல், உங்கள் குழு நாற்பது சதவிகிதம் அதிக உற்பத்தியை வழங்க வேண்டும் என்ற காலாண்டிற்கான இலக்கை உங்களுக்கு அளிக்கிறார். அவர் அதை மாற்ற முடியாத ஒன்று எனக் கூறி, அதை எப்படிச் செய்வது என்பதை நீங்களே கண்டறியுங்கள் என்கிறார். அந்த இலக்கு உங்கள் குழுவின் சீரான செயல்பாட்டைக் குலைத்து, ராஜினாமாக்களைத் தூண்டும் என்று நீங்கள் நம்புகிறீர்கள். உங்கள் குழுவில் மிகவும் திறமையான இருவர் ஏற்கெனவே தனிப்பட்ட முறையில் மன அழுத்தத்தால் பாதிக்கப்பட்டிருப்பதாகக் குறிப்பிட்டுள்ளனர்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You push back directly in your next one-on-one, presenting data on current capacity and the likely attrition risk if the target holds.', 'உங்கள் அடுத்த நேருக்கு நேர் சந்திப்பில், தற்போதைய திறன் மற்றும் இலக்கு தக்கவைக்கப்பட்டால் ஏற்படக்கூடிய பணியாளர் இழப்பு அபாயம் குறித்த தரவுகளை முன்வைத்து, நீங்கள் நேரடியாகப் பதிலடி கொடுக்கிறீர்கள்.', 'D'),
  (2, 'You accept the target, then immediately begin working the room - speaking to peers, finding shared resources, and building a case for support through relationships.', 'நீங்கள் இலக்கை ஏற்றுக்கொண்டவுடன், உடனடியாக சக ஊழியர்களுடன் பேசுவது, பொதுவான வளங்களைக் கண்டறிவது, மற்றும் உறவுகள் மூலம் ஆதரவுக்கான தேவையை உருவாக்குவது போன்ற செயல்பாடுகளைத் தொடங்கவும்.', 'I'),
  (3, 'You take the target on without escalating, redistribute workload carefully, and check in more frequently with the team to keep morale steady.', 'நீங்கள் நிலைமையை மோசமாக்காமல் இலக்கை ஏற்றுக்கொண்டு, பணிச்சுமையை கவனமாகப் பகிர்ந்தளித்து, மன உறுதியை நிலையாக வைத்திருக்கக் குழுவினருடன் அடிக்கடி கலந்துரையாடுகிறீர்கள்.', 'S'),
  (4, 'You build a detailed capacity model showing exactly where the gaps are and present it formally before committing to any number.', 'குறைபாடுகள் எங்கு உள்ளன என்பதைத் துல்லியமாகக் காட்டும் ஒரு விரிவான திறன் மாதிரியை உருவாக்கி, எந்தவொரு எண்ணிக்கையையும் உறுதியளிப்பதற்கு முன்பு அதை முறையாகச் சமர்ப்பிக்கவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q3',
     'What matters more to you in this moment? Your manager has misrepresented your team''s delivery timeline in a skip-level review. The senior leader now has an inaccurate picture of where things stand. If you correct the record, you risk creating tension with your manager. If you stay silent, you are complicit in something you know is false.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? உங்கள் மேலாளர், ஒரு உயர்நிலை மதிப்பாய்வில் உங்கள் குழுவின் பணி நிறைவு காலக்கெடுவைத் தவறாகக் குறிப்பிட்டுள்ளார். அதனால், தற்போதைய நிலை குறித்து அந்த மூத்த தலைவருக்கு ஒரு தவறான சித்திரம் கிடைத்துள்ளது. நீங்கள் அந்தத் தவறைத் திருத்தினால், உங்கள் மேலாளருடன் பதற்றத்தை உருவாக்கும் அபாயம் உள்ளது. நீங்கள் மௌனமாக இருந்தால், பொய் என்று தெரிந்தும் நீங்கள் செய்யும் ஒரு செயலுக்கு உடந்தையாகிறீர்கள்.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Correcting the record matters more. You find a professional way to surface the accurate picture, even if it creates friction with your manager.', 'பதிவைச் சரிசெய்வதுதான் மிகவும் முக்கியம். உங்கள் மேலாளருடன் கருத்து வேறுபாடுகளை ஏற்படுத்தினாலும், உண்மையான நிலையை வெளிக்கொணர நீங்கள் ஒரு தொழில்முறை வழியைக் கண்டறிய வேண்டும்.', 'D'),
  (2, 'The relationship with your manager matters more right now. You find a quieter way to nudge the timeline conversation without making it a confrontation.', 'தற்போது உங்கள் மேலாளருடனான உறவுதான் மிகவும் முக்கியமானது. காலக்கெடு குறித்த உரையாடலை ஒரு மோதலாக மாற்றாமல், அமைதியான முறையில் அதைத் தூண்டிவிட ஒரு வழியைக் கண்டறியுங்கள்.', 'I'),
  (3, 'Keeping the team protected matters most. You focus on making the timeline real rather than managing how it is perceived above.', 'அணியைப் பாதுகாப்பதே மிக முக்கியம். மேலிடத்தில் அது எவ்வாறு பார்க்கப்படுகிறது என்பதை நிர்வகிப்பதை விட, காலக்கெடுவை நிஜமாக்குவதில் நீங்கள் கவனம் செலுத்த வேண்டும்.', 'S'),
  (4, 'Getting the facts straight matters most. You document the accurate version and decide based on evidence what the right channel is to surface it.', 'உண்மைகளைத் தெளிவாக அறிந்துகொள்வதுதான் மிக முக்கியம். நீங்கள் துல்லியமான விவரங்களை ஆவணப்படுத்தி, ஆதாரங்களின் அடிப்படையில் அதை வெளிக்கொணர்வதற்கான சரியான வழி எது என்பதைத் தீர்மானிக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q4',
     'Before you say anything in the skip-level meeting, your senior leader turns to you and asks directly how confident you are in your manager''s assessment of the team''s readiness. Your manager is in the room. The honest answer is that you are not confident. But saying that out loud, in this setting, in front of her, is a different kind of moment entirely.', 'How do you respond now?', 'உயர்நிலை அதிகாரிகளுடனான கூட்டத்தில் நீங்கள் எதையும் சொல்வதற்கு முன்பு, உங்கள் மூத்த தலைவர் உங்கள் பக்கம் திரும்பி, அணியின் தயார்நிலை குறித்த உங்கள் மேலாளரின் மதிப்பீட்டில் உங்களுக்கு எவ்வளவு நம்பிக்கை இருக்கிறது என்று நேரடியாகக் கேட்கிறார். உங்கள் மேலாளர் அந்த அறையில்தான் இருக்கிறார். நேர்மையான பதில் என்னவென்றால், உங்களுக்கு நம்பிக்கை இல்லை என்பதுதான். ஆனால், அதை இந்தச் சூழலில், அவர் முன்னிலையில் சத்தமாகச் சொல்வது என்பது முற்றிலும் வேறுபட்ட ஒரு தருணம்.', 'நீங்கள் இப்போது எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You answer honestly, calmly, and specifically - naming what you are confident about and where you think more work is needed.', 'நீங்கள் நேர்மையாகவும், அமைதியாகவும், குறிப்பாகவும் பதிலளிக்கிறீர்கள் - உங்களுக்கு நம்பிக்கையுள்ள விஷயங்களையும், மேலும் முன்னேற்றம் தேவை என்று நீங்கள் கருதும் விஷயங்களையும் குறிப்பிடுகிறீர்கள்.', 'D'),
  (2, 'You give a measured answer that keeps the relationship intact, framing concerns as areas the team is actively working through.', 'உறவைப் பேணிக்கொண்டு, கவலைகளைக் குழு தீவிரமாகச் செயல்பட்டு வரும் பகுதிகளாகக் குறிப்பிடும் வகையில் நீங்கள் நிதானமான பதிலை அளிக்கிறீர்கள்.', 'I'),
  (3, 'You defer to your manager with a supportive comment and resolve to have the real conversation privately afterward.', 'உங்கள் மேலாளருக்கு ஆதரவான கருத்தைத் தெரிவித்துவிட்டு, உண்மையான உரையாடலை பின்னர் தனிப்பட்ட முறையில் நடத்திக்கொள்ளத் தீர்மானிக்கிறீர்கள்.', 'S'),
  (4, 'You ask for a moment to be precise, then give a qualified answer that is technically accurate without creating an open rupture.', 'துல்லியமாகச் சொல்வதற்கு ஒரு கணம் அவகாசம் கேட்டுவிட்டு, பின்னர் எந்தவொரு வெளிப்படையான பிளவையும் ஏற்படுத்தாமல், தொழில்நுட்ப ரீதியாகத் துல்லியமான ஒரு தகுதியான பதிலை அளிக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q5',
     'One of your team members has missed three consecutive deadlines. He is well-liked, has been with the company longer than you, and the team tends to cover for him quietly. You have had one informal conversation that changed nothing. Your manager has started asking questions about the project''s overall health.', 'What action should you take?', 'உங்கள் குழு உறுப்பினர்களில் ஒருவர் தொடர்ச்சியாக மூன்று காலக்கெடுவைத் தவறவிட்டுள்ளார். அவர் அனைவராலும் விரும்பப்படுபவர், உங்களை விட அதிக காலம் நிறுவனத்தில் பணியாற்றி வருகிறார், மேலும் குழுவினர் அமைதியாக அவருக்கு ஆதரவாகச் செயல்படுகின்றனர். நீங்கள் ஒருமுறை முறைசாரா உரையாடல் நடத்தியும் எந்த மாற்றமும் ஏற்படவில்லை. உங்கள் மேலாளர், திட்டத்தின் ஒட்டுமொத்த நிலை குறித்துக் கேள்விகள் கேட்கத் தொடங்கியுள்ளார்.', 'நீங்கள் என்ன நடவடிக்கை எடுக்க வேண்டும்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You schedule a formal one-on-one, name the pattern directly, set clear expectations with timelines, and make it clear that this is now a performance conversation.', 'நீங்கள் ஒரு முறையான தனிப்பட்ட சந்திப்பைத் திட்டமிட்டு, அந்தப் போக்கை நேரடியாகக் குறிப்பிட்டு, காலக்கெடுவுடன் தெளிவான எதிர்பார்ப்புகளை நிர்ணயித்து, இது இப்போது ஒரு செயல்திறன் சார்ந்த உரையாடல் என்பதைத் தெளிவுபடுத்துகிறீர்கள்.', 'D'),
  (2, 'You approach the conversation relationally first - trying to understand what is driving the misses before putting any formal structure around it.', 'அதற்கு முறையான கட்டமைப்பை உருவாக்குவதற்கு முன்பு, தவறுகளுக்குப் பின்னால் உள்ள காரணத்தைப் புரிந்துகொள்ள முயற்சிப்பதன் மூலம், நீங்கள் முதலில் அந்த உரையாடலை உறவுமுறையின் அடிப்படையில் அணுகுகிறீர்கள்.', 'I'),
  (3, 'You give it one more week, redistribute one of the critical tasks to reduce the immediate risk, and create space for him to recover.', 'இன்னும் ஒரு வாரம் அவகாசம் கொடுங்கள், உடனடி அபாயத்தைக் குறைப்பதற்காக முக்கியப் பணிகளில் ஒன்றை மறுபங்கீடு செய்யுங்கள், மேலும் அவர் குணமடைவதற்கு அவகாசம் அளியுங்கள்.', 'S'),
  (4, 'You document the three missed deadlines with dates and impact, then enter the conversation with a written summary and a structured improvement plan ready.', 'தவறவிடப்பட்ட மூன்று காலக்கெடுக்களையும் தேதிகள் மற்றும் அவற்றின் தாக்கத்துடன் ஆவணப்படுத்திய பிறகு, ஒரு எழுதப்பட்ட சுருக்கம் மற்றும் கட்டமைக்கப்பட்ட மேம்பாட்டுத் திட்டத்துடன் உரையாடலைத் தொடங்குங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q6',
     'Your manager tells you privately that the VP wants a high rating for a team member you believe genuinely does not deserve it. The team member is well connected and has a sponsor two levels above you. The rest of your team knows this person''s output has been inconsistent. You are about to submit performance ratings.', 'How to handle unfair ratings?', 'உண்மையாகவே அதற்குத் தகுதியற்றவர் என்று நீங்கள் நம்பும் ஒரு குழு உறுப்பினருக்கு, துணைத் தலைவர் உயர் மதிப்பீடு கோருவதாக உங்கள் மேலாளர் உங்களிடம் தனிப்பட்ட முறையில் கூறுகிறார். அந்தக் குழு உறுப்பினர் நல்ல செல்வாக்கு மிக்கவர், மேலும் உங்களுக்கு இரண்டு படிநிலைகள் மேலே அவருக்கு ஒரு ஆதரவாளர் இருக்கிறார். அந்த நபரின் செயல்திறன் சீரற்றதாக இருந்து வருகிறது என்பது உங்கள் குழுவின் மற்ற உறுப்பினர்களுக்கும் தெரியும். நீங்கள் செயல்திறன் மதிப்பீடுகளைச் சமர்ப்பிக்க உள்ளீர்கள்.', 'நியாயமற்ற மதிப்பீடுகளை எவ்வாறு கையாள்வது?',
     '{"theme": "", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You submit the rating you believe is accurate and prepare to defend it with evidence if challenged.', 'நீங்கள் துல்லியமானது என்று நம்பும் மதிப்பீட்டைச் சமர்ப்பிக்கவும், மேலும் அது கேள்விக்குட்படுத்தப்பட்டால் ஆதாரங்களுடன் அதை நிரூபிக்கத் தயாராக இருக்கவும்.', 'D'),
  (2, 'You have a quiet conversation with your manager first, understanding the full political picture before you commit to a number.', 'ஒரு தொகையை ஒப்புக்கொள்வதற்கு முன், முழுமையான அரசியல் சூழலைப் புரிந்துகொள்ளும் பொருட்டு, முதலில் உங்கள் மேலாளருடன் நிதானமாகப் பேசுங்கள்.', 'I'),
  (3, 'You submit a moderate rating that gives the person credit for relationships and collaboration even if the output was below par.', 'வெளியீடு சராசரிக்கும் குறைவாக இருந்தபோதிலும், அந்த நபருடனான உறவுகளையும் ஒத்துழைப்பையும் பாராட்டும் வகையில் நீங்கள் ஒரு மிதமான மதிப்பீட்டைச் சமர்ப்பிக்கிறீர்கள்.', 'S'),
  (4, 'You document your assessment in full, submit what the evidence supports, and keep a written record of the conversation with your manager.', 'உங்கள் மதிப்பீட்டை முழுமையாக ஆவணப்படுத்தி, அதற்கான ஆதாரங்களைச் சமர்ப்பித்து, உங்கள் மேலாளருடனான உரையாடலை எழுத்துப்பூர்வமாகப் பதிவு செய்யுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q7',
     'Two things are pulling at you. Which is stronger? A previously strong performer on your team has gone quiet over the past six weeks. Deadlines are slipping. She has not explained why. You suspect something personal is happening. One pull is to give her space and trust - she has earned it over two years. The other pull is to name what you are observing and create a structured conversation before the work suffers further.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? உங்கள் குழுவில் முன்பு சிறப்பாகச் செயல்பட்ட ஒருவர், கடந்த ஆறு வாரங்களாக அமைதியாகிவிட்டார். காலக்கெடு தள்ளிப் போகிறது. அதற்கான காரணத்தை அவர் விளக்கவில்லை. தனிப்பட்ட முறையில் ஏதோ நடக்கிறது என்று நீங்கள் சந்தேகிக்கிறீர்கள். ஒரு உந்துதல், அவருக்கு இடத்தையும் நம்பிக்கையையும் கொடுக்க வேண்டும் என்பது - கடந்த இரண்டு ஆண்டுகளில் அவர் அதற்குத் தகுதியானவர். மற்றொரு உந்துதல், நீங்கள் கவனிப்பதை வெளிப்படையாகக் கூறி, பணி மேலும் பாதிக்கப்படுவதற்கு முன்பு ஒரு முறையான உரையாடலைத் தொடங்குவது.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to name it is stronger. You initiate the conversation, make it safe, and address both the work and whatever might be underneath it.', 'அதற்குப் பெயரிட வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்களே உரையாடலைத் தொடங்கி, அதை ஒரு பாதுகாப்பான சூழலாக மாற்றி, அந்தப் பணியையும் அதன் அடியில் இருக்கக்கூடியவற்றையும் ஒரே நேரத்தில் கையாளுகிறீர்கள்.', 'D'),
  (2, 'The relational pull is stronger. You find a low-pressure way to check in without making it feel like a performance conversation.', 'உறவின் ஈர்ப்பு வலுவாக இருக்கிறது. அது ஒரு நடிப்பு உரையாடல் போலத் தோன்றாமல், குறைந்த அழுத்தத்துடன் நலம் விசாரிக்க ஒரு வழியை நீங்கள் கண்டறிகிறீர்கள்.', 'I'),
  (3, 'The pull to protect her is stronger. You quietly absorb some of the pressure yourself and wait for her to come to you.', 'அவளைப் பாதுகாக்க வேண்டும் என்ற உந்துதல் வலுவாக இருக்கிறது. நீயோ, அந்த அழுத்தத்தில் சிறிதளவை அமைதியாக உனக்குள் உள்வாங்கிக்கொண்டு, அவள் உன்னிடம் வருவதற்காகக் காத்திருக்கிறாய்.', 'S'),
  (4, 'The pull to document and structure is stronger. You track the pattern, then initiate a conversation with clear data to ground it.', 'ஆவணப்படுத்தவும் கட்டமைக்கவும் உள்ள நாட்டம் வலுவாக உள்ளது. நீங்கள் அந்தப் போக்கைக் கண்காணித்து, பின்னர் அதை உறுதிப்படுத்தத் தெளிவான தரவுகளுடன் ஒரு உரையாடலைத் தொடங்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q8',
     'What is actually happening inside you when two of your team members are in open conflict and your previous attempts to mediate have not worked? The tension is now visible to people outside your team. Your manager has noticed. You have tried twice and the situation has worsened. You are not sure whether the problem is them, your approach, or something structural that no one wants to name.', 'How do you manage conflict?', 'உங்கள் குழு உறுப்பினர்கள் இருவர் வெளிப்படையாக மோதலில் ஈடுபடும்போதும், சமாதானம் செய்ய நீங்கள் முன்பு மேற்கொண்ட முயற்சிகள் பலனளிக்காதபோதும், உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது? அந்தப் பதற்றம் இப்போது உங்கள் குழுவிற்கு வெளியே உள்ளவர்களுக்கும் தெரிகிறது. உங்கள் மேலாளர் அதைக் கவனித்துவிட்டார். நீங்கள் இரண்டு முறை முயன்றும் நிலைமை இன்னும் மோசமாகிவிட்டது. பிரச்சனை அவர்களிடமிருந்தா, உங்கள் அணுகுமுறையிலிருந்தா, அல்லது யாரும் குறிப்பிட விரும்பாத ஏதேனும் ஒரு கட்டமைப்புப் பிரச்சனையிலிருந்தா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'முரண்பாடுகளை நீங்கள் எவ்வாறு கையாளுகிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the urgency clearly and move into problem-solving mode - this needs a different approach and you are ready to find it.', 'நீங்கள் அவசரத்தைத் தெளிவாக உணர்ந்து, சிக்கலைத் தீர்க்கும் மனநிலைக்கு மாறுகிறீர்கள் - இதற்கு ஒரு மாறுபட்ட அணுகுமுறை தேவை, அதைக் கண்டறிய நீங்கள் தயாராக இருக்கிறீர்கள்.', 'D'),
  (2, 'You feel the relational weight most. You want to repair things and restore the team''s energy, and that is driving your next move.', 'உறவுகளின் பாரத்தை நீங்கள் தான் அதிகமாக உணர்கிறீர்கள். நீங்கள் நிலைமையைச் சரிசெய்து, அணியின் ஆற்றலை மீட்டெடுக்க விரும்புகிறீர்கள், அதுவே உங்கள் அடுத்தகட்ட நகர்விற்கு உந்துதலாக இருக்கிறது.', 'I'),
  (3, 'You feel the discomfort of the unresolved tension acutely, and your strongest instinct is to find a way to bring the temperature down before doing anything structural.', 'தீர்க்கப்படாத பதற்றத்தின் அசௌகரியத்தை நீங்கள் கடுமையாக உணர்கிறீர்கள், மேலும் கட்டமைப்பு ரீதியாக எதையும் செய்வதற்கு முன்பு, பதற்றத்தைத் தணிப்பதற்கான ஒரு வழியைக் கண்டுபிடிப்பதே உங்கள் வலுவான உள்ளுணர்வாக இருக்கிறது.', 'S'),
  (4, 'You feel uncertain about your own diagnosis and want to slow down, gather more information, and make sure you understand what is actually happening before you act again.', 'உங்கள் நோயறிதலைப் பற்றி உங்களுக்கு நிச்சயமற்ற தன்மை இருப்பதால், மீண்டும் செயல்படுவதற்கு முன்பு நிதானித்து, கூடுதல் தகவல்களைச் சேகரித்து, உண்மையில் என்ன நடக்கிறது என்பதை நீங்கள் புரிந்துகொண்டதை உறுதிப்படுத்திக்கொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q9',
     'In a senior review, a peer manager presents a joint deliverable as though her team built it independently. Your team contributed sixty percent of the work. The senior leader thanks her specifically. You are in the room and so is your team lead, who glances at you waiting to see what you do.', 'What action should you take?', 'ஒரு மூத்த மதிப்பாய்வில், ஒரு சக மேலாளர், தனது குழுவே தனித்து உருவாக்கியதைப் போல ஒரு கூட்டுப் படைப்பை முன்வைக்கிறார். உங்கள் குழு அந்தப் பணியில் அறுபது சதவிகிதப் பங்களித்துள்ளது. அந்த மூத்த தலைவர் குறிப்பாக அவருக்கு நன்றி கூறுகிறார். நீங்களும் உங்கள் குழுத் தலைவரும் அந்த அறையில் இருக்கிறீர்கள்; நீங்கள் என்ன செய்கிறீர்கள் என்று பார்ப்பதற்காக அவர் உங்களைப் பார்க்கிறார்.', 'நீங்கள் என்ன நடவடிக்கை எடுக்க வேண்டும்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You speak up immediately, calmly adding context about the joint nature of the work and naming your team''s specific contributions.', 'நீங்கள் உடனடியாகப் பேசி, அந்தப் பணியின் கூட்டுத் தன்மை குறித்த பின்னணியை அமைதியாக விளக்கி, உங்கள் குழுவின் குறிப்பிட்ட பங்களிப்புகளையும் குறிப்பிடுகிறீர்கள்.', 'D'),
  (2, 'You let it pass in the room, then follow up with the senior leader directly afterward to ensure the full picture is on record.', 'அதை அறைக்குள் கடந்து போக விடுங்கள், பின்னர் முழுமையான விவரம் பதிவில் உள்ளதா என்பதை உறுதிப்படுத்திக்கொள்ள, மூத்த தலைவரிடம் உடனடியாகப் பின்தொடர்ந்து பேசுங்கள்.', 'I'),
  (3, 'You say nothing in the moment, protect the team from the awkwardness, and address it with your peer privately.', 'அந்த நேரத்தில் நீங்கள் எதுவும் பேசாமல், சங்கடத்திலிருந்து அணியைப் பாதுகாத்து, உங்கள் சக ஊழியரிடம் தனிப்பட்ட முறையில் அதைப் பற்றிப் பேசுங்கள்.', 'S'),
  (4, 'You wait until after the meeting, then send a written summary to the relevant stakeholders that accurately reflects contributions.', 'கூட்டம் முடிந்த பிறகு, பங்களிப்புகளைத் துல்லியமாகப் பிரதிபலிக்கும் ஒரு எழுத்துப்பூர்வச் சுருக்கத்தை சம்பந்தப்பட்ட தரப்பினருக்கு அனுப்பவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q10',
     'A cross-functional team member from another department consistently deprioritises your team''s requests. His manager has not made your work a priority and he is simply following that signal. You have no authority over him. The delay is now affecting a delivery your VP is tracking.', 'How to handle delayed cross-functional requests?', 'மற்றொரு துறையைச் சேர்ந்த, பல்துறைப் பணிகளைச் செய்யும் குழு உறுப்பினர் ஒருவர், உங்கள் குழுவின் கோரிக்கைகளுக்குத் தொடர்ந்து முக்கியத்துவம் அளிப்பதில்லை. அவரது மேலாளர் உங்கள் பணிக்கு முன்னுரிமை அளிக்கவில்லை, அவர் வெறுமனே அந்த அறிவுறுத்தலைப் பின்பற்றுகிறார். அவர் மீது உங்களுக்கு எந்த அதிகாரமும் இல்லை. இந்தத் தாமதம், உங்கள் துணைத் தலைவர் கண்காணித்து வரும் ஒரு விநியோகத்தை இப்போது பாதிக்கிறது.', 'தாமதமான பல்துறை கோரிக்கைகளை எவ்வாறு கையாள்வது?',
     '{"theme": "", "layer": "Layer 1", "dimension": "influence_style", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You escalate directly - you send a note to his manager with the timeline impact clearly laid out and ask for a conversation.', 'நீங்கள் நேரடியாக அடுத்த கட்டத்திற்குச் செல்லுங்கள் - காலக்கெடுவின் தாக்கத்தைத் தெளிவாகக் குறிப்பிட்டு, அவருடைய மேலாளருக்கு ஒரு குறிப்பை அனுப்பி, உரையாடலுக்குக் கோருங்கள்.', 'D'),
  (2, 'You invest time in the relationship first. You get coffee with him, understand his pressures, and find a way to make helping your team feel like it benefits him too.', 'முதலில் நீங்கள் அந்த உறவில் நேரத்தை முதலீடு செய்கிறீர்கள். அவருடன் காபி அருந்துங்கள், அவருடைய அழுத்தங்களைப் புரிந்து கொள்ளுங்கள், மேலும் உங்கள் அணிக்கு உதவுவது அவருக்கும் பயனளிக்கும் என்பதை உணரும்படியான ஒரு வழியைக் கண்டறியுங்கள்.', 'I'),
  (3, 'You absorb the delay where possible, redistribute internally, and find a workaround that does not require a political confrontation.', 'முடிந்தவரை தாமதத்தை நீங்களே ஏற்றுக்கொண்டு, அதை நிறுவனத்திற்குள்ளேயே மறுபகிர்வு செய்து, அரசியல் மோதலைத் தேவைப்படுத்தாத ஒரு மாற்று வழியைக் கண்டறியுங்கள்.', 'S'),
  (4, 'You map the dependency clearly, quantify the delay impact, and bring it to your own manager with a specific ask rather than managing it alone.', 'நீங்கள் அதைத் தனியாகக் கையாள்வதற்குப் பதிலாக, சார்புநிலையைத் தெளிவாக வரைபடமாக்கி, தாமதத்தின் தாக்கத்தை அளவிட்டு, ஒரு குறிப்பிட்ட கோரிக்கையுடன் உங்கள் மேலாளரிடம் கொண்டு செல்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q11',
     'What matters more to you in this moment? You have just discovered that a peer has been telling a shared senior stakeholder that your team lacks the capability to deliver the current roadmap. You have not been given the chance to respond. The stakeholder has started asking your manager questions. One pull is to confront your peer directly and clear the air. The other is to let your work speak - deliver the roadmap and make the conversation irrelevant.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? தற்போதைய செயல்திட்டத்தை நிறைவேற்றும் திறன் உங்கள் குழுவிடம் இல்லை என்று, உங்கள் சக ஊழியர் ஒருவர் பொதுவான மூத்த அதிகாரி ஒருவரிடம் கூறி வருவதை நீங்கள் இப்போதுதான் கண்டறிந்துள்ளீர்கள். பதிலளிக்க உங்களுக்கு வாய்ப்பு வழங்கப்படவில்லை. அந்த அதிகாரி உங்கள் மேலாளரிடம் கேள்விகள் கேட்கத் தொடங்கிவிட்டார். ஒரு வழி, உங்கள் சக ஊழியரை நேரடியாக எதிர்கொண்டு நிலைமையைச் சரிசெய்வது. மற்றொன்று, உங்கள் வேலையைப் பேச விடுவது - செயல்திட்டத்தை நிறைவேற்றி, அந்த உரையாடலை முக்கியமற்றதாக்குவது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Confronting it matters more. You speak to your peer directly, name what you have heard, and ask for a straightforward conversation.', 'அதை எதிர்கொள்வதுதான் மிகவும் முக்கியம். உங்கள் சக ஊழியரிடம் நேரடியாகப் பேசி, நீங்கள் கேட்டதைச் சொல்லி, ஒரு நேரடியான உரையாடலுக்குக் கோருங்கள்.', 'D'),
  (2, 'The stakeholder relationship matters more. You find a moment with the senior stakeholder to share your team''s progress and reframe the narrative.', 'பங்குதாரர் உறவு மிகவும் முக்கியமானது. உங்கள் குழுவின் முன்னேற்றத்தைப் பகிர்ந்துகொள்ளவும், நிலைமையை மாற்றி அமைக்கவும் மூத்த பங்குதாரருடன் ஒரு தருணத்தை ஒதுக்குங்கள்.', 'I'),
  (3, 'Delivering matters more. You put your energy into the work and trust that results will outweigh the noise.', 'முடிவுகளை வழங்குவதுதான் மிகவும் முக்கியம். நீங்கள் உங்கள் ஆற்றலை அந்த வேலையில் செலுத்தி, அதன் விளைவுகள் தேவையற்ற சத்தங்களை விட மேலோங்கும் என்று நம்புகிறீர்கள்.', 'S'),
  (4, 'Understanding the full picture matters more. You gather what was actually said, from whom, and through which channel before you respond to anything.', 'முழுமையான நிலவரத்தைப் புரிந்துகொள்வது மிகவும் முக்கியம். எதற்கும் பதிலளிக்கும் முன், உண்மையில் என்ன கூறப்பட்டது, யாரால், எந்த வழியில் கூறப்பட்டது என்பதை நீங்கள் அறிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q12',
     'The honest feeling underneath this is something you do not usually admit. A peer you considered an ally has been working against you quietly. You found out through someone you trust. The professional response is clear enough. But sitting with the knowledge that someone you thought was in your corner was not - that is a different kind of sting, and it is still sitting in your chest when you walk into the building this morning.', 'What is your next move?', 'இதற்கு அடியில் இருக்கும் உண்மையான உணர்வை நீங்கள் பொதுவாக ஒப்புக்கொள்வதில்லை. உங்கள் கூட்டாளியாக நீங்கள் கருதிய ஒரு சக ஊழியர், உங்களுக்கு எதிராக அமைதியாகச் செயல்பட்டு வருகிறார். நீங்கள் நம்பும் ஒருவர் மூலமாகவே இதை நீங்கள் தெரிந்துகொண்டீர்கள். தொழில்முறை ரீதியான பதில் தெளிவாகவே இருக்கிறது. ஆனால், உங்களுக்கு ஆதரவாக இருப்பார் என்று நீங்கள் நினைத்த ஒருவர் அப்படி இல்லை என்ற உண்மையுடன் இருப்பது - அது வேறு விதமான வலி. இன்று காலை நீங்கள் இந்தக் கட்டிடத்திற்குள் நுழையும்போதும் அந்த வலி உங்கள் நெஞ்சில் இருந்துகொண்டே இருக்கிறது.', 'உங்கள் அடுத்த நடவடிக்கை என்ன?',
     '{"theme": "", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name the feeling to yourself, set it aside, and focus on what needs to happen professionally. You will process it later.', 'அந்த உணர்வை உங்களுக்குள்ளேயே பெயரிட்டு, அதை ஒதுக்கி வைத்துவிட்டு, தொழில்ரீதியாக என்ன நடக்க வேண்டுமோ அதில் கவனம் செலுத்துங்கள். அதை நீங்கள் பின்னர் சிந்தித்துப் பார்க்கலாம்.', 'D'),
  (2, 'You reach out to someone you trust outside the situation, say it out loud, and then decide how to move.', 'அந்தச் சூழ்நிலைக்கு வெளியே நீங்கள் நம்பும் ஒருவரிடம் பேசி, அதை உரக்கச் சொல்லிவிட்டு, பிறகு அடுத்தகட்ட நடவடிக்கை என்னவென்று முடிவு செய்யுங்கள்.', 'I'),
  (3, 'You sit with it, give yourself time, and do not make any moves until the emotional charge has settled.', 'அதனுடன் இருங்கள், உங்களுக்கு நீங்களே அவகாசம் கொடுங்கள், மேலும் அந்த உணர்ச்சிப் பதற்றம் தணியும் வரை எந்த நடவடிக்கையும் எடுக்காதீர்கள்.', 'S'),
  (4, 'You channel it into clarity - you review what you know, what you assumed, and what you should have documented better.', 'நீங்கள் அதைத் தெளிவாக்குகிறீர்கள் - உங்களுக்குத் தெரிந்தவை, நீங்கள் ஊகித்தவை, மேலும் நீங்கள் சிறப்பாக ஆவணப்படுத்தியிருக்க வேண்டியவை ஆகியவற்றை மீள்பார்வை செய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q13',
     'You have been asked to implement a bell curve rating this cycle that requires you to mark one of your solid performers as below expectations. She has not underperformed. The directive is structural, not merit-based. She will not understand that distinction easily. You have three days before ratings are due.', 'How to handle unfair rating?', 'இந்தச் சுழற்சியில், உங்கள் நிறுவனத்தில் சிறப்பாகச் செயல்படுபவர்களில் ஒருவரை ''எதிர்பார்ப்புகளுக்குக் கீழ்'' என மதிப்பிட வேண்டிய ஒரு மணி வடிவ மதிப்பீட்டு முறையைச் செயல்படுத்தும்படி நீங்கள் கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள். அவர் மோசமாகச் செயல்படவில்லை. இந்த வழிகாட்டுதல் கட்டமைப்பு சார்ந்தது, தகுதி அடிப்படையிலானது அல்ல. அந்த வேறுபாட்டை அவரால் எளிதில் புரிந்துகொள்ள முடியாது. மதிப்பீடுகளைச் சமர்ப்பிப்பதற்கு உங்களுக்கு மூன்று நாட்கள் அவகாசம் உள்ளது.', 'நியாயமற்ற மதிப்பீட்டை எவ்வாறு கையாள்வது?',
     '{"theme": "", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You have the conversation directly - you tell her honestly that the rating is structural, not a reflection of your view of her work, and you own the discomfort of delivering it.', 'நீங்கள் நேரடியாக உரையாடுங்கள் - அந்த மதிப்பீடு ஒரு கட்டமைப்பு சார்ந்தது என்றும், அது அவருடைய படைப்பு குறித்த உங்கள் பார்வையின் பிரதிபலிப்பு அல்ல என்றும் அவரிடம் நேர்மையாகக் கூறுங்கள்; மேலும், அதைத் தெரிவிப்பதில் உள்ள சங்கடத்தையும் நீங்களே ஏற்றுக்கொள்ளுங்கள்.', 'D'),
  (2, 'You soften the framing carefully, focus on the areas for growth, and protect her from the full weight of a system-level decision she cannot change.', 'நீங்கள் அணுகுமுறையை கவனமாக மென்மையாக்கி, வளர்ச்சிக்கான அம்சங்களில் கவனம் செலுத்தி, அவளால் மாற்ற முடியாத ஒரு அமைப்பு ரீதியான முடிவின் முழுச் சுமையிலிருந்தும் அவளைப் பாதுகாக்கிறீர்கள்.', 'I'),
  (3, 'You delay as long as possible and try once more through your manager to get an exception before you deliver the rating.', 'நீங்கள் மதிப்பீட்டை வழங்குவதற்கு முன்பு, முடிந்தவரை தாமதித்து, உங்கள் மேலாளர் மூலம் மீண்டும் ஒருமுறை விதிவிலக்கு பெற முயற்சி செய்யுங்கள்.', 'S'),
  (4, 'You document your objection to the rating formally before submitting it, so there is a record that the rating was directed rather than discretionary.', 'மதிப்பீட்டைச் சமர்ப்பிப்பதற்கு முன்பு, அதற்கான உங்கள் ஆட்சேபனையை நீங்கள் முறையாக ஆவணப்படுத்துகிறீர்கள். இதன் மூலம், அந்த மதிப்பீடு விருப்பத்தின் பேரில் வழங்கப்பட்டதல்ல, மாறாக ஒரு வழிகாட்டுதலின் பேரில் வழங்கப்பட்டது என்பதற்கான பதிவு இருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q14',
     'A cost-cutting directive has come through requiring you to remove a team benefit - flexible Friday hours - that your team has relied on for two years. It was never written into contracts but it became a real part of how your team works. Leadership wants it communicated this week. You did not design this decision and you do not agree with it.', 'What is the best action?', 'செலவைக் குறைக்கும் நோக்கில் ஒரு உத்தரவு பிறப்பிக்கப்பட்டுள்ளது. அதன்படி, கடந்த இரண்டு ஆண்டுகளாக உங்கள் குழு நம்பியிருந்த ''வெள்ளிக்கிழமை நெகிழ்வான வேலை நேரம்'' என்ற குழுப் பலனை நீங்கள் நீக்க வேண்டும். இது ஒப்பந்தங்களில் ஒருபோதும் சேர்க்கப்படவில்லை, ஆனால் உங்கள் குழுவின் செயல்பாட்டு முறையில் இது ஒரு முக்கிய அங்கமாகிவிட்டது. இந்த வாரம் இது தெரிவிக்கப்பட வேண்டும் என தலைமை விரும்புகிறது. இந்த முடிவை நீங்கள் வடிவமைக்கவில்லை, மேலும் நீங்கள் இதை ஏற்கவில்லை.', 'சிறந்த நடவடிக்கை எது?',
     '{"theme": "", "layer": "Layer 1", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You communicate it clearly and on time, then separately make your disagreement known upward through the right channel.', 'நீங்கள் அதைத் தெளிவாகவும் சரியான நேரத்திலும் தெரிவிக்க வேண்டும், பின்னர் உங்கள் கருத்து வேறுபாட்டை உரிய வழிமுறையின் மூலம் மேலதிகாரிகளுக்குத் தனியாகத் தெரியப்படுத்த வேண்டும்.', 'D'),
  (2, 'You frame the communication carefully - emphasising what is staying, what leadership is working on, and keeping the team''s trust in the process.', 'எது நிலைத்திருக்கிறது, தலைமை எதில் செயல்படுகிறது என்பதை வலியுறுத்தியும், செயல்முறையின் மீது குழுவின் நம்பிக்கையைத் தக்கவைத்தும், நீங்கள் தகவல்தொடர்பைக் கவனமாக வடிவமைக்கிறீர்கள்.', 'I'),
  (3, 'You take extra time this week to be available to the team, absorb the emotional fallout, and focus on making the transition as smooth as possible.', 'இந்த வாரம் நீங்கள் குழுவினருடன் இருப்பதற்கும், அதனால் ஏற்படும் மன உளைச்சலை உள்வாங்கிக் கொள்வதற்கும், இந்த மாற்றத்தை முடிந்தவரை சுமுகமாக மேற்கொள்வதில் கவனம் செலுத்துவதற்கும் கூடுதல் நேரத்தை எடுத்துக் கொள்கிறீர்கள்.', 'S'),
  (4, 'You prepare a detailed FAQ before the announcement so your team has complete information and does not feel blindsided.', 'அறிவிப்புக்கு முன்பாகவே நீங்கள் ஒரு விரிவான கேள்வி-பதில் பட்டியலைத் தயார் செய்கிறீர்கள், இதன்மூலம் உங்கள் குழுவினர் முழுமையான தகவல்களைப் பெறுவதோடு, திடீரென அதிர்ச்சியடைவதாகவும் உணர மாட்டார்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q15',
     'The conflict you feel most is between doing this quickly and doing this well. A restructuring directive requires you to tell a team member of seven years that her role is being eliminated. HR has given you a script and a timeline. The script feels clinical. The timeline feels rushed. You know this person. She has given a great deal to this team. Moving fast protects the organisation. Moving carefully honours the relationship.', 'How will you handle this?', 'இதை விரைவாகச் செய்வதற்கும், இதைச் சிறப்பாகச் செய்வதற்கும் இடையேதான் நீங்கள் அதிகம் உணரும் முரண்பாடு உள்ளது. ஒரு மறுசீரமைப்பு உத்தரவின்படி, ஏழு ஆண்டுகளாக உங்கள் குழுவில் பணியாற்றி வரும் ஒருவரிடம், அவரது பதவி நீக்கப்படுவதாக நீங்கள் கூற வேண்டும். மனிதவளத் துறை உங்களுக்கு ஒரு உரையாடல் குறிப்பையும் காலக்கெடுவையும் வழங்கியுள்ளது. அந்த உரையாடல் குறிப்பு இயந்திரத்தனமாகத் தோன்றுகிறது. காலக்கெடுவோ அவசரப்படுத்தப்பட்டதாகத் தோன்றுகிறது. உங்களுக்கு அந்த நபரைத் தெரியும். அவர் இந்தக் குழுவிற்குப் பெரும் பங்களிப்பை வழங்கியுள்ளார். வேகமாகச் செயல்படுவது நிறுவனத்தைப் பாதுகாக்கிறது. கவனமாகச் செயல்படுவது உறவைக் கௌரவிக்கிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You move on the timeline but rewrite the conversation in your own words - you owe her honesty, not a script.', 'நீங்கள் காலவரிசையில் முன்னேறுங்கள், ஆனால் உரையாடலை உங்கள் சொந்த வார்த்தைகளில் மாற்றி எழுதுங்கள் - நீங்கள் அவளுக்கு நேர்மையைக் காட்டக் கடமைப்பட்டுள்ளீர்கள், ஒரு திரைக்கதையை அல்ல.', 'D'),
  (2, 'You take a day longer than the timeline suggests and use it to prepare something that feels human, then communicate with care.', 'குறிப்பிட்ட காலக்கெடுவை விட ஒரு நாள் கூடுதலாக எடுத்துக்கொண்டு, அந்த நேரத்தைப் பயன்படுத்தி மனிதத்தன்மை வாய்ந்த ஒன்றை உருவாக்கி, பின்னர் அக்கறையுடன் தொடர்புகொள்ளுங்கள்.', 'I'),
  (3, 'You follow the timeline and the script. You protect yourself and the organisation by staying within process, then check in with her personally after.', 'நீங்கள் கால அட்டவணையையும் திட்டமிடப்பட்ட செயல்முறையையும் பின்பற்றுகிறீர்கள். செயல்முறைக்குள் இருப்பதன் மூலம் உங்களையும் நிறுவனத்தையும் பாதுகாத்துக் கொள்கிறீர்கள், பின்னர் அவரிடம் தனிப்பட்ட முறையில் கலந்தாலோசிக்கிறீர்கள்.', 'S'),
  (4, 'You follow the timeline but document your concerns about the process in writing to HR so there is a record of how this was handled.', 'நீங்கள் காலக்கெடுவைப் பின்பற்றுங்கள், ஆனால் இந்த செயல்முறை எவ்வாறு கையாளப்பட்டது என்பதற்கான பதிவு இருக்கும் வகையில், அது குறித்த உங்கள் கவலைகளை மனிதவளத் துறைக்கு எழுத்துப்பூர்வமாக ஆவணப்படுத்துங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q16',
     'Before you say anything to your team, you sit with the policy you have been asked to enforce. You do not believe it is right. You were not consulted. You were simply handed it and told to implement. The weight of that sits differently today - not just as a task, but as a question about what it means to be the person in this seat.', 'How will you handle this?', 'உங்கள் குழுவிடம் எதையும் சொல்வதற்கு முன், நீங்கள் அமல்படுத்தும்படி கேட்டுக்கொள்ளப்பட்ட கொள்கையுடன் அமர்ந்து சிந்திக்கிறீர்கள். அது சரியானது என்று நீங்கள் நம்புவதில்லை. உங்களிடம் கலந்தாலோசிக்கப்படவில்லை. அது உங்களிடம் வெறுமனே ஒப்படைக்கப்பட்டு, செயல்படுத்தும்படி கூறப்பட்டது. அதன் பாரம் இன்று வேறுவிதமாக அமைகிறது - அது வெறும் ஒரு பணியாக மட்டுமல்லாமல், இந்தப் பதவியில் இருக்கும் ஒருவராக இருப்பதன் அர்த்தம் என்ன என்பது குறித்த ஒரு கேள்வியாகவும் இருக்கிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the tension clearly and resolve it quickly - your job is to implement, and you do, while using the right channels to push back.', 'நீங்கள் பதற்றத்தைத் தெளிவாக உணர்ந்து அதை விரைவாகத் தீர்க்கிறீர்கள் - செயல்படுத்துவதுதான் உங்கள் வேலை, அதை நீங்கள் சரியான வழிகளைப் பயன்படுத்தி எதிர்த்துக்கொண்டே செய்கிறீர்கள்.', 'D'),
  (2, 'You feel the weight of the team''s trust. They look to you to protect them, and right now you are the one delivering the blow.', 'அணியின் நம்பிக்கையின் பாரத்தை நீங்கள் உணர்கிறீர்கள். தங்களைக் காக்க அவர்கள் உங்களை நம்பியிருக்கிறார்கள், ஆனால் தற்சமயம் அந்த அடியைக் கொடுப்பவர் நீங்கள்தான்.', 'I'),
  (3, 'You feel a strong need to separate what you personally believe from what you are professionally required to do, and you focus on making the delivery as humane as possible.', 'உங்கள் தனிப்பட்ட நம்பிக்கைகளையும், தொழில்ரீதியாக நீங்கள் செய்ய வேண்டியவற்றையும் பிரித்துப் பார்க்க வேண்டியதன் அவசியத்தை நீங்கள் வலுவாக உணர்கிறீர்கள், மேலும் அவற்றை முடிந்தவரை மனிதாபிமானத்துடன் வழங்குவதில் கவனம் செலுத்துகிறீர்கள்.', 'S'),
  (4, 'You feel most uncomfortable with the lack of clarity about where this directive came from and whether it was properly thought through. That absence of process bothers you more than the directive itself.', 'இந்த உத்தரவு எங்கிருந்து வந்தது மற்றும் அது முறையாகச் சிந்தித்து எடுக்கப்பட்டதா என்பது குறித்த தெளிவின்மையே உங்களுக்கு மிகுந்த அசௌகரியத்தை ஏற்படுத்துகிறது. அந்த உத்தரவை விட, செயல்முறையின் இந்த இல்லாமையே உங்களை அதிகமாகப் பாதிக்கிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q17',
     'You were passed over for promotion. Your manager''s explanation was vague - something about timing and visibility. You know a peer with comparable output was promoted six months ago. You have been in this role for three years. You have a one-on-one tomorrow.', 'How will you handle this?', 'உங்களுக்குப் பதவி உயர்வு மறுக்கப்பட்டது. உங்கள் மேலாளரின் விளக்கம் தெளிவற்றதாக இருந்தது - நேரம் மற்றும் வெளிப்படைத்தன்மை பற்றிய ஏதோ ஒன்று. உங்களைப் போன்றே செயல்திறன் கொண்ட ஒரு சக ஊழியர் ஆறு மாதங்களுக்கு முன்பு பதவி உயர்வு பெற்றார் என்பது உங்களுக்குத் தெரியும். நீங்கள் இந்தப் பதவியில் மூன்று ஆண்டுகளாக இருக்கிறீர்கள். நாளை உங்களுக்கு ஒரு தனிப்பட்ட சந்திப்பு உள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You go into the meeting with direct questions: what specifically needs to change, by when, and what does the decision look like. You want a clear answer.', 'நீங்கள் நேரடியான கேள்விகளுடன் கூட்டத்திற்குச் செல்கிறீர்கள்: குறிப்பாக என்ன மாற்றப்பட வேண்டும், எப்போது மாற்றப்பட வேண்டும், மற்றும் அந்த முடிவு எப்படி இருக்கும் என்பன போன்ற கேள்விகள். உங்களுக்கு ஒரு தெளிவான பதில் வேண்டும்.', 'D'),
  (2, 'You use the meeting to rebuild the relationship first - you want to understand your manager''s perspective fully before you push.', 'முதலில் உறவை மீண்டும் கட்டியெழுப்ப அந்தச் சந்திப்பைப் பயன்படுத்திக்கொள்ளுங்கள் - நீங்கள் வற்புறுத்துவதற்கு முன்பு உங்கள் மேலாளரின் கண்ணோட்டத்தை முழுமையாகப் புரிந்துகொள்ள வேண்டும்.', 'I'),
  (3, 'You process the disappointment, go into the meeting calmly, and focus on what you can control going forward.', 'நீங்கள் ஏமாற்றத்தை உள்வாங்கிக்கொண்டு, அமைதியாகக் கூட்டத்திற்குச் சென்று, இனிவரும் காலங்களில் உங்கள் கட்டுப்பாட்டில் உள்ள விஷயங்களில் கவனம் செலுத்துங்கள்.', 'S'),
  (4, 'You prepare a documented record of your contributions and bring it into the conversation as evidence to anchor the discussion.', 'உங்கள் பங்களிப்புகளின் ஆவணப் பதிவைத் தயாரித்து, கலந்துரையாடலை வலுப்படுத்துவதற்கான சான்றாக அதனை உரையாடலில் முன்வைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q18',
     'You have been given a significant stretch assignment - leading a cross-functional integration project - with no title change, no additional compensation, and no formal mandate. The project is high visibility. Failure will be visible. Success may benefit someone above you more than it benefits you.', 'How will you handle this?', 'பதவி மாற்றம், கூடுதல் ஊதியம், அல்லது முறையான அதிகாரம் எதுவும் இல்லாமல், பல்துறை ஒருங்கிணைப்புத் திட்டத்திற்குத் தலைமை தாங்கும் ஒரு சவாலான முக்கியப் பொறுப்பு உங்களுக்கு வழங்கப்பட்டுள்ளது. இத்திட்டம் அதிக கவனத்தைப் பெறும் ஒன்றாகும். தோல்வியும் வெளிப்படையாகத் தெரியும். இதில் கிடைக்கும் வெற்றி, உங்களுக்குக் கிடைக்கும் நன்மையை விட உங்களுக்கு மேலுள்ள ஒருவருக்கு அதிகப் பயனளிக்கக்கூடும்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You take it, lead it hard, and use the visibility as leverage in the next performance conversation.', 'நீங்கள் அதை ஏற்றுக்கொண்டு, வலுவாக முன்னின்று வழிநடத்தி, அடுத்த செயல்திறன் உரையாடலில் இந்த வெளிச்சத்தை ஒரு சாதகமாகப் பயன்படுத்திக்கொள்ளுங்கள்.', 'D'),
  (2, 'You accept it, but before you start, you have a direct conversation about what success looks like for you - not just for the organisation.', 'நீங்கள் அதை ஏற்றுக்கொள்கிறீர்கள், ஆனால் தொடங்குவதற்கு முன், நிறுவனத்திற்கு மட்டுமல்ல, உங்களுக்கான வெற்றி என்பது என்ன என்பது பற்றி நேரடியாக உரையாடுகிறீர்கள்.', 'I'),
  (3, 'You take it because walking away feels like the wrong signal, and you trust that doing it well will speak for itself eventually.', 'விலகிச் செல்வது ஒரு தவறான அறிகுறி என்று தோன்றுவதால் நீங்கள் அதை ஏற்றுக்கொள்கிறீர்கள், மேலும் அதைச் சிறப்பாகச் செய்வது காலப்போக்கில் தானாகவே பேசும் என்று நம்புகிறீர்கள்.', 'S'),
  (4, 'You take it, build a clear scope document, and make sure there is a written record of your role and expected outcomes from day one.', 'இதை ஏற்றுக்கொண்டு, ஒரு தெளிவான பணி வரையறை ஆவணத்தை உருவாக்குங்கள். மேலும், முதல் நாளிலிருந்தே உங்கள் பங்கு மற்றும் எதிர்பார்க்கப்படும் விளைவுகள் குறித்த எழுத்துப்பூர்வமான பதிவு இருப்பதை உறுதி செய்துகொள்ளுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q19',
     'Two things are pulling at you. Which is stronger? You have realised that four years have passed in this role and no one above you has proactively initiated a development conversation. You have delivered. You have not been invisible. One pull is to wait - the right moment, the right relationship, the right opening. The other pull is to name it directly: you are ready for more, and someone above you needs to know that.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? இந்தப் பதவியில் நான்கு ஆண்டுகள் கடந்துவிட்டன, ஆனால் உங்களுக்கு மேலுள்ள யாரும் முன்முயற்சியாக வளர்ச்சி குறித்த உரையாடலைத் தொடங்கவில்லை என்பதை நீங்கள் உணர்ந்திருக்கிறீர்கள். நீங்கள் உங்கள் கடமையைச் செய்திருக்கிறீர்கள். நீங்கள் கவனிக்கப்படாமல் இருக்கவில்லை. ஒரு ஈர்ப்பு, சரியான தருணம், சரியான உறவு, சரியான வாய்ப்பு வரும் வரை காத்திருப்பது. மற்றொரு ஈர்ப்பு, அதை நேரடியாகக் கூறுவது: நீங்கள் இன்னும் முன்னேறத் தயாராக இருக்கிறீர்கள், உங்களுக்கு மேலுள்ள ஒருவர் அதைத் தெரிந்துகொள்ள வேண்டும்.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to name it is stronger. You initiate the conversation with your manager and make your ambition explicit.', 'அதற்குப் பெயரிட வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்களே உங்கள் மேலாளருடன் உரையாடலைத் தொடங்கி, உங்கள் லட்சியத்தைத் தெளிவாகத் தெரிவிக்கிறீர்கள்.', 'D'),
  (2, 'The pull to build the relationship first is stronger. You invest in the people above you before you make the ask.', 'முதலில் உறவை வலுப்படுத்த வேண்டும் என்ற ஈர்ப்பு வலிமையானது. நீங்கள் ஒரு கோரிக்கையை வைப்பதற்கு முன், உங்களுக்கு மேலுள்ளவர்கள் மீது முதலீடு செய்கிறீர்கள்.', 'I'),
  (3, 'The pull to wait for the right moment is stronger. You want to be sure the timing and the relationship can hold the conversation.', 'சரியான தருணத்திற்காகக் காத்திருக்க வேண்டும் என்ற ஈர்ப்பு வலுவாக இருக்கிறது. அந்த உரையாடலுக்குச் சரியான நேரமும் உறவும் பொருந்துமா என்பதை நீங்கள் உறுதிப்படுத்திக்கொள்ள விரும்புகிறீர்கள்.', 'S'),
  (4, 'The pull to document your readiness is stronger. You build the case before you have the conversation so that it is grounded in evidence.', 'உங்கள் தயார்நிலையை ஆவணப்படுத்த வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. உரையாடலைத் தொடங்குவதற்கு முன்பே நீங்கள் அதற்கான வாதத்தை முன்வைக்கிறீர்கள், அதனால் அது ஆதாரங்களின் அடிப்படையில் அமைந்திருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q20',
     'What is actually happening inside you when the peer with less experience and lower output gets the promotion and you are still here? You know the professional answer. You know what you are supposed to feel. But underneath that, in the part you do not usually name out loud - there is something real sitting there, and it is not just disappointment.', 'How do you manage disappointment?', 'குறைந்த அனுபவமும் குறைந்த செயல்திறனும் கொண்ட உங்கள் சக ஊழியருக்குப் பதவி உயர்வு கிடைத்து, நீங்கள் மட்டும் இன்னும் அதே நிலையில் இருக்கும்போது, ​​உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது? அதற்கான தொழில்முறைப் பதில் உங்களுக்குத் தெரியும். நீங்கள் என்ன உணர வேண்டும் என்பதும் உங்களுக்குத் தெரியும். ஆனால், அதற்கு அடியில், நீங்கள் வழக்கமாக வெளிப்படையாகக் குறிப்பிடாத அந்தப் பகுதியில், உண்மையான ஒன்று குடியிருக்கிறது; அது வெறும் ஏமாற்றம் மட்டுமல்ல.', 'ஏமாற்றத்தை நீங்கள் எப்படிச் சமாளிக்கிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is frustration, and you let yourself feel it fully before you decide what to do with it.', 'விரக்தி ஏற்படுகிறது, அதை என்ன செய்வதென்று தீர்மானிப்பதற்கு முன், நீங்கள் அதை முழுமையாக உணர அனுமதிக்கிறீர்கள்.', 'D'),
  (2, 'There is a social wound - a question about whether the people above you actually see you - and that is what is actually driving the sting.', 'ஒரு சமூகப் புண் இருக்கிறது – அதாவது, உங்களுக்கு மேலுள்ளவர்கள் உங்களை உண்மையில் கவனிக்கிறார்களா என்ற கேள்வி – அதுதான் உண்மையில் அந்த வலியைத் தூண்டுகிறது.', 'I'),
  (3, 'There is a slow, uncomfortable doubt about whether staying patient is still the right strategy. That question is harder to sit with than the loss.', 'பொறுமையாக இருப்பது இன்னும் சரியான உத்திதானா என்பது குறித்து ஒரு மெதுவான, சங்கடமான சந்தேகம் எழுகிறது. அந்த இழப்பை விட, அந்தக் கேள்வியுடன் இருப்பது மிகவும் கடினம்.', 'S'),
  (4, 'There is a need to understand exactly what happened - not to dwell, but because not knowing the real reason is what feels most intolerable.', 'சரியாக என்ன நடந்தது என்பதைத் தெரிந்துகொள்ள வேண்டிய அவசியம் உள்ளது - அதிலேயே மூழ்கிக் கிடப்பதற்காக அல்ல, மாறாக உண்மையான காரணம் தெரியாமல் இருப்பதுதான் மிகவும் தாங்க முடியாததாக உணர்வதால்தான்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q21',
     'A reorg has been announced. Your role now reports into a leader you have had significant friction with over the past eighteen months. Nothing has been said formally about expectations or the working relationship. You are expected to show up to his team meeting next Monday as though the past did not happen.', 'How will you handle this?', 'ஒரு மறுசீரமைப்பு அறிவிக்கப்பட்டுள்ளது. கடந்த பதினெட்டு மாதங்களாக உங்களுடன் கணிசமான கருத்து வேறுபாடுகளைக் கொண்டிருந்த ஒரு தலைவரின் கீழ் இப்போது உங்கள் பதவி அமையும். எதிர்பார்ப்புகள் அல்லது பணி உறவுமுறை குறித்து முறையாக எதுவும் கூறப்படவில்லை. கடந்த காலம் எதுவும் நடக்காதது போல், வரும் திங்கட்கிழமை நடைபெறும் அவரது குழு கூட்டத்தில் நீங்கள் கலந்துகொள்ள வேண்டும் என எதிர்பார்க்கப்படுகிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a one-on-one with him before Monday to establish how you want to work together going forward - you name the fresh start explicitly.', 'இனிவரும் காலங்களில் நீங்கள் இருவரும் எவ்வாறு இணைந்து பணியாற்ற விரும்புகிறீர்கள் என்பதைத் தெளிவுபடுத்துவதற்காக, திங்கட்கிழமைக்கு முன்னர் அவருடன் ஒரு தனிப்பட்ட சந்திப்பைக் கோருகிறீர்கள் - அந்தப் புதிய தொடக்கத்தை நீங்கள் வெளிப்படையாகக் குறிப்பிடுகிறீர்கள்.', 'D'),
  (2, 'You show up to Monday''s meeting with full energy and let your presence speak. You build the relationship through action, not a pre-conversation.', 'திங்கட்கிழமை கூட்டத்திற்கு நீங்கள் முழு ஆற்றலுடன் வந்து, உங்கள் இருப்பே பேசட்டும் என விட்டுவிடுகிறீர்கள். முன் உரையாடலால் அல்லாமல், செயலால் உறவை உருவாக்குகிறீர்கள்.', 'I'),
  (3, 'You give it a few weeks, observe how he operates with the broader team, and only seek a direct conversation once you have a clearer read.', 'சில வாரங்கள் பொறுத்திருந்து, அவர் மற்ற குழுவினருடன் எவ்வாறு செயல்படுகிறார் என்பதைக் கவனித்து, அவரைப் பற்றித் தெளிவான புரிதல் ஏற்பட்ட பின்னரே நேரடியாகப் பேச முற்படுங்கள்.', 'S'),
  (4, 'You review your previous interactions carefully, identify where the friction originated, and go into Monday with a clear sense of what you want to do differently.', 'உங்கள் முந்தைய உரையாடல்களைக் கவனமாக மீளாய்வு செய்து, உரசல் எங்கிருந்து தொடங்கியது என்பதைக் கண்டறிந்து, திங்கட்கிழமையன்று நீங்கள் என்ன வித்தியாசமாகச் செய்ய விரும்புகிறீர்கள் என்பது குறித்த தெளிவான புரிதலுடன் செயல்படுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q22',
     'Your team is being merged with another team. The other manager - a peer you respect - has been given the combined leadership. You are now effectively a senior team member without a management title. Your team does not know what this means for them. You have not been given clarity either.', 'How will you handle this?', 'உங்கள் குழு மற்றொரு குழுவுடன் இணைக்கப்படுகிறது. நீங்கள் மதிக்கும் சக மேலாளரான மற்றொரு மேலாளருக்கு, ஒருங்கிணைந்த தலைமைப் பொறுப்பு வழங்கப்பட்டுள்ளது. நீங்கள் இப்போது நிர்வாகப் பதவிப் பெயர் இல்லாத ஒரு மூத்த குழு உறுப்பினராகச் செயல்படுகிறீர்கள். இது தங்களுக்கு என்ன விளைவுகளை ஏற்படுத்தும் என்பது உங்கள் குழுவிற்குத் தெரியாது. உங்களுக்கும் இதுகுறித்து எந்தத் தெளிவும் வழங்கப்படவில்லை.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You immediately seek a conversation with the new combined manager to understand your role clearly, then communicate with your team with whatever clarity you have.', 'உங்கள் பங்கைத் தெளிவாகப் புரிந்துகொள்வதற்காக, புதிய ஒருங்கிணைந்த மேலாளருடன் உடனடியாக உரையாடலை மேற்கொள்ளுங்கள்; பின்னர், உங்களுக்குத் தெரிந்த தெளிவுடன் உங்கள் குழுவினருடன் தொடர்புகொள்ளுங்கள்.', 'D'),
  (2, 'You focus on the relationships first - yours with the new manager and the merged team''s cohesion - and trust that the structural clarity will come.', 'முதலில், புதிய மேலாளருடனான உங்கள் உறவு மற்றும் ஒன்றிணைக்கப்பட்ட அணியின் ஒருங்கிணைப்பு போன்ற உறவுகளில் கவனம் செலுத்துங்கள்; கட்டமைப்புத் தெளிவு தானாகவே வந்துவிடும் என்று நம்புங்கள்.', 'I'),
  (3, 'You keep your team calm, absorb their anxiety, and project stability even while managing your own uncertainty privately.', 'நீங்கள் உங்கள் குழுவினரை அமைதியாக வைத்து, அவர்களின் பதற்றத்தைத் தாங்கிக்கொண்டு, ஸ்திரத்தன்மையை நிலைநாட்டும் அதே வேளையில், தனிப்பட்ட முறையில் உங்கள் சொந்த நிச்சயமற்ற தன்மையையும் நிர்வகிக்கிறீர்கள்.', 'S'),
  (4, 'You ask for the organisational structure in writing before you communicate anything to your team, so you are not passing on information that may change.', 'உங்கள் குழுவிடம் எதையும் தெரிவிப்பதற்கு முன், நிறுவனத்தின் கட்டமைப்பை எழுத்துப்பூர்வமாகக் கேட்பதன் மூலம், மாறக்கூடிய தகவல்களை நீங்கள் பரிமாறாமல் இருக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q23',
     'What matters more to you in this moment? A new process has been mandated from above. Your team has tested it and believes it will reduce output quality and slow delivery. They have brought you their concerns. One pull is to protect their confidence in the process - implement it, stay aligned with leadership, and manage the discontent internally. The other pull is to represent your team''s concerns upward before the damage shows in the work.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? மேலதிகாரிகளிடமிருந்து ஒரு புதிய செயல்முறை கட்டாயமாக்கப்பட்டுள்ளது. உங்கள் குழு அதைச் சோதித்துப் பார்த்ததில், அது வெளியீட்டின் தரத்தைக் குறைத்து, விநியோகத்தைத் தாமதப்படுத்தும் என்று நம்புகிறது. அவர்கள் தங்கள் கவலைகளை உங்களிடம் தெரிவித்துள்ளனர். ஒரு உந்துதல் என்னவென்றால், அந்தச் செயல்முறையின் மீதான அவர்களின் நம்பிக்கையைப் பாதுகாப்பது - அதைச் செயல்படுத்துவது, தலைமைத்துவத்துடன் இணக்கமாக இருப்பது, மற்றும் அதிருப்தியை நிறுவனத்திற்குள்ளேயே கையாள்வது. மற்றொரு உந்துதல் என்னவென்றால், வேலையில் பாதிப்பு வெளிப்படுவதற்கு முன்பே, உங்கள் குழுவின் கவலைகளை மேலதிகாரிகளிடம் எடுத்துரைப்பது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Representing the concerns upward matters more. You bring a structured objection to your manager with data before implementation begins.', 'கவலைகளை மேலதிகாரிகளிடம் தெரிவிப்பது மிகவும் முக்கியம். செயலாக்கம் தொடங்குவதற்கு முன்பு, தரவுகளுடன் கூடிய ஒரு கட்டமைக்கப்பட்ட ஆட்சேபணையை உங்கள் மேலாளரிடம் நீங்கள் முன்வைக்க வேண்டும்.', 'D'),
  (2, 'The team''s morale matters more. You implement the process but make their concerns visible to leadership through a different channel.', 'அணியின் மன உறுதிதான் மிகவும் முக்கியம். நீங்கள் செயல்முறையைச் செயல்படுத்துங்கள், ஆனால் அவர்களின் கவலைகளை வேறு ஒரு வழிமுறையின் மூலம் தலைமைக்குத் தெரியப்படுத்துங்கள்.', 'I'),
  (3, 'Stability matters more. You implement the process, set a review checkpoint, and let the data make the argument in a few weeks.', 'நிலைத்தன்மைதான் மிகவும் முக்கியம். நீங்கள் செயல்முறையைச் செயல்படுத்தி, ஒரு மதிப்பாய்வுச் சோதனைக் கட்டத்தை அமைத்து, சில வாரங்களில் தரவுகளே அதற்கான வாதத்தை முன்வைக்கட்டும்.', 'S'),
  (4, 'Accuracy matters more. You document your team''s concerns formally, implement as directed, and create a measurement framework to track the impact.', 'துல்லியம் மிகவும் முக்கியம். உங்கள் குழுவின் கவலைகளை முறையாக ஆவணப்படுத்தி, அறிவுறுத்தப்பட்டபடி செயல்படுத்தி, அதன் தாக்கத்தைக் கண்காணிக்க ஒரு அளவீட்டுக் கட்டமைப்பை உருவாக்குங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q24',
     'Before you say anything to anyone about whether your role is at risk - before you project calm for your team, before you respond to the rumours circulating on Slack - what is actually happening inside you when no one in leadership will give you a direct answer?', 'How do you manage uncertainty?', 'உங்கள் பதவிக்கு ஆபத்து உள்ளதா என்பது பற்றி யாரிடமும் சொல்வதற்கு முன் - உங்கள் குழுவினரிடம் அமைதியைக் காட்டுவதற்கு முன் - ஸ்லாக்கில் பரவி வரும் வதந்திகளுக்குப் பதிலளிப்பதற்கு முன் - தலைமைப் பொறுப்பில் உள்ள எவரும் உங்களுக்கு நேரடியான பதில் அளிக்காதபோது, ​​உண்மையில் உங்களுக்குள் என்னதான் நடக்கிறது?', 'நிச்சயமற்ற தன்மையை நீங்கள் எவ்வாறு சமாளிக்கிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the urgency clearly and it is pushing you toward action - you want clarity and you are prepared to push for it.', 'நீங்கள் அவசரத்தை தெளிவாக உணர்கிறீர்கள், அது உங்களைச் செயல்படத் தூண்டுகிறது - உங்களுக்குத் தெளிவு வேண்டும், அதற்காகப் போராடவும் நீங்கள் தயாராக இருக்கிறீர்கள்.', 'D'),
  (2, 'You feel most unsettled by not knowing how the people above you are thinking about you specifically, and that uncertainty about your standing is harder than the structural ambiguity.', 'உங்களுக்கு மேலுள்ளவர்கள் உங்களைப் பற்றி குறிப்பாக எப்படி நினைக்கிறார்கள் என்று தெரியாததுதான் உங்களை மிகவும் அமைதியற்றதாக ஆக்குகிறது, மேலும் உங்கள் நிலை குறித்த அந்த நிச்சயமற்ற தன்மையானது, கட்டமைப்பு ரீதியான தெளிவின்மையை விடக் கடினமானது.', 'I'),
  (3, 'You feel a strong need to keep things stable around you - your team''s anxiety is real and managing it is what you are focusing on, even while your own uncertainty sits underneath.', 'உங்களைச் சுற்றியுள்ள சூழலை நிலையாக வைத்திருக்க வேண்டும் என்ற ஒரு வலுவான தேவையை நீங்கள் உணர்கிறீர்கள்; உங்கள் குழுவின் பதட்டம் உண்மையானது, உள்ளுக்குள் உங்கள் சொந்த நிச்சயமற்ற தன்மை இருந்தாலும், அதைச் சமாளிப்பதில்தான் நீங்கள் கவனம் செலுத்துகிறீர்கள்.', 'S'),
  (4, 'You feel most frustrated by the absence of information - you make decisions with data and the fact that no one is giving you any feels like a system failure, not just an oversight.', 'தகவல் இல்லாததுதான் உங்களுக்கு மிகுந்த விரக்தியை அளிக்கிறது - நீங்கள் தரவுகளைக் கொண்டே முடிவுகளை எடுக்கிறீர்கள், ஆனால் யாரும் உங்களுக்கு எந்தத் தகவலையும் தராதது ஒரு கவனக்குறைவு மட்டுமல்ல, அது ஒரு அமைப்பு ரீதியான தோல்வி போலவே தோன்றுகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q25',
     'Your manager asks you to exclude a specific finding from a client report. The finding is accurate. Removing it protects a relationship the company values. Including it is what you would do if you were making the call alone. You have two hours before the report goes out.', 'How will you handle this?', 'வாடிக்கையாளர் அறிக்கையிலிருந்து ஒரு குறிப்பிட்ட கண்டுபிடிப்பை நீக்குமாறு உங்கள் மேலாளர் உங்களைக் கேட்கிறார். அந்தக் கண்டுபிடிப்பு துல்லியமானது. அதை நீக்குவது, நிறுவனம் மதிக்கும் ஒரு உறவைப் பாதுகாக்கிறது. நீங்கள் தனியாக இந்த முடிவை எடுப்பதாக இருந்தால், அதைச் சேர்ப்பீர்கள். அறிக்கை அனுப்பப்படுவதற்கு உங்களுக்கு இரண்டு மணிநேரம் உள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell your manager you are not comfortable removing it, explain your reasoning, and ask whether there is a different way to handle the client relationship.', 'அதை நீக்குவதில் உங்களுக்குச் சங்கடமாக இருப்பதாக உங்கள் மேலாளரிடம் கூறி, அதற்கான காரணத்தையும் விளக்கி, வாடிக்கையாளர் உறவைக் கையாள வேறு வழி உள்ளதா என்றும் கேளுங்கள்.', 'D'),
  (2, 'You ask for a fifteen-minute call with your manager before the report goes out to fully understand the rationale - then decide based on what you hear.', 'அறிக்கை அனுப்பப்படுவதற்கு முன்பு, அதன் பின்னணியில் உள்ள காரணத்தை முழுமையாகப் புரிந்துகொள்வதற்காக உங்கள் மேலாளருடன் பதினைந்து நிமிட தொலைபேசி உரையாடலுக்குக் கேளுங்கள் - பின்னர், நீங்கள் கேட்பவற்றின் அடிப்படையில் முடிவெடுக்கவும்.', 'I'),
  (3, 'You flag your concern to your manager in writing, send the email trail to yourself, and then follow her direction while your objection is on record.', 'உங்கள் கவலையை உங்கள் மேலாளருக்கு எழுத்துப்பூர்வமாகத் தெரிவித்து, அந்த மின்னஞ்சல் தொடரை உங்களுக்கே அனுப்பிக்கொண்டு, உங்கள் எதிர்ப்பு பதிவில் இருக்கும் வரை அவர் கூறும் வழிகாட்டுதல்களைப் பின்பற்றுங்கள்.', 'S'),
  (4, 'You ask for the specific commercial or legal reason the finding should be excluded before you make any decision, and you document the conversation.', 'எந்தவொரு முடிவையும் எடுப்பதற்கு முன், அந்த முடிவு ஏன் நிராகரிக்கப்பட வேண்டும் என்பதற்கான குறிப்பிட்ட வணிக அல்லது சட்டப்பூர்வ காரணத்தை நீங்கள் கேட்டுத் தெரிந்துகொள்கிறீர்கள், மேலும் அந்த உரையாடலை ஆவணப்படுத்துகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q26',
     'A team member comes to you and discloses that the process your team has been running for eighteen months contains a systematic error. The outputs that went to clients were inaccurate. Your predecessor knew. Nothing was said. You have been in the role for four months.', 'How will you handle this?', 'உங்கள் குழு பதினெட்டு மாதங்களாகச் செயல்படுத்தி வரும் செயல்முறையில் ஒரு முறையான பிழை இருப்பதாக, குழு உறுப்பினர் ஒருவர் உங்களிடம் வந்து தெரிவிக்கிறார். வாடிக்கையாளர்களுக்கு அனுப்பப்பட்ட வெளியீடுகள் துல்லியமற்றவையாக இருந்தன. உங்களுக்கு முன்னிருந்தவருக்கு இது தெரிந்திருந்தது. எதுவும் கூறப்படவில்லை. நீங்கள் இந்தப் பொறுப்பில் நான்கு மாதங்களாக இருக்கிறீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You escalate immediately - to your manager and to whoever owns client relationships - with the full picture as you understand it. You do not wait.', 'உங்களுக்குப் புரிந்த வரையில் முழு விவரங்களையும் உடனடியாக உங்கள் மேலாளரிடமும், வாடிக்கையாளர் உறவுகளுக்குப் பொறுப்பானவரிடமும் கொண்டு செல்லுங்கள். நீங்கள் காத்திருக்கக் கூடாது.', 'D'),
  (2, 'You spend twenty-four hours understanding the full scope and impact before you escalate, so you are not raising a problem without a clear picture.', 'நீங்கள் ஒரு தெளிவான புரிதல் இல்லாமல் பிரச்சனையை எழுப்பாமல் இருப்பதற்காக, ஒரு பிரச்சனையின் முழு வீச்சையும் தாக்கத்தையும் புரிந்துகொள்வதற்கு முன், அதன் அடுத்தகட்டத்திற்குச் செல்லுங்கள்; அதன்மூலம் நீங்கள் இருபத்தி நான்கு மணிநேரம் செலவிடுகிறீர்கள்.', 'I'),
  (3, 'You talk to your predecessor first. You want to understand what they knew and why they made the choice they did before you decide how to move.', 'நீங்கள் முதலில் உங்களுக்கு முன்னிருந்தவருடன் பேசுங்கள். நீங்கள் அடுத்தகட்ட நடவடிக்கை குறித்து முடிவெடுப்பதற்கு முன், அவர்களுக்கு என்ன தெரிந்திருந்தது என்பதையும், அவர்கள் ஏன் அந்த முடிவை எடுத்தார்கள் என்பதையும் புரிந்துகொள்ள வேண்டும்.', 'S'),
  (4, 'You document everything you currently know, calculate the extent of the error, identify which clients were affected, and bring a structured summary upward with a proposed remediation.', 'நீங்கள் தற்போது அறிந்த அனைத்தையும் ஆவணப்படுத்தி, பிழையின் அளவைக் கணக்கிட்டு, எந்தெந்த வாடிக்கையாளர்கள் பாதிக்கப்பட்டனர் என்பதைக் கண்டறிந்து, முன்மொழியப்பட்ட சரிசெய்தலுடன் ஒரு கட்டமைக்கப்பட்ட சுருக்கத்தை மேலதிகாரிகளுக்குச் சமர்ப்பிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q27',
     'The conflict you feel most is between protecting yourself and doing what is right. A peer has asked you to back their version of events in a senior review. You were in the room. Their version is incomplete. It does not lie outright but it omits enough to create a false impression. If you back them, you protect a peer relationship and avoid a difficult situation. If you tell the truth fully, you create conflict that will not go away quickly.', 'How will you handle conflict?', 'உங்களைப் பாதுகாத்துக் கொள்வதற்கும், சரியானதைச் செய்வதற்கும் இடையேதான் நீங்கள் அதிகம் உணரும் முரண்பாடு உள்ளது. ஒரு மூத்த மாணவர் மதிப்பாய்வில், நடந்த நிகழ்வுகள் குறித்த அவர்களின் கூற்றை ஆதரிக்குமாறு ஒரு சக மாணவர் உங்களைக் கேட்டுள்ளார். நீங்கள் அந்த அறையில் இருந்தீர்கள். அவர்களின் கூற்று முழுமையற்றது. அது அப்பட்டமாகப் பொய் சொல்லவில்லை, ஆனால் ஒரு தவறான எண்ணத்தை உருவாக்கும் அளவுக்குப் போதுமான தகவல்களை அது விட்டுவிடுகிறது. நீங்கள் அவர்களை ஆதரித்தால், சக மாணவர் உறவைப் பாதுகாத்து, ஒரு கடினமான சூழ்நிலையைத் தவிர்க்கிறீர்கள். நீங்கள் உண்மையை முழுமையாகச் சொன்னால், விரைவில் தீராத ஒரு முரண்பாட்டை நீங்களே உருவாக்குகிறீர்கள்.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Doing what is right is stronger. You give your honest account in the review, regardless of what it costs the peer relationship.', 'சரியானதைச் செய்வதே வலிமையானது. சக மதிப்பாய்வாளர்களுடனான உறவுக்கு என்ன பாதிப்பு ஏற்பட்டாலும், மதிப்பாய்வில் உங்கள் நேர்மையான கருத்தைத் தெரிவிக்கிறீர்கள்.', 'D'),
  (2, 'The relationship pulls harder in the moment, but you find a way to give an accurate account without directly contradicting your peer in the room.', 'அந்தத் தருணத்தில் உறவுமுறை மிகவும் வலுவாக இருக்கும், ஆனாலும் அறையில் இருக்கும் உங்கள் சக நபருக்கு நேரடியாக முரண்படாமல், துல்லியமான ஒரு விளக்கத்தை அளிக்க நீங்கள் ஒரு வழியைக் கண்டுபிடிப்பீர்கள்.', 'I'),
  (3, 'Avoiding the conflict pulls harder. You back the version, tell yourself it is not technically a lie, and manage the discomfort afterward.', 'முரண்பாட்டைத் தவிர்ப்பது மேலும் கடினமானதாக இருக்கும். நீங்கள் அந்தப் பதிப்பை ஆதரித்து, அது தொழில்நுட்ப ரீதியாக ஒரு பொய் அல்ல என்று உங்களுக்குள் சொல்லிக்கொண்டு, பின்னர் ஏற்படும் சங்கடத்தைச் சமாளிப்பீர்கள்.', 'S'),
  (4, 'You ask for time before the review to speak to your peer directly. You tell them you cannot back an incomplete version and give them the chance to correct it themselves.', 'மதிப்பாய்வுக்கு முன்பு உங்கள் சக ஊழியரிடம் நேரடியாகப் பேச நேரம் கேட்கிறீர்கள். ஒரு முழுமையற்ற பதிப்பை உங்களால் ஆதரிக்க முடியாது என்று அவர்களிடம் கூறி, அதை அவர்களே திருத்திக்கொள்ள வாய்ப்பளிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q28',
     'The honest feeling underneath this - when your manager asks you to approve overtime hours that were not worked - is not just discomfort with the task. There is something else underneath it, and if you are being honest with yourself right now, sitting in this moment before you respond, you know what it is.', 'How will you handle this?', 'நீங்கள் செய்யாத கூடுதல் நேர வேலைக்கு ஒப்புதல் அளிக்குமாறு உங்கள் மேலாளர் கேட்கும்போது, ​​இதன் அடிநாதமாக இருக்கும் உண்மையான உணர்வு என்பது அந்த வேலையின் மீதான ஒருவித சங்கடம் மட்டுமல்ல. அதன் அடியில் வேறு ஏதோ ஒன்று இருக்கிறது; பதிலளிப்பதற்கு முன் இந்தத் தருணத்தில் நீங்கள் உங்களுக்கு உண்மையாக இருந்தால், அது என்னவென்று உங்களுக்குத் தெரியும்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'It is a line you know you cannot cross, and the clarity of that is actually calming - you know exactly what you will say.', 'அது உங்களால் தாண்ட முடியாத ஒரு எல்லை என்று உங்களுக்குத் தெரியும், மேலும் அந்தத் தெளிவு உண்மையில் அமைதியைத் தருகிறது - நீங்கள் என்ன சொல்வீர்கள் என்பது உங்களுக்குத் துல்லியமாகத் தெரியும்.', 'D'),
  (2, 'It is the discomfort of disappointing someone you work closely with and who trusts you, and that pull is real even though you know what the right answer is.', 'உங்களுடன் நெருக்கமாகப் பணியாற்றும், உங்களை நம்பும் ஒருவரை ஏமாற்றிவிடுவோமோ என்ற சங்கடம் உண்டு; சரியான பதில் என்னவென்று உங்களுக்குத் தெரிந்திருந்தாலும், அந்த ஈர்ப்பு உண்மையானது.', 'I'),
  (3, 'It is the fear of what saying no might cost you - the relationship, the trust, the informal goodwill that makes this job workable - and that fear is sitting right there.', '''இல்லை'' என்று சொன்னால் என்ன இழப்பு ஏற்படுமோ என்ற பயம் - அதாவது, இந்த வேலையைச் சாத்தியமாக்கும் உறவு, நம்பிக்கை, முறைசாரா நல்லெண்ணம் ஆகியவற்றை இழந்துவிடுவோமோ என்ற பயம் - அந்தப் பயம் அங்கேயே குடிகொண்டிருக்கிறது.', 'S'),
  (4, 'It is the need to understand exactly how this request got to you - who authorised it, what the precedent is, and what the systemic implications are - because the individual ask matters less than the pattern behind it.', 'இந்தக் கோரிக்கை உங்களிடம் எப்படி வந்தது - இதற்கு யார் அங்கீகாரம் அளித்தது, முன்னுதாரணம் என்ன, மற்றும் இதன் அமைப்பு ரீதியான தாக்கங்கள் என்ன என்பனவற்றைத் துல்லியமாகப் புரிந்துகொள்ள வேண்டிய அவசியம் உள்ளது. ஏனெனில், தனிப்பட்ட கோரிக்கையை விட அதன் பின்னணியில் உள்ள செயல்முறையே முக்கியமானது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q29',
     'You are presenting your team''s quarterly results to a senior leadership panel for the first time. Three minutes in, a director interrupts and asks why delivery was four days behind schedule on the flagship project. You know the answer. Part of it reflects a resourcing gap that was flagged and not addressed. Part of it reflects a call you made that slowed things down.', 'How will you handle this?', 'உங்கள் குழுவின் காலாண்டு முடிவுகளை முதல் முறையாக ஒரு மூத்த தலைமைத்துவக் குழுவிடம் சமர்ப்பிக்கிறீர்கள். மூன்று நிமிடங்களில், ஒரு இயக்குநர் குறுக்கிட்டு, முதன்மைத் திட்டத்தின் பணிகள் ஏன் நான்கு நாட்கள் தாமதமானது என்று கேட்கிறார். அதற்கான பதில் உங்களுக்குத் தெரியும். சுட்டிக்காட்டப்பட்டும் சரிசெய்யப்படாத ஒரு வளப் பற்றாக்குறையே இதற்குக் காரணம். இன்னொரு காரணம், நீங்கள் எடுத்த ஒரு முடிவு பணிகளைத் தாமதப்படுத்தியது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You answer directly and completely - the resourcing gap and your call, both named, with what you learned.', 'நீங்கள் கற்றுக்கொண்டவற்றைக் கொண்டு, வளப் பற்றாக்குறை மற்றும் உங்கள் கோரிக்கை ஆகிய இரண்டிற்கும் நேரடியாகவும் முழுமையாகவும் பதிலளிக்கிறீர்கள்.', 'D'),
  (2, 'You acknowledge the delay, focus on the recovery and the outcome, and address the causes briefly without making the conversation about what went wrong.', 'நீங்கள் தாமதத்தை ஒப்புக்கொண்டு, மீட்சி மற்றும் அதன் விளைவில் கவனம் செலுத்தி, என்ன தவறு நடந்தது என்பதைப் பற்றியதாக உரையாடலை மாற்றாமல், அதற்கான காரணங்களைச் சுருக்கமாகக் குறிப்பிடுகிறீர்கள்.', 'I'),
  (3, 'You answer carefully, name the resourcing factor, and take personal ownership without going into detail that might open a broader conversation about your decision-making.', 'நீங்கள் கவனமாகப் பதிலளித்து, வள ஆதாரக் காரணியைக் குறிப்பிட்டு, உங்கள் முடிவெடுக்கும் செயல்முறை குறித்து ஒரு விரிவான உரையாடலைத் தொடங்கக்கூடிய விவரங்களுக்குள் செல்லாமல், தனிப்பட்ட பொறுப்பை ஏற்றுக்கொள்கிறீர்கள்.', 'S'),
  (4, 'You give a complete, structured answer - cause, decision, outcome, and what the team has put in place to prevent recurrence - before the panel moves on.', 'குழு அடுத்த கட்டத்திற்குச் செல்வதற்கு முன், நீங்கள் காரணம், முடிவு, விளைவு மற்றும் மீண்டும் நிகழாமல் தடுக்க குழு என்ன நடவடிக்கைகளை எடுத்துள்ளது என்பது உள்ளிட்ட ஒரு முழுமையான, கட்டமைக்கப்பட்ட பதிலை அளிக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q30',
     'A senior leader asks you a direct question in a town hall that puts you in conflict. She asks whether your team believes the new performance framework is fair. Your team has told you privately it is not. Your manager is on stage beside the senior leader. The room is watching.', 'How do you handle this?', 'ஒரு பொதுக் கூட்டத்தில், ஒரு மூத்த தலைவர் உங்களிடம் ஒரு நேரடிக் கேள்வியைக் கேட்கிறார், அது உங்களை ஒரு முரண்பாட்டிற்குள் தள்ளுகிறது. புதிய செயல்திறன் கட்டமைப்பு நியாயமானது என்று உங்கள் குழு நம்புகிறதா என்று அவர் கேட்கிறார். அது நியாயமானதல்ல என்று உங்கள் குழு உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளது. அந்த மூத்த தலைவருக்கு அருகில் மேடையில் உங்கள் மேலாளர் இருக்கிறார். அறையில் உள்ள அனைவரும் பார்த்துக் கொண்டிருக்கிறார்கள்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "influence_style", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You give an honest answer - you share that your team has questions about the framework and you would welcome a forum to work through them.', 'நீங்கள் ஒரு நேர்மையான பதிலை அளிக்கிறீர்கள் - உங்கள் குழுவிற்கு அந்தக் கட்டமைப்பு குறித்து கேள்விகள் இருப்பதாகவும், அவற்றைத் தீர்த்து வைப்பதற்கு ஒரு கலந்துரையாடல் தளத்தை வரவேற்பதாகவும் பகிர்ந்து கொள்கிறீர்கள்.', 'D'),
  (2, 'You give a diplomatic answer that opens the door without closing it - you say the team is engaging with it and you would value the chance to share their feedback through the right channel.', 'நீங்கள், வாய்ப்பை முற்றிலுமாக மூடாமல் திறக்கும் விதத்தில் ஒரு ராஜதந்திரமான பதிலை அளிக்கிறீர்கள் - அதாவது, குழுவினர் இதுகுறித்து ஆராய்ந்து வருவதாகவும், சரியான வழிமுறையின் மூலம் அவர்களின் கருத்துக்களைப் பகிர்ந்துகொள்ளும் வாய்ப்பை நீங்கள் பெரிதும் மதிப்பீர்கள் என்றும் கூறுகிறீர்கள்.', 'I'),
  (3, 'You defer to the process - you say the team is working through it and you trust that the feedback mechanism will capture what they need to say.', 'நீங்கள் அந்தச் செயல்முறைக்கு இடமளிக்கிறீர்கள் - அதாவது, குழு அதைச் செயல்படுத்தி வருவதாகவும், அவர்கள் கூற விரும்புவதை பின்னூட்ட வழிமுறை உள்வாங்கிக்கொள்ளும் என்று நம்புவதாகவும் சொல்கிறீர்கள்.', 'S'),
  (4, 'You ask whether this is the right moment for that feedback or whether there is a better format - and in doing so, you buy time without saying anything inaccurate.', 'அந்தக் கருத்தைத் தெரிவிக்க இது சரியான தருணமா அல்லது இதைவிடச் சிறந்த வடிவம் ஏதேனும் உள்ளதா என்று நீங்கள் கேட்பதன் மூலம், தவறான எதையும் கூறாமல் கால அவகாசம் பெறுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q31',
     'Two things are pulling at you. Which is stronger? You need to give critical feedback to a team member who is ten years older than you and has significantly more industry experience. He has not delivered on a commitment that affected the team. One pull is to be direct - the feedback needs to land and softening it does not serve him. The other pull is to be careful - the power dynamic is reversed in ways that matter, and getting the delivery wrong could damage something that is hard to rebuild.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? உங்களை விட பத்து வயது மூத்தவரும், தொழில்துறையில் கணிசமான அனுபவம் உள்ளவருமான ஒரு குழு உறுப்பினருக்கு நீங்கள் விமர்சன ரீதியான பின்னூட்டத்தை வழங்க வேண்டும். அவர், குழுவைப் பாதித்த ஒரு வாக்குறுதியை நிறைவேற்றத் தவறிவிட்டார். ஒரு உந்துதல், நேரடியாகப் பின்னூட்டம் அளிக்க வேண்டும் என்பது - பின்னூட்டம் அவரைச் சென்றடைய வேண்டும், அதை மென்மையாக்குவது அவருக்குப் பயனளிக்காது. மற்றொரு உந்துதல், கவனமாக இருக்க வேண்டும் என்பது - அதிகார சமநிலை முக்கியமான வழிகளில் தலைகீழாக மாறியுள்ளது, மேலும் பின்னூட்டத்தை தவறாக வழங்குவது, மீண்டும் கட்டமைக்கக் கடினமான ஒன்றைச் சேதப்படுத்திவிடும்.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "influence_style", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to be direct is stronger. You give the feedback clearly, professionally, and without over-softening. You trust him to receive it as an adult.', 'நேரடியாகப் பேச வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்கள் பின்னூட்டத்தைத் தெளிவாகவும், தொழில்முறையாகவும், அதே சமயம் மிகவும் மென்மையாகாமலும் அளிக்கிறீர்கள். அதை அவர் ஒரு முதிர்ந்தவராக ஏற்றுக்கொள்வார் என்று நீங்கள் நம்புகிறீர்கள்.', 'D'),
  (2, 'The pull to be relational is stronger. You frame it as a conversation, acknowledge his experience, and make sure he feels heard before you name what needs to change.', 'உறவைப் பேணுவதற்கான நாட்டம் வலுவாக உள்ளது. நீங்கள் அதை ஒரு உரையாடலாக வடிவமைத்து, அவருடைய அனுபவத்தை ஏற்றுக்கொண்டு, என்ன மாற்றப்பட வேண்டும் என்று குறிப்பிடுவதற்கு முன்பு, அவர் சொல்வது கேட்கப்படுகிறது என்று அவர் உணர்வதை உறுதிப்படுத்திக் கொள்ளுங்கள்.', 'I'),
  (3, 'The pull to be careful is stronger. You take extra time to prepare, rehearse the delivery, and prioritise preserving the relationship while still saying what needs to be said.', 'கவனமாக இருக்க வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்கள் தயாராவதற்கும், பேசும் விதத்தை ஒத்திகை பார்ப்பதற்கும் கூடுதல் நேரம் எடுத்துக்கொள்கிறீர்கள்; சொல்ல வேண்டியதைச் சொல்லும் அதே வேளையில், உறவைப் பேணுவதற்கும் முன்னுரிமை அளிக்கிறீர்கள்.', 'S'),
  (4, 'The pull to be precise is stronger. You document the specific commitment, the gap, and the impact before you meet, so the conversation is grounded in fact rather than perception.', 'துல்லியமாகச் சொல்வதானால், அந்த ஈர்ப்பு மிகவும் வலிமையானது. நீங்கள் சந்திப்பதற்கு முன்பே, குறிப்பிட்ட அர்ப்பணிப்பு, இடைவெளி மற்றும் அதன் தாக்கம் ஆகியவற்றை ஆவணப்படுத்துவதால், அந்த உரையாடல் வெறும் யூகத்தின் அடிப்படையில் அமையாமல், உண்மைகளின் அடிப்படையில் அமைகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q32',
     'Before you walk into the room to represent your manager''s position on a decision you privately disagree with - before you put on the face that says you are aligned - what is actually happening inside you?', 'What happens inside you now?', 'தனிப்பட்ட முறையில் நீங்கள் உடன்படாத ஒரு முடிவில், உங்கள் மேலாளரின் நிலைப்பாட்டை எடுத்துரைப்பதற்காக அறைக்குள் நுழைவதற்கு முன்பும், அவருடன் உடன்படுவதாகக் காட்டும் முகமூடியை அணிவதற்கு முன்பும், உங்கள் உள்ளுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'இப்போது உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel a clear tension between your professional role and your personal view, and you have already decided which one leads in this room.', 'உங்கள் தொழில்முறைப் பணிக்கும் தனிப்பட்ட பார்வைக்கும் இடையே ஒரு தெளிவான முரண்பாட்டை நீங்கள் உணர்கிறீர்கள், மேலும் இந்த அறையில் எது மேலோங்குகிறது என்பதையும் நீங்கள் ஏற்கனவே தீர்மானித்துவிட்டீர்கள்.', 'D'),
  (2, 'You feel most uncomfortable with how this will be read by the people in the room who know you well enough to see through a performance.', 'உங்கள் நடிப்பை ஊடுருவிப் பார்க்கும் அளவுக்கு உங்களை நன்கு அறிந்த, அறையில் உள்ள மற்றவர்கள் இதை எப்படிப் புரிந்துகொள்வார்களோ என்பதுதான் உங்களுக்கு மிகவும் சங்கடமாக இருக்கிறது.', 'I'),
  (3, 'You feel the weight of loyalty - to your manager, to the position, to the relationship - and that loyalty is actually what is carrying you into this room.', 'உங்கள் மேலாளர் மீதும், பதவி மீதும், உறவு மீதும் உள்ள விசுவாசத்தின் பாரத்தை நீங்கள் உணர்கிறீர்கள்; உண்மையில் அந்த விசுவாசம்தான் உங்களை இந்த அறைக்குள் அழைத்து வருகிறது.', 'S'),
  (4, 'You feel an analytical discomfort: you have not been given enough information to know whether the position is actually wrong or just incomplete, and presenting it as solid when you are not sure feels like the real problem.', 'நீங்கள் ஒரு பகுப்பாய்வு ரீதியான சங்கடத்தை உணர்கிறீர்கள்: அந்த நிலைப்பாடு உண்மையில் தவறானதா அல்லது முழுமையற்றதா என்பதை அறிந்துகொள்ள உங்களுக்குப் போதுமான தகவல்கள் வழங்கப்படவில்லை, மேலும் உங்களுக்கு உறுதியாகத் தெரியாதபோது அதை உறுதியானதாக முன்வைப்பதுதான் உண்மையான சிக்கல் என்று தோன்றுகிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q33',
     'Your best performer tells you she is being actively approached by a competitor. She wants to understand what her future looks like here before she makes a decision. She is giving you the chance to respond. You have limited ability to change her compensation right now, and the promotion cycle is four months away.', 'How will you retain her?', 'உங்கள் நிறுவனத்தில் சிறப்பாகச் செயல்படுபவர், ஒரு போட்டியாளர் தன்னைத் தீவிரமாக அணுகுவதாக உங்களிடம் கூறுகிறார். ஒரு முடிவை எடுப்பதற்கு முன்பு, இங்கு தனது எதிர்காலம் எப்படி இருக்கும் என்பதை அவர் புரிந்துகொள்ள விரும்புகிறார். பதிலளிப்பதற்கான வாய்ப்பை அவர் உங்களுக்கு அளிக்கிறார். தற்போதைக்கு அவரது ஊதியத்தை மாற்றுவதற்கான உங்கள் அதிகாரம் குறைவாகவே உள்ளது, மேலும் பதவி உயர்வுக்கான காலம் இன்னும் நான்கு மாதங்கள் தொலைவில் உள்ளது.', 'அவளை எப்படித் தக்கவைத்துக் கொள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "relationship_dependency", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You are direct with her about what you can and cannot do, then make the strongest honest case for what her future looks like - including the specifics.', 'உங்களால் என்ன செய்ய முடியும், என்ன செய்ய முடியாது என்பதை அவளிடம் நேரடியாகக் கூறுங்கள். பின்னர், அதன் விவரங்கள் உட்பட, அவளுடைய எதிர்காலம் எப்படி இருக்கும் என்பதற்கான மிக வலுவான, நேர்மையான வாதத்தை முன்வையுங்கள்.', 'D'),
  (2, 'You focus on the relationship and the conversation first - you want her to feel genuinely heard and valued before you talk about any concrete offer.', 'நீங்கள் முதலில் உறவிலும் உரையாடலிலும் கவனம் செலுத்துங்கள் - எந்தவொரு உறுதியான சலுகையைப் பற்றியும் பேசுவதற்கு முன்பு, அவள் தன் குரல் உண்மையாகவே கேட்கப்படுவதாகவும் மதிக்கப்படுவதாகவும் உணர வேண்டும் என நீங்கள் விரும்புவீர்கள்.', 'I'),
  (3, 'You tell her you will go to bat for her and immediately begin working the system - talking to your manager, to HR, finding what flexibility exists.', 'அவருக்காக நீங்கள் பரிந்து பேசுவீர்கள் என்று அவரிடம் கூறிவிட்டு, உடனடியாக உங்கள் மேலாளரிடமும், மனிதவளத் துறையிடமும் பேசி, என்னென்ன நெகிழ்வுத்தன்மைகள் உள்ளன என்பதைக் கண்டறிந்து, அந்த நடைமுறையைச் செயல்படுத்தத் தொடங்குங்கள்.', 'S'),
  (4, 'You ask her exactly what she is evaluating - compensation, role, growth, culture - and use her answer to have the most targeted conversation you can.', 'அவர் ஊதியம், பதவி, வளர்ச்சி, நிறுவனத்தின் கலாச்சாரம் என எவற்றையெல்லாம் மதிப்பிடுகிறார் என்று அவரிடம் துல்லியமாகக் கேட்டு, அவரது பதிலைப் பயன்படுத்தி உங்களால் முடிந்தவரை மிகவும் இலக்கு சார்ந்த உரையாடலை மேற்கொள்ளுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q34',
     'A team member discloses a serious personal crisis to you in a one-on-one. He is clearly struggling and has asked you to keep it confidential. You are his manager. His performance has been affected. You know HR should probably be involved. He has asked you not to tell anyone.', 'How will you handle this?', 'உங்கள் குழு உறுப்பினர் ஒருவர், தனக்கு ஏற்பட்ட ஒரு கடுமையான தனிப்பட்ட நெருக்கடியை உங்களிடம் தனிப்பட்ட முறையில் வெளிப்படுத்துகிறார். அவர் மிகவும் சிரமப்படுகிறார் என்பது தெளிவாகத் தெரிகிறது, மேலும் அதை இரகசியமாக வைக்குமாறு உங்களிடம் கேட்டுக்கொண்டுள்ளார். நீங்கள் அவருடைய மேலாளர். இதனால் அவருடைய செயல்திறன் பாதிக்கப்பட்டுள்ளது. மனிதவளத் துறை இதில் தலையிட வேண்டும் என்பது உங்களுக்குத் தெரியும். யாரிடமும் சொல்ல வேண்டாம் என்று அவர் உங்களிடம் கேட்டுக்கொண்டுள்ளார்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell him clearly that you care about him and want to support him, and you are also honest that as his manager there are limits to confidentiality you need to name.', 'நீங்கள் அவர் மீது அக்கறை கொண்டுள்ளீர்கள் என்றும் அவருக்கு ஆதரவளிக்க விரும்புகிறீர்கள் என்றும் அவரிடம் தெளிவாகக் கூறுங்கள்; மேலும், அவருடைய மேலாளர் என்ற முறையில், இரகசியத்தைக் காப்பதில் சில வரம்புகள் உள்ளன என்பதையும் நீங்கள் வெளிப்படையாகக் குறிப்பிட வேண்டும்.', 'D'),
  (2, 'You focus entirely on the human moment first - you let him speak, you do not make any commitments or threats, and you find the right way to handle the process question later.', 'நீங்கள் முதலில் அந்த மனிதத் தருணத்தில் முழுமையாகக் கவனம் செலுத்துகிறீர்கள் - அவரைப் பேச விடுகிறீர்கள், எந்த வாக்குறுதிகளையோ அச்சுறுத்தல்களையோ அளிப்பதில்லை, மேலும் செயல்முறை தொடர்பான கேள்வியைக் கையாள்வதற்கான சரியான வழியைப் பின்னர் கண்டறிகிறீர்கள்.', 'I'),
  (3, 'You honour his request for now, give him time, and create a plan with him for how he wants to manage the work impact before you decide what else needs to happen.', 'தற்போதைக்கு நீங்கள் அவரது கோரிக்கையை ஏற்றுக்கொண்டு, அவருக்கு அவகாசம் அளித்து, வேறு என்ன செய்ய வேண்டும் என்று தீர்மானிப்பதற்கு முன், பணியின் தாக்கத்தை அவர் எவ்வாறு கையாள விரும்புகிறார் என்பது குறித்து அவருடன் இணைந்து ஒரு திட்டத்தை உருவாக்குங்கள்.', 'S'),
  (4, 'You explain the confidentiality boundaries, document the conversation for your own records, and ask HR how to proceed without disclosing his name initially.', 'நீங்கள் இரகசியத்தன்மை வரம்புகளை விளக்கி, உங்கள் சொந்தப் பதிவுகளுக்காக அந்த உரையாடலை ஆவணப்படுத்தி, ஆரம்பத்தில் அவரது பெயரை வெளியிடாமல் எவ்வாறு தொடர்வது என்று மனிதவளத் துறையிடம் கேட்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q35',
     'What matters more to you in this moment? You have a team member who delivers strong results consistently but is quietly damaging team cohesion. He dominates meetings, dismisses peers'' ideas, and has started influencing the team''s newer members in ways that concern you. One pull is to protect the results - he is delivering what the team needs and removing that pressure creates risk. The other pull is to address the behaviour - the long-term damage to cohesion is real and getting worse.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? உங்கள் குழுவில் ஒருவர் தொடர்ந்து சிறப்பான முடிவுகளைத் தந்தாலும், அவர் அமைதியாகக் குழுவின் ஒற்றுமையைச் சேதப்படுத்துகிறார். அவர் கூட்டங்களில் ஆதிக்கம் செலுத்துகிறார், சக ஊழியர்களின் யோசனைகளை நிராகரிக்கிறார், மேலும் உங்களுக்குக் கவலையளிக்கும் விதங்களில் குழுவின் புதிய உறுப்பினர்களைப் பாதிக்கத் தொடங்கியுள்ளார். ஒரு காரணம், முடிவுகளைப் பாதுகாப்பதாகும் - அவர் குழுவிற்குத் தேவையானதைச் செய்கிறார், மேலும் அந்த அழுத்தத்தை நீக்குவது ஆபத்தை உருவாக்கும். மற்றொரு காரணம், அவரது நடத்தையைக் கையாள்வதாகும் - ஒற்றுமைக்கு ஏற்படும் நீண்டகால பாதிப்பு உண்மையானது மற்றும் மோசமடைந்து வருகிறது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Addressing the behaviour matters more. You have the conversation regardless of the output risk, because the cultural damage is already costing you.', 'அந்த நடத்தையைக் கையாள்வதுதான் மிகவும் முக்கியம். அதனால் ஏற்படக்கூடிய விளைவுகளைப் பொருட்படுத்தாமல் நீங்கள் அந்த உரையாடலைத் தொடர வேண்டும், ஏனெனில் கலாச்சார ரீதியான பாதிப்பு ஏற்கெனவே உங்களுக்கு இழப்பை ஏற்படுத்திக் கொண்டிருக்கிறது.', 'D'),
  (2, 'The relationship and the conversation matter most. You approach it as a coaching conversation, not a warning, and invest in helping him see the impact.', 'உறவும் உரையாடலும்தான் மிகவும் முக்கியமானவை. நீங்கள் அதை ஒரு எச்சரிக்கையாகக் கருதாமல், ஒரு வழிகாட்டுதல் உரையாடலாக அணுகி, அதன் தாக்கத்தை அவர் உணர்ந்துகொள்ள உதவுவதில் கவனம் செலுத்துங்கள்.', 'I'),
  (3, 'The team''s stability matters more right now. You manage the behaviour quietly, address the most visible incidents, and buy time before a bigger conversation.', 'தற்போது அணியின் ஸ்திரத்தன்மைதான் மிகவும் முக்கியம். நீங்கள் அவர்களின் நடத்தையை அமைதியாகக் கையாண்டு, வெளிப்படையாகத் தெரியும் சம்பவங்களைக் கவனித்து, ஒரு பெரிய உரையாடலுக்கு முன் அவகாசம் வாங்கிக்கொள்ளுங்கள்.', 'S'),
  (4, 'The evidence matters most. You document specific incidents before you say anything, so the conversation is grounded and cannot be dismissed as subjective.', 'ஆதாரமே மிகவும் முக்கியம். நீங்கள் எதையும் சொல்வதற்கு முன் குறிப்பிட்ட சம்பவங்களை ஆவணப்படுத்துகிறீர்கள், அதனால் அந்த உரையாடல் ஆதாரப்பூர்வமாக இருக்கும், அதை அகநிலை சார்ந்தது என்று புறக்கணிக்க முடியாது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q36',
     'The honest feeling underneath this - when the new joiner hired above the team''s level is being quietly excluded by the rest of the group - is something most managers do not name out loud. You see it happening. You understand why the team is doing it. And there is a part of you, if you are being honest, that is not entirely unsympathetic to their frustration.', 'How to handle team exclusion?', 'இதற்கு அடியில் இருக்கும் உண்மையான உணர்வை - அதாவது, அணியின் தகுதிக்கு அப்பாற்பட்டு புதிதாகப் பணியமர்த்தப்பட்ட ஒருவர், மற்ற குழுவினரால் அமைதியாகப் புறக்கணிக்கப்படும்போது - பெரும்பாலான மேலாளர்கள் வெளிப்படையாகக் குறிப்பிடுவதில்லை. அது நடப்பதை நீங்கள் பார்க்கிறீர்கள். அணி ஏன் அப்படிச் செய்கிறது என்பதை நீங்கள் புரிந்துகொள்கிறீர்கள். மேலும், நீங்கள் நேர்மையாக இருந்தால், அவர்களின் விரக்தியின் மீது முற்றிலும் அனுதாபம் கொள்ளாத ஒரு பகுதியும் உங்களுக்குள் இருக்கிறது.', 'அணியிலிருந்து நீக்கப்படுவதை எவ்வாறு கையாள்வது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name the feeling to yourself, separate it from your role, and take clear action to integrate the new joiner regardless of what you privately understand about the team''s frustration.', 'அந்த உணர்வை நீங்களே உள்வாங்கிக்கொண்டு, அதை உங்கள் பங்கிலிருந்து பிரித்து, குழுவின் விரக்தியைப் பற்றி நீங்கள் தனிப்பட்ட முறையில் என்ன புரிந்துகொண்டாலும், புதிதாகச் சேர்பவரை ஒருங்கிணைக்கத் தெளிவான நடவடிக்கை எடுங்கள்.', 'D'),
  (2, 'You feel the relational complexity clearly - the new joiner needs your support and the team needs to feel heard - and you are trying to hold both at once.', 'உறவுகளில் உள்ள சிக்கலான தன்மையை நீங்கள் தெளிவாக உணர்கிறீர்கள் - புதிதாகச் சேர்ந்தவருக்கு உங்கள் ஆதரவும், குழுவினர் தங்கள் குரல் கேட்கப்படுகிறது என்ற உணர்வையும் பெற வேண்டும் - ஆனால் நீங்கள் இரண்டையும் ஒரே நேரத்தில் கையாள முயற்சிக்கிறீர்கள்.', 'I'),
  (3, 'You feel the pull to let it play out for a little longer, to see whether the team comes around on their own, because intervening too early might make it worse.', 'அணி தானாகவே இயல்பு நிலைக்குத் திரும்புகிறதா என்று பார்ப்பதற்காக, இன்னும் சிறிது காலம் அதை அப்படியே விட்டுவிட வேண்டும் என்ற ஒரு உந்துதல் ஏற்படுகிறது; ஏனெனில், மிக விரைவில் தலையிடுவது நிலைமையை இன்னும் மோசமாக்கிவிடக்கூடும்.', 'S'),
  (4, 'You feel most uncomfortable with the fact that you do not have enough information about why the exclusion is happening - whether it is about the hire level, the person, or something else - and you want to understand it fully before you act.', 'இந்த விலக்கல் ஏன் நிகழ்கிறது என்பது பற்றி - அது பணியமர்த்தல் நிலை, அந்த நபர் அல்லது வேறு ஏதேனும் காரணத்தினாலா என்பது பற்றி - உங்களிடம் போதுமான தகவல்கள் இல்லாததுதான் உங்களுக்கு மிகுந்த சங்கடத்தை ஏற்படுத்துகிறது; மேலும், நீங்கள் நடவடிக்கை எடுப்பதற்கு முன்பு அதை முழுமையாகப் புரிந்துகொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q37',
     'You have been covering two roles for five months. No additional support has materialised. The recognition has been informal at best. Your output is holding but your energy is not. You have a one-on-one with your manager this week.', 'How will you handle this?', 'நீங்கள் ஐந்து மாதங்களாக இரண்டு பொறுப்புகளைக் கையாண்டு வருகிறீர்கள். கூடுதல் ஆதரவு எதுவும் கிடைக்கவில்லை. கிடைத்த அங்கீகாரம் அதிகபட்சம் முறைசாராததாகவே இருந்துள்ளது. உங்கள் செயல்திறன் சீராக உள்ளது, ஆனால் உங்கள் ஆற்றல் குறையவில்லை. இந்த வாரம் உங்கள் மேலாளருடன் உங்களுக்குத் தனிப்பட்ட சந்திப்பு உள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name it directly: you have been covering two roles for five months and you need either support, a title change, or a clear timeline. You make the ask explicit.', 'நீங்கள் அதை நேரடியாகக் குறிப்பிடுகிறீர்கள்: ஐந்து மாதங்களாக நீங்கள் இரண்டு பொறுப்புகளைக் கவனித்து வருகிறீர்கள், உங்களுக்கு ஆதரவோ, பதவி மாற்றமோ, அல்லது ஒரு தெளிவான காலக்கெடுவோ தேவைப்படுகிறது. உங்கள் கோரிக்கையைத் தெளிவாக முன்வைக்கிறீர்கள்.', 'D'),
  (2, 'You approach it relationally - you want your manager to understand the full human impact before you make any specific request.', 'நீங்கள் இதை ஒரு உறவுமுறை கண்ணோட்டத்தில் அணுகுகிறீர்கள் - அதாவது, நீங்கள் ஏதேனும் ஒரு குறிப்பிட்ட கோரிக்கையை வைப்பதற்கு முன்பு, அதன் முழுமையான மனிதத் தாக்கத்தை உங்கள் மேலாளர் புரிந்துகொள்ள வேண்டும் என விரும்புகிறீர்கள்.', 'I'),
  (3, 'You raise the sustainability concern without putting your manager in a corner - you want a conversation, not a confrontation, and you focus on what you need going forward.', 'உங்கள் மேலாளரைச் சங்கடப்படுத்தாமல், நிலைத்தன்மை குறித்த கவலையை நீங்கள் எழுப்புகிறீர்கள் - நீங்கள் ஒரு மோதலை அல்ல, உரையாடலையே விரும்புகிறீர்கள், மேலும் எதிர்காலத்தில் உங்களுக்குத் தேவையானவற்றில் கவனம் செலுத்துகிறீர்கள்.', 'S'),
  (4, 'You bring documentation: a breakdown of what the two roles require, what you have delivered across both, and what a reasonable support structure would look like.', 'நீங்கள் ஆவணங்களைக் கொண்டு வாருங்கள்: அந்த இரண்டு பணிகளுக்கும் என்னென்ன தேவைப்படுகின்றன என்பதன் விவரம், இரண்டிலும் நீங்கள் என்ன வழங்கியுள்ளீர்கள், மற்றும் ஒரு பொருத்தமான ஆதரவுக் கட்டமைப்பு எப்படி இருக்கும் என்பது ஆகியவை அதில் அடங்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q38',
     'You have noticed that you have become the manager who always says yes. Your team has started to expect it. Senior stakeholders have started to rely on it. You are not sure when it became your identity, but you are aware that it is no longer serving you and it may not be serving your team.', 'How will you change this?', 'நீங்கள் எப்போதும் ''ஆம்'' என்று சொல்லும் மேலாளராக மாறிவிட்டதை கவனித்திருக்கிறீர்கள். உங்கள் குழுவினர் அதை எதிர்பார்க்கத் தொடங்கியுள்ளனர். முக்கியப் பங்குதாரர்கள் அதைச் சார்ந்திருக்கத் தொடங்கியுள்ளனர். அது எப்போது உங்கள் அடையாளமாக மாறியது என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை, ஆனால் அது இனி உங்களுக்குப் பயனளிக்கவில்லை என்பதையும், உங்கள் குழுவினருக்கும் பயனளிக்காமல் இருக்கலாம் என்பதையும் நீங்கள் உணர்ந்திருக்கிறீர்கள்.', 'நீங்கள் இதை எப்படி மாற்றுவீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You start saying no to something specific this week - one ask, clearly declined, with a reason - and you use it as the first step in resetting the pattern.', 'இந்த வாரம் நீங்கள் ஒரு குறிப்பிட்ட விஷயத்திற்கு ''இல்லை'' என்று சொல்லத் தொடங்குகிறீர்கள் - ஒரு கோரிக்கையை, காரணத்துடன் தெளிவாக மறுத்துவிடுகிறீர்கள் - மேலும் அந்தப் போக்கை மாற்றுவதற்கான முதல் படியாக அதைப் பயன்படுத்துகிறீர்கள்.', 'D'),
  (2, 'You talk to someone you trust first - a peer, a mentor, someone outside your direct chain - before you change any behaviour, because you want to make sure you understand what is driving it.', 'எந்தவொரு நடத்தையையும் மாற்றுவதற்கு முன், அதற்குப் பின்னால் உள்ள காரணத்தை நீங்கள் முழுமையாகப் புரிந்துகொண்டீர்கள் என்பதை உறுதிப்படுத்திக்கொள்ள, முதலில் நீங்கள் நம்பும் ஒருவரிடம் - உங்கள் சக ஊழியர், வழிகாட்டி, அல்லது உங்கள் நேரடித் தொடர்பு வட்டத்திற்கு வெளியே உள்ள ஒருவரிடம் - பேச வேண்டும்.', 'I'),
  (3, 'You ease into it - you do not want to overcorrect or create confusion, so you start by delaying responses instead of declining, creating space to choose more carefully.', 'நீங்கள் மெதுவாகச் செயல்பட வேண்டும் - அளவுக்கு அதிகமாகத் திருத்தவோ அல்லது குழப்பத்தை ஏற்படுத்தவோ நீங்கள் விரும்ப மாட்டீர்கள், எனவே, மறுப்பதற்குப் பதிலாகப் பதில்களைத் தாமதப்படுத்துவதன் மூலம் தொடங்குகிறீர்கள், இது மிகவும் கவனமாகத் தேர்வுசெய்ய இடமளிக்கிறது.', 'S'),
  (4, 'You map out where the yes pattern is costing you most - which relationships, which requests, which recurring demands - before you make any changes.', 'எந்த மாற்றங்களையும் செய்வதற்கு முன், ''ஆம்'' என்ற இந்த அணுகுமுறை உங்களுக்கு எங்கே அதிக இழப்பை ஏற்படுத்துகிறது என்பதை - அதாவது எந்த உறவுகள், எந்தக் கோரிக்கைகள், எந்தத் தொடர்ச்சியான தேவைகள் - நீங்கள் வரைபடமாக்கிக் கொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q39',
     'Two things are pulling at you. Which is stronger? A project failure that was not entirely your fault has been attributed to you. It is affecting how people above you see you. One pull is to correct the record - explain the context, name what was outside your control, make sure the real picture is understood. The other pull is to own it fully - take the hit, show how you are responding, and rebuild credibility through what you do next.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை இழுக்கின்றன. அவற்றில் எது வலிமையானது? முற்றிலும் உங்கள் தவறில்லாத ஒரு திட்டத் தோல்வி, உங்கள் மீது சுமத்தப்பட்டுள்ளது. அது உங்களுக்கு மேலுள்ளவர்கள் உங்களைப் பார்க்கும் விதத்தைப் பாதிக்கிறது. ஒரு இழுத்தல், நடந்ததைச் சரிசெய்வது - சூழலை விளக்குவது, உங்கள் கட்டுப்பாட்டிற்கு அப்பாற்பட்டது எது என்பதைக் குறிப்பிடுவது, உண்மையான நிலவரம் புரிந்துகொள்ளப்படுவதை உறுதி செய்வது. மற்றொரு இழுத்தல், அதை முழுமையாக ஏற்றுக்கொள்வது - பாதிப்பை ஏற்றுக்கொள்வது, நீங்கள் எவ்வாறு பதிலளிக்கிறீர்கள் என்பதைக் காட்டுவது, மேலும் அடுத்து நீங்கள் செய்வதன் மூலம் நம்பகத்தன்மையை மீண்டும் கட்டியெழுப்புவது.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to correct the record is stronger. You are not willing to carry full accountability for something that was shared, and you find a professional way to say so.', 'பதிவைத் திருத்த வேண்டும் என்ற அழுத்தம் வலுவாக உள்ளது. பகிரப்பட்ட ஒரு விஷயத்திற்கு முழுப் பொறுப்பையும் ஏற்க நீங்கள் தயாராக இல்லை, மேலும் அதை வெளிப்படுத்த ஒரு தொழில்முறை வழியைக் கண்டறிகிறீர்கள்.', 'D'),
  (2, 'The relational pull is stronger. You focus on the people above you and what they need to see - clear ownership, a recovery plan, no defensiveness.', 'உறவுகளின் ஈர்ப்பு வலுவாக இருக்கிறது. உங்களுக்கு மேலுள்ளவர்கள் மீதும், அவர்கள் காண விரும்பும் தெளிவான பொறுப்புணர்வு, மீட்புத் திட்டம், தற்காப்பு மனப்பான்மையின்மை போன்றவற்றின் மீதும் நீங்கள் கவனம் செலுத்துகிறீர்கள்.', 'I'),
  (3, 'The pull to own it is stronger. You absorb the attribution, focus on what you are doing about it, and trust that your response will speak louder than any correction.', 'அதை ஏற்றுக்கொள்வதற்கான உந்துதல் வலுவாக இருக்கிறது. நீங்கள் அந்தப் பழியை உள்வாங்கிக்கொண்டு, அதைப் பற்றி நீங்கள் என்ன செய்கிறீர்கள் என்பதில் கவனம் செலுத்தி, எந்தவொரு திருத்தத்தையும் விட உங்கள் பதில் உரக்கப் பேசும் என்று நம்புகிறீர்கள்.', 'S'),
  (4, 'The pull to understand it fully first is stronger. You want to know exactly how the attribution happened and through whose account before you respond to anything.', 'முதலில் அதை முழுமையாகப் புரிந்துகொள்ள வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. எதற்கும் பதிலளிக்கும் முன், அந்தப் பெயர் எப்படி, யாருடைய கணக்கின் மூலம் குறிப்பிடப்பட்டது என்பதை நீங்கள் துல்லியமாகத் தெரிந்துகொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 1 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S1-Q40',
     'Before you answer anyone''s question about how you are doing - before you give the professional version - what is actually happening inside you when you realise you no longer feel energised by your work and you do not know whether that is the role, the organisation, or something in you?', 'Why feel unenergized by work?', 'நீங்கள் எப்படி இருக்கிறீர்கள் என்று யாராவது கேட்கும் கேள்விக்கு பதிலளிப்பதற்கு முன் - அதாவது, உங்கள் தொழில்முறை விளக்கத்தைக் கொடுப்பதற்கு முன் - உங்கள் வேலையில் உங்களுக்கு இனி ஆற்றல் இல்லை என்பதை நீங்கள் உணரும்போதும், அது உங்கள் பதவியின் தவறா, நிறுவனத்தின் தவறா, அல்லது உங்களுக்குள் இருக்கும் ஏதோ ஒன்றின் தவறா என்று உங்களுக்குத் தெரியாதபோதும், உண்மையில் உங்களுக்குள் என்னதான் நடக்கிறது?', 'வேலையில் ஏன் உற்சாகம் இல்லாமல் உணர வேண்டும்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is clarity underneath the discomfort - you know something needs to change and the not-knowing-what is just the next problem to solve.', 'அந்த அசௌகரியத்திற்கு அடியில் ஒரு தெளிவு இருக்கிறது - ஏதோ ஒன்று மாற வேண்டும் என்பதும், அது என்னவென்று தெரியாத நிலைதான் தீர்க்கப்பட வேண்டிய அடுத்த பிரச்சனை என்பதும் உங்களுக்குத் தெரியும்.', 'D'),
  (2, 'There is a quiet sadness that you have not quite named yet - not burnout exactly, but a loss of something you used to feel when you walked in, and you are not sure what to do with that.', 'நீங்கள் இன்னும் சரியாகப் பெயரிடாத ஒரு அமைதியான சோகம் இருக்கிறது - அது சரியாகச் சொல்வதானால், மன அழுத்தம் அல்ல; மாறாக, நீங்கள் உள்ளே நுழையும்போது முன்பு உணர்ந்த ஒன்றை இழந்தது போன்ற ஓர் உணர்வு, அதை வைத்து என்ன செய்வதென்றும் உங்களுக்குத் தெரியவில்லை.', 'I'),
  (3, 'There is a strong desire to restore the equilibrium - to find the thing that will make it feel right again - because the alternative, that it may be something deeper, is not something you are ready to sit with.', 'சமநிலையை மீட்டெடுக்க வேண்டும் என்ற, அதாவது எல்லாவற்றையும் மீண்டும் சரியாக்கும் ஒன்றைக் கண்டறிய வேண்டும் என்ற ஒரு தீவிரமான விருப்பம் இருக்கிறது. ஏனென்றால், அதற்கு மாற்றாக இருக்கக்கூடிய, ஒருவேளை இன்னும் ஆழமான ஒன்றாக இருக்கக்கூடிய விஷயத்தை நீங்கள் ஆழ்ந்து சிந்திக்கத் தயாராக இல்லை.', 'S'),
  (4, 'There is a need to diagnose it properly before you act on it - to separate the situational from the structural from the personal - because making a move based on a feeling rather than an analysis does not feel like the right way to make a decision this significant.', 'அதன் மீது நடவடிக்கை எடுப்பதற்கு முன், அதைச் சரியாகக் கண்டறிய வேண்டிய அவசியம் உள்ளது - சூழ்நிலை சார்ந்தவை, கட்டமைப்பு சார்ந்தவை மற்றும் தனிப்பட்டவை ஆகியவற்றைப் பிரித்துப் பார்க்க வேண்டும் - ஏனெனில், பகுப்பாய்வின் அடிப்படையில் அல்லாமல் ஒரு உணர்வின் அடிப்படையில் ஒரு முடிவை எடுப்பது, இவ்வளவு முக்கியமான ஒரு முடிவை எடுப்பதற்கான சரியான வழியாகத் தோன்றவில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q1',
     'Your manager has committed your team to a cross-functional initiative without consulting you. You found out through the initiative''s project lead, not through her. The commitment requires two of your best people to split their time for the next six weeks - a period when your team is already stretched on a delivery your VP is tracking. Your manager is travelling and unreachable until tomorrow.', 'How will you handle this?', 'உங்கள் மேலாளர் உங்களிடம் கலந்தாலோசிக்காமல், உங்கள் குழுவை ஒரு பல்துறை முன்னெடுப்பில் ஈடுபடுத்தியுள்ளார். இந்த விஷயத்தை நீங்கள் அவரிடமிருந்து அல்ல, அந்த முன்னெடுப்பின் திட்டத் தலைவர் மூலமாகவே தெரிந்துகொண்டீர்கள். இந்த ஈடுபாட்டின் காரணமாக, உங்கள் குழுவின் சிறந்த ஊழியர்களில் இருவர் அடுத்த ஆறு வாரங்களுக்குத் தங்கள் நேரத்தைப் பிரித்துச் செலவிட வேண்டியுள்ளது. இந்தக் காலகட்டத்தில்தான், உங்கள் துணைத் தலைவர் கண்காணித்து வரும் ஒரு திட்டப்பணியை முடிப்பதில் உங்கள் குழு ஏற்கெனவே அதிகப் பணிச்சுமையுடன் இருக்கிறது. உங்கள் மேலாளர் பயணம் மேற்கொண்டுள்ளதால், நாளை வரை அவரைத் தொடர்புகொள்ள இயலாது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You send her a message today flagging the capacity conflict clearly and telling her you need a conversation before you confirm anything to the project lead.', 'திறன் முரண்பாட்டைத் தெளிவாகச் சுட்டிக்காட்டி, திட்டத் தலைவரிடம் எதையும் உறுதி செய்வதற்கு முன்பு அவருடன் உரையாட வேண்டும் என்று கூறி, இன்று அவருக்கு ஒரு செய்தியை அனுப்புங்கள்.', 'D'),
  (2, 'You reach out to the project lead, acknowledge the commitment, and ask for twenty-four hours before confirming names - you want to speak to your manager first.', 'நீங்கள் திட்டத் தலைவரைத் தொடர்புகொண்டு, அவரது அர்ப்பணிப்பை ஏற்றுக்கொண்டு, பெயர்களை உறுதி செய்வதற்கு முன் இருபத்தி நான்கு மணிநேரம் அவகாசம் கேட்கிறீர்கள் - நீங்கள் முதலில் உங்கள் மேலாளரிடம் பேச வேண்டும்.', 'I'),
  (3, 'You absorb it, begin working out which two people can be spared with the least damage, and brief your manager when she is back rather than creating noise while she is travelling.', 'நீங்கள் அதை உள்வாங்கிக்கொண்டு, குறைந்தபட்ச சேதத்துடன் எந்த இருவரைக் காப்பாற்றலாம் என்று கணக்கிடத் தொடங்குங்கள், மேலும் உங்கள் மேலாளர் பயணம் செய்யும்போது சத்தம் போடுவதற்குப் பதிலாக, அவர் திரும்பி வந்ததும் அவருக்குத் தகவல் தெரிவியுங்கள்.', 'S'),
  (4, 'You document your current team capacity, the delivery timeline your VP is tracking, and the specific impact of splitting two people before you respond to anyone.', 'யாருக்கும் பதிலளிப்பதற்கு முன், உங்கள் தற்போதைய குழுவின் திறன், உங்கள் துணைத் தலைவர் கண்காணிக்கும் பணி நிறைவு காலக்கெடு, மற்றும் இருவரைப் பிரிப்பதால் ஏற்படும் குறிப்பிட்ட தாக்கம் ஆகியவற்றை நீங்கள் ஆவணப்படுத்த வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q2',
     'Your manager has started copying herself into your email communications with senior stakeholders - without explaining why and without asking you. The stakeholders have noticed. One of them mentioned it to you with a raised eyebrow. You have not raised it with your manager yet. It has happened six times in the past month.', 'How will you handle this?', 'உங்கள் மேலாளர், ஏன் என்று விளக்காமலும் உங்களிடம் கேட்காமலும், மூத்த அதிகாரிகளுடனான உங்கள் மின்னஞ்சல் பரிமாற்றங்களில் தன்னையே இணைத்துக்கொள்ளத் தொடங்கியுள்ளார். அந்த அதிகாரிகள் இதைக் கவனித்துவிட்டனர். அவர்களில் ஒருவர் புருவத்தை உயர்த்தி உங்களிடம் இதைக் குறிப்பிட்டார். நீங்கள் இன்னும் உங்கள் மேலாளரிடம் இதைப் பற்றிக் கூறவில்லை. கடந்த ஒரு மாதத்தில் இது ஆறு முறை நிகழ்ந்துள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You bring it up directly in your next one-on-one - you name the pattern, ask what is driving it, and make clear you need to understand the reason before it continues.', 'உங்கள் அடுத்த தனிப்பட்ட சந்திப்பில் இதை நேரடியாகக் குறிப்பிடுங்கள் - அந்தப் போக்கின் பெயரைச் சொல்லி, அதற்கு என்ன காரணம் என்று கேட்டு, அது தொடர்வதற்கு முன் அதற்கான காரணத்தை நீங்கள் புரிந்துகொள்ள வேண்டும் என்பதைத் தெளிவுபடுத்துங்கள்.', 'D'),
  (2, 'You raise it carefully, framing it as a question about how she wants the two of you to manage upward communications together going forward.', 'இனிமேல் நீங்கள் இருவரும் இணைந்து மேலதிகாரிகளுடனான தகவல்தொடர்புகளை எவ்வாறு கையாள வேண்டும் என்று அவள் விரும்புகிறாள் என்பது பற்றிய ஒரு கேள்வியாக அதை வடிவமைத்து, நீங்கள் கவனமாக எழுப்புகிறீர்கள்.', 'I'),
  (3, 'You let it continue for now, pay close attention to whether there is a pattern in which emails she copies herself on, and form a view before you say anything.', 'இப்போதைக்கு இதைத் தொடர விடுங்கள்; அவள் தன்னைத்தானே நகல் எடுத்துக்கொள்ளும் மின்னஞ்சல்களில் ஏதேனும் ஒரு முறைமை உள்ளதா என்பதை உன்னிப்பாகக் கவனித்து, எதையும் சொல்வதற்கு முன் ஒரு முடிவுக்கு வாருங்கள்.', 'S'),
  (4, 'You prepare a brief summary of the communications she has inserted herself into, the stakeholders involved, and the potential perception impact before you have the conversation.', 'உரையாடலைத் தொடங்குவதற்கு முன், அவர் ஈடுபட்டிருக்கும் தகவல்தொடர்புகள், சம்பந்தப்பட்ட தரப்பினர் மற்றும் அதனால் ஏற்படக்கூடிய கருத்துத் தாக்கம் ஆகியவை குறித்த ஒரு சுருக்கத்தை நீங்கள் தயார் செய்யுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q3',
     'What matters more to you in this moment? Your manager has told you, privately and firmly, that you are not ready for the next level. You believe she is wrong. You have watched two peers get promoted with comparable track records and less tenure. One pull is to accept her assessment, work to the criteria she has named, and prove it over the next cycle. The other pull is to push back - to respectfully but clearly challenge her view and ask for evidence that distinguishes you from the peers who were promoted.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? நீங்கள் அடுத்த கட்டத்திற்குத் தயாராக இல்லை என்று உங்கள் மேலாளர் உங்களிடம் தனிப்பட்ட முறையிலும் உறுதியாகவும் கூறியுள்ளார். அவர் சொல்வது தவறு என்று நீங்கள் நம்புகிறீர்கள். உங்களைப் போன்றே ஒத்த பணி அனுபவமும், குறைந்த பணி அனுபவமும் கொண்ட உங்கள் சக ஊழியர்கள் இருவர் பதவி உயர்வு பெற்றதை நீங்கள் பார்த்திருக்கிறீர்கள். ஒரு உந்துதல் என்னவென்றால், அவரது மதிப்பீட்டை ஏற்றுக்கொண்டு, அவர் குறிப்பிட்ட அளவுகோல்களின்படி செயல்பட்டு, அடுத்த சுழற்சியில் அதை நிரூபிப்பது. மற்றொரு உந்துதல் என்னவென்றால், அவரை எதிர்த்துப் பேசுவது - அதாவது, மரியாதையுடனும் ஆனால் தெளிவாகவும் அவரது கருத்தை எதிர்த்து, பதவி உயர்வு பெற்ற சக ஊழியர்களிடமிருந்து உங்களை வேறுபடுத்திக் காட்டும் ஆதாரங்களைக் கேட்பது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Pushing back matters more. You ask for a specific, evidence-based conversation about what differentiates you from the peers who were promoted and what the actual bar looks like.', 'எதிர்த்துப் பேசுவதுதான் மிகவும் முக்கியம். பதவி உயர்வு பெற்ற சக போட்டியாளர்களிடமிருந்து உங்களை வேறுபடுத்திக் காட்டுவது எது என்பது பற்றியும், உண்மையான தகுதி வரம்பு எப்படி இருக்கிறது என்பது பற்றியும், குறிப்பிட்ட, ஆதார அடிப்படையிலான ஒரு உரையாடலுக்கு நீங்கள் கோர வேண்டும்.', 'D'),
  (2, 'The relationship matters more right now. You accept her feedback graciously, ask for a development plan, and use the next cycle to demonstrate that her assessment was premature.', 'தற்போது உறவுதான் மிகவும் முக்கியம். நீங்கள் அவரது கருத்தை கனிவுடன் ஏற்றுக்கொண்டு, ஒரு மேம்பாட்டுத் திட்டத்தைக் கேட்டு, அவரது மதிப்பீடு அவசரமானது என்பதை நிரூபிக்க அடுத்த சுழற்சியைப் பயன்படுத்திக்கொள்ளுங்கள்.', 'I'),
  (3, 'Your own clarity matters most. You take the feedback away, reflect on it honestly, and decide for yourself whether she is right before you decide how to respond.', 'உங்கள் சொந்தத் தெளிவுதான் மிகவும் முக்கியம். அந்தப் பின்னூட்டத்தை உள்வாங்கிக்கொண்டு, அதைப்பற்றி நேர்மையாகச் சிந்தித்து, எப்படிப் பதிலளிப்பது என்று முடிவெடுப்பதற்கு முன், அவர் சொல்வது சரியா என்பதை நீங்களே முடிவு செய்யுங்கள்.', 'S'),
  (4, 'The data matters most. You build a structured comparison of your outputs, scope, and impact against the peers who were promoted and bring it to a follow-up conversation as the basis for a different conclusion.', 'தரவுகளே மிகவும் முக்கியமானவை. பதவி உயர்வு பெற்ற சக ஊழியர்களுடன் உங்கள் வெளியீடுகள், செயல் எல்லை மற்றும் தாக்கம் ஆகியவற்றை ஒரு கட்டமைக்கப்பட்ட ஒப்பீட்டிற்கு உட்படுத்தி, அதை ஒரு மாற்று முடிவிற்கான அடிப்படையாகப் பின்தொடர் உரையாடலுக்குக் கொண்டு செல்லுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q4',
     'Before you say anything in the debrief your manager has called after the senior stakeholder presentation - the one where you went off script and answered a question honestly that she had briefed you to deflect - what is actually sitting with you right now?', 'How are you feeling now?', 'மூத்த பங்குதாரர் விளக்கக்காட்சிக்குப் பிறகு உங்கள் மேலாளர் அழைத்த கலந்துரையாடல் கூட்டத்தில் நீங்கள் எதையும் சொல்வதற்கு முன் - அந்த விளக்கக்காட்சியில், அவர் தவிர்க்கச் சொல்லி உங்களுக்கு அறிவுறுத்திய ஒரு கேள்விக்கு நீங்கள் திட்டமிடப்படாத பதிலைக் கூறி, நேர்மையாகப் பதிலளித்தீர்கள் - இப்போது உண்மையில் உங்கள் மனதில் என்ன ஓடிக்கொண்டிருக்கிறது?', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A clear conviction. You said what was true and you would say it again. The discomfort belongs to the situation, not the decision.', 'தெளிவான உறுதிப்பாடு. நீங்கள் உண்மையையே சொன்னீர்கள், அதையே மீண்டும் சொல்வீர்கள். சங்கடம் என்பது சூழ்நிலையால் ஏற்பட்டது, முடிவால் அல்ல.', 'D'),
  (2, 'A complicated mix. You know you were right, but the look on her face in that room is still sitting with you, and the cost to that relationship is more real to you than you expected it to be.', 'இது ஒரு சிக்கலான கலவை. நீங்கள் செய்தது சரிதான் என்று உங்களுக்குத் தெரியும், ஆனால் அந்த அறையில் அவள் முகபாவம் இன்னும் உங்கள் மனதில் இருக்கிறது, மேலும் அந்த உறவுக்கு ஏற்பட்ட இழப்பு நீங்கள் எதிர்பார்த்ததை விட உங்களுக்கு மிகவும் உண்மையானதாகத் தோன்றுகிறது.', 'I'),
  (3, 'A low hum of anxiety about what comes next. Not regret about what you said - but a realistic awareness that this conversation could go in several directions and not all of them are good for you.', 'அடுத்து என்ன நடக்குமோ என்ற பதற்றத்தின் மெல்லிய முணுமுணுப்பு. நீங்கள் சொன்னதைப் பற்றிய வருத்தம் அல்ல - மாறாக, இந்த உரையாடல் பல திசைகளில் செல்லக்கூடும் என்றும், அவை அனைத்தும் உங்களுக்கு நல்லவையாக இருக்காது என்றும் ஒரு யதார்த்தமான புரிதல்.', 'S'),
  (4, 'A need to reconstruct exactly what was asked, what you said, and how the room responded - because you want to understand the full picture before she gives you her version of it.', 'என்ன கேட்கப்பட்டது, நீங்கள் என்ன சொன்னீர்கள், அந்த அறையில் இருந்தவர்கள் எப்படிப் பதிலளித்தார்கள் என்பதைத் துல்லியமாக மீண்டும் நினைவுகூர வேண்டிய தேவை ஏற்படுகிறது - ஏனென்றால், அவள் தன் தரப்பு விளக்கத்தைக் கொடுப்பதற்கு முன்பு, நீங்கள் முழுமையான நிலவரத்தைப் புரிந்துகொள்ள விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q5',
     'A team member who joined eight months ago is technically capable but has developed a habit of raising objections to decisions in team settings after those decisions have already been made and communicated. The objections are sometimes valid. The timing consistently undermines the team''s momentum and your authority. Two other team members have mentioned it to you separately.', 'How will you handle dissent?', 'எட்டு மாதங்களுக்கு முன்பு சேர்ந்த ஒரு குழு உறுப்பினர் தொழில்நுட்ப ரீதியாகத் திறமையானவர், ஆனால் குழுச் சூழல்களில் முடிவுகள் எடுக்கப்பட்டுத் தெரிவிக்கப்பட்ட பிறகும், அந்த முடிவுகளுக்கு ஆட்சேபனை தெரிவிக்கும் பழக்கத்தை வளர்த்துக் கொண்டுள்ளார். அந்த ஆட்சேபனைகள் சில சமயங்களில் நியாயமானவையாகவும் இருக்கின்றன. அவர் அவ்வாறு ஆட்சேபனை தெரிவிக்கும் நேரம், குழுவின் முன்னேற்றத்தையும் உங்கள் அதிகாரத்தையும் தொடர்ந்து சீர்குலைக்கிறது. மற்ற இரண்டு குழு உறுப்பினர்கள் இதை உங்களிடம் தனித்தனியாகக் குறிப்பிட்டுள்ளனர்.', 'எதிர்ப்புகளை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You have a direct one-on-one with him this week - you name the pattern specifically, distinguish between raising concerns and undermining decisions, and set a clear expectation.', 'இந்த வாரம் நீங்கள் அவருடன் நேரடியாக உரையாடுகிறீர்கள் - அந்தப் போக்கைத் குறிப்பாகக் குறிப்பிட்டு, கவலைகளை எழுப்புவதற்கும் முடிவுகளைச் சீர்குலைப்பதற்கும் உள்ள வேறுபாட்டை விளக்கி, ஒரு தெளிவான எதிர்பார்ப்பை முன்வைக்கிறீர்கள்.', 'D'),
  (2, 'You raise it as a broader team conversation about how the group handles disagreement - you address the pattern without targeting him individually in the first instance.', 'குழு கருத்து வேறுபாடுகளை எவ்வாறு கையாளுகிறது என்பது பற்றிய ஒரு பரந்த குழு உரையாடலாக நீங்கள் அதை எழுப்புகிறீர்கள் - முதல் கட்டத்தில் அவரைத் தனிப்பட்ட முறையில் குறிவைக்காமல், அந்தப் போக்கைக் கையாளுகிறீர்கள்.', 'I'),
  (3, 'You give it one more instance, then use that specific moment as the entry point for the conversation rather than raising it in the abstract.', 'அதை பொதுவாக எழுப்புவதற்குப் பதிலாக, அதற்கு இன்னொரு சந்தர்ப்பம் கொடுத்து, பின்னர் அந்த குறிப்பிட்ட தருணத்தை உரையாடலுக்கான நுழைவாயிலாகப் பயன்படுத்துங்கள்.', 'S'),
  (4, 'You document the last three incidents - what was decided, what he raised, and the impact on the team - so the conversation is grounded in specific examples rather than a general impression.', 'கடைசி மூன்று சம்பவங்களையும் - என்ன முடிவு எடுக்கப்பட்டது, அவர் என்ன எழுப்பினார், மற்றும் அது குழுவில் ஏற்படுத்திய தாக்கம் ஆகியவற்றையும் - நீங்கள் ஆவணப்படுத்துவதன் மூலம், அந்த உரையாடலானது ஒரு பொதுவான அபிப்பிராயத்தை விட, குறிப்பிட்ட உதாரணங்களின் அடிப்படையில் அமைந்திருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q6',
     'Your team has delivered a piece of work to a senior stakeholder that contains a material error. The error came from a data source your team did not verify - a process gap that should have been caught. You found out this morning. The stakeholder has not yet noticed. You have a scheduled check-in with her in four hours.', 'How will you handle this?', 'உங்கள் குழு, ஒரு முக்கியப் பிழையைக் கொண்ட ஒரு பணியை மூத்த பங்குதாரர் ஒருவரிடம் சமர்ப்பித்துள்ளது. உங்கள் குழு சரிபார்க்காத ஒரு தரவு மூலத்திலிருந்து அந்தப் பிழை வந்துள்ளது - இது கண்டறியப்பட்டிருக்க வேண்டிய ஒரு செயல்முறைக் குறைபாடு. இதை நீங்கள் இன்று காலைதான் கண்டுபிடித்தீர்கள். அந்தப் பங்குதாரர் இன்னும் இதைக் கவனிக்கவில்லை. இன்னும் நான்கு மணி நேரத்தில் அவருடன் நீங்கள் ஒரு சந்திப்பை ஏற்பாடு செய்துள்ளீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You call her before the scheduled check-in, name the error, explain what happened, and tell her what you are doing to correct it.', 'திட்டமிடப்பட்ட சந்திப்புக்கு முன்பு நீங்கள் அவளைத் தொலைபேசியில் அழைத்து, பிழையைக் குறிப்பிட்டு, என்ன நடந்தது என்பதை விளக்கி, அதைச் சரிசெய்ய நீங்கள் என்ன செய்கிறீர்கள் என்பதையும் அவளிடம் கூறுங்கள்.', 'D'),
  (2, 'You spend the next three hours fixing the error and producing a corrected version so that when you walk into the check-in you can present the problem and the resolution simultaneously.', 'அடுத்த மூன்று மணிநேரத்தை அந்தப் பிழையைச் சரிசெய்து, திருத்தப்பட்ட பதிப்பை உருவாக்குவதில் செலவிடுகிறீர்கள். அதன் மூலம், நீங்கள் சரிபார்ப்பு அறைக்குள் நுழையும்போது, ​​சிக்கலையும் அதற்கான தீர்வையும் ஒரே நேரத்தில் முன்வைக்க முடியும்.', 'I'),
  (3, 'You raise it in the check-in - clearly, without deflection - and use the conversation to understand whether the error has already influenced any decisions before you focus on the fix.', 'சரிபார்ப்பின் போதே அதை நீங்கள் தெளிவாகவும், திசை திருப்பாமலும் எழுப்பி, அதைச் சரிசெய்வதில் கவனம் செலுத்துவதற்கு முன்பு, அந்தப் பிழை ஏற்கனவே ஏதேனும் முடிவுகளைப் பாதித்துள்ளதா என்பதைப் புரிந்துகொள்ள அந்த உரையாடலைப் பயன்படுத்திக்கொள்ளுங்கள்.', 'S'),
  (4, 'You document the error, the source of the gap, and the corrective steps before the check-in so you can present a structured account rather than an unprepared one.', 'சரிபார்ப்பிற்கு முன்பாகவே, பிழை, அந்த இடைவெளிக்கான காரணம் மற்றும் அதற்கான திருத்த நடவடிக்கைகள் ஆகியவற்றை நீங்கள் ஆவணப்படுத்துகிறீர்கள். இதன் மூலம், ஆயத்தமில்லாத ஒரு அறிக்கைக்குப் பதிலாக, கட்டமைக்கப்பட்ட ஒரு அறிக்கையை உங்களால் வழங்க முடியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q7',
     'Two things are pulling at you. Which is stronger? Your team has underdelivered on a commitment that mattered. The causes are genuinely mixed - some within your team''s control, some outside it. One pull is to own it fully when you speak to your manager - take the hit cleanly, protect the team from scrutiny, and rebuild through results. The other pull is to present the full picture - name every contributing factor accurately so the accountability sits where it actually belongs.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை உந்துகின்றன. அவற்றில் எது வலிமையானது? முக்கியத்துவம் வாய்ந்த ஒரு வாக்குறுதியை உங்கள் குழு நிறைவேற்றத் தவறிவிட்டது. அதற்கான காரணங்கள் உண்மையாகவே பலதரப்பட்டவை - சில உங்கள் குழுவின் கட்டுப்பாட்டில் உள்ளவை, சில அதற்கு அப்பாற்பட்டவை. ஒரு உந்துதல், உங்கள் மேலாளரிடம் பேசும்போது அதை முழுமையாக ஏற்றுக்கொள்வது - பழியை நேர்மையாக ஏற்றுக்கொள்வது, விமர்சனங்களிலிருந்து குழுவைப் பாதுகாப்பது, மற்றும் முடிவுகளின் மூலம் மீண்டும் கட்டமைப்பது. மற்றொரு உந்துதல், முழுமையான சித்திரத்தை முன்வைப்பது - பொறுப்பு உண்மையில் இருக்க வேண்டிய இடத்தில் இருக்க, பங்களித்த ஒவ்வொரு காரணியையும் துல்லியமாகக் குறிப்பிடுவது.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to own it fully is stronger. Your team needs to see you absorb the pressure, and partial accountability reads as defensiveness to people above you.', 'அதை முழுமையாகப் பொறுப்பேற்க வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்கள் அழுத்தத்தை உள்வாங்கிக் கொள்வதை உங்கள் குழுவினர் பார்க்க வேண்டும், மேலும் பகுதி நேரப் பொறுப்பு என்பது உங்களுக்கு மேலுள்ளவர்களுக்கு ஒரு தற்காப்பு நிலைப்பாடாகத் தோன்றும்.', 'D'),
  (2, 'The relational pull is stronger - you want your manager to trust your account, and a partial picture, even if accurate, may damage that trust more than a clean ownership.', 'உறவு ரீதியான ஈர்ப்பு மிகவும் வலிமையானது - உங்கள் மேலாளர் உங்கள் கணக்கை நம்ப வேண்டும் என நீங்கள் விரும்புவீர்கள், மேலும் ஒரு முழுமையான பொறுப்பேற்பை விட, ஒரு முழுமையற்ற சித்திரம், அது துல்லியமாக இருந்தாலும் கூட, அந்த நம்பிக்கையை அதிகமாகச் சேதப்படுத்தக்கூடும்.', 'I'),
  (3, 'The pull to present the full picture is stronger. You will not carry accountability that belongs elsewhere, and you can do it without being defensive if you are precise and factual.', 'முழுமையான சித்திரத்தை முன்வைக்க வேண்டும் என்ற உந்துதல் வலுவாக இருக்கும். வேறு யாருக்கோ உரிய பொறுப்பை நீங்கள் ஏற்க வேண்டியிருக்காது, மேலும் நீங்கள் துல்லியமாகவும் உண்மைகளை அடிப்படையாகக் கொண்டும் இருந்தால், தற்காப்பு உணர்வின்றி அதைச் செய்ய முடியும்.', 'S'),
  (4, 'The pull to document first is strongest. You want a written record of the contributing factors before you speak to your manager so that whatever you say is grounded and retrievable.', 'முதலில் ஆவணப்படுத்த வேண்டும் என்ற உந்துதல் மிகவும் வலுவானது. உங்கள் மேலாளரிடம் பேசுவதற்கு முன்பு, பங்களிக்கும் காரணிகளின் எழுத்துப்பூர்வமான பதிவு உங்களுக்குத் தேவை. அப்போதுதான் நீங்கள் கூறுவது ஆதாரப்பூர்வமானதாகவும், பின்னர் மீட்டெடுக்கக்கூடியதாகவும் இருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q8',
     'What is actually happening inside you when a team member breaks down in a one-on-one - not over work, but over something personal and serious - and you are sitting across from someone who genuinely needs support right now but you are also a manager in a professional context with limits you have never had to name out loud before?', 'How do you manage conflict?', 'ஒரு குழு உறுப்பினர், வேலை சம்பந்தமாக அல்லாமல், தனிப்பட்ட மற்றும் தீவிரமான ஒரு விஷயத்திற்காக உங்களுடன் தனிப்பட்ட முறையில் மனம் உடைந்து அழும்போது, ​​உங்களுக்குள் உண்மையில் என்னதான் நிகழ்கிறது? அந்த நேரத்தில் உண்மையாகவே ஆதரவு தேவைப்படும் ஒருவருக்கு எதிரே நீங்கள் அமர்ந்திருக்கிறீர்கள்; ஆனால் அதே சமயம், தொழில்முறைச் சூழலில், இதுவரை நீங்கள் வெளிப்படையாகச் சொல்லாத சில வரம்புகளைக் கொண்ட ஒரு மேலாளராகவும் இருக்கிறீர்கள்.', 'முரண்பாடுகளை நீங்கள் எவ்வாறு கையாளுகிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the human pull most strongly and you follow it - the professional limits can be navigated, but the moment in front of you is real and it deserves a real response.', 'நீங்கள் மனித ஈர்ப்பை மிகவும் வலுவாக உணர்ந்து அதைப் பின்பற்றுகிறீர்கள் - தொழில்முறை வரம்புகளைக் கடந்து செல்ல முடியும், ஆனால் உங்கள் கண்முன் இருக்கும் தருணம் உண்மையானது, அதற்கு ஒரு உண்மையான பிரதிபலிப்பு தேவை.', 'D'),
  (2, 'You feel a careful balance between care and role - you want to be fully present for this person without creating an expectation of support that you cannot sustain within this relationship.', 'கவனிப்புக்கும் உங்கள் பங்கிற்கும் இடையில் நீங்கள் ஒரு கவனமான சமநிலையை உணர்கிறீர்கள் - இந்த உறவில் உங்களால் நிலைநிறுத்த முடியாத ஆதரவுக்கான எதிர்பார்ப்பை உருவாக்காமல், அந்த நபருக்காக நீங்கள் முழுமையாக இருக்க விரும்புகிறீர்கள்.', 'I'),
  (3, 'You feel the weight of responsibility - not just for the person in front of you but for what comes next, whether they are okay, whether you have done enough, whether you should be doing more.', 'உங்களுக்கு முன்னால் இருப்பவருக்கான பொறுப்பு மட்டுமல்ல, அடுத்து என்ன நடக்கும், அவர்கள் நலமாக இருக்கிறார்களா, நீங்கள் போதுமான அளவு செய்துவிட்டீர்களா, இன்னும் அதிகமாகச் செய்ய வேண்டுமா என்பது போன்ற விஷயங்களின் பாரத்தையும் நீங்கள் உணர்கிறீர்கள்.', 'S'),
  (4, 'You feel the discomfort of the boundary acutely - you want to respond well but you are also aware that you are not equipped to be what this person might need right now, and that awareness is sitting alongside the care.', 'அந்த எல்லையின் சங்கடத்தை நீங்கள் ஆழமாக உணர்கிறீர்கள் - நீங்கள் சிறப்பாகப் பதிலளிக்க விரும்பினாலும், அந்த நபருக்கு இப்போது என்ன தேவையோ அதைச் செய்வதற்கு உங்களிடம் தகுதி இல்லை என்பதையும் நீங்கள் அறிந்திருக்கிறீர்கள்; அந்த விழிப்புணர்வு, அக்கறையோடு சேர்ந்தே இருக்கிறது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q9',
     'A peer manager from the product team has been making decisions in your shared workstream without looping you in. The decisions are not wrong but they are affecting your team''s work. When you raised it informally last month she said she would be more inclusive. Nothing has changed. A third instance happened yesterday.', 'How will you handle conflict?', 'தயாரிப்புக் குழுவைச் சேர்ந்த ஒரு சக மேலாளர், உங்கள் பகிரப்பட்ட பணிப்பாய்வில் உங்களிடம் தெரிவிக்காமல் முடிவுகளை எடுத்து வருகிறார். அந்த முடிவுகள் தவறானவை அல்ல, ஆனால் அவை உங்கள் குழுவின் வேலையைப் பாதிக்கின்றன. கடந்த மாதம் நீங்கள் இதுகுறித்து முறைசாராமல் தெரிவித்தபோது, ​​அவர் அனைவரையும் உள்ளடக்கிச் செயல்படுவதாகக் கூறினார். ஆனால், எந்த மாற்றமும் ஏற்படவில்லை. நேற்று மூன்றாவது முறையாக இது நிகழ்ந்துள்ளது.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You send her a clear, direct message today - you name the three instances, what was decided without you, and what you need to change before the next decision point.', 'இன்று அவளுக்கு ஒரு தெளிவான, நேரடியான செய்தியை அனுப்புங்கள் - அந்த மூன்று நிகழ்வுகளையும், உங்கள் அனுமதியின்றி எடுக்கப்பட்ட முடிவையும், அடுத்த முடிவெடுக்கும் தருணத்துக்கு முன்பு நீங்கள் மாற்ற வேண்டியவை என்ன என்பதையும் குறிப்பிடுங்கள்.', 'D'),
  (2, 'You request a working session this week - not to escalate, but to establish a joint decision-making process for the shared workstream going forward.', 'நீங்கள் இந்த வாரம் ஒரு பணி அமர்வைக் கோருகிறீர்கள் - பிரச்சினையை அடுத்த கட்டத்திற்கு எடுத்துச் செல்வதற்காக அல்ல, மாறாக, இனிவரும் காலங்களில் பகிரப்பட்ட பணிப்பாய்விற்கான ஒரு கூட்டு முடிவெடுக்கும் செயல்முறையை நிறுவுவதற்காக.', 'I'),
  (3, 'You raise it with your own manager and ask her to have a conversation with the product manager''s lead - the informal approach has not worked and you do not want to escalate peer-to-peer again.', 'இதை உங்கள் மேலாளரிடம் தெரிவித்து, தயாரிப்பு மேலாளரின் தலைவருடன் உரையாடுமாறு அவரிடம் கேளுங்கள் - முறைசாரா அணுகுமுறை பலனளிக்கவில்லை என்பதாலும், நீங்கள் மீண்டும் சக ஊழியர்களிடம் இந்தப் பிரச்சினையைக் கொண்டு செல்ல விரும்பவில்லை என்பதாலும் இவ்வாறு செய்யுங்கள்.', 'S'),
  (4, 'You document the three instances with dates, what was decided, and the impact on your team, then send a structured note to your peer with a specific proposal for how decisions in the shared workstream should be made.', 'அந்த மூன்று நிகழ்வுகளையும் தேதிகள், எடுக்கப்பட்ட முடிவு மற்றும் உங்கள் குழுவில் ஏற்பட்ட தாக்கம் ஆகியவற்றுடன் ஆவணப்படுத்தி, பின்னர் பகிரப்பட்ட பணிப்பாய்வில் முடிவுகள் எவ்வாறு எடுக்கப்பட வேண்டும் என்பதற்கான ஒரு குறிப்பிட்ட முன்மொழிவுடன், உங்கள் சக ஊழியருக்கு ஒரு கட்டமைக்கப்பட்ட குறிப்பை அனுப்பவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q10',
     'You need a senior peer in the finance function to accelerate a budget approval that is holding up your team''s work. He has a reputation for being immovable on process and timelines. You have not built a strong relationship with him. Your manager has suggested you try directly before she escalates.', 'How will you handle this?', 'உங்கள் குழுவின் வேலையைத் தாமதப்படுத்தும் ஒரு வரவுசெலவுத் திட்ட ஒப்புதலை விரைவுபடுத்த, நிதிப் பிரிவில் உள்ள ஒரு மூத்த அதிகாரி உங்களுக்குத் தேவை. செயல்முறைகள் மற்றும் காலக்கெடு விஷயத்தில் அவர் வளைந்து கொடுக்காதவர் என்ற பெயர் அவருக்கு உண்டு. நீங்கள் அவருடன் ஒரு வலுவான உறவை ஏற்படுத்திக்கொள்ளவில்லை. அவர் அடுத்த கட்டத்திற்குக் கொண்டு செல்வதற்கு முன்பு, நீங்கள் நேரடியாக முயற்சி செய்யுமாறு உங்கள் மேலாளர் பரிந்துரைத்துள்ளார்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "influence_style", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You reach out directly, name the business urgency clearly, and ask him to tell you what he needs to accelerate the process rather than asking him to skip it.', 'நீங்கள் அவரை நேரடியாகத் தொடர்புகொண்டு, வணிகத்தின் அவசரத் தேவையைத் தெளிவாகக் குறிப்பிட்டு, அந்தச் செயல்முறையைத் தவிர்க்கச் சொல்வதற்குப் பதிலாக, அதை விரைவுபடுத்த அவருக்கு என்ன தேவை என்று கூறுமாறு கேளுங்கள்.', 'D'),
  (2, 'You find a shared connection - someone he respects who can brief him on your team''s situation before you make contact - and use that opening to make the ask land differently.', 'நீங்கள் தொடர்புகொள்வதற்கு முன்பு, உங்கள் அணியின் நிலைமை குறித்து அவருக்கு விளக்கக்கூடிய, அவர் மதிக்கும் ஒரு பொதுவான தொடர்பைக் கண்டறிந்து, அந்த வாய்ப்பைப் பயன்படுத்தி உங்கள் கோரிக்கையை வித்தியாசமான முறையில் முன்வையுங்கள்.', 'I'),
  (3, 'You prepare a tight brief: the business case for urgency, the cost of delay, the specific ask, and a one-page summary he can use internally. You make the ask easy to say yes to.', 'நீங்கள் ஒரு சுருக்கமான அறிக்கையைத் தயாரிக்கிறீர்கள்: அவசரத்திற்கான வணிகக் காரணம், தாமதத்தால் ஏற்படும் செலவு, குறிப்பிட்ட கோரிக்கை, மற்றும் அவர் நிறுவனத்திற்குள் பயன்படுத்தக்கூடிய ஒரு பக்கச் சுருக்கம் ஆகியவை அதில் அடங்கும். அந்தக் கோரிக்கைக்கு ''ஆம்'' என்று சொல்வதை எளிதாக்குகிறீர்கள்.', 'S'),
  (4, 'You send a formal written request with the supporting documentation, the urgency rationale, and a specific proposed approval date - you create a paper trail and let him respond to the evidence.', 'துணை ஆவணங்கள், அவசரத்திற்கான காரணம் மற்றும் முன்மொழியப்பட்ட ஒரு குறிப்பிட்ட ஒப்புதல் தேதியுடன் ஒரு முறையான எழுத்துப்பூர்வ கோரிக்கையை நீங்கள் அனுப்புகிறீர்கள் - இதன் மூலம் ஒரு ஆவணப் பதிவை உருவாக்கி, அந்த ஆதாரங்களுக்கு அவர் பதிலளிக்க அனுமதிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q11',
     'The conflict you feel most is between managing the relationship and managing the outcome. A peer you work with regularly has submitted work to a shared stakeholder that you believe contains a significant analytical flaw. The stakeholder has not yet acted on it. If you flag the flaw, you correct the record but create friction with a peer you depend on. If you stay silent, the stakeholder may make a poor decision based on flawed analysis - and you knew.', 'How to handle flawed analysis?', 'உறவை நிர்வகிப்பதற்கும், அதன் விளைவை நிர்வகிப்பதற்கும் இடையேதான் நீங்கள் அதிகம் உணரும் முரண்பாடு உள்ளது. நீங்கள் வழக்கமாகப் பணிபுரியும் ஒரு சக ஊழியர், ஒரு பொதுவான பங்குதாரரிடம் சமர்ப்பித்த ஒரு பணியில், ஒரு குறிப்பிடத்தக்க பகுப்பாய்வுக் குறைபாடு இருப்பதாக நீங்கள் நம்புகிறீர்கள். அந்தப் பங்குதாரர் இன்னும் அதன் மீது எந்த நடவடிக்கையும் எடுக்கவில்லை. நீங்கள் அந்தக் குறைபாட்டைச் சுட்டிக்காட்டினால், பதிவைத் திருத்துகிறீர்கள், ஆனால் நீங்கள் சார்ந்திருக்கும் ஒரு சக ஊழியருடன் உராய்வை உருவாக்குகிறீர்கள். நீங்கள் மௌனமாக இருந்தால், அந்தப் பங்குதாரர் குறைபாடுள்ள பகுப்பாய்வின் அடிப்படையில் ஒரு தவறான முடிவை எடுக்கக்கூடும் - அது உங்களுக்கு முன்பே தெரிந்திருந்தது.', 'குறைபாடுள்ள பகுப்பாய்வை எவ்வாறு கையாள்வது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Correcting the record matters more. You find a professional way to raise the flaw with the stakeholder - not to undermine your peer, but because the outcome is more important than the relationship friction.', 'பதிவைச் சரிசெய்வதே மிகவும் முக்கியமானது. சம்பந்தப்பட்ட நபரிடம் அந்தக் குறைபாட்டை எழுப்ப நீங்கள் ஒரு தொழில்முறை வழியைக் கண்டறிய வேண்டும் - அது உங்கள் சக ஊழியரின் மதிப்பைக் குறைப்பதற்காக அல்ல, மாறாக உறவுச் சிக்கல்களை விட அதன் விளைவு மிகவும் முக்கியமானது என்பதால்தான்.', 'D'),
  (2, 'The peer relationship matters more in the first instance - you go to your peer directly, tell her what you have noticed, and give her the chance to correct it herself before anyone else is involved.', 'முதலில், சக ஊழியருடனான உறவுதான் மிகவும் முக்கியம் - நீங்கள் உங்கள் சக ஊழியரிடம் நேரடியாகச் சென்று, நீங்கள் கவனித்ததை அவரிடம் கூறி, வேறு யாரும் தலையிடுவதற்கு முன்பு அதை அவரே சரிசெய்துகொள்ள வாய்ப்பளிக்க வேண்டும்.', 'I'),
  (3, 'The outcome matters most but the method matters too - you find a way to surface the flaw through a question or a clarification that does not make it a confrontation with either party.', 'முடிவுதான் மிக முக்கியம், ஆனால் கையாளும் முறையும் முக்கியம் - இரு தரப்பினருடனும் மோதலை ஏற்படுத்தாத வகையில், ஒரு கேள்வி அல்லது விளக்கத்தின் மூலம் அந்தக் குறையை வெளிக்கொணர ஒரு வழியைக் கண்டறிய வேண்டும்.', 'S'),
  (4, 'The evidence matters most. You work through the analysis yourself first to make sure you are correct about the flaw before you say anything to anyone.', 'ஆதாரமே மிகவும் முக்கியமானது. யாரிடமும் எதையும் சொல்வதற்கு முன், அந்தக் குறைபாடு குறித்து நீங்கள் சொல்வது சரிதானா என்பதை உறுதிப்படுத்திக்கொள்ள, முதலில் நீங்களே அந்தப் பகுப்பாய்வைச் செய்து பாருங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q12',
     'The honest feeling underneath this - when a peer you have always been cordial with suddenly goes cold on you after you got the assignment she wanted - is not just about the awkwardness of working alongside someone who resents you. There is something else underneath it that you have not named yet.', 'What feeling lies underneath this?', 'நீங்கள் எப்போதும் நட்பாகப் பழகிய ஒரு சக ஊழியர், அவர் விரும்பிய வேலையை நீங்கள் பெற்ற பிறகு திடீரென்று உங்களிடம் இருந்து விலகிச் செல்லும்போது, ​​இதன் அடியில் இருக்கும் உண்மையான உணர்வு என்பது, உங்களை வெறுக்கும் ஒருவருடன் இணைந்து பணியாற்றுவதில் உள்ள சங்கடத்தைப் பற்றியது மட்டுமல்ல. அதன் அடியில் நீங்கள் இன்னும் குறிப்பிடாத வேறு ஏதோ ஒன்று இருக்கிறது.', 'இதன் அடியில் என்ன உணர்வு புதைந்துள்ளது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a clean discomfort. The relationship has changed and you would rather know that clearly than pretend it has not. You can work with this.', 'ஒரு தெளிவான சங்கடம் நிலவுகிறது. உறவு மாறிவிட்டது; அது மாறவில்லை என்று பாசாங்கு செய்வதை விட, அதைத் தெளிவாக அறிந்துகொள்வதே உங்களுக்கு விருப்பம். இதை நீங்கள் சமாளித்துச் செயல்படலாம்.', 'D'),
  (2, 'There is a loss - not of the relationship exactly, but of the version of this workplace where you believed the people around you were broadly in your corner. That assumption has shifted.', 'ஒரு இழப்பு ஏற்பட்டுள்ளது - அது உறவின் இழப்பு என்பதல்ல, மாறாக, உங்களைச் சுற்றியிருந்தவர்கள் பெரும்பாலும் உங்களுக்கு ஆதரவாக இருக்கிறார்கள் என்று நீங்கள் நம்பியிருந்த இந்தப் பணியிடத்தின் ஒரு வடிவத்தின் இழப்பு. அந்த அனுமானம் மாறிவிட்டது.', 'I'),
  (3, 'There is a guilt you are managing. Not because you did anything wrong, but because you know what it feels like to watch someone else get the thing you wanted, and some part of you is sitting with that knowledge right now.', 'நீங்கள் ஒரு குற்றவுணர்வைச் சமாளித்துக் கொண்டிருக்கிறீர்கள். நீங்கள் ஏதேனும் தவறு செய்ததால் அல்ல, மாறாக, நீங்கள் விரும்பிய ஒன்றை மற்றவர் பெறுவதைப் பார்ப்பது எப்படி இருக்கும் என்று உங்களுக்குத் தெரியும் என்பதாலும், உங்கள் உள்ளத்தின் ஒரு பகுதி அந்த உண்மையை தற்போது உள்வாங்கிக் கொண்டிருப்பதாலும்தான்.', 'S'),
  (4, 'There is a strategic alertness. Someone who resents you and sits at your level in this organisation is a variable you need to understand - what she will do with it, who she talks to, how it will show up.', 'ஒரு வியூக ரீதியான விழிப்புணர்வு இருக்கிறது. உங்கள் மீது வெறுப்பு கொண்டு, இந்த நிறுவனத்தில் உங்கள் நிலையில் இருக்கும் ஒருவர், நீங்கள் புரிந்துகொள்ள வேண்டிய ஒரு காரணியாக இருக்கிறார் - அதை வைத்து அவர் என்ன செய்வார், யாரிடம் பேசுவார், அது எப்படி வெளிப்படும் என்பனவற்றையெல்லாம் கவனிக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q13',
     'Your organisation has just announced a hiring freeze effective immediately. Your team was expecting two new joiners to start next month - roles that were offered, accepted, and critical to a project you have already scoped with those headcount assumptions. You need to communicate this to your team today. You also need to figure out what to say to the two people who accepted offers.', 'How will you handle this?', 'உங்கள் நிறுவனம் உடனடியாக அமலுக்கு வரும் வகையில் ஆள்சேர்ப்பு நிறுத்தம் ஒன்றை அறிவித்துள்ளது. அடுத்த மாதம் இரண்டு புதியவர்கள் பணியில் சேருவார்கள் என உங்கள் குழு எதிர்பார்த்திருந்தது. அந்தப் பதவிகள் ஏற்கெனவே வழங்கப்பட்டு, ஏற்றுக்கொள்ளப்பட்டதோடு, குறிப்பிட்ட எண்ணிக்கையிலான பணியாளர்களைக் கொண்டு நீங்கள் வரையறுத்துள்ள ஒரு திட்டத்திற்கும் மிகவும் முக்கியமானவை. இதை நீங்கள் இன்று உங்கள் குழுவிடம் தெரிவிக்க வேண்டும். மேலும், பணி வாய்ப்புகளை ஏற்றுக்கொண்ட அந்த இருவரிடம் என்ன சொல்வது என்பதையும் நீங்கள் முடிவு செய்ய வேண்டும்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You communicate to your team today - clearly, fully, and with whatever you know - before rumour gets there first. You address the two incoming hires separately and immediately after.', 'வதந்தி பரவுவதற்கு முன்பே, இன்று உங்கள் குழுவினரிடம் தெளிவாகவும், முழுமையாகவும், உங்களுக்குத் தெரிந்த அனைத்தையும் கொண்டும் தகவல் தெரிவியுங்கள். அதன்பிறகு உடனடியாக, புதிதாகப் பணியில் சேரும் இருவரிடமும் தனித்தனியாகப் பேசுங்கள்.', 'D'),
  (2, 'You speak to HR before you communicate anything, making sure you understand the obligations to the two incoming hires before you say anything to anyone.', 'யாரிடமும் எதையும் தெரிவிப்பதற்கு முன், புதிதாகப் பணியில் சேரும் இருவருக்கும் உள்ள கடமைகளை நீங்கள் புரிந்துகொண்டதை உறுதி செய்துகொண்டு, மனிதவளத் துறையிடம் (HR) பேச வேண்டும்.', 'I'),
  (3, 'You speak to your team first - they are your immediate responsibility - and manage the incoming hire conversation through HR so you are not making promises you cannot keep.', 'முதலில் உங்கள் குழுவினருடன் பேசுங்கள் - அவர்கள் உங்கள் உடனடிப் பொறுப்பு - மேலும், உங்களால் நிறைவேற்ற முடியாத வாக்குறுதிகளை அளிக்காமல் இருக்க, புதிதாகப் பணியில் சேரவிருப்பவர் குறித்த உரையாடலை மனிதவளத் துறை (HR) மூலம் நிர்வகிக்கவும்.', 'S'),
  (4, 'You prepare two separate communications - one for your team and one for the incoming hires - each accurate, specific, and neither overpromising, before you send anything.', 'நீங்கள் எதையும் அனுப்புவதற்கு முன்பு, உங்கள் குழுவிற்கு ஒன்று, புதிதாகப் பணியில் சேருபவர்களுக்கு ஒன்று என இரண்டு தனித்தனித் தகவல்களைத் தயார் செய்கிறீர்கள்; அவை ஒவ்வொன்றும் துல்லியமாகவும், குறிப்பிட்டதாகவும், அதே சமயம் மிகைப்படுத்தப்படாத வாக்குறுதிகளை அளிப்பதாகவும் இருக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q14',
     'A directive has come through requiring all managers to implement a new meeting cadence - daily standups replacing the weekly rhythms your team has used effectively for three years. The rationale given is visibility and accountability. Your team is experienced and self-directed. You believe this will be experienced as surveillance and will damage morale. You have no flexibility on whether to implement it.', 'How will you handle this?', 'உங்கள் குழு கடந்த மூன்று ஆண்டுகளாகத் திறம்படப் பயன்படுத்தி வந்த வாராந்திரக் கூட்டங்களுக்குப் பதிலாக, தினசரி சந்திப்புகளை நடத்தும் ஒரு புதிய கூட்ட முறையை அனைத்து மேலாளர்களும் நடைமுறைப்படுத்த வேண்டும் என்று ஒரு உத்தரவு வந்துள்ளது. இதற்குக் கூறப்படும் காரணம், வெளிப்படைத்தன்மை மற்றும் பொறுப்புக்கூறல் ஆகும். உங்கள் குழு அனுபவம் வாய்ந்தது மற்றும் சுயமாகச் செயல்படக்கூடியது. இது ஒரு கண்காணிப்பாக உணரப்படும் என்றும், மன உறுதியைக் குலைக்கும் என்றும் நீங்கள் நம்புகிறீர்கள். இதை நடைமுறைப்படுத்துவதா வேண்டாமா என்பதில் உங்களுக்கு எந்த நெகிழ்வுத்தன்மையும் இல்லை.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You implement it, but you tell your team directly that the change is a leadership directive, explain what is driving it, and make clear you will advocate for a review after sixty days.', 'நீங்கள் அதைச் செயல்படுத்துகிறீர்கள், ஆனால் இந்த மாற்றம் ஒரு தலைமைத்துவ உத்தரவு என்பதை உங்கள் குழுவிடம் நேரடியாகத் தெரிவித்து, அதற்கான காரணத்தை விளக்கி, அறுபது நாட்களுக்குப் பிறகு ஒரு மறுஆய்வுக்குப் பரிந்துரைப்பீர்கள் என்பதையும் தெளிவுபடுத்த வேண்டும்.', 'D'),
  (2, 'You implement it in a way that honours the intent without the damage - you adapt the format so that the standups are genuinely useful rather than performative.', 'நோக்கத்திற்குப் பாதிப்பு ஏற்படுத்தாமல் அதை மதிக்கும் வகையில் நீங்கள் அதைச் செயல்படுத்துகிறீர்கள் - அதாவது, ஸ்டாண்டப் காமெடி வெறும் வெளிவேடமாக இல்லாமல், உண்மையாகவே பயனுள்ளதாக இருக்கும்படி அதன் வடிவத்தை மாற்றியமைக்கிறீர்கள்.', 'I'),
  (3, 'You implement it fully as directed and focus your energy on keeping your team''s morale steady through the transition rather than framing it as something to manage around.', 'அறிவுறுத்தப்பட்டபடி அதை முழுமையாகச் செயல்படுத்தி, அதைச் சமாளிக்க வேண்டிய ஒரு விஷயமாகக் கருதுவதற்குப் பதிலாக, இந்த மாற்றத்தின்போது உங்கள் குழுவின் மன உறுதியை நிலையாக வைத்திருப்பதில் உங்கள் ஆற்றலைச் செலுத்துங்கள்.', 'S'),
  (4, 'You implement it precisely as directed, document your team''s response over the first month, and build a data-based case for a review at the sixty-day mark.', 'அறிவுறுத்தப்பட்டபடி அதைத் துல்லியமாகச் செயல்படுத்தி, முதல் மாதத்தில் உங்கள் குழுவின் செயல்பாடுகளை ஆவணப்படுத்தி, அறுபதாவது நாளில் மறுஆய்வு செய்வதற்கான தரவு அடிப்படையிலான ஒரு முன் அறிக்கையை உருவாக்குங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q15',
     'The conflict you feel most is between honesty and protection. You have been asked to communicate a change to your team that you know is the first step in a larger restructuring - but leadership has not authorised you to share that context. Your team is smart. They will read the signals. If you tell them only what you are authorised to share, they will sense there is more and the uncertainty will be worse than the truth. If you go beyond your brief, you breach a confidence that was placed in you.', 'How will you handle this?', 'நீங்கள் மிகவும் உணரும் முரண்பாடு, நேர்மைக்கும் பாதுகாப்பிற்கும் இடையிலானது. ஒரு பெரிய மறுசீரமைப்பின் முதல் படி என்று உங்களுக்குத் தெரிந்த ஒரு மாற்றத்தை உங்கள் குழுவிடம் தெரிவிக்குமாறு நீங்கள் கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள் - ஆனால், அந்தச் சூழலைப் பகிர்ந்துகொள்ள தலைமை உங்களுக்கு அதிகாரம் அளிக்கவில்லை. உங்கள் குழு புத்திசாலிகள். அவர்கள் சமிக்ஞைகளைப் புரிந்துகொள்வார்கள். பகிர்ந்துகொள்ள உங்களுக்கு அதிகாரம் அளிக்கப்பட்டதை மட்டும் நீங்கள் அவர்களிடம் சொன்னால், இன்னும் அதிகம் இருக்கிறது என்பதை அவர்கள் உணர்ந்துகொள்வார்கள், மேலும் அந்த நிச்சயமற்ற தன்மை உண்மையை விட மோசமாக இருக்கும். உங்களுக்கு வழங்கப்பட்ட அதிகார வரம்பை மீறி நீங்கள் செயல்பட்டால், உங்கள் மீது வைக்கப்பட்ட நம்பிக்கையை நீங்கள் மீறுகிறீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Honesty with your team wins. You find a way to signal that this is part of a larger picture without disclosing specifics - you do not lie to people who trust you.', 'உங்கள் குழுவிடம் நேர்மையாக இருப்பது வெற்றியைத் தரும். குறிப்பிட்ட விவரங்களை வெளியிடாமல், இது ஒரு பெரிய திட்டத்தின் ஒரு பகுதி என்பதை உணர்த்த ஒரு வழியைக் கண்டறியுங்கள் - உங்களை நம்புபவர்களிடம் நீங்கள் பொய் சொல்லக்கூடாது.', 'D'),
  (2, 'The confidence placed in you wins. You deliver exactly what you are authorised to share and hold the line, even knowing your team will sense the gap.', 'உங்கள் மீது வைக்கப்படும் நம்பிக்கையே வெற்றி பெறுகிறது. உங்கள் குழுவினர் அந்த இடைவெளியை உணர்ந்து கொள்வார்கள் என்று தெரிந்திருந்தும், நீங்கள் பகிர அனுமதிக்கப்பட்டதை அப்படியே வழங்கி, உங்கள் நிலைப்பாட்டில் உறுதியாக நிற்கிறீர்கள்.', 'I'),
  (3, 'Their stability wins. You focus the conversation on what this means for them in practical terms right now, and you avoid both lying and revealing - you stay in the present tense.', 'அவர்களின் நிலைத்தன்மை வெல்கிறது. நடைமுறையில் இது அவர்களுக்கு இப்போது என்ன அர்த்தம் என்பதைப் பற்றி உரையாடலை மையப்படுத்தி, பொய் சொல்வதையும் உண்மைகளை வெளிப்படுத்துவதையும் தவிர்த்து, நிகழ்காலத்தில் இருங்கள்.', 'S'),
  (4, 'The process wins. You go back to leadership before you communicate anything and ask explicitly what you are permitted to say - you will not manage this conversation in ambiguity.', 'செயல்முறையே வெல்லும். நீங்கள் எதையும் தெரிவிப்பதற்கு முன், தலைமையிடம் திரும்பிச் சென்று, என்ன பேச உங்களுக்கு அனுமதி உண்டு என்பதைத் தெளிவாகக் கேளுங்கள் - இந்த உரையாடலை உங்களால் தெளிவற்ற நிலையில் கையாள முடியாது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q16',
     'Before you walk into the meeting where you will tell a loyal, long-serving team member that her role is being eliminated - before you find the words, before you manage your expression - what is actually happening inside you right now?', 'How are you feeling now?', 'விசுவாசமாகவும் நீண்ட காலமாகவும் பணியாற்றி வரும் ஒரு குழு உறுப்பினரின் பதவி நீக்கப்படவுள்ளது என்பதை அவரிடம் தெரிவிக்கப்போகும் கூட்டத்திற்குள் நீங்கள் நுழைவதற்கு முன்பு - வார்த்தைகளைத் தேடுவதற்கு முன்பு, உங்கள் முகபாவனைகளைச் சீர்செய்வதற்கு முன்பு - இந்தத் தருணத்தில் உண்மையில் உங்கள் உள்ளுக்குள் என்னதான் நிகழ்ந்துகொண்டிருக்கிறது?', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a professional composure sitting on top of something harder. You know what you are here to do and you will do it well. But you know this person and that knowledge is present right now whether you want it to be or not.', 'கடினமான ஒன்றின் மீது ஒரு தொழில்முறை நிதானம் குடிகொண்டிருக்கிறது. நீங்கள் இங்கு என்ன செய்ய வந்திருக்கிறீர்கள் என்பது உங்களுக்குத் தெரியும், அதை நீங்கள் சிறப்பாகச் செய்வீர்கள். ஆனால், இந்த நபரை உங்களுக்குத் தெரியும், நீங்கள் விரும்பினாலும் விரும்பாவிட்டாலும் அந்த அறிவு இப்போதே உங்களிடம் இருக்கிறது.', 'D'),
  (2, 'There is a guilt that has nothing to do with the decision itself - it is the guilt of being the one who has to deliver it, of being the face of something that was decided above you, of sitting in this seat today.', 'அந்த முடிவுடன் நேரடியாகத் தொடர்பில்லாத ஒரு குற்றவுணர்வு இருக்கிறது - அது, அந்த முடிவை நிறைவேற்ற வேண்டிய கட்டாயத்தில் இருப்பதாலும், உங்களுக்கு மேலாக எடுக்கப்பட்ட ஒரு முடிவின் முகமாக இருப்பதாலும், இன்று இந்த இருக்கையில் அமர்ந்திருப்பதாலும் ஏற்படும் குற்றவுணர்வு.', 'I'),
  (3, 'There is a quiet grief. Not dramatic - but real. Someone who gave a great deal to this team is about to have their working life upended and you are the person in the room when it happens.', 'ஒரு அமைதியான துக்கம் நிலவுகிறது. அது நாடகத்தனமானதல்ல - ஆனால் உண்மையானது. இந்த அணிக்குத் தனது பெரும் பங்களிப்பை வழங்கிய ஒருவரின் பணி வாழ்க்கை தலைகீழாக மாறப்போகிறது, அது நிகழும்போது அந்த அறையில் இருக்கும் நபர் நீங்கள்தான்.', 'S'),
  (4, 'There is a focused discomfort with the inadequacy of anything you are about to say. You have prepared. You know what you want to convey. And you also know that words are going to be insufficient for what she is about to hear.', 'நீங்கள் சொல்லப்போகும் எதன் மீதும் ஒரு தீவிரமான சங்கடம் இருக்கிறது. நீங்கள் தயாராகிவிட்டீர்கள். நீங்கள் எதைத் தெரிவிக்க விரும்புகிறீர்கள் என்பது உங்களுக்குத் தெரியும். மேலும், அவள் கேட்கப்போவதை விவரிக்க வார்த்தைகள் போதாது என்பதும் உங்களுக்குத் தெரியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q17',
     'You are in a performance calibration meeting as one of four managers. A colleague begins attributing a team outcome to his own leadership that you know involved significant contributions from your team. The senior leader facilitating the meeting is nodding. You were not planning to speak until your team''s section.', 'How will you handle conflict?', 'நான்கு மேலாளர்களில் ஒருவராக நீங்கள் ஒரு செயல்திறன் மதிப்பீட்டுக் கூட்டத்தில் இருக்கிறீர்கள். உங்கள் குழுவின் குறிப்பிடத்தக்க பங்களிப்புகள் இருந்தபோதிலும், ஒரு சக ஊழியர் தனது சொந்தத் தலைமைத்துவத்தால்தான் ஒரு குழுவின் வெற்றி கிடைத்தது என்று கூறத் தொடங்குகிறார். கூட்டத்தை வழிநடத்தும் மூத்த தலைவர் தலையசைக்கிறார். உங்கள் குழுவின் பகுதி தொடங்கும் வரை பேசுவதற்கு நீங்கள் திட்டமிடவில்லை.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You speak up in the moment - professionally and specifically - and add the context that accurately reflects your team''s contribution.', 'நீங்கள் அந்தந்தத் தருணத்தில் - தொழில்முறையாகவும் குறிப்பாகவும் - உங்கள் குழுவின் பங்களிப்பைத் துல்லியமாகப் பிரதிபலிக்கும் சூழலை விளக்கிக் கூறுகிறீர்கள்.', 'D'),
  (2, 'You let it pass in the meeting and speak directly to the senior leader afterward to ensure the full picture is on record.', 'நீங்கள் அதை கூட்டத்தில் கண்டுகொள்ளாமல் விட்டுவிட்டு, முழுமையான விவரம் பதிவில் இருப்பதை உறுதிசெய்ய, பின்னர் மூத்த தலைவரிடம் நேரடியாகப் பேச வேண்டும்.', 'I'),
  (3, 'You make a note, let the meeting continue, and raise it with your own manager later - you do not want to create a peer conflict in a calibration room.', 'நீங்கள் ஒரு குறிப்பை எடுத்துக்கொண்டு, கூட்டத்தைத் தொடர விடுங்கள், பின்னர் உங்கள் மேலாளரிடம் அதைப் பற்றிப் பேசுங்கள் - ஒரு மதிப்பீட்டு அறையில் சக ஊழியர்களுக்கிடையேயான மோதலை நீங்கள் உருவாக்க விரும்ப மாட்டீர்கள்.', 'S'),
  (4, 'You wait for your team''s section and use it to lay out the full contribution record clearly, letting the accuracy of your account correct the earlier framing without direct confrontation.', 'உங்கள் குழுவின் பகுதிக்காகக் காத்திருந்து, அதைப் பயன்படுத்தி முழுமையான பங்களிப்புப் பதிவைத் தெளிவாக முன்வையுங்கள்; இதன்மூலம், நேரடி மோதல் ஏதுமின்றி, உங்கள் கூற்றின் துல்லியம் முந்தைய கட்டமைப்பைச் சரிசெய்யட்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q18',
     'You have been asked to mentor a junior manager who your organisation is fast-tracking. She is talented. She is also being given opportunities that were not offered to you at her stage - access to senior leaders, stretch projects, visible assignments. You are expected to invest in her development. You are doing it. And you are also aware of how it sits with you.', 'How will you mentor her?', 'உங்கள் நிறுவனம் விரைவாகப் பதவி உயர்வு அளிக்கும் ஒரு இளநிலை மேலாளருக்கு வழிகாட்டுமாறு நீங்கள் கேட்டுக்கொள்ளப்பட்டுள்ளீர்கள். அவர் திறமையானவர். மேலும், அவரது தற்போதைய நிலையில் உங்களுக்கு வழங்கப்படாத வாய்ப்புகளும் அவருக்கு வழங்கப்படுகின்றன - அதாவது, மூத்த தலைவர்களை அணுகும் வாய்ப்பு, சவாலான திட்டங்கள், வெளிப்படையான பொறுப்புகள் போன்றவை. அவரது வளர்ச்சியில் நீங்கள் முதலீடு செய்வீர்கள் என்று எதிர்பார்க்கப்படுகிறது. நீங்கள் அதைச் செய்துகொண்டும் இருக்கிறீர்கள். அது உங்களுக்கு எப்படிப்பட்ட உணர்வைத் தருகிறது என்பதையும் நீங்கள் அறிவீர்கள்.', 'நீங்கள் அவளுக்கு எப்படி வழிகாட்டுவீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You invest fully and genuinely - her success is real and your mentoring matters, regardless of how the comparison sits with you privately.', 'நீங்கள் முழுமையாகவும் உண்மையாகவும் முதலீடு செய்கிறீர்கள் - தனிப்பட்ட முறையில் அந்த ஒப்பீடு உங்களுக்கு எப்படி இருந்தாலும், அவளுடைய வெற்றி உண்மையானது மற்றும் உங்கள் வழிகாட்டுதல் முக்கியமானது.', 'D'),
  (2, 'You raise the investment you are making with your own manager and use it as an opportunity to have a direct conversation about your own development and where you are heading.', 'நீங்கள் செய்யும் முதலீடு குறித்து உங்கள் மேலாளரிடம் எடுத்துரைத்து, அதை உங்கள் சொந்த வளர்ச்சி மற்றும் உங்கள் எதிர்காலப் பாதை பற்றி நேரடியாக உரையாடுவதற்கான ஒரு வாய்ப்பாகப் பயன்படுத்திக்கொள்ளுங்கள்.', 'I'),
  (3, 'You mentor her well and use the relationship to build your own visibility with the senior leaders she has access to - you find the mutual benefit rather than just the cost.', 'நீங்கள் அவளுக்குச் சிறந்த வழிகாட்டியாக இருப்பதோடு, அவளுக்கு அணுகக்கூடிய மூத்த தலைவர்களிடம் உங்கள் செல்வாக்கை வளர்த்துக்கொள்ள அந்த உறவைப் பயன்படுத்திக்கொள்கிறீர்கள் - இதன்மூலம், நீங்கள் செலவை மட்டும் பார்க்காமல், பரஸ்பரப் பயனையும் காண்கிறீர்கள்.', 'S'),
  (4, 'You mentor her systematically - structured sessions, documented progress, clear outcomes - and make sure your contribution to her development is visible and on record.', 'நீங்கள் அவளுக்கு முறையாக வழிகாட்டுங்கள் - கட்டமைக்கப்பட்ட அமர்வுகள், ஆவணப்படுத்தப்பட்ட முன்னேற்றம், தெளிவான முடிவுகள் ஆகியவற்றின் மூலம் - மேலும் அவளது வளர்ச்சியில் உங்கள் பங்களிப்பு வெளிப்படையாகவும் பதிவிலும் இருப்பதை உறுதி செய்யுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q19',
     'Two things are pulling at you. Which is stronger? You have been offered a role in a different division - same level, different function, more visibility, more ambiguity. Your current role is stable, your team is strong, and your relationships are established. One pull is to stay - you have built something real here and the timing is not right to walk away from it. The other pull is to move - the discomfort of a new challenge is exactly the signal that tells you this is the right direction.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? உங்களுக்கு வேறு ஒரு பிரிவில் ஒரு பதவி வழங்கப்பட்டுள்ளது - அதே நிலை, வேறுபட்ட செயல்பாடு, அதிக வெளிப்படைத்தன்மை, அதிக தெளிவின்மை. உங்கள் தற்போதைய பதவி நிலையானது, உங்கள் குழு வலிமையானது, மேலும் உங்கள் உறவுகள் நன்கு நிலைபெற்றுள்ளன. ஒரு ஈர்ப்பு, இங்கேயே தங்கிவிட வேண்டும் என்கிறது - நீங்கள் இங்கே ஒரு உண்மையான விஷயத்தை உருவாக்கியுள்ளீர்கள், இதை விட்டு விலகுவதற்கு இது சரியான நேரம் அல்ல. மற்றொரு ஈர்ப்பு, வேறு இடத்திற்குச் செல்ல வேண்டும் என்கிறது - ஒரு புதிய சவாலின் அசௌகரியமே, இதுதான் சரியான திசை என்பதை உங்களுக்கு உணர்த்தும் சமிக்ஞையாகும்.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to move is stronger. Comfort is not growth, and you have been comfortable here long enough that the discomfort of the new role is actually the most honest signal you have had in a year.', 'இடம் மாற வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. சௌகரியம் என்பது வளர்ச்சி அல்ல, மேலும் நீங்கள் இங்கு நீண்ட காலமாக சௌகரியமாக இருந்ததால், இந்தப் புதிய பொறுப்பின் அசௌகரியமே உண்மையில் கடந்த ஓராண்டில் நீங்கள் பெற்ற மிகவும் நேர்மையான சமிக்ஞையாகும்.', 'D'),
  (2, 'The relational pull is stronger - the team you have built and the network you have here are not easily rebuilt, and you are not ready to trade them for visibility in a function you do not know yet.', 'உறவுகளின் ஈர்ப்பு மிகவும் வலிமையானது - நீங்கள் உருவாக்கிய குழுவையும், இங்குள்ள உங்கள் தொடர்பு வலையமைப்பையும் எளிதில் மீண்டும் கட்டமைக்க முடியாது; மேலும், உங்களுக்கு இன்னும் பரிச்சயமில்லாத ஒரு துறையில் வெளிப்படைத்தன்மைக்காக அவற்றை விட்டுக்கொடுக்கவும் நீங்கள் தயாராக இல்லை.', 'I'),
  (3, 'The pull to stay is stronger. The timing is wrong - your team is in the middle of something important and leaving now would be a failure of something you care about more than your own next step.', 'இங்கேயே தங்குவதற்கான ஈர்ப்பு வலுவாக உள்ளது. இது சரியான நேரமல்ல - உங்கள் குழு ஒரு முக்கியமான பணியில் ஈடுபட்டுள்ளது, இப்போது விலகுவது என்பது, உங்கள் சொந்த அடுத்தகட்ட நடவடிக்கையை விட நீங்கள் அதிகம் அக்கறை கொள்ளும் ஒரு விஷயத்தில் ஏற்படும் தோல்வியாக இருக்கும்.', 'S'),
  (4, 'The pull to understand what you would be moving into is stronger - before you decide, you want a clear picture of what the new role actually involves, who you would be working with, and what success looks like there.', 'நீங்கள் நுழையப்போகும் பணி என்னவென்பதைப் புரிந்துகொள்ள வேண்டும் என்ற ஆர்வம் மிகவும் வலுவானது - முடிவெடுப்பதற்கு முன், அந்தப் புதிய பணியில் உண்மையில் என்னென்ன அடங்கும், நீங்கள் யாருடன் பணிபுரிவீர்கள், அங்கு வெற்றி என்பது எப்படி இருக்கும் என்பனவற்றைப் பற்றிய ஒரு தெளிவான சித்திரம் உங்களுக்குத் தேவைப்படும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q20',
     'The honest feeling underneath this - when a peer who you privately know is not as strong as you gets recognised publicly at the all-hands while you sit in the audience - is something you manage quickly and professionally. But right now, in this moment, before the managing happens, what is actually there?', 'What is actually there now?', 'தனிப்பட்ட முறையில் உங்களை விடத் திறமை குறைந்தவர் என்று உங்களுக்குத் தெரிந்த ஒரு சக ஊழியர், நீங்கள் பார்வையாளர் வரிசையில் அமர்ந்திருக்கும்போது, ​​அனைவரும் கூடும் கூட்டத்தில் பகிரங்கமாக அங்கீகரிக்கப்படும்போது ஏற்படும் அந்த நேர்மையான உணர்வை, நீங்கள் விரைவாகவும் தொழில்முறையாகவும் சமாளித்துவிடுவீர்கள். ஆனால் இப்பொழுதே, இந்தச் சமாளிப்பு நடப்பதற்கு முன்பு, இந்தத் தருணத்தில், உண்மையில் அங்கே என்ன இருக்கிறது?', 'உண்மையில் இப்போது அங்கே என்ன இருக்கிறது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A clean frustration. Not at the peer - at the system that made this choice and at yourself for still being surprised by it.', 'ஒரு தெளிவான விரக்தி. சக ஊழியர் மீது அல்ல - இந்த முடிவை எடுத்த அமைப்பு மீதும், அது குறித்து இன்னும் ஆச்சரியப்படுவதற்காக உங்கள் மீதேயான விரக்தி.', 'D'),
  (2, 'A quiet question about whether you are invisible in ways you have not fully reckoned with - and that question is harder to sit with than the frustration.', 'நீங்கள் முழுமையாக உணர்ந்துகொள்ளாத வழிகளில் நீங்கள் கண்ணுக்குத் தெரியாதவராக இருக்கிறீர்களா என்பது பற்றிய ஒரு மெல்லிய கேள்வி - மேலும் அந்தக் கேள்வியானது, விரக்தியை விடவும் ஜீரணிக்கக் கடினமானது.', 'I'),
  (3, 'A tiredness. Not from today specifically - from the accumulated weight of watching this particular pattern repeat in this particular organisation, and wondering how much longer you are willing to keep sitting in the audience.', 'ஒரு சோர்வு. குறிப்பாக இன்றைய தினத்தினால் அல்ல - இந்தக் குறிப்பிட்ட நிறுவனத்தில், இந்தக் குறிப்பிட்ட போக்கு மீண்டும் மீண்டும் நிகழ்வதைப் பார்த்து, இன்னும் எவ்வளவு காலத்திற்கு பார்வையாளர் வரிசையில் அமர்ந்திருக்கத் தயாராக இருக்கிறோம் என்று யோசிப்பதால் ஏற்பட்ட திரண்ட பாரத்தினால் உண்டானது.', 'S'),
  (4, 'A sharp analytical instinct - you want to understand exactly how this decision was made, who was in the room, and what criteria were applied, because if you understand the mechanism you can decide whether to work within it or stop trying.', 'கூர்மையான பகுப்பாய்வு உள்ளுணர்வு - இந்த முடிவு எப்படி எடுக்கப்பட்டது, அந்த அறையில் யார் இருந்தார்கள், என்ன அளவுகோல்கள் பயன்படுத்தப்பட்டன என்பதை நீங்கள் துல்லியமாகப் புரிந்துகொள்ள விரும்புவீர்கள், ஏனெனில் அந்தச் செயல்முறையைப் புரிந்துகொண்டால், அதற்குள் இருந்து செயல்படுவதா அல்லது முயற்சியைக் கைவிடுவதா என்பதை உங்களால் தீர்மானிக்க முடியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q21',
     'A new operating model has been introduced that changes how your team''s work gets prioritised. Decisions that used to sit with you now go through a central prioritisation committee that meets fortnightly. Your team is used to moving quickly. The first three requests you submitted have been pending for three weeks with no response. A critical piece of work is stalled.', 'How will you handle this?', 'உங்கள் குழுவின் பணிகளுக்கு முன்னுரிமை அளிக்கும் முறையை மாற்றும் ஒரு புதிய செயல்பாட்டு முறை அறிமுகப்படுத்தப்பட்டுள்ளது. முன்பு உங்கள் பொறுப்பில் இருந்த முடிவுகள், இப்போது பதினைந்து நாட்களுக்கு ஒருமுறை கூடும் ஒரு மைய முன்னுரிமைக் குழுவின் மூலம் எடுக்கப்படுகின்றன. உங்கள் குழு வேகமாகச் செயல்பட்டுப் பழக்கப்பட்டதாகும். நீங்கள் சமர்ப்பித்த முதல் மூன்று கோரிக்கைகளும் எந்தப் பதிலும் இன்றி மூன்று வாரங்களாக நிலுவையில் உள்ளன. ஒரு முக்கியமான பணி தடைபட்டுள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You escalate directly - you contact the committee lead, name the stalled requests, and ask for a decision timeline on the critical item.', 'நீங்கள் நேரடியாகப் பிரச்சினையை அடுத்த கட்டத்திற்கு எடுத்துச் செல்கிறீர்கள் - குழுத் தலைவரைத் தொடர்புகொண்டு, தேக்கமடைந்த கோரிக்கைகளைக் குறிப்பிட்டு, அந்த முக்கியமான விடயம் குறித்து முடிவெடுப்பதற்கான காலக்கெடுவைக் கேட்கிறீர்கள்.', 'D'),
  (2, 'You invest time in understanding how the committee works, who holds influence in it, and what gets things moved - then you use that knowledge before you escalate anything formally.', 'குழு எவ்வாறு செயல்படுகிறது, அதில் யாருக்கு செல்வாக்கு உள்ளது, மற்றும் எதனால் காரியங்கள் முன்னெடுக்கப்படுகின்றன என்பதைப் புரிந்துகொள்வதில் நீங்கள் நேரத்தைச் செலவிடுகிறீர்கள் - பின்னர், எந்தவொரு விஷயத்தையும் முறையாக மேல் அதிகாரிகளுக்குக் கொண்டு செல்வதற்கு முன்பு அந்த அறிவைப் பயன்படுத்துகிறீர்கள்.', 'I'),
  (3, 'You find a workaround for the critical item - you keep it moving through informal channels while the formal process catches up - and flag the bottleneck to your manager separately.', 'முக்கியமான விடயத்திற்கு நீங்கள் ஒரு மாற்று வழியைக் கண்டறிகிறீர்கள் - முறைசார்ந்த செயல்முறை அதைச் சரிசெய்யும் வரை, முறைசாரா வழிகள் மூலம் அதைத் தொடர்ந்து நகர்த்துகிறீர்கள் - மேலும், அந்தத் தேக்கநிலையை உங்கள் மேலாளரிடம் தனியாகச் சுட்டிக்காட்டுகிறீர்கள்.', 'S'),
  (4, 'You document the three pending requests, the dates submitted, the business impact of the delay, and bring a structured case to your manager asking for help unblocking the process.', 'நிலுவையில் உள்ள மூன்று கோரிக்கைகளையும், அவை சமர்ப்பிக்கப்பட்ட தேதிகளையும், தாமதத்தால் வணிகத்தில் ஏற்படும் தாக்கத்தையும் ஆவணப்படுத்தி, அந்தச் செயல்முறையில் உள்ள தடையை நீக்க உதவுமாறு உங்கள் மேலாளரிடம் ஒரு கட்டமைக்கப்பட்ட அறிக்கையைச் சமர்ப்பிக்கவும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q22',
     'Your organisation has brought in an external consultant to review your function''s structure and effectiveness. The consultant has been interviewing people across the team, including some of your direct reports, without telling you what they are asking or what the outputs will be. You have been told the review will conclude with recommendations that will be shared with your manager. You have not been interviewed yet.', 'How will you handle this?', 'உங்கள் நிறுவனத்தின் செயல்பாட்டுத் துறையின் கட்டமைப்பு மற்றும் செயல்திறனை ஆய்வு செய்வதற்காக, ஒரு வெளி ஆலோசகரை நியமித்துள்ளது. அந்த ஆலோசகர், என்ன கேள்விகளைக் கேட்கிறார் அல்லது அதன் முடிவுகள் என்னவாக இருக்கும் என்பதை உங்களுக்குத் தெரிவிக்காமல், உங்கள் கீழ் நேரடியாகப் பணியாற்றுபவர்கள் உட்பட, குழு முழுவதும் உள்ளவர்களை நேர்காணல் செய்து வருகிறார். இந்த ஆய்வு, உங்கள் மேலாளருடன் பகிரப்படும் பரிந்துரைகளுடன் முடிவடையும் என்று உங்களுக்குத் தெரிவிக்கப்பட்டுள்ளது. ஆனால், நீங்கள் இன்னும் நேர்காணல் செய்யப்படவில்லை.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a meeting with the consultant this week - you want to understand the scope of the review and ensure your perspective is part of the picture they are forming.', 'இந்த வாரம் ஆலோசகருடன் ஒரு சந்திப்பைக் கோருகிறீர்கள் - ஆய்வின் நோக்கத்தைப் புரிந்துகொள்ளவும், அவர்கள் உருவாக்கும் சித்திரத்தில் உங்கள் கண்ணோட்டமும் ஒரு பகுதியாக இருப்பதை உறுதிசெய்யவும் நீங்கள் விரும்புகிறீர்கள்.', 'D'),
  (2, 'You speak to your manager first - you want to understand what she has commissioned, what she is hoping to learn, and whether there is something specific driving the timing.', 'முதலில் உங்கள் மேலாளரிடம் பேசுங்கள் - அவர் என்ன பணியை ஒப்படைத்துள்ளார், என்ன கற்றுக்கொள்ள விரும்புகிறார், மேலும் இந்த காலக்கெடுவை நிர்ணயிப்பதற்கு ஏதேனும் குறிப்பிட்ட காரணம் உள்ளதா என்பதையும் நீங்கள் தெரிந்துகொள்ள வேண்டும்.', 'I'),
  (3, 'You let the process run and focus on ensuring your team feels steady - your job right now is to keep the work moving and not let the review create more anxiety than it already has.', 'நீங்கள் செயல்முறையை அதன் போக்கில் விட்டுவிட்டு, உங்கள் குழுவினர் நிம்மதியாக உணர்வதை உறுதி செய்வதில் கவனம் செலுத்துங்கள் - இப்போது உங்கள் வேலை, பணியைத் தொடர்ந்து முன்னெடுத்துச் செல்வதும், இந்த மதிப்பாய்வு ஏற்கெனவே ஏற்படுத்தியுள்ள பதற்றத்தை மேலும் அதிகரிக்க விடாமல் தடுப்பதும்தான்.', 'S'),
  (4, 'You prepare a clear picture of your function''s structure, outputs, and challenges before your interview, so that when it happens you are presenting an accurate and complete account rather than an improvised one.', 'உங்கள் நேர்காணலுக்கு முன்பாகவே, உங்கள் பணியின் கட்டமைப்பு, வெளியீடுகள் மற்றும் சவால்கள் குறித்த ஒரு தெளிவான சித்திரத்தை நீங்கள் தயார் செய்துகொள்கிறீர்கள். அப்போதுதான், நேர்காணல் நடக்கும்போது, ​​நீங்கள் மேம்போக்காகத் தயாரிக்கப்பட்ட ஒரு விவரத்திற்குப் பதிலாக, துல்லியமான மற்றும் முழுமையான ஒரு விளக்கத்தை அளிக்க முடியும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q23',
     'What matters more to you in this moment? A new senior leader has arrived and has made it clear she wants her team leads to bring her problems, not solutions - she wants to be involved earlier in the thinking. This is the opposite of how you have been operating for three years. One pull is to adapt fully and immediately - she is your new leader and her style is the style you work within now. The other pull is to adapt selectively - preserve the parts of your operating style that have made you effective while signalling openness to her approach.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? ஒரு புதிய மூத்த தலைவர் வந்துள்ளார். அவர் தனது குழுத் தலைவர்கள் தீர்வுகளை அல்ல, பிரச்சனைகளையே தன்னிடம் கொண்டு வர வேண்டும் என்பதைத் தெளிவாகக் கூறிவிட்டார் - அவர் சிந்தனையின் ஆரம்பத்திலேயே தன்னை ஈடுபடுத்திக்கொள்ள விரும்புகிறார். இது, கடந்த மூன்று ஆண்டுகளாக நீங்கள் செயல்பட்டு வந்த முறைக்கு முற்றிலும் நேர்மாறானது. ஒரு உந்துதல் என்னவென்றால், முழுமையாகவும் உடனடியாகவும் மாற்றியமைத்துக் கொள்வதுதான் - அவர் உங்கள் புதிய தலைவர், மேலும் அவரது பாணிதான் இப்போது நீங்கள் செயல்படும் பாணியாகும். மற்றொரு உந்துதல் என்னவென்றால், தேர்ந்தெடுத்து மாற்றியமைத்துக் கொள்வது - உங்களைத் திறம்படச் செயல்பட வைத்த உங்கள் செயல்பாட்டுப் பாணியின் பகுதிகளைப் பாதுகாத்துக் கொள்வதுடன், அவரது அணுகுமுறைக்குத் திறந்த மனதுடன் இருப்பதையும் வெளிப்படுத்துவது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Adapting fully matters more. You are not so attached to your style that you cannot change it when a new leader has been clear about what she needs.', 'முழுமையாகத் தழுவிக்கொள்வதே மிகவும் முக்கியம். ஒரு புதிய தலைவர் தனக்கு என்ன தேவை என்பதில் தெளிவாக இருக்கும்போது, ​​உங்கள் பாணியை மாற்ற முடியாத அளவுக்கு நீங்கள் அதனுடன் பிணைக்கப்படவில்லை.', 'D'),
  (2, 'The relationship matters most right now. You adapt visibly and quickly to what she has asked for, use the first few months to earn her trust, and then let your track record create room for your own style over time.', 'தற்போது உறவுதான் மிகவும் முக்கியம். அவள் கேட்டதற்கு ஏற்ப நீங்கள் வெளிப்படையாகவும் விரைவாகவும் உங்களை மாற்றிக்கொண்டு, முதல் சில மாதங்களை அவளது நம்பிக்கையைப் பெறப் பயன்படுத்திக்கொண்டு, பின்னர் காலப்போக்கில் உங்கள் முந்தைய செயல்பாடுகள் உங்களுக்கென ஒரு தனிப் பாணிக்கு வழிவிடட்டும்.', 'I'),
  (3, 'Preserving what works matters more. You bring problems earlier as she has asked, but you continue to think through solutions in parallel - you are not willing to become less effective in order to appear more collaborative.', 'பலனளிக்கும் விஷயங்களைப் பாதுகாப்பதே மிகவும் முக்கியம். அவர் கேட்டுக் கொண்டபடி நீங்கள் பிரச்சனைகளை முன்கூட்டியே கொண்டு வருகிறீர்கள், ஆனால் அதே நேரத்தில் தீர்வுகளையும் தொடர்ந்து சிந்திக்கிறீர்கள் - அதிக ஒத்துழைப்புடன் செயல்படுபவராகத் தோன்றுவதற்காக, உங்கள் செயல்திறனைக் குறைத்துக் கொள்ள நீங்கள் தயாராக இல்லை.', 'S'),
  (4, 'Understanding her reasoning matters most. Before you change how you work, you want to understand why she operates this way - what has driven this preference - so your adaptation is genuine rather than performative.', 'அவளுடைய காரணத்தைப் புரிந்துகொள்வது மிகவும் முக்கியம். நீங்கள் பணிபுரியும் விதத்தை மாற்றுவதற்கு முன், அவள் ஏன் இந்த வழியில் செயல்படுகிறாள் - இந்த விருப்பத்திற்கு என்ன காரணம் - என்பதை நீங்கள் புரிந்துகொள்ள வேண்டும். அப்போதுதான் உங்கள் மாற்றம் வெளிவேடமாக இல்லாமல் உண்மையானதாக இருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q24',
     'Before you respond to the all-staff survey that asks whether you feel confident in the organisation''s direction - before you calculate the right answer for a document that your manager may eventually see - what is actually happening inside you six months into a structural change that has not yet stabilised?', 'What is happening inside you?', 'நிறுவனத்தின் போக்கில் உங்களுக்கு நம்பிக்கை உள்ளதா எனக் கேட்கும் அனைத்து ஊழியர் கணக்கெடுப்பிற்குப் பதிலளிப்பதற்கு முன்பும், உங்கள் மேலாளர் இறுதியில் பார்க்கக்கூடிய ஒரு ஆவணத்திற்கான சரியான பதிலைக் கணக்கிடுவதற்கு முன்பும், இன்னும் நிலைபெறாத ஒரு கட்டமைப்பு மாற்றம் தொடங்கி ஆறு மாதங்கள் ஆன நிலையில், உங்களுக்குள் உண்மையில் என்னதான் நிகழ்ந்துகொண்டிருக்கிறது?', 'உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a genuine ambivalence. You can see the logic of the direction and you also see the gaps, and neither your confidence nor your doubt is complete. That is the honest answer.', 'ஒரு உண்மையான இருநிலை மனப்பான்மை நிலவுகிறது. அந்தத் திசையின் பின்னணியில் உள்ள தர்க்கத்தையும் உங்களால் காண முடிகிறது; அதிலுள்ள குறைபாடுகளையும் உங்களால் பார்க்க முடிகிறது. உங்கள் நம்பிக்கையும் சரி, சந்தேகமும் சரி, இரண்டும் முழுமையானவை அல்ல. அதுதான் நேர்மையான பதில்.', 'D'),
  (2, 'There is a careful political awareness. You know what the survey is for and you are making a considered choice about what to share in a format that is not as anonymous as it claims to be.', 'ஒரு கவனமான அரசியல் விழிப்புணர்வு இருக்கிறது. இந்தக் கணக்கெடுப்பு எதற்காக என்பதை நீங்கள் அறிவீர்கள்; மேலும், அது கூறிக்கொள்வது போல முற்றிலும் அநாமதேயமாக இல்லாத ஒரு வடிவத்தில், எதைப் பகிர்வது என்பது குறித்து நீங்கள் நன்கு யோசித்து ஒரு முடிவை எடுக்கிறீர்கள்.', 'I'),
  (3, 'There is a tiredness underneath the ambivalence. You want to feel confident. You remember what it felt like to feel confident about where this place was going. And the distance between that memory and today is something you have not fully processed.', 'அந்த இருநிலை மனப்பான்மைக்கு அடியில் ஒரு சோர்வு இருக்கிறது. நீங்கள் நம்பிக்கையுடன் உணர விரும்புகிறீர்கள். இந்த இடம் செல்லும் பாதை குறித்து நம்பிக்கையுடன் இருந்தபோது எப்படி உணர்ந்தீர்கள் என்பது உங்களுக்கு நினைவிருக்கிறது. அந்த நினைவிற்கும் இன்றைய நிலைக்கும் இடையிலான இடைவெளியை நீங்கள் இன்னும் முழுமையாக உள்வாங்கிக்கொள்ளவில்லை.', 'S'),
  (4, 'There is a strong need to separate what you know from what you feel - to give an answer that is grounded in evidence rather than mood - because you do not trust your own state right now to give an accurate read on the actual direction.', 'உங்களுக்குத் தெரிந்ததை உங்கள் உணர்வுகளிலிருந்து பிரித்துப் பார்க்க வேண்டிய வலுவான தேவை உள்ளது - மனநிலையை அடிப்படையாகக் கொண்டிராமல், சான்றுகளின் அடிப்படையில் ஒரு பதிலை அளிக்க வேண்டும் - ஏனெனில், உண்மையான போக்கைத் துல்லியமாகக் கணிக்கும் அளவுக்குத் தற்போதைய உங்கள் மனநிலையை நீங்கள் நம்புவதில்லை.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q25',
     'Your manager asks you to delay raising a team member''s formal grievance with HR by two weeks. Her reason is that a senior leader involved in the grievance is in the middle of a critical client negotiation and the timing would be damaging. The grievance involves a serious complaint about that leader''s conduct. The team member who raised it is already fragile.', 'How will you handle this?', 'ஒரு குழு உறுப்பினரின் முறையான புகாரை மனிதவளத் துறையிடம் தெரிவிப்பதை இரண்டு வாரங்களுக்குத் தாமதப்படுத்துமாறு உங்கள் மேலாளர் உங்களைக் கேட்டுக்கொள்கிறார். அதற்கான காரணம், அந்தப் புகாரில் சம்பந்தப்பட்ட ஒரு மூத்த தலைவர் ஒரு முக்கியமான வாடிக்கையாளர் பேச்சுவார்த்தையில் ஈடுபட்டுள்ளார் என்பதும், அவ்வாறு செய்வதற்கான நேரம் பாதிப்பை ஏற்படுத்தும் என்பதுமாகும். அந்தப் புகார், அந்தத் தலைவரின் நடத்தை குறித்த ஒரு கடுமையான குற்றச்சாட்டை உள்ளடக்கியுள்ளது. அதை எழுப்பிய குழு உறுப்பினர் ஏற்கெனவே மன உளைச்சலில் இருக்கிறார்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell your manager you are not able to delay a formal grievance at the expense of the person who raised it, and you proceed with the HR submission on the required timeline.', 'முறையீட்டை எழுப்பிய நபருக்குப் பாதிப்பு ஏற்படுத்தும் வகையில், முறையான புகாரைத் தாமதப்படுத்த உங்களால் இயலாது என்று உங்கள் மேலாளரிடம் கூறிவிட்டு, தேவைப்படும் காலக்கெடுவுக்குள் மனிதவளத் துறைக்கான சமர்ப்பிப்பைத் தொடர்கிறீர்கள்.', 'D'),
  (2, 'You ask HR directly - without naming the request - whether a two-week delay in submitting a formal grievance has any policy or legal implications, and you let that answer guide what you do next.', 'முறையான புகாரைச் சமர்ப்பிப்பதில் ஏற்படும் இரண்டு வாரத் தாமதத்திற்கு ஏதேனும் கொள்கை அல்லது சட்டரீதியான தாக்கங்கள் உள்ளதா என்று, கோரிக்கையின் பெயரைக் குறிப்பிடாமல், நீங்கள் மனிதவளத் துறையிடம் நேரடியாகக் கேட்டு, அந்தப் பதிலின் அடிப்படையில் உங்கள் அடுத்தகட்ட நடவடிக்கையை மேற்கொள்ளுங்கள்.', 'I'),
  (3, 'You tell your manager you will speak to the team member and let her decide whether she wants to delay - it is her grievance and the decision belongs to her, not to the organisation.', 'நீங்கள் அந்தக் குழு உறுப்பினரிடம் பேசி, அவர் தாமதப்படுத்த விரும்புகிறாரா என்பதை அவரே முடிவு செய்ய விடுவதாக உங்கள் மேலாளரிடம் கூறுங்கள் - அது அவருடைய குறை, அந்த முடிவு அவரிடமே உள்ளது, நிறுவனத்திடமல்ல.', 'S'),
  (4, 'You document your manager''s request - the reason given, the timing, the personnel involved - before you respond to it or act on it in any direction.', 'உங்கள் மேலாளரின் கோரிக்கைக்குப் பதிலளிப்பதற்கு அல்லது அதன் மீது எந்த நடவடிக்கையும் எடுப்பதற்கு முன்பு, அவர் கூறிய காரணம், நேரம், சம்பந்தப்பட்ட பணியாளர்கள் போன்ற விவரங்களை நீங்கள் ஆவணப்படுத்த வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q26',
     'You discover that one of your team members has been using a licensed software tool in a way that violates the vendor''s usage terms. The violation has been going on for four months. The team member believed the usage was permitted. You have been inadvertently benefiting from the outputs. The vendor has not yet flagged it.', 'How will you handle this?', 'உங்கள் குழு உறுப்பினர்களில் ஒருவர், உரிமம் பெற்ற மென்பொருள் கருவியை அதன் வழங்குநரின் பயன்பாட்டு விதிமுறைகளை மீறும் வகையில் பயன்படுத்தி வருவதை நீங்கள் கண்டறிகிறீர்கள். இந்த மீறல் நான்கு மாதங்களாகத் தொடர்ந்து வருகிறது. அந்தப் பயன்பாடு அனுமதிக்கப்பட்டது என்று அந்தக் குழு உறுப்பினர் நம்பியுள்ளார். அதன் வெளியீடுகளிலிருந்து நீங்கள் அறியாமலேயே பயனடைந்து வருகிறீர்கள். வழங்குநர் இன்னும் இதைக் குறித்துக் காட்டவில்லை.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You stop the usage immediately, disclose the violation to the relevant internal team - legal or procurement - and manage the conversation with the vendor proactively rather than waiting to be caught.', 'நீங்கள் பிடிபடுவதற்காகக் காத்திருக்காமல், பயன்பாட்டை உடனடியாக நிறுத்தி, சட்ட அல்லது கொள்முதல் போன்ற தொடர்புடைய உள் குழுவிடம் அந்த மீறலைத் தெரிவித்து, விற்பனையாளருடனான உரையாடலை முன்கூட்டியே கையாள வேண்டும்.', 'D'),
  (2, 'You speak to your team member first, understand the full picture, then decide together what the right disclosure path looks like before you go to anyone else.', 'வேறு யாரிடமும் செல்வதற்கு முன், முதலில் உங்கள் குழு உறுப்பினரிடம் பேசி, முழு நிலவரத்தையும் புரிந்துகொண்டு, சரியான தகவல் வெளிப்படுத்தும் வழிமுறை எது என்பதை ஒன்றாக முடிவு செய்யுங்கள்.', 'I'),
  (3, 'You stop the usage quietly, document that it has stopped, and monitor whether the vendor raises it before you decide whether proactive disclosure creates more risk than it resolves.', 'நீங்கள் அந்தப் பயன்பாட்டை அமைதியாக நிறுத்தி, அது நிறுத்தப்பட்டதை ஆவணப்படுத்தி, முன்கூட்டியே வெளிப்படுத்துவது தீர்ப்பதை விட அதிக ஆபத்தை உருவாக்குகிறதா என்று தீர்மானிப்பதற்கு முன், விற்பனையாளர் அதை மீண்டும் எழுப்புகிறாரா என்பதைக் கண்காணிக்க வேண்டும்.', 'S'),
  (4, 'You document the full history of the usage, the outputs generated, and the extent of the violation, then bring the complete picture to legal and let them determine the appropriate response.', 'பயன்பாட்டின் முழு வரலாறு, உருவாக்கப்பட்ட வெளியீடுகள் மற்றும் மீறலின் அளவு ஆகியவற்றை நீங்கள் ஆவணப்படுத்தி, பின்னர் அந்த முழுமையான விவரத்தையும் சட்டத்துறையிடம் சமர்ப்பித்து, பொருத்தமான நடவடிக்கையை அவர்களே தீர்மானிக்க விடுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q27',
     'The conflict you feel most is between institutional loyalty and personal integrity. You were in a meeting where a decision was made that you believe will harm a group of people - not catastrophically, but meaningfully and unnecessarily. You were not asked for your view. The decision has been made and is being implemented. One pull is to raise it through whatever channel is available - even belatedly, even if it changes nothing. The other pull is to implement your part of it professionally and absorb the discomfort privately.', 'What matters more to you?', 'நீங்கள் மிகவும் உணரும் முரண்பாடு, நிறுவன விசுவாசத்திற்கும் தனிப்பட்ட நேர்மைக்கும் இடையிலானது. நீங்கள் ஒரு கூட்டத்தில் இருந்தீர்கள், அங்கு எடுக்கப்பட்ட ஒரு முடிவு, ஒரு குழுவினருக்குத் தீங்கு விளைவிக்கும் என்று நீங்கள் நம்புகிறீர்கள் - அது பேரழிவாக அல்ல, ஆனால் குறிப்பிடத்தக்க வகையிலும் தேவையற்ற விதத்திலும். உங்கள் கருத்து கேட்கப்படவில்லை. அந்த முடிவு எடுக்கப்பட்டு, செயல்படுத்தப்பட்டு வருகிறது. ஒருபுறம், அது எந்த மாற்றத்தையும் ஏற்படுத்தாவிட்டாலும், தாமதமாகக் கூட, கிடைக்கக்கூடிய எந்த வழியின் மூலமாகவாவது அதை எழுப்ப வேண்டும் என்ற உந்துதல் உள்ளது. மறுபுறம், அதில் உங்கள் பங்கைத் தொழில்ரீதியாகச் செயல்படுத்தி, அந்த அசௌகரியத்தைத் தனிப்பட்ட முறையில் உள்வாங்கிக்கொள்ள வேண்டும் என்ற உந்துதல் உள்ளது.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "upward_courage", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Raising it matters more. You find the appropriate channel and put your concern on record, even if the decision does not change. You need to have said something.', 'அதை எழுப்புவதுதான் மிகவும் முக்கியம். முடிவில் மாற்றம் ஏற்படாவிட்டாலும், நீங்கள் பொருத்தமான வழியைக் கண்டறிந்து உங்கள் கவலையைப் பதிவு செய்ய வேண்டும். நீங்கள் ஏதேனும் சொல்லியிருக்க வேண்டும்.', 'D'),
  (2, 'Institutional loyalty wins in this instance. You implement your part professionally, voice your concern to your manager privately, and accept that some decisions are above your authority to change.', 'இந்தச் சூழலில் நிறுவனப் பற்று வெற்றி பெறுகிறது. நீங்கள் உங்கள் பங்கைத் தொழில்முறையாகச் செயல்படுத்துகிறீர்கள், உங்கள் கவலையை மேலாளரிடம் தனிப்பட்ட முறையில் தெரிவிக்கிறீர்கள், மேலும் சில முடிவுகளை மாற்றும் அதிகாரம் உங்களுக்கு இல்லை என்பதை ஏற்றுக்கொள்கிறீர்கள்.', 'I'),
  (3, 'The people who will be harmed matter most. You find a way to mitigate the impact within your own span of control, even if you cannot change the decision itself.', 'பாதிக்கப்படப்போகும் மக்களே மிகவும் முக்கியமானவர்கள். அந்த முடிவை உங்களால் மாற்ற முடியாவிட்டாலும், உங்கள் கட்டுப்பாட்டிற்குள் அதன் தாக்கத்தைக் குறைப்பதற்கான ஒரு வழியை நீங்கள் கண்டறிய வேண்டும்.', 'S'),
  (4, 'The record matters most. You document your concern formally - through a written note to your manager or through the appropriate feedback channel - not to stop the decision but to ensure your position is not ambiguous if this is revisited later.', 'பதிவு செய்வதுதான் மிகவும் முக்கியம். உங்கள் கவலையை நீங்கள் முறையாக ஆவணப்படுத்துவது - உங்கள் மேலாளருக்கு எழுத்துப்பூர்வமான குறிப்பு மூலமாகவோ அல்லது பொருத்தமான பின்னூட்ட வழிமுறை மூலமாகவோ - அந்த முடிவைத் தடுப்பதற்காக அல்ல, மாறாக, பிற்காலத்தில் இது மறுபரிசீலனை செய்யப்படும்போது உங்கள் நிலைப்பாடு தெளிவற்றதாக இருக்காமல் இருப்பதை உறுதி செய்வதற்காகவே ஆகும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q28',
     'The honest feeling underneath this - when your manager tells you that the compliance issue your team surfaced has been reviewed above and the decision is to handle it internally without external disclosure - is not simply about whether you agree with the decision. It is something more specific. You are sitting with it right now before you respond.', 'How will you handle this?', 'உங்கள் குழு வெளிப்படுத்திய இணக்கப் பிரச்சினை உயர் மட்டத்தில் மதிப்பாய்வு செய்யப்பட்டு, அதை வெளித் தகவல் ஏதுமின்றி நிறுவனத்திற்குள்ளேயே கையாள முடிவு செய்யப்பட்டுள்ளது என்று உங்கள் மேலாளர் உங்களிடம் கூறும்போது, ​​அதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்பது, நீங்கள் அந்த முடிவை ஏற்கிறீர்களா என்பதைப் பற்றியது மட்டுமல்ல. அது இன்னும் குறிப்பிட்ட ஒரு விஷயம். நீங்கள் பதிலளிப்பதற்கு முன்பு, அந்த முடிவை இப்போதே ஆழ்ந்து சிந்தித்துக் கொண்டிருக்கிறீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a clear discomfort that is also a clear line. You know what you can carry professionally and what you cannot, and this is sitting very close to that line.', 'ஒரு தெளிவான அசௌகரியம் இருக்கிறது, அதுவே ஒரு தெளிவான எல்லைக்கோடாகவும் உள்ளது. தொழில்ரீதியாக எதை உங்களால் கையாள முடியும், எதை முடியாது என்பது உங்களுக்குத் தெரியும், இது அந்த எல்லைக்கோட்டிற்கு மிக அருகில் இருக்கிறது.', 'D'),
  (2, 'There is a tiredness - not surprise, a tiredness - at the pattern of watching things get smoothed over rather than addressed, and the weight of being one of the people who keeps being asked to be smooth about it.', 'பிரச்சனைகள் கவனிக்கப்படாமல், அவை மூடிமறைக்கப்படுவதைப் பார்க்கும் போக்கினாலும், அதைப் பற்றி மென்மையாக நடந்துகொள்ளும்படி தொடர்ந்து கேட்கப்படும் நபர்களில் ஒருவராக இருப்பதன் பாரத்தினாலும் ஒருவித சோர்வு ஏற்படுகிறது - அது ஆச்சரியமல்ல, உண்மையான சோர்வு.', 'I'),
  (3, 'There is a genuine uncertainty. You do not know enough about the full picture - the legal landscape, the scale of the issue, the options that were actually considered - to know whether the decision is wrong or just uncomfortable.', 'ஒரு உண்மையான நிச்சயமற்ற தன்மை நிலவுகிறது. அந்த முடிவு தவறானதா அல்லது சங்கடமானதா என்பதை அறிந்துகொள்வதற்கு, சட்டச் சூழல், பிரச்சினையின் அளவு, உண்மையில் பரிசீலிக்கப்பட்ட தெரிவுகள் போன்ற முழுமையான விவரங்களைப் பற்றி உங்களுக்குப் போதுமான அளவு தெரியாது.', 'S'),
  (4, 'There is a strong need to understand exactly what was decided, by whom, and on what basis, because you will not carry accountability for an outcome you did not have full information about.', 'என்ன முடிவு எடுக்கப்பட்டது, யாரால், மற்றும் எந்த அடிப்படையில் எடுக்கப்பட்டது என்பதைத் துல்லியமாகப் புரிந்துகொள்வது மிகவும் அவசியமாகும். ஏனெனில், உங்களுக்கு முழுமையான தகவல் இல்லாத ஒரு முடிவுக்கு நீங்கள் பொறுப்பேற்க வேண்டியிருக்காது.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q29',
     'You are three slides into a presentation to a senior leadership panel when you realise the data on your second slide contains an error. It is not catastrophic but it is visible to anyone who knows the numbers. The panel has already moved on. You can correct it now, mid-presentation, or complete the presentation and address it at the end.', 'How to handle slide errors', 'மூத்த தலைமைத்துவக் குழுவிடம் நீங்கள் ஒரு விளக்கக்காட்சியை வழங்கிக் கொண்டிருக்கும்போது, ​​மூன்றாவது ஸ்லைடைக் காட்டியிருப்பீர்கள். அப்போது, ​​உங்கள் இரண்டாவது ஸ்லைடில் உள்ள தரவுகளில் ஒரு பிழை இருப்பதை உணர்கிறீர்கள். அது ஒன்றும் பெரிய பிழை அல்ல, ஆனால் எண்களை அறிந்த எவருக்கும் அது புலப்படும். குழுவினர் ஏற்கெனவே அடுத்த விஷயத்திற்குச் சென்றுவிட்டனர். நீங்கள் இப்போது, ​​விளக்கக்காட்சியின் நடுவிலேயே அதைத் திருத்தலாம், அல்லது விளக்கக்காட்சியை முழுமையாக முடித்துவிட்டு இறுதியில் அதைப் பற்றிப் பேசலாம்.', 'ஸ்லைடு பிழைகளை எவ்வாறு கையாள்வது',
     '{"theme": "", "layer": "Layer 1", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You stop and correct it immediately. You name it clearly, give the right number, and continue. Letting it sit is worse than the interruption.', 'நீங்கள் உடனடியாக நிறுத்தி அதைச் சரிசெய்ய வேண்டும். அதன் பெயரைத் தெளிவாகக் குறிப்பிட்டு, சரியான எண்ணைக் கொடுத்துவிட்டுத் தொடர வேண்டும். அதை அப்படியே விட்டுவிடுவது, குறுக்கீட்டை விட மோசமானது.', 'D'),
  (2, 'You complete the presentation and address the error in your closing remarks - you own it cleanly and provide the correct figure before the room has a chance to raise it.', 'நீங்கள் விளக்கக்காட்சியை நிறைவுசெய்து, உங்கள் முடிவுரையில் அந்தப் பிழையைச் சரிசெய்கிறீர்கள் - அதாவது, அதை வெளிப்படையாக ஏற்றுக்கொண்டு, சபையில் உள்ளவர்கள் அந்தப் பிழையை எழுப்புவதற்கு முன்பே சரியான எண்ணிக்கையை வழங்குகிறீர்கள்.', 'I'),
  (3, 'You complete the presentation, wait for questions, and correct it if the panel raises it. The error is minor and the interruption may do more damage than the mistake.', 'நீங்கள் விளக்கக்காட்சியை முடித்துவிட்டு, கேள்விகளுக்காகக் காத்திருந்து, குழுவினர் அதைக் கேட்டால் திருத்தவும். பிழை சிறியது, மேலும் அந்தத் தவறை விட குறுக்கீடு அதிக பாதிப்பை ஏற்படுத்தக்கூடும்.', 'S'),
  (4, 'You add a verbal footnote to the slide - you qualify the figure without flagging it as an error - and send a corrected version to all attendees within the hour after the session.', 'நீங்கள் ஸ்லைடில் ஒரு வாய்மொழி அடிக்குறிப்பைச் சேர்க்கிறீர்கள் - அதாவது, படத்தை ஒரு பிழையாகக் குறிப்பிடாமல் அதன் தகுதியை விளக்குகிறீர்கள் - மேலும் அமர்வு முடிந்த ஒரு மணி நேரத்திற்குள் திருத்தப்பட்ட பதிப்பை அனைத்துப் பங்கேற்பாளர்களுக்கும் அனுப்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q30',
     'Your team has done genuinely strong work this quarter but they are invisible to the senior leaders who matter. The work speaks for itself - to people who are paying attention. Most of the senior leaders are not. You have a thirty-minute slot in the next leadership forum and you need to decide how to use it.', 'How will you handle this?', 'இந்தக் காலாண்டில் உங்கள் குழு உண்மையிலேயே சிறப்பான பணியைச் செய்துள்ளது, ஆனால் முக்கியத்துவம் வாய்ந்த மூத்த தலைவர்களின் பார்வையில் அவர்கள் தென்படவில்லை. கவனிப்பவர்களுக்கு அந்தப் பணியே பேசும். ஆனால் பெரும்பாலான மூத்த தலைவர்கள் அப்படிச் செய்வதில்லை. அடுத்த தலைமைத்துவக் கருத்தரங்கில் உங்களுக்கு முப்பது நிமிட நேரம் ஒதுக்கப்பட்டுள்ளது, அதை எப்படிப் பயன்படுத்துவது என்று நீங்கள் முடிவு செய்ய வேண்டும்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "influence_style", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You use it to present the work directly - outputs, impact, what the team built - and trust that the quality is the case.', 'பணியின் வெளியீடுகள், அதன் தாக்கம், குழு உருவாக்கியவை போன்றவற்றை நேரடியாக முன்வைக்கவும், அதன் தரம் சிறப்பாக இருக்கும் என நம்பவும் நீங்கள் இதைப் பயன்படுத்துகிறீர்கள்.', 'D'),
  (2, 'You use it to tell the story of the work - the problem, the stakes, the team''s decisions under pressure, and the outcome - because the quality means nothing if the room does not feel it.', 'பணியின் கதையைச் சொல்ல நீங்கள் அதைப் பயன்படுத்துகிறீர்கள் - அதாவது, சிக்கல், அதில் உள்ள சவால்கள், அழுத்தத்தின் கீழ் குழுவின் முடிவுகள் மற்றும் அதன் விளைவு ஆகியவற்றை எடுத்துரைக்க. ஏனெனில், அந்தத் தரத்தை அங்கிருப்பவர்கள் உணரவில்லை என்றால், அதன் தரத்தால் எந்தப் பயனும் இல்லை.', 'I'),
  (3, 'You use it to connect the team''s work to the questions the senior leaders are currently asking - you make your team''s output relevant to what is already on their minds.', 'மூத்த தலைவர்கள் தற்போது கேட்டுக்கொண்டிருக்கும் கேள்விகளுடன் குழுவின் பணிகளை இணைக்க நீங்கள் இதைப் பயன்படுத்துகிறீர்கள் - அதாவது, அவர்களின் மனதில் ஏற்கனவே உள்ளவற்றுடன் உங்கள் குழுவின் வெளியீட்டைப் பொருத்தமானதாக ஆக்குகிறீர்கள்.', 'S'),
  (4, 'You use it to present a structured evidence pack - what was delivered, how it compares to targets, the methodology, the data - and leave nothing to interpretation.', 'வழங்கப்பட்டவை, அவை இலக்குகளுடன் எவ்வாறு ஒப்பிடப்படுகின்றன, வழிமுறை, தரவுகள் போன்றவற்றை உள்ளடக்கிய ஒரு கட்டமைக்கப்பட்ட ஆதாரத் தொகுப்பை முன்வைக்கவும், எதற்கும் விளக்கத்திற்கு இடமளிக்காமல் இருக்கவும் நீங்கள் இதைப் பயன்படுத்துகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q31',
     'Two things are pulling at you. Which is stronger? A senior leader has asked you a question in a public forum and you do not have a complete answer. One pull is to give the partial answer you have - confidently, clearly, and indicate you will follow up on the rest. The other pull is to fully acknowledge the gap - tell the room you will come back with a complete answer rather than giving something that might be wrong.', 'How will you handle this?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? ஒரு மூத்த தலைவர் பொதுக்கூட்டத்தில் உங்களிடம் ஒரு கேள்வியைக் கேட்டிருக்கிறார், ஆனால் உங்களிடம் அதற்கான முழுமையான பதில் இல்லை. ஒரு உந்துதல் என்னவென்றால், உங்களிடம் உள்ள பகுதிப் பதிலை நம்பிக்கையுடனும், தெளிவாகவும் கூறி, மீதமுள்ள பதிலை பின்னர் தெரிவிப்பதாகும். மற்றொரு உந்துதல் என்னவென்றால், அந்த இடைவெளியை முழுமையாக ஒப்புக்கொண்டு, தவறாக இருக்கக்கூடிய ஒரு பதிலைக் கொடுப்பதற்குப் பதிலாக, முழுமையான பதிலுடன் மீண்டும் வருவேன் என்று அங்கிருப்பவர்களிடம் கூறுவதாகும்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "decision_speed", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to give the partial answer is stronger. You know enough to be useful and a confident partial answer with a clear follow-up is more credible than a full deflection.', 'பகுதி பதிலை அளிப்பதற்கான உந்துதல் வலுவாக உள்ளது. பயனுள்ளதாக இருப்பதற்குத் தேவையான அளவு உங்களுக்குத் தெரியும், மேலும் முழுமையான திசைதிருப்பலை விட, தெளிவான தொடர் கேள்வியுடன் கூடிய நம்பிக்கையான பகுதி பதில் அதிக நம்பகத்தன்மை வாய்ந்தது.', 'D'),
  (2, 'The pull to acknowledge the gap is stronger. A wrong partial answer in this room does more damage than intellectual honesty, and you are comfortable saying you will come back with a complete picture.', 'இடைவெளியை ஒப்புக்கொள்ள வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. இந்த அறையில் அளிக்கப்படும் ஒரு தவறான, முழுமையற்ற பதில், அறிவுசார் நேர்மையை விட அதிக பாதிப்பை ஏற்படுத்தும்; மேலும், ஒரு முழுமையான சித்திரத்துடன் திரும்பி வருவேன் என்று நீங்கள் தயக்கமின்றிக் கூறுகிறீர்கள்.', 'I'),
  (3, 'The pull to buy time is strongest. You ask a clarifying question - not to avoid the answer but to ensure you are responding to what was actually asked - and use the pause to think.', 'நேரம் வாங்குவதற்கான உந்துதல் மிகவும் வலுவாக இருக்கும். நீங்கள் பதிலைத் தவிர்ப்பதற்காக அல்ல, மாறாக உண்மையில் கேட்கப்பட்ட கேள்விக்குத்தான் பதிலளிக்கிறீர்கள் என்பதை உறுதி செய்வதற்காக ஒரு தெளிவுபடுத்தும் கேள்வியைக் கேட்டு, அந்த இடைவெளியைச் சிந்திப்பதற்குப் பயன்படுத்திக் கொள்கிறீர்கள்.', 'S'),
  (4, 'The pull to qualify is strongest. You give what you know with explicit caveats about what you are confirming, so the room has your best current thinking without treating it as a final answer.', 'தகுதிப்படுத்த வேண்டும் என்ற உந்துதல் மிகவும் வலிமையானது. நீங்கள் உறுதிப்படுத்தும் விஷயங்களைப் பற்றிய தெளிவான நிபந்தனைகளுடன், உங்களுக்குத் தெரிந்ததை எடுத்துரைக்கிறீர்கள். அதனால், அதை ஒரு இறுதிப் பதிலாகக் கருதாமல், அந்த அறையில் உள்ளவர்கள் உங்களுடைய தற்போதைய சிறந்த சிந்தனையைப் பெறுகிறார்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q32',
     'Before you speak in the meeting where your team''s work will be evaluated alongside three other teams by the most senior leader you have presented to in this organisation - before you open your mouth - what is actually happening inside you?', 'What are you feeling now?', 'இந்த நிறுவனத்தில் நீங்கள் இதுவரை விளக்கமளித்ததிலேயே மிகவும் மூத்த தலைவரால், உங்கள் குழுவின் பணி மற்ற மூன்று குழுக்களுடன் சேர்த்து மதிப்பீடு செய்யப்படவிருக்கும் கூட்டத்தில் நீங்கள் பேசுவதற்கு முன்பு - உங்கள் வாயைத் திறப்பதற்கு முன் - உண்மையில் உங்கள் உள்ளுக்குள் என்னதான் நடக்கிறது?', 'நீங்கள் இப்போது என்ன உணர்கிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "approval_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'A focused readiness. You know the work. You trust the work. Whatever the outcome, you are walking in with the clearest possible account of what your team has done.', 'ஒருமுகப்படுத்தப்பட்ட தயார்நிலை. உங்களுக்குப் பணி தெரியும். அந்தப் பணியை நீங்கள் நம்புகிறீர்கள். முடிவு எதுவாக இருந்தாலும், உங்கள் குழு என்ன செய்துள்ளது என்பது குறித்த மிகத் தெளிவான அறிக்கையுடன் நீங்கள் களமிறங்குகிறீர்கள்.', 'D'),
  (2, 'An awareness of the room that is sharper than it should be - who is in it, how they are reading you before you have said anything, what impression is forming before the first slide.', 'இருக்க வேண்டியதை விடக் கூர்மையான ஓர் அறை குறித்த விழிப்புணர்வு - அதில் யார் இருக்கிறார்கள், நீங்கள் எதுவும் சொல்வதற்கு முன்பே அவர்கள் உங்களை எப்படிப் புரிந்துகொள்கிறார்கள், முதல் ஸ்லைடு வருவதற்கு முன்பே என்ன அபிப்பிராயம் உருவாகிறது என்பன போன்ற உணர்வுகள்.', 'I'),
  (3, 'A quiet wish that the work could simply speak for itself - that you did not have to perform it, frame it, sell it - that quality were enough on its own without the theatre around it.', 'அந்தப் படைப்பு தானாகவே பேசிக்கொள்ள வேண்டும் என்ற ஒரு மெல்லிய ஆசை; அதை நிகழ்த்திக் காட்டவோ, வடிவமைக்கவோ, விற்கவோ தேவையில்லை; அதைச் சுற்றியுள்ள ஆர்ப்பாட்டம் இல்லாமலேயே, அதன் தரம் மட்டுமே போதுமானதாக இருக்க வேண்டும்.', 'S'),
  (4, 'A specific anxiety about the two questions you cannot fully answer - the ones you know are coming, the ones where your data has a gap - and a running rehearsal of how to handle them without losing the room.', 'உங்களால் முழுமையாகப் பதிலளிக்க முடியாத இரண்டு கேள்விகளைப் பற்றிய ஒரு குறிப்பிட்ட பதற்றம் - அதாவது, வரப்போகின்றன என்று உங்களுக்குத் தெரிந்த, உங்கள் தரவுகளில் இடைவெளி உள்ள கேள்விகள் - மற்றும் முன்னிலையை இழக்காமல் அவற்றை எவ்வாறு கையாள்வது என்பது குறித்த ஒரு தொடர் ஒத்திகை.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q33',
     'A strong team member asks you for an honest assessment of his chances of being promoted in the next cycle. You know the likely answer is not positive - the organisation has been slow on promotions, his profile is not yet differentiated enough, and the cycle is four months away. He is asking you because he trusts you. A vague answer protects the relationship in the short term. A direct answer may unsettle him.', 'How will you give feedback?', 'ஒரு திறமையான குழு உறுப்பினர், அடுத்த பதவி உயர்வுச் சுற்றில் தனக்குப் பதவி உயர்வு கிடைப்பதற்கான வாய்ப்புகள் குறித்து ஒரு நேர்மையான மதிப்பீட்டை உங்களிடம் கேட்கிறார். அதற்கான பதில் சாதகமாக இருக்க வாய்ப்பில்லை என்பது உங்களுக்குத் தெரியும் - ஏனெனில், நிறுவனம் பதவி உயர்வுகளை வழங்குவதில் மெதுவாகச் செயல்படுகிறது, அவரது தகுதி இன்னும் போதுமான அளவு தனித்துவமாக இல்லை, மேலும் அந்தச் சுற்று இன்னும் நான்கு மாதங்களில் வரவிருக்கிறது. அவர் உங்களை நம்புவதால்தான் உங்களிடம் கேட்கிறார். ஒரு தெளிவற்ற பதில், குறுகிய காலத்திற்கு அந்த உறவைப் பாதுகாக்கும். ஒரு நேரடியான பதில் அவரை நிலைகுலையச் செய்யலாம்.', 'நீங்கள் எவ்வாறு கருத்து தெரிவிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "relationship_dependency", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You give him the honest picture - not brutal, but clear - because he asked for your honest assessment and giving him anything else is a disservice to the trust he has placed in you.', 'நீங்கள் அவரிடம் உண்மையை - கடுமையாக இல்லாமல், ஆனால் தெளிவாக - கூறுங்கள். ஏனெனில், அவர் உங்கள் நேர்மையான மதிப்பீட்டைக் கேட்டிருக்கிறார்; வேறு எதையும் அவருக்குக் கொடுப்பது, அவர் உங்கள் மீது வைத்துள்ள நம்பிக்கைக்குச் செய்யும் துரோகமாகும்.', 'D'),
  (2, 'You give him a conditional picture - you tell him what would need to be true for a strong case and let him draw his own conclusion about how close he is.', 'நீங்கள் அவருக்கு ஒரு நிபந்தனைக்குட்பட்ட சித்திரத்தை அளிக்கிறீர்கள் - ஒரு வலுவான வாதத்திற்கு என்னவெல்லாம் உண்மையாக இருக்க வேண்டும் என்று அவரிடம் கூறி, அவர் எவ்வளவு தூரம் நெருங்கி இருக்கிறார் என்பது குறித்த தனது சொந்த முடிவை அவரே எடுக்க விட்டுவிடுகிறீர்கள்.', 'I'),
  (3, 'You tell him what you genuinely believe, soften the timing concerns, and focus the conversation on what he can do between now and then to change the picture.', 'நீங்கள் உண்மையாக நம்புவதை அவரிடம் கூறுங்கள், காலக்கெடு குறித்த கவலைகளைத் தணித்து, இப்போது முதல் அப்போதுக்குள் நிலைமையை மாற்றுவதற்கு அவர் என்ன செய்ய முடியும் என்பதில் உரையாடலை மையப்படுத்துங்கள்.', 'S'),
  (4, 'You separate what you know from what you do not - you tell him directly where his profile is strong, where it has a gap, and what the promotion decision will likely turn on.', 'உங்களுக்குத் தெரிந்தவற்றையும் தெரியாதவற்றையும் பிரித்து, அவருடைய தகுதிகளில் எது வலுவாக இருக்கிறது, எது பலவீனமாக உள்ளது, மற்றும் பதவி உயர்வு முடிவு பெரும்பாலும் எதைப் பொறுத்து அமையும் என்பதை அவரிடம் நேரடியாகக் கூறுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q34',
     'Two of your team members are both strong individually but create friction every time they work together. It has been going on for seven months. You have spoken to each of them separately. The friction continues. You need them on the same project for the next three months - there is no organisational workaround.', 'How will you manage conflict?', 'உங்கள் குழு உறுப்பினர்களில் இருவர் தனித்தனியாகத் திறமையானவர்கள், ஆனால் அவர்கள் ஒன்றாகப் பணிபுரியும் ஒவ்வொரு முறையும் உரசல் ஏற்படுகிறது. இது ஏழு மாதங்களாகத் தொடர்கிறது. நீங்கள் அவர்கள் ஒவ்வொருவரிடமும் தனித்தனியாகப் பேசியுள்ளீர்கள். ஆனாலும், இந்த உரசல் தொடர்கிறது. அடுத்த மூன்று மாதங்களுக்கு அவர்கள் இருவரும் ஒரே திட்டத்தில் உங்களுக்குத் தேவைப்படுகிறார்கள் - இதற்கு நிறுவன ரீதியாக வேறு மாற்று வழி இல்லை.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "conflict_response", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell both of them directly that this project requires them to work together effectively, that the pattern so far has not been acceptable, and that you expect them to find a way - with your support - before the project begins.', 'இந்தத் திட்டத்திற்கு அவர்கள் இருவரும் திறம்பட இணைந்து பணியாற்ற வேண்டும் என்றும், இதுவரையிலான செயல்முறை ஏற்றுக்கொள்ளத்தக்கதாக இல்லை என்றும், திட்டம் தொடங்குவதற்கு முன்பாக உங்கள் ஆதரவுடன் அவர்கள் ஒரு வழியைக் கண்டுபிடிப்பார்கள் என எதிர்பார்ப்பதாகவும் அவர்கள் இருவரிடமும் நேரடியாகக் கூறுங்கள்.', 'D'),
  (2, 'You design the project so their work overlaps as little as possible - you minimise the touchpoints structurally so the friction has less surface to generate heat.', 'அவர்களின் பணிகள் முடிந்தவரை குறைவாக ஒன்றோடொன்று மேற்பொருந்தும்படி நீங்கள் திட்டத்தை வடிவமைக்கிறீர்கள் - அதாவது, உராய்வினால் வெப்பம் உருவாகுவதற்கான பரப்பு குறையும் வகையில், கட்டமைப்பு ரீதியாகத் தொடு புள்ளிகளைக் குறைக்கிறீர்கள்.', 'I'),
  (3, 'You run a joint conversation with both of them present - name the pattern, describe what you need from both of them, and create a shared commitment to a working agreement before the project starts.', 'திட்டம் தொடங்குவதற்கு முன், அவர்கள் இருவரும் முன்னிலையில் ஒரு கூட்டு உரையாடலை நடத்துங்கள் - செயல்முறையின் போக்கைக் குறிப்பிடுங்கள், அவர்கள் இருவரிடமிருந்தும் உங்களுக்கு என்ன தேவை என்பதை விவரியுங்கள், மேலும் ஒரு செயல்படும் ஒப்பந்தத்திற்கான பகிரப்பட்ட உறுதிப்பாட்டை உருவாக்குங்கள்.', 'S'),
  (4, 'You document the friction incidents from the past seven months and use the specifics in a conversation with each of them to ensure the discussion is grounded in observable behaviour rather than general tension.', 'கடந்த ஏழு மாதங்களில் நடந்த உரசல் சம்பவங்களை நீங்கள் ஆவணப்படுத்தி, அவர்களில் ஒவ்வொருவருடனும் நடத்தும் உரையாடலில் அந்தத் தகவல்களின் விவரங்களைப் பயன்படுத்துவதன் மூலம், அந்த உரையாடல் பொதுவான பதற்றத்தை அடிப்படையாகக் கொண்டிராமல், கண்கூடாகக் காணக்கூடிய நடத்தையை அடிப்படையாகக் கொண்டிருப்பதை உறுதிசெய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q35',
     'What matters more to you in this moment? A team member comes to you and says she has been approached about a role in another part of the organisation - a role that would be a genuine step up for her. She is asking for your honest view. One pull is to encourage her - she is ready and it is the right move for her career. The other pull is to be honest about the timing - losing her right now would significantly damage your team''s capacity and you are not sure you can rebuild quickly enough.', 'What matters more to you?', 'இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம்? ஒரு குழு உறுப்பினர் உங்களிடம் வந்து, நிறுவனத்தின் மற்றொரு பிரிவில் தனக்கு ஒரு பதவிக்கான அழைப்பு வந்திருப்பதாகவும், அது தனக்கு ஒரு உண்மையான முன்னேற்றப் படியாக இருக்கும் என்றும் கூறுகிறார். அவர் உங்கள் நேர்மையான கருத்தைக் கேட்கிறார். ஒரு உந்துதல் அவரை ஊக்குவிப்பதாகும் - அவர் தயாராக இருக்கிறார், மேலும் இது அவரது தொழில் வாழ்க்கைக்கு சரியான நகர்வு. மற்றொரு உந்துதல், சரியான நேரம் குறித்து நேர்மையாக இருப்பதாகும் - இந்த நேரத்தில் அவரை இழப்பது உங்கள் குழுவின் திறனைப் பெருமளவில் பாதிக்கும், மேலும் போதுமான வேகத்தில் உங்களால் மீண்டும் கட்டமைக்க முடியுமா என்பதும் உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "", "layer": "Layer 2", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Her development matters more. You give her your honest, positive assessment and help her put her best case forward, regardless of the timing for your team.', 'அவளுடைய வளர்ச்சிதான் மிகவும் முக்கியம். உங்கள் குழுவிற்கு நேரம் சாதகமாக இல்லாதபோதிலும், நீங்கள் அவளுக்கு உங்கள் நேர்மையான, நேர்மறையான மதிப்பீட்டை வழங்கி, அவள் தனது சிறந்த தரப்பை முன்வைக்க உதவுங்கள்.', 'D'),
  (2, 'Honesty about both matters most - you tell her she is ready, you also tell her your team situation honestly, and you let her make the decision with the full picture.', 'இந்த இரண்டு விஷயங்களிலும் நேர்மையாக இருப்பதுதான் மிக முக்கியம் - அவள் தயாராக இருக்கிறாள் என்று அவளிடம் சொல்லுங்கள், உங்கள் அணியின் நிலைமையையும் அவளிடம் நேர்மையாகத் தெரிவியுங்கள், மேலும் முழுமையான நிலவரத்தை அறிந்து அவளையே முடிவெடுக்க விடுங்கள்.', 'I'),
  (3, 'The team''s stability matters more right now. You are not dishonest, but you emphasise the timing challenges and suggest she consider whether this is the right moment.', 'தற்போது அணியின் ஸ்திரத்தன்மைதான் மிகவும் முக்கியம். நீங்கள் நேர்மையற்றவர் அல்ல, ஆனால் காலக்கட்டச் சவால்களை வலியுறுத்தி, இது சரியான தருணமா என்பதை அவர் பரிசீலிக்க வேண்டும் என்று பரிந்துரைக்கிறீர்கள்.', 'S'),
  (4, 'Getting the facts right matters most - you understand exactly what the other role involves before you give her any assessment, so your view is based on what she would actually be moving into.', 'உண்மைகளைச் சரியாக அறிந்துகொள்வதுதான் மிக முக்கியம் - அவருக்கு எந்த மதிப்பீட்டையும் வழங்குவதற்கு முன்பு, அவர் வகிக்கவிருக்கும் பணி என்னவென்பதை நீங்கள் துல்லியமாகப் புரிந்துகொள்ள வேண்டும், அப்போதுதான் உங்கள் பார்வை, அவர் உண்மையில் என்ன பணிக்குச் செல்லவிருக்கிறார் என்பதை அடிப்படையாகக் கொண்டிருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q36',
     'The honest feeling underneath this - when you realise the new joiner you championed in the hiring process is not working out and the team knows it before you have said anything officially - is not just a professional problem to solve. You are sitting with something more specific right now.', 'How do you handle this?', 'ஆள்சேர்ப்புச் செயல்பாட்டின்போது நீங்கள் பெரிதும் ஆதரித்த புதிய பணியாளர் சரியாகச் செயல்படவில்லை என்பதையும், நீங்கள் அதிகாரப்பூர்வமாக எதையும் கூறுவதற்கு முன்பே அது உங்கள் குழுவிற்குத் தெரிந்துவிட்டது என்பதையும் நீங்கள் உணரும்போது, ​​இதன் அடிநாதத்தில் இருக்கும் உண்மையான உணர்வு என்பது தீர்க்கப்பட வேண்டிய ஒரு தொழில்முறைப் பிரச்சனை மட்டுமல்ல. நீங்கள் தற்போது அதைவிடவும் ஒரு குறிப்பிட்ட பிரச்சனையுடன் இருக்கிறீர்கள்.', 'நீங்கள் இதை எப்படி கையாளுகிறீர்கள்?',
     '{"theme": "", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a clear ownership - you backed this person into this role and the outcome sits with you, and you are ready to carry that without deflection.', 'தெளிவான பொறுப்புணர்வு உள்ளது - நீங்கள் தான் இந்த நபரை இந்தப் பொறுப்பிற்கு கொண்டு வந்தீர்கள், அதன் விளைவு உங்களுடையது, அதை நீங்கள் சற்றும் பின்வாங்காமல் ஏற்கத் தயாராக இருக்கிறீர்கள்.', 'D'),
  (2, 'There is a guilt that is also a question - whether you saw what you wanted to see in the interview, whether the advocacy came from genuine assessment or from something less rigorous, and what that says about your judgment.', 'குற்றவுணர்ச்சி என்பது ஒரு கேள்வியும் கூடவே; நேர்காணலில் நீங்கள் காண விரும்பியதைக் கண்டீர்களா, உங்கள் வாதம் உண்மையான மதிப்பீட்டிலிருந்து வந்ததா அல்லது அவ்வளவு கண்டிப்பானதல்லாத ஒன்றிலிருந்து வந்ததா, மேலும் அது உங்கள் முடிவெடுக்கும் திறனைப் பற்றி என்ன சொல்கிறது என்பவைதான் அந்தக் கேள்விகள்.', 'I'),
  (3, 'There is a protectiveness sitting alongside the clarity. This person deserves a fair outcome, not to become the answer to your team''s frustration, and you are thinking about how to manage what comes next for them as much as for the team.', 'தெளிவுடன் கூடவே ஒருவித பாதுகாப்பு உணர்வும் இருக்கிறது. இந்த நபர் ஒரு நியாயமான முடிவுக்குத் தகுதியானவர், உங்கள் அணியின் விரக்திக்குத் தீர்வாக அவர் ஆகிவிடக்கூடாது. மேலும், அணியின் நலனுக்காகச் சிந்திப்பதைப் போலவே, அவருக்கான அடுத்தகட்ட நடவடிக்கைகளை எப்படி நிர்வகிப்பது என்பது குறித்தும் நீங்கள் சிந்திக்கிறீர்கள்.', 'S'),
  (4, 'There is a strong pull to understand the full picture before you do anything - whether the fit issues are about the person, the role, the onboarding, or some combination - because the action you take depends on the diagnosis being right.', 'பொருத்தமின்மைச் சிக்கல்கள் ஒரு நபரைப் பற்றியதா, பதவியைப் பற்றியதா, பணியில் சேர்ப்பதைப் பற்றியதா, அல்லது இவற்றின் கலவையைப் பற்றியதா என்பதைப் பொருட்படுத்தாமல், எதையும் செய்வதற்கு முன் முழுமையான சூழலைப் புரிந்துகொள்ள வேண்டிய ஒரு வலுவான உந்துதல் உள்ளது; ஏனெனில், கண்டறியப்பட்ட முடிவு சரியாக இருந்தால்தான் நீங்கள் எடுக்கும் நடவடிக்கை சாத்தியமாகும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q37',
     'You have realised that you spend the first forty-five minutes of every morning clearing other people''s urgencies before you get to your own work. It has been this way for a year. You are productive by other people''s measures. You are behind on everything that actually matters to you. You have a calendar review with yourself scheduled this Friday.', 'How will you prioritize work?', 'ஒவ்வொரு காலையிலும் முதல் நாற்பத்தைந்து நிமிடங்களை, உங்கள் சொந்த வேலைகளைத் தொடங்குவதற்கு முன் மற்றவர்களின் அவசர வேலைகளைத் தீர்ப்பதிலேயே செலவிடுகிறீர்கள் என்பதை நீங்கள் உணர்ந்திருக்கிறீர்கள். ஒரு வருடமாக இது இப்படியேதான் இருக்கிறது. மற்றவர்களின் அளவுகோல்களின்படி நீங்கள் செயல்திறன் மிக்கவராக இருக்கிறீர்கள். உங்களுக்கு உண்மையில் முக்கியமான எல்லாவற்றிலும் நீங்கள் பின்தங்கியிருக்கிறீர்கள். இந்த வெள்ளிக்கிழமை, உங்களுடனேயே ஒரு கால அட்டவணை மீளாய்வு செய்யத் திட்டமிட்டுள்ளீர்கள்.', 'பணிகளுக்கு எவ்வாறு முன்னுரிமை அளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "autonomy_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You block two hours of protected time every morning starting Monday - you do not ask for permission and you do not explain it. You just change the pattern.', 'திங்கட்கிழமை முதல் ஒவ்வொரு காலையிலும் இரண்டு மணி நேரப் பாதுகாக்கப்பட்ட நேரத்தை நீங்கள் ஒதுக்குகிறீர்கள் - நீங்கள் அனுமதி கேட்பதில்லை, அதற்கான விளக்கமும் அளிப்பதில்லை. உங்கள் வழக்கத்தை அப்படியே மாற்றுகிறீர்கள்.', 'D'),
  (2, 'You use Friday''s calendar review to map every recurring demand on your mornings and have explicit conversations with the key requesters about what can shift and what cannot.', 'உங்கள் காலைப் பொழுதுகளில் மீண்டும் மீண்டும் வரும் ஒவ்வொரு தேவையையும் பட்டியலிடவும், எதை மாற்றலாம், எதை மாற்ற முடியாது என்பது குறித்து முக்கிய கோரிக்கையாளர்களுடன் தெளிவான உரையாடல்களை நடத்தவும் வெள்ளிக்கிழமை காலண்டர் மதிப்பாய்வைப் பயன்படுத்துகிறீர்கள்.', 'I'),
  (3, 'You start smaller - you protect one morning a week for the next month, prove to yourself that the world does not end, and build from there.', 'சிறிய அளவில் தொடங்குங்கள் - அடுத்த மாதம் முழுவதும் வாரத்திற்கு ஒரு காலைப் பொழுதை ஒதுக்கி, உலகம் முடிந்துவிடுவதில்லை என்பதை உங்களுக்கு நீங்களே நிரூபித்து, அங்கிருந்து முன்னேறுங்கள்.', 'S'),
  (4, 'You map out exactly where the forty-five minutes go - which requests, from whom, how often, what they actually require - before you change anything, so you are restructuring based on evidence rather than instinct.', 'நீங்கள் எதையும் மாற்றுவதற்கு முன், அந்த நாற்பத்தைந்து நிமிடங்கள் எங்கே ஒதுக்கப்பட வேண்டும் - எந்தக் கோரிக்கைகள், யாரிடமிருந்து, எவ்வளவு அடிக்கடி, அவற்றுக்கு உண்மையில் என்ன தேவை என்பனவற்றையெல்லாம் - எனத் துல்லியமாகத் திட்டமிடுகிறீர்கள். இதன் மூலம், நீங்கள் உள்ளுணர்வின் அடிப்படையில் அல்லாமல், ஆதாரங்களின் அடிப்படையில் மறுசீரமைப்பு செய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q38',
     'You have been managing at high intensity for eleven months - a reorg, two difficult personnel situations, a critical delivery, and a team that has needed more from you than usual. You are functioning. You are not well. You have a quarterly review with your manager next week where you are expected to report on your team''s performance and your plans for the next quarter.', 'How will you handle burnout?', 'கடந்த பதினொரு மாதங்களாக நீங்கள் மிகுந்த தீவிரத்துடன் நிர்வகித்து வருகிறீர்கள் - ஒரு மறுசீரமைப்பு, இரண்டு சிக்கலான பணியாளர் சூழ்நிலைகள், ஒரு முக்கியமான செயல்திட்டம், மற்றும் வழக்கத்தை விட உங்களிடமிருந்து அதிக உழைப்பைக் கோரிய ஒரு குழு. நீங்கள் செயல்படுகிறீர்கள். ஆனால், நீங்கள் நலமாக இல்லை. அடுத்த வாரம் உங்கள் மேலாளருடன் உங்களுக்கு ஒரு காலாண்டு ஆய்வு உள்ளது. அதில், உங்கள் குழுவின் செயல்திறன் மற்றும் அடுத்த காலாண்டிற்கான உங்கள் திட்டங்கள் குறித்து நீங்கள் அறிக்கை அளிக்க வேண்டும் என எதிர்பார்க்கப்படுகிறது.', 'மனச்சோர்வை நீங்கள் எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "", "layer": "Layer 1", "dimension": "stability_need", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell your manager the truth in the review - that you have been operating at unsustainable intensity and you need to have an honest conversation about capacity before you commit to the next quarter.', 'மதிப்பாய்வின்போது உங்கள் மேலாளரிடம் உண்மையைச் சொல்லுங்கள் - அதாவது, நீங்கள் தாங்க முடியாத தீவிரத்தில் இயங்கி வருகிறீர்கள் என்றும், அடுத்த காலாண்டிற்கு ஒப்புக்கொள்வதற்கு முன்பு திறன் குறித்து ஒரு நேர்மையான உரையாடல் நடத்த வேண்டும் என்றும் கூறுங்கள்.', 'D'),
  (2, 'You deliver the review professionally and find a separate moment - before or after - to have the personal conversation about sustainability privately rather than mixing it into the performance discussion.', 'நீங்கள் மதிப்பாய்வைத் தொழில்முறையாக வழங்குவதோடு, செயல்திறன் விவாதத்தில் நிலைத்தன்மையைக் கலக்காமல், அதற்கு முன்னரோ பின்னரோ ஒரு தனித் தருணத்தில் அதுகுறித்த தனிப்பட்ட உரையாடலைத் தனியாக நடத்துங்கள்.', 'I'),
  (3, 'You deliver the review fully and manage the sustainability concern yourself - you have a plan for the next quarter that includes recovery time and you do not need to make it your manager''s problem.', 'மதிப்பாய்வை முழுமையாக சமர்ப்பித்து, நிலைத்தன்மை தொடர்பான கவலையை நீங்களே நிர்வகிக்கவும் - அடுத்த காலாண்டிற்கான மீட்பு நேரத்தையும் உள்ளடக்கிய ஒரு திட்டம் உங்களிடம் உள்ளது, மேலும் அதை உங்கள் மேலாளரின் பிரச்சனையாக மாற்ற வேண்டிய அவசியமில்லை.', 'S'),
  (4, 'You prepare for the review with a structured picture of what the last eleven months have required - the scope, the demands, the intensity - so that if you raise the sustainability concern it is grounded in evidence, not just a feeling.', 'கடந்த பதினொரு மாதங்களில் என்னென்ன தேவைப்பட்டன - அதன் வீச்சு, கோரிக்கைகள், தீவிரம் - என்பது குறித்த ஒரு கட்டமைக்கப்பட்ட சித்திரத்துடன் நீங்கள் மதிப்பாய்வுக்குத் தயாராகிறீர்கள். அப்போதுதான், நீங்கள் நிலைத்தன்மை குறித்த கவலையை எழுப்பும்போது, ​​அது வெறும் உணர்வாக இல்லாமல், ஆதாரங்களின் அடிப்படையில் அமைந்திருக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q39',
     'Two things are pulling at you. Which is stronger? You have been managing people for six years and you are increasingly aware that the parts of the job you find most meaningful are not the management parts. You are good at the people leadership. You are not sure it is what you want to be good at forever. One pull is to follow the meaning - understand what it is pointing toward and begin moving in that direction. The other pull is to stay the course - you are building toward something real here and abandoning it based on a feeling is not a strategy.', 'Which pull is stronger here?', 'இரண்டு விஷயங்கள் உங்களை ஈர்க்கின்றன. அவற்றில் எது வலிமையானது? நீங்கள் ஆறு ஆண்டுகளாக மக்களை நிர்வகித்து வருகிறீர்கள், மேலும் இந்த வேலையில் நிர்வாகப் பகுதிகள் அல்ல, மாறாக வேறு சில பகுதிகளே உங்களுக்கு மிகவும் அர்த்தமுள்ளதாகத் தோன்றுகின்றன என்பதை நீங்கள் அதிகமாக உணர்கிறீர்கள். நீங்கள் மக்கள் தலைமைத்துவத்தில் சிறந்தவர். ஆனால், என்றென்றும் அதில் சிறந்து விளங்க விரும்புகிறீர்களா என்பது உங்களுக்கு உறுதியாகத் தெரியவில்லை. ஒரு ஈர்ப்பு, அதன் அர்த்தத்தைப் பின்பற்றுவது - அது எதைச் சுட்டிக்காட்டுகிறது என்பதைப் புரிந்துகொண்டு, அந்தத் திசையில் நகரத் தொடங்குவது. மற்றொரு ஈர்ப்பு, நீங்கள் செல்லும் பாதையிலேயே தொடர்ந்து செல்வது - நீங்கள் இங்கே ஒரு உண்மையான விஷயத்தை நோக்கிப் பயணிக்கிறீர்கள், ஒரு உணர்வின் அடிப்படையில் அதைக் கைவிடுவது ஒரு உத்தி அல்ல.', 'இங்கு எந்த ஈர்ப்பு விசை வலிமையானது?',
     '{"theme": "", "layer": "Layer 2", "dimension": "career_patience", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The pull to follow the meaning is stronger. Six years is long enough to know the difference between a passing dissatisfaction and a signal about direction, and this feels like a signal.', 'அதன் அர்த்தத்தைப் பின்தொடர வேண்டும் என்ற ஈர்ப்பு வலுவாக உள்ளது. ஒரு தற்காலிக அதிருப்திக்கும், ஒரு திசையைக் காட்டும் சமிக்ஞைக்கும் இடையிலான வேறுபாட்டை அறிந்துகொள்ள ஆறு ஆண்டுகள் என்பது போதுமான காலமாகும், மேலும் இது ஒரு சமிக்ஞை போலவே தோன்றுகிறது.', 'D'),
  (2, 'The relational pull is stronger - the people you are responsible for, the team you have built, the thing you are in the middle of - they are real and they matter and you are not ready to step away from them based on a question you have not fully answered yet.', 'உறவுகளின் ஈர்ப்பு வலிமையானது - நீங்கள் பொறுப்பேற்றிருக்கும் நபர்கள், நீங்கள் உருவாக்கிய குழு, நீங்கள் ஈடுபட்டிருக்கும் விஷயம் - இவை உண்மையானவை, முக்கியமானவை, மேலும் நீங்கள் இன்னும் முழுமையாக விடை காணாத ஒரு கேள்வியின் அடிப்படையில் அவற்றிடமிருந்து விலகிச் செல்லத் தயாராக இல்லை.', 'I'),
  (3, 'The pull to stay the course is stronger. Meaning is not always present and its absence is not always information. You have built something real here and you are going to see it through before you make any decisions.', 'பாதையில் தொடர்ந்து பயணிக்க வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. அர்த்தம் எப்போதும் இருப்பதில்லை, அதன் இல்லாமை எப்போதும் தகவலாக இருப்பதில்லை. நீங்கள் இங்கே ஒரு உண்மையான விஷயத்தைக் கட்டமைத்துள்ளீர்கள், எந்த முடிவுகளையும் எடுப்பதற்கு முன்பு அதை முழுமையாகச் செய்து முடிக்கப் போகிறீர்கள்.', 'S'),
  (4, 'The pull to understand the signal first is stronger. You want to know what the dissatisfaction is actually pointing toward before you act on it - whether it is the function, the level, the organisation, or something more fundamental about the kind of work you want to be doing.', 'முதலில் அந்த சமிக்ஞையைப் புரிந்துகொள்ள வேண்டும் என்ற உந்துதல் வலுவாக உள்ளது. நீங்கள் அதன் மீது நடவடிக்கை எடுப்பதற்கு முன், அந்த அதிருப்தி உண்மையில் எதைச் சுட்டிக்காட்டுகிறது என்பதைத் தெரிந்துகொள்ள விரும்புகிறீர்கள் - அது உங்கள் பணி, பதவி நிலை, அமைப்பு அல்லது நீங்கள் செய்ய விரும்பும் வேலையின் தன்மை குறித்த மிகவும் அடிப்படையான விஷயமாக இருக்கலாம்.', 'C')
) AS v(ord, en, ta, fac);

-- Medium Set 2 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Medium', 'EMP-MED-S2-Q40',
     'Before you answer your manager''s question about where you see yourself in three years - before you give the version that is ambitious enough to show drive but measured enough to seem grounded - what is actually happening inside you right now, in this seat, in this organisation, today?', 'What is happening inside you?', 'மூன்று ஆண்டுகளில் உங்களை எங்கே காண்கிறீர்கள் என்ற உங்கள் மேலாளரின் கேள்விக்குப் பதிலளிப்பதற்கு முன் - உங்கள் உந்துதலைக் காட்டும் அளவுக்கு லட்சியமாகவும், அதே சமயம் யதார்த்தமாகத் தோன்றும் அளவுக்கு நிதானமாகவும் இருக்கும் பதிலைக் கூறுவதற்கு முன் - உண்மையில் இப்போது, ​​இந்த இருக்கையில், இந்த நிறுவனத்தில், இன்று உங்களுக்குள் என்னதான் நடந்து கொண்டிருக்கிறது?', 'உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "", "layer": "Layer 3", "dimension": "role_ambiguity_tolerance", "board": "Medium", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'There is a genuine answer underneath the rehearsed one, and it is not that different from what you are about to say. You are more aligned than the caution of this moment makes you feel.', 'ஒத்திகை பார்க்கப்பட்ட பதிலுக்கு அடியில் ஒரு உண்மையான பதில் இருக்கிறது; அது நீங்கள் இப்போது சொல்லப்போவதிலிருந்து பெரிதும் வேறுபட்டதல்ல. இந்தத் தருணத்தின் எச்சரிக்கை உணர்வு உங்களுக்கு ஏற்படுத்துவதை விட, நீங்கள் சரியான பாதையிலேயே இருக்கிறீர்கள்.', 'D'),
  (2, 'There is an honesty you are managing carefully - you do not know where you see yourself in three years and the performance of certainty in this conversation is something you are slightly tired of giving.', 'நீங்கள் நேர்மையை மிகவும் கவனமாகக் கையாளுகிறீர்கள் - இன்னும் மூன்று ஆண்டுகளில் நீங்கள் எங்கே இருப்பீர்கள் என்று உங்களுக்கே தெரியாது, மேலும் இந்த உரையாடலில் உறுதியைக் காட்டுவது போல் நடிப்பதில் நீங்கள் சற்றே சோர்வடைந்துவிட்டீர்கள்.', 'I'),
  (3, 'There is a question sitting underneath the ambition - whether three years here is actually what you want or whether the answer you are about to give is the answer this room expects from someone who wants to stay and be taken seriously.', 'அந்த லட்சியத்தின் அடியில் ஒரு கேள்வி அடங்கியுள்ளது - இங்கு மூன்று ஆண்டுகள் இருப்பதுதான் உண்மையில் உங்கள் விருப்பமா, அல்லது நீங்கள் அளிக்கப்போகும் பதில், இங்கு தங்கி மதிக்கப்பட விரும்பும் ஒருவரிடமிருந்து இந்த அறை எதிர்பார்க்கும் பதிலா என்பதுதான் அது.', 'S'),
  (4, 'There is a specific frustration - not at your manager, at the question itself - because three-year plans in organisations that change this fast feel like a ritual with no real information value, and you are about to participate in it anyway.', 'ஒரு குறிப்பிட்ட விரக்தி இருக்கிறது - அது உங்கள் மேலாளர் மீதல்ல, மாறாக அந்தக் கேள்வி மீதே - ஏனென்றால், இவ்வளவு வேகமாக மாறும் நிறுவனங்களில் உள்ள மூன்றாண்டுத் திட்டங்கள், உண்மையான தகவல் மதிப்பு ஏதுமில்லாத ஒரு சடங்கு போலத் தோன்றுகின்றன, மேலும் நீங்கள் எப்படியும் அதில் பங்கேற்கப் போகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- ============================================================
-- Sheet 'Level 3' -> board 'Executive'
-- ============================================================
-- Executive Set 1 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q1',
     'You are presenting the annual strategy to the board when a non-executive director interrupts mid-presentation and publicly questions the credibility of your market assumptions. Three other board members lean forward. The room shifts. Your CFO looks at you waiting for your lead.', 'How will you handle conflict?', 'நீங்கள் இயக்குநர்கள் குழுவிடம் ஆண்டுத் திட்டத்தை முன்வைத்துக் கொண்டிருக்கும்போது, ​​ஒரு செயல்சாரா இயக்குநர் விளக்கக்காட்சியின் நடுவே குறுக்கிட்டு, உங்கள் சந்தை அனுமானங்களின் நம்பகத்தன்மையை பகிரங்கமாகக் கேள்விக்குள்ளாக்குகிறார். மற்ற மூன்று இயக்குநர்கள் குழு உறுப்பினர்கள் முன்னோக்கிச் சாய்கிறார்கள். அறை அதிர்கிறது. உங்கள் தலைமை நிதி அதிகாரி, நீங்கள் என்ன சொல்வீர்கள் என்று எதிர்பார்த்து உங்களைப் பார்க்கிறார்.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 1", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You address the challenge directly and firmly, redirecting the board back to the strategic logic without ceding control of the room.', 'நீங்கள் சவாலை நேரடியாகவும் உறுதியாகவும் எதிர்கொண்டு, அறையின் கட்டுப்பாட்டை இழக்காமல், நிர்வாகக் குழுவை மீண்டும் வியூக ரீதியான தர்க்கத்திற்குத் திருப்புகிறீர்கள்.', 'D'),
  (2, 'You acknowledge the director''s concern warmly, invite others to share their perspective, and use the energy in the room to build broader engagement.', 'இயக்குநரின் அக்கறையை நீங்கள் மனப்பூர்வமாக ஏற்றுக்கொண்டு, மற்றவர்களையும் தங்கள் கண்ணோட்டத்தைப் பகிர்ந்துகொள்ள அழைத்து, அந்த அறையில் நிலவும் ஆற்றலைப் பயன்படுத்தி பரந்த ஈடுபாட்டை உருவாக்குகிறீர்கள்.', 'I'),
  (3, 'You pause, thank the director for raising it, and suggest a focused discussion after the presentation to give it the depth it deserves.', 'நீங்கள் சற்று நிறுத்தி, அதை எழுப்பியதற்காக இயக்குநருக்கு நன்றி கூறி, அதற்குத் தகுந்த ஆழத்தை அளிப்பதற்காக விளக்கக்காட்சிக்குப் பிறகு ஒரு செறிவான கலந்துரையாடலைப் பரிந்துரைக்கிறீர்கள்.', 'S'),
  (4, 'You ask the director to specify which assumptions they are questioning and request that the discussion be grounded in the data before you.', 'அவர்கள் எந்த அனுமானங்களைக் கேள்விக்குட்படுத்துகிறார்கள் என்பதைக் குறிப்பிடுமாறு இயக்குநரிடம் நீங்கள் கேட்கிறீர்கள், மேலும் அந்த விவாதம் உங்கள் முன் உள்ள தரவுகளின் அடிப்படையில் அமைய வேண்டும் என்றும் கோருகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q2',
     'Your company is three weeks from closing a significant acquisition. An independent board member privately tells you she has concerns about the cultural fit and wants to table the deal at the next board meeting. You have already briefed investors and the integration team is mobilised.', 'How will you handle this?', 'உங்கள் நிறுவனம் ஒரு முக்கியமான கையகப்படுத்தலை நிறைவு செய்வதற்கு இன்னும் மூன்று வாரங்களே உள்ளன. ஒரு சுயாதீன இயக்குநர் குழு உறுப்பினர், நிறுவனத்தின் கலாச்சாரப் பொருத்தம் குறித்து தனக்குக் கவலைகள் இருப்பதாகவும், அடுத்த இயக்குநர் குழுக் கூட்டத்தில் இந்த ஒப்பந்தத்தை முன்வைக்க விரும்புவதாகவும் உங்களிடம் தனிப்பட்ட முறையில் கூறுகிறார். நீங்கள் ஏற்கெனவே முதலீட்டாளர்களுக்கு இதுகுறித்து விளக்கமளித்துவிட்டீர்கள், மேலும் ஒருங்கிணைப்புக் குழுவும் களமிறக்கப்பட்டுள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 1", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You meet with her before the board meeting, make your case directly, and if needed call an informal board conversation to resolve it before it becomes a formal motion.', 'வாரியக் கூட்டத்திற்கு முன்பு நீங்கள் அவரைச் சந்தித்து, உங்கள் தரப்பை நேரடியாக எடுத்துரைத்து, தேவைப்பட்டால் அது ஒரு முறையான தீர்மானமாக மாறுவதற்கு முன்பே தீர்ப்பதற்காக ஒரு முறைசாரா வாரியக் கலந்துரையாடலைக் கூட்டவும்.', 'D'),
  (2, 'You invest time understanding her specific concerns, bring her into the inner circle of the integration planning, and work to convert her from skeptic to advocate.', 'அவருடைய குறிப்பிட்ட கவலைகளைப் புரிந்துகொள்வதற்கு நீங்கள் நேரம் ஒதுக்கி, ஒருங்கிணைப்புத் திட்டமிடலின் உள்வட்டத்தில் அவரை இணைத்துக்கொண்டு, அவரைச் சந்தேகவாதியிலிருந்து ஆதரவாளராக மாற்றப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You slow down, take her concerns seriously, and propose a 30-day integration readiness review before proceeding - even if it delays the deal.', 'நீங்கள் நிதானித்து, அவருடைய கவலைகளைக் கவனமாகக் கருத்தில் கொண்டு, ஒப்பந்தம் தாமதமானாலும் கூட, அடுத்தகட்ட நடவடிக்கைக்கு முன் 30 நாள் ஒருங்கிணைப்புத் தயார்நிலை மதிப்பாய்வை முன்மொழியுங்கள்.', 'S'),
  (4, 'You commission an independent cultural assessment report and present it at the board meeting with structured evidence addressing each of her concerns.', 'நீங்கள் ஒரு சுயாதீனமான கலாச்சார மதிப்பீட்டு அறிக்கையைத் தயாரிக்கப் பணித்து, அவருடைய ஒவ்வொரு கவலையையும் நிவர்த்தி செய்யும் கட்டமைக்கப்பட்ட ஆதாரங்களுடன் அதனை வாரியக் கூட்டத்தில் சமர்ப்பிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q3',
     'An activist investor has acquired a 7% stake and is publicly demanding board representation and a strategic pivot away from your core business. The chairman calls you before the board meeting and says the board is divided. Half want to engage. Half want to resist.What matters more to you in this moment - protecting the strategic direction you have built over three years, or maintaining board cohesion even if it means opening the door to an agenda you do not believe in?', 'How will you handle conflict?', 'ஒரு செயல்பாட்டாளர் முதலீட்டாளர் 7% பங்குகளை வாங்கியுள்ளார். அவர், நிர்வாகக் குழுவில் தனக்குப் பிரதிநிதித்துவம் வேண்டும் என்றும், உங்கள் முக்கியத் தொழிலிலிருந்து விலகி ஒரு மூலோபாய மாற்றத்தை மேற்கொள்ள வேண்டும் என்றும் பகிரங்கமாகக் கோருகிறார். நிர்வாகக் குழு கூட்டத்திற்கு முன்பு தலைவர் உங்களை அழைத்து, குழு பிளவுபட்டுள்ளதாகக் கூறுகிறார். பாதிப் பேர் கலந்துரையாட விரும்புகிறார்கள். மீதிப் பேர் எதிர்க்க விரும்புகிறார்கள். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம் - மூன்று ஆண்டுகளாக நீங்கள் கட்டமைத்த மூலோபாய திசையைப் பாதுகாப்பதா, அல்லது நீங்கள் நம்பாத ஒரு செயல்திட்டத்திற்கு வழி திறந்தாலும் கூட, நிர்வாகக் குழுவின் ஒற்றுமையைப் பேணுவதா?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 2", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Protecting the strategy. You will not compromise a three-year vision because of short-term investor pressure.', 'வியூகத்தைப் பாதுகாத்தல். குறுகிய கால முதலீட்டாளர் அழுத்தத்திற்காக, மூன்றாண்டுத் தொலைநோக்குப் பார்வையில் நீங்கள் சமரசம் செய்துகொள்ள மாட்டீர்கள்.', 'D'),
  (2, 'Maintaining relationships. A divided board is more dangerous than a difficult investor and you will work to find common ground.', 'உறவுகளைப் பேணுதல். ஒரு சிக்கலான முதலீட்டாளரை விட, பிளவுபட்ட நிர்வாகக் குழு மிகவும் ஆபத்தானது; எனவே, நீங்கள் ஒரு பொதுவான உடன்பாட்டைக் கண்டறியப் பாடுபடுவீர்கள்.', 'I'),
  (3, 'Preserving stability. You would rather make a measured concession now than allow the conflict to destabilise the organisation.', 'நிலைத்தன்மையைப் பாதுகாத்தல். மோதல் அமைப்பைச் சீர்குலைப்பதை அனுமதிப்பதை விட, இப்போது நிதானமான ஒரு விட்டுக்கொடுப்பைச் செய்வதே சிறந்தது.', 'S'),
  (4, 'Getting the facts right. You want a thorough analysis of the investor''s demands before the board takes any position at all.', 'உண்மைகளைச் சரியாக அறிந்துகொள்வது. நிர்வாகக் குழு எந்தவொரு நிலைப்பாட்டையும் எடுப்பதற்கு முன்பாகவே, முதலீட்டாளரின் கோரிக்கைகள் குறித்து ஒரு முழுமையான பகுப்பாய்வு தேவை.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q4',
     'The audit committee has received a whistleblower complaint about financial reporting practices in one of your business units. The complaint names a senior leader who reports directly to you. The committee chair has asked you to respond formally within 72 hours.Before you say anything to the committee or your team - what is actually happening inside you when you read that complaint for the first time?', 'How will you handle this?', 'உங்கள் வணிகப் பிரிவுகளில் ஒன்றில் உள்ள நிதி அறிக்கை நடைமுறைகள் குறித்து, தணிக்கைக் குழுவுக்கு ஒரு முறைகேடு அம்பலப்படுத்துபவரின் புகார் வந்துள்ளது. அந்தப் புகாரில், உங்களுக்கு நேரடியாகக் கீழ் பணிபுரியும் ஒரு மூத்த தலைவரின் பெயர் குறிப்பிடப்பட்டுள்ளது. 72 மணி நேரத்திற்குள் முறையாகப் பதிலளிக்குமாறு குழுவின் தலைவர் உங்களைக் கேட்டுள்ளார். குழுவிடமோ அல்லது உங்கள் அணியிடமோ நீங்கள் எதையும் கூறுவதற்கு முன்பு - அந்தப் புகாரை நீங்கள் முதல் முறையாகப் படிக்கும்போது, ​​உண்மையில் உங்கள் உள்ளுக்குள் என்ன நிகழ்கிறது?', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the weight of responsibility land entirely on you and your first instinct is to get ahead of this before anyone else defines the narrative.', 'பொறுப்பின் முழுச் சுமையும் உங்கள் மீது விழுவதாக நீங்கள் உணர்கிறீர்கள், மேலும் வேறு யாரும் நிலைமையை வரையறுப்பதற்கு முன்பே இதிலிருந்து மீண்டுவிட வேண்டும் என்பதே உங்கள் முதல் உள்ளுணர்வாக இருக்கிறது.', 'D'),
  (2, 'You feel exposed - aware of how this looks, who is watching, and what it means for how you are perceived at the board level.', 'நீங்கள் பாதுகாப்பற்றதாக உணர்கிறீர்கள் - இது எப்படித் தெரிகிறது, யார் உங்களைக் கவனிக்கிறார்கள், மேலும் நிர்வாகக் குழு மட்டத்தில் நீங்கள் எப்படிப் பார்க்கப்படுகிறீர்கள் என்பதற்கு இது என்ன அர்த்தம் என்பதைப் பற்றி நீங்கள் அறிந்திருக்கிறீர்கள்.', 'I'),
  (3, 'You feel protective of the people involved and deeply uncomfortable with the idea that someone on your team may have felt they had no other option than to escalate this way.', 'சம்பந்தப்பட்டவர்கள் மீது நீங்கள் பாதுகாப்பு உணர்வைக் கொண்டிருப்பதோடு, உங்கள் குழுவில் உள்ள ஒருவர் வேறு வழியின்றி இந்த வழியில் நிலைமையைக் கொண்டு சென்றிருக்கலாம் என்ற எண்ணம் உங்களுக்கு மிகுந்த சங்கடத்தையும் ஏற்படுத்துகிறது.', 'S'),
  (4, 'You feel the need to understand exactly what happened before you form any opinion - the complaint could be accurate, distorted, or motivated by something else entirely.', 'எந்தவொரு கருத்தையும் உருவாக்குவதற்கு முன்பு, உண்மையில் என்ன நடந்தது என்பதைத் துல்லியமாகப் புரிந்துகொள்ள வேண்டிய அவசியத்தை நீங்கள் உணர்கிறீர்கள் - ஏனெனில் அந்தப் புகார் உண்மையானதாகவோ, திரித்துக் கூறப்பட்டதாகவோ, அல்லது முற்றிலும் வேறு ஒரு நோக்கத்தால் தூண்டப்பட்டதாகவோ இருக்கலாம்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q5',
     'A factory in your largest manufacturing unit has reported an explosion. Two workers are confirmed dead. Four are hospitalised. A local journalist has already posted on social media and the story is gaining traction. Your communications team is waiting for your direction and your operations head is on the phone.', 'How will you handle crisis?', 'உங்களின் மிகப்பெரிய உற்பத்திப் பிரிவில் உள்ள ஒரு தொழிற்சாலையில் வெடிவிபத்து ஏற்பட்டுள்ளதாகத் தெரிவிக்கப்பட்டுள்ளது. இரண்டு தொழிலாளர்கள் உயிரிழந்தது உறுதி செய்யப்பட்டுள்ளது. நால்வர் மருத்துவமனையில் அனுமதிக்கப்பட்டுள்ளனர். ஒரு உள்ளூர் பத்திரிகையாளர் ஏற்கனவே சமூக ஊடகங்களில் இச்செய்தியைப் பதிவிட்டுள்ளார், மேலும் இச்செய்தி பரவலாகப் பேசப்பட்டு வருகிறது. உங்கள் தகவல் தொடர்பு குழுவினர் உங்கள் வழிகாட்டுதலுக்காகக் காத்திருக்கின்றனர், மேலும் உங்கள் செயல்பாட்டுத் தலைவர் தொலைபேசியில் தொடர்பில் இருக்கிறார்.', 'நெருக்கடியை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 1", "dimension": "decision_speed", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You immediately take charge of the response - issue a holding statement within the hour, deploy your crisis team to the site, and personally call the families before the media does.', 'பதிலளிக்கும் பொறுப்பை நீங்கள் உடனடியாக ஏற்க வேண்டும் - ஒரு மணி நேரத்திற்குள் ஒரு தற்காலிக அறிக்கையை வெளியிட வேண்டும், உங்கள் நெருக்கடிக் குழுவை சம்பவ இடத்திற்கு அனுப்ப வேண்டும், மேலும் ஊடகங்கள் தொடர்புகொள்வதற்கு முன்பே குடும்பத்தினரை நீங்கள் நேரில் அழைக்க வேண்டும்.', 'D'),
  (2, 'You convene your core leadership team, align on a unified response position, and ensure the public statement reflects both accountability and human sensitivity before it goes out.', 'நீங்கள் உங்கள் முக்கியத் தலைமைத்துவக் குழுவைக் கூட்டி, ஒருமித்த பதிலளிப்பு நிலைப்பாட்டை வகுத்து, பொது அறிக்கை வெளியிடப்படுவதற்கு முன்பு அது பொறுப்புடைமையையும் மனித உணர்வையும் பிரதிபலிப்பதை உறுதிசெய்ய வேண்டும்.', 'I'),
  (3, 'You ensure the families are contacted and supported first, that your people on the ground have what they need, and that the response is led by care rather than by communications strategy.', 'குடும்பங்கள் முதலில் தொடர்பு கொள்ளப்பட்டு அவர்களுக்கு ஆதரவளிக்கப்படுவதையும், களத்தில் உள்ள உங்கள் பணியாளர்களுக்குத் தேவையானவை கிடைப்பதையும், மேலும் இந்த நடவடிக்கை தகவல் தொடர்பு உத்தியை விட அக்கறையின் அடிப்படையில் வழிநடத்தப்படுவதையும் நீங்கள் உறுதி செய்ய வேண்டும்.', 'S'),
  (4, 'You instruct the team to gather complete information from the site before any public statement is made - you will not speak until you know exactly what happened.', 'எந்தவொரு பொது அறிக்கையும் வெளியிடுவதற்கு முன்பு, அந்த இடத்திலிருந்து முழுமையான தகவல்களைச் சேகரிக்குமாறு குழுவினருக்கு நீங்கள் அறிவுறுத்துகிறீர்கள்; என்ன நடந்தது என்று துல்லியமாகத் தெரிந்துகொள்ளும் வரை நீங்கள் பேசக்கூடாது.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q6',
     'A national media outlet has published an investigative piece claiming your company systematically underpaid women at the senior management level over a five-year period. The data in the article is partially accurate but significantly misrepresented. Your legal team advises you not to comment. Your CHRO says silence will be interpreted as guilt.', 'How will you handle conflict?', 'உங்கள் நிறுவனம் கடந்த ஐந்தாண்டுகளாக உயர் நிர்வாக மட்டத்தில் உள்ள பெண்களுக்குத் திட்டமிட்டு குறைவான ஊதியம் வழங்கியதாகக் கூறி, ஒரு தேசிய ஊடகம் புலனாய்வுக் கட்டுரை ஒன்றை வெளியிட்டுள்ளது. கட்டுரையில் உள்ள தரவுகள் ஓரளவு துல்லியமானவை, ஆனால் பெருமளவில் தவறாகச் சித்தரிக்கப்பட்டுள்ளன. இதுகுறித்து கருத்து தெரிவிக்க வேண்டாம் என உங்கள் சட்டக் குழு உங்களுக்கு அறிவுறுத்துகிறது. மௌனம் குற்ற உணர்வாகவே கருதப்படும் என்று உங்கள் தலைமை மனிதவள அதிகாரி கூறுகிறார்.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You issue a direct public response the same day, correct the misrepresentation with specific data, and invite an independent audit to be published within 60 days.', 'நீங்கள் அதே நாளில் ஒரு நேரடி பொதுப் பதிலை வெளியிட்டு, குறிப்பிட்ட தரவுகளுடன் தவறான சித்தரிப்பைத் திருத்தி, 60 நாட்களுக்குள் வெளியிடுமாறு ஒரு சுயாதீன தணிக்கைக்கு அழைப்பு விடுக்கிறீர்கள்.', 'D'),
  (2, 'You reach out personally to the journalist, request a follow-up conversation, and work to build a more accurate narrative through relationship rather than confrontation.', 'நீங்கள் பத்திரிகையாளரைத் தனிப்பட்ட முறையில் அணுகி, தொடர் உரையாடலுக்குக் கோரிக்கை விடுத்து, மோதலைத் தவிர்த்து உறவின் மூலம் மேலும் துல்லியமான ஒரு விவரத்தை உருவாக்கப் பாடுபடுகிறீர்கள்.', 'I'),
  (3, 'You focus internally first - address your own leadership team and employees directly before responding externally, so your people hear from you before they read about it.', 'நீங்கள் முதலில் உள்நோக்கம் கொண்டிருங்கள் - வெளிப்புறமாகப் பதிலளிப்பதற்கு முன், உங்கள் சொந்தத் தலைமைக் குழு மற்றும் ஊழியர்களிடம் நேரடியாகப் பேசுங்கள். இதன்மூலம், அவர்கள் அதைப் பற்றிப் படிப்பதற்கு முன்பே உங்களிடமிருந்து நேரடியாகக் கேட்பார்கள்.', 'S'),
  (4, 'You commission a full internal data review, engage a third-party audit firm, and respond only when you have a factually complete and defensible position.', 'நீங்கள் ஒரு முழுமையான உள் தரவு மதிப்பாய்வை மேற்கொள்கிறீர்கள், ஒரு மூன்றாம் தரப்பு தணிக்கை நிறுவனத்தை ஈடுபடுத்துகிறீர்கள், மேலும் உண்மைகளின் அடிப்படையில் முழுமையான மற்றும் தற்காத்துக் கொள்ளக்கூடிய ஒரு நிலைப்பாடு உங்களிடம் இருக்கும்போது மட்டுமே பதிலளிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q7',
     'Your company''s largest product line has been linked to an adverse health outcome in a small but statistically significant consumer group. Regulators have not yet acted. Legal says you are not liable. Your head of product says pulling the product would cost 340 crore in revenue this quarter.Two things are pulling at you. Which is stronger - the instinct to act immediately and pull the product because it is the right thing to do, or the discipline to wait for regulatory and legal process to run its course before making a decision that cannot be undone?', 'How will you handle crisis?', 'உங்கள் நிறுவனத்தின் மிகப்பெரிய தயாரிப்பு வரிசையானது, சிறிய ஆனால் புள்ளிவிவரப்படி குறிப்பிடத்தக்க ஒரு நுகர்வோர் குழுவில் பாதகமான உடல்நல விளைவுடன் தொடர்புபடுத்தப்பட்டுள்ளது. ஒழுங்குமுறை ஆணையங்கள் இன்னும் நடவடிக்கை எடுக்கவில்லை. சட்டப் பிரிவு, நீங்கள் பொறுப்பல்ல என்கிறது. உங்கள் தயாரிப்புப் பிரிவுத் தலைவர், அந்தத் தயாரிப்பைத் திரும்பப் பெறுவதால் இந்தக் காலாண்டில் 340 கோடி வருவாய் இழப்பு ஏற்படும் என்கிறார். இரண்டு விஷயங்கள் உங்களை அலைக்கழிக்கின்றன. எது வலிமையானது - செய்வது சரி என்பதால் உடனடியாகச் செயல்பட்டு அந்தத் தயாரிப்பைத் திரும்பப் பெற வேண்டும் என்ற உள்ளுணர்வா, அல்லது மாற்ற முடியாத ஒரு முடிவை எடுப்பதற்கு முன், ஒழுங்குமுறை மற்றும் சட்டரீதியான செயல்முறைகள் அதன் போக்கில் முடிவடையும் வரை காத்திருக்கும் ஒழுக்கமா?', 'நெருக்கடியை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 2", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Act immediately. You will not wait for a regulator to tell you what your conscience already has.', 'உடனடியாகச் செயல்படுங்கள். உங்கள் மனசாட்சி ஏற்கனவே உணர்த்தியதை ஒரு ஒழுங்குமுறை ஆணையம் சொல்வதற்காக நீங்கள் காத்திருக்க மாட்டீர்கள்.', 'D'),
  (2, 'Act through people. You want to bring your leadership team, your board, and your key stakeholders into this decision so the action carries collective weight.', 'மக்கள் மூலமாகச் செயல்படுங்கள். இந்த முடிவில் உங்கள் தலைமைக் குழு, உங்கள் வாரியம் மற்றும் உங்கள் முக்கியப் பங்குதாரர்களை நீங்கள் ஈடுபடுத்த வேண்டும், அப்போதுதான் அந்தச் செயலுக்கு ஒரு கூட்டு முக்கியத்துவம் கிடைக்கும்.', 'I'),
  (3, 'Act carefully. You are deeply aware of the impact on employees, supply chain partners, and the communities dependent on this product line.', 'கவனமாகச் செயல்படுங்கள். ஊழியர்கள், விநியோகச் சங்கிலிப் பங்காளர்கள் மற்றும் இந்தத் தயாரிப்பு வரிசையைச் சார்ந்திருக்கும் சமூகங்கள் மீது ஏற்படக்கூடிய தாக்கத்தை நீங்கள் நன்கு அறிவீர்கள்.', 'S'),
  (4, 'Act on evidence. You need the epidemiological data reviewed by an independent body before you make an irreversible commercial and reputational decision.', 'ஆதாரங்களின் அடிப்படையில் செயல்படுங்கள். மாற்ற முடியாத வணிக மற்றும் நற்பெயர் சார்ந்த முடிவை எடுப்பதற்கு முன், நோய்ப்பரவல் தரவுகளை ஒரு சுயாதீன அமைப்பு மதிப்பாய்வு செய்ய வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q8',
     'A senior leader in your organisation has been arrested on charges of financial fraud unrelated to the company. He is well-liked, high-performing, and has been with the organisation for 14 years. The news is breaking publicly. Your board expects a statement by end of day.The honest feeling underneath this - before you draft the statement, before you call the board, before you speak to HR - what are you actually feeling?', 'What are you actually feeling?', 'உங்கள் நிறுவனத்தின் ஒரு மூத்த தலைவர், நிறுவனத்துடன் தொடர்பில்லாத நிதி மோசடி குற்றச்சாட்டின் பேரில் கைது செய்யப்பட்டுள்ளார். அவர் அனைவராலும் விரும்பப்படுபவர், உயர் செயல்திறன் கொண்டவர், மேலும் 14 ஆண்டுகளாக அந்த நிறுவனத்தில் பணியாற்றி வருகிறார். இந்தச் செய்தி பகிரங்கமாக வெளியாகிறது. உங்கள் நிர்வாகக் குழு, இன்றைய தினத்தின் இறுதிக்குள் ஒரு அறிக்கையை எதிர்பார்க்கிறது. இந்தச் சூழலுக்குப் பின்னால் உள்ள உண்மையான உணர்வு என்னவென்றால் - நீங்கள் அந்த அறிக்கையைத் தயாரிப்பதற்கு முன்பும், நிர்வாகக் குழுவை அழைப்பதற்கு முன்பும், மனிதவளத் துறையிடம் பேசுவதற்கு முன்பும் - நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 3", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the urgency to protect the organisation and act decisively before this defines you or the company in a way you cannot control.', 'இது உங்களையோ அல்லது நிறுவனத்தையோ உங்கள் கட்டுப்பாட்டிற்கு அப்பாற்பட்ட வகையில் வரையறுப்பதற்கு முன்பாக, அமைப்பைப் பாதுகாத்து உறுதியான நடவடிக்கை எடுக்க வேண்டிய அவசரத்தை நீங்கள் உணர்கிறீர்கள்.', 'D'),
  (2, 'You feel the complexity of managing perceptions - internally and externally - and the weight of knowing that whatever you say will be read in multiple ways by multiple audiences.', 'உள்ளேயும் வெளியேயும் உள்ள கண்ணோட்டங்களைக் கையாள்வதில் உள்ள சிக்கலையும், நீங்கள் சொல்வது எதுவாக இருந்தாலும் அது பலதரப்பட்ட பார்வையாளர்களால் பல்வேறு விதங்களில் புரிந்துகொள்ளப்படும் என்ற பாரத்தையும் நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the grief of it. Someone you trusted, someone the organisation invested in, is now at the centre of something that feels like a betrayal - and that is painful before it is a crisis.', 'அதன் துயரத்தை நீங்கள் உணர்கிறீர்கள். நீங்கள் நம்பிய ஒருவர், நிறுவனம் முதலீடு செய்த ஒருவர், இப்போது ஒரு துரோகம் போன்ற உணர்வைத் தரும் விஷயத்தின் மையத்தில் இருக்கிறார் - அது ஒரு நெருக்கடியாக மாறுவதற்கு முன்பே வேதனையானது.', 'S'),
  (4, 'You feel frustrated by the absence of complete information and resistant to making a public statement until you understand what is actually true and what is not.', 'முழுமையான தகவல்கள் இல்லாததால் நீங்கள் விரக்தியடைவதோடு, உண்மையில் எது உண்மை, எது பொய் என்பதைப் புரிந்துகொள்ளும் வரை பொது அறிக்கை வெளியிடவும் தயங்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q9',
     'Your highest revenue-generating sales leader has missed targets for the third consecutive quarter. In the same period she has created significant team conflict, lost two high-potential team members who cited her leadership style as their reason for leaving, and received the lowest peer feedback scores in the division. She is also responsible for your single largest client relationship.', 'How to handle underperforming leader?', 'உங்கள் நிறுவனத்தில் அதிக வருவாய் ஈட்டும் விற்பனைத் தலைவர், தொடர்ந்து மூன்றாவது காலாண்டாக இலக்குகளை அடையத் தவறியுள்ளார். இதே காலகட்டத்தில், அவர் குழுவில் குறிப்பிடத்தக்க மோதல்களை உருவாக்கியுள்ளார்; அவரது தலைமைப் பாணியையே விலகுவதற்கான காரணமாகக் குறிப்பிட்ட, அதிகத் திறனுள்ள இரண்டு குழு உறுப்பினர்களை இழந்துள்ளார்; மேலும், உங்கள் பிரிவிலேயே மிகக் குறைந்த சக மதிப்பீட்டு மதிப்பெண்களையும் பெற்றுள்ளார். உங்கள் நிறுவனத்தின் மிகப்பெரிய ஒற்றை வாடிக்கையாளர் உறவுக்கும் அவரே பொறுப்பாவார்.', 'செயல்திறன் குறைந்த தலைவரை எவ்வாறு கையாள்வது?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You have a direct performance conversation, set a 60-day improvement plan with clear metrics, and make clear that the next miss will result in a role change regardless of the client relationship.', 'செயல்திறன் குறித்த நேரடி உரையாடலை நடத்தி, தெளிவான அளவீடுகளுடன் 60 நாள் மேம்பாட்டுத் திட்டத்தை அமைத்து, வாடிக்கையாளர் உறவைப் பொருட்படுத்தாமல் அடுத்த தவறு நிகழ்ந்தால் பதவி மாற்றம் ஏற்படும் என்பதைத் தெளிவுபடுத்துங்கள்.', 'D'),
  (2, 'You invest personal time in understanding what has changed for her, rebuild the relationship, and work alongside her to reset her motivation and team dynamic before escalating formally.', 'முறையாக அடுத்த கட்டத்திற்குச் செல்வதற்கு முன், அவளுக்குள் என்ன மாற்றம் ஏற்பட்டுள்ளது என்பதைப் புரிந்துகொள்வதற்கும், உறவை மீண்டும் கட்டியெழுப்புவதற்கும், அவளுடைய ஊக்கத்தையும் குழு இயக்கவியலையும் மீட்டமைக்க அவளுடன் இணைந்து பணியாற்றுவதற்கும் நீங்கள் தனிப்பட்ட நேரத்தை ஒதுக்குகிறீர்கள்.', 'I'),
  (3, 'You bring in a neutral senior leader to mediate between her and the team, protect the relationships that can still be saved, and give the situation time to stabilise before making any structural decisions.', 'அவருக்கும் குழுவிற்கும் இடையில் மத்தியஸ்தம் செய்யவும், இன்னும் காப்பாற்றப்படக்கூடிய உறவுகளைப் பாதுகாக்கவும், மேலும் எந்தவொரு கட்டமைப்பு முடிவுகளையும் எடுப்பதற்கு முன்பு நிலைமை சீரடைய அவகாசம் அளிக்கவும் நீங்கள் ஒரு நடுநிலையான மூத்த தலைவரை நியமிக்கிறீர்கள்.', 'S'),
  (4, 'You commission a full 360 review, map the revenue risk of the client relationship, and build a transition plan before having the performance conversation so you are not making decisions without complete data.', 'செயல்திறன் குறித்த கலந்துரையாடலை நடத்துவதற்கு முன்பு, முழுமையான தரவுகள் இல்லாமல் நீங்கள் முடிவுகளை எடுக்காமல் இருப்பதற்காக, ஒரு முழுமையான 360 டிகிரி மதிப்பாய்வை மேற்கொண்டு, வாடிக்கையாளர் உறவின் வருவாய் அபாயத்தை வரைபடமாக்கி, ஒரு மாற்றத் திட்டத்தை உருவாக்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q10',
     'During a leadership offsite, a business unit head publicly challenges your assessment of the company''s growth strategy in front of the full senior leadership team. He is respected, well-networked, and partially right. The room is watching to see how you handle it.', 'How will you handle conflict?', 'ஒரு தலைமைத்துவக் கூட்டத்தின்போது, ​​ஒரு வணிகப் பிரிவுத் தலைவர், முழு மூத்த தலைமைத்துவக் குழுவின் முன்னிலையில், நிறுவனத்தின் வளர்ச்சி உத்தி குறித்த உங்கள் மதிப்பீட்டைப் பகிரங்கமாகச் சவால் விடுகிறார். அவர் மதிக்கப்படுபவர், நல்ல தொடர்புகளைக் கொண்டவர், மேலும் ஓரளவு சரியானவரும் கூட. நீங்கள் அதை எப்படிக் கையாளுகிறீர்கள் என்பதைப் பார்க்க அந்த அறையில் உள்ள அனைவரும் கவனித்துக் கொண்டிருக்கிறார்கள்.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You engage his challenge directly, acknowledge where he is right, hold your position where you disagree, and use the moment to sharpen the strategic debate in the room.', 'நீங்கள் அவருடைய சவாலை நேரடியாக எதிர்கொண்டு, அவர் சொல்வது சரி என்பதை ஏற்றுக்கொண்டு, நீங்கள் முரண்படும் இடங்களில் உங்கள் நிலைப்பாட்டில் உறுதியாக இருந்து, அந்தத் தருணத்தைப் பயன்படுத்தி அறையில் நடக்கும் வியூக விவாதத்தை மேலும் கூர்மைப்படுத்துங்கள்.', 'D'),
  (2, 'You invite the room into the conversation, facilitate a broader discussion, and let the collective intelligence of the leadership team surface the strongest position rather than making it a two-person debate.', 'நீங்கள் அறையில் உள்ள அனைவரையும் உரையாடலில் ஈடுபடுத்தி, ஒரு பரந்த கலந்துரையாடலுக்கு வழிவகுத்து, அதை இருவர் விவாதமாக மாற்றுவதற்குப் பதிலாக, தலைமை அணியின் கூட்டு அறிவாற்றலே வலுவான நிலைப்பாட்டை வெளிக்கொணர அனுமதிக்கிறீர்கள்.', 'I'),
  (3, 'You acknowledge his perspective, protect the relationship publicly, and suggest a deeper conversation between the two of you after the session to work through the disagreement properly.', 'நீங்கள் அவருடைய கண்ணோட்டத்தை ஏற்றுக்கொண்டு, வெளிப்படையாக உறவைப் பாதுகாத்து, கருத்து வேறுபாட்டை முறையாகத் தீர்ப்பதற்காக அமர்வுக்குப் பிறகு உங்கள் இருவருக்கும் இடையே ஒரு ஆழமான உரையாடலைப் பரிந்துரைக்கிறீர்கள்.', 'S'),
  (4, 'You ask him to walk the group through the specific data or analysis behind his position so the conversation is grounded in evidence rather than competing opinions.', 'அவரது நிலைப்பாட்டிற்குப் பின்னால் உள்ள குறிப்பிட்ட தரவுகள் அல்லது பகுப்பாய்வை குழுவிற்கு விளக்குமாறு அவரிடம் நீங்கள் கேட்கிறீர்கள், இதன்மூலம் உரையாடல் முரண்பட்ட கருத்துக்களின் அடிப்படையில் இல்லாமல் ஆதாரங்களின் அடிப்படையில் அமையும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q11',
     'A member of your core leadership team - someone you personally hired and mentored - has been underperforming for two quarters. Your CHRO has recommended a formal performance improvement process. Three of his peers have told you privately they have lost confidence in him. He has a young family and you know this role means everything to him.The conflict you feel most is between - your responsibility to the organisation and the team who depend on strong leadership around them, and your loyalty to someone you brought in, believed in, and who trusted you with his career.', 'How to handle underperforming leader?', 'உங்கள் முக்கிய தலைமைத்துவக் குழுவின் உறுப்பினர் ஒருவர் - அதாவது, நீங்கள் தனிப்பட்ட முறையில் பணியமர்த்தி வழிகாட்டிய ஒருவர் - கடந்த இரண்டு காலாண்டுகளாகத் திறமையின்றிச் செயல்பட்டு வருகிறார். உங்கள் தலைமை மனிதவள அதிகாரி (CHRO), ஒரு முறையான செயல்திறன் மேம்பாட்டுச் செயல்முறையைப் பரிந்துரைத்துள்ளார். அவருடைய சக ஊழியர்களில் மூவர், அவர் மீது தங்களுக்கு நம்பிக்கை போய்விட்டதாக உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளனர். அவருக்கு ஒரு இளம் குடும்பம் உள்ளது, மேலும் இந்தப் பதவி அவருக்கு எல்லாமே என்பது உங்களுக்குத் தெரியும். நீங்கள் மிகவும் உணரும் முரண்பாடு, ஒருபுறம் வலுவான தலைமைத்துவத்தைச் சார்ந்திருக்கும் நிறுவனம் மற்றும் குழுவின் மீதான உங்கள் பொறுப்பு; மறுபுறம், நீங்கள் பணியமர்த்தி, நம்பி, தனது தொழில் வாழ்க்கையை உங்களிடம் ஒப்படைத்த ஒருவரின் மீதான உங்கள் விசுவாசம்.', 'செயல்திறன் குறைந்த தலைவரை எவ்வாறு கையாள்வது?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You act on your responsibility to the organisation. The team''s performance and confidence cannot be held hostage to a personal relationship.', 'நிறுவனத்தின் மீதான உங்கள் பொறுப்பை நீங்கள் நிறைவேற்ற வேண்டும். அணியின் செயல்திறனையும் நம்பிக்கையையும் ஒரு தனிப்பட்ட உறவுக்குப் பணயமாக்கக் கூடாது.', 'D'),
  (2, 'You find a way to have the honest conversation that protects both - you will not let the formal process begin without giving him the real picture first, privately, with genuine support.', 'இருவரையும் பாதுகாக்கும் வகையில் நேர்மையான உரையாடலை நடத்துவதற்கான ஒரு வழியை நீங்கள் கண்டறியுங்கள் - உண்மையான ஆதரவுடன், தனிப்பட்ட முறையில், அவருக்கு முதலில் நிஜமான நிலையைத் தெரிவிக்காமல், முறைசார்ந்த செயல்முறையைத் தொடங்க நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'I'),
  (3, 'You feel the pull of loyalty strongly. You want to find every possible way to help him recover before the process begins - a role change, additional support, more time.', 'விசுவாசத்தின் ஈர்ப்பை நீங்கள் வலுவாக உணர்கிறீர்கள். சிகிச்சை செயல்முறை தொடங்குவதற்கு முன்பு, அவர் மீண்டு வர உதவுவதற்கு சாத்தியமான எல்லா வழிகளையும் நீங்கள் கண்டறிய விரும்புகிறீர்கள் - பொறுப்பு மாற்றம், கூடுதல் ஆதரவு, அதிக நேரம்.', 'S'),
  (4, 'You want the data to be unambiguous before you act. Two quarters and peer feedback are concerning but you want a structured assessment before making a decision that will affect his life significantly.', 'நீங்கள் செயல்படுவதற்கு முன்பு தரவுகள் தெளிவானதாக இருக்க வேண்டும் என விரும்புவீர்கள். இரண்டு காலாண்டுகளும் சக ஊழியர்களின் பின்னூட்டமும் கவலையளிப்பதாக இருந்தாலும், அவரது வாழ்க்கையை கணிசமாகப் பாதிக்கக்கூடிய ஒரு முடிவை எடுப்பதற்கு முன்பு, நீங்கள் ஒரு கட்டமைக்கப்பட்ட மதிப்பீட்டை விரும்புவீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q12',
     'You have just concluded a town hall where you announced a restructuring that will eliminate one division and redeploy 200 people. The session was professional. The questions were hard. One long-serving employee stood up and said quietly - I have given this company 18 years. I did not expect to feel disposable.What is actually happening inside you as you walk off that stage?', 'How do you feel internally?', 'நீங்கள் சற்றுமுன்தான் ஒரு பொதுக் கூட்டத்தை முடித்திருந்தீர்கள். அதில், ஒரு பிரிவை நீக்கி, 200 பேரை வேறு பணிகளுக்கு மாற்றும் ஒரு மறுசீரமைப்பை அறிவித்தீர்கள். அந்தக் கூட்டம் தொழில்முறையாக இருந்தது. கேள்விகள் கடினமாக இருந்தன. நீண்டகாலமாகப் பணியாற்றும் ஒரு ஊழியர் எழுந்து நின்று மெதுவாகக் கூறினார் - "நான் இந்த நிறுவனத்திற்கு 18 ஆண்டுகள் சேவையாற்றியுள்ளேன். நான் ஒரு பொருட்டாக மதிக்கப்படாதவனாக உணர்வேன் என்று எதிர்பார்க்கவில்லை." அந்த மேடையிலிருந்து நீங்கள் இறங்கிச் செல்லும்போது, ​​உண்மையில் உங்கள் உள்ளுக்குள் என்னதான் நடந்துகொண்டிருந்தது?', 'உங்களுக்கு உள்ளுக்குள் எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 3", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the weight of the decision but also a clear sense that you made the right call for the organisation - and that clarity carries you forward even when the room is hard.', 'அந்த முடிவின் பாரத்தை நீங்கள் உணர்ந்தாலும், நிறுவனத்திற்கு அதுவே சரியான முடிவு என்ற தெளிவான உணர்வும் உங்களுக்கு ஏற்படும் - மேலும், சூழல் கடினமாக இருக்கும்போதும் அந்தத் தெளிவு உங்களை முன்னோக்கிச் செலுத்தும்.', 'D'),
  (2, 'You are acutely aware of how you came across, replaying moments where you could have connected more, wondering whether people left feeling heard or simply managed.', 'நீங்கள் வெளிப்பட்ட விதத்தைப் பற்றித் தீவிரமாக உணர்ந்து, இன்னும் அதிகமாக இணைந்திருக்கக்கூடிய தருணங்களை மீண்டும் மீண்டும் அசைபோட்டு, மக்கள் தங்கள் குரல் கேட்கப்பட்டதாக உணர்ந்து சென்றார்களா அல்லது வெறுமனே சமாளிக்கப்பட்டதாக உணர்ந்தார்களா என்று யோசிக்கிறீர்கள்.', 'I'),
  (3, 'You feel that employee''s words deeply. Not as a crisis communication problem - as a human reality. And it sits with you in a way that does not resolve quickly.', 'அந்த ஊழியரின் வார்த்தைகளை நீங்கள் ஆழமாக உணர்கிறீர்கள். அதை ஒரு நெருக்கடிக்காலத் தகவல் தொடர்புப் பிரச்சனையாக அல்லாமல், ஒரு மனித யதார்த்தமாக உணர்கிறீர்கள். மேலும், அது எளிதில் தீராத ஒரு விதத்தில் உங்கள் மனதில் ஆழமாகப் பதிந்துவிடுகிறது.', 'S'),
  (4, 'You are already processing what you could have communicated more precisely, what data you should have presented differently, and what you will adjust in the next session.', 'எதை இன்னும் துல்லியமாகத் தெரிவித்திருக்கலாம், எந்தத் தரவுகளை வேறுவிதமாக வழங்கியிருக்க வேண்டும், அடுத்த அமர்வில் எவற்றைச் சரிசெய்வீர்கள் என்பனவற்றை நீங்கள் ஏற்கெனவே சிந்தித்துக் கொண்டிருக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q13',
     'Your organisation has the opportunity to acquire a direct competitor at a significant discount. The seller needs a decision in 10 days. Your strategy team has completed 60% of the due diligence. Your CFO says the financials are strong but the cultural integration risk is real. Your board is divided and wants more time.', 'What is your acquisition decision?', 'உங்கள் நிறுவனத்திற்கு, ஒரு நேரடிப் போட்டியாளரை கணிசமான தள்ளுபடியில் கையகப்படுத்தும் வாய்ப்பு கிடைத்துள்ளது. விற்பனையாளருக்கு 10 நாட்களில் ஒரு முடிவு தேவைப்படுகிறது. உங்கள் வியூகக் குழு, உரிய விடாமுயற்சியின் 60%-ஐ முடித்துவிட்டது. உங்கள் தலைமை நிதி அதிகாரி, நிதிநிலை வலுவாக இருப்பதாகக் கூறுகிறார், ஆனால் கலாச்சார ஒருங்கிணைப்பு அபாயம் உண்மையானது. உங்கள் நிர்வாகக் குழுவில் கருத்து வேறுபாடு நிலவுகிறது, மேலும் அவர்கள் கூடுதல் அவகாசம் கோருகின்றனர்.', 'உங்கள் கையகப்படுத்தும் முடிவு என்ன?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 1", "dimension": "decision_speed", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You push to close. The strategic window is rare, the financials are sound, and integration risk is manageable with the right team. You will not let process caution cost you a decade-defining opportunity.', 'நீங்கள் ஒப்பந்தத்தை முடிக்க முனைவீர்கள். மூலோபாய வாய்ப்பு கிடைப்பது அரிது, நிதிநிலை வலுவாக உள்ளது, மேலும் சரியான குழுவுடன் ஒருங்கிணைப்பு அபாயத்தையும் சமாளிக்க முடியும். செயல்முறை குறித்த எச்சரிக்கை உணர்வு, பத்தாண்டுகளை வரையறுக்கும் ஒரு வாய்ப்பை உங்களுக்கு இழக்கச் செய்ய நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'D'),
  (2, 'You bring your leadership team and key board members into an intensive 5-day sprint, build alignment through inclusion, and move to a decision with the people who will execute it fully bought in.', 'உங்கள் தலைமைத்துவக் குழுவையும் முக்கிய இயக்குநர் குழு உறுப்பினர்களையும் ஒரு தீவிரமான 5-நாள் விரைவுச் செயல்பாட்டில் ஈடுபடுத்தி, அனைவரையும் உள்ளடக்குவதன் மூலம் ஒருங்கிணைப்பை உருவாக்கி, அதைச் செயல்படுத்தப் போகிறவர்களின் முழு ஆதரவுடன் ஒரு முடிவை நோக்கி நகர்கிறீர்கள்.', 'I'),
  (3, 'You request a 5-day extension from the seller, use the time to address the board''s concerns carefully, and will not proceed without a level of consensus that gives the integration a real chance.', 'நீங்கள் விற்பனையாளரிடம் 5 நாள் கால நீட்டிப்பைக் கோருகிறீர்கள், அந்த நேரத்தைப் பயன்படுத்தி நிர்வாகக் குழுவின் கவலைகளைக் கவனமாகக் கையாளுகிறீர்கள், மேலும் ஒருங்கிணைப்பிற்கு ஒரு உண்மையான வாய்ப்பை வழங்கும் அளவிலான ஒருமித்த கருத்து ஏற்படாமல் மேற்கொண்டு செல்ல மாட்டீர்கள்.', 'S'),
  (4, 'You commission a rapid but rigorous risk assessment on the top five integration variables, present it to the board with scenario modeling, and make the decision on evidence rather than instinct.', 'முதல் ஐந்து ஒருங்கிணைப்பு மாறிகள் மீது விரைவான ஆனால் துல்லியமான இடர் மதிப்பீட்டை மேற்கொண்டு, அதைச் சூழ்நிலை மாதிரிகளுடன் இயக்குநர்கள் குழுவிடம் சமர்ப்பித்து, உள்ளுணர்வின் அடிப்படையில் அல்லாமல் சான்றுகளின் அடிப்படையில் முடிவெடுக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q14',
     'You are 18 months into a digital transformation programme that has consumed significant capital and leadership bandwidth. Early results are below projections. Your board is losing patience. A peer organisation has just announced they are abandoning a similar programme. Two of your own leaders are privately recommending you cut losses.', 'How will you handle this?', 'கணிசமான மூலதனத்தையும் தலைமைத்துவ ஆற்றலையும் எடுத்துக்கொண்ட ஒரு டிஜிட்டல் உருமாற்றத் திட்டத்தில் நீங்கள் 18 மாதங்களாக இருக்கிறீர்கள். ஆரம்பகட்ட முடிவுகள் கணிப்புகளை விடக் குறைவாக உள்ளன. உங்கள் நிர்வாகக் குழு பொறுமையை இழந்து வருகிறது. சக நிறுவனம் ஒன்று இதேபோன்ற ஒரு திட்டத்தைக் கைவிடுவதாக இப்போதுதான் அறிவித்துள்ளது. உங்கள் நிறுவனத்தின் தலைவர்களில் இருவர், நஷ்டத்தைக் குறைத்துக்கொள்ளுமாறு தனிப்பட்ட முறையில் உங்களுக்குப் பரிந்துரைக்கின்றனர்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You hold the course. You have conviction in the strategy, the early results are within acceptable variance, and you will not let short-term pressure reverse an 18-month investment in the right direction.', 'நீங்கள் உங்கள் பாதையில் உறுதியாக இருக்கிறீர்கள். அந்த உத்தியின் மீது உங்களுக்கு நம்பிக்கை உள்ளது, ஆரம்பகட்ட முடிவுகள் ஏற்றுக்கொள்ளக்கூடிய மாறுபாட்டிற்குள் இருக்கின்றன, மேலும் சரியான திசையில் செய்யப்பட்ட 18 மாத முதலீட்டை, குறுகிய கால அழுத்தம் திசை திருப்ப நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'D'),
  (2, 'You reinvigorate the programme by rebuilding internal energy - hold a leadership reset session, reconnect the team to the original vision, and rebuild momentum from the inside before making any structural changes.', 'உள் ஆற்றலை மீண்டும் கட்டியெழுப்புவதன் மூலம் நீங்கள் திட்டத்திற்குப் புத்துயிர் அளிக்கிறீர்கள் - எந்தவொரு கட்டமைப்பு மாற்றங்களையும் செய்வதற்கு முன்பு, ஒரு தலைமைத்துவ மறுசீரமைப்பு அமர்வை நடத்துங்கள், குழுவை அசல் தொலைநோக்குப் பார்வையுடன் மீண்டும் இணைத்து, உள்ளிருந்தே உத்வேகத்தை மீண்டும் உருவாக்குங்கள்.', 'I'),
  (3, 'You slow the pace, reduce the pressure on the organisation, consolidate the gains already made, and give the programme time to prove itself without the weight of board expectation forcing premature conclusions.', 'நீங்கள் வேகத்தைக் குறைத்து, நிறுவனத்தின் மீதான அழுத்தத்தைக் குறைத்து, ஏற்கனவே அடைந்த முன்னேற்றங்களை ஒருங்கிணைத்து, நிர்வாகக் குழுவின் எதிர்பார்ப்புகளின் சுமையால் முன்கூட்டிய முடிவுகள் எடுக்கப்படாமல், அந்தத் திட்டம் தன்னை நிரூபித்துக் கொள்ள அவகாசம் அளிக்கிறீர்கள்.', 'S'),
  (4, 'You commission an independent programme review, benchmark against comparable transformations in your sector, and make a data-driven decision about whether to continue, pivot, or exit within 45 days.', 'நீங்கள் ஒரு சுயாதீனமான திட்ட மதிப்பாய்வை மேற்கொண்டு, உங்கள் துறையில் உள்ள ஒப்பிடக்கூடிய மாற்றங்களுடன் அளவுகோலிட்டு, 45 நாட்களுக்குள் திட்டத்தைத் தொடர்வதா, மாற்றுவதா அல்லது வெளியேறுவதா என்பது குறித்து தரவுகளின் அடிப்படையில் ஒரு முடிவை எடுக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q15',
     'You are deciding whether to enter a new market that represents significant growth potential but requires exiting a product category that has been central to your company''s identity for 20 years. The financial case is strong. The strategic logic is clear. But the organisation has never made a change of this magnitude and you are not certain they can execute it.What matters more to you in this moment - the size of the opportunity and your conviction in the strategy, or the organisational readiness and the real risk of execution failure at this scale?', 'How will you handle this?', 'குறிப்பிடத்தக்க வளர்ச்சி சாத்தியக்கூறுகளைக் கொண்ட ஒரு புதிய சந்தையில் நுழைவதா வேண்டாமா என்று நீங்கள் முடிவு செய்கிறீர்கள். ஆனால், அதற்காக, கடந்த 20 ஆண்டுகளாக உங்கள் நிறுவனத்தின் அடையாளமாக விளங்கிய ஒரு தயாரிப்புப் பிரிவிலிருந்து நீங்கள் வெளியேற வேண்டியுள்ளது. நிதி ரீதியாக அதற்கான காரணம் வலுவாக உள்ளது. உத்தி ரீதியான தர்க்கமும் தெளிவாக இருக்கிறது. ஆனால், இந்த அளவு பெரிய மாற்றத்தை அந்த நிறுவனம் இதற்கு முன் ஒருபோதும் செய்ததில்லை, மேலும் அவர்களால் அதைச் செயல்படுத்த முடியுமா என்பதும் உங்களுக்கு உறுதியாகத் தெரியவில்லை. இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - வாய்ப்பின் அளவும் உத்தியின் மீதான உங்கள் நம்பிக்கையுமா, அல்லது நிறுவனத்தின் தயார்நிலையும் இந்த அளவிலான செயலாக்கத் தோல்வியின் உண்மையான அபாயமுமா?', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 2", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The opportunity. Markets do not wait for organisations to be ready. You build readiness through the doing.', 'வாய்ப்பு. நிறுவனங்கள் தயாராவதற்காக சந்தைகள் காத்திருப்பதில்லை. செயல்படுவதன் மூலமே நீங்கள் தயார்நிலையை உருவாக்குகிறீர்கள்.', 'D'),
  (2, 'The people. You will not commit to a strategy the organisation cannot execute with confidence. Alignment and energy matter as much as strategic logic.', 'மக்கள். ஒரு நிறுவனத்தால் நம்பிக்கையுடன் செயல்படுத்த முடியாத ஒரு உத்திக்கு நீங்கள் ஒப்புக்கொள்ள மாட்டீர்கள். உத்திசார்ந்த தர்க்கத்தைப் போலவே ஒருங்கிணைப்பும் ஆற்றலும் முக்கியம்.', 'I'),
  (3, 'The stability of the transition. You want to protect what has been built while reaching for what is possible - and that requires a pace the organisation can sustain.', 'மாற்றத்தின் நிலைத்தன்மை. சாத்தியமானதை நோக்கிச் செல்லும் அதே வேளையில், இதுவரை கட்டமைக்கப்பட்டவற்றையும் நீங்கள் பாதுகாக்க விரும்புகிறீர்கள் - அதற்கு, நிறுவனத்தால் நிலைநிறுத்தக்கூடிய ஒரு வேகம் தேவைப்படுகிறது.', 'S'),
  (4, 'The evidence. Organisational readiness can be assessed. You want that assessment before you make a commitment of this scale.', 'ஆதாரம். நிறுவனத்தின் தயார்நிலையை மதிப்பிட முடியும். இந்த அளவிலான ஒரு உறுதிப்பாட்டை மேற்கொள்வதற்கு முன்பு, அந்த மதிப்பீடு உங்களுக்குத் தேவை.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q16',
     'You have spent six months building a market entry strategy for Southeast Asia. It has been approved by the board. The investment is committed. Two weeks before launch, your country head sends you data suggesting the core customer assumption in the strategy may be wrong - and the window to course-correct is closing fast.Before you say anything to your board or your team - what is actually happening inside you when you read that data?', 'How do you feel internally?', 'தென்கிழக்கு ஆசியாவிற்கான சந்தை நுழைவு உத்தியை உருவாக்குவதில் நீங்கள் ஆறு மாதங்கள் செலவழித்துள்ளீர்கள். அது இயக்குநர்கள் குழுவால் அங்கீகரிக்கப்பட்டுள்ளது. முதலீடும் உறுதிசெய்யப்பட்டுள்ளது. சந்தை தொடங்குவதற்கு இரண்டு வாரங்களுக்கு முன்பு, அந்த உத்தியில் உள்ள முக்கிய வாடிக்கையாளர் குறித்த அனுமானம் தவறாக இருக்கலாம் என்று சுட்டிக்காட்டும் தரவுகளை உங்கள் நாட்டுத் தலைவர் உங்களுக்கு அனுப்புகிறார் - மேலும், பாதையைச் சரிசெய்வதற்கான கால அவகாசமும் வேகமாக குறைந்து வருகிறது. உங்கள் இயக்குநர்கள் குழுவிடமோ அல்லது உங்கள் அணியிடமோ எதையும் சொல்வதற்கு முன்பு - அந்தத் தரவுகளைப் படிக்கும்போது உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'உங்களுக்கு உள்ளுக்குள் எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 3", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the immediate need to take control of the situation - assess it fast, decide fast, act fast, and not let uncertainty sit longer than it has to.', 'சூழ்நிலையை உடனடியாகக் கட்டுப்பாட்டில் கொண்டுவர வேண்டியதன் அவசியத்தை நீங்கள் உணர்கிறீர்கள் - அதை விரைவாக மதிப்பிடுங்கள், விரைவாக முடிவெடுங்கள், விரைவாகச் செயல்படுங்கள், மேலும் இந்த நிச்சயமற்ற நிலையைத் தேவைக்கு அதிகமாக நீடிக்க விடாதீர்கள்.', 'D'),
  (2, 'You feel the complexity of managing this across multiple audiences - the board, the country team, the investors - and the awareness that how you handle the next 48 hours will define how this is remembered.', 'இயக்குநர் குழு, நாட்டுக் குழு, முதலீட்டாளர்கள் எனப் பலதரப்பட்ட தரப்பினரிடையே இதை நிர்வகிப்பதில் உள்ள சிக்கலையும், அடுத்த 48 மணி நேரத்தை நீங்கள் கையாளும் விதமே இது எவ்வாறு நினைவுகூரப்படும் என்பதைத் தீர்மானிக்கும் என்ற விழிப்புணர்வையும் நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the discomfort of having championed something that may now need to change - and the genuine care about what this means for the team that has been building toward this launch.', 'தற்போது மாற்றப்பட வேண்டியிருக்கக்கூடிய ஒரு விஷயத்தை ஆதரித்ததினால் ஏற்படும் சங்கடத்தையும், அதே சமயம் இந்த வெளியீட்டிற்காகக் கட்டமைத்து வந்த குழுவிற்கு இது எத்தகைய தாக்கத்தை ஏற்படுத்தும் என்பது குறித்த உண்மையான அக்கறையையும் நீங்கள் உணர்கிறீர்கள்.', 'S'),
  (4, 'You feel a strong need to verify the data independently before you react - one country head''s read on customer assumptions is not sufficient to unwind six months of validated strategy.', 'நீங்கள் எதிர்வினையாற்றுவதற்கு முன்பு, தரவுகளைச் சுயாதீனமாகச் சரிபார்க்க வேண்டிய வலுவான தேவையை உணர்கிறீர்கள் - ஆறு மாதங்களாகச் சரிபார்க்கப்பட்ட உத்தியைக் கைவிடுவதற்கு, வாடிக்கையாளர் அனுமானங்கள் குறித்த ஒரு நாட்டுத் தலைவரின் கணிப்பு மட்டும் போதுமானதல்ல.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q17',
     'You are integrating two organisations following a merger. Eight months in, the cultural conflict is open and damaging. Leaders from the acquired company feel colonised. Your own leaders feel their authority is being undermined. Productivity is down 18% in merged teams. The board wants results by end of quarter.', 'How will you resolve conflict?', 'ஒரு இணைப்புக்குப் பிறகு நீங்கள் இரண்டு நிறுவனங்களை ஒருங்கிணைக்கிறீர்கள். எட்டு மாதங்கள் கழிந்த நிலையில், கலாச்சார மோதல் வெளிப்படையாகவும் பாதிப்பை ஏற்படுத்துவதாகவும் உள்ளது. கையகப்படுத்தப்பட்ட நிறுவனத்தின் தலைவர்கள் தாங்கள் அடிமைப்படுத்தப்பட்டதாக உணர்கிறார்கள். உங்கள் சொந்தத் தலைவர்கள் தங்கள் அதிகாரம் குறைமதிப்பிற்கு உட்படுத்தப்படுவதாக உணர்கிறார்கள். இணைக்கப்பட்ட குழுக்களில் உற்பத்தித்திறன் 18% குறைந்துள்ளது. இந்தக் காலாண்டின் இறுதிக்குள் முடிவுகளை வாரியம் எதிர்பார்க்கிறது.', 'மோதலை எவ்வாறு தீர்ப்பீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 1", "dimension": "change_tolerance", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You make structural decisions - clarify accountabilities, remove ambiguity from the reporting lines, and make it clear that the integration timeline is not negotiable regardless of cultural comfort.', 'நீங்கள் கட்டமைப்பு சார்ந்த முடிவுகளை எடுக்கிறீர்கள் - பொறுப்புகளைத் தெளிவுபடுத்துங்கள், அறிக்கையிடல் முறைகளில் உள்ள தெளிவின்மையை நீக்குங்கள், மேலும் கலாச்சார ரீதியான சௌகரியத்தைப் பொருட்படுத்தாமல் ஒருங்கிணைப்புக் காலக்கெடுவில் பேச்சுவார்த்தைக்கு இடமில்லை என்பதைத் தெளிவுபடுத்துங்கள்.', 'D'),
  (2, 'You bring the two leadership cohorts together in a structured offsite, facilitate honest dialogue, and invest in building genuine relationships before you push for performance outcomes.', 'செயல்திறன் சார்ந்த முடிவுகளை வலியுறுத்துவதற்கு முன்பு, நீங்கள் இரண்டு தலைமைத்துவக் குழுக்களையும் ஒரு கட்டமைக்கப்பட்ட வெளிக்களச் சந்திப்பில் ஒன்றிணைத்து, நேர்மையான உரையாடலை எளிதாக்கி, உண்மையான உறவுகளைக் கட்டியெழுப்புவதில் முதலீடு செய்கிறீர்கள்.', 'I'),
  (3, 'You slow the integration pace in the highest-conflict areas, protect the functioning parts of both cultures, and prioritise stability over speed while trust is rebuilt.', 'அதிக மோதல் நிலவும் பகுதிகளில் ஒருங்கிணைப்பின் வேகத்தைக் குறைத்து, இரு கலாச்சாரங்களின் செயல்படும் பகுதிகளைப் பாதுகாத்து, நம்பிக்கை மீண்டும் கட்டியெழுப்பப்படும் அதே வேளையில் வேகத்தை விட நிலைத்தன்மைக்கு முன்னுரிமை அளிக்க வேண்டும்.', 'S'),
  (4, 'You commission a cultural diagnostic, identify the specific friction points with data, and build an integration roadmap that addresses each one systematically before making structural changes.', 'நீங்கள் ஒரு கலாச்சாரப் பகுப்பாய்வை மேற்கொண்டு, தரவுகளைக் கொண்டு குறிப்பிட்ட முரண்பாட்டுப் புள்ளிகளை அடையாளம் கண்டு, கட்டமைப்பு மாற்றங்களைச் செய்வதற்கு முன்பு ஒவ்வொன்றையும் முறையாகக் கையாளும் ஒரு ஒருங்கிணைப்புத் திட்ட வரைபடத்தை உருவாக்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q18',
     'You have introduced a new performance management system that requires managers to have transparent, documented conversations about individual performance - including low ratings. Six months in, adoption is inconsistent. Several senior managers are avoiding the hard conversations entirely and inflating scores to manage relationships. The system is becoming theatre.', 'How will you handle conflict?', 'குறைந்த மதிப்பீடுகள் உட்பட, தனிநபர் செயல்திறன் குறித்து மேலாளர்கள் வெளிப்படையான, ஆவணப்படுத்தப்பட்ட உரையாடல்களை நடத்த வேண்டும் எனக் கோரும் ஒரு புதிய செயல்திறன் மேலாண்மை முறையை நீங்கள் அறிமுகப்படுத்தியுள்ளீர்கள். ஆறு மாதங்கள் கழிந்தும், இதை ஏற்றுக்கொள்வது சீரற்றதாக உள்ளது. பல மூத்த மேலாளர்கள் இந்தக் கடினமான உரையாடல்களை முற்றிலுமாகத் தவிர்த்து, உறவுகளை நிர்வகிப்பதற்காக மதிப்பெண்களைப் பெருக்கிக் காட்டுகிறார்கள். இந்த முறை ஒரு நாடகமாக மாறி வருகிறது.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 1", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You make adherence non-negotiable - managers who are not using the system as designed will face consequences, and you will enforce this personally if needed.', 'பின்பற்றுவதை நீங்கள் விட்டுக்கொடுக்க முடியாததாக ஆக்குகிறீர்கள் - இந்த அமைப்பை வடிவமைக்கப்பட்டபடி பயன்படுத்தாத மேலாளர்கள் விளைவுகளைச் சந்திக்க நேரிடும், மேலும் தேவைப்பட்டால் இதை நீங்கள் தனிப்பட்ட முறையில் அமல்படுத்துவீர்கள்.', 'D'),
  (2, 'You identify the managers who are using it well, make them visible, and build a peer influence movement around authentic adoption rather than forcing compliance from the top.', 'இதைச் சிறப்பாகப் பயன்படுத்தும் மேலாளர்களை நீங்கள் அடையாளம் கண்டு, அவர்களை வெளிச்சத்திற்குக் கொண்டு வந்து, மேலிருந்து இணக்கத்தைத் திணிப்பதற்குப் பதிலாக, உண்மையான தத்தெடுப்பை மையமாகக் கொண்டு ஒரு சக ஊழியர் செல்வாக்கு இயக்கத்தை உருவாக்குகிறீர்கள்.', 'I'),
  (3, 'You have individual conversations with the managers who are avoiding it, understand what is making it hard for them, and work to remove the barriers before escalating to enforcement.', 'இதைத் தவிர்த்துவரும் மேலாளர்களுடன் நீங்கள் தனிப்பட்ட முறையில் உரையாடி, அவர்களுக்கு எது சிரமத்தை ஏற்படுத்துகிறது என்பதைப் புரிந்துகொண்டு, அமலாக்க நடவடிக்கைக்குச் செல்வதற்கு முன் அந்தத் தடைகளை அகற்றப் பணியாற்ற வேண்டும்.', 'S'),
  (4, 'You analyse adoption data by team and manager, identify where the system design is creating the avoidance behaviour, and fix the structural problems before blaming the people.', 'நீங்கள் குழு மற்றும் மேலாளர் வாரியாகத் தத்தெடுப்புத் தரவைப் பகுப்பாய்வு செய்து, அமைப்பு வடிவமைப்பு எங்கு தவிர்ப்பு நடத்தையை உருவாக்குகிறது என்பதைக் கண்டறிந்து, மக்களைக் குறை கூறுவதற்கு முன்பு கட்டமைப்புச் சிக்கல்களைச் சரிசெய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q19',
     'A long-serving leader - 22 years with the company, trusted, loved by the organisation - has been found to have consistently tolerated a toxic sub-culture in his division. The behaviour has not been illegal but it has been damaging. Three high-potential women have left because of it in the past 18 months. You now know. You must decide what to do.Two things are pulling at you. Which is stronger - the pull to protect someone who has given everything to this organisation and may not fully understand the harm he caused, or the pull to act decisively because the culture you say you stand for demands it and the people who left deserved better?', 'How will you handle culture?', 'நிறுவனத்தில் 22 ஆண்டுகள் பணியாற்றி, நிறுவனத்தால் நம்பப்பட்டு, நேசிக்கப்பட்ட ஒரு நீண்டகாலத் தலைவர், தனது பிரிவில் நிலவிய ஒரு நச்சுத்தன்மை வாய்ந்த உள் கலாச்சாரத்தைத் தொடர்ந்து சகித்து வந்திருப்பது கண்டறியப்பட்டுள்ளது. அந்த நடத்தை சட்டவிரோதமானதல்ல, ஆனால் அது பாதிப்பை ஏற்படுத்தியுள்ளது. கடந்த 18 மாதங்களில், அதிகத் திறனுள்ள மூன்று பெண்கள் இதன் காரணமாகப் பணியை விட்டு விலகியுள்ளனர். இப்போது உங்களுக்குத் தெரியும். என்ன செய்வதென்று நீங்கள் முடிவு செய்ய வேண்டும். இரண்டு விஷயங்கள் உங்களை இழுக்கின்றன. எது வலிமையானது - இந்த நிறுவனத்திற்காகத் தன் அனைத்தையும் அர்ப்பணித்த, தான் ஏற்படுத்திய தீங்கை முழுமையாகப் புரிந்துகொள்ளாத ஒருவரைக் காக்க வேண்டும் என்ற ஈர்ப்பா, அல்லது நீங்கள் ஆதரிப்பதாகக் கூறும் கலாச்சாரம் அதைக் கோருவதாலும், பணியை விட்டு விலகியவர்கள் இதைவிடச் சிறந்ததற்குத் தகுதியானவர்கள் என்பதாலும் உறுதியாகச் செயல்பட வேண்டும் என்ற ஈர்ப்பா?', 'கலாச்சாரத்தை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 2", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Decisive action. The culture you lead is defined by what you tolerate. You cannot protect legacy at the expense of the people who paid the price for it.', 'தீர்க்கமான நடவடிக்கை. நீங்கள் எதைச் சகித்துக்கொள்கிறீர்களோ, அதைக் கொண்டே நீங்கள் வழிநடத்தும் கலாச்சாரம் வரையறுக்கப்படுகிறது. அதற்காக விலை கொடுத்த மக்களின் நலனைப் பலிகொடுத்து, அந்தப் பாரம்பரியத்தை உங்களால் பாதுகாக்க முடியாது.', 'D'),
  (2, 'Honest conversation first. You owe him the truth - directly, privately, and with genuine care - before any formal process begins. How he responds will shape what comes next.', 'முதலில் நேர்மையான உரையாடல். எந்தவொரு முறையான செயல்முறையும் தொடங்குவதற்கு முன்பு, நீங்கள் அவரிடம் உண்மையை நேரடியாக, தனிப்பட்ட முறையில், உண்மையான அக்கறையுடன் கூறக் கடமைப்பட்டுள்ளீர்கள். அவர் எவ்வாறு பதிலளிக்கிறார் என்பதுதான் அடுத்து என்ன நடக்கும் என்பதைத் தீர்மானிக்கும்.', 'I'),
  (3, 'A careful transition. You want to find a way to address the harm, support the people affected, and manage his exit - if it comes to that - in a way that does not destroy a 22-year relationship publicly.', 'இது ஒரு கவனமான மாற்றம். ஏற்பட்ட பாதிப்பைச் சரிசெய்யவும், பாதிக்கப்பட்டவர்களுக்கு ஆதரவளிக்கவும், ஒருவேளை அவர் வெளியேற நேர்ந்தால் அதை நிர்வகிக்கவும், 22 வருட உறவைப் பொதுவெளியில் சிதைக்காத வகையில் ஒரு வழியைக் கண்டறிய வேண்டும்.', 'S'),
  (4, 'A complete picture. You want to understand the full scope of what happened, who knew, what was reported and when, before you decide what action is proportionate and defensible.', 'ஒரு முழுமையான சித்திரம். எந்த நடவடிக்கை பொருத்தமானது மற்றும் நியாயமானது என்று தீர்மானிப்பதற்கு முன், என்ன நடந்தது, யாருக்குத் தெரிந்திருந்தது, என்ன எப்போது புகாரளிக்கப்பட்டது என்பதன் முழு வீச்சையும் நீங்கள் புரிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q20',
     'You have just signed off on a return-to-office mandate requiring all senior leaders to be in the office four days a week. The policy was agreed at board level. Two of your most valued executives - both of whom relocated their families during the pandemic and built their lives around remote work - have told you privately they will resign if it is enforced.The honest feeling underneath this - before you speak to HR, before you revisit the policy, before you respond to them - what are you actually feeling?', 'How are you really feeling?', 'அனைத்து மூத்த தலைவர்களும் வாரத்தில் நான்கு நாட்கள் அலுவலகத்தில் இருக்க வேண்டும் என்ற, அலுவலகத்திற்குத் திரும்புதல் கட்டளைக்கு நீங்கள் இப்போதுதான் ஒப்புதல் அளித்துள்ளீர்கள். இந்தக் கொள்கை இயக்குநர்கள் குழு மட்டத்தில் ஒப்புக்கொள்ளப்பட்டது. உங்களால் மிகவும் மதிக்கப்படும் இரண்டு நிர்வாகிகள் - பெருந்தொற்று காலத்தில் தங்கள் குடும்பங்களை வேறு இடத்திற்கு மாற்றி, தொலைதூரப் பணியைச் சுற்றியே தங்கள் வாழ்க்கையை அமைத்துக் கொண்டவர்கள் - இந்தக் கொள்கை அமல்படுத்தப்பட்டால் தாங்கள் ராஜினாமா செய்வதாக உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளனர். இதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்னவென்றால் - நீங்கள் மனிதவளத் துறையிடம் பேசுவதற்கு முன்பும், இந்தக் கொள்கையை மறுபரிசீலனை செய்வதற்கு முன்பும், அவர்களுக்குப் பதிலளிப்பதற்கு முன்பும் - நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the tension between holding a position you committed to and the real cost of losing two people who are genuinely hard to replace - and you are already thinking about whether the policy is worth that price.', 'நீங்கள் உறுதியளித்த ஒரு பதவியைத் தக்கவைத்துக் கொள்வதற்கும், உண்மையாகவே மாற்றுவதற்கு கடினமான இரண்டு நபர்களை இழப்பதன் உண்மையான விலைக்கும் இடையிலான பதற்றத்தை உணர்கிறீர்கள் - மேலும் அந்த விலைக்கு இந்தக் கொள்கை தகுதியானதா என்று நீங்கள் ஏற்கனவே சிந்திக்கத் தொடங்கிவிட்டீர்கள்.', 'D'),
  (2, 'You feel the relational weight of it - these are people you respect and like, and the idea of losing them because of a structural policy rather than a performance issue feels wrong in a way that is hard to articulate.', 'அதன் உறவுரீதியான பாரத்தை நீங்கள் உணர்கிறீர்கள் - இவர்கள் நீங்கள் மதிக்கும் மற்றும் விரும்பும் நபர்கள், மேலும் செயல்திறன் பிரச்சனையால் அல்லாமல் ஒரு கட்டமைப்பு கொள்கையின் காரணமாக அவர்களை இழக்க நேரிடும் என்ற எண்ணம், வார்த்தைகளால் விவரிக்க முடியாத ஒரு விதத்தில் தவறாகத் தோன்றுகிறது.', 'I'),
  (3, 'You feel genuine conflict. The policy is right for the organisation. The people are right for the organisation. You do not want to choose between them and you are not sure you have to.', 'உங்களுக்கு உண்மையான ஒரு முரண்பாடு ஏற்படுகிறது. அந்தக் கொள்கை நிறுவனத்திற்குச் சரியானது. அதில் பணியாற்றும் நபர்கள் நிறுவனத்திற்குப் பொருத்தமானவர்கள். நீங்கள் அவர்களுக்கு இடையே ஒருவரைத் தேர்ந்தெடுக்க விரும்பவில்லை, அதே சமயம் அப்படிச் செய்ய வேண்டுமா என்பதும் உங்களுக்கு உறுதியாகத் தெரியவில்லை.', 'S'),
  (4, 'You feel the need to understand whether the policy is actually achieving what it was designed to achieve before you enforce it at the cost of talent you cannot easily replace.', 'எளிதில் மாற்றீடு செய்ய முடியாத திறமையாளர்களை இழக்கும் விலையில் ஒரு கொள்கையை அமல்படுத்துவதற்கு முன்பு, அது வடிவமைக்கப்பட்ட நோக்கத்தை உண்மையில் நிறைவேற்றுகிறதா என்பதைப் புரிந்துகொள்ள வேண்டிய அவசியத்தை நீங்கள் உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q21',
     'In a leadership team meeting, a peer CXO presents a proposal that directly overlaps with an initiative your division has been leading for six months. He presents it as his own without any reference to your work. The CEO responds positively. The room moves on.', 'How do you address credit?', 'ஒரு தலைமைத்துவக் குழு கூட்டத்தில், சக தலைமை நிர்வாக அதிகாரி ஒருவர், உங்கள் பிரிவு ஆறு மாதங்களாக முன்னெடுத்துவரும் ஒரு முயற்சியுடன் நேரடியாகப் பொருந்தக்கூடிய ஒரு முன்மொழிவை முன்வைக்கிறார். உங்கள் பணியைப் பற்றி எந்தக் குறிப்பும் இல்லாமல், அவர் அதைத் தனது சொந்த முன்மொழிவாக முன்வைக்கிறார். தலைமை நிர்வாக அதிகாரி சாதகமாகப் பதிலளிக்கிறார். கூட்டம் அடுத்த கட்டத்திற்கு நகர்கிறது.', 'கடனை எவ்வாறு கையாளுகிறீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise it in the room - calmly, specifically, and without drama - and make clear that this builds on work your division has already completed.', 'நீங்கள் அதை அறையில் - அமைதியாகவும், குறிப்பாகவும், ஆர்ப்பாட்டமின்றியும் - எழுப்பி, இது உங்கள் பிரிவு ஏற்கனவே முடித்த பணியின் தொடர்ச்சி என்பதைத் தெளிவுபடுத்த வேண்டும்.', 'D'),
  (2, 'You let the meeting close, then speak to the peer directly and privately to understand whether this was deliberate or an oversight - and to make clear it cannot happen again.', 'கூட்டம் முடிந்த பிறகு, இது வேண்டுமென்றே செய்யப்பட்டதா அல்லது கவனக்குறைவால் ஏற்பட்டதா என்பதைப் புரிந்துகொள்வதற்கும், இது மீண்டும் நடக்காது என்பதைத் தெளிவுபடுத்துவதற்கும், உங்கள் சக ஊழியரிடம் நேரடியாகவும் தனிப்பட்ட முறையிலும் பேசுங்கள்.', 'I'),
  (3, 'You say nothing in the room to avoid a public conflict, flag it to your CEO separately, and focus on protecting the relationship with your peer while ensuring your contribution is on record.', 'பொது மோதலைத் தவிர்ப்பதற்காக அறையில் எதுவும் பேசாமல், அதை உங்கள் தலைமை நிர்வாக அதிகாரிக்குத் தனியாகத் தெரிவித்து, உங்கள் பங்களிப்புப் பதிவு செய்யப்படுவதை உறுதிசெய்துகொண்டே, உங்கள் சக ஊழியருடனான உறவைப் பாதுகாப்பதில் கவனம் செலுத்துங்கள்.', 'S'),
  (4, 'You document the timeline of your division''s work, share it with the CEO in a follow-up note, and let the evidence speak without making the interpersonal dynamic a visible issue.', 'உங்கள் பிரிவின் பணிகளின் காலவரிசையை ஆவணப்படுத்தி, அதை ஒரு பின்தொடர் குறிப்பில் தலைமை நிர்வாக அதிகாரியுடன் பகிர்ந்து, தனிப்பட்ட உறவுமுறைகளை வெளிப்படையான ஒரு பிரச்சினையாக மாற்றாமல், சான்றுகளே பேசட்டும் என்று விட்டுவிடுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q22',
     'You have been informally told by a trusted board member that you are the leading candidate for the Group CEO role. Two weeks later, a peer with strong external visibility and board relationships is brought in as a consultant to lead a high-profile strategic review - a role you expected to lead. Nothing official has changed but the signal is ambiguous.', 'How will you handle ambiguity?', 'குழுமத்தின் தலைமைச் செயல் அதிகாரி (CEO) பதவிக்கு நீங்கள்தான் முன்னணி வேட்பாளர் என்று, நம்பகமான ஒரு நிர்வாகக் குழு உறுப்பினர் உங்களுக்கு முறைசாரா முறையில் தெரிவித்துள்ளார். இரண்டு வாரங்களுக்குப் பிறகு, வலுவான வெளித் தொடர்புகளையும் நிர்வாகக் குழு உறவுகளையும் கொண்ட உங்கள் சக ஊழியர் ஒருவர், ஒரு முக்கியத்துவம் வாய்ந்த உத்திசார் ஆய்வை வழிநடத்த ஆலோசகராக நியமிக்கப்படுகிறார் - இந்தப் பொறுப்பை நீங்கள்தான் வழிநடத்துவீர்கள் என்று எதிர்பார்த்திருந்தீர்கள். அதிகாரப்பூர்வமாக எதுவும் மாறவில்லை, ஆனால் இதன் மூலம் வெளிப்படும் செய்தி தெளிவற்றதாக உள்ளது.', 'தெளிவற்ற தன்மையை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 1", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a direct conversation with the chairman, name what you have observed, and ask for clarity on where you stand - you will not spend energy managing ambiguity when a direct conversation can resolve it.', 'தலைவருடன் நேரடி உரையாடலுக்குக் கோரிக்கை விடுங்கள், நீங்கள் கவனித்தவற்றைக் குறிப்பிடுங்கள், மேலும் உங்கள் நிலைப்பாடு குறித்துத் தெளிவு கேளுங்கள் - ஒரு நேரடி உரையாடலால் தீர்க்கப்படக்கூடிய தெளிவற்ற தன்மையைச் சமாளிப்பதில் உங்கள் ஆற்றலைச் செலவிட மாட்டீர்கள்.', 'D'),
  (2, 'You increase your own visibility - take on additional board interactions, strengthen key relationships, and make your strategic thinking more present in the conversations that matter.', 'உங்கள் இருப்பை நீங்களே வெளிப்படுத்திக் கொள்ளுங்கள் - கூடுதல் நிர்வாகக் குழு கலந்துரையாடல்களை மேற்கொள்ளுங்கள், முக்கிய உறவுகளை வலுப்படுத்துங்கள், மேலும் முக்கியத்துவம் வாய்ந்த உரையாடல்களில் உங்கள் வியூகச் சிந்தனையை அதிகளவில் வெளிப்படுத்துங்கள்.', 'I'),
  (3, 'You stay focused on delivering results in your current role, trust that your track record speaks, and resist the urge to play internal politics in a situation that may be less significant than it feels.', 'உங்கள் தற்போதைய பணியில் சிறந்த முடிவுகளை வழங்குவதில் கவனம் செலுத்துங்கள், உங்கள் முந்தைய சாதனைகளே பேசும் என நம்புங்கள், மேலும் வெளித்தோற்றத்தில் முக்கியத்துவம் குறைந்ததாகத் தோன்றும் ஒரு சூழலில் உள்ளக அரசியல் விளையாடும் ஆசையைத் தவிர்த்துவிடுங்கள்.', 'S'),
  (4, 'You gather more information before acting - speak to two or three trusted colleagues, understand the context behind the consultant appointment, and assess whether your read of the situation is accurate.', 'செயல்படுவதற்கு முன் நீங்கள் கூடுதல் தகவல்களைச் சேகரிக்க வேண்டும் - நம்பகமான இரண்டு அல்லது மூன்று சக ஊழியர்களிடம் பேசுங்கள், ஆலோசகர் நியமனத்தின் பின்னணியைப் புரிந்து கொள்ளுங்கள், மேலும் சூழ்நிலை குறித்த உங்கள் கணிப்பு துல்லியமானதா என்பதை மதிப்பிடுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q23',
     'You and a peer CXO have a long-standing professional respect but a persistent tension around resource allocation. In a leadership offsite, he proposes a shared services model that would effectively move three of your key functions under a central unit he would lead. The CEO is listening with interest.What matters more to you in this moment - protecting the operational control and autonomy that makes your division effective, or being seen as a collaborative leader who puts the organisation''s efficiency above divisional interests?', 'How will you handle conflict?', 'உங்களுக்கும் உங்கள் சக CXO-வுக்கும் இடையே நீண்டகால தொழில்முறை மரியாதை இருந்தாலும், வள ஒதுக்கீடு தொடர்பாக ஒரு தொடர்ச்சியான பதற்றம் நிலவுகிறது. ஒரு தலைமைத்துவக் கூட்டத்தில், அவர் ஒரு பகிரப்பட்ட சேவை மாதிரியை முன்மொழிகிறார். அது, உங்கள் மூன்று முக்கியப் பணிகளை அவர் தலைமை தாங்கும் ஒரு மையப் பிரிவின் கீழ் திறம்படக் கொண்டுவரும். தலைமைச் செயல் அதிகாரி (CEO) ஆர்வத்துடன் கேட்டுக்கொண்டிருக்கிறார். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம் - உங்கள் பிரிவைத் திறம்படச் செயல்பட வைக்கும் செயல்பாட்டுக் கட்டுப்பாட்டையும் தன்னாட்சியையும் பாதுகாப்பதா, அல்லது பிரிவு நலன்களை விட நிறுவனத்தின் செயல்திறனுக்கு முன்னுரிமை அளிக்கும் ஒரு கூட்டுத் தலைவராகக் கருதப்படுவதா?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 2", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Protecting control. You know what your division needs to perform and centralising these functions will slow you down regardless of how the model is presented.', 'கட்டுப்பாட்டைப் பாதுகாத்தல். உங்கள் பிரிவு என்ன செய்ய வேண்டும் என்பது உங்களுக்குத் தெரியும்; மாதிரி எவ்வாறு முன்வைக்கப்பட்டாலும், இந்தச் செயல்பாடுகளை மையப்படுத்துவது உங்கள் வேகத்தைக் குறைக்கும்.', 'D'),
  (2, 'Being seen as collaborative. You will engage constructively with the proposal - and use your influence in that process to shape it in a direction that protects what matters most to your division.', 'ஒத்துழைப்புடன் செயல்படுபவராகக் கருதப்படுதல். நீங்கள் அந்த முன்மொழிவுடன் ஆக்கப்பூர்வமாக ஈடுபடுவீர்கள் - மேலும், உங்கள் பிரிவுக்கு மிகவும் முக்கியமானவற்றைப் பாதுகாக்கும் திசையில் அதை வடிவமைக்க, அந்தச் செயல்பாட்டில் உங்கள் செல்வாக்கைப் பயன்படுத்துவீர்கள்.', 'I'),
  (3, 'Protecting relationships. You do not want this to become a public confrontation with a peer you respect - you would rather find a solution that both of you can live with.', 'உறவுகளைப் பாதுகாத்தல். நீங்கள் மதிக்கும் ஒரு சக ஊழியருடன் இது ஒரு பொது மோதலாக மாறுவதை நீங்கள் விரும்ப மாட்டீர்கள் - மாறாக, உங்கள் இருவராலும் ஏற்றுக்கொள்ளக்கூடிய ஒரு தீர்வைக் காணவே விரும்புவீர்கள்.', 'S'),
  (4, 'Getting the analysis right. You want to see the evidence that a shared services model will actually deliver the efficiency gains before you agree to restructure something that is currently working.', 'பகுப்பாய்வைச் சரியாகச் செய்வது. தற்போது சிறப்பாகச் செயல்படும் ஒன்றை மறுசீரமைக்க ஒப்புக்கொள்வதற்கு முன்பு, பகிரப்பட்ட சேவைகள் மாதிரியானது உண்மையில் செயல்திறன் மேம்பாடுகளை வழங்கும் என்பதற்கான ஆதாரத்தை நீங்கள் காண வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q24',
     'You have been passed over for a promotion that was explicitly discussed with you as the next step in your career. A peer who joined 18 months ago has been appointed instead. The CEO calls you personally to explain the decision and asks you to stay and support the transition.Before you say anything on that call - what is actually happening inside you?', 'How do you feel inside?', 'உங்கள் தொழில் வாழ்க்கையின் அடுத்த கட்டம் என்று உங்களுடன் வெளிப்படையாக விவாதிக்கப்பட்ட ஒரு பதவி உயர்வு உங்களுக்கு மறுக்கப்பட்டுள்ளது. அதற்குப் பதிலாக, 18 மாதங்களுக்கு முன்பு சேர்ந்த உங்கள் சக ஊழியர் ஒருவர் நியமிக்கப்பட்டுள்ளார். தலைமை நிர்வாக அதிகாரி (CEO) இந்த முடிவை விளக்குவதற்காக உங்களைத் தனிப்பட்ட முறையில் அழைத்து, இந்த மாற்றத்திற்கு ஆதரவளிக்குமாறும், பணியில் நீடிக்குமாறும் கேட்டுக்கொள்கிறார். அந்த அழைப்பில் நீங்கள் எதையும் சொல்வதற்கு முன் - உண்மையில் உங்கள் உள்ளுக்குள் என்னதான் நடக்கிறது?', 'உங்களுக்குள் எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 3", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel anger - clean, clear anger - and underneath it a resolve to decide quickly whether this organisation deserves your continued commitment or whether this is the signal to move.', 'உங்களுக்குள் ஒரு கோபம் எழுகிறது - தூய்மையான, தெளிவான கோபம் - அதன் அடியில், இந்த அமைப்புக்கு உங்கள் தொடர்ச்சியான அர்ப்பணிப்பு தேவையா அல்லது இது விலகுவதற்கான சமிக்ஞையா என்பதை விரைவாக முடிவு செய்ய வேண்டும் என்ற உறுதியும் குடிகொள்கிறது.', 'D'),
  (2, 'You feel the complexity of the moment - aware of how you respond on this call will be watched and interpreted, and that your composure or lack of it will define how you are seen from this point forward.', 'அந்தத் தருணத்தின் சிக்கலான தன்மையை நீங்கள் உணர்கிறீர்கள்; இந்த அழைப்பில் நீங்கள் பதிலளிக்கும் விதம் கவனிக்கப்பட்டு, அதற்கேற்ப விளக்கம் அளிக்கப்படும் என்பதையும், உங்கள் நிதானம் அல்லது அதன் பற்றாக்குறைதான் இனிமேல் நீங்கள் எப்படிப் பார்க்கப்படுவீர்கள் என்பதைத் தீர்மானிக்கும் என்பதையும் நீங்கள் அறிந்திருக்கிறீர்கள்.', 'I'),
  (3, 'You feel hurt. Not rage - hurt. Because you trusted the conversation, trusted the process, and trusted the people. And that trust has just been broken in a way that takes time to absorb.', 'நீங்கள் காயப்பட்டதாக உணர்கிறீர்கள். அது கோபம் அல்ல - காயம். ஏனென்றால், நீங்கள் அந்த உரையாடலை நம்பினீர்கள், அந்த செயல்முறையை நம்பினீர்கள், அந்த மக்களை நம்பினீர்கள். அந்த நம்பிக்கை இப்போது உடைந்துவிட்டது; அதை உள்வாங்கிக்கொள்ள சிறிது காலம் ஆகும்.', 'S'),
  (4, 'You feel the need to understand the real reason before you react. The explanation you are about to hear may or may not be the full picture - and you want to listen carefully before you decide anything.', 'எதிர்வினையாற்றுவதற்கு முன் உண்மையான காரணத்தைப் புரிந்துகொள்ள வேண்டிய அவசியத்தை நீங்கள் உணர்கிறீர்கள். நீங்கள் கேட்கப்போகும் விளக்கம் முழுமையானதாக இருக்கலாம் அல்லது இல்லாமலும் இருக்கலாம் - எனவே, எதையும் தீர்மானிப்பதற்கு முன் நீங்கள் கவனமாகக் கேட்க விரும்புகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q25',
     'Your CFO of seven years has resigned with four weeks notice to join a competitor. She has been central to your investor relationships, your banking covenants, and two ongoing regulatory submissions. You have no internal successor ready. The board expects continuity.', 'How to handle CFO resignation?', 'ஏழு ஆண்டுகளாக உங்கள் நிறுவனத்தின் தலைமை நிதி அதிகாரியாகப் பணியாற்றியவர், ஒரு போட்டி நிறுவனத்தில் சேருவதற்காக, நான்கு வார கால அவகாசத்தில் ராஜினாமா செய்துள்ளார். உங்கள் முதலீட்டாளர் உறவுகள், வங்கி ஒப்பந்தங்கள் மற்றும் தற்போது நடைபெற்று வரும் இரண்டு ஒழுங்குமுறை சமர்ப்பிப்புகள் ஆகியவற்றில் அவர் முக்கியப் பங்கு வகித்துள்ளார். அவருக்குப் பதிலாகப் பொறுப்பேற்க உங்களிடம் நிறுவனத்திற்குள் யாரும் தயாராக இல்லை. இயக்குநர் குழு, தொடர்ச்சியை எதிர்பார்க்கிறது.', 'தலைமை நிதி அதிகாரியின் ராஜினாமாவை எவ்வாறு கையாள்வது?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You move immediately - activate your network, brief two executive search firms, and begin conversations with two or three known candidates in parallel while you personally cover the critical investor and regulatory touchpoints.', 'நீங்கள் உடனடியாகச் செயல்படுங்கள் - உங்கள் தொடர்பு வட்டத்தைச் செயல்படுத்துங்கள், இரண்டு உயர்நிலை நிர்வாகத் தேடல் நிறுவனங்களுக்கு விவரங்களை விளக்குங்கள், மேலும் முக்கியமான முதலீட்டாளர் மற்றும் ஒழுங்குமுறை சார்ந்த சந்திப்புகளை நீங்கள் தனிப்பட்ட முறையில் கையாளும் அதே வேளையில், நன்கு அறியப்பட்ட இரண்டு அல்லது மூன்று வேட்பாளர்களுடன் ஒரே நேரத்தில் உரையாடல்களைத் தொடங்குங்கள்.', 'D'),
  (2, 'You bring your finance leadership team together, identify who has the strongest relationships and capabilities, and build a collective bridge while the search runs - distributing the load across people rather than carrying it alone.', 'உங்கள் நிதித் தலைமை அணியை ஒன்றிணைத்து, யாரிடம் வலுவான உறவுகளும் திறன்களும் உள்ளன என்பதைக் கண்டறிந்து, தேடல் நடைபெறும்போதே ஒரு கூட்டுப் பாலத்தை உருவாக்குகிறீர்கள் - இதன் மூலம் சுமையை தனியாகச் சுமக்காமல் அனைவரிடமும் பகிர்ந்தளிக்கிறீர்கள்.', 'I'),
  (3, 'You stabilise the function first - ensure your team feels secure, that no critical process is at risk, and that the transition is managed calmly before you turn your attention to the external search.', 'முதலில் நீங்கள் செயல்பாட்டை நிலைப்படுத்த வேண்டும் - உங்கள் குழுவினர் பாதுகாப்பாக உணர்வதையும், எந்தவொரு முக்கிய செயல்முறையும் ஆபத்தில் இல்லை என்பதையும், இந்த மாற்றம் அமைதியாகக் கையாளப்படுவதையும் உறுதிசெய்த பின்னரே, வெளிப்புறத் தேடலில் உங்கள் கவனத்தைத் திருப்ப வேண்டும்.', 'S'),
  (4, 'You map every critical dependency she owns - every relationship, covenant, submission, and process - before you brief a search firm, so you know exactly what the successor role requires and what the interim period must protect.', 'ஒரு தேடல் நிறுவனத்திற்கு விளக்கமளிப்பதற்கு முன்பு, அவருக்குச் சொந்தமான ஒவ்வொரு முக்கிய சார்புநிலையையும் - ஒவ்வொரு உறவு, உடன்படிக்கை, சமர்ப்பிப்பு மற்றும் செயல்முறை - நீங்கள் வரைபடமாக்குகிறீர்கள். இதன்மூலம், வாரிசுப் பணிக்கு என்ன தேவை என்பதையும், இடைக்காலம் எதைப் பாதுகாக்க வேண்டும் என்பதையும் நீங்கள் துல்லியமாக அறிந்துகொள்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q26',
     'A high-potential leader you have been developing for three years has been approached by a competitor and has come to you honestly to discuss it. She is not threatening - she is transparent. She says she feels ready for a role larger than what currently exists for her in your organisation.', 'How will you retain her?', 'நீங்கள் மூன்று ஆண்டுகளாக வளர்த்து வரும், அதிகத் திறனுள்ள ஒரு தலைவரை, அவரது போட்டியாளர் ஒருவர் அணுகி, அது குறித்து உங்களிடம் நேர்மையாகப் பேச வந்துள்ளார். அவர் மிரட்டலாகப் பேசவில்லை; வெளிப்படையாக இருக்கிறார். உங்கள் நிறுவனத்தில் தற்போது அவருக்காக இருக்கும் பதவியை விடப் பெரிய ஒரு பொறுப்பிற்குத் தான் தயாராக இருப்பதாக அவர் கூறுகிறார்.', 'அவளை எப்படித் தக்கவைத்துக் கொள்வீர்கள்?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 1", "dimension": "relationship_dependency", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell her directly what you can offer, what the realistic timeline is, and if the competitor''s opportunity is genuinely better for her career you will support her in taking it - you will not make promises you cannot keep to retain her.', 'உங்களால் என்ன வழங்க முடியும், அதற்கான யதார்த்தமான காலக்கெடு என்ன என்பதை அவளிடம் நேரடியாகக் கூறுங்கள். மேலும், போட்டியாளரின் வாய்ப்பு அவளது தொழில் வாழ்க்கைக்கு உண்மையிலேயே சிறந்ததாக இருந்தால், அதை அவள் ஏற்றுக்கொள்வதற்கு நீங்கள் ஆதரவளிப்பீர்கள் என்றும், அவளைத் தக்கவைத்துக் கொள்வதற்காக உங்களால் நிறைவேற்ற முடியாத வாக்குறுதிகளை அளிக்க மாட்டீர்கள் என்றும் சொல்லுங்கள்.', 'D'),
  (2, 'You invest in the conversation fully - understand what is driving the pull, what she needs to feel valued and seen, and work to create a path that genuinely addresses her ambition before she makes a decision.', 'நீங்கள் அந்த உரையாடலில் முழுமையாக ஈடுபடுங்கள் - அவளை ஈர்ப்பதற்கான காரணம் என்ன, அவள் மதிக்கப்படுவதாகவும் கவனிக்கப்படுவதாகவும் உணர அவளுக்கு என்ன தேவை என்பதைப் புரிந்துகொண்டு, அவள் ஒரு முடிவை எடுப்பதற்கு முன்பே அவளுடைய லட்சியத்தை உண்மையாகவே நிறைவேற்றும் ஒரு பாதையை உருவாக்கப் பாடுபடுங்கள்.', 'I'),
  (3, 'You express how much she means to the team and the organisation, explore whether there is a way to expand her role or responsibility in the near term, and ask her to give you time before she decides.', 'அவர் குழுவிற்கும் நிறுவனத்திற்கும் எவ்வளவு முக்கியமானவர் என்பதை நீங்கள் வெளிப்படுத்துங்கள், குறுகிய காலத்தில் அவரது பங்கு அல்லது பொறுப்பை விரிவுபடுத்த வழி உள்ளதா என ஆராயுங்கள், மேலும் அவர் முடிவெடுப்பதற்கு முன் உங்களுக்கு அவகாசம் அளிக்குமாறு அவரிடம் கேளுங்கள்.', 'S'),
  (4, 'You assess what is actually available - internally and structurally - before making any commitment, so that whatever you offer is real and not a retention promise you will struggle to deliver.', 'எந்தவொரு உறுதிமொழியையும் அளிப்பதற்கு முன், நிறுவனத்திற்குள்ளும் கட்டமைப்பு ரீதியாகவும் உண்மையில் என்னென்ன வசதிகள் உள்ளன என்பதை நீங்கள் மதிப்பிட வேண்டும். அப்போதுதான், நீங்கள் வழங்குவது உண்மையானதாக இருக்கும், மேலும் அதை நிறைவேற்ற நீங்கள் சிரமப்படும் ஒரு தக்கவைப்பு வாக்குறுதியாக அது இருக்காது.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q27',
     'You are the deciding vote on a succession decision for a critical business unit head role. Two internal candidates have been assessed. Candidate A is the safer choice - experienced, known, lower risk. Candidate B is higher potential, less proven at this level, and your personal conviction is that she is the right long-term bet - but she could struggle in the first 12 months.Two things are pulling at you. Which is stronger - the fiduciary responsibility to the organisation to minimise execution risk in a critical role, or your conviction as a leader that developing and backing high-potential talent is itself a strategic responsibility?', 'How will you manage succession?', 'ஒரு முக்கிய வணிகப் பிரிவுத் தலைவர் பதவிக்கான வாரிசு நியமன முடிவில் தீர்மானிக்கும் அதிகாரம் உங்களுடையது. நிறுவனத்திற்குள்ளிருந்து இரண்டு வேட்பாளர்கள் மதிப்பீடு செய்யப்பட்டுள்ளனர். வேட்பாளர் A ஒரு பாதுகாப்பான தேர்வு - அனுபவம் வாய்ந்தவர், நன்கு அறியப்பட்டவர், மற்றும் குறைந்த இடர்பாடு உடையவர். வேட்பாளர் B அதிக ஆற்றல் கொண்டவர், ஆனால் இந்த மட்டத்தில் அவ்வளவாக நிரூபிக்கப்படாதவர். நீண்ட காலத்திற்கு அவரே சரியான தேர்வு என்பது உங்கள் தனிப்பட்ட நம்பிக்கை - ஆனாலும், முதல் 12 மாதங்களில் அவர் சிரமப்படக்கூடும். இரண்டு விஷயங்கள் உங்களை உந்துகின்றன. எது வலிமையானது - ஒரு முக்கியப் பதவியில் செயல்படுத்தும் இடரைக் குறைப்பதற்கான நிறுவனத்தின் மீதான நம்பிக்கைப் பொறுப்பா, அல்லது அதிக ஆற்றல் கொண்ட திறமையாளர்களை வளர்ப்பதும் அவர்களுக்கு ஆதரவளிப்பதும் ஒரு உத்திசார்ந்த பொறுப்பு என்ற ஒரு தலைவராக உங்கள் நம்பிக்கையா?', 'வாரிசுரிமையை எவ்வாறு நிர்வகிப்பீர்கள்?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 2", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Back Candidate B. Organisations that always take the safe choice in succession decisions build safe, average leadership pipelines. Your job is to make the call others won''t.', 'வேட்பாளர் B-க்கு ஆதரவளியுங்கள். வாரிசுரிமை முடிவுகளில் எப்போதும் பாதுகாப்பான தேர்வை மேற்கொள்ளும் நிறுவனங்கள், பாதுகாப்பான, சராசரியான தலைமைத்துவத் தொடர்வரிசைகளை உருவாக்குகின்றன. மற்றவர்கள் எடுக்கத் துணியாத அந்த முடிவை எடுப்பதுதான் உங்கள் வேலை.', 'D'),
  (2, 'Back Candidate B - but invest personally in her success. Your conviction means nothing without the support system to back it up. You will be in her corner for the full first year.', 'வேட்பாளர் B-க்கு ஆதரவளியுங்கள் - ஆனால் அவரது வெற்றியில் தனிப்பட்ட முறையில் முதலீடு செய்யுங்கள். உங்கள் உறுதியான நம்பிக்கைக்குப் பின்புலமாக ஒரு ஆதரவு அமைப்பு இல்லையென்றால், அதற்கு எந்த மதிப்பும் இல்லை. முதல் வருடம் முழுவதும் நீங்கள் அவருக்குத் துணையாக இருப்பீர்கள்.', 'I'),
  (3, 'Back Candidate A - for now. The timing is wrong for a developmental bet. You will create the right opportunity for Candidate B when the risk profile is lower.', 'தற்போதைக்கு, போட்டியாளர் A-க்கு ஆதரவளியுங்கள். ஒரு மேம்பாட்டு முயற்சிக்கு இது சரியான நேரம் அல்ல. இடர் அளவு குறைவாக இருக்கும்போது, ​​போட்டியாளர் B-க்கு நீங்கள் சரியான வாய்ப்பை உருவாக்குவீர்கள்.', 'S'),
  (4, 'Commission a structured assessment of both candidates against the specific demands of this role at this moment - your gut is data, but it is not sufficient data for a decision of this consequence.', 'தற்போதைய நிலையில் இந்தப் பதவியின் குறிப்பிட்ட தேவைகளுக்கு ஏற்ப, இரு வேட்பாளர்களையும் ஒரு கட்டமைக்கப்பட்ட மதிப்பீட்டிற்கு உட்படுத்துங்கள் - உங்கள் உள்ளுணர்வு ஒரு தரவுதான், ஆனால் இத்தகைய முக்கியத்துவம் வாய்ந்த ஒரு முடிவை எடுப்பதற்கு அது மட்டும் போதுமான தரவு அல்ல.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q28',
     'You have spent 18 months building a succession plan for your own role. Your board has approved it. The internal successor you championed has been announced. Three weeks later, it becomes clear he is struggling - the board is losing confidence, two senior stakeholders have raised concerns privately, and you are beginning to question your own judgment.What is actually happening inside you when you realise the succession may be failing?', 'How will you handle this?', 'உங்கள் பதவிக்கான வாரிசுத் திட்டத்தை உருவாக்குவதில் நீங்கள் 18 மாதங்களைச் செலவழித்துள்ளீர்கள். உங்கள் நிர்வாகக் குழு அதற்கு ஒப்புதல் அளித்துள்ளது. நீங்கள் முன்னிறுத்திய உள்ளக வாரிசு அறிவிக்கப்பட்டுவிட்டார். மூன்று வாரங்களுக்குப் பிறகு, அவர் சிரமப்படுகிறார் என்பது தெளிவாகிறது - நிர்வாகக் குழு நம்பிக்கையை இழக்கிறது, இரண்டு மூத்த பங்குதாரர்கள் தனிப்பட்ட முறையில் கவலைகளை எழுப்பியுள்ளனர், மேலும் உங்கள் சொந்த முடிவெடுக்கும் திறனையே நீங்களும் கேள்விக்குள்ளாக்கத் தொடங்குகிறீர்கள். வாரிசுத் திட்டம் தோல்வியடையக்கூடும் என்பதை நீங்கள் உணரும்போது, ​​உங்களுக்குள் உண்மையில் என்னதான் நிகழ்கிறது?', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 3", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the urgency to intervene - to use whatever influence you still have to stabilise the situation before it becomes irreversible and before your judgment is publicly questioned.', 'நிலைமை மீளமுடியாத நிலையை அடைவதற்கு முன்பும், உங்கள் முடிவெடுக்கும் திறன் பகிரங்கமாகக் கேள்விக்குள்ளாக்கப்படுவதற்கு முன்பும், அதைச் சீர்செய்ய உங்களிடம் எஞ்சியிருக்கும் செல்வாக்கைப் பயன்படுத்தித் தலையிட வேண்டிய அவசரத்தை நீங்கள் உணர்கிறீர்கள்.', 'D'),
  (2, 'You feel the exposure of having been the person who championed this appointment - aware that your credibility and legacy are now partly tied to how this plays out.', 'இந்த நியமனத்தை முன்னெடுத்தவர் நீங்கள்தான் என்ற வெளிப்பாட்டை உணர்கிறீர்கள்; உங்கள் நம்பகத்தன்மையும் புகழும் இப்போது ஓரளவிற்கு இது எவ்வாறு முடிவடைகிறது என்பதைப் பொறுத்தே அமைந்துள்ளன என்பதையும் நீங்கள் அறிந்திருக்கிறீர்கள்.', 'I'),
  (3, 'You feel responsible for him personally. You brought him to this moment. If he is struggling, part of that is on you - and you want to help him, not just protect yourself.', 'தனிப்பட்ட முறையில் அவருக்கு நீங்கள் பொறுப்பு என்று உணர்கிறீர்கள். நீங்கள்தான் அவரை இந்த நிலைக்குக் கொண்டு வந்தீர்கள். அவர் சிரமப்படுகிறார் என்றால், அதில் ஒரு பகுதிக்கு நீங்களும் பொறுப்பு - மேலும் நீங்கள் உங்களைப் பாதுகாத்துக் கொள்வதோடு மட்டுமல்லாமல், அவருக்கு உதவவும் விரும்புகிறீர்கள்.', 'S'),
  (4, 'You feel the need to assess clearly and honestly whether the concerns are about his capability, the support he has been given, or the conditions he inherited - before you decide what intervention, if any, is warranted.', 'என்ன தலையீடு தேவை என்பதைத் தீர்மானிப்பதற்கு முன், அந்தக் கவலைகள் அவருடைய திறனைப் பற்றியதா, அவருக்கு வழங்கப்பட்ட ஆதரவைப் பற்றியதா, அல்லது அவர் மரபுரிமையாகப் பெற்ற நிலைமைகளைப் பற்றியதா என்பதைத் தெளிவாகவும் நேர்மையாகவும் மதிப்பிட வேண்டியதன் அவசியத்தை நீங்கள் உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q29',
     'A key government ministry has informally signalled that approvals for your new plant - 18 months in development - will be delayed unless you appoint a specific individual to your advisory board. The individual is known to be politically connected but professionally undistinguished. Your legal team says it is not illegal. Your ethics team says it is a grey area.', 'How will you handle this?', 'உங்கள் ஆலோசனைக் குழுவில் ஒரு குறிப்பிட்ட நபரை நீங்கள் நியமிக்காவிட்டால், 18 மாதங்களாக உருவாக்கப்பட்டு வரும் உங்கள் புதிய ஆலைக்கான ஒப்புதல்கள் தாமதமாகும் என்று ஒரு முக்கிய அரசாங்க அமைச்சகம் முறைசாரா முறையில் தெரிவித்துள்ளது. அந்த நபர் அரசியல் செல்வாக்கு மிக்கவர் என்றும், ஆனால் தொழில்ரீதியாகப் புகழ்பெற்றவர் அல்ல என்றும் அறியப்படுகிறது. இது சட்டவிரோதமானது அல்ல என்று உங்கள் சட்டக் குழு கூறுகிறது. இது ஒரு தெளிவற்ற பகுதி என்று உங்கள் நெறிமுறைக் குழு கூறுகிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 1", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You decline. You will find another way to move the approvals forward - through legitimate channels, industry bodies, or direct ministerial engagement - and you will not create a dependency on a relationship you do not respect.', 'நீங்கள் மறுத்துவிடுவீர்கள். முறையான வழிகள், தொழில்துறை அமைப்புகள் அல்லது நேரடி அமைச்சர் ஈடுபாடு ஆகியவற்றின் மூலம் ஒப்புதல்களை முன்னெடுத்துச் செல்ல மற்றொரு வழியைக் கண்டுபிடிப்பீர்கள்; மேலும், நீங்கள் மதிக்காத ஓர் உறவைச் சார்ந்திருக்கும் நிலையை உருவாக்க மாட்டீர்கள்.', 'D'),
  (2, 'You engage a senior government relations advisor to navigate the situation and find an alternative path that satisfies the ministry''s underlying interest without the specific appointment they have signalled.', 'அவர்கள் சுட்டிக்காட்டியுள்ள குறிப்பிட்ட நியமனம் இல்லாமலேயே, அமைச்சகத்தின் அடிப்படை நலன்களைப் பூர்த்தி செய்யும் ஒரு மாற்று வழியைக் கண்டறிந்து, அந்தச் சூழ்நிலையைச் சமாளிப்பதற்காக நீங்கள் ஒரு மூத்த அரசாங்க உறவுகள் ஆலோசகரை நியமிக்கிறீர்கள்.', 'I'),
  (3, 'You slow down, protect your team from the pressure, and give the situation time to clarify - sometimes these signals do not materialise into actual blocks and you do not want to make a permanent decision in response to an informal one.', 'நீங்கள் நிதானித்து, உங்கள் அணியை அழுத்தத்திலிருந்து பாதுகாத்து, நிலைமை தெளிவடைய நேரம் கொடுக்க வேண்டும் - சில சமயங்களில் இந்த அறிகுறிகள் உண்மையான தடைகளாக உருவெடுப்பதில்லை, மேலும் ஒரு முறைசாரா முடிவுக்குப் பதிலளிக்கும் விதமாக நீங்கள் ஒரு நிரந்தர முடிவை எடுக்க விரும்ப மாட்டீர்கள்.', 'S'),
  (4, 'You document the signal, brief your board audit committee, and get a formal legal and governance opinion before making any decision - you will not act on informal pressure without a clear record.', 'எந்தவொரு முடிவையும் எடுப்பதற்கு முன், நீங்கள் அந்த சமிக்ஞையை ஆவணப்படுத்தி, உங்கள் வாரிய தணிக்கைக் குழுவுக்கு விளக்கமளித்து, முறையான சட்ட மற்றும் நிர்வாகக் கருத்தைப் பெற வேண்டும் - தெளிவான பதிவு இல்லாமல் முறைசாரா அழுத்தத்தின் பேரில் நீங்கள் செயல்பட மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q30',
     'You are leading a major infrastructure project that requires approvals from three separate government departments. Two departments have cleared. The third - whose minister has been publicly critical of your sector - is stalling. Your investors are watching the timeline. Your construction partner has given you a 60-day window before costs escalate.', 'How will you handle delay?', 'மூன்று வெவ்வேறு அரசுத் துறைகளின் ஒப்புதல்கள் தேவைப்படும் ஒரு பெரிய உள்கட்டமைப்புத் திட்டத்தை நீங்கள் வழிநடத்துகிறீர்கள். இரண்டு துறைகள் ஒப்புதல் அளித்துவிட்டன. உங்கள் துறையைப் பகிரங்கமாக விமர்சித்த அமைச்சரைக் கொண்ட மூன்றாவது துறை, தாமதப்படுத்துகிறது. உங்கள் முதலீட்டாளர்கள் காலக்கெடுவைக் கவனித்து வருகின்றனர். செலவுகள் அதிகரிப்பதற்கு முன்பு, உங்கள் கட்டுமானக் கூட்டாளர் உங்களுக்கு 60 நாட்கள் அவகாசம் அளித்துள்ளார்.', 'தாமதத்தை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a direct meeting with the minister, make the economic case personally, and if necessary escalate to the chief minister''s office - you will not let one department define the outcome of a project of this scale.', 'நீங்கள் அமைச்சருடன் நேரடி சந்திப்பைக் கோருங்கள், பொருளாதார ரீதியான காரணங்களை நேரில் எடுத்துரையுங்கள், தேவைப்பட்டால் முதலமைச்சர் அலுவலகத்திற்கும் இதைக் கொண்டு செல்லுங்கள் - இந்த அளவிலான ஒரு திட்டத்தின் முடிவை ஒரே ஒரு துறை தீர்மானிக்க நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'D'),
  (2, 'You map the minister''s stakeholder network, identify the relationships that can open the right door, and build your path to approval through people rather than through confrontation.', 'நீங்கள் அமைச்சரின் பங்குதாரர் வலையமைப்பை வரைபடமாக்கி, சரியான வழியைத் திறக்கக்கூடிய உறவுகளை அடையாளம் கண்டு, மோதல்கள் மூலமாக அல்லாமல் மக்கள் வழியாக உங்கள் ஒப்புதலுக்கான பாதையை அமைத்துக் கொள்கிறீர்கள்.', 'I'),
  (3, 'You work through the department''s official channels methodically, demonstrate full compliance with every requirement, and build a record of cooperation that makes continued stalling difficult to justify.', 'நீங்கள் துறையின் அதிகாரப்பூர்வ வழிமுறைகள் மூலம் முறையாகப் பணியாற்றி, ஒவ்வொரு தேவைக்கும் முழுமையாக இணங்குவதை நிரூபித்து, தொடர்ந்து தாமதம் செய்வதை நியாயப்படுத்துவது கடினமாக இருக்கும் அளவிற்கு ஓர் ஒத்துழைப்புப் பதிவை உருவாக்குகிறீர்கள்.', 'S'),
  (4, 'You commission an independent review of every technical and regulatory requirement for the approval, eliminate any legitimate objection the department could raise, and make the decision to stall a purely political one with no procedural cover.', 'ஒப்புதலுக்கான ஒவ்வொரு தொழில்நுட்ப மற்றும் ஒழுங்குமுறைத் தேவை குறித்தும் ஒரு சுயாதீனமான ஆய்வுக்கு நீங்கள் ஆணையிடுகிறீர்கள், துறை எழுப்பக்கூடிய எந்தவொரு நியாயமான ஆட்சேபனையையும் நீக்குகிறீர்கள், மேலும் தாமதப்படுத்தும் முடிவை எந்தவொரு நடைமுறைப் பாதுகாப்பும் இல்லாத முற்றிலும் அரசியல் ரீதியான ஒன்றாக ஆக்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q31',
     'Your company is a significant employer in a state where a contentious election is approaching. Both major parties have approached you - one asking for a public statement of support, the other asking you to stay neutral in exchange for regulatory goodwill. Your employees, investors, and customers span both sides of the political divide.What matters more to you in this moment - the principle that your organisation should not be drawn into political alignment, or the pragmatic reality that regulatory goodwill in this sector has material consequences for your business and your people''s livelihoods?', 'How will you handle politics?', 'சர்ச்சைக்குரிய தேர்தல் ஒன்று நெருங்கிக்கொண்டிருக்கும் ஒரு மாநிலத்தில், உங்கள் நிறுவனம் ஒரு முக்கிய வேலைவாய்ப்பு வழங்குநராக விளங்குகிறது. இரு முக்கிய கட்சிகளும் உங்களை அணுகியுள்ளன - ஒரு கட்சி பொது ஆதரவு அறிக்கை ஒன்றையும், மற்றொரு கட்சி ஒழுங்குமுறை நல்லெண்ணத்திற்கு ஈடாக நீங்கள் நடுநிலை வகிக்க வேண்டும் என்றும் கோரியுள்ளன. உங்கள் ஊழியர்கள், முதலீட்டாளர்கள் மற்றும் வாடிக்கையாளர்கள் அரசியல் பிளவின் இரு பக்கங்களிலும் உள்ளனர். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - உங்கள் நிறுவனம் அரசியல் சார்புநிலைக்குள் இழுக்கப்படக்கூடாது என்ற கொள்கையா, அல்லது இந்தத் துறையில் உள்ள ஒழுங்குமுறை நல்லெண்ணம் உங்கள் வணிகத்திற்கும் உங்கள் மக்களின் வாழ்வாதாரத்திற்கும் குறிப்பிடத்தக்க விளைவுகளை ஏற்படுத்தும் என்ற நடைமுறை உண்மையா?', 'அரசியலை எப்படி கையாள்வீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 2", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The principle. You will not trade regulatory goodwill for political alignment. That path, once started, does not end well.', 'கொள்கை இதுதான். அரசியல் சார்புக்காக ஒழுங்குமுறை நல்லெண்ணத்தை நீங்கள் கைவிடக்கூடாது. அந்தப் பாதை, ஒருமுறை தொடங்கிவிட்டால், நல்ல முடிவில் முடிவதில்லை.', 'D'),
  (2, 'The relationships. You will manage both conversations carefully, stay neutral publicly, and ensure that neither party sees you as hostile - politics is about relationships, not statements.', 'உறவுகள். நீங்கள் இரு தரப்பு உரையாடல்களையும் கவனமாகக் கையாள்வீர்கள், பொதுவெளியில் நடுநிலையாக இருப்பீர்கள், மேலும் எந்தத் தரப்பும் உங்களை விரோதியாகக் கருதாமல் இருப்பதை உறுதி செய்வீர்கள் - அரசியல் என்பது உறவுகளைப் பற்றியது, அறிக்கைகளைப் பற்றியது அல்ல.', 'I'),
  (3, 'The stability of your people and organisation. You will do what protects jobs and continuity - and if that means navigating political relationships carefully, that is your responsibility as a leader.', 'உங்கள் பணியாளர்கள் மற்றும் நிறுவனத்தின் நிலைத்தன்மை. வேலைகளையும் தொடர்ச்சியையும் பாதுகாக்கும் செயல்களை நீங்கள் செய்வீர்கள் - அதற்காக அரசியல் உறவுகளைக் கவனமாகக் கையாள வேண்டியிருந்தாலும், ஒரு தலைவராக அது உங்கள் பொறுப்பாகும்.', 'S'),
  (4, 'The governance position. You will establish a clear, documented policy on political neutrality and apply it consistently - your defence against both parties is a principled position, not a negotiated one.', 'ஆளுகை நிலைப்பாடு. நீங்கள் அரசியல் நடுநிலைமை குறித்த தெளிவான, ஆவணப்படுத்தப்பட்ட கொள்கையை உருவாக்கி, அதைத் தொடர்ச்சியாகச் செயல்படுத்துவீர்கள் - இரு கட்சிகளுக்கும் எதிரான உங்கள் பாதுகாப்பு என்பது ஒரு கொள்கை ரீதியான நிலைப்பாடே தவிர, பேச்சுவார்த்தை மூலம் எட்டப்பட்டதல்ல.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q32',
     'You have just learned that a competitor has obtained what appears to be a confidential strategic document from your organisation. The document outlines your market entry plan for the next 24 months. You do not yet know how it was obtained. Your strategy team is shaken. Your board has been informed.Before you say anything to your board or your team - what is actually happening inside you?', 'How do you feel inside?', 'உங்கள் நிறுவனத்திடமிருந்து, இரகசியமானதாகத் தோன்றும் ஒரு மூலோபாய ஆவணத்தை ஒரு போட்டியாளர் பெற்றுவிட்டார் என்பதை நீங்கள் இப்போதுதான் அறிந்துகொண்டீர்கள். அந்த ஆவணம், அடுத்த 24 மாதங்களுக்கான உங்கள் சந்தை நுழைவுத் திட்டத்தை விவரிக்கிறது. அது எப்படிப் பெறப்பட்டது என்பது உங்களுக்கு இன்னும் தெரியவில்லை. உங்கள் மூலோபாயக் குழு அதிர்ந்துள்ளது. உங்கள் நிர்வாகக் குழுவிற்குத் தகவல் தெரிவிக்கப்பட்டுள்ளது. உங்கள் நிர்வாகக் குழுவிடமோ அல்லது உங்கள் குழுவிடமோ எதையும் சொல்வதற்கு முன் - உங்களுக்குள் உண்மையில் என்னதான் நடந்துகொண்டிருக்கிறது?', 'உங்களுக்குள் எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 3", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the instinct to find out who did this and act - fast, decisively, and without ambiguity. Whoever is responsible for this breach will be held accountable.', 'இதைச் செய்தவர் யார் என்பதைக் கண்டறிந்து, விரைவாகவும், உறுதியாகவும், சந்தேகத்திற்கு இடமின்றியும் செயல்பட வேண்டும் என்ற உள்ளுணர்வு உங்களுக்குள் எழுகிறது. இந்த மீறலுக்குப் பொறுப்பானவர் எவராக இருந்தாலும், அவர் பொறுப்பேற்க வைக்கப்படுவார்.', 'D'),
  (2, 'You feel the reputational and relational exposure - aware of how this looks to your board, your investors, and your team, and the importance of how you lead through the next 72 hours.', 'உங்கள் நற்பெயர் மற்றும் உறவுகளில் ஏற்படக்கூடிய பாதிப்பை நீங்கள் உணர்கிறீர்கள்; இது உங்கள் நிர்வாகக் குழு, முதலீட்டாளர்கள் மற்றும் உங்கள் குழுவினருக்கு எப்படித் தோற்றமளிக்கும் என்பதையும், அடுத்த 72 மணி நேரத்தில் நீங்கள் எவ்வாறு வழிநடத்துகிறீர்கள் என்பதன் முக்கியத்துவத்தையும் நீங்கள் அறிந்திருக்கிறீர்கள்.', 'I'),
  (3, 'You feel a deep discomfort with the idea that someone inside your organisation - someone you may know and trust - may have been responsible for this. That possibility is harder to sit with than the strategic damage.', 'உங்கள் நிறுவனத்திற்குள் இருக்கும், உங்களுக்குத் தெரிந்த மற்றும் நீங்கள் நம்பும் ஒருவர் இதற்குப் பொறுப்பாக இருந்திருக்கலாம் என்ற எண்ணம் உங்களுக்கு ஆழ்ந்த சங்கடத்தை ஏற்படுத்துகிறது. மூலோபாய ரீதியான சேதத்தை விட, அந்த சாத்தியக்கூற்றை ஏற்றுக்கொள்வது கடினமாக உள்ளது.', 'S'),
  (4, 'You feel the need to establish facts before you feel anything definitive. The document may have been obtained through legal competitive intelligence. The breach may be technical rather than human. You will not react to a story you have not verified.', 'உறுதியான முடிவுக்கு வருவதற்கு முன், நீங்கள் உண்மைகளை நிலைநாட்ட வேண்டியதன் அவசியத்தை உணர்கிறீர்கள். அந்த ஆவணம் சட்டரீதியான போட்டிப் புலனாய்வு மூலம் பெறப்பட்டிருக்கலாம். அந்த மீறல் மனிதத் தவறை விட தொழில்நுட்ப ரீதியானதாக இருக்கலாம். நீங்கள் சரிபார்க்காத ஒரு செய்திக்கு எதிர்வினையாற்ற மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q33',
     'A regulator conducting a routine inspection has privately indicated to your compliance head that a specific finding - one that would trigger a significant penalty and public disclosure - could be recorded differently in the report if your organisation demonstrates cooperative intent through an accelerated remediation commitment. Nothing has been put in writing.', 'How will you handle inspection?', 'வழக்கமான ஆய்வை மேற்கொள்ளும் ஒரு ஒழுங்குமுறை ஆணையம், உங்கள் நிறுவனம் துரிதப்படுத்தப்பட்ட சீரமைப்பு உறுதிப்பாட்டின் மூலம் ஒத்துழைக்கும் நோக்கத்தை வெளிப்படுத்தினால், ஒரு குறிப்பிடத்தக்க அபராதம் மற்றும் பொது வெளிப்படுத்தலைத் தூண்டக்கூடிய ஒரு குறிப்பிட்ட குறைபாடு அறிக்கையில் வேறுவிதமாகப் பதிவு செய்யப்படலாம் என்று உங்கள் இணக்கப் பிரிவுத் தலைவரிடம் தனிப்பட்ட முறையில் தெரிவித்துள்ளது. இதுகுறித்து எதுவும் எழுத்துப்பூர்வமாக வழங்கப்படவில்லை.', 'ஆய்வை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You decline immediately and instruct your compliance head to engage the regulator only through formal documented channels from this point forward. You brief your board audit committee the same day.', 'நீங்கள் உடனடியாக மறுத்துவிட்டு, இனிமேல் முறைப்படியான, ஆவணப்படுத்தப்பட்ட வழிகள் மூலமாக மட்டுமே ஒழுங்குமுறை ஆணையத்துடன் தொடர்புகொள்ளுமாறு உங்கள் இணக்கப் பிரிவுத் தலைவருக்கு அறிவுறுத்துகிறீர்கள். அதே நாளில் உங்கள் வாரியத் தணிக்கைக் குழுவுக்கு இதுகுறித்து விளக்கமளிக்கிறீர்கள்.', 'D'),
  (2, 'You escalate to your external legal counsel and your board chair before any further engagement with the regulator - you will not make this decision without the right people in the room.', 'ஒழுங்குமுறை ஆணையத்துடன் மேலும் ஈடுபடுவதற்கு முன்பு, உங்கள் வெளி சட்ட ஆலோசகர் மற்றும் உங்கள் வாரியத் தலைவரிடம் இந்த விஷயத்தைக் கொண்டு செல்லுங்கள் - சரியான நபர்கள் உடன் இல்லாமல் இந்த முடிவை நீங்கள் எடுக்க மாட்டீர்கள்.', 'I'),
  (3, 'You pull back from the inspection process, slow down your compliance head''s engagement, and give yourself time to understand the full implications before responding to a signal that may not mean what it appears to mean.', 'வெளித்தோற்றத்தில் தோன்றும் அர்த்தத்தைத் தராத ஒரு சமிக்ஞைக்குப் பதிலளிக்கும் முன், நீங்கள் ஆய்வுச் செயல்முறையிலிருந்து பின்வாங்கி, உங்கள் இணக்கப் பிரிவுத் தலைவரின் ஈடுபாட்டைக் குறைத்து, அதன் முழுமையான தாக்கங்களைப் புரிந்துகொள்ள உங்களுக்கு அவகாசம் அளிக்க வேண்டும்.', 'S'),
  (4, 'You document every interaction with the regulator to date, request that all future communication be in writing, and commission an independent legal review of your obligations and exposure before deciding how to respond.', 'ஒழுங்குமுறை ஆணையத்துடன் இதுவரையிலான ஒவ்வொரு தொடர்பையும் நீங்கள் ஆவணப்படுத்துகிறீர்கள், எதிர்காலத் தொடர்புகள் அனைத்தும் எழுத்துப்பூர்வமாக இருக்குமாறு கோருகிறீர்கள், மேலும் எவ்வாறு பதிலளிப்பது என்று தீர்மானிப்பதற்கு முன்பு உங்கள் கடமைகள் மற்றும் பாதிப்புகள் குறித்து ஒரு சுயாதீனமான சட்ட மதிப்பாய்வை மேற்கொள்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q34',
     'A strategic investor has asked you to adjust the revenue recognition timeline in your fundraise deck - moving projected revenues 6 months earlier than your finance team believes is defensible. He has indicated this adjustment is what stands between a term sheet and no deal. Your company needs the capital.', 'How will you handle this?', 'ஒரு மூலோபாய முதலீட்டாளர், உங்கள் நிதி திரட்டும் விளக்கவுரையில் உள்ள வருவாய் அங்கீகாரக் காலக்கெடுவைச் சரிசெய்யுமாறு உங்களைக் கேட்டுள்ளார் - அதாவது, உங்கள் நிதிக் குழு ஏற்கத்தக்கது என்று நம்புவதை விட, கணிக்கப்பட்ட வருவாயை 6 மாதங்களுக்கு முன்னதாக மாற்றியுள்ளார். இந்தச் சரிசெய்தல்தான் ஒரு ஒப்பந்தத்திற்கும் ஒப்பந்தம் இல்லாமல் போவதற்கும் இடையில் உள்ள தடையாக இருக்கிறது என்று அவர் சுட்டிக்காட்டியுள்ளார். உங்கள் நிறுவனத்திற்கு மூலதனம் தேவைப்படுகிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 1", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You decline. You will present the numbers your finance team can defend and find another investor if this one requires you to misrepresent your timeline.', 'நீங்கள் மறுத்துவிடுவீர்கள். உங்கள் நிதிக் குழுவால் ஏற்றுக்கொள்ளக்கூடிய புள்ளிவிவரங்களை நீங்கள் முன்வைப்பீர்கள், மேலும் இந்த முதலீட்டாளர் உங்கள் காலக்கெடுவைத் தவறாகக் குறிப்பிட வேண்டிய கட்டாயத்தை ஏற்படுத்தினால், மற்றொரு முதலீட்டாளரைத் தேடுவீர்கள்.', 'D'),
  (2, 'You explore whether there is a legitimate basis - a different accounting treatment, a scenario projection - that could address the investor''s concern without crossing the line your finance team has drawn.', 'உங்கள் நிதிக் குழு வகுத்துள்ள எல்லையைத் தாண்டாமல், முதலீட்டாளரின் கவலையைத் தீர்க்கக்கூடிய ஒரு முறையான அடிப்படை - அதாவது வேறுபட்ட கணக்கியல் முறை, ஒரு சூழ்நிலைக் கணிப்பு - உள்ளதா என்பதை நீங்கள் ஆராய்கிறீர்கள்.', 'I'),
  (3, 'You slow the conversation down, ask for more time, and use the space to find alternative capital sources so you are not making this decision with a gun to your head.', 'நீங்கள் உரையாடலை நிதானப்படுத்தி, கூடுதல் நேரம் கேட்டு, அந்த இடைவெளியை மாற்று மூலதன ஆதாரங்களைக் கண்டறியப் பயன்படுத்திக் கொள்ளுங்கள். இதன் மூலம், நெருக்கடியான சூழலில் இந்த முடிவை எடுக்க வேண்டிய நிலை உங்களுக்கு ஏற்படாது.', 'S'),
  (4, 'You ask your CFO and external auditors to define precisely where the line is - what is aggressive but defensible versus what is misrepresentation - and make your decision based on that technical assessment.', 'ஆக்ரோஷமான ஆனால் நியாயப்படுத்தக்கூடிய கூற்றுகளுக்கும், தவறான சித்தரிப்புகளுக்கும் இடையிலான எல்லைக்கோடு எது என்பதைத் துல்லியமாக வரையறுக்குமாறு உங்கள் தலைமை நிதி அதிகாரி மற்றும் வெளித் தணிக்கையாளர்களிடம் கேட்டு, அந்தத் தொழில்நுட்ப மதிப்பீட்டின் அடிப்படையில் உங்கள் முடிவை எடுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q35',
     'Your most profitable division is run by a leader who consistently delivers results but has been found, for the second time, to have approved a vendor contract that benefits a company in which his brother-in-law holds a minority stake. The conflict of interest was not disclosed. The contracts were commercially fair. No money was stolen. But the governance violation is clear.Two things are pulling at you. Which is stronger - the knowledge that this leader generates 34% of your company''s EBITDA and losing him would be materially painful, or the clarity that a second governance violation cannot be tolerated regardless of commercial contribution?', 'How will you handle misconduct?', 'உங்கள் நிறுவனத்தின் அதிக லாபம் தரும் பிரிவை, தொடர்ந்து சிறந்த முடிவுகளை வழங்கும் ஒரு தலைவர் நடத்தி வருகிறார். ஆனால், அவரது மைத்துனர் சிறுபான்மைப் பங்கு வைத்திருக்கும் ஒரு நிறுவனத்திற்குப் பயனளிக்கும் ஒரு விற்பனையாளர் ஒப்பந்தத்திற்கு அவர் ஒப்புதல் அளித்திருப்பது, இரண்டாவது முறையாகக் கண்டறியப்பட்டுள்ளது. இந்த நல முரண்பாடு வெளியிடப்படவில்லை. அந்த ஒப்பந்தங்கள் வணிகரீதியாக நியாயமானவை. எந்தப் பணமும் திருடப்படவில்லை. ஆனால், நிர்வாக மீறல் தெளிவாகத் தெரிகிறது. இரண்டு விஷயங்கள் உங்களை அலைக்கழிக்கின்றன. எது வலிமையானது - இந்தத் தலைவர் உங்கள் நிறுவனத்தின் 34% EBITDA-வை உருவாக்குகிறார் என்பதும், அவரை இழப்பது பொருளாதார ரீதியாகப் பெரும் வேதனையைத் தரும் என்பதும், அல்லது வணிகப் பங்களிப்பைப் பொருட்படுத்தாமல் இரண்டாவது நிர்வாக மீறலைச் சகித்துக்கொள்ள முடியாது என்ற தெளிவும்?', 'முறைகேட்டை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 2", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The governance line. Commercial performance is not a defence for repeated ethics violations. You act - and you act consistently, because the moment you make exceptions for results, you have no governance at all.', 'ஆளுகைக் கொள்கை. தொடர்ச்சியான நெறிமுறை மீறல்களுக்கு வணிகச் செயல்திறன் ஒரு தற்காப்பு வாதமாகாது. நீங்கள் செயல்பட வேண்டும் - அதுவும் சீராகச் செயல்பட வேண்டும், ஏனெனில் முடிவுகளுக்காக நீங்கள் விதிவிலக்கு அளிக்கும் கணமே, உங்களிடம் ஆளுகை என்பதே இல்லாமல் போய்விடுகிறது.', 'D'),
  (2, 'The honest conversation first. Before any formal process, you sit with him directly and make clear what this means - what you know, what it costs him, and what you need from him now. His response will determine the next step.', 'முதலில் நேர்மையான உரையாடல். எந்தவொரு முறையான செயல்முறைக்கும் முன்பு, நீங்கள் அவருடன் நேரடியாக அமர்ந்து, இதன் அர்த்தம் என்னவென்பதை - உங்களுக்கு என்ன தெரியும், இதனால் அவருக்கு என்ன செலவாகும், இப்போது அவரிடமிருந்து உங்களுக்கு என்ன தேவை என்பதைத் தெளிவுபடுத்துங்கள். அவருடைய பதில் அடுத்த கட்டத்தைத் தீர்மானிக்கும்.', 'I'),
  (3, 'The human reality. This is a person, not a policy violation. You want to find a path that holds him accountable, addresses the governance failure, and does not unnecessarily destroy a career and a relationship.', 'மனித யதார்த்தம். இது ஒரு கொள்கை மீறலல்ல, ஒரு தனிநபர் பிரச்சினை. அவரைப் பொறுப்பேற்கச் செய்து, நிர்வாகத் தோல்வியைச் சரிசெய்து, அதே சமயம் அவரது தொழில் வாழ்க்கையையும் உறவையும் தேவையற்ற முறையில் சிதைக்காத ஒரு வழியை நீங்கள் கண்டறிய வேண்டும்.', 'S'),
  (4, 'The full picture. You want a complete governance review - all vendor contracts, all relationships, all disclosure records - before you decide what action is proportionate. A second violation is serious. You want to know if it is the full picture.', 'முழுமையான சித்திரம். என்ன நடவடிக்கை பொருத்தமானது என்று தீர்மானிப்பதற்கு முன், அனைத்து விற்பனையாளர் ஒப்பந்தங்கள், அனைத்து உறவுகள், அனைத்து வெளிப்படுத்தல் பதிவுகள் என ஒரு முழுமையான நிர்வாக மீளாய்வு உங்களுக்குத் தேவை. இரண்டாவது மீறல் என்பது தீவிரமானது. இது முழுமையான சித்திரம்தானா என்பதை நீங்கள் தெரிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q36',
     'You are preparing for an analyst briefing. Your IR team has drafted a narrative that is technically accurate but deliberately omits context that would lead analysts to a more cautious view of your next quarter. Nothing in the draft is false. But you know that a sophisticated analyst with the full picture would ask harder questions.The honest feeling underneath this - before you approve the draft, before you brief your IR team, before you walk into that room - what are you actually feeling?', 'What are you actually feeling?', 'நீங்கள் ஒரு ஆய்வாளர் விளக்கக் கூட்டத்திற்குத் தயாராகிக் கொண்டிருக்கிறீர்கள். உங்கள் முதலீட்டாளர் உறவுகள் (IRs) குழு, தொழில்நுட்ப ரீதியாகத் துல்லியமான ஒரு விவர வரைவைத் தயாரித்துள்ளது; ஆனால், உங்கள் அடுத்த காலாண்டைப் பற்றி ஆய்வாளர்களை மிகவும் எச்சரிக்கையான கண்ணோட்டத்திற்கு இட்டுச்செல்லும் சூழல் விவரங்களை அது வேண்டுமென்றே தவிர்த்துள்ளது. அந்த வரைவில் எதுவும் பொய்யல்ல. ஆனால், முழுமையான நிலவரத்தை அறிந்த ஒரு தேர்ந்த ஆய்வாளர், இன்னும் கடினமான கேள்விகளைக் கேட்பார் என்பது உங்களுக்குத் தெரியும். இதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்னவென்றால் - அந்த வரைவிற்கு நீங்கள் ஒப்புதல் அளிப்பதற்கு முன்பு, உங்கள் முதலீட்டாளர் உறவுகள் குழுவிற்கு விளக்கமளிப்பதற்கு முன்பு, அந்த அறைக்குள் நுழைவதற்கு முன்பு - நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 3", "dimension": "accuracy_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the tension between your responsibility to manage market expectations and your discomfort with a narrative that is accurate but incomplete - and you are not yet sure which side of that line you are on.', 'சந்தை எதிர்பார்ப்புகளை நிர்வகிக்கும் உங்கள் பொறுப்பிற்கும், துல்லியமான ஆனால் முழுமையற்ற ஒரு கூற்றின் மீதான உங்கள் சங்கடத்திற்கும் இடையே ஒரு பதற்றத்தை நீங்கள் உணர்கிறீர்கள் - மேலும், அந்தக் கோட்டின் எந்தப் பக்கம் நீங்கள் இருக்கிறீர்கள் என்பது உங்களுக்கு இன்னும் உறுதியாகத் தெரியவில்லை.', 'D'),
  (2, 'You feel the awareness that analysts and investors are watching how you communicate, and that your credibility over time is built on whether they feel they can trust what you say - and omission has a way of surfacing.', 'பகுப்பாய்வாளர்களும் முதலீட்டாளர்களும் நீங்கள் உரையாடும் விதத்தைக் கவனித்துக் கொண்டிருக்கிறார்கள் என்ற விழிப்புணர்வை நீங்கள் உணர்கிறீர்கள்; மேலும், நீங்கள் சொல்வதை அவர்களால் நம்ப முடியுமா என்பதைப் பொறுத்தே காலப்போக்கில் உங்கள் நம்பகத்தன்மை கட்டமைக்கப்படுகிறது - இந்நிலையில், நீங்கள் சொல்லாத விஷயங்கள் வெளிப்பட ஒரு வழி உண்டு.', 'I'),
  (3, 'You feel uncomfortable. Not because the draft is wrong - but because you know what it leaves out, and the people in that room deserve better than a technically accurate version of reality.', 'நீங்கள் சங்கடமாக உணர்கிறீர்கள். அந்த வரைவு தவறானது என்பதற்காக அல்ல - மாறாக, அது எதையெல்லாம் விட்டுவிடுகிறது என்பது உங்களுக்குத் தெரியும் என்பதாலும், அந்த அறையில் உள்ளவர்கள், தொழில்நுட்ப ரீதியாகத் துல்லியமான ஒரு யதார்த்தத்தை விடச் சிறந்ததற்குத் தகுதியானவர்கள் என்பதாலும்தான்.', 'S'),
  (4, 'You feel the need to review the draft against your disclosure obligations precisely - not because you distrust your IR team but because the line between selective presentation and material omission is one you will not cross without being certain where it sits.', 'உங்கள் தகவல் மீட்டெடுப்புக் குழுவின் மீது உங்களுக்கு அவநம்பிக்கை இருப்பதனால் அல்ல, மாறாக, தேர்ந்தெடுக்கப்பட்ட தகவல்களை வழங்குவதற்கும் முக்கியமான தகவல்களை மறைப்பதற்கும் இடையிலான கோடு எங்கே இருக்கிறது என்பதில் உங்களுக்கு உறுதியாகத் தெரியாமல் நீங்கள் அதைக் கடக்க மாட்டீர்கள் என்பதாலேயே, உங்கள் வெளிப்படுத்தல் கடமைகளுக்கு எதிராக அந்த வரைவை நீங்கள் துல்லியமாக மதிப்பாய்வு செய்ய வேண்டிய அவசியத்தை உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q37',
     'You have been running at full capacity for 14 consecutive months - a merger, a restructuring, a regulatory crisis, and a leadership team transition, all overlapping. Your doctor has told you your stress markers are at a level that requires intervention. Your board has offered you a two-week break. Your organisation is in the middle of a critical quarter.', 'How will you handle this?', 'தொடர்ச்சியாக 14 மாதங்களாக நீங்கள் முழுத் திறனுடன் இயங்கிக் கொண்டிருக்கிறீர்கள் - ஒரு இணைப்பு, ஒரு மறுசீரமைப்பு, ஒரு ஒழுங்குமுறை நெருக்கடி, மற்றும் ஒரு தலைமைத்துவக் குழு மாற்றம் என அனைத்தும் ஒன்றன்பின் ஒன்றாக நிகழ்ந்துள்ளன. உங்கள் மன அழுத்தக் குறிகாட்டிகள் தலையீடு தேவைப்படும் அளவில் இருப்பதாக உங்கள் மருத்துவர் கூறியுள்ளார். உங்கள் நிர்வாகக் குழு உங்களுக்கு இரண்டு வார கால ஓய்வை வழங்கியுள்ளது. உங்கள் நிறுவனம் ஒரு முக்கியமான காலாண்டின் மத்தியில் உள்ளது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You take the break - not because you want to but because you know that a leader operating at diminished capacity is a liability, and protecting your health is protecting your organisation.', 'நீங்கள் அந்த ஓய்வை எடுப்பது, உங்கள் விருப்பத்தினால் அல்ல; மாறாக, திறன் குறைந்த நிலையில் செயல்படும் ஒரு தலைவர் ஒரு சுமையாக இருப்பார் என்பதையும், உங்கள் உடல்நலத்தைப் பாதுகாப்பதே உங்கள் நிறுவனத்தைப் பாதுகாப்பதாகும் என்பதையும் நீங்கள் அறிந்திருப்பதாலேயே ஆகும்.', 'D'),
  (2, 'You delegate the two weeks to your leadership team, use the time to step back rather than step away, and stay connected at a level that lets you rest without creating anxiety in the organisation.', 'அந்த இரண்டு வாரங்களை உங்கள் தலைமைத்துவக் குழுவிடம் ஒப்படைத்து, ஒதுங்கிச் செல்வதற்குப் பதிலாகப் பின்வாங்குவதற்கு அந்த நேரத்தைப் பயன்படுத்திக்கொண்டு, நிறுவனத்தில் பதற்றத்தை ஏற்படுத்தாமல் நீங்கள் ஓய்வெடுக்க அனுமதிக்கும் ஒரு மட்டத்தில் தொடர்பில் இருங்கள்.', 'I'),
  (3, 'You delay the break by three weeks until the quarter closes - you cannot fully rest if you are worried about what is happening - and commit to a proper break once the critical period passes.', 'காலாண்டு முடியும் வரை மூன்று வாரங்களுக்கு உங்கள் ஓய்வைத் தாமதப்படுத்துங்கள் - என்ன நடக்கிறது என்பது குறித்து நீங்கள் கவலைப்பட்டால் உங்களால் முழுமையாக ஓய்வெடுக்க முடியாது - மேலும், அந்த நெருக்கடியான காலகட்டம் முடிந்தவுடன் ஒரு முறையான ஓய்வை எடுத்துக்கொள்ள உறுதி கொள்ளுங்கள்.', 'S'),
  (4, 'You assess which specific commitments in the next two weeks are truly irreplaceable and which can be delegated or deferred - and build a structured handover that lets you take the break without operational risk.', 'அடுத்த இரண்டு வாரங்களில் எந்தெந்தக் குறிப்பிட்ட கடமைகள் உண்மையிலேயே மாற்றீடு செய்ய முடியாதவை, எவற்றை மற்றவர்களிடம் ஒப்படைக்கலாம் அல்லது ஒத்திவைக்கலாம் என்பதை நீங்கள் மதிப்பீடு செய்து, செயல்பாட்டு இடர் இல்லாமல் நீங்கள் ஓய்வு எடுக்க உதவும் ஒரு கட்டமைக்கப்பட்ட பொறுப்பு ஒப்படைப்புத் திட்டத்தை உருவாக்குகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q38',
     'You have noticed over the past six months that you are making decisions more slowly, second-guessing yourself more often, and feeling less certain about calls that would previously have felt clear. You have not discussed this with anyone. Your team has not raised it. But you feel it.', 'Why are you becoming indecisive?', 'கடந்த ஆறு மாதங்களாக, நீங்கள் முடிவெடுப்பதில் அதிக வேகம் காட்டுவதையும், உங்களை நீங்களே அடிக்கடி சந்தேகப்படுவதையும், முன்பு தெளிவாக இருந்ததாகத் தோன்றிய முடிவுகள் குறித்து இப்போது குறைந்த உறுதியுடன் உணர்வதையும் கவனித்திருக்கிறீர்கள். இதைப்பற்றி நீங்கள் யாரிடமும் விவாதிக்கவில்லை. உங்கள் குழுவும் இதைக் குறிப்பிடவில்லை. ஆனால், நீங்கள் அதை உணர்கிறீர்கள்.', 'நீங்கள் ஏன் முடிவெடுக்க முடியாமல் தவிக்கிறீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 1", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name it to yourself and act on it - identify what has changed, whether it is a specific domain of decisions or a broader pattern, and address it directly rather than hoping it resolves on its own.', 'நீங்களே அதை அடையாளம் கண்டு அதற்கேற்ப செயல்படுங்கள் - அது ஒரு குறிப்பிட்ட முடிவெடுக்கும் துறையாக இருந்தாலும் சரி அல்லது ஒரு பரந்த போக்காக இருந்தாலும் சரி, என்ன மாற்றம் ஏற்பட்டுள்ளது என்பதைக் கண்டறிந்து, அது தானாகவே சரியாகிவிடும் என்று நம்புவதற்குப் பதிலாக அதை நேரடியாக எதிர்கொள்ளுங்கள்.', 'D'),
  (2, 'You have a trusted conversation - with a coach, a mentor, or a peer you respect - not to diagnose the problem but to think out loud with someone who will be honest with you.', 'பிரச்சனையைக் கண்டறிவதற்காக அல்ல, மாறாக உங்களிடம் நேர்மையாக இருக்கும் ஒருவருடன் உங்கள் எண்ணங்களை உரக்கப் பகிர்ந்துகொள்வதற்காக, நீங்கள் மதிக்கும் ஒரு பயிற்சியாளர், வழிகாட்டி அல்லது சக ஊழியருடன் நம்பகமான உரையாடலை மேற்கொள்கிறீர்கள்.', 'I'),
  (3, 'You give it time. Leadership capacity moves in cycles and you have been through demanding periods before. You will observe it for another quarter before concluding it is a pattern rather than a phase.', 'அதற்குக் கால அவகாசம் கொடுங்கள். தலைமைத்துவத் திறன் சுழற்சி முறையில் மாறும், மேலும் நீங்கள் இதற்கு முன்பும் சவாலான காலகட்டங்களைக் கடந்து வந்திருக்கிறீர்கள். இது ஒரு தற்காலிக நிலை அல்ல, மாறாக ஒரு தொடர் நிகழ்வு என்று முடிவுக்கு வருவதற்கு முன், இன்னும் ஒரு காலாண்டுக்கு நீங்கள் இதைக் கவனிப்பீர்கள்.', 'S'),
  (4, 'You track it systematically - keep a private log of the decisions where you felt uncertain, look for patterns in the type, domain, and context, and build enough data to understand what is actually happening before you intervene.', 'நீங்கள் அதை முறையாகக் கண்காணிக்கிறீர்கள் - உங்களுக்கு நிச்சயமற்றதாகத் தோன்றிய முடிவுகளை ஒரு தனிப்பட்ட பதிவேட்டில் பதிவுசெய்து, வகை, களம் மற்றும் சூழலில் உள்ள வடிவங்களைத் தேடி, நீங்கள் தலையிடுவதற்கு முன்பு உண்மையில் என்ன நடக்கிறது என்பதைப் புரிந்துகொள்ளப் போதுமான தரவுகளைச் சேகரிக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q39',
     'You are three years into the most demanding role of your career. The results have been strong. The board is satisfied. But privately, you feel increasingly isolated - fewer people who tell you the truth, fewer conversations that are not transactional, less clarity about whether the choices you are making are right or simply unchallenged.What matters more to you in this moment - maintaining the composure and confidence that your role requires you to project, or being honest with yourself and perhaps one trusted person about how much the isolation of leadership is costing you?', 'How will you handle isolation?', 'உங்கள் தொழில் வாழ்க்கையின் மிகவும் சவாலான பொறுப்பில் நீங்கள் மூன்று வருடங்களைக் கடந்துள்ளீர்கள். முடிவுகள் சிறப்பாக அமைந்துள்ளன. நிர்வாகக் குழுவும் திருப்தி அடைந்துள்ளது. ஆனால் தனிப்பட்ட முறையில், நீங்கள் மேலும் மேலும் தனிமைப்படுத்தப்பட்டதாக உணர்கிறீர்கள் - உங்களிடம் உண்மையைச் சொல்பவர்கள் குறைவு, பரிவர்த்தனை அல்லாத உரையாடல்கள் குறைவு, நீங்கள் எடுக்கும் முடிவுகள் சரியானவையா அல்லது கேள்விக்குட்படுத்தப்படாதவையா என்பதில் தெளிவின்மை. இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம் - உங்கள் பொறுப்பு வெளிப்படுத்தக் கோரும் நிதானத்தையும் நம்பிக்கையையும் பேணுவதா, அல்லது தலைமைப் பொறுப்பின் தனிமை உங்களை எவ்வளவு பாதிக்கிறது என்பது பற்றி உங்களுடனும் ஒருவேளை நீங்கள் நம்பும் ஒருவருடனும் நேர்மையாக இருப்பதா?', 'தனிமையை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 2", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Acting on it. Isolation is a performance risk, not a personal weakness. You will build the structures - a coach, a peer group, honest advisors - that give you what the role no longer naturally provides.', 'அதன்படி செயல்படுதல். தனிமை என்பது செயல்திறனுக்கு ஓர் ஆபத்து, அது தனிப்பட்ட பலவீனம் அல்ல. அந்தப் பணி இயல்பாக இனி வழங்காதவற்றை உங்களுக்குத் தரும் கட்டமைப்புகளை - ஒரு பயிற்சியாளர், சக குழுவினர், நேர்மையான ஆலோசகர்கள் - நீங்களே உருவாக்குவீர்கள்.', 'D'),
  (2, 'Being honest with someone. Not publicly - but with one person who knows you well enough to help you think. The composure you project to the organisation does not have to be the only version of you that exists.', 'ஒருவரிடம் நேர்மையாக இருப்பது. பொதுவெளியில் அல்ல - ஆனால், நீங்கள் சிந்திப்பதற்கு உதவக்கூடிய அளவிற்கு உங்களை நன்கு அறிந்த ஒருவரிடம். நீங்கள் நிறுவனத்தின் முன் வெளிப்படுத்தும் நிதானம் மட்டுமே உங்களின் ஒரே வடிவமாக இருக்க வேண்டிய அவசியமில்லை.', 'I'),
  (3, 'Giving it time. Every leader goes through periods of isolation. You have navigated hard things before. You will find your footing again - and reaching out before you have processed it yourself feels premature.', 'இதற்கு நேரம் கொடுங்கள். ஒவ்வொரு தலைவரும் தனிமைக் காலங்களைக் கடந்து செல்கிறார்கள். இதற்கு முன்பும் நீங்கள் கடினமான சூழ்நிலைகளைச் சமாளித்திருக்கிறீர்கள். நீங்கள் மீண்டும் நிலைபெறுவீர்கள் - நீங்களே அதை உள்வாங்கிக் கொள்வதற்கு முன்பு உதவி கேட்பது அவசரமான செயலாகத் தோன்றும்.', 'S'),
  (4, 'Understanding it precisely. What specifically has changed - which relationships, which conversations, which feedback loops - and whether the isolation is structural or situational. You will not address a pattern you have not accurately diagnosed.', 'அதைத் துல்லியமாகப் புரிந்துகொள்வது. குறிப்பாக என்ன மாறியுள்ளது - எந்த உறவுகள், எந்த உரையாடல்கள், எந்தப் பின்னூட்டச் சுழல்கள் - மேலும் இந்தத் தனிமைப்படுத்தல் கட்டமைப்பு ரீதியானதா அல்லது சூழ்நிலை சார்ந்ததா என்பதும் இதில் அடங்கும். நீங்கள் துல்லியமாகக் கண்டறியாத ஒரு போக்கைக் கையாள மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 1 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 1, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S1-Q40',
     'You have achieved most of what you set out to achieve in this role. The organisation is stronger. The strategy is working. But you feel the pull toward something different - not dissatisfaction exactly, but a quiet sense that you are no longer growing the way you need to grow. You have not said this to anyone.Before you say anything - to your board, to your family, to yourself with full honesty - what is actually happening inside you?', 'What is actually happening inside?', 'இந்தப் பதவியில் நீங்கள் அடைய நினைத்தவற்றில் பெரும்பாலானவற்றை அடைந்துவிட்டீர்கள். நிறுவனம் வலுப்பெற்றுள்ளது. வியூகம் பலனளிக்கிறது. ஆனால், வேறு எதையோ நோக்கிய ஒரு ஈர்ப்பை நீங்கள் உணர்கிறீர்கள் - அது துல்லியமாக அதிருப்தி அல்ல, மாறாக நீங்கள் வளர வேண்டிய விதத்தில் இனி வளரவில்லை என்ற ஒரு அமைதியான உணர்வு. இதை நீங்கள் யாரிடமும் சொல்லவில்லை. உங்கள் நிர்வாகக் குழுவிடம், உங்கள் குடும்பத்தினரிடம், அல்லது உங்களிடமே முழு நேர்மையுடன் எதையும் சொல்வதற்கு முன், உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'உள்ளே உண்மையில் என்னதான் நடக்கிறது?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 3", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the restlessness of someone who has proven what they needed to prove - and the recognition that staying past the point of genuine engagement is not fair to you or to the organisation.', 'தாங்கள் நிரூபிக்க வேண்டியதை நிரூபித்துவிட்ட ஒருவரின் தவிப்பையும், உண்மையான ஈடுபாட்டின் எல்லையைத் தாண்டி நீடிப்பது உங்களுக்கோ அல்லது அந்த நிறுவனத்திற்கோ நியாயமில்லை என்ற புரிதலையும் நீங்கள் உணர்கிறீர்கள்.', 'D'),
  (2, 'You feel the complexity of admitting this - aware of what it means for relationships, for how you will be perceived, for the people who depend on the stability your presence represents.', 'இதை ஒப்புக்கொள்வதில் உள்ள சிக்கலை நீங்கள் உணர்கிறீர்கள் - இது உறவுகளுக்கு என்ன அர்த்தம் தரும், உங்களைப் பற்றி மற்றவர்கள் எப்படிப் பார்ப்பார்கள், உங்கள் இருப்பு பிரதிநிதித்துவப்படுத்தும் ஸ்திரத்தன்மையைச் சார்ந்திருக்கும் மக்களுக்கு என்ன விளைவுகளை ஏற்படுத்தும் என்பதை நீங்கள் அறிந்திருக்கிறீர்கள்.', 'I'),
  (3, 'You feel the grief of it alongside the pull. This role has meant something real. Leaving it - even when it is the right time - involves a loss that deserves to be acknowledged before it becomes a decision.', 'அதன் ஈர்ப்புடன் சேர்ந்து துக்கத்தையும் நீங்கள் உணர்கிறீர்கள். இந்தப் பொறுப்பு உங்களுக்கு உண்மையான அர்த்தத்தைக் கொடுத்திருக்கிறது. அதை விட்டு விலகுவது - அது சரியான நேரமாக இருந்தாலும் கூட - ஒரு முடிவாக மாறுவதற்கு முன்பு அங்கீகரிக்கப்பட வேண்டிய ஒரு இழப்பை உள்ளடக்கியது.', 'S'),
  (4, 'You feel the need to be certain this is a signal and not a phase - to distinguish between genuine readiness to move and the temporary flatness that comes after a period of sustained intensity. You will not act on a feeling you have not interrogated.', 'இது ஒரு சமிக்ஞைதானா அல்லது ஒரு தற்காலிக நிலையா என்பதை நீங்கள் உறுதிப்படுத்திக்கொள்ள வேண்டிய அவசியத்தை உணர்கிறீர்கள் - செயல்படுவதற்கான உண்மையான தயார்நிலைக்கும், நீடித்த தீவிரத்திற்குப் பிறகு வரும் தற்காலிக மந்தநிலைக்கும் இடையே வேறுபடுத்தி அறிய விரும்புகிறீர்கள். நீங்கள் ஆராய்ந்து பார்க்காத ஒரு உணர்வின் அடிப்படையில் செயல்பட மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q1
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q1',
     'You are chairing a board meeting to present a major capital allocation decision - a 2,000 crore investment in a new manufacturing vertical. Midway through your presentation, the lead independent director passes a note to two other board members. They begin a side conversation. The room fractures. Your CFO stops mid-slide.', 'How will you handle distraction?', 'ஒரு புதிய உற்பத்தித் துறையில் 2,000 கோடி ரூபாய் முதலீடு செய்வது குறித்த ஒரு முக்கிய மூலதன ஒதுக்கீட்டு முடிவை முன்வைப்பதற்காக, நீங்கள் ஒரு இயக்குநர் குழுக் கூட்டத்திற்குத் தலைமை தாங்குகிறீர்கள். உங்கள் விளக்கக்காட்சியின் நடுவில், தலைமைச் சுதந்திர இயக்குநர் மற்ற இரண்டு இயக்குநர் குழு உறுப்பினர்களுக்கு ஒரு குறிப்பைக் கொடுக்கிறார். அவர்கள் தனியாக உரையாடத் தொடங்குகிறார்கள். அறையில் இருந்தவர்கள் பிளவுபடுகிறார்கள். உங்கள் தலைமை நிதி அதிகாரி, ஸ்லைடின் பாதியிலேயே நிறுத்துகிறார்.', 'கவனச்சிதறலை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 1", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You pause the presentation, address the room directly, and invite the independent director to share his concern openly so the full board can engage with it together.', 'நீங்கள் விளக்கக்காட்சியை இடைநிறுத்தி, சபையில் உள்ளவர்களை நேரடியாக நோக்கி, சுயேச்சை இயக்குநரைத் தனது கவலையை வெளிப்படையாகப் பகிர்ந்து கொள்ள அழைக்கிறீர்கள், இதன்மூலம் முழு நிர்வாகக் குழுவும் அது குறித்து ஒன்றாக விவாதிக்க முடியும்.', 'D'),
  (2, 'You read the room, lighten the tone, and create a natural break that allows the side conversation to surface without making anyone feel confronted or exposed.', 'நீங்கள் சூழலைப் புரிந்துகொண்டு, பேச்சின் தொனியை இலகுவாக்கி, யாரும் சங்கடமாகவோ அல்லது தங்கள் அடையாளம் வெளிப்படுத்தப்பட்டதாகவோ உணராதவாறு, பக்கவாட்டு உரையாடல் இயல்பாக வெளிவர ஒரு இயற்கையான இடைவெளியை உருவாக்குகிறீர்கள்.', 'I'),
  (3, 'You continue the presentation, give the conversation space to settle, and create a structured Q&A at the end where all concerns can be raised without disrupting the flow.', 'நீங்கள் விளக்கக்காட்சியைத் தொடருங்கள், உரையாடல் நிலைபெற இடம் கொடுங்கள், மேலும் இறுதியில், பேச்சின் ஓட்டத்திற்கு இடையூறு செய்யாமல் அனைத்துக் கவலைகளையும் எழுப்பக்கூடிய வகையில் ஒரு கட்டமைக்கப்பட்ட கேள்வி-பதில் அமர்வை உருவாக்குங்கள்.', 'S'),
  (4, 'You pause, ask the independent director if there is a specific data point he would like to examine before you proceed, and offer to address it immediately with the supporting analysis.', 'நீங்கள் சற்று நிறுத்தி, தொடர்வதற்கு முன் அவர் ஆராய விரும்பும் குறிப்பிட்ட தரவு ஏதேனும் உள்ளதா என்று சுயாதீன இயக்குநரிடம் கேட்டு, அதற்கான துணைப் பகுப்பாய்வுடன் உடனடியாகத் தீர்வு காண முன்வருகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q2
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q2',
     'Your company''s largest institutional investor - holding 14% of your equity - has privately requested a meeting outside the normal IR calendar. In the meeting she tells you she is concerned about the pace of your international expansion and is considering reducing her position. You are six weeks from announcing a major partnership that would validate everything she is questioning.', 'How to handle investor concerns?', 'உங்கள் நிறுவனத்தின் 14% பங்குகளை வைத்திருக்கும் அதன் மிகப்பெரிய நிறுவன முதலீட்டாளர், வழக்கமான சர்வதேச உறவுகள் கால அட்டவணைக்கு வெளியே ஒரு சந்திப்பிற்குத் தனிப்பட்ட முறையில் கோரிக்கை விடுத்துள்ளார். அந்தச் சந்திப்பில், உங்கள் சர்வதேச விரிவாக்கத்தின் வேகம் குறித்துத் தனக்குக் கவலை இருப்பதாகவும், தனது முதலீட்டுப் பங்கைக் குறைப்பது குறித்துப் பரிசீலித்து வருவதாகவும் அவர் உங்களிடம் கூறுகிறார். அவர் கேள்விக்குள்ளாக்கும் அனைத்தையும் உறுதிப்படுத்தும் ஒரு பெரிய கூட்டாண்மையை நீங்கள் அறிவிக்க இன்னும் ஆறு வாரங்களே உள்ளன.', 'முதலீட்டாளர்களின் கவலைகளை எவ்வாறு கையாள்வது?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 1", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You tell her directly that you cannot share what is coming but you ask her to hold her position for 60 days and give you the opportunity to demonstrate the strategy''s validity before she acts.', 'வரவிருப்பதை உங்களால் பகிர முடியாது என்று அவளிடம் நேரடியாகக் கூறிவிட்டு, அவள் செயல்படுவதற்கு முன்பு அந்த உத்தியின் செல்லுபடித்தன்மையை உங்களுக்கு நிரூபித்துக் காட்டுவதற்கான வாய்ப்பை அளிக்கும் வகையில் 60 நாட்களுக்குத் தனது நிலையில் உறுதியாக இருக்குமாறு கேட்டுக்கொள்கிறீர்கள்.', 'D'),
  (2, 'You invest the full meeting in understanding her concerns specifically, share as much of your strategic thinking as disclosure allows, and work to rebuild her confidence through the quality of the conversation.', 'சந்திப்பு முழுவதையும் அவளுடைய கவலைகளைத் துல்லியமாகப் புரிந்துகொள்வதில் செலவிடுங்கள், வெளிப்படைத்தன்மை அனுமதிக்கும் அளவிற்கு உங்கள் உத்திசார்ந்த சிந்தனைகளைப் பகிர்ந்துகொள்ளுங்கள், மேலும் உரையாடலின் தரம் மூலம் அவளுடைய நம்பிக்கையை மீண்டும் கட்டியெழுப்ப முயலுங்கள்.', 'I'),
  (3, 'You listen carefully, do not push back, and commit to a structured quarterly dialogue where she has more access to the leadership team - address the relationship before you address the position.', 'நீங்கள் கவனமாகக் கேளுங்கள், எதிர்க்காதீர்கள், மேலும் அவர் தலைமைத்துவக் குழுவை அதிகம் அணுகக்கூடிய ஒரு கட்டமைக்கப்பட்ட காலாண்டு உரையாடலுக்கு உறுதியளியுங்கள் - பதவியைக் கையாள்வதற்கு முன் உறவைக் கையாளுங்கள்.', 'S'),
  (4, 'You prepare a detailed strategic rationale document within the week, walk her through the data behind every international decision, and let the evidence answer her concerns rather than your conviction.', 'நீங்கள் ஒரு வாரத்திற்குள் ஒரு விரிவான மூலோபாய நியாயப்படுத்தல் ஆவணத்தைத் தயாரித்து, ஒவ்வொரு சர்வதேச முடிவின் பின்னணியில் உள்ள தரவுகளை அவளுக்கு விளக்கி, உங்கள் உறுதியான நம்பிக்கையை விட ஆதாரங்களே அவளுடைய கவலைகளுக்குப் பதிலளிக்கட்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q3
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q3',
     'Your company has missed its quarterly guidance for the second consecutive time. The analyst call is tomorrow. Your IR team has prepared a narrative that contextualises the miss within sector-wide headwinds. The story is accurate. But three of your largest investors have already sent pointed messages and one has requested a board-level conversation.What matters more to you in this moment - presenting the most compelling version of a difficult quarter to protect market confidence, or being more direct with investors than your IR team is recommending, even if it creates short-term turbulence?', 'How will you handle conflict?', 'உங்கள் நிறுவனம் தொடர்ந்து இரண்டாவது முறையாக தனது காலாண்டு வழிகாட்டுதலைத் தவறவிட்டுள்ளது. ஆய்வாளர்களுடனான கலந்துரையாடல் நாளை நடைபெற உள்ளது. உங்கள் முதலீட்டாளர் உறவுகள் குழு, துறை முழுவதும் நிலவும் பாதகமான சூழல்களுக்கு மத்தியில் இந்தத் தவறலை விளக்கும் ஒரு விளக்கத்தைத் தயாரித்துள்ளது. அந்த விளக்கம் துல்லியமானதுதான். ஆனால், உங்கள் நிறுவனத்தின் மூன்று பெரிய முதலீட்டாளர்கள் ஏற்கெனவே கூர்மையான செய்திகளை அனுப்பியுள்ளனர், மேலும் ஒருவர் நிர்வாகக் குழு மட்டத்திலான கலந்துரையாடலுக்குக் கோரிக்கை விடுத்துள்ளார். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியம் - சந்தை நம்பிக்கையைப் பாதுகாப்பதற்காக, ஒரு கடினமான காலாண்டின் மிகவும் கவர்ச்சிகரமான ஒரு விளக்கத்தை அளிப்பதா, அல்லது குறுகிய காலச் சிக்கல்களை ஏற்படுத்தினாலும், உங்கள் முதலீட்டாளர் உறவுகள் குழு பரிந்துரைப்பதை விட முதலீட்டாளர்களிடம் இன்னும் நேரடியாக நடந்துகொள்வதா?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 2", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Directness. You will not manage a narrative at the cost of your credibility. Investors who trust you through a bad quarter are worth more than those you retain through a managed story.', 'நேரடித்தன்மை. உங்கள் நம்பகத்தன்மையை இழக்கும் வகையில் ஒரு கதையை நீங்கள் கையாள மாட்டீர்கள். ஒரு மோசமான காலாண்டின் போதும் உங்களை நம்பும் முதலீட்டாளர்கள், நீங்கள் கையாண்ட கதையின் மூலம் தக்கவைத்துக் கொள்ளும் முதலீட்டாளர்களை விட அதிக மதிப்பு வாய்ந்தவர்கள்.', 'D'),
  (2, 'The relationship. You will call your three largest investors personally before the analyst call - not to change the narrative but to ensure they hear from you directly before they hear from the market.', 'உறவுமுறை. ஆய்வாளர் அழைப்பிற்கு முன்பு, உங்கள் மூன்று மிகப்பெரிய முதலீட்டாளர்களை நீங்கள் தனிப்பட்ட முறையில் அழைப்பீர்கள் - இது வழக்கமான போக்கை மாற்றுவதற்காக அல்ல, மாறாக சந்தையிடமிருந்து அவர்கள் தகவல்களைப் பெறுவதற்கு முன்பு, உங்களிடமிருந்து நேரடியாகத் தெரிந்துகொள்வதை உறுதி செய்வதற்காகவே.', 'I'),
  (3, 'Stability. You will follow your IR team''s guidance, deliver the call professionally, and focus on what you can control - the remediation plan and the next quarter''s performance.', 'நிலைத்தன்மை. நீங்கள் உங்கள் IR குழுவின் வழிகாட்டுதலைப் பின்பற்றி, அழைப்பைத் தொழில்முறையாக வழங்கி, உங்கள் கட்டுப்பாட்டில் உள்ளவற்றில் - அதாவது சரிசெய்தல் திட்டம் மற்றும் அடுத்த காலாண்டின் செயல்திறன் ஆகியவற்றில் - கவனம் செலுத்துவீர்கள்.', 'S'),
  (4, 'Precision. You will review every claim in the IR narrative against the underlying data and ensure that what you present is not just accurate but would survive a forensic review by a skeptical analyst.', 'துல்லியம். IR விவரணத்தில் உள்ள ஒவ்வொரு கூற்றையும் அடிப்படைத் தரவுகளுடன் ஒப்பிட்டு நீங்கள் ஆய்வு செய்து, நீங்கள் முன்வைப்பது துல்லியமானது மட்டுமல்லாமல், ஐயுறவு மனப்பான்மை கொண்ட ஒரு ஆய்வாளரின் நுணுக்கமான ஆய்வையும் தாங்கும் என்பதை உறுதி செய்வீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q4
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q4',
     'A founder-board conflict has been building for eight months. The founder - who holds 23% of the company and a board seat - has been openly contradicting executive decisions in board meetings and building a parallel narrative with institutional investors. You are the CEO. The board has asked you to manage it.Before you say anything to the board or the founder - what is actually happening inside you when you sit with this situation alone?', 'How will you handle conflict?', 'நிறுவனருக்கும் நிர்வாகக் குழுவிற்கும் இடையே கடந்த எட்டு மாதங்களாக ஒரு முரண்பாடு உருவாகி வருகிறது. நிறுவனத்தில் 23% பங்குகளையும் நிர்வாகக் குழுவில் ஓர் இடத்தையும் வைத்திருக்கும் நிறுவனர், நிர்வாகக் குழு கூட்டங்களில் நிர்வாக முடிவுகளை வெளிப்படையாக எதிர்ப்பதோடு, நிறுவன முதலீட்டாளர்களுடன் ஒரு மாற்றுப் பார்வையையும் உருவாக்கி வருகிறார். நீங்கள் தலைமை நிர்வாக அதிகாரி. அதை நிர்வகிக்குமாறு நிர்வாகக் குழு உங்களைக் கேட்டுள்ளது. நிர்வாகக் குழுவிடமோ அல்லது நிறுவனரிடமோ எதையும் சொல்வதற்கு முன் - இந்தச் சூழ்நிலையுடன் நீங்கள் தனியாக இருக்கும்போது, ​​உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Board and Investor Relations", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the clarity of knowing this cannot continue and the readiness to have the confrontation directly, even if it is damaging - because the cost of avoiding it is higher than the cost of having it.', 'இது தொடர முடியாது என்ற தெளிவையும், அதனால் பாதிப்பு ஏற்பட்டாலும் அந்த மோதலை நேரடியாக எதிர்கொள்ளும் தயார்நிலையையும் நீங்கள் உணர்கிறீர்கள் - ஏனெனில் அதை எதிர்கொள்வதற்கான செலவை விட அதைத் தவிர்ப்பதற்கான செலவு அதிகம்.', 'D'),
  (2, 'You feel the weight of the audience - the board, the investors, your leadership team - and the awareness that how you handle a founder conflict will define how you are seen as a leader in a way few other situations will.', 'இயக்குநர் குழு, முதலீட்டாளர்கள், உங்கள் தலைமைக் குழு போன்ற பார்வையாளர்களின் செல்வாக்கையும், ஒரு நிறுவனரின் முரண்பாட்டை நீங்கள் கையாளும் விதமே, வேறு சில சூழ்நிலைகளைப் போலல்லாமல், ஒரு தலைவராக நீங்கள் எவ்வாறு பார்க்கப்படுவீர்கள் என்பதை வரையறுக்கும் என்ற விழிப்புணர்வையும் நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the sadness underneath the frustration. This person built something real. Whatever has broken between you was not always broken. And resolving it - even badly - matters more to you than winning it.', 'விரக்திக்கு அடியில் இருக்கும் சோகத்தை உங்களால் உணர முடிகிறது. இந்த நபர் ஒரு உண்மையான உறவைக் கட்டியெழுப்பியுள்ளார். உங்களுக்குள் முறிந்த விஷயம் எப்போதுமே முறிந்திருக்கவில்லை. மேலும், அதில் வெற்றி பெறுவதை விட, அதைச் சரிசெய்வது - அது சரியாக அமையாவிட்டாலும் - உங்களுக்கு மிகவும் முக்கியமானது.', 'S'),
  (4, 'You feel the need to map the situation completely before you act - who has said what, what the founder''s actual concerns are beneath the behaviour, what the board''s real mandate to you is, and what resolution actually looks like.', 'நீங்கள் செயல்படுவதற்கு முன்பு, நிலைமையை முழுமையாகப் புரிந்துகொள்ள வேண்டியதன் அவசியத்தை உணர்கிறீர்கள் - யார் என்ன சொன்னார்கள், அந்த நடத்தைக்குப் பின்னால் நிறுவனரின் உண்மையான கவலைகள் என்ன, உங்களுக்கு வாரியம் வழங்கிய உண்மையான அதிகாரம் என்ன, மற்றும் தீர்வு உண்மையில் எப்படி இருக்கும் என்பனவற்றையெல்லாம் ஆராய வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q5
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q5',
     'A data breach has exposed the personal and financial records of 2.3 million customers. Your technology team identified it six hours ago. Legal says you have 72 hours before mandatory regulatory disclosure. Your communications team wants 48 hours to prepare a response. A journalist from a national outlet has already called your PR head asking for comment.', 'How will you manage breach?', 'தரவுக் கசிவு காரணமாக 23 லட்சம் வாடிக்கையாளர்களின் தனிப்பட்ட மற்றும் நிதிப் பதிவுகள் அம்பலப்படுத்தப்பட்டுள்ளன. உங்கள் தொழில்நுட்பக் குழு ஆறு மணி நேரத்திற்கு முன்பு இதைக் கண்டறிந்தது. கட்டாய ஒழுங்குமுறை வெளிப்படுத்தலுக்கு முன் உங்களுக்கு 72 மணிநேரம் இருப்பதாகச் சட்டத் துறை கூறுகிறது. உங்கள் தகவல் தொடர்பு குழு ஒரு பதிலைத் தயாரிக்க 48 மணிநேரம் கோருகிறது. ஒரு தேசிய ஊடகத்தின் பத்திரிகையாளர் ஏற்கனவே உங்கள் மக்கள் தொடர்புத் தலைவரைத் தொடர்புகொண்டு கருத்து கேட்டுள்ளார்.', 'மீறலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 1", "dimension": "decision_speed", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You issue a holding statement within the hour, personally brief your top 20 institutional clients before the public announcement, and set a 24-hour deadline for a full customer communication - you will not let the story get ahead of you.', 'ஒரு மணி நேரத்திற்குள் ஒரு இடைக்கால அறிக்கையை வெளியிட்டு, பொது அறிவிப்புக்கு முன்பு உங்கள் முதல் 20 நிறுவன வாடிக்கையாளர்களுக்கு நேரில் விளக்கமளித்து, முழுமையான வாடிக்கையாளர் தகவல்தொடர்புக்கு 24 மணி நேரக் காலக்கெடுவை நிர்ணயிக்கிறீர்கள் - இதன் மூலம் அந்தச் செய்தி உங்களை முந்திக்கொள்ள நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'D'),
  (2, 'You convene your crisis response team immediately, ensure every function has a clear role, and build a coordinated response that is both legally sound and humanly sensitive before anything goes public.', 'எந்தவொரு விஷயமும் பொதுவெளியில் வெளிவருவதற்கு முன்பாக, நீங்கள் உங்கள் நெருக்கடிக்கால மீட்புக் குழுவை உடனடியாகக் கூட்டி, ஒவ்வொரு செயல்பாட்டிற்கும் தெளிவான பங்கு இருப்பதை உறுதிசெய்து, சட்டப்படி சரியானதும் மனிதாபிமான உணர்வுடன் கூடியதுமான ஒரு ஒருங்கிணைந்த மீட்பு நடவடிக்கையை உருவாக்க வேண்டும்.', 'I'),
  (3, 'You prioritise the customers first - build the notification and support infrastructure before you manage the external narrative, because how you treat the people affected will define how this crisis is remembered.', 'நீங்கள் வாடிக்கையாளர்களுக்கு முதலில் முன்னுரிமை அளிக்க வேண்டும் - வெளிப்புறக் கதைகளை நிர்வகிப்பதற்கு முன்பாக, அறிவிப்பு மற்றும் ஆதரவு உள்கட்டமைப்பை உருவாக்குங்கள். ஏனெனில், பாதிக்கப்பட்ட மக்களை நீங்கள் நடத்தும் விதமே, இந்த நெருக்கடி எவ்வாறு நினைவுகூரப்படும் என்பதை வரையறுக்கும்.', 'S'),
  (4, 'You demand a complete technical brief before any communication goes out - the scope, the cause, the data categories affected, and the remediation timeline - you will not speak publicly about something you do not fully understand.', 'எந்தவொரு தகவலும் வெளியிடப்படுவதற்கு முன்பு, அதன் நோக்கம், காரணம், பாதிக்கப்பட்ட தரவு வகைகள் மற்றும் சரிசெய்யும் காலக்கெடு ஆகியவற்றை உள்ளடக்கிய ஒரு முழுமையான தொழில்நுட்ப விளக்கத்தை நீங்கள் கோர வேண்டும்; உங்களுக்கு முழுமையாகப் புரியாத ஒன்றைப் பற்றி நீங்கள் பொதுவெளியில் பேச மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q6
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q6',
     'Your company''s regional head has made a public statement at an industry conference that directly contradicts your stated position on a regulatory matter currently under government review. The statement has been picked up by three news outlets. Your legal team is alarmed. The regional head insists he was misquoted.', 'How will you respond now?', 'தற்போது அரசாங்கத்தின் ஆய்வில் உள்ள ஒரு ஒழுங்குமுறை விவகாரம் குறித்து நீங்கள் தெரிவித்த நிலைப்பாட்டிற்கு முற்றிலும் முரணான ஒரு பொது அறிக்கையை, உங்கள் நிறுவனத்தின் பிராந்தியத் தலைவர் ஒரு தொழில் மாநாட்டில் வெளியிட்டுள்ளார். அந்த அறிக்கையை மூன்று செய்தி நிறுவனங்கள் வெளியிட்டுள்ளன. இதனால் உங்கள் சட்டக் குழுவினர் கவலை அடைந்துள்ளனர். தனது கூற்று தவறாக மேற்கோள் காட்டப்பட்டதாக அந்தப் பிராந்தியத் தலைவர் வலியுறுத்துகிறார்.', 'இப்போது நீங்கள் எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You issue a clarification from your office the same day, speak to the regional head directly, and make clear that public statements on regulatory matters require central approval from this point forward.', 'அதே நாளில் உங்கள் அலுவலகத்திலிருந்து ஒரு தெளிவுரையை வெளியிட்டு, பிராந்தியத் தலைவரிடம் நேரடியாகப் பேசி, இனிமேல் ஒழுங்குமுறை சார்ந்த விஷயங்கள் குறித்த பொது அறிக்கைகளுக்கு மத்திய அரசின் ஒப்புதல் தேவை என்பதைத் தெளிவுபடுத்துங்கள்.', 'D'),
  (2, 'You call the journalists personally, offer an on-record clarification from the CEO''s office, and work to reshape the narrative through direct media engagement rather than a formal corporate statement.', 'நீங்கள் பத்திரிகையாளர்களைத் தனிப்பட்ட முறையில் அழைத்து, தலைமைச் செயல் அதிகாரியின் அலுவலகத்திலிருந்து பதிவுசெய்யப்பட்ட விளக்கத்தை அளித்து, ஒரு முறையான நிறுவன அறிக்கைக்குப் பதிலாக நேரடி ஊடக ஈடுபாட்டின் மூலம் கதையாடலை மறுவடிவமைக்கப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You speak to the regional head privately first - understand what actually happened before you react externally - and give him the opportunity to correct it himself before you step in.', 'நீங்கள் முதலில் பிராந்தியத் தலைவரிடம் தனிப்பட்ட முறையில் பேசி, வெளிப்படையாக எதிர்வினையாற்றுவதற்கு முன் உண்மையில் என்ன நடந்தது என்பதைப் புரிந்துகொண்டு, நீங்கள் தலையிடுவதற்கு முன்பாக அதை அவரே சரிசெய்துகொள்ள அவருக்கு வாய்ப்பளிக்கவும்.', 'S'),
  (4, 'You review the original statement, the misquote claim, and the legal exposure before deciding on a response - you will not issue a correction until you know precisely what was said and what it means.', 'ஒரு பதிலை முடிவு செய்வதற்கு முன், நீங்கள் அசல் கூற்று, தவறாக மேற்கோள் காட்டப்பட்டதாகக் கூறப்படும் குற்றச்சாட்டு மற்றும் அதனால் ஏற்படக்கூடிய சட்டரீதியான பாதிப்புகள் ஆகியவற்றை மதிப்பாய்வு செய்வீர்கள் - என்ன கூறப்பட்டது, அதன் பொருள் என்ன என்பதை நீங்கள் துல்லியமாகத் தெரிந்துகொள்ளும் வரை ஒரு திருத்தத்தை வெளியிட மாட்டீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q7
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q7',
     'Your company''s supply chain has failed during peak season. Shelves are empty in 4,000 retail outlets. Customers are vocal on social media. Your largest retail partner has issued a private ultimatum - resolve this within 10 days or they will invoke the penalty clause in your contract. Your operations team says 21 days is the realistic recovery timeline.Two things are pulling at you. Which is stronger - the urgency to protect the retail relationship by committing to a timeline your operations team does not believe in, or the discipline to be honest about the recovery timeline even if it triggers penalties and damages a critical partnership?', 'How will you handle crisis?', 'உச்ச பருவத்தில் உங்கள் நிறுவனத்தின் விநியோகச் சங்கிலி தோல்வியடைந்துள்ளது. 4,000 சில்லறை விற்பனை நிலையங்களில் அலமாரிகள் காலியாக உள்ளன. வாடிக்கையாளர்கள் சமூக ஊடகங்களில் தங்கள் அதிருப்தியை வெளிப்படுத்துகின்றனர். உங்கள் மிகப்பெரிய சில்லறை விற்பனைக் கூட்டாளர் ஒரு தனிப்பட்ட இறுதி எச்சரிக்கையை விடுத்துள்ளார் - இதை 10 நாட்களுக்குள் தீர்க்க வேண்டும், இல்லையெனில் உங்கள் ஒப்பந்தத்தில் உள்ள அபராத விதியை அமல்படுத்துவோம் என்று கூறியுள்ளார். உங்கள் செயல்பாட்டுக் குழுவோ, 21 நாட்களே இதனை மீட்டெடுப்பதற்கான யதார்த்தமான காலக்கெடு என்று கூறுகிறது. இரண்டு விஷயங்கள் உங்களை அலைக்கழிக்கின்றன. உங்கள் செயல்பாட்டுக் குழு நம்பாத ஒரு காலக்கெடுவிற்கு ஒப்புக்கொண்டு, சில்லறை விற்பனை உறவைப் பாதுகாக்க வேண்டிய அவசரமா, அல்லது அபராதங்களைத் தூண்டி, ஒரு முக்கிய கூட்டாண்மையைச் சேதப்படுத்தினாலும், இதனை மீட்டெடுப்பதற்கான காலக்கெடுவைப் பற்றி நேர்மையாக இருக்கும் ஒழுக்கமா - இதில் எது வலிமையானது?', 'நெருக்கடியை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 2", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Honesty. You will tell the retail partner what is actually possible and negotiate the penalty - a promise you cannot keep will cost you more than the penalty clause.', 'நேர்மை. உண்மையில் என்ன சாத்தியம் என்பதை உங்கள் சில்லறை விற்பனைப் பங்குதாரரிடம் கூறி, அபராதம் குறித்துப் பேச்சுவார்த்தை நடத்துங்கள் - உங்களால் நிறைவேற்ற முடியாத ஒரு வாக்குறுதி, அபராத நிபந்தனையை விட உங்களுக்கு அதிக செலவை ஏற்படுத்தும்.', 'D'),
  (2, 'The relationship. You will meet the retail partner''s leadership personally, demonstrate the full force of your response, and work to earn enough goodwill that the timeline becomes a shared problem rather than a contractual one.', 'உறவுமுறை. நீங்கள் சில்லறை விற்பனைக் கூட்டாளியின் தலைமையை நேரில் சந்தித்து, உங்கள் பதிலின் முழு வீரியத்தையும் வெளிப்படுத்தி, காலக்கெடுவானது ஒரு ஒப்பந்தச் சிக்கலாக இல்லாமல் ஒரு பகிரப்பட்ட சிக்கலாக மாறும் அளவிற்குப் போதுமான நன்மதிப்பைப் பெறப் பாடுபடுவீர்கள்.', 'I'),
  (3, 'Stability. You will focus on what your operations team can deliver with certainty and build the partner communication around guaranteed milestones rather than an overall timeline commitment.', 'நிலைத்தன்மை. உங்கள் செயல்பாட்டுக் குழுவால் உறுதியாக வழங்கக்கூடியவற்றில் நீங்கள் கவனம் செலுத்துவீர்கள், மேலும் ஒரு ஒட்டுமொத்த காலக்கெடு உறுதிமொழிக்கு பதிலாக, உத்தரவாதமளிக்கப்பட்ட மைல்கற்களை மையமாகக் கொண்டு கூட்டாளர் தகவல்தொடர்பை உருவாக்குவீர்கள்.', 'S'),
  (4, 'The data. You will have your operations team build a scenario-by-scenario recovery model before you commit to anything - what is possible under normal conditions, accelerated conditions, and maximum resource allocation.', 'தரவு. நீங்கள் எதற்கும் உறுதியளிப்பதற்கு முன்பு, சாதாரண நிலைமைகள், துரிதப்படுத்தப்பட்ட நிலைமைகள் மற்றும் அதிகபட்ச வள ஒதுக்கீட்டின் கீழ் என்ன சாத்தியம் என்பதைப் பற்றிய ஒரு சூழ்நிலை வாரியான மீட்பு மாதிரியை உங்கள் செயல்பாட்டுக் குழு உருவாக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q8
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q8',
     'A senior leader in your organisation has been the subject of a social media campaign alleging personal misconduct outside of work. The allegations are unverified. Your HR and legal teams are investigating. The campaign is gaining traction and three employees have written to you asking for the organisation''s position.The honest feeling underneath this - before you respond to the employees, before you brief the board, before you speak to the leader himself - what are you actually feeling?', 'What are you actually feeling?', 'உங்கள் நிறுவனத்தின் ஒரு மூத்த தலைவர், பணிக்கு வெளியே தனிப்பட்ட முறையில் தவறாக நடந்துகொண்டதாகக் குற்றம் சாட்டி, ஒரு சமூக ஊடகப் பிரச்சாரத்திற்கு உள்ளாகியுள்ளார். இந்தக் குற்றச்சாட்டுகள் சரிபார்க்கப்படாதவை. உங்கள் மனிதவள மற்றும் சட்டக் குழுக்கள் இது குறித்து விசாரித்து வருகின்றன. இந்தப் பிரச்சாரம் வலுப்பெற்று வருகிறது, மேலும் மூன்று ஊழியர்கள் நிறுவனத்தின் நிலைப்பாட்டைக் கேட்டு உங்களுக்குக் கடிதம் எழுதியுள்ளனர். இதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்னவென்றால் - ஊழியர்களுக்குப் பதிலளிப்பதற்கு முன்பும், நிர்வாகக் குழுவிற்கு விளக்கமளிப்பதற்கு முன்பும், அந்தத் தலைவரிடமே பேசுவதற்கு முன்பும் - நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?',
     '{"theme": "Crisis and Reputation Management", "layer": "Layer 3", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the pressure to act and the frustration of being forced to respond to unverified allegations that may be entirely false - and the awareness that acting too quickly could be as damaging as acting too slowly.', 'செயல்பட வேண்டும் என்ற அழுத்தத்தையும், முற்றிலும் பொய்யாக இருக்கக்கூடிய, சரிபார்க்கப்படாத குற்றச்சாட்டுகளுக்குப் பதிலளிக்க நிர்பந்திக்கப்படுவதால் ஏற்படும் விரக்தியையும் நீங்கள் உணர்கிறீர்கள் - மேலும், மிக மெதுவாகச் செயல்படுவது எவ்வளவு பாதிப்பை ஏற்படுத்துமோ, அதே அளவு மிக விரைவாகச் செயல்படுவதும் பாதிப்பை ஏற்படுத்தும் என்ற விழிப்புணர்வும் உங்களுக்கு இருக்கிறது.', 'D'),
  (2, 'You feel the exposure - your name, your organisation, and your leadership judgment are now implicated in something you did not create and cannot fully control - and that loss of control is uncomfortable.', 'நீங்கள் அந்த அம்பலத்தை உணர்கிறீர்கள் - நீங்கள் உருவாக்காததும், முழுமையாகக் கட்டுப்படுத்த முடியாததுமான ஒன்றில் உங்கள் பெயர், உங்கள் நிறுவனம், மற்றும் உங்கள் தலைமைத்துவத் திறன்கள் இப்போது சம்பந்தப்பட்டுள்ளன - மேலும் அந்தக் கட்டுப்பாட்டு இழப்பு ஒரு சங்கடமான உணர்வைத் தருகிறது.', 'I'),
  (3, 'You feel concern for the leader as a person - whatever the truth is, this is a human being in a damaging situation - and you want the investigation to be fair before the organisation takes any position.', 'ஒரு தனிநபராக அந்தத் தலைவர் மீது உங்களுக்கு அக்கறை ஏற்படுகிறது - உண்மை எதுவாக இருந்தாலும், அவர் ஒரு சிக்கலான சூழ்நிலையில் இருக்கும் மனிதர் - மேலும், அந்த அமைப்பு எந்தவொரு நிலைப்பாட்டையும் எடுப்பதற்கு முன்பு, விசாரணை நியாயமாக நடைபெற வேண்டும் என்றும் நீங்கள் விரும்புகிறீர்கள்.', 'S'),
  (4, 'You feel the need to understand exactly what the allegations are, what the investigation has found so far, and what your legal obligations are before you feel anything you can act on.', 'நீங்கள் நடவடிக்கை எடுக்கக்கூடிய எதையும் உணர்வதற்கு முன்பு, குற்றச்சாட்டுகள் என்ன, விசாரணையில் இதுவரை என்ன கண்டறியப்பட்டுள்ளது, மற்றும் உங்கள் சட்டப்பூர்வ கடமைகள் என்ன என்பதைத் துல்லியமாகப் புரிந்துகொள்ள வேண்டியதன் அவசியத்தை நீங்கள் உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q9
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q9',
     'Two of your most senior direct reports - both of whom you respect and rely on - have reached a point of open conflict. It has moved beyond professional disagreement into something personal. Their teams have taken sides. Cross-functional work is stalling. Both leaders have told you privately they cannot continue working at the same level if the situation does not change.', 'How will you handle conflict?', 'நீங்கள் மதித்து, சார்ந்திருக்கும் உங்கள் மிக மூத்த நேரடிப் பணியாளர்களில் இருவர், வெளிப்படையான மோதல் நிலையை எட்டியுள்ளனர். இது தொழில்முறை கருத்து வேறுபாட்டைத் தாண்டி, தனிப்பட்ட பிரச்சனையாக மாறியுள்ளது. அவர்களின் குழுக்கள் இரு தரப்பிலும் சேர்ந்துள்ளன. பல்துறை சார்ந்த பணிகள் தடைபட்டுள்ளன. நிலைமை மாறாவிட்டால், தங்களால் இதே நிலையில் தொடர்ந்து பணியாற்ற முடியாது என்று அந்த இரு தலைவர்களும் உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளனர்.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You meet with both leaders together, name what is happening without softening it, and make clear that the conflict ends here - you will support both of them but you will not tolerate it continuing at the organisation''s expense.', 'நீங்கள் இரு தலைவர்களையும் ஒன்றாகச் சந்தித்து, என்ன நடக்கிறது என்பதை அதன் கடுமையைக் குறைக்காமல் வெளிப்படையாகக் கூறி, இந்த மோதல் இத்துடன் முடிவடைகிறது என்பதைத் தெளிவுபடுத்துங்கள் - நீங்கள் அவர்கள் இருவரையும் ஆதரிப்பீர்கள், ஆனால் நிறுவனத்தின் நலனுக்குப் பாதிப்பு ஏற்படும் வகையில் இது தொடர்வதை நீங்கள் பொறுத்துக்கொள்ள மாட்டீர்கள்.', 'D'),
  (2, 'You invest time with each leader separately, understand what is driving the conflict beneath the surface, and work to rebuild the relationship between them before making any structural decision.', 'எந்தவொரு கட்டமைப்பு ரீதியான முடிவையும் எடுப்பதற்கு முன்பு, நீங்கள் ஒவ்வொரு தலைவருடனும் தனித்தனியாக நேரம் ஒதுக்கி, மேலோட்டமாகப் பார்த்தால் மோதலுக்கு என்ன காரணம் என்பதைப் புரிந்துகொண்டு, அவர்களுக்கு இடையேயான உறவை மீண்டும் கட்டியெழுப்பப் பணியாற்ற வேண்டும்.', 'I'),
  (3, 'You bring in an external facilitator, create a structured dialogue process, and give the relationship every reasonable opportunity to recover before you consider a structural separation.', 'நீங்கள் ஒரு வெளிப்புற ஒருங்கிணைப்பாளரைக் கொண்டுவந்து, ஒரு கட்டமைக்கப்பட்ட உரையாடல் செயல்முறையை உருவாக்கி, அமைப்பு ரீதியான பிரிவினையைக் கருத்தில் கொள்வதற்கு முன், அந்த உறவு மீண்டு வருவதற்குத் தேவையான அனைத்து நியாயமான வாய்ப்புகளையும் வழங்குகிறீர்கள்.', 'S'),
  (4, 'You map the specific decisions and interactions where the conflict has surfaced, identify the structural or role ambiguities that may be fuelling it, and resolve the underlying design problems before addressing the interpersonal ones.', 'முரண்பாடு வெளிப்பட்ட குறிப்பிட்ட முடிவுகளையும் தொடர்புகளையும் நீங்கள் வரைபடமாக்கி, அதைத் தூண்டக்கூடிய கட்டமைப்பு அல்லது பங்கு சார்ந்த தெளிவின்மைகளை அடையாளம் கண்டு, தனிநபர்களுக்கிடையேயான சிக்கல்களைக் கையாள்வதற்கு முன், அடிப்படை வடிவமைப்புச் சிக்கல்களைத் தீர்க்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q10
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q10',
     'A business unit you inherited 18 months ago has been consistently underperforming. You have made three leadership changes, invested in systems and capability, and given the unit significant strategic priority. The results have not moved. Your board is losing patience and has begun to question whether the business unit should exist in its current form.', 'How will you fix it?', '18 மாதங்களுக்கு முன்பு நீங்கள் பொறுப்பேற்ற ஒரு வணிகப் பிரிவு, தொடர்ந்து எதிர்பார்த்த அளவுக்குச் செயல்படவில்லை. நீங்கள் மூன்று முறை தலைமைப் பொறுப்புகளை மாற்றியுள்ளீர்கள், அமைப்புகளிலும் திறன்களிலும் முதலீடு செய்துள்ளீர்கள், மேலும் அந்தப் பிரிவுக்கு குறிப்பிடத்தக்க மூலோபாய முன்னுரிமையையும் வழங்கியுள்ளீர்கள். ஆனாலும், முடிவுகளில் எந்த மாற்றமும் ஏற்படவில்லை. உங்கள் நிர்வாகக் குழு பொறுமையை இழந்து வருகிறது, மேலும் அந்த வணிகப் பிரிவு அதன் தற்போதைய வடிவத்தில் தொடர்ந்து இயங்க வேண்டுமா என்று கேள்வி எழுப்பத் தொடங்கியுள்ளது.', 'நீங்கள் அதை எப்படி சரிசெய்வீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You make a definitive call - either a final 90-day performance covenant with a clear exit plan if the targets are not met, or a recommendation to restructure the unit now rather than extend a cycle that is not working.', 'நீங்கள் ஒரு திட்டவட்டமான முடிவை எடுங்கள் - இலக்குகள் அடையப்படாவிட்டால், தெளிவான வெளியேறும் திட்டத்துடன் கூடிய ஒரு இறுதி 90-நாள் செயல்திறன் உடன்படிக்கையை ஏற்படுத்துவதா, அல்லது பலனளிக்காத ஒரு சுழற்சியை நீட்டிப்பதற்குப் பதிலாக, இப்போதே அந்தப் பிரிவை மறுசீரமைக்கப் பரிந்துரைப்பதா?', 'D'),
  (2, 'You go into the business unit personally - spend two weeks with the team, rebuild direct relationships with the frontline leadership, and understand from the inside what is actually blocking performance before you make a structural recommendation.', 'நீங்கள் ஒரு கட்டமைப்புப் பரிந்துரையை வழங்குவதற்கு முன்பு, வணிகப் பிரிவுக்கு நேரில் சென்று, குழுவுடன் இரண்டு வாரங்கள் செலவிட்டு, களமுனைத் தலைமையுடன் நேரடி உறவுகளை மீண்டும் கட்டியெழுப்பி, செயல்திறனை உண்மையில் எது தடுக்கிறது என்பதை உள்ளிருந்து புரிந்துகொள்ள வேண்டும்.', 'I'),
  (3, 'You protect the team from the board''s pressure while you give the latest leadership change a full cycle to demonstrate results - premature restructuring destroys whatever progress has been made.', 'வாரியத்தின் அழுத்தத்திலிருந்து குழுவைப் பாதுகாக்கும் அதே வேளையில், சமீபத்திய தலைமை மாற்றம் அதன் முடிவுகளை வெளிப்படுத்த ஒரு முழுமையான கால அவகாசத்தையும் நீங்கள் அளிக்கிறீர்கள் - முன்கூட்டிய மறுசீரமைப்பு, அதுவரை அடைந்த முன்னேற்றம் அனைத்தையும் அழித்துவிடும்.', 'S'),
  (4, 'You commission an independent operational review - three months of changes is not sufficient data to conclude the unit is structurally unviable - you want evidence before you recommend elimination.', 'நீங்கள் ஒரு சுயாதீனமான செயல்பாட்டு ஆய்வை மேற்கொள்கிறீர்கள் - மூன்று மாத மாற்றங்கள், அந்தப் பிரிவு கட்டமைப்பு ரீதியாகச் செயல்பட இயலாதது என்று முடிவு செய்வதற்குப் போதுமான தரவு அல்ல - அதை நீக்குவதற்குப் பரிந்துரைக்கும் முன் உங்களுக்கு ஆதாரம் தேவை.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q11
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q11',
     'A leader you championed for a stretch assignment - a role significantly above her current level - is six months in and visibly struggling. Her peers have noticed. Her team''s confidence is shaken. Your CHRO has come to you with a recommendation to reassign her. You were the one who pushed for this appointment against the advice of two board members.The conflict you feel most is between - your responsibility to the organisation and to her team who need stable, effective leadership, and your loyalty to someone you believed in and pushed into a situation that may now be damaging her career.', 'How will you handle conflict?', 'அவரது தற்போதைய நிலையை விட மிகவும் உயர்ந்த ஒரு பொறுப்புக்கு நீங்கள் பரிந்துரைத்த ஒரு தலைவர், அந்தப் பொறுப்பில் சேர்ந்து ஆறு மாதங்கள் ஆன நிலையில், வெளிப்படையாகவே சிரமப்படுகிறார். அவரது சக ஊழியர்கள் இதைக் கவனித்துள்ளனர். அவரது குழுவின் நம்பிக்கை ஆட்டம் கண்டுள்ளது. அவரை வேறு பணிக்கு மாற்றுமாறு உங்கள் தலைமை மனிதவள அதிகாரி (CHRO) உங்களிடம் ஒரு பரிந்துரையுடன் வந்துள்ளார். இரண்டு நிர்வாகக் குழு உறுப்பினர்களின் ஆலோசனையை மீறி, இந்த நியமனத்திற்காக நீங்கள்தான் வலியுறுத்தினீர்கள். நீங்கள் மிகவும் உணரும் முரண்பாடு, ஒருபுறம், நிறுவனத்திற்கும், நிலையான மற்றும் திறமையான தலைமை தேவைப்படும் அவரது குழுவிற்கும் நீங்கள் ஆற்ற வேண்டிய பொறுப்பிற்கும், மறுபுறம், நீங்கள் நம்பி, தற்போது அவரது தொழில் வாழ்க்கையைப் பாதிக்கக்கூடிய ஒரு சூழ்நிலைக்குத் தள்ளிய ஒருவரின் மீதான உங்கள் விசுவாசத்திற்கும் இடையேதான் உள்ளது.', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 2", "dimension": "relationship_dependency", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You act in the organisation''s interest. Allowing the situation to continue because of your personal investment does him a disservice too - the kindest thing is a clear decision, made quickly.', 'நீங்கள் நிறுவனத்தின் நலனுக்காகச் செயல்படுகிறீர்கள். உங்கள் தனிப்பட்ட ஆதாயத்திற்காக இந்த நிலைமையைத் தொடர அனுமதிப்பது அவருக்கும் தீமையே விளைவிக்கும் - விரைவாக எடுக்கப்படும் ஒரு தெளிவான முடிவே மிகவும் கருணையானது.', 'D'),
  (2, 'You intervene directly and personally - not to remove her but to provide the level of support and coaching that should have been there from day one. You will not reassign her before you have genuinely invested in her success.', 'நீங்கள் அவளைப் பணியிலிருந்து நீக்குவதற்காக அல்ல, மாறாக முதல் நாளிலிருந்தே அவளுக்குக் கிடைத்திருக்க வேண்டிய ஆதரவையும் பயிற்சியையும் வழங்குவதற்காக நேரடியாகவும் தனிப்பட்ட முறையிலும் தலையிடுகிறீர்கள். அவளுடைய வெற்றியில் நீங்கள் உண்மையாக அக்கறை செலுத்தும் வரை, அவளை வேறு பணிக்கு மாற்ற மாட்டீர்கள்.', 'I'),
  (3, 'You find a transition that protects her dignity - a role change that is framed as an evolution rather than a failure, that acknowledges what she has built in six months, and does not define her by this one difficult period.', 'அவளது கண்ணியத்தைப் பாதுகாக்கும் ஒரு மாற்றத்தை நீங்கள் கண்டறியுங்கள் - அது ஒரு தோல்வியாகக் கருதப்படாமல் ஒரு பரிணாம வளர்ச்சியாகக் கட்டமைக்கப்படும் ஒரு பாத்திர மாற்றமாகும்; அது, ஆறு மாதங்களில் அவள் கட்டமைத்ததை அங்கீகரிப்பதோடு, இந்த ஒரு கடினமான காலகட்டத்தைக் கொண்டு அவளை வரையறுக்காமலும் இருக்க வேண்டும்.', 'S'),
  (4, 'You assess the situation precisely - what specific capabilities are the gap, what support has she actually received, and whether six months is a sufficient period to conclude she cannot succeed in this role.', 'நீங்கள் நிலைமையைத் துல்லியமாக மதிப்பிடுகிறீர்கள் - எந்தெந்த குறிப்பிட்ட திறன்களில் இடைவெளி உள்ளது, அவர் உண்மையில் என்ன ஆதரவைப் பெற்றுள்ளார், மேலும் இந்தப் பணியில் அவரால் வெற்றி பெற முடியாது என்று முடிவு செய்வதற்கு ஆறு மாதங்கள் போதுமான காலமா என்பதையும் ஆராய்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q12
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q12',
     'You have just delivered a formal performance warning to a leader who has been with the organisation for 11 years - someone who was once considered high potential and who has been a personal loyalty to two previous CEOs. The conversation was hard. He accepted the feedback without argument. As he left the room he said quietly - I never thought it would end like this.What is actually happening inside you after that door closes?', 'How do you feel now?', '11 ஆண்டுகளாக நிறுவனத்தில் பணியாற்றி வரும் ஒரு தலைவருக்கு நீங்கள் இப்போதுதான் ஒரு முறையான செயல்திறன் எச்சரிக்கையை வழங்கியுள்ளீர்கள் - அவர் ஒரு காலத்தில் அதிக ஆற்றல் கொண்டவராகக் கருதப்பட்டவர், மேலும் அவருக்கு முந்தைய இரண்டு தலைமைச் செயல் அதிகாரிகளுக்கும் தனிப்பட்ட விசுவாசமாக இருந்தவர். அந்த உரையாடல் கடினமாக இருந்தது. அவர் எந்தவிதமான வாதமும் இன்றி அந்தப் பின்னூட்டத்தை ஏற்றுக்கொண்டார். அறையை விட்டு வெளியேறும்போது அவர் மெதுவாகச் சொன்னார் - இது இப்படி முடியும் என்று நான் ஒருபோதும் நினைக்கவில்லை. அந்தக் கதவு மூடிய பிறகு, உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'நீங்கள் இப்போது எப்படி உணர்கிறீர்கள்?',
     '{"theme": "Team Performance and Accountability", "layer": "Layer 3", "dimension": "control_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the weight of the decision but not doubt about it - you made the right call for the organisation and for him, even if it does not feel that way to either of you right now.', 'அந்த முடிவின் பாரத்தை நீங்கள் உணர்கிறீர்கள், ஆனால் அதில் உங்களுக்கு எந்த சந்தேகமும் இல்லை - தற்போதைக்கு உங்கள் இருவருக்கும் அப்படித் தோன்றாவிட்டாலும், அந்த நிறுவனத்திற்கும் அவருக்கும் நீங்கள் எடுத்த முடிவு சரியானதுதான்.', 'D'),
  (2, 'You feel the awareness of how this moment will travel - who he will speak to, how it will be interpreted, what it means for how other long-tenured leaders read your leadership style.', 'இந்தத் தருணம் எவ்வாறு பயணிக்கும், அவர் யாரிடம் பேசுவார், அது எவ்வாறு புரிந்துகொள்ளப்படும், நீண்டகாலமாகப் பதவியில் இருக்கும் மற்ற தலைவர்கள் உங்கள் தலைமைப் பாணியை எப்படிப் பார்க்கிறார்கள் என்பதில் அதன் தாக்கம் என்னவாக இருக்கும் என்பது போன்ற உணர்வுகளை நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel grief. Not guilt - grief. For what he was, for what has changed, for the gap between the leader he might have been and the conversation you just had. That feeling is real and it does not resolve quickly.', 'நீங்கள் துயரத்தை உணர்கிறீர்கள். அது குற்றவுணர்ச்சி அல்ல - துயரம். அவர் எப்படிப்பட்டவராக இருந்தார் என்பதற்காகவும், என்ன மாறிவிட்டது என்பதற்காகவும், அவர் எப்படிப்பட்ட தலைவராக இருந்திருக்கக்கூடும் என்பதற்கும் நீங்கள் சற்று முன்பு நடத்திய உரையாடலுக்கும் இடையே உள்ள இடைவெளிக்காகவும் அந்தத் துயரம். அந்த உணர்வு உண்மையானது, அது எளிதில் தீர்ந்துவிடாது.', 'S'),
  (4, 'You feel the need to document the conversation precisely, review whether every step of the process was followed correctly, and ensure that whatever happens next is defensible and fair.', 'உரையாடலைத் துல்லியமாக ஆவணப்படுத்தவும், செயல்முறையின் ஒவ்வொரு படியும் சரியாகப் பின்பற்றப்பட்டதா என்பதை மதிப்பாய்வு செய்யவும், அடுத்து நடப்பவை அனைத்தும் நியாயப்படுத்தக்கூடியதாகவும் நியாயமானதாகவும் இருப்பதை உறுதி செய்யவும் வேண்டியதன் அவசியத்தை நீங்கள் உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q13
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q13',
     'You are the CEO of a mid-sized pharmaceutical company. A competitor has just announced they are exiting a therapeutic category where you hold a secondary position. Their exit creates a window - their distribution relationships, key accounts, and some talent will be available within 90 days. Capturing this requires immediate capital deployment and a clear strategic commitment your board has not yet discussed.', 'How will you handle this?', 'நீங்கள் ஒரு நடுத்தர அளவிலான மருந்து நிறுவனத்தின் தலைமை நிர்வாக அதிகாரி. நீங்கள் துணைப் பங்கு வகிக்கும் ஒரு சிகிச்சைத் துறையிலிருந்து தங்களின் போட்டியாளர் நிறுவனம் வெளியேறுவதாக அறிவித்துள்ளது. அவர்களின் இந்த வெளியேற்றம் ஒரு வாய்ப்பை உருவாக்குகிறது - அவர்களின் விநியோக உறவுகள், முக்கிய வாடிக்கையாளர்கள் மற்றும் சில திறமையானவர்கள் 90 நாட்களுக்குள் கிடைப்பார்கள். இதை கைப்பற்றுவதற்கு, உடனடி மூலதன முதலீடும், உங்கள் நிர்வாகக் குழு இதுவரை விவாதிக்காத ஒரு தெளிவான உத்திசார்ந்த உறுதிப்பாடும் தேவைப்படுகிறது.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 1", "dimension": "decision_speed", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You call an emergency board session within 48 hours, make the case for moving, and ask for capital authority to act before the window closes - you will not let process cost you a market-defining opportunity.', 'நீங்கள் 48 மணி நேரத்திற்குள் ஒரு அவசர வாரியக் கூட்டத்தைக் கூட்டி, அடுத்தகட்ட நடவடிக்கைக்கான காரணங்களை முன்வைத்து, காலக்கெடு முடிவதற்குள் செயல்பட மூலதன அதிகாரத்தைக் கோரினால் - சந்தையைத் தீர்மானிக்கும் ஒரு வாய்ப்பை இந்த செயல்முறை உங்களிடமிருந்து பறித்துக்கொள்ள நீங்கள் அனுமதிக்க மாட்டீர்கள்.', 'D'),
  (2, 'You brief your two most influential board members informally, build pre-alignment before the formal session, and arrive at the board meeting with momentum behind the decision rather than starting from zero.', 'உங்கள் இயக்குநர் குழுவில் மிகவும் செல்வாக்கு மிக்க இரு உறுப்பினர்களுக்கு முறைசாரா முறையில் விளக்கமளித்து, முறையான அமர்வுக்கு முன் ஒருமித்த கருத்தை ஏற்படுத்தி, பூஜ்ஜியத்திலிருந்து தொடங்குவதற்குப் பதிலாக, அந்த முடிவுக்குப் பின்னால் ஒரு உத்வேகத்துடன் இயக்குநர் குழுக் கூட்டத்திற்குச் செல்கிறீர்கள்.', 'I'),
  (3, 'You prepare a thorough board paper, present it at the next scheduled meeting, and trust that a well-constructed case will carry more weight than a rushed decision - if the window closes, there will be another.', 'நீங்கள் ஒரு விரிவான வாரிய அறிக்கையைத் தயாரித்து, அடுத்ததாகத் திட்டமிடப்பட்ட கூட்டத்தில் அதைச் சமர்ப்பித்து, அவசர முடிவை விட நன்கு கட்டமைக்கப்பட்ட வாதத்திற்கு அதிக மதிப்பு இருக்கும் என்று நம்புங்கள் - ஏனெனில், அதற்கான வாய்ப்பு முடிந்தாலும், அடுத்த வாய்ப்பு வரும்.', 'S'),
  (4, 'You instruct your strategy team to produce a 10-day rapid assessment - market share opportunity, capital requirements, integration risk, talent availability - before you take any position to the board.', 'இயக்குநர் குழுவிடம் எந்தவொரு நிலைப்பாட்டையும் எடுப்பதற்கு முன்பு, சந்தைப் பங்கு வாய்ப்பு, மூலதனத் தேவைகள், ஒருங்கிணைப்பு இடர், திறமையானவர்களின் இருப்பு போன்றவற்றை உள்ளடக்கிய 10-நாள் விரைவான மதிப்பீட்டைத் தயாரிக்குமாறு உங்கள் வியூகக் குழுவிற்கு நீங்கள் அறிவுறுத்துகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q14
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q14',
     'You have been building a direct-to-consumer channel for three years, investing against significant internal resistance. The channel is now generating 12% of revenue with strong margin and customer retention data. Your largest distribution partner - responsible for 41% of your overall revenue - has told you privately that if you continue expanding the direct channel, they will reduce your shelf space significantly.', 'How will you handle this?', 'கணிசமான உள் எதிர்ப்புகளுக்கு மத்தியிலும் முதலீடு செய்து, கடந்த மூன்று ஆண்டுகளாக நீங்கள் ஒரு நேரடி நுகர்வோர் விற்பனை வழியை உருவாக்கி வருகிறீர்கள். அந்த விற்பனை வழி, தற்போது வலுவான லாப வரம்பு மற்றும் வாடிக்கையாளர் தக்கவைப்புத் தரவுகளுடன், வருவாயில் 12%-ஐ ஈட்டித் தருகிறது. உங்கள் ஒட்டுமொத்த வருவாயில் 41%-க்குப் பொறுப்பான, உங்களின் மிகப்பெரிய விநியோகப் பங்குதாரர், நீங்கள் இந்த நேரடி விற்பனை வழியைத் தொடர்ந்து விரிவுபடுத்தினால், அவர்கள் உங்கள் விற்பனை இடத்தை கணிசமாகக் குறைத்துவிடுவார்கள் என்று உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளார்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You accelerate the direct channel. The data is clear and the future belongs to organisations that own their customer relationships - you will manage the distribution partner transition, not avoid it.', 'நீங்கள் நேரடி விநியோக வழியை வேகப்படுத்துகிறீர்கள். தரவுகள் தெளிவாக உள்ளன, மேலும் தங்கள் வாடிக்கையாளர் உறவுகளைத் தாங்களே நிர்வகிக்கும் நிறுவனங்களுக்கே எதிர்காலம் சொந்தம் - நீங்கள் விநியோகப் பங்குதாரர் மாற்றத்தை நிர்வகிப்பீர்கள், அதைத் தவிர்க்க மாட்டீர்கள்.', 'D'),
  (2, 'You engage the distribution partner at the senior level, explore whether there is a partnership model that gives them a role in the direct channel ecosystem, and work to convert a threat into a collaboration.', 'நீங்கள் விநியோகப் பங்குதாரருடன் உயர் மட்டத்தில் கலந்துரையாடி, நேரடி விநியோகச் சங்கிலிச் சூழலில் அவர்களுக்கு ஒரு பங்கை வழங்கும் கூட்டாண்மை மாதிரி உள்ளதா என்பதை ஆராய்ந்து, ஓர் அச்சுறுத்தலை ஓர் ஒத்துழைப்பாக மாற்றப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You slow the direct channel expansion, protect the distribution relationship in the short term, and give yourself time to build the direct channel to a scale where the partner''s threat carries less weight.', 'நீங்கள் நேரடி விநியோகச் சங்கிலி விரிவாக்கத்தின் வேகத்தைக் குறைத்து, குறுகிய காலத்திற்கு விநியோக உறவைப் பாதுகாத்து, கூட்டாளியின் அச்சுறுத்தலுக்கு முக்கியத்துவம் குறையும் அளவிற்கு நேரடி விநியோகச் சங்கிலியை உருவாக்க உங்களுக்கு அவகாசம் அளிக்கிறீர்கள்.', 'S'),
  (4, 'You model the revenue and margin impact of both scenarios across a five-year horizon, understand the real financial consequence of the partner''s threat, and make the decision on numbers rather than strategic conviction alone.', 'நீங்கள், ஐந்தாண்டு காலக்கட்டத்தில் இரு சூழ்நிலைகளின் வருவாய் மற்றும் இலாப வரம்பு தாக்கத்தையும் மாதிரியாகக் கொண்டு, கூட்டாளியின் அச்சுறுத்தலால் ஏற்படும் உண்மையான நிதி விளைவுகளைப் புரிந்துகொண்டு, வெறும் உத்திசார்ந்த உறுதியை மட்டும் அடிப்படையாகக் கொள்ளாமல், எண்களின் அடிப்படையில் முடிவெடுக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q15
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q15',
     'Your board has asked you to present two strategic options for the next five years. Option A is a focused, disciplined extension of your current business - lower risk, predictable returns, defensible to investors. Option B is a platform transformation - high capital requirement, significant execution risk, but positions the company as a category leader if it succeeds. You personally believe Option B is right. Your CFO believes Option A is right.What matters more to you in this moment - your conviction in the transformational strategy that you believe is the right long-term call for the company, or the weight of your CFO''s caution and the board''s preference for a narrative they can defend to shareholders?', 'Which strategic option matters more?', 'அடுத்த ஐந்து ஆண்டுகளுக்கான இரண்டு உத்திசார்ந்த தெரிவுகளை முன்வைக்குமாறு உங்கள் நிர்வாகக் குழு உங்களைக் கேட்டுள்ளது. தெரிவு A என்பது உங்கள் தற்போதைய வணிகத்தை ஒருமுகப்படுத்தப்பட்ட, கட்டுப்பாடான முறையில் விரிவுபடுத்துவதாகும் - இது குறைந்த இடர், கணிக்கக்கூடிய வருமானம் மற்றும் முதலீட்டாளர்களிடம் நியாயப்படுத்தக்கூடியது. தெரிவு B என்பது ஒரு தள மாற்றமாகும் - இதற்கு அதிக மூலதனத் தேவை, குறிப்பிடத்தக்க செயலாக்க இடர் உள்ளது, ஆனால் இது வெற்றி பெற்றால் நிறுவனத்தை ஒரு பிரிவில் முன்னணியில் நிலைநிறுத்தும். தனிப்பட்ட முறையில் நீங்கள் தெரிவு B சரியானது என்று நம்புகிறீர்கள். உங்கள் தலைமை நிதி அதிகாரி (CFO) தெரிவு A சரியானது என்று நம்புகிறார். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - நிறுவனத்தின் நீண்டகாலத்திற்குச் சரியான முடிவு என்று நீங்கள் நம்பும் அந்த மாற்றத்திற்கான உத்தியின் மீதான உங்கள் உறுதியான நம்பிக்கையா, அல்லது உங்கள் தலைமை நிதி அதிகாரியின் எச்சரிக்கை உணர்வும், பங்குதாரர்களிடம் நியாயப்படுத்தக்கூடிய ஒரு விளக்கத்திற்கான நிர்வாகக் குழுவின் விருப்பமுமா?', 'எந்த உத்திசார்ந்த தெரிவு அதிக முக்கியத்துவம் வாய்ந்தது?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 2", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Your conviction. The CEO''s job is to see further than the current quarter. You will make the case for Option B and accept the accountability that comes with it.', 'உங்கள் உறுதியான நம்பிக்கை. தற்போதைய காலாண்டையும் தாண்டி தொலைநோக்குப் பார்வை கொண்டிருப்பதே தலைமைச் செயல் அதிகாரியின் பணி. நீங்கள் மாற்றுத் தேர்வு B-க்கு ஆதரவாக வாதிட்டு, அதனுடன் வரும் பொறுப்பையும் ஏற்றுக்கொள்வீர்கள்.', 'D'),
  (2, 'The board''s confidence. You will present both options fully but invest your energy in building the board''s belief in Option B - you need them with you, not behind you, on a decision of this scale.', 'வாரியத்தின் நம்பிக்கை. நீங்கள் இரண்டு விருப்பங்களையும் முழுமையாக முன்வைப்பீர்கள், ஆனால் விருப்பம் B-யின் மீது வாரியத்தின் நம்பிக்கையை வளர்ப்பதில் உங்கள் ஆற்றலைச் செலுத்துங்கள் - இத்தகைய ஒரு பெரிய முடிவில், அவர்கள் உங்களுக்குப் பின்னால் அல்ல, உங்களுடன் இருக்க வேண்டும்.', 'I'),
  (3, 'The organisation''s stability. A transformation that the CFO does not believe in and the board is uncomfortable with is a transformation that will fail. You will choose Option A and create the conditions for a bolder move in year three.', 'நிறுவனத்தின் நிலைத்தன்மை. தலைமை நிதி அதிகாரி நம்பாத மற்றும் நிர்வாகக் குழுவுக்கு சங்கடத்தை ஏற்படுத்தும் ஒரு மாற்றம் தோல்வியடையும். நீங்கள் விருப்பம் A-ஐத் தேர்ந்தெடுத்து, மூன்றாம் ஆண்டில் ஒரு துணிச்சலான நடவடிக்கைக்கான சூழலை உருவாக்குவீர்கள்.', 'S'),
  (4, 'The evidence. You will commission a rigorous external validation of both options, bring in a sector expert the board respects, and let the analysis determine which option has the stronger foundation.', 'சான்றுகள். நீங்கள் இரண்டு தெரிவுகளுக்கும் ஒரு முழுமையான வெளிப்புறச் சரிபார்ப்பை மேற்கொள்வீர்கள், நிர்வாகக் குழு மதிக்கும் ஒரு துறைசார் நிபுணரை வரவழைப்பீர்கள், மேலும் எந்தத் தெரிவுக்கு வலுவான அடித்தளம் உள்ளது என்பதை அந்தப் பகுப்பாய்வே தீர்மானிக்கட்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q16
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q16',
     'You have spent four months designing a reorganisation that will change the reporting structure for 340 people, eliminate two layers of management, and redefine the accountability model for your top 60 leaders. The design is finalised. The announcement is tomorrow. Tonight, a trusted advisor calls you and says - I think you have underestimated how much this will break what is currently working.Before you say anything to your advisor, before you decide whether to delay - what is actually happening inside you at that moment?', 'How will you handle doubt?', '340 பேருக்கான அறிக்கையிடல் கட்டமைப்பை மாற்றவும், இரண்டு நிர்வாக அடுக்குகளை அகற்றவும், உங்கள் முதல் 60 தலைவர்களுக்கான பொறுப்புக்கூறல் மாதிரியை மறுவரையறை செய்யவும் கூடிய ஒரு மறுசீரமைப்பை வடிவமைக்க நீங்கள் நான்கு மாதங்கள் செலவழித்துள்ளீர்கள். வடிவமைப்பு இறுதி செய்யப்பட்டுவிட்டது. நாளை அறிவிப்பு வரவிருக்கிறது. இன்றிரவு, ஒரு நம்பிக்கைக்குரிய ஆலோசகர் உங்களை அழைத்து, "தற்போது சிறப்பாகச் செயல்பட்டுக்கொண்டிருக்கும் அமைப்பை இது எந்த அளவிற்குச் சீர்குலைக்கும் என்பதை நீங்கள் குறைத்து மதிப்பிட்டுவிட்டீர்கள் என்று நான் நினைக்கிறேன்" என்கிறார். உங்கள் ஆலோசகரிடம் எதையும் சொல்வதற்கு முன்பும், தாமதப்படுத்துவதா வேண்டாமா என்று முடிவெடுப்பதற்கு முன்பும் - அந்தத் தருணத்தில் உங்களுக்குள் உண்மையில் என்னதான் நடந்துகொண்டிருக்கிறது?', 'சந்தேகத்தை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Strategic Decision Making", "layer": "Layer 3", "dimension": "accuracy_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel a sharp instinct to hold the course - four months of work, a decision made with full information, and one late call is not sufficient reason to pull back from a decision you believe is right.', 'நீங்கள் எடுக்கும் முடிவில் உறுதியாக இருக்க வேண்டும் என்ற ஒரு தீவிர உள்ளுணர்வு உங்களுக்கு ஏற்படுகிறது - நான்கு மாத கால உழைப்பு, முழுமையான தகவல்களுடன் எடுக்கப்பட்ட ஒரு முடிவு, மற்றும் தாமதமாக வரும் ஒரே ஒரு அழைப்பு ஆகியவை, நீங்கள் சரி என்று நம்பும் ஒரு முடிவிலிருந்து பின்வாங்குவதற்குப் போதுமான காரணங்கள் அல்ல.', 'D'),
  (2, 'You feel the complexity of the moment - if you delay, it signals doubt; if you proceed and it breaks what is working, it signals worse - and you are acutely aware that your handling of the next 12 hours will be scrutinised.', 'அந்தத் தருணத்தின் சிக்கலான தன்மையை நீங்கள் உணர்கிறீர்கள் - தாமதித்தால், அது சந்தேகத்தை உணர்த்துகிறது; தொடர்ந்து செயல்பட்டு, நன்றாகச் செயல்படும் ஒன்றைக் குலைத்தால், அது இன்னும் மோசமானதை உணர்த்துகிறது - மேலும், அடுத்த 12 மணி நேரத்தை நீங்கள் கையாளும் விதம் கூர்ந்து கவனிக்கப்படும் என்பதையும் நீங்கள் ஆழமாக உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the discomfort of genuine uncertainty. You trust this advisor. And the possibility that you have missed something real - something that will cost people you care about - is harder to dismiss than you want it to be.', 'உண்மையான நிச்சயமற்ற தன்மையின் சங்கடத்தை நீங்கள் உணர்கிறீர்கள். இந்த ஆலோசகரை நீங்கள் நம்புகிறீர்கள். மேலும், நீங்கள் நேசிக்கும் நபர்களுக்குப் பாதிப்பை ஏற்படுத்தக்கூடிய ஏதோ ஒரு உண்மையான விஷயத்தை நீங்கள் தவறவிட்டிருக்கலாம் என்ற சாத்தியக்கூற்றை, நீங்கள் விரும்புவதை விட நிராகரிப்பது கடினமாக இருக்கிறது.', 'S'),
  (4, 'You feel the need to identify precisely what your advisor is pointing at - which specific relationships, processes, or accountabilities he believes will break - before you decide whether the concern is addressable or fundamental.', 'அந்தக் கவலை தீர்க்கக்கூடியதா அல்லது அடிப்படையானதா என்பதை நீங்கள் தீர்மானிப்பதற்கு முன், உங்கள் ஆலோசகர் எதைச் சுட்டிக்காட்டுகிறார் - அதாவது, எந்தக் குறிப்பிட்ட உறவுகள், செயல்முறைகள் அல்லது பொறுப்புகள் முறியும் என்று அவர் நம்புகிறார் - என்பதை நீங்கள் துல்லியமாகக் கண்டறிய வேண்டிய அவசியத்தை உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q17
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q17',
     'You have been appointed to lead a 140-year-old banking institution through its first significant digital transformation. The culture is deeply traditional - tenure is valued over performance, hierarchy is respected, and change has historically been managed slowly. Your mandate from the board is to move faster than the organisation is comfortable with.', 'How will you manage change?', '140 ஆண்டுகள் பழமையான ஒரு வங்கி நிறுவனத்தை அதன் முதல் குறிப்பிடத்தக்க டிஜிட்டல் மாற்றத்தின் வழியே வழிநடத்த நீங்கள் நியமிக்கப்பட்டுள்ளீர்கள். அதன் கலாச்சாரம் மிகவும் பாரம்பரியமானது - செயல்திறனை விட பணி அனுபவத்திற்கே மதிப்பு அளிக்கப்படுகிறது, படிநிலை அமைப்பு மதிக்கப்படுகிறது, மேலும் மாற்றங்கள் வரலாற்று ரீதியாக மெதுவாகவே கையாளப்பட்டு வந்துள்ளன. அந்த நிறுவனம் விரும்பாத வேகத்தில் செயல்பட வேண்டும் என்பதே நிர்வாகக் குழு உங்களுக்கு வழங்கியுள்ள ஆணையாகும்.', 'மாற்றத்தை நீங்கள் எவ்வாறு சமாளிப்பீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 1", "dimension": "change_tolerance", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You set a non-negotiable transformation pace, make structural changes in the first 90 days to signal that this is real, and let the discomfort be a feature rather than a problem to be managed.', 'மாற்றத்திற்கான வேகத்தை விட்டுக்கொடுக்க முடியாதபடி நிர்ணயித்து, இது உண்மையானது என்பதை உணர்த்தும் வகையில் முதல் 90 நாட்களில் கட்டமைப்பு மாற்றங்களைச் செய்து, அந்த அசௌகரியத்தை நிர்வகிக்கப்பட வேண்டிய ஒரு பிரச்சனையாகக் கருதாமல், அதன் இயல்பான அம்சமாகவே ஏற்றுக்கொள்ளுங்கள்.', 'D'),
  (2, 'You spend your first 90 days building relationships with the institution''s most respected informal leaders - the people whose endorsement will determine whether the transformation is accepted or resisted.', 'உங்கள் முதல் 90 நாட்களை, அந்த நிறுவனத்தின் மிகவும் மதிக்கப்படும் முறைசாராத் தலைவர்களுடன் உறவுகளை வளர்ப்பதில் செலவிடுகிறீர்கள் - இவர்களுடைய ஒப்புதல்தான் அந்த மாற்றம் ஏற்றுக்கொள்ளப்படுமா அல்லது எதிர்க்கப்படுமா என்பதைத் தீர்மானிக்கும்.', 'I'),
  (3, 'You honour the institution''s history publicly while creating protected spaces for new ways of working - you will not ask the whole organisation to change before you have shown that change produces better outcomes.', 'புதிய பணி முறைகளுக்கான பாதுகாக்கப்பட்ட இடங்களை உருவாக்கும் அதே வேளையில், நிறுவனத்தின் வரலாற்றை நீங்கள் பகிரங்கமாகப் போற்றுகிறீர்கள் - மாற்றம் சிறந்த விளைவுகளைத் தருகிறது என்பதை நீங்கள் நிரூபிக்கும் வரை, முழு அமைப்பையும் மாற்றுமாறு நீங்கள் கோர மாட்டீர்கள்.', 'S'),
  (4, 'You commission a detailed capability and culture assessment, map where the transformation has the strongest foundation and where the resistance is structural, and sequence your moves accordingly.', 'நீங்கள் ஒரு விரிவான திறன் மற்றும் கலாச்சார மதிப்பீட்டை மேற்கொண்டு, மாற்றத்திற்கான அடித்தளம் எங்கு வலுவாக உள்ளது மற்றும் எதிர்ப்பு எங்கு கட்டமைப்பு ரீதியாக உள்ளது என்பதை வரைபடமாக்கி, அதற்கேற்ப உங்கள் நகர்வுகளை வரிசைப்படுத்துகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q18
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q18',
     'You have introduced a new leadership competency framework that requires all senior leaders to be assessed annually by their teams. For the first time, upward feedback will influence compensation decisions. Three of your longest-serving leaders - all strong performers by traditional metrics - have privately told you they find the process infantilising and are considering whether this organisation still fits them.', 'How will you handle resistance?', 'அனைத்து மூத்த தலைவர்களும் தங்கள் குழுக்களால் ஆண்டுதோறும் மதிப்பீடு செய்யப்பட வேண்டும் எனக் கோரும் ஒரு புதிய தலைமைத்துவத் தகுதி கட்டமைப்பை நீங்கள் அறிமுகப்படுத்தியுள்ளீர்கள். முதல் முறையாக, மேலதிகாரிகளின் கருத்துகள் ஊதிய முடிவுகளில் தாக்கத்தை ஏற்படுத்தும். பாரம்பரிய அளவுகோல்களின்படி சிறப்பாகச் செயல்படுபவர்களான, உங்கள் நிறுவனத்தில் நீண்ட காலம் பணியாற்றிய மூன்று தலைவர்கள், இந்தச் செயல்முறை தங்களைக் குழந்தைகளாக்குவதாக உணர்வதாகவும், இந்த அமைப்பு தங்களுக்கு இன்னும் பொருத்தமானதா என்று பரிசீலித்து வருவதாகவும் உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளனர்.', 'எதிர்ப்பை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 1", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You hold the policy. The framework exists because traditional metrics were insufficient and the feedback of the people these leaders manage is legitimate data. You will not exempt senior leaders from accountability to their teams.', 'கொள்கை உங்கள் கையில் உள்ளது. பாரம்பரிய அளவீடுகள் போதுமானதாக இல்லாததாலும், இந்தத் தலைவர்கள் நிர்வகிக்கும் மக்களின் கருத்துகள் முறையான தரவுகளாக இருப்பதாலும் இந்தக் கட்டமைப்பு உள்ளது. மூத்த தலைவர்களை அவர்களின் குழுக்களுக்குப் பொறுப்புக்கூறுவதிலிருந்து நீங்கள் விலக்க முடியாது.', 'D'),
  (2, 'You meet each of the three leaders individually, understand their specific objection, and work to design an implementation that captures the intent of the framework without feeling like a loss of dignity.', 'நீங்கள் மூன்று தலைவர்களையும் தனித்தனியாகச் சந்தித்து, அவர்களின் குறிப்பிட்ட ஆட்சேபனையைப் புரிந்துகொண்டு, கண்ணியத்திற்கு பங்கம் விளைவிப்பது போன்ற உணர்வின்றி, கட்டமைப்பின் நோக்கத்தைப் பிரதிபலிக்கும் ஒரு செயலாக்கத்தை வடிவமைக்கப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You give the framework a full cycle before drawing conclusions - resistance in year one of a cultural change is expected and these leaders may come around once they see how the process actually works.', 'முடிவுகளுக்கு வருவதற்கு முன், அந்தக் கட்டமைப்புக்கு ஒரு முழுமையான சுழற்சியை நீங்கள் அளிக்க வேண்டும் - ஒரு கலாச்சார மாற்றத்தின் முதல் ஆண்டில் எதிர்ப்பு ஏற்படுவது எதிர்பார்க்கக்கூடியதே, மேலும் அந்தச் செயல்முறை உண்மையில் எவ்வாறு செயல்படுகிறது என்பதைப் பார்த்தவுடன் இந்தத் தலைவர்கள் மனம் மாறக்கூடும்.', 'S'),
  (4, 'You review whether the framework design itself is creating unnecessary friction - whether there are specific elements that are poorly calibrated for senior leaders - and refine them before you lose people you cannot afford to lose.', 'கட்டமைப்பு வடிவமைப்பே தேவையற்ற உராய்வை ஏற்படுத்துகிறதா என்பதையும், மூத்த தலைவர்களுக்காகக் குறிப்பிட்ட கூறுகள் சரியாக வடிவமைக்கப்படவில்லையா என்பதையும் நீங்கள் மதிப்பாய்வு செய்து, இழக்கவே கூடாத நபர்களை இழப்பதற்கு முன்பாக அவற்றைச் செம்மைப்படுத்த வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q19
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q19',
     'Your organisation has been through 26 months of continuous change - a merger, a restructuring, a leadership transition, and now a strategy pivot. Engagement scores have dropped 19 points. Your top talent retention rate has declined. Your CHRO tells you the organisation needs a period of stability before it can absorb another change. Your board wants the strategy pivot completed in 12 months.Two things are pulling at you. Which is stronger - the board''s mandate to move at pace on the strategy pivot because the market window is real, or your CHRO''s read that the organisation is exhausted and that pushing harder will cost you the people you need to execute the strategy?', 'How will you handle change?', 'உங்கள் நிறுவனம் 26 மாதங்களாகத் தொடர்ச்சியான மாற்றங்களைச் சந்தித்துள்ளது - ஒரு இணைப்பு, ஒரு மறுசீரமைப்பு, ஒரு தலைமைப் பதவி மாற்றம், இப்போது ஒரு உத்தி மாற்றம். பணியாளர் ஈடுபாட்டு மதிப்பெண்கள் 19 புள்ளிகள் குறைந்துள்ளன. உங்கள் உயர் திறமையாளர்களைத் தக்கவைக்கும் விகிதம் குறைந்துள்ளது. மற்றொரு மாற்றத்தை உள்வாங்குவதற்கு முன்பு நிறுவனத்திற்கு ஒரு ஸ்திரத்தன்மைக் காலம் தேவை என்று உங்கள் தலைமை மனிதவள அதிகாரி (CHRO) கூறுகிறார். உங்கள் நிர்வாகக் குழு, இந்த உத்தி மாற்றத்தை 12 மாதங்களில் முடிக்க விரும்புகிறது. இரண்டு விஷயங்கள் உங்களை அலைக்கழிக்கின்றன. இதில் எது வலிமையானது - சந்தை வாய்ப்பு உண்மையாக இருப்பதால், உத்தி மாற்றத்தை வேகமாக முன்னெடுக்க வேண்டும் என்ற நிர்வாகக் குழுவின் கட்டளையா, அல்லது நிறுவனம் சோர்வடைந்துவிட்டது என்றும், மேலும் கடுமையாகச் செயல்பட்டால் உத்தியைச் செயல்படுத்தத் தேவையான பணியாளர்களை இழக்க நேரிடும் என்றும் உங்கள் தலைமை மனிதவள அதிகாரி கருதுவதா?', 'மாற்றத்தை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 2", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The market window. An exhausted organisation that captures the market is recoverable. An energised organisation that misses the window is not.', 'சந்தைக்கான வாய்ப்பு. சந்தையைக் கைப்பற்றும் ஒரு சோர்வுற்ற நிறுவனத்தை மீட்க முடியும். அந்த வாய்ப்பைத் தவறவிடும் ஒரு ஆற்றல்மிக்க நிறுவனத்தை மீட்க முடியாது.', 'D'),
  (2, 'The people. You will negotiate with the board on pace - not to avoid the pivot but to protect the execution capability that makes the pivot possible. Speed without people is not speed.', 'மக்கள். நீங்கள் இயக்குநர்கள் குழுவுடன் வேகம் குறித்துப் பேச்சுவார்த்தை நடத்துவீர்கள் - அது திசைமாற்றத்தைத் தவிர்ப்பதற்காக அல்ல, மாறாக அந்தத் திசைமாற்றத்தைச் சாத்தியமாக்கும் செயலாக்கத் திறனைப் பாதுகாப்பதற்காகவே. மக்கள் இல்லாத வேகம், வேகமே அல்ல.', 'I'),
  (3, 'Stability. You will design the pivot to feel like a consolidation of what has already been built rather than a new change - framing matters as much as pace when an organisation is tired.', 'நிலைத்தன்மை. இந்தத் திருப்புமுனையை, ஒரு புதிய மாற்றமாகத் தோன்றுவதை விட, ஏற்கனவே கட்டமைக்கப்பட்டவற்றின் ஒரு ஒருங்கிணைப்பாகத் தோன்றும் வகையில் நீங்கள் வடிவமைப்பீர்கள் - ஒரு நிறுவனம் சோர்வடைந்திருக்கும்போது, ​​அதன் வேகத்தைப் போலவே அதை முன்வைக்கும் விதமும் முக்கியமானது.', 'S'),
  (4, 'The data. You will run a rapid organisational readiness assessment - identify which parts of the organisation have capacity to move and which do not - and sequence the pivot around that evidence rather than a uniform timeline.', 'தரவுகள். நீங்கள் ஒரு விரைவான நிறுவனத் தயார்நிலை மதிப்பீட்டை மேற்கொள்வீர்கள் - நிறுவனத்தின் எந்தப் பகுதிகளுக்கு நகரும் திறன் உள்ளது, எவற்றுக்கு இல்லை என்பதைக் கண்டறிந்து, ஒரு சீரான காலவரிசையை அடிப்படையாகக் கொள்ளாமல், அந்த ஆதாரங்களைச் சுற்றியே மாற்றத்தை வரிசைப்படுத்துவீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q20
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q20',
     'You have made the decision to close a manufacturing plant that has been operational for 31 years. The plant employs 1,100 people in a small town where your company is the primary employer. The economics are clear. The decision is right. The announcement is in three days.The honest feeling underneath this - not the business case, not the communication plan, not the severance package - what are you actually feeling three days before that announcement?', 'What are you actually feeling?', '31 ஆண்டுகளாக இயங்கி வந்த ஒரு உற்பத்தி ஆலையை மூட நீங்கள் முடிவு செய்துள்ளீர்கள். உங்கள் நிறுவனமே முதன்மை வேலை வழங்குநராக இருக்கும் ஒரு சிறிய நகரத்தில், அந்த ஆலையில் 1,100 பேர் பணிபுரிகின்றனர். பொருளாதாரக் காரணங்கள் தெளிவாக உள்ளன. இந்த முடிவு சரியானது. இன்னும் மூன்று நாட்களில் அந்த அறிவிப்பு வரவிருக்கிறது. இதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்னவென்றால் - வணிகக் காரணம் அல்ல, தகவல் தொடர்புத் திட்டம் அல்ல, பணிநீக்க இழப்பீட்டுத் தொகை அல்ல - அந்த அறிவிப்புக்கு மூன்று நாட்களுக்கு முன்பு நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?',
     '{"theme": "Organisational Culture and Change", "layer": "Layer 3", "dimension": "relationship_dependency", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the weight of the decision without doubt about it - you have made the right call and you will lead the announcement with the clarity and dignity it deserves, even when the room is devastated.', 'அந்த முடிவின் பாரத்தை நீங்கள் சந்தேகமின்றி உணர்கிறீர்கள் - நீங்கள் எடுத்த முடிவு சரியானது, மேலும் அந்த அறை நிலைகுலைந்து போனாலும், அந்த அறிவிப்பை அதற்குரிய தெளிவுடனும் கண்ணியத்துடனும் நீங்கள் முன்னின்று நடத்துவீர்கள்.', 'D'),
  (2, 'You feel the awareness of how this will travel - the media, the community leaders, the politicians who will make this into a story - and the importance of being the most credible voice in that narrative from day one.', 'ஊடகங்கள், சமூகத் தலைவர்கள், அரசியல்வாதிகள் என இது ஒரு செய்தியாக உருவெடுக்கும் விதம் குறித்த விழிப்புணர்வையும், முதல் நாளிலிருந்தே அந்தப் பிரச்சாரத்தில் மிகவும் நம்பகமான குரலாக இருப்பதன் முக்கியத்துவத்தையும் நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the human cost of it in a way that does not resolve into a business case. 1,100 people. 31 years. A town. That is not an abstraction and you are not pretending it is, even as you prepare to announce it.', 'அதன் மனித இழப்பை நீங்கள் ஒரு வணிகத் திட்டமாக உருவெடுக்காத வகையில் உணர்கிறீர்கள். 1,100 பேர். 31 ஆண்டுகள். ஒரு நகரம். அது ஒரு கற்பனையல்ல; அதை அறிவிக்கத் தயாராகும்போதும் நீங்கள் அப்படிப் பாசாங்கு செய்யவில்லை.', 'S'),
  (4, 'You feel the need to verify one more time that every alternative was genuinely explored - restructuring, partial closure, buyer identification - before you carry the weight of a decision this permanent into that room.', 'இவ்வளவு நிரந்தரமான ஒரு முடிவின் பாரத்தை அந்த அறைக்குள் கொண்டு செல்வதற்கு முன்பு, மறுசீரமைப்பு, பகுதியளவு மூடுதல், வாங்குபவரை அடையாளம் காணுதல் போன்ற ஒவ்வொரு மாற்று வழியும் உண்மையாகவே ஆராயப்பட்டதா என்பதை நீங்கள் மீண்டும் ஒருமுறை சரிபார்க்க வேண்டியதன் அவசியத்தை உணர்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q21
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q21',
     'A peer CXO has been systematically building a relationship with your CEO and using that access to influence decisions that fall within your mandate. He has not overstepped formally - he operates in the grey zone of informal influence. His last three suggestions to the CEO have resulted in direction changes that affect your division without your input.', 'How to handle informal influence?', 'சக CXO ஒருவர், உங்கள் CEO-வுடன் திட்டமிட்டு ஒரு உறவை வளர்த்துக்கொண்டு, அந்த அணுகலைப் பயன்படுத்தி உங்கள் அதிகார வரம்பிற்குள் வரும் முடிவுகளில் செல்வாக்கு செலுத்தி வருகிறார். அவர் முறைப்படி வரம்பு மீறவில்லை - அவர் முறைசாரா செல்வாக்கின் தெளிவற்ற பகுதியில் செயல்படுகிறார். CEO-வுக்கு அவர் அளித்த கடைசி மூன்று ஆலோசனைகளின் விளைவாக, உங்கள் பங்களிப்பு இல்லாமலேயே உங்கள் பிரிவைப் பாதிக்கும் திசை மாற்றங்கள் ஏற்பட்டுள்ளன.', 'முறைசாரா செல்வாக்கை எவ்வாறு கையாள்வது?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 1", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a direct conversation with the CEO, name the pattern specifically, and establish a clear protocol for how decisions affecting your division will be made going forward.', 'நீங்கள் தலைமை நிர்வாக அதிகாரியுடன் ஒரு நேரடி உரையாடலைக் கோருகிறீர்கள், அந்தப் போக்கை குறிப்பாகக் குறிப்பிடுகிறீர்கள், மேலும் இனிவரும் காலங்களில் உங்கள் பிரிவைப் பாதிக்கும் முடிவுகள் எவ்வாறு எடுக்கப்படும் என்பதற்கான ஒரு தெளிவான நெறிமுறையை உருவாக்குகிறீர்கள்.', 'D'),
  (2, 'You invest in your own relationship with the CEO - more regular access, better quality conversations, deeper strategic alignment - and address the influence deficit directly rather than through a confrontation with your peer.', 'தலைமைச் செயல் அதிகாரியுடனான உங்கள் சொந்த உறவில் நீங்கள் முதலீடு செய்கிறீர்கள் - அதாவது, அடிக்கடி அவரைச் சந்திப்பது, சிறந்த தரமான உரையாடல்கள், ஆழமான உத்திசார் ஒருங்கிணைப்பு போன்றவற்றை மேற்கொண்டு, உங்கள் சக ஊழியருடன் மோதல் மூலம் செல்வதற்குப் பதிலாக, செல்வாக்குப் பற்றாக்குறையை நேரடியாகச் சரிசெய்கிறீர்கள்.', 'I'),
  (3, 'You speak to your peer directly, without accusation, and explore whether there is a way to work more collaboratively so that his relationship with the CEO becomes an asset for both of you rather than a source of tension.', 'நீங்கள் உங்கள் சக ஊழியரிடம் குற்றம் சாட்டாமல் நேரடியாகப் பேசி, தலைமை நிர்வாக அதிகாரியுடனான அவரது உறவு பதற்றத்தின் ஆதாரமாக மாறுவதற்குப் பதிலாக உங்கள் இருவருக்கும் ஒரு சொத்தாக மாறும் வகையில், மேலும் ஒத்துழைப்புடன் செயல்படுவதற்கு ஏதேனும் வழி உள்ளதா என்று ஆராயுங்கள்.', 'S'),
  (4, 'You document the specific decisions that have been influenced, map the pattern precisely, and present it to the CEO with enough specificity that the problem is clear without requiring you to name your peer as the source.', 'செல்வாக்கு செலுத்தப்பட்ட குறிப்பிட்ட முடிவுகளை நீங்கள் ஆவணப்படுத்தி, அதன் போக்கைத் துல்லியமாக வரைபடமாக்கி, உங்கள் சக ஊழியரை மூல காரணமாகக் குறிப்பிடத் தேவையின்றி, சிக்கல் தெளிவாகப் புரியும் வகையில் அதைத் தலைமை நிர்வாக அதிகாரிக்கு முன்வைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q22
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q22',
     'You have been in your current CXO role for four years. You were recruited with an implicit understanding that you were being developed for the Group CEO position. A new board chair has been appointed. Within three months, she has reorganised the succession framework and your name no longer appears in the shortlist she has shared with the nominations committee.', 'How will you respond now?', 'நீங்கள் உங்கள் தற்போதைய CXO பதவியில் நான்கு ஆண்டுகளாக இருந்து வருகிறீர்கள். குழுமத்தின் CEO பதவிக்காக நீங்கள் தயார் செய்யப்படுகிறீர்கள் என்ற ஒரு உள்ளார்ந்த புரிதலுடன் நீங்கள் பணியமர்த்தப்பட்டீர்கள். ஒரு புதிய வாரியத் தலைவர் நியமிக்கப்பட்டுள்ளார். மூன்று மாதங்களுக்குள், அவர் வாரிசுரிமைக் கட்டமைப்பை மறுசீரமைத்துள்ளார், மேலும் அவர் நியமனக் குழுவுடன் பகிர்ந்துள்ள இறுதிப் பட்டியலில் உங்கள் பெயர் இப்போது இடம்பெறவில்லை.', 'இப்போது நீங்கள் எப்படிப் பதிலளிப்பீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a meeting with the new chair, ask directly about your standing in the succession framework, and make clear what your expectations were when you joined - you will not manage ambiguity when clarity is available.', 'புதிய தலைவருடன் ஒரு சந்திப்பைக் கோருங்கள், வாரிசுரிமைக் கட்டமைப்பில் உங்கள் நிலை குறித்து நேரடியாகக் கேளுங்கள், மேலும் நீங்கள் பொறுப்பேற்றபோது உங்கள் எதிர்பார்ப்புகள் என்னவாக இருந்தன என்பதைத் தெளிவுபடுத்துங்கள் - தெளிவு இருக்கும்போது, ​​உங்களால் இருபொருள் தன்மையைச் சமாளிக்க முடியாது.', 'D'),
  (2, 'You accelerate your visibility with the board - request opportunities to present, build relationships with individual board members, and demonstrate your readiness through proximity rather than through a conversation about succession.', 'இயக்குநர் குழுவின் முன் உங்கள் இருப்பை விரைவுபடுத்துங்கள் - விளக்கமளிக்க வாய்ப்புகளைக் கோருங்கள், தனிப்பட்ட இயக்குநர் குழு உறுப்பினர்களுடன் உறவுகளை வளர்த்துக் கொள்ளுங்கள், மேலும் வாரிசுரிமைப் பற்றிய உரையாடலின் மூலம் அல்லாமல், நெருக்கத்தின் மூலம் உங்கள் தயார்நிலையை வெளிப்படுத்துங்கள்.', 'I'),
  (3, 'You stay focused on your role, deliver the strongest possible results in the next two quarters, and trust that performance is the most sustainable basis for succession - political conversations with a new chair carry more risk than reward at this stage.', 'நீங்கள் உங்கள் பணியில் கவனம் செலுத்தி, அடுத்த இரண்டு காலாண்டுகளில் மிகச் சிறந்த முடிவுகளை வழங்குங்கள்; மேலும், வாரிசுரிமைக்கு செயல்திறனே மிகவும் நிலையான அடித்தளம் என்று நம்புங்கள் - இந்தக் கட்டத்தில் ஒரு புதிய தலைவருடனான அரசியல் உரையாடல்கள் பலனை விட அதிக ஆபத்தையே கொண்டுள்ளன.', 'S'),
  (4, 'You gather more context first - understand what has driven the succession framework change, whether it reflects a view of you specifically or a broader board reset - before you decide how to respond.', 'எவ்வாறு பதிலளிப்பது என்று தீர்மானிப்பதற்கு முன், நீங்கள் முதலில் கூடுதல் சூழல் விவரங்களைத் திரட்ட வேண்டும் - வாரிசுரிமைக் கட்டமைப்பு மாற்றத்திற்கு என்ன காரணம், அது குறிப்பாக உங்களைப் பற்றிய ஒரு பார்வையைப் பிரதிபலிக்கிறதா அல்லது ஒரு பரந்த நிர்வாகக் குழுவின் மறுசீரமைப்பா என்பதைப் புரிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q23
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q23',
     'At the annual leadership awards, a major recognition - one that you led the work behind - is given to a peer who played a supporting role in the initiative. The CEO presents it publicly. The room applauds. Your team, who worked for 14 months on this, is watching you.What matters more to you in this moment - your own need to have your contribution recognised, and the discomfort of watching credit go elsewhere in front of the people who gave the most to make it happen, or the discipline to hold your composure, protect your team''s dignity, and address the attribution privately?', 'How will you handle conflict?', 'ஆண்டுதோறும் நடைபெறும் தலைமைத்துவ விருதுகள் விழாவில், நீங்கள் முன்னின்று வழிநடத்திய ஒரு முக்கிய அங்கீகாரம், அந்த முன்னெடுப்பில் துணைப் பங்காற்றிய சக ஊழியர் ஒருவருக்கு வழங்கப்படுகிறது. தலைமைச் செயல் அதிகாரி அதை பகிரங்கமாக வழங்குகிறார். அங்கிருப்பவர்கள் கைதட்டுகிறார்கள். இதற்காக 14 மாதங்கள் உழைத்த உங்கள் குழுவினர், உங்களைக் கவனித்துக் கொண்டிருக்கிறார்கள். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - உங்கள் பங்களிப்பு அங்கீகரிக்கப்பட வேண்டும் என்ற உங்கள் சொந்தத் தேவையும், அதைச் சாத்தியமாக்கத் தங்களின் பெரும் பங்களிப்பை வழங்கியவர்களின் முன்னிலையில், அதற்கான பெருமை வேறு ஒருவருக்குச் செல்வதைப் பார்க்கும் சங்கடமுமா, அல்லது உங்கள் நிதானத்தைக் கடைப்பிடித்து, உங்கள் குழுவின் கண்ணியத்தைப் பாதுகாத்து, அந்தப் பெருமையை தனிப்பட்ட முறையில் எடுத்துரைக்கும் ஒழுக்கமா?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 2", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Holding your composure publicly and addressing it directly with the CEO afterward - your team respects how you handle moments like this more than they need the award to carry the right name.', 'பொதுவெளியில் உங்கள் நிதானத்தைக் கடைப்பிடித்து, பின்னர் தலைமைச் செயல் அதிகாரியிடம் நேரடியாக இதுகுறித்துப் பேசுவது - அந்த விருது சரியான பெயரைக் கொண்டிருக்க வேண்டும் என்பதை விட, இதுபோன்ற தருணங்களை நீங்கள் கையாளும் விதத்தை உங்கள் குழுவினர் அதிகம் மதிக்கிறார்கள்.', 'D'),
  (2, 'Finding a way in the moment to acknowledge your team - not to take credit back but to ensure the people who did the work feel seen, even if the formal recognition has already been given elsewhere.', 'முறையான அங்கீகாரம் ஏற்கனவே வேறு இடங்களில் வழங்கப்பட்டிருந்தாலும், புகழைத் திரும்பப் பெறுவதற்காக அல்லாமல், உழைத்தவர்கள் கவனிக்கப்படுகிறார்கள் என்ற உணர்வை உறுதி செய்வதற்காக, அந்தத் தருணத்திலேயே உங்கள் குழுவினரை அங்கீகரிக்க ஒரு வழியைக் கண்டறிவது.', 'I'),
  (3, 'Letting it go in the room. Pursuing credit in a public setting costs more than the recognition is worth. You will protect your team privately and choose your moment carefully.', 'அதை அறைக்குள் விட்டுவிடுவது. பொதுவெளியில் புகழைத் தேடுவது, அதனால் கிடைக்கும் அங்கீகாரத்தை விட அதிக செலவை ஏற்படுத்தும். நீங்கள் உங்கள் குழுவைத் தனிப்பட்ட முறையில் பாதுகாத்து, சரியான தருணத்தைக் கவனமாகத் தேர்ந்தெடுக்க வேண்டும்.', 'S'),
  (4, 'Documenting your division''s contribution to the initiative and ensuring it is on record - formally, clearly, and without drama - so that the attribution is corrected in the institutional memory even if not in the moment.', 'இந்த முன்னெடுப்பிற்கு உங்கள் பிரிவின் பங்களிப்பை ஆவணப்படுத்தி, அதை முறையாகவும், தெளிவாகவும், எந்தவித ஆர்ப்பாட்டமும் இன்றிப் பதிவேட்டில் இடம்பெறச் செய்வதன் மூலம், அந்தத் தருணத்தில் இல்லாவிட்டாலும், நிறுவனத்தின் நினைவகத்தில் அதற்கான காரணம் சரிசெய்யப்படுவதை உறுதி செய்தல்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q24
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q24',
     'A co-founder relationship - one that built this company alongside you for nine years - has quietly broken down. You disagree fundamentally on where the company needs to go. The board knows. The leadership team senses it. Publicly the company is performing well. Privately the relationship is over in everything except title.Before you sit down for what may be the final conversation - what is actually happening inside you?', 'How will you handle conflict?', 'ஒன்பது ஆண்டுகளாக உங்களுடன் இணைந்து இந்த நிறுவனத்தை உருவாக்கிய இணை நிறுவனர் உறவு, யாருக்கும் தெரியாமல் முறிந்துவிட்டது. நிறுவனம் செல்ல வேண்டிய பாதை குறித்து உங்களிடையே அடிப்படை கருத்து வேறுபாடு உள்ளது. நிர்வாகக் குழுவுக்கு அது தெரியும். தலைமைக் குழுவும் அதை உணர்கிறது. வெளிப்படையாக, நிறுவனம் சிறப்பாகச் செயல்படுகிறது. தனிப்பட்ட முறையில், பெயரளவைத் தவிர மற்ற எல்லாவற்றிலும் அந்த உறவு முடிந்துவிட்டது. ஒருவேளை இதுவே இறுதி உரையாடலாக இருக்கலாம், அதற்காக நீங்கள் அமர்வதற்கு முன் - உங்களுக்குள் உண்மையில் என்னதான் நடக்கிறது?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Executive Peer Dynamics", "layer": "Layer 3", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel ready. The clarity of knowing this has run its course is uncomfortable but real - and you would rather end it with honesty than extend it with performance.', 'நீங்கள் தயாராக உணர்கிறீர்கள். இது அதன் போக்கை நிறைவு செய்துவிட்டது என்ற தெளிவு சங்கடமானது, ஆனால் உண்மையானது - மேலும் நடிப்பால் அதை நீட்டிப்பதை விட, நேர்மையுடன் அதை முடிப்பதையே நீங்கள் விரும்புவீர்கள்.', 'D'),
  (2, 'You feel the weight of how this will be read - by the board, by the team, by the market - and the awareness that the story of how this ends will follow both of you for a long time.', 'இதை நிர்வாகக் குழு, அணி, சந்தை ஆகியவை எப்படிப் பார்க்கும் என்பதன் பாரத்தையும், இது எப்படி முடியும் என்ற கதை நீண்ட காலத்திற்கு உங்கள் இருவரையும் பின்தொடரும் என்ற விழிப்புணர்வையும் நீங்கள் உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the grief of nine years. The early days, the hard years, the moments that only the two of you remember. Whatever comes next, this is a loss - and you are sitting with that before you walk into the room.', 'ஒன்பது வருடங்களின் துயரத்தை நீங்கள் உணர்கிறீர்கள். ஆரம்ப நாட்கள், கடினமான ஆண்டுகள், உங்கள் இருவருக்கும் மட்டுமே நினைவில் இருக்கும் தருணங்கள். அடுத்து என்ன வந்தாலும், இது ஒரு இழப்பு - அறைக்குள் நுழைவதற்கு முன்பே நீங்கள் அதனுடன்தான் இருக்கிறீர்கள்.', 'S'),
  (4, 'You feel the need to be precise about what you actually disagree on - whether it is strategy, values, operating model, or something more personal - because the conversation you are about to have needs to be grounded in what is real, not what has accumulated.', 'உத்தி, விழுமியங்கள், செயல்பாட்டு மாதிரி அல்லது இன்னும் தனிப்பட்ட விஷயம் என எதுவாக இருந்தாலும், நீங்கள் உண்மையில் எதில் உடன்படவில்லை என்பதைத் துல்லியமாகக் கூற வேண்டிய அவசியத்தை உணர்கிறீர்கள். ஏனெனில், நீங்கள் நடத்தவிருக்கும் உரையாடல், காலப்போக்கில் சேர்ந்த விஷயங்களின் அடிப்படையில் அல்லாமல், உண்மையான விஷயங்களின் அடிப்படையில் அமைய வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q25
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q25',
     'You are recruiting for a Chief Revenue Officer - the most critical hire of your company''s current growth phase. After a four-month search, your preferred candidate has accepted verbally. Three days before the formal offer, your CHRO tells you she has uncovered a pattern from the candidate''s previous role - aggressive sales culture, two harassment complaints that were settled, no formal finding. Nothing disqualifying on paper. Everything uncomfortable in reality.', 'How will you handle this?', 'உங்கள் நிறுவனத்தின் தற்போதைய வளர்ச்சிக் கட்டத்தின் மிக முக்கியமான பணியான தலைமை வருவாய் அதிகாரி பதவிக்கு நீங்கள் ஆள்சேர்ப்பு செய்கிறீர்கள். நான்கு மாதத் தேடலுக்குப் பிறகு, நீங்கள் விரும்பிய வேட்பாளர் வாய்மொழியாக ஒப்புக்கொண்டுள்ளார். முறைப்படியான பணி நியமன ஆணை வழங்குவதற்கு மூன்று நாட்களுக்கு முன்பு, அந்த வேட்பாளரின் முந்தைய பணியிலிருந்து ஒரு குறிப்பிட்ட போக்கைக் கண்டறிந்ததாக உங்கள் தலைமை வருவாய் அதிகாரி உங்களிடம் கூறுகிறார் - ஆக்ரோஷமான விற்பனைக் கலாச்சாரம், தீர்க்கப்பட்ட இரண்டு துன்புறுத்தல் புகார்கள், ஆனால் முறைப்படியான எந்தக் குற்றச்சாட்டும் இல்லை. எழுத்துப்பூர்வமாக தகுதியிழப்புக்குரிய எதுவும் இல்லை. ஆனால் உண்மையில், அனைத்தும் சங்கடமானவையாகவே இருந்தன.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 1", "dimension": "decision_speed", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You withdraw the offer. The pattern is enough - a CRO who carries that history into your sales organisation creates a risk you are not willing to take regardless of the commercial capability.', 'நீங்கள் அந்தச் சலுகையைத் திரும்பப் பெற்றுக்கொள்கிறீர்கள். அந்தப் போக்கே போதுமானது - அந்தப் பின்னணியை உங்கள் விற்பனை அமைப்புக்குள் கொண்டுவரும் ஒரு CRO, அவரது வணிகத் திறனைப் பொருட்படுத்தாமல் நீங்கள் ஏற்க விரும்பாத ஓர் அபாயத்தை உருவாக்குகிறார்.', 'D'),
  (2, 'You have a direct conversation with the candidate - present what you have found, give him the opportunity to respond, and make your decision based on the quality and honesty of that conversation.', 'வேட்பாளருடன் நேரடியாக உரையாடுங்கள் - நீங்கள் கண்டறிந்தவற்றை முன்வைத்து, பதிலளிக்க அவருக்கு வாய்ப்பளித்து, அந்த உரையாடலின் தரம் மற்றும் நேர்மையின் அடிப்படையில் உங்கள் முடிவை எடுங்கள்.', 'I'),
  (3, 'You slow down the process - delay the formal offer, extend the reference process, and give yourself more time before making a decision that is both commercially significant and reputationally consequential.', 'நீங்கள் செயல்முறையை மெதுவாக்குகிறீர்கள் - முறையான பணி வாய்ப்பைத் தாமதப்படுத்தி, பரிந்துரை செயல்முறையை நீட்டித்து, வணிக ரீதியாகவும் நற்பெயருக்கு முக்கியத்துவம் வாய்ந்ததாகவும் இருக்கும் ஒரு முடிவை எடுப்பதற்கு முன் உங்களுக்கு அதிக நேரத்தை வழங்குகிறீர்கள்.', 'S'),
  (4, 'You commission a thorough background and reference review - speak directly to people who worked with him at the time - and make your decision based on the fullest possible picture of what actually happened.', 'நீங்கள் ஒரு முழுமையான பின்னணி மற்றும் பரிந்துரை மதிப்பாய்வை மேற்கொள்ளுங்கள் - அந்த நேரத்தில் அவருடன் பணிபுரிந்தவர்களிடம் நேரடியாகப் பேசுங்கள் - மேலும் உண்மையில் என்ன நடந்தது என்பது பற்றிய முடிந்தவரை முழுமையான சித்திரத்தின் அடிப்படையில் உங்கள் முடிவை எடுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q26
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q26',
     'Your board has identified an external candidate for the Chief Strategy Officer role - someone with a strong external profile, significant consulting pedigree, and board-level relationships. You have an internal candidate who has been doing the role in an acting capacity for eight months and has performed exceptionally. The board''s preference is clear. Yours is not.', 'How will you handle this?', 'உங்கள் நிர்வாகக் குழு, தலைமை வியூக அதிகாரி பதவிக்கு ஒரு வெளி வேட்பாளரை அடையாளம் கண்டுள்ளது - அவர் வலுவான வெளித் தொடர்புகளையும், குறிப்பிடத்தக்க ஆலோசனைப் பின்னணியையும், நிர்வாகக் குழு மட்டத்திலான தொடர்புகளையும் கொண்டவராக இருக்க வேண்டும். உங்களிடம், கடந்த எட்டு மாதங்களாகத் தற்காலிகப் பொறுப்பில் அப்பொறுப்பை வகித்து, மிகச் சிறப்பாகச் செயல்பட்ட ஒரு உள் வேட்பாளர் இருக்கிறார். நிர்வாகக் குழுவின் விருப்பம் தெளிவாக உள்ளது. உங்களுடையது அவ்வாறு இல்லை.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 1", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You make the case for your internal candidate directly to the board - with data, with specifics, and with the clarity that this is your recommendation and your accountability - and you will not defer to board preference without a fight.', 'உங்கள் உள்ளக வேட்பாளருக்கான வாதத்தை, தரவுகளுடனும், குறிப்பிட்ட விவரங்களுடனும், இது உங்கள் பரிந்துரை மற்றும் உங்கள் பொறுப்பு என்ற தெளிவுடனும் நேரடியாக இயக்குநர்கள் குழுவிடம் முன்வைக்க வேண்டும்; மேலும், ஒரு போராட்டமின்றி இயக்குநர்கள் குழுவின் விருப்பத்திற்கு நீங்கள் அடிபணிய மாட்டீர்கள்.', 'D'),
  (2, 'You facilitate a process where both candidates present to the board, let your internal candidate demonstrate her capability in the room, and allow the quality of that performance to shift the board''s preference without requiring a confrontation.', 'இரு வேட்பாளர்களும் குழுவின் முன் தங்கள் திறமைகளை வெளிப்படுத்தவும், உங்கள் நிறுவனத்தின் வேட்பாளர் அந்த அறையில் தனது திறமையை நிரூபிக்கவும், மேலும் எந்தவொரு மோதலும் தேவைப்படாமல், அந்தச் செயல்பாட்டின் தரம் குழுவின் விருப்பத்தை மாற்றவும் வழிவகுக்கும் ஒரு செயல்முறையை நீங்கள் எளிதாக்குகிறீர்கள்.', 'I'),
  (3, 'You protect your internal candidate''s relationship with the organisation regardless of the outcome - if the external hire proceeds, you will find a way to retain and develop her so the decision does not cost you a leader you have built.', 'முடிவு எப்படி இருந்தாலும், உங்கள் உள்ளகப் பணியாளருக்கும் நிறுவனத்திற்கும் இடையிலான உறவை நீங்கள் பாதுகாக்கிறீர்கள் - வெளிநபரை நியமிக்கும் பணி தொடர்ந்தால், நீங்கள் உருவாக்கிய ஒரு தலைவரை அந்த முடிவு உங்களுக்கு இழக்கச் செய்யாத வகையில், அவரைத் தக்கவைத்து மேம்படுத்துவதற்கான ஒரு வழியைக் கண்டுபிடிப்பீர்கள்.', 'S'),
  (4, 'You request that both candidates be assessed against a structured set of role requirements by an independent evaluator - removing the weight of board preference and personal advocacy from a decision that should be made on merit.', 'தகுதியின் அடிப்படையில் எடுக்கப்பட வேண்டிய ஒரு முடிவிலிருந்து, குழுவின் விருப்பம் மற்றும் தனிப்பட்ட பரிந்துரையின் செல்வாக்கை நீக்கி, இரு வேட்பாளர்களையும் ஒரு சுயாதீன மதிப்பீட்டாளரால், கட்டமைக்கப்பட்ட பணித் தேவைகளின் தொகுப்பின் அடிப்படையில் மதிப்பிட வேண்டும் என்று நீங்கள் கோருகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q27
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q27',
     'You are preparing your own succession and have identified two potential internal candidates. One is ready now but has a ceiling - he will be a competent CEO but not a transformational one. The other has the potential to be exceptional but needs two more years of development. The board wants a succession decision within six months.Two things are pulling at you. Which is stronger - the organisational need for a clear, credible successor who can be announced and prepared within the board''s timeline, or your conviction that waiting two more years for the right leader is worth the uncertainty and board pressure that comes with it?', 'How to choose your successor?', 'நீங்கள் உங்கள் வாரிசு நியமனத்திற்குத் தயாராகி வருகிறீர்கள், மேலும் நிறுவனத்திற்குள்ளேயே இரண்டு சாத்தியமான வேட்பாளர்களை அடையாளம் கண்டுள்ளீர்கள். ஒருவர் இப்போது தயாராக இருக்கிறார், ஆனால் அவருக்கு ஒரு வரம்பு உண்டு - அவர் ஒரு திறமையான தலைமை நிர்வாக அதிகாரியாக இருப்பார், ஆனால் ஒரு மாற்றத்தை ஏற்படுத்தக்கூடியவராக இருக்க மாட்டார். மற்றவருக்கு விதிவிலக்காகச் செயல்படும் ஆற்றல் உள்ளது, ஆனால் அவருக்கு இன்னும் இரண்டு வருட வளர்ச்சி தேவைப்படுகிறது. வாரியம் ஆறு மாதங்களுக்குள் வாரிசு நியமனம் குறித்த முடிவை எதிர்பார்க்கிறது. இரண்டு விஷயங்கள் உங்களை உந்துகின்றன. எது வலிமையானது - வாரியத்தின் காலக்கெடுவுக்குள் அறிவிக்கப்பட்டுத் தயாராகக்கூடிய, தெளிவான, நம்பகமான ஒரு வாரிசுக்கான நிறுவனத்தின் தேவையா, அல்லது சரியான தலைவருக்காக இன்னும் இரண்டு ஆண்டுகள் காத்திருப்பது, அதனுடன் வரும் நிச்சயமற்ற தன்மை மற்றும் வாரியத்தின் அழுத்தத்திற்கு ஈடானது என்ற உங்கள் உறுதியான நம்பிக்கையா?', 'உங்கள் வாரிசை எவ்வாறு தேர்ந்தெடுப்பது?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 2", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Wait for the right leader. A competent CEO in a role that demands transformation is not a safe choice - it is a slow failure. You will push back on the board''s timeline.', 'சரியான தலைவருக்காகக் காத்திருங்கள். மாற்றத்தைக் கோரும் ஒரு பொறுப்பில் திறமையான தலைமைச் செயல் அதிகாரி இருப்பது ஒரு பாதுகாப்பான தேர்வு அல்ல - அது ஒரு மெதுவான தோல்வி. நீங்கள் இயக்குநர் குழுவின் கால அட்டவணையைப் பின்னுக்குத் தள்ளுவீர்கள்.', 'D'),
  (2, 'Develop the timeline together with the board. You will not present a binary - you will build a development plan for the stronger candidate and present a credible 24-month path that gives the board the certainty they need.', 'வாரியத்துடன் இணைந்து கால அட்டவணையை உருவாக்குங்கள். நீங்கள் இருநிலைத் தேர்வை முன்வைக்க மாட்டீர்கள் - மாறாக, வலிமையான வேட்பாளருக்கான ஒரு வளர்ச்சித் திட்டத்தை உருவாக்கி, வாரியத்திற்குத் தேவையான உறுதியை அளிக்கும் நம்பகமான 24 மாத காலப் பாதையை முன்வைப்பீர்கள்.', 'I'),
  (3, 'Announce the credible successor now. The organisation needs the stability of a clear succession decision and you can create development opportunities for the stronger candidate in parallel - they are not mutually exclusive.', 'நம்பகமான வாரிசை இப்போதே அறிவிக்கவும். நிறுவனத்திற்கு ஒரு தெளிவான வாரிசு முடிவின் ஸ்திரத்தன்மை தேவைப்படுகிறது, மேலும் நீங்கள் திறமையான வேட்பாளருக்கு இணையாக வளர்ச்சி வாய்ப்புகளையும் உருவாக்கலாம் - இவை இரண்டும் ஒன்றுக்கொன்று முரண்பட்டவை அல்ல.', 'S'),
  (4, 'Commission an independent succession readiness assessment for both candidates - your read of their relative readiness is informed but not unbiased, and a decision of this consequence deserves external validation.', 'இரு வேட்பாளர்களுக்கும் ஒரு சுயாதீனமான வாரிசுரிமைத் தயார்நிலை மதிப்பீட்டை மேற்கொள்ளுங்கள் - அவர்களின் சார்புநிலைத் தயார்நிலை குறித்த உங்கள் கணிப்பு தகவலறிந்ததாக இருந்தாலும், அது பாரபட்சமற்றது அல்ல, மேலும் இத்தகைய முக்கியத்துவம் வாய்ந்த ஒரு முடிவு புறச் சரிபார்ப்புக்குத் தகுதியானது.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q28
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q28',
     'A leader you hired two years ago with significant fanfare - a high-profile external appointment with a strong track record - has not delivered. The cultural fit was wrong from the start. The team has not respected him. The results have been poor. You defended him to the board twice. Now you are preparing to let him go.What is actually happening inside you before you have that conversation?', 'What is happening inside you?', 'இரண்டு ஆண்டுகளுக்கு முன்பு, பெரும் ஆரவாரத்துடன் நீங்கள் பணியமர்த்திய ஒரு தலைவர் - வலுவான சாதனைப் பதிவைக் கொண்ட ஒரு முக்கிய வெளிநபர் - தனது கடமையைச் சரிவரச் செய்யவில்லை. ஆரம்பத்திலிருந்தே நிறுவனத்தின் கலாச்சாரத்துடன் அவர் பொருந்தவில்லை. குழுவினர் அவரை மதிக்கவில்லை. முடிவுகள் மோசமாக இருந்தன. நீங்கள் இரண்டு முறை நிர்வாகக் குழுவிடம் அவருக்காகப் பரிந்து பேசினீர்கள். இப்போது அவரைப் பதவியிலிருந்து நீக்கத் தயாராகிறீர்கள். அந்த உரையாடலைத் தொடங்குவதற்கு முன்பு, உண்மையில் உங்களுக்குள் என்னதான் நடக்கிறது?', 'உங்களுக்குள் என்ன நடக்கிறது?',
     '{"theme": "Talent Acquisition and Succession", "layer": "Layer 3", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the clarity of a decision that is overdue - you held on too long, you know why, and the cleanest thing you can do now is end it with directness and dignity.', 'காலம் கடந்த ஒரு முடிவின் தெளிவை நீங்கள் உணர்கிறீர்கள் - நீங்கள் நீண்ட காலம் தாமதித்தீர்கள், அதற்கான காரணம் உங்களுக்குத் தெரியும், இப்போது நீங்கள் செய்யக்கூடிய மிகத் தெளிவான காரியம், அதை நேரடியாகவும் கண்ணியமாகவும் முடிவுக்குக் கொண்டுவருவதுதான்.', 'D'),
  (2, 'You feel the exposure. You championed this hire. You defended it twice. And now you are walking into a conversation that will be read as a judgment on your own hiring judgment as much as his performance.', 'நீங்கள் அம்பலப்படுத்தப்படுவதை உணர்கிறீர்கள். இந்த நியமனத்தை நீங்கள் ஆதரித்தீர்கள். இரண்டு முறை அதை நியாயப்படுத்தினீர்கள். ஆனால் இப்போது, ​​அவருடைய செயல்திறனைப் போலவே, உங்கள் சொந்த நியமன முடிவின் மீதான ஒரு விமர்சனமாகவும் பார்க்கப்படும் ஒரு உரையாடலுக்குள் நீங்கள் நுழைகிறீர்கள்.', 'I'),
  (3, 'You feel something close to guilt. Not for making the decision - for the two years he spent in a role that was wrong for him, in a culture that did not receive him, partly because you did not intervene sooner.', 'நீங்கள் குற்ற உணர்ச்சிக்கு நெருக்கமான ஒன்றை உணர்கிறீர்கள். அந்த முடிவை எடுத்ததற்காக அல்ல - மாறாக, உங்களுக்கு முன்னதாகவே நீங்கள் தலையிடாத காரணத்தால், தனக்குப் பொருந்தாத ஒரு பணியிலும், தன்னை ஏற்றுக்கொள்ளாத ஒரு கலாச்சாரத்திலும் அவர் கழித்த அந்த இரண்டு ஆண்டுகளுக்காக.', 'S'),
  (4, 'You feel the need to be precise in the conversation - clear about what has not worked, fair about what he did deliver, and careful to ensure that the process from here is legally sound and professionally handled.', 'உரையாடலில் நீங்கள் துல்லியமாக இருக்க வேண்டியதன் அவசியத்தை உணர்கிறீர்கள் - அதாவது, எது பலனளிக்கவில்லை என்பதில் தெளிவாகவும், அவர் வழங்கியவற்றில் நியாயமாகவும் இருப்பதுடன், இனிவரும் செயல்முறை சட்டப்பூர்வமாகவும் தொழில்முறையாகவும் கையாளப்படுவதை உறுதி செய்வதில் கவனமாகவும் இருக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q29
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q29',
     'You are the managing director of an energy company pursuing environmental clearances for a renewable project. A local community leader - influential, respected, and with genuine concerns about land use - is organising opposition. Your project timeline cannot absorb a six-month delay. Your government relations team recommends bypassing community engagement and working directly through state-level approvals.', 'How will you handle opposition?', 'நீங்கள் ஒரு புதுப்பிக்கத்தக்க எரிசக்தித் திட்டத்திற்கான சுற்றுச்சூழல் அனுமதிகளைப் பெற முயலும் ஒரு எரிசக்தி நிறுவனத்தின் நிர்வாக இயக்குநர். செல்வாக்கு மிக்கவரும், மதிக்கப்படுபவரும், நிலப் பயன்பாடு குறித்து உண்மையான அக்கறை கொண்டவருமான ஒரு உள்ளூர் சமூகத் தலைவர், இதற்கு எதிர்ப்புத் தெரிவிக்கிறார். உங்கள் திட்டக் கால அட்டவணையால் ஆறு மாத கால தாமதத்தைத் தாங்க முடியாது. உங்கள் அரசாங்க உறவுகள் குழு, சமூக ஈடுபாட்டைத் தவிர்த்துவிட்டு, நேரடியாக மாநில அளவிலான ஒப்புதல்களைப் பெறுமாறு பரிந்துரைக்கிறது.', 'எதிர்ப்பை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 1", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You reject the bypass recommendation, request a personal meeting with the community leader, and invest whatever time is needed to address the concerns directly - a project built over community opposition is a project with a permanent vulnerability.', 'நீங்கள் மாற்றுப்பாதை பரிந்துரையை நிராகரித்து, சமூகத் தலைவருடன் ஒரு தனிப்பட்ட சந்திப்பைக் கோரி, கவலைகளை நேரடியாக நிவர்த்தி செய்யத் தேவையான நேரத்தை ஒதுக்கினால் - சமூக எதிர்ப்பின் மீது கட்டப்படும் ஒரு திட்டம், நிரந்தரமான பாதிப்புக்குள்ளாகும் தன்மையைக் கொண்ட ஒரு திட்டமாகும்.', 'D'),
  (2, 'You engage a respected local NGO as an intermediary, build the community engagement through trusted relationships rather than direct corporate contact, and work the problem through people the community already trusts.', 'நீங்கள் மதிக்கப்படும் ஒரு உள்ளூர் தன்னார்வ தொண்டு நிறுவனத்தை இடைத்தரகராக ஈடுபடுத்தி, நேரடி பெருநிறுவனத் தொடர்புக்குப் பதிலாக நம்பகமான உறவுகள் மூலம் சமூக ஈடுபாட்டை வளர்த்து, சமூகம் ஏற்கனவே நம்பும் நபர்கள் மூலம் அந்தப் பிரச்சினைக்குத் தீர்வு காண்கிறீர்கள்.', 'I'),
  (3, 'You slow the project timeline, create a genuine consultation process, and accept the delay as the cost of building a foundation that does not carry ongoing resistance into the operational phase.', 'திட்டத்தின் கால அளவை மெதுவாக்கி, ஒரு உண்மையான கலந்தாய்வு செயல்முறையை உருவாக்கி, செயல்பாட்டுக் கட்டத்திற்குள் தொடர்ச்சியான எதிர்ப்பைக் கொண்டு செல்லாத ஒரு அடித்தளத்தை அமைப்பதற்கான விலையாக அந்தத் தாமதத்தை ஏற்றுக்கொள்கிறீர்கள்.', 'S'),
  (4, 'You commission an independent community impact assessment, present it publicly, and build your engagement around evidence rather than assurance - give the community leader something he can evaluate rather than something he must trust.', 'நீங்கள் ஒரு சுயாதீனமான சமூக தாக்க மதிப்பீட்டை மேற்கொள்ளுங்கள், அதை பொதுவில் சமர்ப்பியுங்கள், மேலும் உறுதிமொழியை விட ஆதாரங்களை அடிப்படையாகக் கொண்டு உங்கள் ஈடுபாட்டை உருவாக்குங்கள் - சமூகத் தலைவர் கட்டாயம் நம்ப வேண்டிய ஒன்றை அவருக்குக் கொடுப்பதற்குப் பதிலாக, அவர் மதிப்பீடு செய்யக்கூடிய ஒன்றை அவருக்குக் கொடுங்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q30
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q30',
     'You are leading a large retail conglomerate. A new regulation requires you to source 30% of your private label products from small and medium enterprises within 18 months. The operational complexity is significant. Your supply chain head says the timeline is unachievable without compromising quality. A trade industry body is organising pushback. You must decide your position.', 'How will you handle regulation?', 'நீங்கள் ஒரு பெரிய சில்லறை வர்த்தகக் குழுமத்தை வழிநடத்துகிறீர்கள். ஒரு புதிய விதிமுறையின்படி, 18 மாதங்களுக்குள் உங்கள் சொந்த முத்திரை தயாரிப்புகளில் 30%-ஐ சிறு மற்றும் நடுத்தர நிறுவனங்களிடமிருந்து நீங்கள் பெற வேண்டும். இதன் செயல்பாட்டுச் சிக்கல் குறிப்பிடத்தக்கது. தரத்தில் சமரசம் செய்யாமல் இந்தக் காலக்கெடுவை அடைவது சாத்தியமில்லை என்று உங்கள் விநியோகச் சங்கிலித் தலைவர் கூறுகிறார். ஒரு வர்த்தகத் துறை அமைப்பு இதற்கு எதிர்ப்புத் தெரிவிக்க ஏற்பாடு செய்து வருகிறது. உங்கள் நிலைப்பாட்டை நீங்கள் தீர்மானிக்க வேண்டும்.', 'ஒழுங்குமுறையை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 1", "dimension": "influence_style", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You publicly support the regulation, commit to the timeline, and use the compliance challenge as a forcing function to build supply chain capabilities that will differentiate you from competitors who are resisting.', 'நீங்கள் அந்த ஒழுங்குமுறையை வெளிப்படையாக ஆதரித்து, காலக்கெடுவிற்கு உறுதியளித்து, அதை எதிர்க்கும் போட்டியாளர்களிடமிருந்து உங்களை வேறுபடுத்திக் காட்டும் விநியோகச் சங்கிலித் திறன்களைக் கட்டமைப்பதற்கு, இந்த இணக்கச் சவாலை ஒரு உந்து சக்தியாகப் பயன்படுத்துகிறீர்கள்.', 'D'),
  (2, 'You engage the ministry directly at a senior level, present a credible alternative timeline with evidence, and work to negotiate a phased implementation that your supply chain can actually deliver.', 'நீங்கள் அமைச்சகத்துடன் நேரடியாக உயர் மட்டத்தில் தொடர்புகொண்டு, ஆதாரங்களுடன் கூடிய நம்பகமான மாற்று கால அட்டவணையை முன்வைத்து, உங்கள் விநியோகச் சங்கிலியால் உண்மையில் வழங்கக்கூடிய ஒரு கட்டம் கட்டமான செயலாக்கத்தைப் பேச்சுவார்த்தை மூலம் அடையப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You join the industry body''s engagement with the government, work collectively to present the operational realities, and use the collective weight of the sector to shape a more workable regulation rather than acting alone.', 'நீங்கள் தனியாகச் செயல்படுவதற்குப் பதிலாக, அரசாங்கத்துடனான தொழில் அமைப்பின் ஈடுபாட்டில் இணைந்து, செயல்பாட்டு யதார்த்தங்களை முன்வைக்கக் கூட்டாகப் பணியாற்றி, மேலும் நடைமுறைக்கு உகந்த ஒரு ஒழுங்குமுறையை வடிவமைக்கத் துறையின் கூட்டு பலத்தைப் பயன்படுத்துகிறீர்கள்.', 'S'),
  (4, 'You commission a detailed supply chain feasibility study, present it to the ministry with specific milestones and quality safeguards, and make your case for a modified timeline on the basis of evidence rather than resistance.', 'நீங்கள் ஒரு விரிவான விநியோகச் சங்கிலி சாத்தியக்கூறு ஆய்வை மேற்கொள்ளப் பணித்து, குறிப்பிட்ட மைல்கற்கள் மற்றும் தரப் பாதுகாப்பு அம்சங்களுடன் அதை அமைச்சகத்திடம் சமர்ப்பித்து, எதிர்ப்பின் அடிப்படையில் அல்லாமல் ஆதாரங்களின் அடிப்படையில் திருத்தப்பட்ட கால அட்டவணைக்கான உங்கள் கோரிக்கையை முன்வைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q31
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q31',
     'A global investor has made it a condition of their next funding tranche that you publish a detailed ESG report including supply chain labour practices. Your supply chain includes third-party vendors in regions where labour standards are inconsistent. A thorough audit will surface findings that are uncomfortable. A surface-level report will satisfy the investor but not withstand scrutiny.What matters more to you in this moment - the funding tranche that your company needs and the investor relationship that comes with surface-level compliance, or the integrity of publishing a report that reflects what is actually happening in your supply chain even if it creates short-term reputational exposure?', 'How will you handle this?', 'ஒரு உலகளாவிய முதலீட்டாளர், தங்களின் அடுத்தகட்ட நிதியுதவிக்கு, விநியோகச் சங்கிலி தொழிலாளர் நடைமுறைகள் உட்பட ஒரு விரிவான ESG அறிக்கையை நீங்கள் வெளியிட வேண்டும் என்பதை ஒரு நிபந்தனையாக விதித்துள்ளார். உங்கள் விநியோகச் சங்கிலியில், தொழிலாளர் தரநிலைகள் சீரற்றதாக உள்ள பிராந்தியங்களில் மூன்றாம் தரப்பு விற்பனையாளர்கள் உள்ளனர். ஒரு முழுமையான தணிக்கை, சங்கடமான கண்டுபிடிப்புகளை வெளிக்கொணரும். ஒரு மேலோட்டமான அறிக்கை முதலீட்டாளரைத் திருப்திப்படுத்தும், ஆனால் அது உன்னிப்பான ஆய்வுக்கு ஈடுகொடுக்காது. இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - உங்கள் நிறுவனத்திற்குத் தேவையான நிதியுதவியும், மேலோட்டமான இணக்கத்தால் கிடைக்கும் முதலீட்டாளர் உறவும், அல்லது குறுகிய கால நற்பெயருக்கு பாதிப்பை ஏற்படுத்தினாலும், உங்கள் விநியோகச் சங்கிலியில் உண்மையில் என்ன நடக்கிறது என்பதைப் பிரதிபலிக்கும் ஒரு அறிக்கையை வெளியிடுவதன் நேர்மையுமா?', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 2", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'Integrity. A surface-level ESG report is a liability waiting to surface. You will publish what is true, present a credible remediation plan, and let that be the basis of the investor relationship.', 'நேர்மை. மேலோட்டமான ESG அறிக்கை என்பது, வெளிப்படக் காத்திருக்கும் ஒரு பொறுப்புப் பற்றாக்குறையாகும். நீங்கள் உண்மையை வெளியிடுவீர்கள், நம்பகமான ஒரு சரிசெய்தல் திட்டத்தை முன்வைப்பீர்கள், மேலும் அதையே முதலீட்டாளர் உறவின் அடிப்படையாகக் கொள்ள வேண்டும்.', 'D'),
  (2, 'The relationship. You will engage the investor directly, share what the audit is likely to surface, and build the ESG disclosure as a joint exercise in transparency rather than a compliance deliverable - investors who are partners in this are more valuable than investors who are gatekeepers.', 'உறவுமுறை. நீங்கள் முதலீட்டாளருடன் நேரடியாக ஈடுபடுவீர்கள், தணிக்கையில் என்னென்ன வெளிவர வாய்ப்புள்ளது என்பதைப் பகிர்ந்துகொள்வீர்கள், மேலும் ESG வெளிப்படுத்தலை ஒரு இணக்க வெளியீடாகக் கருதாமல், வெளிப்படைத்தன்மைக்கான ஒரு கூட்டு முயற்சியாக உருவாக்குவீர்கள் - இதில் பங்காளர்களாக இருக்கும் முதலீட்டாளர்கள், தணிக்கையாளர்களாகச் செயல்படும் முதலீட்டாளர்களை விட அதிக மதிப்புமிக்கவர்கள்.', 'I'),
  (3, 'The funding. You will produce a report that meets the investor''s stated requirements, use the capital to stabilise the business, and build toward a more comprehensive ESG programme once you have the runway to do it properly.', 'நிதி திரட்டல். முதலீட்டாளர் குறிப்பிட்ட தேவைகளைப் பூர்த்தி செய்யும் ஒரு அறிக்கையை நீங்கள் தயாரிப்பீர்கள், வணிகத்தை நிலைப்படுத்த அந்த மூலதனத்தைப் பயன்படுத்துவீர்கள், மேலும் அதை முறையாகச் செயல்படுத்துவதற்கான நிதி ஆதாரம் கிடைத்தவுடன், ஒரு விரிவான ESG திட்டத்தை நோக்கி கட்டமைப்பீர்கள்.', 'S'),
  (4, 'The audit. You will not make a decision about what to publish before you know what the audit actually finds - the scope of the problem will determine the scope of the disclosure.', 'தணிக்கை. தணிக்கை உண்மையில் என்ன கண்டறிகிறது என்பதை நீங்கள் அறியும் வரை, எதை வெளியிடுவது என்பது குறித்து நீங்கள் முடிவெடுக்க மாட்டீர்கள் - சிக்கலின் வீச்சே வெளியிடப்பட வேண்டிய தகவலின் வீச்சைத் தீர்மானிக்கும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q32
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q32',
     'You are negotiating a joint venture with a strategic partner whose majority shareholder has political connections you find ethically uncomfortable. The JV itself is commercially sound. Your legal team sees no compliance issue. Your board supports it. But something about the relationship feels wrong to you personally.Before you sign - what is actually happening inside you?', 'How will you handle conflict?', 'நீங்கள் ஒரு மூலோபாய கூட்டாளருடன் ஒரு கூட்டு முயற்சி குறித்து பேச்சுவார்த்தை நடத்துகிறீர்கள்; அதன் பெரும்பான்மை பங்குதாரருக்கு, உங்களுக்கு அறநெறி ரீதியாக சங்கடமான அரசியல் தொடர்புகள் உள்ளன. அந்தக் கூட்டு முயற்சி வணிக ரீதியாக வலுவானது. உங்கள் சட்டக் குழு அதில் எந்த இணக்கப் பிரச்சினையையும் காணவில்லை. உங்கள் நிர்வாகக் குழு அதை ஆதரிக்கிறது. ஆனால், தனிப்பட்ட முறையில் அந்த உறவில் ஏதோ சரியில்லை என்று உங்களுக்குத் தோன்றுகிறது. நீங்கள் கையெழுத்திடுவதற்கு முன் - உண்மையில் உங்கள் உள்ளுக்குள் என்ன நடக்கிறது?', 'மோதலை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Stakeholder and Political Navigation", "layer": "Layer 3", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the tension between your personal discomfort and your fiduciary responsibility - and the awareness that your discomfort, if it is not grounded in a specific violation, may not be a sufficient reason to walk away from a decision the board has sanctioned.', 'உங்கள் தனிப்பட்ட அசௌகரியத்திற்கும் நம்பிக்கைப் பொறுப்பிற்கும் இடையிலான பதற்றத்தை நீங்கள் உணர்கிறீர்கள் - மேலும், உங்கள் அசௌகரியம் ஒரு குறிப்பிட்ட மீறலை அடிப்படையாகக் கொண்டிருக்கவில்லை என்றால், வாரியம் அங்கீகரித்த ஒரு முடிவிலிருந்து விலகிச் செல்வதற்கு அது போதுமான காரணமாக இருக்காது என்ற விழிப்புணர்வும் உங்களுக்கு ஏற்படுகிறது.', 'D'),
  (2, 'You feel the reputational exposure - not just today but over the life of the JV - and the awareness that partnerships are defined not just by their legal structure but by the company they keep and what that signals to the market.', 'இன்று மட்டுமல்ல, கூட்டு முயற்சியின் வாழ்நாள் முழுவதும் அதன் நற்பெயர் பாதிப்பு அபாயத்தை நீங்கள் உணர்கிறீர்கள். மேலும், கூட்டாண்மைகள் அவற்றின் சட்டக் கட்டமைப்பால் மட்டுமல்ல, அவை கொண்டுள்ள தொடர்புகளாலும், அது சந்தைக்கு உணர்த்தும் செய்திகளாலும் வரையறுக்கப்படுகின்றன என்ற விழிப்புணர்வும் உங்களுக்கு ஏற்படுகிறது.', 'I'),
  (3, 'You feel the discomfort of proceeding with something that does not sit right - and the recognition that the feeling itself is data, even if you cannot yet articulate exactly what it is pointing at.', 'சரியெனப் படாத ஒன்றை முன்னெடுத்துச் செல்வதில் உள்ள அசௌகரியத்தை நீங்கள் உணர்கிறீர்கள் - மேலும், அது எதைச் சுட்டிக்காட்டுகிறது என்பதை உங்களால் இன்னும் துல்லியமாக விவரிக்க முடியாவிட்டாலும், அந்த உணர்வே ஒரு தரவு என்ற அங்கீகாரத்தையும் பெறுகிறீர்கள்.', 'S'),
  (4, 'You feel the need to identify precisely what is making you uncomfortable - whether it is a specific relationship, a specific transaction history, or a general unease - before you decide whether it is actionable or whether you are imposing a personal standard that goes beyond what the situation requires.', 'ஒரு குறிப்பிட்ட உறவோ, ஒரு குறிப்பிட்ட பரிவர்த்தனை வரலாறோ, அல்லது ஒரு பொதுவான சங்கடமோ - எது உங்களுக்கு அசௌகரியத்தை ஏற்படுத்துகிறது என்பதைத் துல்லியமாகக் கண்டறிய வேண்டிய அவசியத்தை நீங்கள் உணர்கிறீர்கள்; அதன் பின்னரே அது குறித்து நடவடிக்கை எடுக்கலாமா அல்லது சூழ்நிலைக்குத் தேவைப்படுவதை மீறிய ஒரு தனிப்பட்ட அளவுகோலை நீங்கள் திணிக்கிறீர்களா என்பதை முடிவு செய்ய வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q33
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q33',
     'Your company is in the final stage of a significant merger. During due diligence, your team discovers that the target company has been recognising revenue from contracts that are not yet fully executed. The accounting is aggressive but possibly defensible. Your investment bankers say raising it now could kill the deal. Your CFO says it needs to be addressed before close.', 'How should you address this?', 'உங்கள் நிறுவனம் ஒரு முக்கிய இணைப்பு நடவடிக்கையின் இறுதிக் கட்டத்தில் உள்ளது. உரிய ஆய்வின் போது, ​​இலக்கு நிறுவனம் இன்னும் முழுமையாக நிறைவேற்றப்படாத ஒப்பந்தங்களிலிருந்து வருவாயைக் கணக்கிட்டு வருவதை உங்கள் குழு கண்டறிகிறது. இந்தக் கணக்கியல் முறை தீவிரமானது, ஆனால் நியாயப்படுத்தக்கூடியதாக இருக்கலாம். இதை இப்போது எழுப்பினால் ஒப்பந்தம் முறிந்துவிடும் என்று உங்கள் முதலீட்டு வங்கியாளர்கள் கூறுகிறார்கள். ஒப்பந்தம் நிறைவடைவதற்குள் இதைக் கவனிக்க வேண்டும் என்று உங்கள் தலைமை நிதி அதிகாரி கூறுகிறார்.', 'இதை நீங்கள் எவ்வாறு அணுக வேண்டும்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 1", "dimension": "accuracy_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You raise it immediately - with your board, with the target company''s leadership, and with your legal and audit advisors - you will not close a deal on a financial foundation you have not fully understood and accepted.', 'இதை நீங்கள் உடனடியாக உங்கள் நிர்வாகக் குழுவிடமும், இலக்கு நிறுவனத்தின் தலைமையிடமும், உங்கள் சட்ட மற்றும் தணிக்கை ஆலோசகர்களிடமும் தெரிவிக்க வேண்டும்; இல்லையெனில், நீங்கள் முழுமையாகப் புரிந்துகொண்டு ஏற்றுக்கொள்ளாத ஒரு நிதி அடித்தளத்தின் மீது ஓர் ஒப்பந்தத்தை உங்களால் இறுதி செய்ய முடியாது.', 'D'),
  (2, 'You engage the target company''s CFO directly in a confidential conversation, understand the full picture, and determine whether this is an accounting philosophy difference or something more serious before you escalate.', 'நீங்கள் அடுத்த கட்டத்திற்குச் செல்வதற்கு முன், இலக்கு நிறுவனத்தின் தலைமை நிதி அதிகாரியுடன் (CFO) நேரடியாக ஒரு ரகசிய உரையாடலில் ஈடுபட்டு, முழு நிலவரத்தையும் புரிந்துகொண்டு, இது கணக்கியல் தத்துவத்தில் உள்ள வேறுபாடா அல்லது இதைவிட தீவிரமான ஒன்றா என்பதைத் தீர்மானிக்க வேண்டும்.', 'I'),
  (3, 'You slow the close timeline, create space for a deeper financial review, and do not allow deal momentum to override the due diligence process - the bankers'' timeline is not your obligation.', 'நீங்கள் ஒப்பந்த நிறைவு காலக்கெடுவைத் தாமதப்படுத்தி, ஆழமான நிதி ஆய்வுக்கு இடமளித்து, ஒப்பந்தத்தின் வேகம் உரிய ஆய்வுச் செயல்முறையை மீற அனுமதிக்காதீர்கள் - வங்கியாளர்களின் காலக்கெடுவைக் கடைப்பிடிப்பது உங்கள் கடமையல்ல.', 'S'),
  (4, 'You instruct your CFO and external auditors to produce a precise technical assessment of the revenue recognition practices - what is defensible, what is aggressive, and what the post-close exposure would be under each accounting treatment.', 'வருவாய் அங்கீகார நடைமுறைகள் குறித்த ஒரு துல்லியமான தொழில்நுட்ப மதிப்பீட்டைத் தயாரிக்குமாறு உங்கள் தலைமை நிதி அதிகாரிக்கும் (CFO) வெளித் தணிக்கையாளர்களுக்கும் நீங்கள் அறிவுறுத்துகிறீர்கள் – அதாவது, எது நியாயமானது, எது வரம்பு மீறியது, மற்றும் ஒவ்வொரு கணக்கியல் முறையின் கீழும் கணக்கு முடிக்கப்பட்ட பிறகு ஏற்படக்கூடிய பாதிப்பு என்னவாக இருக்கும் என்பனவற்றை உள்ளடக்க வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q34
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q34',
     'A whistleblower complaint has been filed with your board alleging that your head of procurement has been steering contracts to vendors who provide personal benefits. The complaint includes specific transaction references. Your head of procurement has been with the company for 16 years and has an exceptional track record. You consider him a personal friend.', 'How will you handle misconduct?', 'உங்கள் கொள்முதல் பிரிவுத் தலைவர், தனிப்பட்ட ஆதாயங்களை வழங்கும் விற்பனையாளர்களுக்கு ஒப்பந்தங்களை வழங்கி வருவதாகக் குற்றம் சாட்டி, உங்கள் நிர்வாகக் குழுவிடம் ஒரு முறைகேடு புகார் அளிக்கப்பட்டுள்ளது. அந்தப் புகாரில் குறிப்பிட்ட பரிவர்த்தனைக் குறிப்புகள் அடங்கியுள்ளன. உங்கள் கொள்முதல் பிரிவுத் தலைவர் 16 ஆண்டுகளாக நிறுவனத்தில் பணியாற்றி வருகிறார், மேலும் அவர் ஒரு மிகச்சிறந்த பணிப்பதிவைக் கொண்டவர். நீங்கள் அவரை உங்கள் தனிப்பட்ட நண்பராகக் கருதுகிறீர்கள்.', 'முறைகேட்டை எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 1", "dimension": "accountability_ownership", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You immediately recuse yourself from the investigation given your personal relationship, brief the audit committee chair, and ensure the investigation is led independently with no involvement from you or your direct reports.', 'உங்கள் தனிப்பட்ட உறவின் காரணமாக நீங்கள் உடனடியாக விசாரணையிலிருந்து விலகிக்கொள்வதுடன், தணிக்கைக் குழுத் தலைவருக்கு இதுகுறித்து விளக்கமளித்து, உங்களிடமிருந்தோ அல்லது உங்களுக்குக் கீழ் பணிபுரிபவர்களிடமிருந்தோ எந்தப் பங்களிப்பும் இல்லாமல் விசாரணை சுதந்திரமாக நடத்தப்படுவதை உறுதிசெய்ய வேண்டும்.', 'D'),
  (2, 'You speak to your head of procurement before the formal investigation begins - not to protect him but to hear his account directly, because you believe he deserves to know what has been alleged before the process starts.', 'முறையான விசாரணை தொடங்குவதற்கு முன்பு உங்கள் கொள்முதல் துறைத் தலைவரிடம் நீங்கள் பேசுகிறீர்கள் - அது அவரைப் பாதுகாப்பதற்காக அல்ல, மாறாக அவர் தரப்பை நேரடியாகக் கூறுவதைக் கேட்பதற்காகவே; ஏனெனில், இந்த செயல்முறை தொடங்குவதற்கு முன்பு, சுமத்தப்பட்ட குற்றச்சாட்டுகள் என்ன என்பதை அவர் அறிந்துகொள்ளத் தகுதியானவர் என்று நீங்கள் நம்புகிறீர்கள்.', 'I'),
  (3, 'You ensure the investigation is thorough but managed carefully - you are aware of the personal and reputational damage an investigation causes even when it finds nothing, and you want it conducted with that awareness.', 'விசாரணை முழுமையானதாகவும் அதே சமயம் கவனமாகவும் நிர்வகிக்கப்படுவதை நீங்கள் உறுதி செய்கிறீர்கள் - ஒரு விசாரணையில் எந்த முடிவும் வராவிட்டாலும், அது தனிப்பட்ட மற்றும் நற்பெயருக்கு ஏற்படுத்தக்கூடிய பாதிப்புகளை நீங்கள் அறிந்திருக்கிறீர்கள், மேலும் அந்த விழிப்புணர்வுடனேயே அது நடத்தப்பட வேண்டும் என்றும் விரும்புகிறீர்கள்.', 'S'),
  (4, 'You review the specific transaction references in the complaint yourself before briefing the audit committee - you want to understand the factual basis of the allegation before you set a process in motion that will be difficult to contain.', 'தணிக்கைக் குழுவுக்கு விளக்கமளிப்பதற்கு முன், புகாரில் உள்ள குறிப்பிட்ட பரிவர்த்தனைக் குறிப்புகளை நீங்களே மதிப்பாய்வு செய்யுங்கள் - கட்டுப்படுத்துவதற்கு கடினமாக இருக்கும் ஒரு செயல்முறையைத் தொடங்குவதற்கு முன், அந்தக் குற்றச்சாட்டுகளின் உண்மை நிலையை நீங்கள் புரிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q35
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q35',
     'Your company operates in a market where informal payments to expedite regulatory approvals are an industry norm. You have maintained a zero-tolerance policy. As a result, your approvals consistently take 40% longer than your competitors. A major project is now at risk of missing a contractual deadline that will trigger a 180 crore penalty. Your operations head has told you privately that one payment would resolve the situation within a week.Two things are pulling at you. Which is stronger - the zero-tolerance policy you have built your governance reputation on and the principle that normalising one exception destroys the policy entirely, or the material reality that 180 crores is a consequence your shareholders, your employees, and your board will pay for a principled position?', 'How will you resolve conflict?', 'ஒழுங்குமுறை ஒப்புதல்களை விரைவுபடுத்துவதற்காக முறைசாரா கொடுப்பனவுகள் செய்வது ஒரு தொழில்துறை வழக்கமாக இருக்கும் சந்தையில் உங்கள் நிறுவனம் இயங்குகிறது. நீங்கள் சகிப்புத்தன்மையற்ற கொள்கையைக் கடைப்பிடித்து வருகிறீர்கள். இதன் விளைவாக, உங்கள் போட்டியாளர்களை விட உங்கள் ஒப்புதல்கள் தொடர்ந்து 40% அதிக நேரம் எடுத்துக்கொள்கின்றன. ஒரு பெரிய திட்டம் இப்போது ஒப்பந்தக் காலக்கெடுவைத் தவறவிடும் அபாயத்தில் உள்ளது, இது 180 கோடி அபராதத்தைத் தூண்டும். ஒரு வாரத்திற்குள் ஒரே ஒரு பணம் செலுத்தினால் இந்தச் சிக்கல் தீர்ந்துவிடும் என்று உங்கள் செயல்பாட்டுத் தலைவர் உங்களிடம் தனிப்பட்ட முறையில் கூறியுள்ளார். இரண்டு விஷயங்கள் உங்களை அலைக்கழிக்கின்றன. எது வலிமையானது - உங்கள் நிர்வாகப் புகழை நீங்கள் கட்டியெழுப்பிய சகிப்புத்தன்மையற்ற கொள்கை மற்றும் ஒரு விதிவிலக்கை இயல்பாக்குவது கொள்கையை முற்றிலுமாக அழித்துவிடும் என்ற கோட்பாடா, அல்லது ஒரு கொள்கை நிலைப்பாட்டிற்காக உங்கள் பங்குதாரர்கள், உங்கள் ஊழியர்கள் மற்றும் உங்கள் வாரியம் 180 கோடி ரூபாய் என்ற விளைவைச் செலுத்துவார்கள் என்ற யதார்த்தமா?', 'மோதலை எவ்வாறு தீர்ப்பீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 2", "dimension": "conflict_response", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The principle. The moment you make the first exception, you no longer have a policy - you have a preference. You will find another way or absorb the penalty.', 'கொள்கை. நீங்கள் முதல் விதிவிலக்கை அளிக்கும் கணமே, உங்களிடம் இருப்பது கொள்கை அல்ல - அது ஒரு விருப்பம் மட்டுமே. நீங்கள் வேறு வழியைக் கண்டுபிடிப்பீர்கள் அல்லது அதற்கான தண்டனையை ஏற்றுக்கொள்வீர்கள்.', 'D'),
  (2, 'The escalation. Before you accept the penalty or consider the exception, you will take this to the highest available government channel - ministry level if necessary - and make the delay a formal, visible, documented issue that creates its own pressure on the approving body.', 'நிலைமை தீவிரமடைதல். நீங்கள் அபராதத்தை ஏற்றுக்கொள்வதற்கு அல்லது விதிவிலக்கைப் பரிசீலிப்பதற்கு முன்பு, இதை அரசாங்கத்தின் மிக உயர்ந்த வழிமுறைக்கு - தேவைப்பட்டால் அமைச்சக நிலை வரை - கொண்டு சென்று, இந்தத் தாமதத்தை ஒப்புதல் அளிக்கும் அமைப்பின் மீது தானாகவே அழுத்தத்தை உருவாக்கும் ஒரு முறையான, வெளிப்படையான, ஆவணப்படுத்தப்பட்ட பிரச்சினையாக மாற்றுவீர்கள்.', 'I'),
  (3, 'The people. 180 crores affects jobs, bonuses, and the communities your operations support. Your principle is not more important than the people who pay the price for it. You will make this decision with that weight fully acknowledged.', 'மக்கள். 180 கோடி ரூபாய் என்பது வேலைவாய்ப்புகள், ஊக்கத்தொகைகள் மற்றும் உங்கள் செயல்பாடுகள் ஆதரிக்கும் சமூகங்களைப் பாதிக்கிறது. அதற்கான விலையைக் கொடுக்கும் மக்களை விட உங்கள் கொள்கை முக்கியமானதல்ல. அந்த முக்கியத்துவத்தை முழுமையாக உணர்ந்துதான் நீங்கள் இந்த முடிவை எடுப்பீர்கள்.', 'S'),
  (4, 'The legal and governance analysis. You want a precise assessment of every available legitimate option - legal challenge, regulatory escalation, force majeure provisions in the contract - before you accept that the only choices are the payment or the penalty.', 'சட்ட மற்றும் நிர்வாகப் பகுப்பாய்வு. பணம் செலுத்துவது அல்லது அபராதம் செலுத்துவது மட்டுமே வழிகள் என்பதை நீங்கள் ஏற்றுக்கொள்வதற்கு முன், சட்டரீதியான சவால், ஒழுங்குமுறை மீறல், ஒப்பந்தத்தில் உள்ள தவிர்க்க முடியாத சூழ்நிலைக்கான விதிகள் போன்ற கிடைக்கக்கூடிய ஒவ்வொரு முறையான தெரிவையும் நீங்கள் துல்லியமாக மதிப்பிட வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q36
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q36',
     'You have discovered that a business practice in one of your international subsidiaries - one that has been running for four years - is in a legal grey zone in that jurisdiction. It is not illegal under current law but a regulatory change under consultation would make it non-compliant. Your legal team says you have 18 months before the regulation is finalised. Your subsidiary generates 22% of group EBITDA.The honest feeling underneath this - before you brief your board, before you instruct legal, before you build the remediation plan - what are you actually feeling?', 'What are you actually feeling?', 'உங்கள் சர்வதேச துணை நிறுவனங்களில் ஒன்றில், கடந்த நான்கு ஆண்டுகளாகச் செயல்பட்டு வரும் ஒரு வணிக நடைமுறை, அந்த அதிகார வரம்பில் சட்டரீதியான தெளிவற்ற நிலையில் இருப்பதை நீங்கள் கண்டறிந்துள்ளீர்கள். தற்போதைய சட்டத்தின் கீழ் அது சட்டவிரோதமானது அல்ல, ஆனால் கலந்தாலோசனையின் கீழ் உள்ள ஒரு ஒழுங்குமுறை மாற்றம், அதை இணக்கமற்றதாக ஆக்கிவிடும். அந்த ஒழுங்குமுறை இறுதி செய்யப்படுவதற்கு உங்களுக்கு 18 மாதங்கள் அவகாசம் இருப்பதாக உங்கள் சட்டக் குழு கூறுகிறது. உங்கள் துணை நிறுவனம், குழுமத்தின் EBITDA-வில் 22%-ஐ ஈட்டுகிறது. இதன் பின்னணியில் உள்ள உண்மையான உணர்வு என்னவென்றால் - உங்கள் நிர்வாகக் குழுவிற்கு விளக்கமளிப்பதற்கு முன்பும், சட்டக் குழுவிற்கு அறிவுறுத்துவதற்கு முன்பும், சரிசெய்யும் திட்டத்தை உருவாக்குவதற்கு முன்பும் - நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?', 'நீங்கள் உண்மையில் என்ன உணர்கிறீர்கள்?',
     '{"theme": "Ethics and Governance Under Pressure", "layer": "Layer 3", "dimension": "risk_appetite", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the urgency to get ahead of this - to act before you are forced to act, to build the remediation plan now rather than wait for a regulation that makes it a crisis - and you want to move faster than the legal timeline suggests you need to.', 'இதை முன்கூட்டியே சமாளிக்க வேண்டிய அவசரத்தை நீங்கள் உணர்கிறீர்கள் - அதாவது, செயல்பட நிர்பந்திக்கப்படுவதற்கு முன்பே செயல்பட வேண்டும், இதை ஒரு நெருக்கடியாக மாற்றும் ஒழுங்குமுறைக்காகக் காத்திருக்காமல் இப்போதே சீரமைப்புத் திட்டத்தை உருவாக்க வேண்டும் - மேலும், சட்டப்பூர்வ காலக்கெடு குறிப்பிடுவதை விட வேகமாகச் செயல்படவும் நீங்கள் விரும்புகிறீர்கள்.', 'D'),
  (2, 'You feel the exposure of having not known sooner - the awareness that four years of a grey-zone practice existing under your leadership is a fact that will be part of this story regardless of what you do next.', 'இதை முன்னரே அறியாததால் ஏற்பட்ட பாதிப்பை நீங்கள் உணர்கிறீர்கள் - அதாவது, நீங்கள் அடுத்து என்ன செய்தாலும், உங்கள் தலைமையின் கீழ் நான்கு ஆண்டுகளாக நிலவி வந்த ஒரு தெளிவற்ற நடைமுறை என்பது இந்தக் கதையின் ஒரு பகுதியாகவே இருக்கும் என்ற விழிப்புணர்வை உணர்கிறீர்கள்.', 'I'),
  (3, 'You feel the discomfort of a situation where doing the right thing is genuinely costly - and the honest recognition that the 22% of EBITDA is not an abstraction but a real consequence that affects real people across the group.', 'சரியானதைச் செய்வது உண்மையாகவே பெரும் இழப்பை ஏற்படுத்தும் ஒரு சூழ்நிலையின் அசௌகரியத்தை நீங்கள் உணர்கிறீர்கள் - மேலும், EBITDA-வில் உள்ள 22% என்பது ஒரு கற்பனையல்ல, மாறாக அது குழுமம் முழுவதும் உள்ள உண்மையான மக்களைப் பாதிக்கும் ஒரு நிஜமான விளைவு என்ற நேர்மையான அங்கீகாரத்தையும் பெறுகிறீர்கள்.', 'S'),
  (4, 'You feel the need to understand the situation precisely before you feel anything else - exactly where the legal line is, how exposed the practice makes you under current law, and what the 18-month timeline actually means for your options.', 'வேறு எதையும் உணர்வதற்கு முன்பு, நீங்கள் நிலைமையை மிகத் துல்லியமாகப் புரிந்துகொள்ள வேண்டியதன் அவசியத்தை உணர்கிறீர்கள் - அதாவது, சட்ட வரம்பு எங்கே இருக்கிறது, தற்போதைய சட்டத்தின் கீழ் இந்த நடைமுறை உங்களை எந்த அளவிற்குப் பாதிக்கின்றது, மேலும் அந்த 18 மாத காலக்கெடு உங்கள் தெரிவுகளுக்கு உண்மையில் என்ன அர்த்தம் தருகிறது என்பனவற்றையெல்லாம் நீங்கள் புரிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q37
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q37',
     'You have been the CEO for six years. In the past 18 months, you have noticed that your relationship with the board has shifted - conversations that were once collaborative feel more evaluative. Two board members who were strong supporters have become more distant. The board chair has not raised any concern formally but the change is real and you feel it.', 'How will you handle this?', 'நீங்கள் ஆறு ஆண்டுகளாக தலைமை நிர்வாக அதிகாரியாக இருந்து வருகிறீர்கள். கடந்த 18 மாதங்களில், நிர்வாகக் குழுவுடனான உங்கள் உறவில் ஒரு மாற்றம் ஏற்பட்டிருப்பதை நீங்கள் கவனித்திருக்கிறீர்கள் - முன்பு ஒத்துழைப்புடன் இருந்த உரையாடல்கள் இப்போது மதிப்பீட்டு ரீதியாகத் தோன்றுகின்றன. உங்களுக்கு வலுவான ஆதரவாளர்களாக இருந்த இரண்டு நிர்வாகக் குழு உறுப்பினர்கள் உங்களிடமிருந்து விலகிச் சென்றுள்ளனர். நிர்வாகக் குழுத் தலைவர் முறையாக எந்தக் கவலையையும் எழுப்பவில்லை, ஆனால் இந்த மாற்றம் உண்மையானது, அதை நீங்களும் உணர்கிறீர்கள்.', 'நீங்கள் இதை எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 1", "dimension": "approval_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You request a direct conversation with the board chair and name what you have observed - you will not manage a dynamic you have not named, and clarity is more useful to you than comfort.', 'நீங்கள் நிர்வாகக் குழுத் தலைவருடன் நேரடி உரையாடலைக் கோரி, நீங்கள் கவனித்தவற்றைக் குறிப்பிடுங்கள் - நீங்கள் குறிப்பிடாத ஒரு சூழலை உங்களால் நிர்வகிக்க முடியாது, மேலும் சௌகரியத்தை விடத் தெளிவு உங்களுக்கு மிகவும் பயனுள்ளதாக இருக்கும்.', 'D'),
  (2, 'You invest in the board relationships that have cooled - more regular touchpoints, better quality briefings, deeper personal access - and work to rebuild the warmth through consistent quality rather than a direct conversation about the shift.', 'குளிர்ந்துவிட்ட நிர்வாகக் குழு உறவுகளில் நீங்கள் முதலீடு செய்கிறீர்கள் - அதாவது, அடிக்கடி தொடர்புகொள்வது, சிறந்த தரமான விளக்கங்கள், ஆழமான தனிப்பட்ட அணுகல் போன்றவற்றை மேற்கொண்டு, அந்த மாற்றத்தைப் பற்றிய நேரடி உரையாடலுக்குப் பதிலாக, தொடர்ச்சியான தரம் மூலம் அந்த நெருக்கத்தை மீண்டும் கட்டியெழுப்பப் பணியாற்றுகிறீர்கள்.', 'I'),
  (3, 'You stay focused on performance and let your results rebuild the relationship - board dynamics shift with company performance and the most sustainable path back to trust is delivering.', 'நீங்கள் செயல்திறனில் கவனம் செலுத்தி, உங்கள் முடிவுகளே உறவை மீண்டும் கட்டியெழுப்பட்டும் - நிறுவனத்தின் செயல்திறனுக்கு ஏற்ப இயக்குநர் குழுவின் செயல்பாடுகள் மாறுகின்றன, மேலும் நம்பிக்கையை மீண்டும் பெறுவதற்கான மிகவும் நீடித்த வழி, வாக்குறுதிகளை நிறைவேற்றுவதே ஆகும்.', 'S'),
  (4, 'You seek feedback through a structured board evaluation process, create a formal mechanism for the board to share their assessment of your performance, and address the dynamic through a process rather than an informal conversation.', 'நீங்கள் ஒரு கட்டமைக்கப்பட்ட குழு மதிப்பீட்டுச் செயல்முறையின் மூலம் பின்னூட்டம் கோருகிறீர்கள், உங்கள் செயல்திறன் குறித்த குழுவின் மதிப்பீட்டைப் பகிர்ந்துகொள்ள ஒரு முறையான வழிமுறையை உருவாக்குகிறீர்கள், மேலும் முறைசாரா உரையாடலுக்குப் பதிலாக ஒரு செயல்முறையின் மூலம் அந்த இயக்கவியலைக் கையாளுகிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q38
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q38',
     'You have led your organisation through a period of intense transformation. The results are strong. The market is recognising the work. But privately, you feel depleted in a way that goes beyond tiredness. You are not sleeping well. You have become shorter with your team. You are making decisions you would normally find straightforward with much more difficulty than they deserve.', 'How will you handle burnout?', 'நீங்கள் உங்கள் நிறுவனத்தை ஒரு தீவிரமான மாற்றத்தின் காலகட்டத்தின் வழியாக வழிநடத்தியுள்ளீர்கள். அதன் முடிவுகள் வலுவாக உள்ளன. சந்தை உங்கள் பணியை அங்கீகரிக்கிறது. ஆனால் தனிப்பட்ட முறையில், சோர்வையும் தாண்டிய ஒருவிதத்தில் நீங்கள் ஆற்றல் இழந்திருப்பதாக உணர்கிறீர்கள். உங்களுக்குச் சரியாகத் தூக்கம் வரவில்லை. உங்கள் குழுவினரிடம் நீங்கள் கடுமையாக நடந்துகொள்கிறீர்கள். சாதாரணமாக உங்களுக்கு எளிதாகத் தோன்றும் முடிவுகளை, அவை தகுதியுள்ளதை விட அதிக சிரமத்துடன் எடுக்கிறீர்கள்.', 'மனச்சோர்வை நீங்கள் எப்படிச் சமாளிப்பீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 1", "dimension": "stability_need", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You name it to yourself and act - schedule the medical review you have been avoiding, speak to your coach, and build the recovery into your schedule as a non-negotiable before the depletion becomes visible to your team and your board.', 'நீங்களே உங்களுக்கு ஒரு முடிவை எடுத்துக்கொண்டு செயல்படுங்கள் - நீங்கள் தவிர்த்து வந்த மருத்துவப் பரிசோதனைக்கு நேரம் ஒதுக்குங்கள், உங்கள் பயிற்சியாளரிடம் பேசுங்கள், மேலும் உங்கள் அணிக்கும் நிர்வாகக் குழுவிற்கும் உங்கள் ஆற்றல் குறைவது தெரியவரும் முன்பே, இந்த மீட்சியை உங்கள் கால அட்டவணையில் ஒரு தவிர்க்க முடியாத அம்சமாகச் சேர்த்துக்கொள்ளுங்கள்.', 'D'),
  (2, 'You confide in one trusted person - your spouse, a mentor, a peer you respect - not to solve it but to stop carrying it alone, because you know that isolation amplifies depletion in a way that compounds over time.', 'அதைத் தீர்ப்பதற்காக அல்ல, மாறாக அதைத் தனியாகச் சுமப்பதை நிறுத்துவதற்காகவே, உங்கள் வாழ்க்கைத் துணை, வழிகாட்டி, நீங்கள் மதிக்கும் சக ஊழியர் என நீங்கள் நம்பும் ஒருவரிடம் உங்கள் மனக்குமுறல்களைப் பகிர்ந்துகொள்கிறீர்கள்; ஏனெனில், தனிமை என்பது காலப்போக்கில் மேலும் தீவிரமடைந்து, சோர்வை அதிகப்படுத்தும் என்பதை நீங்கள் அறிவீர்கள்.', 'I'),
  (3, 'You give yourself permission to slow down for one month - reduce your external commitments, protect your weekends, and trust that the organisation can absorb a temporary reduction in your pace while you recover.', 'ஒரு மாதத்திற்கு உங்கள் வேகத்தைக் குறைத்துக்கொள்ள உங்களுக்கு நீங்களே அனுமதி அளியுங்கள் - உங்கள் வெளி வேலைகளைக் குறைத்து, வார இறுதி நாட்களைப் பாதுகாத்து, நீங்கள் குணமடையும் வரை உங்கள் வேகத்தில் ஏற்படும் தற்காலிகக் குறைவை நிறுவனம் தாங்கிக்கொள்ளும் என்று நம்புங்கள்.', 'S'),
  (4, 'You track what is specifically depleting you - which interactions, which decisions, which commitments - and restructure your schedule systematically to remove or delegate the highest-drain activities before you address the broader recovery.', 'உங்களை குறிப்பாக எது சோர்வடையச் செய்கிறது என்பதை - அதாவது எந்தெந்த ஊடாடல்கள், எந்தெந்த முடிவுகள், எந்தெந்த கடமைகள் - நீங்கள் கண்காணித்து, பரந்த அளவிலான மீட்சியில் கவனம் செலுத்துவதற்கு முன்பு, அதிக ஆற்றலைச் செலவழிக்கும் செயல்பாடுகளை நீக்குவதற்கோ அல்லது மற்றவர்களிடம் ஒப்படைப்பதற்கோ உங்கள் கால அட்டவணையை முறையாக மறுசீரமைக்கிறீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q39
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q39',
     'You are 52 years old, at the height of your career, running a company that is performing well. An executive search firm has reached out about a role that is larger, more complex, and significantly more exposed than your current position. Taking it would mean leaving a team you have built, a strategy you are in the middle of executing, and a stability you have worked hard to create.What matters more to you in this moment - the pull of a larger platform, a harder challenge, and the recognition that you may not get another opportunity at this level, or the responsibility you feel to the organisation, the team, and the strategy you are in the middle of delivering?', 'What matters more to you?', 'உங்களுக்கு 52 வயது, உங்கள் தொழில் வாழ்க்கையின் உச்சத்தில் இருக்கிறீர்கள், மேலும் சிறப்பாகச் செயல்படும் ஒரு நிறுவனத்தை நடத்தி வருகிறீர்கள். உங்கள் தற்போதைய பதவியை விடப் பெரியதும், சிக்கலானதும், மற்றும் குறிப்பிடத்தக்க அளவில் அதிக முக்கியத்துவம் வாய்ந்ததுமான ஒரு பதவிக்காக ஒரு உயர்நிலை நிர்வாகி தேடல் நிறுவனம் உங்களைத் தொடர்பு கொண்டுள்ளது. அந்தப் பதவியை ஏற்பது என்பது, நீங்கள் உருவாக்கிய ஒரு குழுவையும், நீங்கள் செயல்படுத்திக் கொண்டிருக்கும் ஒரு உத்தியையும், கடினமாக உழைத்து உருவாக்கிய ஒரு நிலைத்தன்மையையும் விட்டுச் செல்வதாகும். இந்தத் தருணத்தில் உங்களுக்கு எது மிகவும் முக்கியமானது - ஒரு பெரிய தளத்தின் ஈர்ப்பு, ஒரு கடினமான சவால், மற்றும் இந்த மட்டத்தில் உங்களுக்கு மற்றொரு வாய்ப்பு கிடைக்காமல் போகலாம் என்ற உணர்வு, அல்லது நிறுவனம், குழு, மற்றும் நீங்கள் செயல்படுத்திக் கொண்டிருக்கும் உத்தி ஆகியவற்றின் மீது நீங்கள் உணரும் பொறுப்பு?', 'உங்களுக்கு எது மிகவும் முக்கியம்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 2", "dimension": "strategic_patience", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'The opportunity. You have earned the right to make this decision for yourself. The organisation will find the right successor and the team will be fine. Staying out of obligation at the cost of your own growth is not leadership - it is avoidance.', 'இந்த வாய்ப்பு. இந்த முடிவை நீங்களே எடுப்பதற்கான உரிமையை நீங்கள் பெற்றுள்ளீர்கள். நிறுவனம் சரியான வாரிசைக் கண்டறியும், குழுவும் சிறப்பாகச் செயல்படும். உங்கள் சொந்த வளர்ச்சிக்கு பங்கம் விளைவிக்கும் வகையில் கடமையிலிருந்து விலகி இருப்பது தலைமைத்துவம் அல்ல - அது தவிர்ப்பு.', 'D'),
  (2, 'The conversation. Before you decide anything, you will have an honest conversation with your board chair - not to ask permission but to think through the transition properly with someone who has a stake in it and your respect.', 'அந்த உரையாடல். நீங்கள் எதையும் தீர்மானிப்பதற்கு முன், உங்கள் நிர்வாகக் குழுத் தலைவருடன் ஒரு நேர்மையான உரையாடலை மேற்கொள்வீர்கள் - அது அனுமதி கேட்பதற்காக அல்ல, மாறாக, அந்த மாற்றத்தில் அக்கறை கொண்டவரும் உங்கள் மரியாதைக்குரியவருமான ஒருவருடன், அந்த மாற்றத்தைப் பற்றி முறையாகச் சிந்திப்பதற்காகவே.', 'I'),
  (3, 'The responsibility. You are in the middle of something that matters. The team, the strategy, the people who have bet on this journey with you - leaving now, when the work is not done, is not something you can reconcile with who you are as a leader.', 'பொறுப்பு. நீங்கள் ஒரு முக்கியமான காரியத்தின் நடுவில் இருக்கிறீர்கள். குழு, வியூகம், இந்தப் பயணத்தில் உங்களுடன் இணைந்துள்ள மக்கள் - வேலை முடியாமல் இருக்கும்போது இப்போது அவர்களை விட்டுச் செல்வது, ஒரு தலைவராக உங்கள் அடையாளத்துடன் உங்களால் ஒருபோதும் சமரசம் செய்துகொள்ள முடியாத ஒன்றாகும்.', 'S'),
  (4, 'The clarity. You will evaluate both options against a specific set of criteria - what you still have to contribute here, what the new role actually requires, and whether the timing is right on both sides - before you let either the pull or the obligation make the decision for you.', 'தெளிவு. உங்கள் ஈர்ப்போ அல்லது கடமையோ உங்களுக்காக முடிவெடுக்க அனுமதிக்கும் முன், நீங்கள் இங்கு இன்னும் என்ன பங்களிக்க வேண்டியுள்ளது, புதிய பணிக்கு உண்மையில் என்ன தேவைப்படுகிறது, இரு தரப்பிலும் நேரம் சரியாக உள்ளதா என்பன போன்ற ஒரு குறிப்பிட்ட அளவுகோல்களின் அடிப்படையில் இரண்டு விருப்பங்களையும் மதிப்பீடு செய்வீர்கள்.', 'C')
) AS v(ord, en, ta, fac);

-- Executive Set 2 Q40
WITH q AS (
  INSERT INTO assessment_questions
    (assessment_level_id, set_number, program_id, board, external_code,
     context_text_en, question_text_en, context_text_ta, question_text_ta,
     metadata, is_active, is_deleted)
  VALUES ((SELECT id FROM assessment_levels WHERE level_number = 1), 2, (SELECT id FROM programs WHERE code = 'EMPLOYEE'), 'Executive', 'EMP-EXE-S2-Q40',
     'You have spent 31 years building a career and a reputation in one industry. An opportunity has emerged to lead an organisation in an adjacent sector - one where your skills are transferable but your domain knowledge is limited. The people who know you best believe you can do it. You are not sure they are right.Before you say yes or no - what is actually happening inside you?', 'How will you handle change?', 'நீங்கள் ஒரே துறையில் 31 ஆண்டுகளாக உங்கள் தொழில் வாழ்க்கையையும் நற்பெயரையும் கட்டமைத்துள்ளீர்கள். அதற்கு அருகிலுள்ள ஒரு துறையில் உள்ள நிறுவனத்தை வழிநடத்த ஒரு வாய்ப்பு உருவாகியுள்ளது - அத்துறையில் உங்கள் திறமைகள் பொருந்தக்கூடியவை, ஆனால் உங்கள் துறைசார் அறிவு குறைவாக உள்ளது. உங்களை நன்கு அறிந்தவர்கள், உங்களால் அதைச் செய்ய முடியும் என்று நம்புகிறார்கள். அவர்கள் சொல்வது சரிதானா என்று உங்களுக்கு உறுதியாகத் தெரியவில்லை. ஆம் அல்லது இல்லை என்று சொல்வதற்கு முன் - உண்மையில் உங்களுக்குள் என்ன நடக்கிறது?', 'மாற்றத்தை நீங்கள் எவ்வாறு கையாள்வீர்கள்?',
     '{"theme": "Leader Wellbeing and Sustainability", "layer": "Layer 3", "dimension": "change_tolerance", "board": "Executive", "source": "employee_xlsx_v1"}'::jsonb, true, false)
  RETURNING id
)
INSERT INTO assessment_question_options
  (question_id, display_order, option_text_en, option_text_ta,
   disc_factor, score_value, is_correct, is_active, is_deleted)
SELECT q.id, v.ord, v.en, v.ta, v.fac, 1, false, true, false
FROM q, (VALUES
  (1, 'You feel the excitement of a new challenge alongside a clear-eyed recognition of the risk - and the awareness that the discomfort of not knowing is exactly the condition under which you have historically grown the most.', 'ஒரு புதிய சவாலின் உற்சாகத்தையும், அதிலுள்ள அபாயத்தைத் தெளிவாக உணர்ந்துகொள்வதையும் ஒருசேர நீங்கள் உணர்கிறீர்கள்; மேலும், என்ன செய்வதென்று தெரியாததால் ஏற்படும் அந்த அசௌகரியத்தில்தான், வரலாற்று ரீதியாக நீங்கள் மிக அதிகமாக வளர்ந்திருக்கிறீர்கள் என்ற விழிப்புணர்வும் உங்களுக்கு ஏற்படுகிறது.', 'D'),
  (2, 'You feel the identity question underneath the professional one - who you are when you are not the expert in the room, when your reputation does not precede you, when you have to earn credibility from the beginning again.', 'தொழில்முறைப் பிரச்சினைக்கு அடியில் உள்ள அடையாளப் பிரச்சினையை நீங்கள் உணர்கிறீர்கள் - அதாவது, அந்த அறையில் நீங்கள் நிபுணராக இல்லாதபோது, ​​உங்கள் புகழ் உங்களை முந்திக்கொண்டு செல்லாதபோது, ​​மீண்டும் தொடக்கத்திலிருந்து நம்பகத்தன்மையை நீங்கள் சம்பாதிக்க வேண்டியிருக்கும்போது, ​​நீங்கள் யார் என்பதே அந்தப் பிரச்சினை.', 'I'),
  (3, 'You feel the pull of both directions and the difficulty of separating genuine readiness from fear of staying and genuine caution from fear of going - and you know that whichever you choose, you will wonder about the other.', 'இரு திசைகளின் ஈர்ப்பையும், தங்கிவிடுவதற்கான பயத்திலிருந்து உண்மையான தயார்நிலையையும், சென்றுவிடுவதற்கான பயத்திலிருந்து உண்மையான எச்சரிக்கையையும் பிரித்தறிவதில் உள்ள சிரமத்தையும் நீங்கள் உணர்கிறீர்கள் - மேலும், நீங்கள் எதைத் தேர்ந்தெடுத்தாலும், மற்றொன்றைப் பற்றி நீங்கள் வியப்படைவீர்கள் என்பதும் உங்களுக்குத் தெரியும்.', 'S'),
  (4, 'You feel the need to understand the role precisely before you trust your instinct - what the first 12 months actually require, where your knowledge gaps are specific and bridgeable, and whether the organisation has the patience for a leader who is learning the domain while leading it.', 'உங்கள் உள்ளுணர்வை நம்புவதற்கு முன்பு, அந்தப் பொறுப்பைத் துல்லியமாகப் புரிந்துகொள்ள வேண்டியதன் அவசியத்தை நீங்கள் உணர்கிறீர்கள் – அதாவது, முதல் 12 மாதங்களுக்கு உண்மையில் என்ன தேவைப்படும், உங்கள் அறிவு இடைவெளிகள் எவை குறிப்பிட்டவை மற்றும் சரிசெய்யக்கூடியவை, மேலும், ஒரு துறையை வழிநடத்தும்போதே அதைக் கற்றுக்கொள்ளும் ஒரு தலைவரைத் தாங்கிக்கொள்ள அந்த நிறுவனத்திற்குப் பொறுமை இருக்கிறதா என்பனவற்றையெல்லாம் நீங்கள் அறிந்துகொள்ள வேண்டும்.', 'C')
) AS v(ord, en, ta, fac);

COMMIT;

-- Imported 240 questions and 960 options.